if object_id('prGetJobCostToInvoice') is not null
	drop proc prGetJobCostToInvoice

go

create proc prGetJobCostToInvoice
@JobId int 

as

set transaction isolation level read uncommitted
set nocount on


declare @Material float,
	@Labour float,
	@Expense float


select @Material = isnull(sum(Nettotal),0) from invSalesHeader where JobId = @JobId

if (select isnull(AddLabourCostToJobInvoice,0) from invOption where CompanyID = (select CompanyID from invJobForm where Id = @JobId)) = 1
	select @Labour = isnull(sum(total),0)  from invLabourDetails where JobId = @JobId
else
        set @Labour = 0

--Expense From Sales
select @Expense = isnull(sum(t1.amount),0) from invSalesAdditions t1 
join invSalesHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
where t2.JobId = @JobId

--Expense From Job Expense
select @Expense = isnull(@Expense,0) + isnull(sum(t1.amount),0)+ isnull(sum(t1.Tax),0) from invJobExpenseDetails t1 
join invJobExpenseHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.No = t2.No
where t2.JobId = @JobId


select t1.No,t1.Date,t1.JobNo,t2.name [CostCentre],t1.CustomerId,isnull(t3.name,t1.Customer) Customer,c.tin,c.gst,t1.Colour,t1.ModelNo,t1.Year,
t1.Amount,@Material Material,@Labour Labour,@Expense Expense, @Material + @Labour + @Expense Total,t1.Advance from invJobForm t1
left join invCostCentre t2 on t1.CostCentreId = t2.Id
left join aAccount t3 on t1.CustomerId = t3.Id
left join invCustomer c on t1.CustomerId = c.AccountId
where t1.Id = @JobId

select t2.Code,t2.name Particulars, t1.WorkId,isnull(t1.EmployeeId,0)EmployeeId ,isnull(t3.name,'') Employee,sum(t1.qty) Qty, t1.WorkRate Rate,
sum(t1.WorkTotal) Amount from invLabourDetails t1
join invJobWork t2 on t1.WorkId = t2.Id
left outer join aAccount t3 on t1.EmployeeId = t3.Id
where t1.JobId = @JobId
group by t2.Code,t2.name,t1.WorkId,isnull(t1.EmployeeId,0) ,isnull(t3.name,''),t1.WorkRate
union all
select p.Code,p.name Particulars,null,null,null,sum(t1.qty) Qty, t1.Rate,
sum(t1.Gross) Amount from invSalesDetails t1
join invSalesHeader h on t1.CompanyId=h.CompanyId and t1.PeriodId=h.PeriodId and t1.VtypeId=h.VtypeId and t1.No=h.No
join invProduct p on t1.ProductId=p.Id
where h.JobId = @JobId
group by p.Code,p.name,t1.Rate


Go



if OBJECT_ID('prGetJobInvoice') is not null
	drop proc prGetJobInvoice
go

create proc prGetJobInvoice
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int 

as

set transaction isolation level read uncommitted
set nocount on

declare @Material float,
	@Labour float,
	@Expense float,
        @JobId int

select @JobId = JobId from invJobInvoice 
where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and [No] = @No 

select * from invJobInvoice 
where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and [No] = @No 


select @Material = isnull(sum(Nettotal),0) from invSalesHeader 
where JobId = @JobId


if (select isnull(AddLabourCostToJobInvoice,0) from invOption where CompanyID = (select CompanyID from invJobForm where Id = @JobId)) = 1
	select @Labour = isnull(sum(total),0)  from invLabourDetails where JobId = @JobId
else
        set @Labour = 0


select @Expense = isnull(sum(t1.amount),0) from invSalesAdditions t1 
join invSalesHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
where t2.JobId = @JobId

--Expense From Job Expense
select @Expense = isnull(@Expense,0) + isnull(sum(t1.amount),0)+ isnull(sum(t1.Tax),0) from invJobExpenseDetails t1 
join invJobExpenseHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.No = t2.No
where t2.JobId = @JobId


--if isnull(@Material,0) > 0 
	--set @Material = @Material - isnull(@Expense,0)

select t1.No,t1.Date,t1.JobNo,isnull(t2.name,0) [CostCentre],t1.CustomerId,isnull(t3.name,t1.Customer) Customer,c.TIN,c.GST,t1.Colour,t1.ModelNo,t1.Year,
t1.Amount,@Material Material,@Labour Labour,@Expense Expense, @Material + @Labour + @Expense Total,t1.Advance from invJobForm t1
left outer join invCostCentre t2 on t1.CostCentreId = t2.Id
left outer join aAccount t3 on t1.CustomerId = t3.Id
left join invCustomer c on t3.ID=c.AccountID
where t1.Id = @JobId


select t1.Sno,t1.WorkId,t1.Qty,t1.Rate,t1.Amount,t2.name Particulars,t2.Code,
isnull(t1.EmployeeId,0)EmployeeId ,isnull(t3.name,'') Employee from invJobInvoiceDetails t1
join invJobWork t2 on t1.WorkId = t2.Id 
left outer join aAccount t3 on t1.EmployeeId = t3.Id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.VtypeId = @VtypeId and t1.[No] = @No 
union all
select 0,null,sum(t1.qty) Qty, t1.Rate,sum(t1.Gross) Amount,p.name Particulars,p.Code,null,null from invSalesDetails t1
join invSalesHeader h on t1.CompanyId=h.CompanyId and t1.PeriodId=h.PeriodId and t1.VtypeId=h.VtypeId and t1.No=h.No
join invProduct p on t1.ProductId=p.Id
where h.JobId = @JobId
group by p.Code,p.name,t1.Rate

go


if OBJECT_ID('prSaveJobInvoice') is not null
	drop proc prSaveJobInvoice
go

create proc prSaveJobInvoice
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int,
@Date int,
@JobId int,
@Amount float,
@Notes nvarchar(max),
@RefNo varchar(25),
@OutVno int output,
@XmlProductDetails xml,
@Discount float,
@Cash float,
@Card float,
@CustomerId int,
@CreditCardID int,
@SalesmanID int,
@JobTotal float,
@TaxGroupID int,
@Tax float,
@EInvoice int = null

as
set nocount on
set xact_abort on
declare @Id int

set @OutVno = 0

begin tran

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetJobInvoiceMaxVno
    @CompanyId = @CompanyId,
    @PeriodId = @PeriodId,
    @VtypeId = @VtypeId

    select @No = [No] from @T1 
	
  end
else
   begin
     exec prDeleteJobInvoice
     @CompanyId = @CompanyId,
     @PeriodId = @PeriodId,
     @VtypeId = @VtypeId,
     @No = @No 
   end    


   insert invJobInvoice(CompanyID,PeriodID,VtypeId,No,Date,JobId,Amount,Notes,RefNo,Discount,Cash,Card,CustomerId,CreditCardID,JobTotal,SalesmanID,TaxGroupID,Tax,EInvoice)
   values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@JobId,@Amount,@Notes,@RefNo,@Discount,nullif(@Cash,0),nullif(@Card,0),nullif(@CustomerId,0),nullif(@CreditCardID,0),@JobTotal,nullif(@SalesmanID,0),nullif(@TaxGroupID,0),nullif(@Tax,0),@EInvoice)    


declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert invJobInvoiceDetails
([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[WorkId],[Qty],[Rate],[AMount],[EmployeeId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[WorkId],[Qty],[Rate],[AMount],nullif(EmployeeId,0)
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
WorkId         int '@WorkId',
EmployeeId     int '@EmployeeId', 
Qty            float '@Qty',
Rate           float '@Rate',
Amount         float '@Amount'
)
where WorkId>0

exec sp_xml_removedocument @Idoc

	


--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and CompanyId=@CompanyId) and isnull(@EInvoice,0) not in(2,4)
Begin


	declare @JobInvoiceAccount int,
	        @DiscountAccountID int,
	        --@CashInHandID int,
		@VoucherTypeID int
		--@CreditCard int

	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	select @JobInvoiceAccount = JobInvoiceAccount from invOption where CompanyID=@CompanyID


    if isnull(@VoucherTypeID,0) > 0 and isnull(@JobInvoiceAccount,0) > 0
    begin

		declare @Code nvarchar(50),@Name nvarchar(100)
		select @Code = 'Job '+ JobNo,@Name=Customer from invJobForm where ID = @JobId

		if (@Amount - isnull(@Cash,0) - isnull(@Card,0)) >0 and @CustomerId = 0
		begin	
			select @CustomerId=ID from aAccount where Code=@Code

			if @CustomerId = 0
			Begin
				--Insertion to account
				declare @t table(ID int,Status tinyint,Message varchar(100))

				declare @UnderID int
				select @UnderID=Customers from aAccountSettings

				declare @AccountSubGroupID int
				select @AccountSubGroupID=AccountSubGroupID from aAccount where ID=@UnderID

				insert @t 
				exec spSaveAccount @ID=@CustomerId,@Code=@Code,@Name=@Name,@AccountSubGroupID=@AccountSubGroupID,
				@UnderAccountID=@UnderID,@OB=null,@DrCr=null,@CompanyID=1,
				@ModuleID=1,@IsAllowDuplicateName=1

				select @CustomerId =ID from @t where Status=0

				delete invCustomer where AccountId = @CustomerId
				insert invCustomer (CompanyId,AccountId,Name) select @CompanyId,@CustomerId,@Name where @CustomerId > 0

			End

	    	

        end
	        
	      
	  if @CustomerId = 0
		select @CustomerId=ID from aAccount where Code=@Code

			update invJobInvoice set CustomerId = nullif(@CustomerId,0) 
            where CompanyId = @CompanyId and
            PeriodId = @PeriodId and
            VtypeId = @VtypeId and
            No = @No

  
	  if @CustomerId > 0
      begin
	     --Net Total
         insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,SNo)
	     values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@JobInvoiceAccount,@Amount,'Job Invoice ' + @RefNo,nullif(@CreditCardID,0),1) 		

		 if @Cash <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@CustomerId,@Cash,'Cash Payment (Job Invoice ' + @RefNo + ')',2 from aAccountSettings where CompanyId=@CompanyId

		 if @Card <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@CustomerId,@Card,'Card Payment (Job Invoice ' + @RefNo + ')',3 from aAccountSettings where CompanyId=@CompanyId

	  end	
  


   	  if @CustomerId = 0 
	  begin 		
     --   --Net Total
	    --insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,SNo)
	    --values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@JobInvoiceAccount,@Amount,'Job Invoice ' + @RefNo,nullif(@CreditCardID,0),1) 

		if @Cash <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@JobInvoiceAccount,@Cash,'Cash Payment (Job Invoice ' + @RefNo + ')',2 from aAccountSettings where CompanyId=@CompanyId

		 if @Card <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@JobInvoiceAccount,@Card,'Card Payment (Job Invoice ' + @RefNo + ')',3 from aAccountSettings where CompanyId=@CompanyId


      end   

	  
	  --Discount
	  if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,DiscountPaid,@JobInvoiceAccount,@Discount,'Job Invoice Discount ' + @RefNo from aAccountSettings where CompanyID=@CompanyID

 	  --Tax
	  if @Tax<>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@JobInvoiceAccount,OutPutTaxAccount,@Tax,'Job Invoice Tax ' + @RefNo from invOption where CompanyID=@CompanyID
		

	end	

End

set @OutVno = @No

commit tran

go

if object_id('spGetInvJobInvoiceTaxSummary') is not null drop proc spGetInvJobInvoiceTaxSummary

go

create proc spGetInvJobInvoiceTaxSummary
@CompanyID int,
@PeriodID int,
@VTypeID int,
@No int 

as

set transaction isolation level read uncommitted

declare @T Table (TaxRate float,NetValue float,Tax float)
insert @T
select 15.0 TaxRate,
sum(cast(cast(Amount as numeric(18,10)) as numeric(18,2)))NetValue,
SUM(cast(cast(Amount*15.0/100.0 as numeric(18,10)) as numeric(18,2)))Tax
from invJobInvoiceDetails d
where CompanyID=@CompanyID and PeriodID=@PeriodID and VTypeID=@VTypeID and No=@No

insert @T
select 15.0 TaxRate,
sum(cast(cast(sd.Gross as numeric(18,10)) as numeric(18,2)))NetValue,
SUM(cast(cast(sd.Gross*15.0/100.0 as numeric(18,10)) as numeric(18,2)))Tax
from invSalesDetails sd
join invSalesHeader sh on sd.CompanyId=sh.CompanyId and sd.PeriodId=sh.PeriodId and sd.VtypeId=sh.VtypeId and sd.No=sh.No
join invJobInvoice ji on sh.JobId=ji.JobId
where ji.CompanyID=@CompanyID and ji.PeriodID=@PeriodID and ji.VTypeID=@VTypeID and ji.No=@No


select TaxRate,sum(NetValue)NetValue,sum(Tax)Tax from @T
group by TaxRate


go






if OBJECT_ID('prDeleteJobInvoice') is not null
	drop proc prDeleteJobInvoice
go

create proc prDeleteJobInvoice
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int as
set nocount on

delete invJobInvoice 
where CompanyId = @CompanyId and PeriodId = @PeriodId  and VtypeId = @VtypeId and No = @No

delete invJobInvoiceDetails 
where CompanyId = @CompanyId and PeriodId = @PeriodId  and VtypeId = @VtypeId and No = @No

declare @VoucherTypeID int
select @VoucherTypeID= isnull(AccountVTypeID,0) from invVoucherTypeDetails where ID=@VtypeId
delete aTransaction where ModuleID=1 and VoucherTypeID = @VoucherTypeID and [No] = @No and CompanyID=@CompanyID and PeriodID=@PeriodID


go

if not exists(select name from sys.columns where object_id = object_id('invProjectSettings') and name = 'DisablePostingInSales') 
  alter table invProjectSettings add DisablePostingInSales bit 

go

if OBJECT_ID('prSaveinvProjectSettings') is not null
	drop proc prSaveinvProjectSettings
go
	
create proc prSaveinvProjectSettings
@AccountLinking bit,
@PointSettingsOfProduct bit,
@Rep1InSales bit,
@Rep1Caption varchar(50),
@Rep2InSales bit,
@Rep2Caption varchar(50),
@AdditionInSales bit,
@AdditionCaption varchar(50),
@AdditionDebtor int,
@AdditionAccount int,
@DataTransfer int,
@SizePropertyId int,
@PurchaseProperty bit,
@AutoBarcode bit,
@SalesProperty bit,
@PiecesInSales bit,
@PiecesCaption varchar(10),
@AirwayBillNoInSales bit,
@AirwayBillNoCaption varchar(50),
@Mailing bit,
@ProductSerialNo bit,
@SalesRateInPurchase bit,
@HideQtyInPrint bit,
@RcvDealer bit,
@ClearSales bit,
@GarageWorks bit,
@Water bit,
@PDADevice bit,
@PrintWithoutSaving bit,
@Transportation bit,
@DayEnd bit,
@CompanyID int,
@BlockMasterCreation bit =0,
@UniversalNoSeries bit =0,
@HideEdit bit =0,
@PiecesInPurchase bit,
@PurchasePiecesCaption varchar(10),
@DisablePostingInSales bit

as

set nocount on
update invOption set 
	[AccountLinking] = @AccountLinking, 
	AdditionCaption=nullif(@AdditionCaption,''),
	AdditionAccount=nullif(@AdditionAccount,0) where CompanyId=	@CompanyID

	

if not exists(select 1 from invProjectSettings where CompanyId=	@CompanyID)
Begin
Insert invProjectSettings( PointSettingsOfProduct,Rep1InSales,Rep1Caption,Rep2InSales,Rep2Caption,AdditionInSales,
DataTransfer,SizePropertyId,PurchaseProperty,AutoBarcode,SalesProperty,PiecesInSales,PiecesCaption,AirwayBillNoInSales
,AirwayBillNoCaption,Mailing,ProductSerialNo,SalesRateInPurchase,HideQtyInPrint,RcvDealer,ClearSales,GarageWorks,Water,
PDADevice,PrintWithoutSaving,Transportation,DayEnd,CompanyId,BlockMasterCreation,UniversalNoSeries,HideEdit,
PiecesInPurchase ,PurchasePiecesCaption,DisablePostingInSales) 
values (@PointSettingsOfProduct,@Rep1InSales,@Rep1Caption,@Rep2InSales,@Rep2Caption,@AdditionInSales,@DataTransfer,
@SizePropertyId,@PurchaseProperty,@AutoBarcode,@SalesProperty,@PiecesInSales,@PiecesCaption,@AirwayBillNoInSales,
@AirwayBillNoCaption,@Mailing,@ProductSerialNo,@SalesRateInPurchase,@HideQtyInPrint,@RcvDealer,@ClearSales,@GarageWorks,
@Water,@PDADevice,@PrintWithoutSaving,@Transportation,@DayEnd,@CompanyId,@BlockMasterCreation,@UniversalNoSeries,@HideEdit,
@PiecesInPurchase ,@PurchasePiecesCaption,@DisablePostingInSales)

End
else
update invProjectSettings set
[PointSettingsOfProduct]= @PointSettingsOfProduct,
[Rep1InSales]= @Rep1InSales,
[Rep1Caption]= @Rep1Caption,
[Rep2InSales]= @Rep2InSales,
[Rep2Caption]= @Rep2Caption,
[AdditionInSales] = @AdditionInSales,
[DataTransfer] = @DataTransfer,
[SizePropertyId] = @SizePropertyId,
[PurchaseProperty] = @PurchaseProperty,
[AutoBarcode] = @AutoBarcode ,
[SalesProperty] = @SalesProperty,
[PiecesInSales] = @PiecesInSales,
[PiecesCaption] = @PiecesCaption,
[AirwayBillNoInSales] = @AirwayBillNoInSales,
[AirwayBillNoCaption] = @AirwayBillNoCaption,
[Mailing] = @Mailing,
[ProductSerialNo] = @ProductSerialNo,
[SalesRateInPurchase] = @SalesRateInPurchase ,
[HideQtyInPrint] = @HideQtyInPrint,
[RcvDealer] = @RcvDealer, 
[ClearSales] = @ClearSales,
[GarageWorks] = @GarageWorks,
[Water] = @Water,
[PDADevice] = @PDADevice,
PrintWithoutSaving = @PrintWithoutSaving,
Transportation = @Transportation,
DayEnd = @DayEnd,
BlockMasterCreation=@BlockMasterCreation,
UniversalNoSeries=@UniversalNoSeries,
HideEdit=@HideEdit,
PiecesInPurchase = @PiecesInPurchase ,
PurchasePiecesCaption = @PurchasePiecesCaption,
DisablePostingInSales=@DisablePostingInSales
where CompanyId=@CompanyID
go

if object_id('prSaveSales') is not null
	drop proc prSaveSales
go

create proc prSaveSales
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int,
@Date int,
@DeliveryDate int,
@CustomerId int,
@PaymentMode tinyint,
@SalesManId int,
@RateLevelId int,
@DueDate int,
@QuotationNo int,
@Total float,
@DiscountP float,
@Discount float,
@NetTotal float,
@Notes nvarchar(4000),
@TaxCalculation int,
@Tax float,
@SalesReturn float,
@Addition float,
@XmlProductDetails xml,
@Rep1 int,
@Rep2 int,
@Paid float,
@RoundOff float,
@AirwayBillNo varchar(50),
@XmlPropertyDetails xml,
@Advance float,
@Time int,
@XmlAdditions xml,
@FooterAddition float,
@PrePrintingString varchar(50),
@FromTime int=null,
@ToTime int=null,
@JobId int,
@ReturnId int,
@CostCentreId int,
@ShippingId int,
@ShippingNo varchar(50),
@Address nvarchar(300)=null, 
@Export bit=null,
@CreditCardID int=null,
@InterState bit=null,
@CardId int = null,
@Redempted int = null,
@PaidBy tinyint=null,
@XmlProductSno xml,
@TaxGroupID int=null,
@BillTax float=null,
@Description nvarchar(100)=null,
@LocalMobileNo varchar(100) = null,
@Approve bit=null,
@UserId int = null,
@Addition2 float=null,
@TokenNo int = null,
@QRCodeImage Image=null,
@Remark1 nVarchar(500) =null,
@Remark2 nVarchar(500) =null,
@Remark3 nVarchar(500) =null,
@Remark4 nVarchar(500) =null,
@EInvoice int = null,
@XmlTray xml=null,
@NotEdit bit = null,
@Remark5 nvarchar(2000) = null ,
@Remark6 nvarchar(2000) = null ,
@Remark7 nvarchar(2000) = null ,
@Remark8 nvarchar(2000) = null ,
@Remark9 nvarchar(2000) = null ,
@Remark10 nvarchar(2000) = null ,
@Remark11 nvarchar(2000) = null ,
@Remark12 nvarchar(2000) = null ,
@Discount1 float=null,
@Discount2 float=null,
@Discount3 float=null,
@Eway bit = null


as
set nocount on
set xact_abort on

declare @Message varchar(100)
if not exists(select 1 from invOption where CompanyID=@CompanyID and SalesAllowDuplicateInvoiceNo=1) 
Begin
	if len(rtrim(@AirwayBillNo))>0
		select @Message='Invoice No Already given for Sales ' + cast(No as varchar) from invSalesHeader where CompanyID = @CompanyID and PeriodID = @PeriodID and VtypeId = @VtypeId and No <> @No and AirwayBillNo  = @AirwayBillNo 
End

if @Message is not null
Begin
	select @No No,@Message Message
	return
End

--Due Day Blocking
if (@PaymentMode>0)
Begin
	if exists(select 1 from invOption where SalesBlockByCreditLimit=1 and CompanyId=@CompanyId)
	Begin
		declare @DueDays int
		select @DueDays=DueDays from invCustomer where AccountID=@CustomerId and DueDays>0
		
		if isnull(@DueDays,0)=0
			select @DueDays=DueDays from invCostCentre where Id=@CostCentreId

		if (@DueDays>0)
		Begin
			
			if exists(select 1 from invOption where CompanyId=@CompanyId and DueCalculation=1)
			Begin
				declare @OS table(PeriodId int,Date smalldatetime,VoucherTypeID int,VType varchar(50),No int,SNo int,Account nvarchar(100),Description varchar(300),Age int,Amount varchar(50))

				if exists(select 1 from invVendor where AccountId=@CustomerID)
					insert @OS
					exec spGetVendorOutstandingBills @CompanyId=@CompanyId,@ToDate=@Date,@VendorId=@CustomerID,@Type=2
				else
					insert @OS
					exec spGetCustomerOutstandingBills @CompanyId=@CompanyId,@ToDate=@Date,@CustomerID=@CustomerID,@Type=2

				delete @OS where isnumeric(Amount)=0
				select @Message='Due Days Over For No. ' + cast(No as varchar)+ char(10)+char(13)+'Amount - '+ Amount + char(10)+char(13) + 'Days - ' + cast(Age as varchar) from @OS where Age>@DueDays and cast(replace(Amount,',','') as float)>0
				if @Message is not null
				Begin
					select @No No,@Message Message
					return
				End
			End
			Else
			Begin
				declare @Due table(PeriodId int,Date smalldatetime,VoucherTypeID int,VType varchar(50),No int,Description varchar(300),Amount varchar(50),Age int,Balance varchar(50))
				insert @Due 
				exec spCustomersAgeing @ToDate=@Date,@AccountID=@CustomerID,@Type=3,@CompanyId=@CompanyId
				select @Message='Due Days Over For No. ' + cast(No as varchar)+ char(10)+char(13)+'Amount - '+ Amount + char(10)+char(13)+ 'Balance - '+Balance + char(10)+char(13) + 'Days - ' + cast(Age as varchar) from @Due where Age>@DueDays
				if @Message is not null
				Begin
					select @No No,@Message Message
					return
				End
			End
			
		End
	End
End

----------
declare @VoucherTypeID int
declare @Sync bit
Begin Transaction
if(@No = 0)
begin
	declare @T1 table([No] int)
	insert @T1 exec prGetSalesMaxVno @CompanyID,@PeriodID,@VtypeId
	select @No = [No] from @T1 
	--Token No
	if exists(select 1 from invOption where CompanyId=@CompanyId and TokenNo=1)
	begin
	    select  @TokenNo = isnull(max(TokenNo),0) + 1 from invSalesHeader 
        where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and [Date] = @Date 
	end
end
else
begin
	if exists(select 1 from invOption where CompanyId=@CompanyId and SalesRecovery=1)
	Begin
		declare @HSNo int
		select @HSNo=isnull(max(HSNo),0)+1 from invSalesHeaderHistory where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
		exec spSaveSalesHistory @CompanyId=@CompanyId,@PeriodId=@PeriodId,@VtypeId=@VtypeId,@No=@No,@HSNo=@HSNo
	End

	delete invSalesHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesPropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesAdditions where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invPrivilegeCardSales where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesProductSerialNumber where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesTrayDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No

	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	delete aTransaction where ModuleID=1 and VoucherTypeID = @VoucherTypeID and [No] = @No and CompanyID=@CompanyID and PeriodID=@PeriodID
	set @Sync=1
end	
  	
insert invSalesHeader([CompanyID],[PeriodID],[VtypeId],[No],[Date],[DeliveryDate],[CustomerId],[PaymentMode],
[SalesManId],[RateLevelId],[DueDate],[QuotationNo],[Total],[DiscountP],[Discount],[NetTotal],
[Notes],[TaxCalculation],[Tax],[SalesReturn],[Rep1],[Rep2],[Paid],[RoundOff],[AirwayBillNo],
Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnId,CostCentreId,ShippingId,ShippingNo,CreditCardID,
[Address],InterState,CardId,PaidBy,TaxGroupID,BillTax,LocalMobileNo,Sync,Approve,UserId,TokenNo,QRCodeImage,Remark1,Remark2,
Remark3,Remark4,EInvoice,NotEdit,[Remark5],[Remark6],[Remark7],[Remark8],[Remark9],[Remark10],[Remark11],[Remark12],Discount1,
Discount2,Discount3,EWay)
values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@DeliveryDate,@CustomerId,@PaymentMode,nullif(@SalesManId,0),@RateLevelId,@DueDate,@QuotationNo,
@Total,@DiscountP,@Discount,@NetTotal,@Notes,@TaxCalculation,@Tax,@SalesReturn,nullif(@Rep1,0),nullif(@Rep2,0),
nullif(@Paid,0),nullif(@RoundOff,0),nullif(@AirwayBillNo,''),nullif(@Advance,0),@Time,nullif(@FooterAddition,0),
nullif(@PrePrintingString,''),nullif(@FromTime,0),nullif(@ToTime,0),nullif(@JobId,0),nullif(@ReturnId,0),nullif(@CostCentreId,0),
nullif(@ShippingId,0),nullif(@ShippingNo,''),nullif(@CreditCardID,0),nullif(rtrim(@Address),''),nullif(@InterState,0),nullif(@CardId,0),nullif(@PaidBy,0),
nullif(@TaxGroupID,0),nullif(@BillTax,0),nullif(@LocalMobileNo,''),@Sync,nullif(@Approve,0),nullif(@UserId,0),nullif(@TokenNo,0),@QRCodeImage,
@Remark1,@Remark2,@Remark3,@Remark4,nullif(@EInvoice,0),nullif(@NotEdit,0),NULLIF(@Remark5,''),NULLIF(@Remark6,''),NULLIF(@Remark7,''),NULLIF(@Remark8,''),NULLIF(@Remark9,''),
NULLIF(@Remark10,''),NULLIF(@Remark11,''),NULLIF(@Remark12,''),nullif(@Discount1,0),nullif(@Discount2,0),nullif(@Discount3,0),@Eway)


--Details Part
declare @Details table(Sno int,ProductId int,SalesmanId int,WarehouseId int,UomId int,Qty float,Foc float,FType int,Pieces float,Rate float,MRP float,Gross float,
					   Addition float,TaxGroupId int,Tax float,DiscountP float,Discount float,Total float,MfrDate int,ExpDate int,Remark nvarchar(1000),BarcodeId int,
					   IType int,IPeriodId int,INo int,ISno int,IQty float,IFOC float,SerialNoId int,ARate float,Length float,Width float,Addition1 float,Addition2 float,Cost float,Remark1 nvarchar(100))

declare @Idoc int
exec sp_xml_preparedocument @Idoc out,@XmlProductDetails

insert @Details
([Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1)
select [Sno],[ProductId],nullif([WarehouseId],0),isnull(nullif([UomId],0),1),[Qty],[Foc],nullif([Pieces],0)[Pieces],
[Rate],MRP,[Gross],nullif(Addition,0) Addition,nullif([TaxGroupId],0),[Tax],[DiscountP],
[Discount],[Total],
case when @Date<>convert(varchar,[MfrDate],112) then convert(varchar,[MfrDate],112) end,
case when @Date<>convert(varchar,[ExpDate],112) then convert(varchar,[ExpDate],112) end,
nullif([Remark],'') [Remark],isnull([BarcodeId],0),nullif([IType],0) [IType],nullif(IPeriodId,0),nullif([INo],0) [INo],
case when IType>0 then isnull(ISno,0) end,nullif([IQty],0) [IQTy], nullif([IFOC],0) [IFOC],nullif([SerialNoId],0) SerialNoId,nullif(SalesmanId,0),
case when [Foc] = 0 then null else [FType] end,nullif(case when Rate<>ARate then ARate end,0),nullif(Length,0),nullif(Width,0),nullif(Addition1,0),nullif(Addition2,0),nullif(Cost,0),nullif(Remark1,'')
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
ProductId      int '@ProductId',
SalesmanId     int '@SalesmanId',
WarehouseId    int '@WarehouseId',
UomId          int '@UomId',
Qty            float '@Qty',
Foc            float '@Foc',
FType          int   '@FType',
Pieces         float '@Pieces',
Rate           float '@Rate',
MRP            float '@MRP',
Gross          float '@Gross',
Addition       float '@Addition', 
TaxGroupId     int '@TaxGroupId',
Tax            float '@Tax',
DiscountP      float '@DiscountP',
Discount       float '@Discount',
Total          float '@Total',
MfrDate        datetime '@MfrDate',
ExpDate        datetime '@ExpDate',
Remark         nvarchar(1000) '@Remark',
BarcodeId      int '@BarcodeId',
IType		   int '@IType',
IPeriodId	   int '@IPeriodId',
INo		       int '@INo',
ISno		   int '@ISno',
IQty		   float '@IQty',
IFOC           float '@IFOC',
SerialNoId     int '@SerialNoId',
ARate          float '@ARate' ,
Length         float '@Length' ,
Width          float '@Width' ,
Addition1      float '@Addition1',
Addition2      float '@Addition2',
Cost           float '@Cost',
Remark1         nvarchar(100) '@Remark1'
)
where ProductId>0

declare @CGSAccountId int
select @CGSAccountId=CostOfGoodsSoldAccountId from invOption where CompanyID = @CompanyID
if @CGSAccountId>0
Begin
	declare @Stock table(CompanyId int,ProductId int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float)
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	update invSalesHeader set BlockStockCalculation=1 where Date=@Date and Time>@Time
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	declare @BeforeCostofGoods float
	select @BeforeCostofGoods=sum(Qty*Rate) from @Stock
End

insert invSalesDetails([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1)
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],nullif([WarehouseId],0),[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1
from @Details

exec sp_xml_removedocument @Idoc


if @CGSAccountId>0
Begin
	delete @Stock
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	update invSalesHeader set BlockStockCalculation=null where Date=@Date and Time>@Time
	declare @AfterCostofGoods float
	select @AfterCostofGoods=sum(Qty*Rate) from @Stock
End

----------------

if isnull(@CardId,0) >0
begin
  declare @PointAccumulationAmount float
  select @PointAccumulationAmount = t2.PointAccumulationAmount from invPrivilegeCardIssue t1
  join invPrivilegeCard t2 on t1.CardId = t2.Id 
  where t1.Id = @CardId

  declare @LessProfitAmount float
  select @LessProfitAmount=sum(Total) from @Details d join invProduct p on d.ProductId=p.Id where p.LessProfit=1

  insert invPrivilegeCardSales([CompanyID],[PeriodID],[VtypeId],[No],CardId,BillAmount,Points,Redempted)
  select @CompanyID,@PeriodID,@VtypeId,@No,@CardId,@NetTotal,(@NetTotal-isnull(@LessProfitAmount,0))/@PointAccumulationAmount,@Redempted
  where isnull(@PointAccumulationAmount,0) > 0
end 


--Property

exec sp_xml_preparedocument @Idoc out,@XmlPropertyDetails
insert invSalesPropertyDetails(CompanyID,PeriodID,[VtypeId],[No],[Sno],[ProductId],[SubPropertyId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno int '@Sno',
ProductId int '@ProductId',
SubPropertyId int '@SubPropertyId'
)

exec sp_xml_removedocument @Idoc
--Additions
	declare @SalesAdditions table(CreditorID int,DebtorID int,Description varchar(100),Amount float)
	exec sp_xml_preparedocument @Idoc out,@XmlAdditions
	insert @SalesAdditions(CreditorID,DebtorID,Description,Amount)
	select CreditorID,DebtorID,nullif(Description,''),Amount from openxml (@Idoc,'/TableHeader/Table1',2)
	with
	(
	CreditorID  int '@CreditorID',
	DebtorID    int '@DebtorID',
	Description varchar(100) '@Description',
	Amount      float '@Amount'
	)
	where Amount>0
	exec sp_xml_removedocument @Idoc

	insert invSalesAdditions(CompanyId,PeriodId,VtypeId,No,CreditorID,DebtorID,Description,Amount)
	select @CompanyId,@PeriodId,@VtypeId,@No,CreditorID,DebtorID,Description,Amount from @SalesAdditions

 --Sales Product Serial Number (Bulk Saving)
 exec sp_xml_preparedocument @Idoc out,@XmlProductSno  
 insert invSalesProductSerialNumber([CompanyId],[PeriodId],[VtypeId],[No],[USno],[Sno],[ProductId],[SerialNoId],SerialNo)  
 select @CompanyId,@PeriodId,@VtypeId,@No,[USno],[Sno],[ProductId],nullif([Id],0),case when Id=0 then SerialNo end from openxml (@Idoc,'/TableHeader/Table1',2)  
 with  
 (  
 USno int '@USno',  
 Sno int '@Sno',  
 ProductId int '@ProductId',
 Id int '@Id',
 SerialNo varchar(100) '@SerialNo'
 )  
 exec sp_xml_removedocument @Idoc  

  
-- Tray Details
 
 exec sp_xml_preparedocument @Idoc out,@XmlTray  
 insert invSalesTrayDetails([CompanyId],[PeriodId],[VtypeId],[No],ProductID,OB,[In],[Out],Balance)  
 select @CompanyId,@PeriodId,@VtypeId,@No,ProductID,[OB],[In],[Out],Balance  from openxml (@Idoc,'/TableHeader/Table1',2)  
 with  
 (  
 ProductID int '@ProductID',
 [OB] int '@OB', 
 [In] int '@In',  
 [Out] int '@Out',   
 Balance int '@Balance'
  
 )  
 exec sp_xml_removedocument @Idoc  


--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and CompanyId=@CompanyId) 
   and exists(select 1 from invProjectSettings where isnull(DisablePostingInSales,0)=0 and CompanyId=@CompanyId)
   and isnull(@EInvoice,0) not in(2,4)
Begin
	if @PaymentMode=0  and isnull(@PaidBy,0)=0
		set @Paid=0
	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	declare @SalesAccountID int,
	        @DiscountAccountID int,
	        @CashInHandID int,
	        @SalesRoundOffAccount int,
			@CreditCard int,
			@AdditionAccountID int,
			--@CGSAccountId int,
			@PurchaseAccountID int
	
	
	--select @SalesRoundOffAccount = SalesRoundOffAccount,@AdditionAccountID=AdditionAccount,@CashInHandID=nullif(SalesCashAccountId,0),@CGSAccountId=CostOfGoodsSoldAccountId from invOption where CompanyID = @CompanyID        
	select @SalesRoundOffAccount = SalesRoundOffAccount,@AdditionAccountID=AdditionAccount,@CashInHandID=nullif(SalesCashAccountId,0) from invOption where CompanyID = @CompanyID        
	select @SalesAccountID=Sales,@DiscountAccountID=DiscountPaid,@CashInHandID=isnull(@CashInHandID,CashInHand),@CreditCard=CreditCard,@PurchaseAccountID=Purchase from aAccountSettings where CompanyID=@CompanyID
	select @CreditCard=AccountId from aCreditCard where Id=@CreditCardId and AccountId>0
	select @CostCentreId=CostCentreId from invCostCentre where Id=@CostCentreId
	select @CostCentreId=nullif(@CostCentreId,0)

	select @CashInHandID=AccountID from invSalesman where Id=@SalesManId and AccountID>0

	--Footer Addition
	declare @FooterAdditionToPost float
	if not exists(select top 1 1 from @SalesAdditions) and @FooterAddition<>0
	Begin
		set @FooterAdditionToPost=@FooterAddition
	End

	declare @PNetTotal float
	select @PNetTotal=@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+ isnull(@FooterAdditionToPost,0) - isnull(@SalesReturn,0) + isnull(@BillTax,0)
	--select @PNetTotal=@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+ isnull(@FooterAdditionToPost,0) + isnull(@BillTax,0)
	if @PaymentMode=0 --Cash
	Begin
		--Paid
		if @Paid>0
		Begin
			if @PNetTotal<>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@SalesAccountID,@PNetTotal-isnull(@Advance,0)-isnull(@Paid,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Payment In Sales',@CostCentreId) 

		End
		Else
		Begin
			if @PNetTotal<>0
				--Net Total
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@SalesAccountID,@PNetTotal-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 
		End

		if @Advance>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,@SalesAccountID,@Advance,'Advance Adjustment',@CostCentreId) 
	End

	if @PaymentMode in(1,2) --Credit
	Begin
		--Paid
		if @Paid>0
		Begin
			if exists(select 1 from invOption where CompanyID=@CompanyID and SalesPostPaidSeparately=1)
			Begin
				if @PNetTotal<>0
					insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
					values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal,'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo,CostCentreId,CreditCardID)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@CustomerId,@Paid,'Payment In Sales',1,@CostCentreId,nullif(case when @PaidBy=1 then @CreditCardID end,0)) 	
			End
			Else
			Begin
				if (@PNetTotal-isnull(@Paid,0))<>0
					insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
					values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal-isnull(@Paid,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo,CostCentreId,CreditCardID)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Payment In Sales',1,@CostCentreId,nullif(case when @PaidBy=1 then @CreditCardID end,0)) 
			End
		End
		Else
		Begin
			--if @PNetTotal<>0
				--Net Total
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal,'Sales '+ substring(@Notes,1,90) + @AirwayBillNo+isnull(' '+@Description,''),@CostCentreId) 
		End
	End
	if @PaymentMode=3 --Credit Card
	Begin
		--Paid
		if @Paid>0
		Begin
			if (@PNetTotal-@Paid>0)
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditCard,@SalesAccountID,@PNetTotal-@Paid-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,nullif(@CreditCardID,0),@CostCentreId) 

			if (@Paid>@PNetTotal)
				set @Paid=@PNetTotal

			if @Paid>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Sales',@CostCentreId) 
		End
		Else
			--Net Total
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditCard,@SalesAccountID,@PNetTotal-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,nullif(@CreditCardID,0),@CostCentreId) 


		if @Advance>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,@SalesAccountID,@Advance,'Advance Adjustment',@CostCentreId) 
	End
	--Discount
	if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DiscountAccountID,@SalesAccountID,@Discount,'Sales Discount',@CostCentreId) 
	--Tax
	if @Tax>0
	Begin
		declare  @TaxAccountID int
		select @TaxAccountID=OutPutTaxAccount from invOption
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@TaxAccountID,@Tax,'Sales Tax',@CostCentreId) 
	End

	--Bill Tax
	if @BillTax>0
	Begin
		select @TaxAccountID=OutPutTaxAccount from invOption
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@TaxAccountID,@BillTax,'Sales Tax',@CostCentreId) 
	End

	--Addition
	if @Addition>0
	Begin
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,isnull(@AdditionAccountID,0),@Addition,'Addition In Sales',@CostCentreId) 
	End
	
	--Addition2
	if @Addition2>0
	Begin
		select @AdditionAccountID=isnull(SalesAddition2AccountId,@AdditionAccountID) from invOption where CompanyId=@CompanyId
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,isnull(@AdditionAccountID,0),@Addition2,@CostCentreId) 
	End

	--Footer Addition
	if @FooterAdditionToPost<>0
	Begin
        declare @SalesAdditionAccount int
		select @SalesAdditionAccount=SalesAdditionAccount from invOption where CompanyId=@CompanyId
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@SalesAdditionAccount,@FooterAdditionToPost,@CostCentreId) 
	End

	--Round off
	if ISNULL(@SalesRoundOffAccount,0) >  0 and @RoundOff <> 0
	begin
		if @RoundOff > 0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@SalesRoundOffAccount,@RoundOff,@CostCentreId) 
		else 
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		    values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesRoundOffAccount,@SalesAccountID,abs(@RoundOff),@CostCentreId) 	
	end

	--Additions
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,1,DebtorID,CreditorID,Amount,Description,@CostCentreId from @SalesAdditions


	--Product Account
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,p.AccountId,sum(d.Gross),p.Name,@CostCentreId from @Details d join invProduct p on d.ProductId=p.Id where p.AccountId is not null group by p.AccountId,p.Name


	if @CGSAccountId>0
	Begin
		--Cost Of Goods Sold

		--declare @CGS table(Date int,ProductID int,BarcodeID int,Rate float,CP float,SRate float)

		--insert tmpTable(Id,SPID)
		--select distinct ProductId,@@SPID from @Details

		--insert @CGS
		--exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=15

		declare @Cost float

		--select @Cost=sum(c.Rate*(d.Qty+d.Foc)*u.Secondary) from @CGS c join @Details d on c.ProductId=d.ProductId join (select distinct ProductId,UomId,Secondary from invUOMLevels)u on c.ProductId=u.ProductId and d.UOMId=u.UOMId

		set @Cost = isnull(@BeforeCostofGoods,0)-isnull(@AfterCostofGoods,0)

		if @Cost<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
			select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CGSAccountId,@PurchaseAccountId,@Cost,'Sales',@CostCentreId --from @CGS --having sum(CP)<>0

	End

End

if @JobId >0 and (select isnull(Status,0) from invJobCustomization) =  0	
  update InvJobForm Set Status=1 where ID=@JobId
Commit

if @Export=1
	exec prExportSales @CompanyID=@CompanyID,@PeriodID=@PeriodID,@VtypeID=@VtypeID,@ExportNo=@No

select @No No,@Message Message,@HSNo HSNo

go

if OBJECT_ID('prSaveJobInvoice') is not null
	drop proc prSaveJobInvoice
go

create proc prSaveJobInvoice
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int,
@Date int,
@JobId int,
@Amount float,
@Notes nvarchar(max),
@RefNo varchar(25),
@OutVno int output,
@XmlProductDetails xml,
@Discount float,
@Cash float,
@Card float,
@CustomerId int,
@CreditCardID int,
@SalesmanID int,
@JobTotal float,
@TaxGroupID int,
@Tax float,
@EInvoice int = null,
@Remark1 nVarchar(500) =null,
@Remark2 nVarchar(500) =null,
@Remark3 nVarchar(500) =null,
@Remark4 nVarchar(500) =null

as
set nocount on
set xact_abort on
declare @Id int

set @OutVno = 0

begin tran

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetJobInvoiceMaxVno
    @CompanyId = @CompanyId,
    @PeriodId = @PeriodId,
    @VtypeId = @VtypeId

    select @No = [No] from @T1 
	
  end
else
   begin
     exec prDeleteJobInvoice
     @CompanyId = @CompanyId,
     @PeriodId = @PeriodId,
     @VtypeId = @VtypeId,
     @No = @No 
   end    


   insert invJobInvoice(CompanyID,PeriodID,VtypeId,No,Date,JobId,Amount,Notes,RefNo,Discount,Cash,Card,CustomerId,CreditCardID,JobTotal,SalesmanID,TaxGroupID,Tax,EInvoice,Remark1,Remark2,Remark3,Remark4)
   values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@JobId,@Amount,@Notes,@RefNo,@Discount,nullif(@Cash,0),nullif(@Card,0),nullif(@CustomerId,0),nullif(@CreditCardID,0),@JobTotal,nullif(@SalesmanID,0),nullif(@TaxGroupID,0),nullif(@Tax,0),@EInvoice,nullif(@Remark1,''),nullif(@Remark2,''),nullif(@Remark3,''),nullif(@Remark4,''))    


declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert invJobInvoiceDetails
([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[WorkId],[Qty],[Rate],[AMount],[EmployeeId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[WorkId],[Qty],[Rate],[AMount],nullif(EmployeeId,0)
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
WorkId         int '@WorkId',
EmployeeId     int '@EmployeeId', 
Qty            float '@Qty',
Rate           float '@Rate',
Amount         float '@Amount'
)
where WorkId>0

exec sp_xml_removedocument @Idoc

	


--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and CompanyId=@CompanyId) and isnull(@EInvoice,0) not in(2,4)
Begin


	declare @JobInvoiceAccount int,
	        @DiscountAccountID int,
	        --@CashInHandID int,
		@VoucherTypeID int
		--@CreditCard int

	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	select @JobInvoiceAccount = JobInvoiceAccount from invOption where CompanyID=@CompanyID


    if isnull(@VoucherTypeID,0) > 0 and isnull(@JobInvoiceAccount,0) > 0
    begin

		declare @Code nvarchar(50),@Name nvarchar(100)
		select @Code = 'Job '+ JobNo,@Name=Customer from invJobForm where ID = @JobId

		if (@Amount - isnull(@Cash,0) - isnull(@Card,0)) >0 and @CustomerId = 0
		begin	
			select @CustomerId=ID from aAccount where Code=@Code

			if @CustomerId = 0
			Begin
				--Insertion to account
				declare @t table(ID int,Status tinyint,Message varchar(100))

				declare @UnderID int
				select @UnderID=Customers from aAccountSettings

				declare @AccountSubGroupID int
				select @AccountSubGroupID=AccountSubGroupID from aAccount where ID=@UnderID

				insert @t 
				exec spSaveAccount @ID=@CustomerId,@Code=@Code,@Name=@Name,@AccountSubGroupID=@AccountSubGroupID,
				@UnderAccountID=@UnderID,@OB=null,@DrCr=null,@CompanyID=1,
				@ModuleID=1,@IsAllowDuplicateName=1

				select @CustomerId =ID from @t where Status=0

				delete invCustomer where AccountId = @CustomerId
				insert invCustomer (CompanyId,AccountId,Name) select @CompanyId,@CustomerId,@Name where @CustomerId > 0

			End

	    	

        end
	        
	      
	  if @CustomerId = 0
		select @CustomerId=ID from aAccount where Code=@Code

			update invJobInvoice set CustomerId = nullif(@CustomerId,0) 
            where CompanyId = @CompanyId and
            PeriodId = @PeriodId and
            VtypeId = @VtypeId and
            No = @No

  
	  if @CustomerId > 0
      begin
	     --Net Total
         insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,SNo)
	     values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@JobInvoiceAccount,@Amount,'Job Invoice ' + @RefNo,nullif(@CreditCardID,0),1) 		

		 if @Cash <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@CustomerId,@Cash,'Cash Payment (Job Invoice ' + @RefNo + ')',2 from aAccountSettings where CompanyId=@CompanyId

		 if @Card <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@CustomerId,@Card,'Card Payment (Job Invoice ' + @RefNo + ')',3 from aAccountSettings where CompanyId=@CompanyId

	  end	
  


   	  if @CustomerId = 0 
	  begin 		
     --   --Net Total
	    --insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,SNo)
	    --values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@JobInvoiceAccount,@Amount,'Job Invoice ' + @RefNo,nullif(@CreditCardID,0),1) 

		if @Cash <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@JobInvoiceAccount,@Cash,'Cash Payment (Job Invoice ' + @RefNo + ')',2 from aAccountSettings where CompanyId=@CompanyId

		 if @Card <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@JobInvoiceAccount,@Card,'Card Payment (Job Invoice ' + @RefNo + ')',3 from aAccountSettings where CompanyId=@CompanyId


      end   

	  
	  --Discount
	  if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,DiscountPaid,@JobInvoiceAccount,@Discount,'Job Invoice Discount ' + @RefNo from aAccountSettings where CompanyID=@CompanyID

 	  --Tax
	  if @Tax<>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@JobInvoiceAccount,OutPutTaxAccount,@Tax,'Job Invoice Tax ' + @RefNo from invOption where CompanyID=@CompanyID
		

	end	

End

set @OutVno = @No

commit tran

go

if object_id('spGetInvSalesDetails') is not null
	drop proc spGetInvSalesDetails  
go
  
create proc spGetInvSalesDetails  
@CompanyID int,  
@PeriodID int,  
@VtypeID int,  
@No int  

as  

set transaction isolation level read uncommitted

declare @SalesDetails Table(SNo int,Code varchar(50),Product nvarchar(200),Packing nvarchar(500),OtherLanguage nvarchar(200),Qty float,
Rate float,MRP float,DP float,Discount float,Gross float,[Net Amount] float,[Vat Amount] float,Total float,Pieces float,
OutPutTax float,MDate smalldatetime,ExpDate smalldatetime,Remark nvarchar(1000),FOC float,Property1 varchar(50),Property2 varchar(50),
Property3 varchar(50),Property4 varchar(50),Property5 varchar(50),Property6 varchar(50),Barcode varchar(50),Uom nvarchar(50),
HUOM varchar(50),ProductID int,UOMID int,
SerialNo nvarchar(100),Box varchar(50),CategoryCode varchar(50),ST varchar(10),Addition float,Addition1 float,Addition2 float,
NOP float,PProperty1 varchar(50),PProperty2 varchar(50),PProperty3 varchar(50),PProperty4 varchar(50),PProperty5 varchar(50),
PProperty6 varchar(50),PProperty7 varchar(50),Remark1 nvarchar(1000))  
  
insert @SalesDetails(SNo,Code,Product,Packing,OtherLanguage,Qty,Rate,MRP,DP,Discount,Gross,[Net Amount],[Vat Amount],Total,Pieces,OutPutTax,
MDate,ExpDate,Remark,FOC,Barcode,Uom,HUOM,ProductID,UOMID,SerialNo,Box,Addition,Addition1,Addition2,NOP,Remark1)  
select s.Sno,p.Code,p.Name Product,p.Packing,p.OtherLanguage,s.Qty,
s.Rate,s.MRP,s.DiscountP,S.Discount,s.Gross,   
s.Gross - s.discount  [Net Amount],s.tax  [Vat Amt],  
s.Total,s.Pieces,s.TaxGroupID,  
cast(cast(s.MfrDate as varchar) as smalldatetime)MDate,
--substring(CAST(s.ExpDate as varchar),5,2) + '/' + substring(CAST(s.ExpDate as varchar),1,4)  ExpDate,
cast(cast(s.ExpDate as varchar) as smalldatetime)ExpDate,
replace(S.Remark,'|',char(13)+char(10)),
S.Foc,s.BarcodeID,u.name,u.name,s.ProductId,s.UOMID,sn.SerialNo,1,s.Addition,Addition1,Addition2,1,s.Remark1 from invSalesDetails s  
join invProduct p on s.ProductId=p.Id  
join invUom u on s.UomId=u.Id  
left outer join invProductSerialNumber sn on s.SerialNoId = sn.Id
where s.companyid = @CompanyID and s.periodId = @PeriodId and s.VtypeId=@VtypeID and s.No=@No  


--HideQty
if exists(select 1 from invHideQtyInPrint)
Begin
	declare @CustomerID int
	select @CustomerID=CustomerId from invSalesHeader where companyid = @CompanyID and periodId = @PeriodId and VtypeId=@VtypeID and No=@No
	update sd set sd.Qty=0 from @SalesDetails sd join invHideQtyInPrint hq on sd.ProductID=hq.ProductID where hq.CustomerID=@CustomerID
End


--Category Code
declare @CategoryPropertyId int
select @CategoryPropertyId = isnull(CategoryPropertyId,0) from invOption where CompanyId = @CompanyId

update t1 set t1.CategoryCode = t3.Code from  @SalesDetails t1
join invProductPropertyDetails t2 on t1.ProductId = t2.ProductId and t2.PropertyId = @CategoryPropertyId
join invProductSubProperty t3 on t2.SubPropertyId = t3.Id
-----------

--Out Put Tax
update sd set sd.OutPutTax=t.OutPutTax from @SalesDetails sd join invTaxGroup t on sd.OutPutTax = t.Id

--Barcode
update sd set sd.Barcode=b.Barcode from @SalesDetails sd join invAutoBarcodeAndSalesRate b on sd.ProductId = b.ProductId and sd.Barcode = b.BarcodeId

--UBC
update sd set sd.Barcode=u.Barcode from @SalesDetails sd join invUomLevels u on sd.ProductId = u.ProductId and sd.UOMID = u.UomId where isnull(sd.Barcode,'0')='0'

--Higher Measurement  
update s set s.HUOM=u.name,s.NOP=ul.Multiplayer from invUOM u join invUOMLevels ul on u.id=ul.UOMID join @SalesDetails s on s.ProductID=ul.ProductID and s.UOMID=ul.UnitID and ul.Secondary<>1 and ul.SNo<3

--Properties  
declare @Property table(Ord tinyint,SNo int,Property varchar(100))  
  
insert @Property  
select Ord,sd.SNo,sp.Name  
from   
(select row_number() over (partition by (select 1) order by ID)Ord,* from invPurchaseProperty) p  
cross join @SalesDetails sd  
join invPurchaseSubProperty sp on p.ID=sp.PropertyID  
join invSalesPropertyDetails spd on sd.sno=spd.sno and sp.ID=spd.SubPropertyID  
where spd.CompanyID=@CompanyID and spd.PeriodID=@PeriodID and spd.VTypeID=@VTypeID and spd.No=@No  
  
update sd set sd.Property1=p.Property from @SalesDetails sd join @Property p on sd.sno=p.sno where p.Ord=1  
update sd set sd.Property2=p.Property from @SalesDetails sd join @Property p on sd.sno=p.sno where p.Ord=2  
update sd set sd.Property3=p.Property from @SalesDetails sd join @Property p on sd.sno=p.sno where p.Ord=3  
update sd set sd.Property4=p.Property from @SalesDetails sd join @Property p on sd.sno=p.sno where p.Ord=4 
update sd set sd.Property5=p.Property from @SalesDetails sd join @Property p on sd.sno=p.sno where p.Ord=5  
update sd set sd.Property6=p.Property from @SalesDetails sd join @Property p on sd.sno=p.sno where p.Ord=6

--Product Properties  
update sd set sd.PProperty1=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=1
update sd set sd.PProperty2=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=2
update sd set sd.PProperty3=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=3
update sd set sd.PProperty4=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=4
update sd set sd.PProperty5=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=5
update sd set sd.PProperty6=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=6
update sd set sd.PProperty7=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @SalesDetails sd on ppd.ProductID=sd.ProductId where psp.PropertyId=7


--Box
update sd set sd.Box=cast(floor(Qty/n.MultiPlayer) as varchar)+'.'+cast(convert(int,floor(Qty))%convert(int,floor(n.MultiPlayer)) as varchar) from @SalesDetails sd join invUOMLevels n on sd.ProductID=n.ProductID and n.Secondary<>1 and n.SNo<3  and floor(n.MultiPlayer)<>0

--ST
update @SalesDetails set ST='RETURN' where Qty<0
  

declare @Currency float

select @Currency=Rate from aCurrencySettingsDetails


select *,isnull(@Currency,0) Currency from @SalesDetails  



go


if OBJECT_ID('prGetJobInvoiceForPrint') is not null
	drop proc prGetJobInvoiceForPrint
go

create proc prGetJobInvoiceForPrint
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int as
set nocount on


select t1.No,cast(cast(t1.Date as varchar) as datetime) Date,t1.Amount,t1.Notes,t1.RefNo,t1.Discount,t1.Tax,
t2.JobNo,t3.name [CostCentre],t2.Customer,t1.Cash,t1.Card,t1.JobTotal - isnull(t1.Cash,0) - isnull(t1.Card,0) - isnull(t2.Advance,0) Balance,
t2.VehicleNo,t2.VehicleNo2,t2.ContactNo,t2.Work,t2.AdditionalWork,t2.Colour,t2.ModelNo,
isnull(t2.Advance,0) Advance, t1.JobTotal,t2.ModelName,t2.Year,t1.QRCodeImage,c.* from invJobInvoice t1
join invJobForm t2 on t1.JobId = t2.Id
join invCostCentre t3 on t2.CostCentreId = t3.Id
left join invCustomer c on t2.CustomerId=c.AccountID
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.VtypeId = @VtypeId and t1.[No] = @No 

go


if OBJECT_ID('prGetDeliverdServiceReport') is not null
	drop proc prGetDeliverdServiceReport
go

create proc prGetDeliverdServiceReport
@CompanyID int,
@FromDate int,
@ToDate int,
@Status int,
@StaffID int=null,
@ServiceType int=null
as

set nocount on
set transaction isolation level read uncommitted

declare @Service Table(ServiceID int,Status int)
 
 if @Status=0
 Begin
	insert @Service
	select t1.ID ,case when t4.No is null then 0 else 1 end from invServiceOrder t1 
	join  invServiceHeader t3 on t1.ID=t3.ServiceID 
	left outer join  invServiceInvoice t4 on t1.ID=t4.ServiceID 
	where t1.CompanyId=@CompanyID  and isnull(t3.Date,t1.[Date]) between @FromDate and @ToDate  and t3.Status>0
	and (isnull(t3.DeliveredSalesManID,t1.SalesManID)=@StaffID or isnull(@StaffID,0)=0)
	and (t1.JobWorkID=@ServiceType or isnull(@ServiceType,0)=0)
 End
 else  if @Status=1
 Begin
	insert @Service
	select t1.ID ,case when t4.No is null then 0 else 1 end from invServiceOrder t1 
	join  invServiceHeader t3 on t1.ID=t3.ServiceID 
	left outer join  invServiceInvoice t4 on t1.ID=t4.ServiceID 
	where t1.CompanyId=@CompanyID  and t1.[Date] between @FromDate and @ToDate  and t3.Status=1 and t4.No is null
	and (isnull(t3.DeliveredSalesManID,t1.SalesManID)=@StaffID or isnull(@StaffID,0)=0)
	and (t1.JobWorkID=@ServiceType or isnull(@ServiceType,0)=0)
 End
 else  if @Status=2 
 Begin
	insert @Service
	select t1.ID ,case when t4.No is null then 0 else 1 end from invServiceOrder t1 
	join  invServiceHeader t3 on t1.ID=t3.ServiceID 
	join  invServiceInvoice t4 on t1.ID=t4.ServiceID 
	where t1.CompanyId=@CompanyID  and t4.[Date] between @FromDate and @ToDate  and t3.Status=1  
	and (isnull(t3.DeliveredSalesManID,t1.SalesManID)=@StaffID or isnull(@StaffID,0)=0)
	and (t1.JobWorkID=@ServiceType or isnull(@ServiceType,0)=0)
 End
 else  if @Status=3 
 Begin
	insert @Service
	select t1.ID ,case when t4.No is null then 0 else 1 end from invServiceHeader t3
	left join  invServiceOrder t1 on t1.ID=t3.ServiceID 
	left join  invServiceInvoice t4 on t1.ID=t4.ServiceID 
	where t1.CompanyId=@CompanyID  
	and t3.[Date] between @FromDate and @ToDate
	and t3.Status=2  
	and (isnull(t3.DeliveredSalesManID,t1.SalesManID)=@StaffID or isnull(@StaffID,0)=0)
	and (t1.JobWorkID=@ServiceType or isnull(@ServiceType,0)=0)
 End
 
 
select t1.[No],cast(cast(t1.[Date] as varchar)as smalldatetime)Date,t1.[JobNo],t1.[ProductName],t1.[SerialNo],t1.[Work],
t1.[ProductRemarks],cast(cast(t4.[Date] as varchar)as smalldatetime)DDate,t2.Name Customer,t2.Mobileno,t1.ContactNo,t1.ContactPerson,s.Name Staff,
case when t4.No is null then 'Not Delivered' else (case when t3.Status=2 then 'Returned' else  'Delivered' end) end Status,
t1.Advance ,t1.Amount EstimatedAmount,t1.RecievedItems,t3.ConsumedRate ,t3.Discount ,t3.LocalPurchase ,t3.NetTotal,t3.Notes,t3.ServiceCharge ,
t3.WorkDone ,t3.WorkTotal,w.Name ServiceType  from invServiceOrder t1 
join @Service Sr on t1.Id=Sr.ServiceID
join invJobWork w on t1.JobWorkID=w.Id 
join invCustomer t2 on t1.CustomerId = t2.AccountID
left outer join invSalesman S on  t1.[SalesManID]=S.ID
join  invServiceHeader t3 on t1.ID=t3.ServiceID 
left outer join  invServiceInvoice t4 on t1.ID=t4.ServiceID --and t3.Status<1
 where t1.CompanyId=@CompanyID  --and t1.[Date] between @FromDate and @ToDate  
 and t3.Status>0 order by t1.No
 
go

if OBJECT_ID('prGetJobInvoiceForPrint') is not null
	drop proc prGetJobInvoiceForPrint
go

create proc prGetJobInvoiceForPrint
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int as
set nocount on


select t1.No,cast(cast(t1.Date as varchar) as datetime) Date,t1.Amount,t1.Notes,t1.RefNo,t1.Discount,t1.Tax,
t2.JobNo,t3.name [CostCentre],t2.Customer,t1.Cash,t1.Card,t1.JobTotal - isnull(t1.Cash,0) - isnull(t1.Card,0) - isnull(t2.Advance,0) Balance,
t2.VehicleNo,t2.VehicleNo2,t2.ContactNo,t2.Work,t2.AdditionalWork,t2.Colour,t2.ModelNo,
isnull(t2.Advance,0) Advance, t1.JobTotal,t2.ModelName,t2.Year,t1.QRCodeImage,c.*,v.InvoiceFormat from invJobInvoice t1
join invJobForm t2 on t1.JobId = t2.Id
join invCostCentre t3 on t2.CostCentreId = t3.Id
left join invCustomer c on t2.CustomerId=c.AccountID
left join invVoucherTypeStartNo v on v.CompanyId=@CompanyID and v.PeriodId=@PeriodID and v.VtypeId=@VtypeID 
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.VtypeId = @VtypeId and t1.[No] = @No 

go


