create table #SSales(CompanyId  int,ProductId int,PQty float, SQty float,CostRate float,Sales float,Stock float)
insert #SSales(CompanyId,ProductId,SQty,CostRate,Sales) 
select CompanyId,ProductId,sum(Qty),sum(Cost)/nullif(sum(Qty),0),sum(Sales) from #Sales 
group by CompanyId,ProductId 
---------------------
 update t1  set t1.PQty=t2.PQty,t1.CostRate=t2.Cost* t2.PQty from #SSales t1 join #Products t2 on t1.ProductId=t2.ProductId
 
  update t1  set t1.Stock=t2.Qty  from #SSales t1 join #t1 t2 on t1.ProductId=t2.ProductId
 

select t2.Name,t1.PQty [Purchase Qty],t1.CostRate,t1.SQty[Sales Qty],t1.Sales,t1.Stock [Current Stock]  from #SSales t1 join invProduct t2 on t1.ProductId=t2.Id


