if OBJECT_ID ('prGetNextJobNo')is not null 
	drop proc prGetNextJobNo

go

create proc prGetNextJobNo

as
set nocount on

declare @Prefix varchar(50)    
declare @Size int    
declare @Code varchar(50)


select @Prefix=isnull(max(Left(JobNo, PatIndex('%[0-9]%', JobNo + '1') - 1)),''),@Size=isnull(max(len(JobNo)),0) from invJobForm
where isnumeric(JobNo)=0

select @Code=isnull(max(cast(replace(JobNo,@Prefix,'') as numeric)),0)+1 from invJobForm
where PATINDEX('%[^0-9]%',replace(JobNo,@Prefix,'')) = 0 and len(replace(JobNo,@Prefix,'')) > 0 and JobNo like @Prefix+'%'

if len(@Prefix+@Code)>@Size set @Size=len(@Prefix+@Code)
select @Prefix+replicate('0',@Size-len(@Prefix+@Code))+@Code No 

go


if OBJECT_ID('prCompanyTransferPrint1') is not null
	drop proc prCompanyTransferPrint1
go

create proc prCompanyTransferPrint1
@PeriodId int,
@No int as

set nocount on
set transaction isolation level read uncommitted

declare @Details table(SNo int,ProductID int,Code varchar(50),Particulars nvarchar(200),UOMId int,UOM varchar(50),Qty float,Rate float,SRate float,Total float,Property1 varchar(50),Property2 varchar(50),Property3 varchar(50),Remark nvarchar(100),SerialNoId int,Barcode varchar(50),TaxGroupId int,TaxP float,Tax float,BarcodeId int,PProperty1 varchar(100),PProperty2 varchar(100),PProperty3 varchar(100),PProperty4 varchar(100),PProperty5 varchar(100),PProperty6 varchar(100),PProperty7 varchar(100))

insert @Details(SNo,ProductID,Code,Particulars,UOMId,UOM,Qty,Rate,SRate,Total,Remark,SerialNoId,TaxGroupId,Tax,BarcodeId)
select t1.[Sno],t1.ProductID,t2.Code,t2.Name Particulars,t1.UomId,
t4.Name Uom,t1.[Qty],t1.[Rate],t1.SRate,t1.[Total],t1.Remark,t1.SerialNoId,t2.TaxGroupId,t1.Tax,t1.BarcodeId from invCompanyTransferDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
join invUom t4 on t1.UomId = t4.Id 
where t1.PeriodId = @PeriodId and t1.[No] = @No 
order by t1.Sno 

--TaxP
update d set d.TaxP=t.OutputTax from @Details d join invTaxGroup t on d.TaxGroupId=t.Id

--Properties  
declare @Property table(Ord tinyint,SNo int,Property varchar(100))  
  
insert @Property  
select Ord,sd.SNo,sp.Name  
from   
(select row_number() over (partition by (select 1) order by ID)Ord,* from invPurchaseProperty) p  
cross join @Details sd  
join invPurchaseSubProperty sp on p.ID=sp.PropertyID  
join invCompanyTransferPropertyDetails spd on sd.sno=spd.sno and sp.ID=spd.SubPropertyID  
where spd.PeriodID=@PeriodID and spd.No=@No  
  
update sd set sd.Property1=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=1  
update sd set sd.Property2=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=2  
update sd set sd.Property3=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=3  

--Barcode
update d set d.Barcode=u.Barcode from @Details d join invUOMLevels u on d.ProductId=u.ProductId and d.UomId=u.UomId

--AutoBarcode
update d set d.Barcode=b.Barcode from @Details d join invAutoBarcodeAndSalesRate b on d.ProductId=b.ProductId and d.BarcodeId=b.BarcodeId


--Product Properties  
update sd set sd.PProperty1=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=1
update sd set sd.Property2=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=2
update sd set sd.Property3=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=3
update sd set sd.PProperty4=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=4
update sd set sd.PProperty5=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=5
update sd set sd.PProperty6=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=6
update sd set sd.PProperty7=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=7

--Serial No to Summary

declare @CTPS table(No int,SNo int,USNo int,SerialNoID int)
insert @CTPS
select No,SNo,USNo,SerialNoID from invCompanyTransferProductSerialNumber where PeriodId=@PeriodId and No=@No

declare @DetailsSummary table(MinSNo int,MaxSNo int,ProductID int,SerialNo varchar(8000),Qty float,Rate float,Total float,Property1 varchar(50),Property2 varchar(50),Property3 varchar(50),UOMId int)

insert @DetailsSummary(MinSNo,MaxSNo,ProductID,Qty,Rate,Total,Property1,Property2,Property3,UOMId)
select min(ctps.SNo),max(ctps.SNo),d.ProductId,d.Qty,d.Rate,sum(d.Total)Total,d.Property1,d.Property2,d.Property3,d.UOMId from @Details d
left join @CTPS ctps on @No=ctps.No and d.SNo=ctps.USno
group by d.ProductId,d.Qty,d.Rate,d.Property1,d.Property2,d.Property3,d.UOMId

declare @Counter int
select @Counter=max(MaxSno-MinSno) from @DetailsSummary

while @Counter>=0
Begin
	update s set s.SerialNo=ps.SerialNo+isnull(', '+s.SerialNo,'') from @DetailsSummary s 
	join @Details d on s.ProductID=d.ProductID and s.Rate=d.Rate and isnull(s.Property1,'')=isnull(d.Property1,'') and isnull(s.Property2,'')=isnull(d.Property2,'') and isnull(s.Property3,'')=isnull(d.Property3,'') and s.UOMId=d.UOMId --and d.SNo=s.MinSNo+@Counter
	join @CTPS ctps on @No=ctps.No and d.SNo=ctps.USNo and (@Counter+1)=ctps.Sno
	join invProductSerialNumber ps on ctps.SerialNoID=ps.Id
	set @Counter=@Counter-1

End

;with ul as
(select ProductId,UOMId,MAX(Barcode)Barcode from invUOMLevels group by ProductId,UOMId)

select ROW_NUMBER()over(order by (select 1))Sno,p.Code,p.Name,p.OtherLanguage,u.Name UOM,ul.Barcode UBC,s.SerialNo,s.Qty,s.Rate,Total,Property1,Property2,Property3 from @DetailsSummary s 
join invProduct p on s.ProductID=p.Id 
join invUOM u on s.UOMId=u.Id
join ul on s.ProductId=ul.ProductId and s.UomId=ul.UomId
order by MinSNo

go

