--Payment Modes
declare @idoc int
exec sp_xml_preparedocument @idoc output,@xmlPaymentModes

declare @PM table(Id int)

insert @PM(Id)
select Id from openxml(@idoc, '/DetailsTable/Table1',2)
with
(
Id int '@Id'
) 
exec sp_xml_removedocument @idoc


update invPaymentModes set Checked=0

update p1 set p1.Checked=1 from invPaymentModes p1 join @PM p2 on p1.Id=p2.Id


go

if OBJECT_ID('prGetOtherUomPurchaseRate') is not null 
	drop proc prGetOtherUomPurchaseRate 
go

create proc prGetOtherUomPurchaseRate
@ProductId int,
@UomId int,
@CompanyId int=1
as
set nocount on

--declare @Rate float,
--		@SRate float

declare @T1 table
(
UBC varchar(50),
Rate float,
Cost float,
SRate float,
Date int,
UOMId int
)


if exists(select 1 from invOption where PurchaseRate=1 and CompanyId=@CompanyId)
Begin
	insert @T1(Rate,Cost,SRate,Date,UOMId)
	select top 1 Rate,CostPrice,SRate,Date,t1.UOMId from invPurchaseDetails t1
	join invPurchaseHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
	where t1.ProductId = @ProductId and t2.CompanyId=@CompanyId
	order by Date desc

	insert @T1(Rate,Cost,SRate,Date,UOMId)
	select top 1 Rate,Rate,SRate,Date,t1.UOMId from invCompanyTransferDetails t1
	join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
	where t1.ProductId = @ProductId and t1.UomId = @UomId  and t2.CompanyTo=@CompanyId
	order by Date desc
	
End	
Else
Begin
	if not exists(select 1 from invOption where isnull(SalesRate,0)=3)
		insert @T1(Rate,Cost,SRate,UOMId)
		select top 1 Rate,CostPrice,SRate,UOMId from invPurchaseDetails t1
		join invPurchaseHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
		where t1.ProductId = @ProductId and t2.CompanyId=@CompanyId
		order by t2.Date desc 
End

if not exists(select 1 from @T1)
	insert @T1(UBC,Rate,SRate)
	select Barcode,Cost,Rate from invUOMLevels where ProductId=@ProductId and UOMId=@UOMId
else
Begin
	update t1 set t1.Rate=t1.Rate/u.Secondary,t1.Cost=t1.Cost/u.Secondary,t1.SRate=t1.SRate/u.Secondary from @T1 t1 join invUOMLevels u on u.ProductId=@ProductId and u.UOMId=t1.UOMId  
	update t set t.UBC=u.Barcode,t.Rate=isnull(t.Rate,u.Cost)*u.Secondary,t.Cost=isnull(t.Cost,u.Cost)*u.Secondary,t.SRate=isnull(t.SRate,u.Rate)*u.Secondary from @T1 t join invUOMLevels u on u.ProductId=@ProductId and u.UOMId=@UOMId
End

select top 1 UBC,Rate,Cost,SRate from @T1 order by date desc

go


