if OBJECT_ID('prCompanyTransferPrint') is not null
	drop proc prCompanyTransferPrint
go

create proc prCompanyTransferPrint
@PeriodId int,
@No int as

set nocount on
set transaction isolation level read uncommitted

declare @Details table(SNo int,ProductID int,Code varchar(50),Particulars nvarchar(200),NameInOL nvarchar(200),UOMId int,UOM varchar(50),Qty float,Rate float,SRate float,Total float,Property1 varchar(50),Property2 varchar(50),Property3 varchar(50),Remark nvarchar(100),SerialNoId int,Barcode varchar(50),TaxGroupId int,TaxP float,Tax float,BarcodeId int,PProperty1 varchar(100),PProperty2 varchar(100),PProperty3 varchar(100),PProperty4 varchar(100),PProperty5 varchar(100),PProperty6 varchar(100),PProperty7 varchar(100))

insert @Details(SNo,ProductID,Code,Particulars,NameInOL,UOMId,UOM,Qty,Rate,SRate,Total,Remark,SerialNoId,TaxGroupId,Tax,BarcodeId)
select t1.[Sno],t1.ProductID,t2.Code,t2.Name Particulars,t2.OtherLanguage,t1.UomId,
t4.Name Uom,t1.[Qty],t1.[Rate],t1.SRate,t1.[Total],t1.Remark,t1.SerialNoId,t2.TaxGroupId,t1.Tax,t1.BarcodeId from invCompanyTransferDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
join invUom t4 on t1.UomId = t4.Id 
where t1.PeriodId = @PeriodId and t1.[No] = @No 
order by t1.Sno 

--TaxP
update d set d.TaxP=t.OutputTax from @Details d join invTaxGroup t on d.TaxGroupId=t.Id

--Properties  
declare @Property table(Ord tinyint,SNo int,Property varchar(100))  
  
insert @Property  
select Ord,sd.SNo,sp.Name  
from   
(select row_number() over (partition by (select 1) order by ID)Ord,* from invPurchaseProperty) p  
cross join @Details sd  
join invPurchaseSubProperty sp on p.ID=sp.PropertyID  
join invCompanyTransferPropertyDetails spd on sd.sno=spd.sno and sp.ID=spd.SubPropertyID  
where spd.PeriodID=@PeriodID and spd.No=@No  
  
update sd set sd.Property1=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=1  
update sd set sd.Property2=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=2  
update sd set sd.Property3=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=3  

--Barcode
update d set d.Barcode=u.Barcode from @Details d join invUOMLevels u on d.ProductId=u.ProductId and d.UomId=u.UomId

--AutoBarcode
update d set d.Barcode=b.Barcode from @Details d join invAutoBarcodeAndSalesRate b on d.ProductId=b.ProductId and d.BarcodeId=b.BarcodeId


--Product Properties  
update sd set sd.PProperty1=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=1
update sd set sd.Property2=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=2
update sd set sd.Property3=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=3
update sd set sd.PProperty4=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=4
update sd set sd.PProperty5=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=5
update sd set sd.PProperty6=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=6
update sd set sd.PProperty7=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @Details sd on ppd.ProductID=sd.ProductId where psp.PropertyId=7


select d.*,s.SerialNo from @Details d
left join invCompanyTransferProductSerialNumber ps on @PeriodID=ps.PeriodID and @No=ps.No and d.SNo=ps.USNo and d.ProductID=ps.ProductID
left join invProductSerialNumber s on (ps.SerialNoID=s.ID or d.SerialNoId=s.Id)

go

if OBJECT_ID('prSaveJobInvoice') is not null
	drop proc prSaveJobInvoice
go

create proc prSaveJobInvoice
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int,
@Date int,
@JobId int,
@Amount float,
@Notes nvarchar(max),
@RefNo varchar(25),
@OutVno int output,
@XmlProductDetails xml,
@Discount float,
@Cash float,
@Card float,
@CustomerId int,
@CreditCardID int,
@SalesmanID int,
@JobTotal float,
@TaxGroupID int,
@Tax float,
@EInvoice int = null,
@Remark1 nVarchar(500) =null,
@Remark2 nVarchar(500) =null,
@Remark3 nVarchar(500) =null,
@Remark4 nVarchar(500) =null

as
set nocount on
set xact_abort on
declare @Id int

set @OutVno = 0

begin tran

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetJobInvoiceMaxVno
    @CompanyId = @CompanyId,
    @PeriodId = @PeriodId,
    @VtypeId = @VtypeId

    select @No = [No] from @T1 
	
  end
else
   begin
     exec prDeleteJobInvoice
     @CompanyId = @CompanyId,
     @PeriodId = @PeriodId,
     @VtypeId = @VtypeId,
     @No = @No 
   end    


   insert invJobInvoice(CompanyID,PeriodID,VtypeId,No,Date,JobId,Amount,Notes,RefNo,Discount,Cash,Card,CustomerId,CreditCardID,JobTotal,SalesmanID,TaxGroupID,Tax,EInvoice,Remark1,Remark2,Remark3,Remark4)
   values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@JobId,@Amount,@Notes,@RefNo,@Discount,nullif(@Cash,0),nullif(@Card,0),nullif(@CustomerId,0),nullif(@CreditCardID,0),@JobTotal,nullif(@SalesmanID,0),nullif(@TaxGroupID,0),nullif(@Tax,0),@EInvoice,nullif(@Remark1,''),nullif(@Remark2,''),nullif(@Remark3,''),nullif(@Remark4,''))    


declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert invJobInvoiceDetails
([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[WorkId],[Qty],[Rate],[AMount],[EmployeeId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[WorkId],[Qty],[Rate],[AMount],nullif(EmployeeId,0)
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
WorkId         int '@WorkId',
EmployeeId     int '@EmployeeId', 
Qty            float '@Qty',
Rate           float '@Rate',
Amount         float '@Amount'
)
where WorkId>0

exec sp_xml_removedocument @Idoc

	


--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and CompanyId=@CompanyId) and isnull(@EInvoice,0) not in(2,4)
Begin


	declare @JobInvoiceAccount int,
	        @DiscountAccountID int,
	        --@CashInHandID int,
		@VoucherTypeID int
		--@CreditCard int

	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	select @JobInvoiceAccount = JobInvoiceAccount from invOption where CompanyID=@CompanyID


    if isnull(@VoucherTypeID,0) > 0 and isnull(@JobInvoiceAccount,0) > 0
    begin

		declare @Code nvarchar(50),@Name nvarchar(100)
		select @Code = 'Job '+ JobNo,@Name=Customer from invJobForm where ID = @JobId

		if (@Amount - isnull(@Cash,0) - isnull(@Card,0)) >0 and @CustomerId = 0
		begin	
			select @CustomerId=ID from aAccount where Code=@Code

			if @CustomerId = 0
			Begin
				--Insertion to account
				declare @t table(ID int,Status tinyint,Message varchar(100))

				declare @UnderID int
				select @UnderID=Customers from aAccountSettings

				declare @AccountSubGroupID int
				select @AccountSubGroupID=AccountSubGroupID from aAccount where ID=@UnderID

				insert @t 
				exec spSaveAccount @ID=@CustomerId,@Code=@Code,@Name=@Name,@AccountSubGroupID=@AccountSubGroupID,
				@UnderAccountID=@UnderID,@OB=null,@DrCr=null,@CompanyID=1,
				@ModuleID=1,@IsAllowDuplicateName=1

				select @CustomerId =ID from @t where Status=0

				delete invCustomer where AccountId = @CustomerId
				insert invCustomer (CompanyId,AccountId,Name) select @CompanyId,@CustomerId,@Name where @CustomerId > 0

			End

	    	

        end
	        
	      
	  if @CustomerId = 0
		select @CustomerId=ID from aAccount where Code=@Code

			update invJobInvoice set CustomerId = nullif(@CustomerId,0) 
            where CompanyId = @CompanyId and
            PeriodId = @PeriodId and
            VtypeId = @VtypeId and
            No = @No

	  declare @PostPaidSeparately bit
	  select @PostPaidSeparately=isnull(SalesPostPaidSeparately,0) from invOption where CompanyID=@CompanyId

	  if @CustomerId > 0
      begin
		 if (@PostPaidSeparately=1)
		 Begin
			 --Net Total
			 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
			 values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@JobInvoiceAccount,@Amount,'Job Invoice ' + @RefNo,1) 		

			 if @Cash <> 0	
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
				select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@CustomerId,@Cash,'Cash Payment (Job Invoice ' + @RefNo + ')',2 from aAccountSettings where CompanyId=@CompanyId

			 if @Card <> 0	
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
				select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@CustomerId,@Card,'Card Payment (Job Invoice ' + @RefNo + ')',3 from aAccountSettings where CompanyId=@CompanyId
		End		
		Else
		Begin
			if (@Amount-isnull(@Cash,0)-isnull(@Card,0))<>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@JobInvoiceAccount,@Amount-isnull(@Cash,0)-isnull(@Card,0),'Job Invoice ' + @RefNo,1) 		
		End
	  end	
  


   	  if (@CustomerId = 0 or @CustomerId>0 and @PostPaidSeparately=0)
	  begin 		

		if @Cash <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@JobInvoiceAccount,@Cash,@RefNo,2 from aAccountSettings where CompanyId=@CompanyId

		 if @Card <> 0	
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo)
            select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@JobInvoiceAccount,@Card,@RefNo,3 from aAccountSettings where CompanyId=@CompanyId


      end   

	  
	  --Discount
	  if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,DiscountPaid,@JobInvoiceAccount,@Discount,'Job Invoice Discount ' + @RefNo from aAccountSettings where CompanyID=@CompanyID

 	  --Tax
	  if @Tax<>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@JobInvoiceAccount,OutPutTaxAccount,@Tax,'Job Invoice Tax ' + @RefNo from invOption where CompanyID=@CompanyID
		

	end	

End

set @OutVno = @No

commit tran

go

if object_id('prExportPurchaseReturn') is not null 
	drop proc prExportPurchaseReturn

go

create proc prExportPurchaseReturn
@CompanyID int,
@PeriodID int,
@VtypeID int,
@ExportNo int

as

set xact_abort on

declare @tCompanyID int
declare @No int

SET @tCompanyID=@CompanyID

declare @TableColumnList varchar(max),
        @ColumnList varchar(max),
        @UpdateColumnList varchar(max)
        

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID

if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Exporting to same DB is not allowable'
	return
End 


if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

		select @RmtSrvName='['+ @RmtSrvName+'].'
end

select @RmtUsrName='dbo'
   
create table #T1(No int)
exec('insert #T1 select No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseReturnHeader where CompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and ExportNo='+@ExportNo)
select @No=max(No) from #T1

--Begin Transaction


if(@No is null)
begin
	exec('insert #T1 exec '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.prGetPurchaseReturnMaxVno '+@tCompanyID+','+@PeriodID+','+@VtypeId)
	select @No = [No] from #T1 
end
else
begin

	exec('delete '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseReturnHeader where CompanyId = '+@tCompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseReturnDetails where CompanyId = '+@tCompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
    exec('delete t from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@No+' and t.CompanyID='+@tCompanyID+' and t.PeriodID='+@PeriodID)

end	


--insertion

--aPeriod
select @UpdateColumnList = dbo.fnGetUpdateColumnList('aPeriod','Id')
exec('update t2 set ' + @UpdateColumnList + ' from aPeriod t1 
      join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aPeriod t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aPeriod'),
       @ColumnList = dbo.fnGetColumnList('aPeriod')

exec('insert '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aPeriod (' + @TableColumnList + ') select ' + @ColumnList + ' from aPeriod t1 
left outer join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aPeriod t2 on t1.Id = t2.Id where t2.Id is null')



--aAccountGroup
