      select VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,TaxGroupId,Tax,Total,MfrDate,ExpDate,Remark,CompanyId,PeriodId from #PurchaseReturnDetails')


