--Commit

select @No

go

if object_id('prSalesTaxB2C') is not null
  drop proc prSalesTaxB2C

go

create proc prSalesTaxB2C
@CompanyId int,
@VTypeId int,
@FromDate int,
@ToDate int 

as 

set transaction isolation level read uncommitted
set nocount on 

select isnull(t6.OutPutTax,0) Rate,sum(t2.Gross - isnull(t2.Discount,0)) Taxable from invSalesHeader t1
join invSalesDetails t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VTypeId = t2.VTypeId and t1.No = t2.No
join aAccount t3 on t1.CustomerId = t3.Id
left outer join (select AccountId,GST from invCustomer union select AccountId,GST from invVendor) t4 on t1.CustomerId = t4.AccountId 
left outer join invTaxGroup t6 on t2.TaxGroupId = t6.Id 
where t1.CompanyId = @CompanyId and (t1.Date between @FromDate and @ToDate) and len(isnull(t4.GST,'')) <> 15 
group by isnull(t6.OutPutTax,0) ORDER BY isnull(t6.OutPutTax,0)

go

if not exists(select name from sys.columns where object_id = object_id('invCustomer') and name = 'Location') 
    exec sp_rename 'invCustomer.Fax','Location'


go

if object_id('prStockReport') is not null
  drop proc prStockReport

go
  
create proc prStockReport 
@To int, 
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@ValueDataWhereClause varchar(max),
@MasterDataWhereClause varchar(max),  
@Order varchar(max),
@GrandTotal varchar(max),
@AlterHeaderTable varchar(max),
@AlterGroupTable varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@ProcessedValueFilter varchar(max),
@ProcessedMasterFilter varchar(max),
@CompanyID int,
@PRateCalculation int=null,
@CostCentreId int=0
as  
   
set nocount on  
set transaction isolation level read uncommitted

declare @cols varchar(max),
        @colVal varchar(max),
        @WhereClause varchar(max)         

create table #T1 
(
CompanyId int,
ProductId int,
Rate float,
CP float,
SRate float,
WRate float,
MRP float,
Qty float,
StockQty float,
Stock varchar(50),
StockCP float,
StockMultiplier float,
Barcode varchar(50),
Pieces float
)

create table #Vendors
(
ProductId int,
VendorId int,
Name nvarchar(200)
)

create table #TaxGroup
(
ProductId int,
TaxGroupId int
)

declare @Purchase table
(
ProductId int,
VendorId int,
TaxGroupId int
)

insert #Vendors (ProductId,VendorId) select ProductId,max(VendorId) from invPrefeRredVendors group by ProductId

insert #TaxGroup(ProductId,TaxGroupId) select Id,TaxGroupId from invProduct

Sales
;with t1 as (select t2.ProductId,t2.TaxGroupId,row_number() over(partition by t2.ProductId order by t1.Date desc) Sno from invSalesHeader t1
join invSalesDetails t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No 
where t1.CompanyID = @CompanyID
and t1.Date<=@To
)

update tg set tg.TaxGroupId=t1.TaxGroupId from #TaxGroup tg join t1 on tg.ProductId=t1.ProductId
--------

;with t1 as (select t1.VendorId,t2.ProductId,t2.TaxGroupId,row_number() over(partition by t2.ProductId order by t1.Date desc) Sno from invPurchaseHeader t1
join invPurchaseDetails t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No 
where t1.CompanyID = @CompanyID
and t1.Date<=@To
)

insert @Purchase (ProductId,VendorId,TaxGroupId) select ProductId,VendorId,TaxGroupId from t1 where sno = 1

update t1 set t1.VendorId = t2.VendorId from #Vendors t1
join @Purchase t2 on t1.ProductId = t2.ProductId

update t1 set t1.TaxGroupId = t2.TaxGroupId from #TaxGroup t1
join @Purchase t2 on t1.ProductId = t2.ProductId


insert #Vendors (ProductId,VendorId) 
select t1.ProductId,t1.VendorId from @Purchase t1
left outer join #Vendors t2 on t1.ProductId = t2.ProductId 
where t2.ProductId is null

update t1 set t1.Name = t2.Name from #Vendors t1
join aAccount t2 on t1.VendorId = t2.Id

declare @OptCompanyId int
select @OptCompanyId=min(Id) from aCompany
set @OptCompanyId=case when @CompanyID=0 then @OptCompanyId else @CompanyID end

declare @InActiveStock bit
select @InActiveStock=isnull(InActiveStock,0) from invOption where CompanyId=@OptCompanyId

if len(@ValueDataWhereClause) > 0 and LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0 and ' + @ValueDataWhereClause + ' and ' + @MasterDataWhereClause 
else if len(@ValueDataWhereClause) > 0 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0 and ' + @ValueDataWhereClause 
else if LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0 and ' + @MasterDataWhereClause 
else 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0'  


if len(@WhereClause) > 0 
begin
	exec('insert tmpTable(SPID,ID,BarcodeID) select @@spid,t3.Id,null from invProduct t3 
				join invUom t4 on t3.BaseUom = t4.id 
				join vw_ProductProerty t6 on t3.Id = t6.Id
				join #TaxGroup tg on t3.Id=tg.ProductId
                left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
				left join #Vendors t10 on t3.Id = t10.ProductId
				left join invCostCentre t11 on t3.CostCentreId = t11.Id
				' + @WhereClause) 
	end
else
begin
	
	insert tmpTable(SPID,ID,BarcodeID) select @@spid,Id,null from invProduct 
	where (isnull(inactive,0) = 0 or @InActiveStock=1) and isnull(NonStockItem,0) = 0
end


declare @CurrentPRateCalculation int
if @CompanyId <> 0 and @PRateCalculation is not null
begin
  select @CurrentPRateCalculation = PRateCalculation from invOption where CompanyId = @CompanyId
  update invOption set PRateCalculation = @PRateCalculation where CompanyId = @CompanyId
end



insert #T1(CompanyId,ProductId,Rate,CP,SRate,WRate,MRP,Qty,Pieces) 
exec spstock @ToDate=@To,@Type=1,@CompanyID=@CompanyID,@CostCentreId=@CostCentreId

--MRP
update t1 set t1.MRP=p.MRP from #T1 t1 join invProduct p on t1.ProductId=p.Id where isnull(t1.MRP,0)=0

exec('insert #T1(CompanyId,ProductId,Rate,CP,SRate,WRate,MRP,Qty) 
	select '+@CompanyId+',t3.Id,t3.Cost,t3.Cost,t3.Rate,t3.WRate,t3.MRP,0 from invProduct t3 
	join invUom t4 on t3.BaseUom = t4.id 
	join vw_ProductProerty t6 on t3.Id = t6.Id
	join #TaxGroup tg on t3.Id=tg.ProductId
	left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
	left join #Vendors t10 on t3.Id = t10.ProductId
	left join invCostCentre t11 on t3.CostCentreId = t11.Id
	left join #T1 t on t3.Id=t.ProductId and '+@CompanyId+'=t.CompanyId 
	'+@WhereClause + ' and t.ProductId is null ')

if @CompanyId <> 0 and @CurrentPRateCalculation is not null
begin
  update invOption set PRateCalculation = @CurrentPRateCalculation where CompanyId = @CompanyId
end

if len(@ProcessedValueFilter) > 0 
begin
	update #T1 set Rate=isnull(Rate,0),CP=isnull(CP,0),SRate=isnull(SRate,0),Qty=isnull(Qty,0)--to filter null value also
	exec ('delete t1 from #T1 t1 where not (' + @ProcessedValueFilter +')')
end		

if len(@ProcessedMasterFilter) > 0 
begin
  exec ('delete t1 from #T1 t1 where not (' + @ProcessedMasterFilter +')')
end		


create index ind#T1 on #T1(ProductId)

--Stock CP,Qty
update t set t.Barcode=u.Barcode,t.StockQty=round(t.Qty/u.MultiPlayer,10),t.StockMultiplier=u.MultiPlayer,t.StockCP=t.CP*u.Secondary from #T1 t join invProduct p on p.Id=t.ProductId join invUOMLevels u on t.ProductId=u.ProductId and p.StockUom=u.UomId where u.Multiplayer<>0
update t set t.Stock=cast(floor(t.StockQty) as varchar)+'.'+cast((t.StockQty-floor(t.StockQty))*t.StockMultiplier as varchar) from #T1 t
--WRate
update t set t.Wrate=r.Rate from invBarcode r join #T1 t on r.ProductId=t.ProductId join invRateLevel l on r.LevelId=l.Id and l.Rate=3 where t.Wrate is null
update t set t.Wrate=r.WRate from invProduct r join #T1 t on r.Id=t.ProductId where t.Wrate is null or t.Wrate=0


if @Group = 0  
	if @GroupTotal = 0     
		begin
			
			exec('select row_number() over (order by (select 1)) SNo,' + @Columns + ' from #T1 t1 
			join invProduct t3 on t1.ProductId = t3.Id 
			join invUom t4 on t3.BaseUom = t4.id 
			left join invUom t5 on t3.StockUom = t5.Id 
			join vw_ProductProerty t6 on t1.ProductId = t6.Id
            join aCompany t7 on t1.CompanyId = t7.Id
			join #TaxGroup tg on t3.Id=tg.ProductId
			left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
			left join #Vendors t10 on t1.ProductId = t10.ProductId
			left join invCostCentre t11 on t3.CostCentreId = t11.Id
			' + @Order)


		end
    else
		begin
			if LEN(@Order) = 0 
				begin
					exec('select row_number() over (order by (select 1)) SNo,' + @Columns + ' from #T1 t1 
					join invProduct t3 on t1.ProductId = t3.Id 
					join invUom t4 on t3.BaseUom = t4.id
                 	left join invUom t5 on t3.StockUom = t5.Id  
					join vw_ProductProerty t6 on t1.ProductId = t6.Id
					join aCompany t7 on t1.CompanyId = t7.Id
                    join #TaxGroup tg on t3.Id=tg.ProductId
					left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
					left join #Vendors t10 on t1.ProductId = t10.ProductId
					left join invCostCentre t11 on t3.CostCentreId = t11.Id
					union all select null,' + @GrandTotal + ' from #T1 t1 
					join invProduct t3 on t1.ProductId = t3.Id 
					join invUom t4 on t3.BaseUom = t4.id 
                    left join invUom t5 on t3.StockUom = t5.Id 
			   		join vw_ProductProerty t6 on t1.ProductId = t6.Id
                    join aCompany t7 on t1.CompanyId = t7.Id
                    join #TaxGroup tg on t3.Id=tg.ProductId
					left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
					left join #Vendors t10 on t1.ProductId = t10.ProductId
					left join invCostCentre t11 on t3.CostCentreId = t11.Id
					' )

				end
		  else
			begin
			     declare @Query varchar(max)
					 
				 
				set @Query = 'select case when row_id=0 then row_number() over ('+@Order+') end-1 SNo,* from 
                                (select 0 row_id,' + @Columns + ' from #T1 t1 
								 join invProduct t3 on t1.ProductId = t3.Id 
				                 join invUom t4 on t3.BaseUom = t4.id 
			                     left join invUom t5 on t3.StockUom = t5.Id 
				                 left outer join vw_ProductProerty t6 on t1.ProductId = t6.Id
                                 join aCompany t7 on t1.CompanyId = t7.Id
                                 join #TaxGroup tg on t3.Id=tg.ProductId
								 left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
								 left join #Vendors t10 on t1.ProductId = t10.ProductId
								 left join invCostCentre t11 on t3.CostCentreId = t11.Id
				                 union all 
								 select 1 row_id,' + @GrandTotal + ' from #T1 t1 
				                 join invProduct t3 on t1.ProductId = t3.Id 
				                 join invUom t4 on t3.BaseUom = t4.id 
			                     left join invUom t5 on t3.StockUom = t5.Id 
				                 join vw_ProductProerty t6 on t1.ProductId = t6.Id
                                 join aCompany t7 on t1.CompanyId = t7.Id
                                 join #TaxGroup tg on t3.Id=tg.ProductId
								 left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
								 left join #Vendors t10 on t1.ProductId = t10.ProductId
								 left join invCostCentre t11 on t3.CostCentreId = t11.Id
				) p ' + replace(@order,'order by','order by row_id,')
				
				 
          		exec(@Query)
			end	   		
		end			

else  
	begin  
		
		create table #Stock ([ ] int)
		exec(@AlterHeaderTable)
		alter table #Stock drop column [ ]

		exec('insert #Stock select ' + @Columns + ' from #T1 t1 
		join invProduct t3 on t1.ProductId = t3.Id 
		join invUom t4 on t3.BaseUom = t4.id 
		left join invUom t5 on t3.StockUom = t5.Id 		
        join vw_ProductProerty t6 on t1.ProductId = t6.Id
        join aCompany t7 on t1.CompanyId = t7.Id
        join #TaxGroup tg on t3.Id=tg.ProductId
	    left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
		left join #Vendors t10 on t1.ProductId = t10.ProductId
		left join invCostCentre t11 on t3.CostCentreId = t11.Id
		' + @Order)

		create table #StockGroup(Rid numeric identity(1,1))  
		exec(@AlterGroupTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #Stock,#StockGroup
	end   


go

if OBJECT_ID('prSaveSalesReturn') is not null
	drop proc prSaveSalesReturn
go

create proc prSaveSalesReturn
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int,
@Date int,
@DeliveryDate int,
@CustomerId int,
@PaymentMode tinyint,
@SalesManId int,
@RateLevelId int,
@Total float,
@DiscountP float,
@Discount float,
@NetTotal float,
@Notes varchar(500),
@TaxCalculation int ,
@Tax float, 
@Addition float,
@OutVno int output,
@XmlProductDetails xml,
@Id int,
@CreditNote bit,
@Time int,
@RefNo varchar(100)=null,
@XmlPropertyDetails xml=null,
@FooterAddition float=null,
@Addition2 float=null,
@RoundOff float=null,
@Paid float=null,
@QRCodeImage Image=null,
@SalesNo int=null,
@EInvoice int = null,
@CostCentreId int=null,
@TaxGroupID int=null,
@BillTax float=null,
@AdditionalNotes varchar(max)=null,
@ReasonId int=null,
@UserId int=null

as

set nocount on
set xact_abort on

Begin transaction

if(@No = 0)
begin
    declare @T1 table([No] int)
    insert @T1 exec prGetSalesReturnMaxVno @CompanyID,@PeriodID,@VtypeId
    select @No = [No] from @T1 
  
    select @Id  = isnull(max(Id),0) + 1 from invSalesReturnHeader

    insert invSalesReturnHeader([CompanyID],[PeriodID],[VtypeId],[No],[Date],[DeliveryDate],[CustomerId],[PaymentMode],
    [SalesManId],[RateLevelId],[Total],[DiscountP],[Discount],[NetTotal],[Notes],[TaxCalculation],[Tax],[Id],[CreditNote],[Time],[RefNo],Addition,RoundOff,Paid,QRCodeImage,SalesNo,EInvoice,CostCentreId,TaxGroupId,BillTax,AdditionalNotes,ReasonId,UserId)
    values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@DeliveryDate,@CustomerId,@PaymentMode,@SalesManId,@RateLevelId,
    @Total,@DiscountP,@Discount,@NetTotal,@Notes,nullif(@TaxCalculation,0),nullif(@Tax,0),@Id,nullif(@CreditNote,0),@Time,nullif(@RefNo,''),nullif(@FooterAddition,0),nullif(@RoundOff,0),nullif(@Paid,0),@QRCodeImage,nullif(@SalesNo,0),nullif(@EInvoice,0),nullif(@CostCentreId,0),nullif(@TaxGroupId,0),nullif(@BillTax,0),nullif(@AdditionalNotes,''),nullif(@ReasonId,0),nullif(@UserId,0))
	
end
else
begin
	exec prDeleteSalesReturn @VtypeId=@VtypeId,@No=@No,@CompanyID=@CompanyID,@PeriodID=@PeriodID,@DeleteHeader = 0,@Id = @Id,@Status = 0
		
	update invSalesReturnHeader set
	[Date]= @Date,
	[DeliveryDate]= @DeliveryDate,
	[CustomerId]= @CustomerId,
	[PaymentMode]= @PaymentMode,
	[SalesManId]= @SalesManId,
	[RateLevelId]= @RateLevelId,
	[Total]= @Total,
	[DiscountP]= @DiscountP,
	[Discount]= @Discount,
	[NetTotal]= @NetTotal,
	[Notes]= @Notes,
	[Tax]= nullif(@Tax,0),
	[TaxCalculation]= nullif(@TaxCalculation,0),
    [CreditNote] = nullif(@CreditNote,0),
    [Time] = @Time  ,
    [RefNo] = nullif(@RefNo,''),
	Addition=nullif(@FooterAddition,0),
	RoundOff= nullif(@RoundOff,0),
	Paid=nullif(@Paid,0),
	QRCodeImage=@QRCodeImage,
	SalesNo=@SalesNo,
	EInvoice=nullif(@EInvoice,0),
	CostCentreId=nullif(@CostCentreId,0),
	BillTax=@BillTax,
	AdditionalNotes=@AdditionalNotes,
	ReasonId=nullif(@ReasonId,0),
	UserId=nullif(@UserId,0),
	Sync=1
	where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
end	


--Details
declare @Details table
(Sno            int,
 ProductId      int,
 WarehouseId    int,
 UomId          int,
 Qty            float,
 Foc            float,
 Rate           float,
 Gross          float,
 Addition       float,
 DiscountP      float,
 Discount       float,
 Total          float,
 MfrDate        datetime,
 ExpDate        datetime,
 Remark         varchar(100),
 BarcodeId      int,
 TaxGroupId     int,
 Tax            float,
 SerialNoId     int,
 Addition2      float,
 SerialNo       varchar(100),
 Cost           float
)

declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert @Details
([Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Rate],[Gross],Addition,
[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],[TaxGroupId],[Tax],[SerialNoId],Addition2,SerialNo,Cost)
select [Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Rate],[Gross],Addition,
[DiscountP],[Discount],[Total],MfrDate,ExpDate,[Remark],[BarcodeId],[TaxGroupId],Tax,SerialNoId,Addition2,SerialNo,Cost from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
ProductId      int '@ProductId',
WarehouseId    int '@WarehouseId',
UomId          int '@UomId',
Qty            float '@Qty',
Foc            float '@Foc',
Rate           float '@Rate',
Gross          float '@Gross',
Addition       float '@Addition',
DiscountP      float '@DiscountP',
Discount       float '@Discount',
Total          float '@Total',
MfrDate        datetime '@MfrDate',
ExpDate        datetime '@ExpDate',
Remark         varchar(100) '@Remark',
BarcodeId      int '@BarcodeId',
TaxGroupId     int '@TaxGroupId',
Tax            float '@Tax',
SerialNoId     int '@SerialNoId',
Addition2      float '@Addition2',
SerialNo       varchar(100) '@SerialNo',
Cost           float '@Cost'
)

exec sp_xml_removedocument @Idoc


declare @CGSAccountId int
select @CGSAccountId=CostOfGoodsSoldAccountId from invOption where CompanyID = @CompanyID
if @CGSAccountId>0
Begin
	declare @Stock table(CompanyId int,ProductId int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float)
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	declare @BeforeCostofGoods float
	select @BeforeCostofGoods=sum(Qty*Rate) from @Stock
End


insert invSalesReturnDetails
([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Rate],[Gross],Addition,
[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],[TaxGroupId],[Tax],[SerialNoId],Addition2,SerialNo,Cost)
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],nullif([WarehouseId],0),[UomId],[Qty],[Foc],[Rate],[Gross],Addition,
[DiscountP],[Discount],[Total],convert(varchar,[MfrDate],112),convert(varchar,[ExpDate],112),[Remark],
nullif([BarcodeId],0) [BarcodeId],[TaxGroupId],nullif([Tax],0),nullif(SerialNoId,0),nullif(Addition2,0),case when SerialNoId=0 then SerialNo end,Cost from @Details


if @CGSAccountId>0
Begin
	delete @Stock
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	declare @AfterCostofGoods float
	select @AfterCostofGoods=sum(Qty*Rate) from @Stock
End


--Property
exec sp_xml_preparedocument @Idoc out ,@XmlPropertyDetails

insert invSalesReturnPropertyDetails(CompanyID,PeriodID,[VtypeId],[No],[Sno],[ProductId],[SubPropertyId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno int '@Sno',
ProductId int '@ProductId',
SubPropertyId int '@SubPropertyId'
)

exec sp_xml_removedocument @Idoc

--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and @CreditNote = 0) and isnull(@EInvoice,0) not in(2,4)
Begin
	declare @VoucherTypeID int
	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId

	declare @DebtorID int,@DiscountAccountID int,@CashInHandID int,@SalesRoundOffAccount int,@PurchaseAccountID int,@CreditCardID int,@CommissionAccountID int

	select @DebtorID=nullif(SRAccount,0),@SalesRoundOffAccount = SalesRoundOffAccount from invOption where CompanyID = @CompanyID

	select @DebtorID=isnull(@DebtorID,Sales),@DiscountAccountID=DiscountPaid,@CashInHandID=isnull(@CashInHandID,CashInHand),@PurchaseAccountID=Purchase,@CreditCardID=isnull(CreditCard,0),@CommissionAccountID=Commission from aAccountSettings where CompanyID=@CompanyID

	select @CashInHandID=AccountID from invSalesman where Id=@SalesManId and AccountID>0

	select @CostCentreId=CostCentreId from invCostCentre where id=@CostCentreId
	select @CostCentreId=c.CostCentreId from invVoucherTypeDetails v join invCostCentre c on v.CostCentreId=c.id where v.ID=@VtypeId
	select @CostCentreId=nullif(@CostCentreId,0)

	if @PaymentMode=0 
		set @CustomerId=@CashInHandID
	Else if @PaymentMode=2
		set @CustomerId=@CreditCardID

	set @VoucherTypeID=isnull(@VoucherTypeID,0)

	--Total
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
	values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DebtorID,@CustomerId,@Total-@Discount+isnull(@RoundOff,0)+isnull(@BillTax,0),rtrim('Sales Return   ' + isnull(@RefNo,'')),@CostCentreId) 

	--Discount
	if @Discount>0
	Begin
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DebtorID,@DiscountAccountID,@Discount,'Sales Return Discount',@CostCentreId) 
	End

	--Tax
	set @Tax=isnull(@Tax,0)+isnull(@BillTax,0)
	if @Tax>0
	Begin
		declare  @TaxAccountID int
		select @TaxAccountID=OutPutTaxAccount from invOption
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@TaxAccountID,@DebtorID,@Tax,'Sales Tax',@CostCentreId) 
	End
	
	--Footer Addition
	if @FooterAddition<>0
	Begin
        declare @SalesAdditionAccount int
		select @SalesAdditionAccount=SalesAdditionAccount from invOption where CompanyId=@CompanyId
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAdditionAccount,@CustomerId,@FooterAddition,'Addition in Return',@CostCentreId) 
	End

	declare @AdditionAccountID int
	select @AdditionAccountID=AdditionAccount from invOption where CompanyID = @CompanyID
	--Addition
	if @Addition<>0
	Begin
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,isnull(@AdditionAccountID,0),@DebtorID,@Addition,'Addition In Return',@CostCentreId) 
	End

	--Addition2
	if @Addition2>0
	Begin
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,isnull(@AdditionAccountID,0),@DebtorID,@Addition2,@CostCentreId) 
	End

	--Round off
	if ISNULL(@SalesRoundOffAccount,0) >  0 and @RoundOff <> 0
	begin
		if @RoundOff > 0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesRoundOffAccount,@DebtorID,@RoundOff,@CostCentreId) 
		else 
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		    values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DebtorID,@SalesRoundOffAccount,abs(@RoundOff),@CostCentreId) 	
	end

	--Paid
	if @PaymentMode=1 and @Paid<>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@CashInHandID,@Paid,'Payment In Sales Return',@CostCentreId) 
	
	--Product Account
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,p.AccountId,@DebtorID,sum(d.Gross),p.Name,@CostCentreId from @Details d join invProduct p on d.ProductId=p.Id where p.AccountId is not null group by p.AccountId,p.Name
	
	--Salesman Commission
	if @SalesManId>0 and @CommissionAccountID>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,s.AccountID1,@CommissionAccountID,@NetTotal*s.Commission/100.0,'Salesman Commission',@CostCentreId from invSalesMan s 
		where s.Id=@SalesManId and s.AccountID1>0 and s.Commission<>0

	if @CGSAccountId>0
	Begin
		----Cost Of Goods Sold
		
		declare @Cost float

		set @Cost = isnull(@AfterCostofGoods,0)-isnull(@BeforeCostofGoods,0)

		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@PurchaseAccountId,@CGSAccountId,@Cost,'Sales Return',@CostCentreId --from @CGS having sum(CP)<>0

	End

End

set @OutVno = @No 

Commit

go


if object_id('spGetInvSalesHeader') is not null
	drop proc spGetInvSalesHeader
go

create proc spGetInvSalesHeader      
@CompanyID int,      
@PeriodID int,      
@VtypeID int,      
@No int      
as      
set nocount on   
set transaction isolation level read uncommitted

declare @Table table(CustomerID int,Code nvarchar(50),Customer nvarchar(100),Under nvarchar(100),VType varchar(50),No int,Date smalldatetime,
Amount float,Notes nvarchar(500),SalesReturn float,AirWayBillNo varchar(50),PaymentMode tinyint,VtypeDetails varchar(50),QuotationNo int,
Rep1 varchar(100),Rep2 varchar(100),DeliveryDate smalldatetime,Discount float,Total float,SalesMan nvarchar(50),Address1 nvarchar(100),
Address2 nvarchar(100),Address3 nvarchar(100),Place nvarchar(100),Phone nVarchar(50),MobileNo nVarchar(50),Email nVarchar(100),Location varchar(500),
ContactPerson nvarchar(100),PaymentTerms nvarchar(100),RoundOff float,Advance float,Tax float,Paid float,TIN nVarchar(100),CST nVarchar(100),
DLNo1 nVarchar(100),DLNo2 nVarchar(100),PrePrintingString  nVarchar(100),Time int,DiscountP float,Company varchar(50),Property1 varchar(100),
Addition float,GST nVarchar(100),Address nvarchar(300),TaxP float,BillTax float,CustomerInOL nvarchar(100),ReturnID int,RateLevel varchar(50),
UserName varchar(100),CardNo varchar(25),CardID int,Points float,Redempted float,DueDate datetime,TokenNo int,CostCentre nvarchar(50),
QRCodeImage Image,PeriodCode varchar(50),PeriodName varchar(50),ShippingNo varchar(50),Remark1 nVarchar(2000),Remark2 nVarchar(2000),Remark3 nVarchar(2000),Remark4 nVarchar(2000),
Address4 nvarchar(100),Address5 nvarchar(100),Address6 nvarchar(100),Address7 nvarchar(100),Address8 nvarchar(100),Address9 nvarchar(100),AName nvarchar(100)
,InvoiceFormat nvarchar(100),SalesManCode nvarchar(50),SRVtypeId int,SRNo int,PiadBy int,CreditCardID int,CreditCard nVarchar(50),Discount1 float,Discount2 float,Discount3 float)  

insert @Table(CustomerID,Code,Under,VType,No,Date,Amount,Notes,SalesReturn,AirWayBillNo,PaymentMode,VtypeDetails,QuotationNo,DeliveryDate,
Discount,Total,SalesMan,RoundOff,Advance,Tax,Paid,PrePrintingString,Time,DiscountP,Company,Addition,Address,TaxP,BillTax,CustomerInOL,ReturnID,
RateLevel,UserName,CardID,DueDate,TokenNo,CostCentre,QRCodeImage,PeriodCode,PeriodName,ShippingNo,Remark1,Remark2,Remark3,Remark4,AName,SRVtypeId,
SRNo,PiadBy,CreditCardID,Discount1,Discount2,Discount3)  

select s.CustomerID,a.Code,u.Name,v.Code,s.No,cast(cast(s.Date as varchar)as smalldatetime),s.NetTotal,s.Notes,s.SalesReturn,s.AirWayBillNo,
s.PaymentMode,v.Description,QuotationNo,cast(cast(s.DeliveryDate as varchar)as smalldatetime)DeliveryDate,s.Discount,s.Total,s.SalesManID,
s.RoundOff,s.Advance,s.Tax,s.Paid,s.PrePrintingString,s.Time,s.DiscountP,co.Name Company,s.Addition,s.Address,s.TaxGroupID,s.BillTax,a.NameInOL,
s.ReturnID,s.RateLevelID,usr.name,pc.CardId,cast(cast(nullif(s.duedate,0) as varchar) as datetime),s.TokenNo,s.CostCentreId,s.QRCodeImage,
p.Code,p.Name,s.ShippingNo,Remark1,Remark2,Remark3,Remark4,a.Name,sr.VtypeId,sr.No,s.PaidBy,s.CreditCardID,s.Discount1,s.Discount2,s.Discount3 from invSalesHeader s      
join invVoucherTypeDetails v on s.VtypeID=v.ID      
join aAccount a on s.CustomerID=a.ID  
join aAccount u on a.UnderAccountID=u.ID  
join aCompany co on s.CompanyID=co.ID  
join aPeriod p on s.PeriodId=p.Id
left outer join invUser usr on s.userid = usr.id
left outer join invPrivilegeCardSales pc on pc.CompanyId=s.CompanyId and pc.PeriodId=s.PeriodId and pc.VtypeId=s.VtypeID and pc.No=s.No
left outer join invSalesReturnHeader sr on s.ReturnId=sr.Id
where s.CompanyID=@CompanyID and s.PeriodID=@PeriodID and s.VtypeId=@VtypeID and s.No=@No      


--Customer
update t set t.Customer=c.Name,t.Address1=c.Address1,t.Address2=c.Address2,t.Address3=c.Address3,t.Address4=c.Address4,t.Address5=c.Address5,t.Address6=c.Address6,t.Address7=c.Address7,t.Place=c.Place,t.Phone=c.Phone,t.Address8=c.Address8,t.Address9=c.Address9,
t.MobileNo=c.MobileNo,t.EMail=c.EMail,t.Location=c.Location,t.ContactPerson=c.ContactPerson,t.PaymentTerms=c.PaymentTerms,t.DLNo1=c.DLNo1,
t.DLNo2=c.DLNo2,t.TIN=c.TIN,t.GST=c.GST,t.CST=c.CST from invCustomer c join @Table t on c.AccountID=t.CustomerID

--Vendor
update t set t.Customer=c.Name,t.Address1=c.Address1,t.Address2=c.Address2,t.Address3=c.Address3,t.Phone=c.Phone,t.MobileNo=c.MobileNo,
t.EMail=c.EMail,t.Location=c.Fax,t.ContactPerson=c.ContactPerson,t.PaymentTerms=c.PaymentTerms,t.DLNo1=c.DLNo1,t.DLNo2=c.DLNo2,t.GST=c.GST,
t.TIN=c.TIN from invVendor c join @Table t on c.AccountID=t.CustomerID where t.Customer is null
 

--Rep1  
update t set t.Rep1=r.Name from invRep1 r join @Table t on r.ID=t.Rep1   
--Rep2  
update t set t.Rep2=r.Name from invRep2 r join @Table t on r.ID=t.Rep2  
--Salesman  
update t set t.Salesman=s.Name,t.SalesmanCode=s.Code from invSalesMan s join @Table t on s.ID=t.SalesMan  
--Property1  
update t set t.Property1=s.Name from @Table t join invAccountPropertyDetails pd on t.CustomerID=pd.AccountID join invAccountSubProperty s on pd.SubPropertyID=s.ID  
where pd.PropertyID=1  
--TaxP
update t set t.TaxP=tg.OutPutTax from invTaxGroup tg join @Table t on tg.ID=t.TaxP
--Rate Level
update t set t.RateLevel=r.Name from invRateLevel r join @Table t on r.ID=t.RateLevel
--Rate Level
update t set t.CostCentre=c.Name from invCostCentre c join @Table t on c.ID=t.CostCentre
--CreditCard
update t set t.CreditCard=c.Name from  aCreditCard c join @Table t on c.ID=t.CreditCardID

  
--Privilege Card
declare @PC Table (CardID int ,CardNo Varchar(50),Points float,Redempted float)
insert @PC
select i.id,i.CardNo, Sum(pc.Points),SUM(pc.Redempted) from invPrivilegeCardSales pc join invPrivilegeCardIssue i on pc.CardID=i.ID
join @Table t on pc.CardId =t.CardID  
group by i.id,i.CardNo
update t set t.CardNo=pc.CardNo,t.Points=pc.Points,t.Redempted=pc.Redempted from @PC pc join @Table t on pc.CardId =t.CardID  
-------------

--Invoice Format
update t set t.InvoiceFormat=v.InvoiceFormat from @Table t join invVoucherTypeStartNo v on v.CompanyId=@CompanyID and v.PeriodId=@PeriodID and v.VtypeId=@VtypeID 

select * from @Table  

go

if not exists(select name from sys.columns where object_id = object_id('invOption') and name = 'ClearProductSearchText') 
  alter table invOption add ClearProductSearchText bit

go


