if object_id('prSaveinvCustomer') is not null
	drop proc prSaveinvCustomer
go	
	
create proc prSaveinvCustomer
@Id int,
@Code varchar(15),
@Name nvarchar(100),
@UnderID int,
@NickName nvarchar(100),
@NameInOL nvarchar(100),
@Address1 nvarchar(100),
@Address2 nvarchar(100),
@Address3 nvarchar(100),
@Address4 nvarchar(100)=null,
@Address5 nvarchar(100)=null,
@Address6 nvarchar(100)=null,
@Address7 nvarchar(100)=null,
@Address8 nvarchar(100)=null,
@Address9 nvarchar(100)=null,
@Place nvarchar(100),
@Phone nvarchar(50),
@MobileNo nvarchar(50),
@Email nvarchar(100),
@Web varchar(100),
@Location varchar(500),
@ContactPerson nvarchar(100),
@CreditLimit float,
@DueDays float,
@CurrencyId int,
@RateLevelId int,
@SalesManId int,
@PaymentTerms nvarchar(100),
@FileNo nvarchar(50),
@Remark nvarchar(250),
@OB float,
@OBType bit,
@CompanyID int,
@xmlPropertyData xml,
@TIN nvarchar(100),
@CST nvarchar(100),
@DLNo1 nvarchar(100),
@DLNo2 nvarchar(100),
@GST nvarchar(100),
@OBCompanyID int=1,
@PaymentMode tinyint=null,
@Image Image =null,
@CostCentreId int=null,
@Approve bit=null
as

set nocount on

declare @DuplicateCustomer bit
declare @AllowDuplicatePhoneNo bit

select @DuplicateCustomer = DuplicateCustomer,@AllowDuplicatePhoneNo=AllowDuplicatePhoneNo from invOption 
where CompanyID=@CompanyID

declare @Message nvarchar(500)

--------
if isnull(@AllowDuplicatePhoneNo,0)=0
Begin
	if len(isnull(@Phone,'')+isnull(@MobileNo,''))>0
	Begin
		select @Message='There is already customer ' + Name + ' with the given phone number(s)' from invCustomer 
		where AccountID<>@Id and isnull(Phone,'')+isnull(MobileNo,'')=isnull(@Phone,'')+isnull(@MobileNo,'')
		if @Message is not null
		Begin
			select @Id ID,3 Status,@Message Message
			return
		End
	End
End
----------

--Insertion to account
if isnull(@UnderID,0)=0
	select @UnderID=Customers from aAccountSettings

declare @AccountSubGroupID int
select @AccountSubGroupID=AccountSubGroupID from aAccount where ID=@UnderID

select @CompanyID=nullif(@CompanyID,0)

declare @t table(ID int,Status tinyint,Message varchar(100)) 


if len(@Code) = 0-- To Generate New Code
Begin
	declare @Prefix varchar(50)    
	declare @Size int    
	
	select @Prefix=isnull(max(Left(Code, PatIndex('%[0-9]%', Code + '1') - 1)),''),@Size=isnull(max(len(Code)),0) from aAccount  where isnumeric(Code)=0
	select @Code=isnull(max(cast(replace(Code,@Prefix,'') as numeric)),0)+1 from aAccount where PATINDEX('%[^0-9]%',replace(Code,@Prefix,''))=0 and len(replace(Code,@Prefix,''))>0 and Code like @Prefix+'%'
	if len(@Prefix+@Code)>@Size set @Size=len(@Prefix+@Code)
	select @Code=@Prefix+replicate('0',@Size-len(@Prefix+@Code))+@Code  

End


declare @WarnMessage varchar(max)

if @Id>0
Begin
	select @WarnMessage='THE OB HAS REFERENCE IN BILLWISE RECEIPT : '+ cast(b.No as varchar)+' AND CAN''T UPDATE' from aBillwiseReceiptDtl b 
	join aBillwiseReceiptHdr h on b.CompanyId=h.CompanyId and b.PeriodId=h.PeriodId and b.No=h.No 
	where b.CompanyID=@OBCompanyID and b.EPeriodID is null and b.EVoucherTypeID is null  and b.ENo is null and h.CustomerId=@Id

	if (@WarnMessage is null)
		delete aTransaction where PeriodID is null and Date is null and No is null and (DebtorID=@Id and CreditorID=1 or DebtorID=1 and CreditorID=@Id) and CompanyID=@OBCompanyID
	Else
		set @OBCompanyID=null
End

insert @t 
exec spSaveAccount @ID=@Id,@Code=@Code,@Name=@Name,@NameInOL=@NameInOL,
	 @AccountSubGroupID=@AccountSubGroupID,@UnderAccountID=@UnderID,
     @OB=@OB,@DrCr=@OBType,@CompanyID=@OBCompanyID,@ModuleID=1,@IsAllowDuplicateName = @DuplicateCustomer


declare @NewId int

select @NewId=ID from @t where Status=0
if @NewId is null
Begin
	select * from @t
	return
End



if @NickName=''
	set @NickName=@Name

if isnull(@Id,0) = 0
  begin
      insert invCustomer([AccountId],[Name],[Address1],[Address2],[Address3],[Place],[Phone],[MobileNo],[Email],
      [Web],Location,[ContactPerson],[CreditLimit],[DueDays],[CurrencyId],[RateLevelId],[SalesManId],[PaymentTerms],FileNo,[Remark],
      [TIN],[CST],[DLNo1],[DLNo2],CompanyID,GST,PaymentMode,Image,Address4,Address5,Address6,Address7,Address8,Address9,CostCentreId,Approve)
      values(@NewId,@NickName,nullif(@Address1,''),nullif(@Address2,''),nullif(@Address3,''),nullif(@Place,''),
      nullif(@Phone,''),nullif(@MobileNo,''),nullif(@Email,''),nullif(@Web,''),nullif(@Location,''),
      nullif(@ContactPerson,''),nullif(@CreditLimit,0),nullif(@DueDays,0),nullif(@CurrencyId,0),
      nullif(@RateLevelId,0),nullif(@SalesManId,0),nullif(@PaymentTerms,''),nullif(@FileNo,''),
      nullif(@Remark,''),nullif(@TIN,''),nullif(@CST,''),nullif(@DLNo1,''),nullif(@DLNo2,''),@CompanyID,nullif(@GST,''),nullif(@PaymentMode,0),@Image,
	  nullif(@Address4,''),nullif(@Address5,''),nullif(@Address6,''),nullif(@Address7,''),nullif(@Address8,''),nullif(@Address9,''),nullif(@CostCentreId,0),nullif(@Approve,0))	  
  end
else
	begin
		update invCustomer set [Name]= @NickName,
		                    [Address1]= nullif(@Address1,''),
							[Address2]= nullif(@Address2,''),
							[Address3]= nullif(@Address3,''),
							[Place] = nullif(@Place,''),
							[Phone]= nullif(@Phone,''),
							[MobileNo]= nullif(@MobileNo,''),
							[Email]= nullif(@Email,''),
							[Web]= nullif(@Web,''),
							Location= nullif(@Location,''),
							[ContactPerson]= nullif(@ContactPerson,''),
							[CreditLimit]= nullif(@CreditLimit,0),
							[DueDays]= nullif(@DueDays,0),
							[CurrencyId]= nullif(@CurrencyId,0),
							[RateLevelId] = nullif(@RateLevelId,0),
							[SalesManId] = nullif(@SalesManId,0) , 
							[PaymentTerms]= nullif(@PaymentTerms,''),
							FileNo=nullif(@FileNo,''),
							[Remark]= nullif(@Remark,''),
							[TIN] = nullif(@TIN,''),
							[CST] = nullif(@CST,''),
							[DLNo1] = nullif(@DLNo1,''),
							[DLNo2] = nullif(@DLNo2,''),
							CompanyID=@CompanyID,
							[GST] = nullif(@GST,''),
							PaymentMode=nullif(@PaymentMode,0),
							Image=@Image,
							[Address4]= nullif(@Address4,''),
							[Address5]= nullif(@Address5,''),
							[Address6]= nullif(@Address6,''),
							[Address7]= nullif(@Address7,''),
							[Address8]= nullif(@Address8,''),
							[Address9]= nullif(@Address9,''),
							CostCentreId=nullif(@CostCentreId,0),
							Approve=nullif(@Approve,0)

		where [AccountID]= @NewId

        delete invAccountPropertyDetails where [AccountID]= @NewId	
	end     


   declare @Idoc int
   --<Property>
   exec sp_xml_preparedocument @Idoc out ,@xmlPropertyData
   
   insert invAccountPropertyDetails([AccountId],[PropertyId],[SubPropertyId])
   select @NewId,[PropertyId],[SubPropertyId] from openxml(@Idoc,'/TableHeader/Table1',2)
   with
   (
		PropertyId int '@PropertyId',
		SubPropertyId int '@SubPropertyId'
   )
   
   exec sp_xml_removedocument @Idoc 
   --<Property/>  
     
  
  select @NewId ID,0 status ,'Saved Successfully. '+ isnull(@WarnMessage,'') Message

go 



if object_id('prGetinvCustomerById') is not null
	drop proc prGetinvCustomerById
go	
	
create proc prGetinvCustomerById
@Id int,
@CompanyID int=1

as

set nocount on
set transaction isolation level read uncommitted

declare @OBE int
select @OBE=OpeningBalanceEquity from aAccountSettings where CompanyId=@CompanyId

declare @OB float
select @OB=case when CreditorID=@ID then -1 else 1 end*Amount from aTransaction where PeriodID is null and Date is null and VoucherTypeID is null and No is null and (DebtorID=@ID and CreditorID=@OBE or DebtorID=@OBE and CreditorID=@ID) and CompanyID=@CompanyID 

select t2.[Id],t2.[Code],t2.[Name],t2.UnderAccountID,t3.Name Under,t1.[Name] [NickName],t2.NameInOL,
t1.[Address1],t1.[Address2],t1.[Address3],t1.[Place],t1.[TIN],t1.[CST],t1.[DLNo1],t1.[DLNo2],
t1.[Phone],t1.[MobileNo],t1.[Email],t1.[Web],t1.Location,t1.[ContactPerson],t1.[CreditLimit],
t1.[DueDays],t1.[CurrencyId],t1.[RateLevelId],t1.[SalesManId],t1.[PaymentTerms],t1.FileNo,t1.[Remark],
abs(@OB) OB,case when @OB<0 then 1 else 0 end OBType,t1.CompanyID,t1.GST,t1.PaymentMode,t1.Image,t1.Address4,t1.Address5,t1.Address6,t1.Address7,t1.Address8,t1.Address9,t1.CostCentreId,t1.Approve from invCustomer t1
join aAccount t2 on t1.AccountID = t2.Id 
join aAccount t3 on t2.UnderAccountID=t3.ID
where t2.Id = @Id 
union all
select t2.[Id],t2.[Code],t2.[Name],t2.UnderAccountID,t3.Name Under,t1.[Name] [NickName],t2.NameInOL,
t1.[Address1],t1.[Address2],t1.[Address3],null,t1.[TIN],t1.[CST],t1.[DLNo1],t1.[DLNo2],
t1.[Phone],t1.[MobileNo],t1.[Email],t1.[Web],t1.[Fax],t1.[ContactPerson],t1.[CreditLimit],
t1.[DueDays],t1.[CurrencyId],null,null,t1.[PaymentTerms],null,t1.[Remark],
abs(@OB) OB,case when @OB<0 then 1 else 0 end OBType,t1.CompanyID,t1.GST,null,null,null,null,null,null,null,null,null,null from invVendor t1
join aAccount t2 on t1.AccountID = t2.Id 
join aAccount t3 on t2.UnderAccountID=t3.ID
where t2.Id = @Id 


select t1.Name Property,ISNULL(t3.Name,'') [Sub Property],isnull(t2.SubPropertyId,0) SubPropertyId  from invAccountProperty t1
left outer join invAccountPropertyDetails t2 on t1.Id = t2.PropertyId and t2.AccountId = @Id  
left outer join invAccountSubProperty t3 on t2.SubPropertyId = t3.Id  order by t1.Id 

go

IF OBJECT_ID('prGetPurchase') IS NOT NULL
	DROP PROC prGetPurchase

GO

create proc prGetPurchase  
@CompanyID int,  
@PeriodID int,  
@VtypeId int,  
@No int as  
  
set nocount on  
set transaction isolation level read uncommitted  
  
--Temporaraly Storing Purchase Uom Details   
delete tmpPurchaseUomDetails where ProcId = @@spid  
insert tmpPurchaseUomDetails(ProcId,Sno,ProductId,UomId,LevelId,Rate)  
select @@spid,Sno,ProductId,UomId,LevelId,Rate from invPurchaseUomDetails   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No  
-----------------------------------------  
  
select t1.[No],t1.[Date],t1.[DeliveryDate],t1.[VendorId],t2.Name [Vendor],t1.[PaymentMode],t1.[InvoiceNo],  
t1.[LRNo],t1.[DueDate],t1.[Total],t1.[DiscountP],t1.[Discount],t1.[NetTotal],t1.[Notes],  
t1.[TaxCalculation],t1.[Tax],t1.[TaxType],RoundOff,Paid,t1.InterState,t1.CurrencyId,t1.FromAccountId,t1.ChequeNo,t1.ChequeDate,  
t1.Status,t1.SalesOrderRefNo,t1.Image,t1.Advance,t1.CostCentreId,t1.Discount1,t1.Discount2,t1.Discount3,t1.BillTaxGroupID,t1.BillTax,t1.Image1,t1.SalesManId,t1.Address from invPurchaseHeader t1  
join aAccount t2 on t1.VendorId = t2.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No  
  
declare @Details table(PSNo int,Code nvarchar(50),Particulars nvarchar(200),ProductId int,Warehouse varchar(50),WarehouseId int,Uom varchar(50),  
UomId int,Qty float,Foc float,FRate float,Rate float,CostPrice float,Profit float,SRate float,WRate float,Gross float,DiscountP float,Discount float,Total float,MfrDate smalldatetime,  
ExpDate smalldatetime,Remark varchar(100),TaxGroupId int,TaxGroup varchar(50),TaxP float,Tax float,IType int,IPeriodID int,INo int,ISno int,IQty float,IFOC float,Mrp float,UBC varchar(50),  
NativeCaption nvarchar(200),InactiveStock bit,NOP float,Addition float,CCode varchar(50),SerialNo bit,Point float,CostDistribution float,  
Discount1 float,NonStock bit,Pieces float)  
  
insert @Details(PSNo,Code,Particulars,ProductId,WarehouseId,Uom,UomId,Qty,Foc,FRate,Rate,CostPrice,Profit,SRate,WRate,Gross,DiscountP,  
Discount,Total,MfrDate,ExpDate,Remark,TaxGroupId,Tax,IType,IPeriodID,INo,ISno,IQty,IFOC,Mrp,NativeCaption,InactiveStock,Addition,NOP,  
SerialNo,Point,CostDistribution,Discount1,NonStock,Pieces)  
select t1.[Sno] PSNo,t2.[Code],t2.Name Particulars,t1.[ProductId],t1.[WarehouseId],t4.Name Uom,  
t1.[UomId],t1.[Qty],t1.[Foc],t1.[FRate],t1.[Rate],t1.[CostPrice],t1.[Profit],t1.[SRate],t1.WRate,t1.[Gross],t1.[DiscountP],  
t1.[Discount],t1.[Total],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],  
cast(cast(case when t1.[ExpDate]<21000101 then t1.[ExpDate] end as varchar) as datetime) [ExpDate] ,t1.[Remark],  
t1.TaxGroupId,t1.Tax,  
t1.[IType],t1.IPeriodID,t1.[INo],t1.[ISno],t1.[IQty],t1.[IFOC],ISNULL(t1.Mrp,0) Mrp,  
t2.OtherLanguage NativeCaption,ISNULL(t1.InactiveStock,0) InactiveStock,t1.Addition,1 NOP,isnull(t2.SerialNo,0),Point,CostDistribution,  
Discount1,t2.NonStockItem,isnull(t1.Pieces,0) from invPurchaseDetails t1  
join invProduct t2 on t1.ProductId = t2.Id   
join invUom t4 on t1.UomId = t4.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No    
  
  
--Category Codes  
declare @@CatPropID int  
select @@CatPropID=CategoryPropertyID from invOption where CompanyID=@CompanyID  
  
declare @Category table(ProductID int,Code varchar(50))  
  
if @@CatPropID is not null  
Begin  
 insert @Category  
 select pp.ProductID,sp.Code from invProductPropertyDetails pp join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID  
End  
  
update d set d.CCode=c.Code from @Details d join @Category c on d.ProductID=c.ProductID  
  
--Barcode  
update d set d.UBC=ul.Barcode from @Details d join invUOMLevels ul on d.ProductID=ul.ProductID and d.UOMId=ul.UOMID  
  
--WareHouse  
update d set d.WareHouse=w.Name from @Details d join invWareHouse w on d.WarehouseID=w.ID  
  
--Tax Group  
update d set d.TaxGroup=t.Name,d.TaxP=t.InputTax from @Details d join invTaxGroup t on d.TaxGroupID=t.ID   
  
--NOP  
update d set d.NOP=ul.Multiplayer from @Details d join invUOMLevels ul on d.ProductID=ul.ProductID and ul.Secondary<>1 and ul.SNo<3  
  
--Final Selection  
select * from @Details order by PSno  
---------------------------  
  
select SNo,BarcodeId,Barcode,SRate,Printed,Sticker from invAutoBarcodeAndSalesRate   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No order by Sno  
  
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1  
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id   
join invPurchaseProperty t3 on t2.PropertyId = t3.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No order by t1.Sno   
  
select [PSno],[Sno],[SerialNo],[Id] from invProductSerialNumber   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No   
order by [PSno],[Sno]  
  
select a.CreditorID,c.Name Creditor,a.DebtorID,d.Name Debtor,a.Description,a.Amount,a.DNo from invPurchaseAdditions a  
join aAccount c on a.CreditorID=c.ID  
join aAccount d on a.DebtorID=d.ID  
where a.CompanyID = @CompanyID and a.PeriodID  = @PeriodID and a.[VtypeId] = @VtypeId and a.[No] = @No   
  
  
select t.ProductID,p.Name Product,t.OB,t.[In],t.[Out],t.Balance from invPurchaseTrayDetails t  
join invProduct p on t.ProductID=p.ID  
where t.CompanyID = @CompanyID and t.PeriodID  = @PeriodID and t.[VtypeId] = @VtypeId and t.[No] = @No   
  
GO

if object_id('prGetActiveProductForCompanyTransfer') is not null
	drop proc prGetActiveProductForCompanyTransfer
go	
   
create proc prGetActiveProductForCompanyTransfer
@CompanyId int  

as  

set nocount on  
set transaction isolation level read uncommitted

create table #Product ([ ] bit,Id int,Code varchar(100),Name nvarchar(300),NameInOL nvarchar(300),UBC varchar(50),TaxGroupID int,TaxGroup varchar(50),Tax float,TaxInclusive bit,SerialNo bit,Cost float,Stock float,NonStock bit)

insert #Product(Id,Code,Name,NameInOL,TaxGroupID,TaxInclusive,SerialNo,NonStock)
select Id,Code,Name,OtherLanguage,TaxGroupID,TaxInclusive,SerialNo,NonStockItem from invProduct 
where Inactive = 0 or Inactive is null order by Name


if exists(select 1 from invOption where (SalesStockItemsOnly=1 or SalesDisplayStock=1) and CompanyID=@CompanyID)--Stock
Begin
    
	declare @PurchaseProperty bit
	select top 1 @PurchaseProperty = 1 from invPurchaseSubProperty
	select @PurchaseProperty=SalesProperty from invProjectSettings where CompanyId=@CompanyID

	create table #PStock (CompanyID int,ProductID int,PurchaseSubPropertyID int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float) 
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct
	
	if @PurchaseProperty=1
	Begin
		insert #PStock(ProductID,PurchaseSubPropertyID,Qty) 
		exec spPurchasePropertyStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=0
	End
		
	Else
	Begin
		insert #PStock(CompanyID,ProductID,Rate,CP,SRate,WRate,MRP,Qty,Pieces) 
		exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=1

		if exists(select 1 from invOption where TaxOption=2 and CompanyID=@CompanyID)
			update p set p.Cost=s.Rate,p.Stock=s.Qty from #Product p join #PStock s on p.ID=s.ProductID and round(s.Qty,2)<>0
		else
			update p set p.Cost=s.CP,p.Stock=s.Qty from #Product p join #PStock s on p.ID=s.ProductID and round(s.Qty,2)<>0

		if exists(select 1 from invOption where SalesStockItemsOnly=1 and CompanyID=@CompanyID)
			delete #Product where (Stock<=0 or Stock is null) and (NonStock=0 or NonStock is null)
	
	
	End
	
End


--UBC
update p set p.UBC=u.Barcode from #Product p join invUOMLevels u on p.ID=u.ProductID

--TaxGroup
update p set p.TaxGroup=t.Name,p.Tax=t.OutputTax from #Product p join invTaxGroup t on p.TaxGroupID=t.ID


if exists(select top 1 1 from invOption where DefaultSearchInSales=3)
	select Code +'       '+ Name [Code + Name],* from #Product
else
	select *,replace(Name,'*','')Name1 from #Product 

go




if object_id('spRebuildIndex') is not null drop proc spRebuildIndex

go

create proc spRebuildIndex as 
declare @table_name varchar(100)
declare @table_schema varchar(100)
declare @cmd varchar(max)
declare curs cursor for select table_name,table_schema from information_schema.tables where table_type = 'BASE TABLE'
open curs
fetch next from curs into @table_name,@table_schema
while @@fetch_status = 0  
begin
    set @cmd = 'alter index all on '+ @table_schema +'.[' + @table_name + '] rebuild with (fillfactor = 80)'  
    exec (@cmd)  
	fetch next from curs into @table_name,@table_schema
end
close curs
deallocate curs


