if OBJECT_ID('prPurchaseDetailsPrint') is not null
	drop proc prPurchaseDetailsPrint
go

create proc prPurchaseDetailsPrint
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int as

set nocount on
set transaction isolation level read uncommitted

declare @PR table(Sno int,ProductID int,Code varchar(50),Particulars nvarchar(200),OtherLanguage nvarchar(200),Warehouse varchar(50),UOMID int,Uom varchar(50),
Qty float,Foc float,FRate float,Rate float,CostPrice float,Profit float,SRate float,Gross float,DiscountP float,Discount float,Total float,
Remark varchar(50),MfrDate smalldatetime,ExpDate smalldatetime,TaxGroup varchar(50),TaxP float,Tax float,Mrp float,UBC varchar(50),Barcode varchar(50),SerialNo varchar(8000),CategoryCode nvarchar(100))

insert @PR(Sno,ProductID,Code,Particulars,OtherLanguage,Warehouse,UOMID,Uom,Qty,Foc,FRate,Rate,CostPrice,Profit,SRate,Gross,DiscountP,Discount,Total,Remark,MfrDate,ExpDate,TaxGroup,TaxP,Tax,Mrp)
select t1.[Sno],t1.ProductID,t2.[Code],t2.Name Particulars,t2.OtherLanguage,isnull(t3.Name,0) Warehouse,t1.UOMID,t4.Name Uom,
t1.[Qty],t1.[Foc],t1.[FRate],t1.[Rate],t1.[CostPrice],t1.[Profit],t1.[SRate],t1.[Gross],t1.[DiscountP],
t1.[Discount],t1.[Total],t1.[Remark],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],
cast(cast(t1.[ExpDate] as varchar) as datetime) [ExpDate],isnull(t5.Name,'') TaxGroup,isnull(t5.OutputTax,0) TaxP,t1.Tax,
ISNULL(t1.Mrp,0) Mrp from invPurchaseDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
left outer join invWarehouse t3 on t1.WarehouseId = t3.Id 
join invUom t4 on t1.UomId = t4.Id 
left outer join invTaxGroup t5 on t1.TaxGroupId = t5.Id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No

--UBC
update p set p.UBC=u.Barcode from @PR p join invUOMLevels u on p.ProductID = u.ProductID and p.UomId = u.UomId

--Barcode
update p set p.Barcode=b.Barcode from @PR p join invAutoBarcodeAndSalesRate b on @CompanyId=b.CompanyId and @PeriodId=b.PeriodId and @VtypeId=b.VtypeId and @No=b.No and p.Sno=b.Sno and p.ProductId=b.ProductId

--SerialNumber
declare @i int
set @i=1
while exists(select 1 from invProductSerialNumber where CompanyId=@CompanyId and VtypeId=@VtypeId and PeriodId=@PeriodId and No=@No and SNo=@i)
Begin
	update p set p.SerialNo=isnull(p.SerialNo+', ','')+b.SerialNo from @PR p join invProductSerialNumber b on @CompanyId=b.CompanyId and @PeriodId=b.PeriodId and @VtypeId=b.VtypeId and @No=b.No and p.Sno=b.PSno and b.SNo=@i
	set @i=@i+1
End



--Category Code
declare @CategoryPropertyId int
select @CategoryPropertyId = isnull(CategoryPropertyId,0) from invOption where CompanyId = @CompanyId

update t1 set t1.CategoryCode = t3.Code from  @PR t1
join invProductPropertyDetails t2 on t1.ProductId = t2.ProductId and t2.PropertyId = @CategoryPropertyId
join invProductSubProperty t3 on t2.SubPropertyId = t3.Id

select * from @PR order by Sno 

go

if object_id('prSalesReturnHeaderPrint') is not  null
  drop proc prSalesReturnHeaderPrint

go


create proc prSalesReturnHeaderPrint  
@CompanyID int,  
@PeriodID int,  
@VtypeId int,  
@No int 

as  

set transaction isolation level read uncommitted
set nocount on  

declare @SR table(No int,Date smalldatetime,DeliveryDate smalldatetime,Code varchar(50),Customer nvarchar(100),Under nvarchar(100),NameInOL nvarchar(100),VType varchar(50),Address1 nvarchar(100),Address2 nvarchar(100),Address3 nvarchar(100),Address4 nvarchar(100),Address5 nvarchar(100),Address6 nvarchar(100),Address7 nvarchar(100),Phone varchar(50),MobileNo varchar(50),TIN varchar(50),CST varchar(50),DLNo1 varchar(50),DLNo2 varchar(50),GST varchar(50),Place varchar(50),Email varchar(100),Location varchar(50),ContactPerson varchar(50),PaymentTerms varchar(50),PaymentMode varchar(50),SalesMan nvarchar(50),RateLevel varchar(50),Tax float,Total float,DiscountP float,Discount float,NetTotal float,Notes nvarchar(300),VTypeDetails varchar(50),Time int,RefNo varchar(50),Addition float,CustomerId int,SalesmanId int,RateLevelId int,Paid float,RoundOff float,QRCodeImage Image,InvoiceFormat nvarchar(100),BillTax float,SalesNo int)

insert @SR(No,Date,DeliveryDate,VType,PaymentMode,Tax,Total,DiscountP,Discount,NetTotal,Notes,VTypeDetails,Time,RefNo,Addition,CustomerId,SalesmanId,RateLevelId,Paid,RoundOff,QRCodeImage,BillTax,SalesNo)
select t1.[No],cast(cast(t1.[Date] as varchar) as datetime) [Date],cast(cast(t1.[DeliveryDate] as varchar) as datetime) [DeliveryDate],v.code VType,case when  t1.[PaymentMode] = 0 then 'Cash' else 'Credit' end [PaymentMode],t1.Tax,t1.[Total],t1.[DiscountP],t1.[Discount],t1.[NetTotal],t1.[Notes],v.Description VTypeDetails,t1.Time,t1.RefNo,t1.Addition,t1.CustomerId,t1.SalesmanId,t1.RateLevelId,t1.Paid,t1.RoundOff,t1.QRCodeImage,t1.BillTax,t1.SalesNo from invSalesReturnHeader t1  
join invVoucherTypeDetails v on t1.VTypeID=v.ID  
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No  

--Code
update s set s.Code=a.Code,s.NameInOL=a.NameInOL from @SR s join aAccount a on s.CustomerId=a.Id

--Name
update s set s.Customer=c.Name,s.Address1=c.Address1,s.Address2=c.Address2,s.Address3=c.Address3,s.Address4=c.Address4,s.Address5=c.Address5,s.Address6=c.Address6,s.Address7=c.Address7,s.Phone=c.Phone,s.MobileNo=c.MobileNo,s.TIN=c.TIN,s.CST=c.CST,s.DLNo1=c.DLNo1,s.DLNo2=c.DLNo2,s.GST=c.GST,s.Place=c.Place,s.Email=c.Email,s.Location=c.Location,s.ContactPerson=c.ContactPerson,s.PaymentTerms=c.PaymentTerms from @SR s join invCustomer c on s.CustomerId=c.AccountId

--Name
update s set s.Customer=c.Name,s.Address1=c.Address1,s.Address2=c.Address2,s.Address3=c.Address3,s.Phone=c.Phone,s.MobileNo=c.MobileNo,s.TIN=c.TIN,s.CST=c.CST,s.DLNo1=c.DLNo1,s.DLNo2=c.DLNo2,s.GST=c.GST,s.Email=c.Email,s.Location=c.Fax,s.ContactPerson=c.ContactPerson,s.PaymentTerms=c.PaymentTerms from @SR s join invVendor c on s.CustomerId=c.AccountId


--Under
update s set s.Under=u.Name from @SR s join aAccount a on a.Id=s.CustomerId join aAccount u on a.UnderAccountId=u.Id

--Salesman
update s set s.Salesman=a.Name from @SR s join invSalesman a on s.SalesmanId=a.Id

--Rate Level
update s set s.RateLevel=a.Name from @SR s join invRateLevel a on s.SalesmanId=a.Id

--Invoice Format
update t set t.InvoiceFormat=v.InvoiceFormat from @SR t join invVoucherTypeStartNo v on v.CompanyId=@CompanyID and v.PeriodId=@PeriodID and v.VtypeId=@VtypeID 

select * from @SR

GO

