if OBJECT_ID('prImportROLProducts') is not null
	drop proc prImportROLProducts

go

create proc prImportROLProducts
@WarehouseId int,
@CompanyId int=1
as

declare @Product table(Id int,MinStock float,ROL float)
insert @Product
select Id,MinStock,ROL from invProduct where MinStock<>0 or ROL<>0

create table #ROQ(CompanyId int,ProductId int,BarcodeId int,Qty float,Stock float,Moving float,Pieces float)
delete tmpTable where SPID=@@SPID
insert tmpTable(Id,SPId)
select Id,@@spid from @Product

insert #ROQ(CompanyId,ProductId,BarcodeId,Stock,Pieces)
exec spStock @Type=12,@ToDate=99999999,@WHID=@WarehouseId,@CompanyId=@CompanyId


-- Reached ROL/Min Stock 
delete s from #ROQ s join @Product p on s.ProductId=p.Id where isnull(p.ROL,0)<s.Stock and isnull(p.MinStock,0)<s.Stock
update s set s.Qty=p.MinStock-s.Stock from #ROQ s join @Product p on s.ProductId=p.Id


--Moving
;with m as
(select d.ProductId,sum(d.Qty)Qty from invSalesDetails d 
join #ROQ p on d.ProductId=p.ProductId and d.CompanyId=p.CompanyId 
join invSalesHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
where datediff(D,cast(cast(h.date as varchar) as smalldatetime),current_timestamp)<15
group by d.ProductId)

update r set r.Moving=m.Qty from #ROQ r join m on r.ProductId=m.ProductId

if object_id('pSalesDetails') is not null
Begin
	;with m as
	(select d.ProductId,sum(d.Qty)Qty from pSalesDetails d 
	 join #ROQ p on d.ProductId=p.ProductId and d.CompanyId=p.CompanyId 
	 join pSalesHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
	 where datediff(D,cast(cast(h.date as varchar) as smalldatetime),current_timestamp)<15
	 group by d.ProductId)

	 update r set r.Moving=m.Qty from #ROQ r join m on r.ProductId=m.ProductId
End

--Vendor
create table #Vendors(ProductId int,Id int)
insert #Vendors
select ProductId,max(VendorId) from invPreferredVendors group by ProductId
-----------


declare @dbo varchar(50)
select  @dbo=schema_name(schema_id) from sys.objects where name='fnGetProductPropertyColumnList'

create table #Cols(Cols nvarchar(max))
exec('insert #Cols select '+@dbo+'.fnGetProductPropertyColumnList(''t4.'',1)')

declare @PropertyColumns varchar(max)
select @PropertyColumns=','+Cols from #Cols


exec('
declare @Warehouse varchar(100)
select @Warehouse = Name from invWarehouse where Id = ' + @WarehouseId + '
select cast(0 as bit) [ ],t1.Code,t1.Name Particulars,t3.Barcode UBC,t1.Id ProductId,t2.Name Uom,t2.Id UomId,@Warehouse Warehouse,
' + @WarehouseId + ' WarehouseId,t1.MinStock,s.Stock,s.Moving,isnull(s.Qty,t1.ROQ)Qty,t3.Cost Rate' + @PropertyColumns + ',a.Code VCode,a.Name Vendor from invProduct t1
join invUom t2 on t1.PurchaseUom = t2.Id 
join (select ProductId,UOMId,max(Barcode)Barcode,max(Cost)Cost from invUomLevels group by ProductId,UOMId)t3 on t1.Id = t3.ProductId and t1.PurchaseUom = t3.UomId 
join vw_ProductProerty t4 on t1.Id = t4.Id 
left join #ROQ s on t1.Id=s.ProductId
left join #Vendors v on t1.Id=v.ProductId
left join aAccount a on v.Id=a.Id
where isnull(s.Qty,t1.ROQ)>0')


go

if object_id('prSalesReturnDetailsPrint2') is not null drop proc prSalesReturnDetailsPrint2

go

create proc prSalesReturnDetailsPrint2
@CompanyID int,  
@PeriodID int,  
@VtypeID int,  
@No int  

as  

set nocount on
set transaction isolation level read uncommitted

declare @Details table(SNo int,ProductId int,Rate float,Taxable float,Tax float,Total float)

insert @Details
select 1,max(case when p.HideFromDevice is null then ProductId end)ProductId
,sum(case when p.HideFromDevice is null then sd.Rate end)Rate
,sum(case when sd.Tax<>0 then Gross end)Taxable,sum(Tax)Tax,sum(Total)Total from invSalesReturnDetails sd
join invProduct p on sd.ProductId=p.Id
where CompanyID=@CompanyID and PeriodID=@PeriodID and VtypeID=@VtypeID and No=@No


select d.Sno,p.Name Product,d.Rate,d.Taxable,d.Tax/d.Taxable*100.0 TaxP,d.Tax,d.Total from @Details d
join invSalesReturnHeader h on h.CompanyId=@CompanyId and h.PeriodID=@PeriodID and h.VtypeID=@VtypeID and h.No=@No 
join invProduct p on d.ProductId=p.Id

go

if object_id('prSalesReturnDetailsPrint1') is not null
	drop proc prSalesReturnDetailsPrint1  
go
  
create proc prSalesReturnDetailsPrint1  
@CompanyID int,  
@PeriodID int,  
@VtypeID int,  
@No int  
as  

declare @Details table(SNo int,ProductID int,SerialNoID int,Qty float,Rate float,Total float,Property1 varchar(50),Property2 varchar(50),Property3 varchar(50))

insert @Details(SNo,ProductID,SerialNoID,Qty,Rate,Total)
select SNo,d.ProductId,d.SerialNoId,d.Qty,d.Rate,d.Total from invSalesReturnDetails d
where CompanyID=@CompanyID and PeriodID=@PeriodID and VtypeID=@VtypeID and No=@No


--Purchase Properties  
declare @Property table(Ord tinyint,SNo int,Property varchar(100))  
  
insert @Property  
select Ord,sd.SNo,sp.Name  
from   
(select row_number() over (partition by (select 1) order by ID)Ord,* from invPurchaseProperty) p  
cross join @Details sd  
join invPurchaseSubProperty sp on p.ID=sp.PropertyID  
join invSalesReturnPropertyDetails spd on sd.sno=spd.sno and sp.ID=spd.SubPropertyID  
where spd.CompanyID=@CompanyID and spd.PeriodID=@PeriodID and spd.VTypeID=@VTypeID and spd.No=@No  
  
update sd set sd.Property1=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=1  
update sd set sd.Property2=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=2  
update sd set sd.Property3=p.Property from @Details sd join @Property p on sd.sno=p.sno where p.Ord=3  


declare @DetailsSummary table(MinSNo int,MaxSNo int,ProductID int,SerialNo varchar(500),Qty float,Rate float,Total float,Property1 varchar(50),Property2 varchar(50),Property3 varchar(50))

insert @DetailsSummary(MinSNo,MaxSNo,ProductID,Qty,Rate,Total,Property1,Property2,Property3)
select min(SNo),max(SNo),d.ProductId,sum(d.Qty)Qty,d.Rate,sum(d.Total)Total,d.Property1,d.Property2,d.Property3 from @Details d
group by d.ProductId,d.Rate,d.Property1,d.Property2,d.Property3

declare @Counter int
select @Counter=max(MaxSno-MinSno) from @DetailsSummary

while @Counter>=0
Begin
	update s set s.SerialNo=ps.SerialNo+isnull(', '+s.SerialNo,'') from @DetailsSummary s 
	join @Details d on s.ProductID=d.ProductID and s.Rate=d.Rate and isnull(s.Property1,'')=isnull(d.Property1,'') and isnull(s.Property2,'')=isnull(d.Property2,'') and isnull(s.Property3,'')=isnull(d.Property3,'') and d.SNo=s.MinSNo+@Counter
	join invProductSerialNumber ps on d.SerialNoID=ps.Id

	set @Counter=@Counter-1

End

select ROW_NUMBER()over(order by (select 1))Sno,p.Name,s.SerialNo,Qty,s.Rate,Total,Property1,Property2,Property3 from @DetailsSummary s join invProduct p on s.ProductID=p.Id order by MinSNo

go


if object_id('prBillWiseProfitReport') is not null
  drop proc prBillWiseProfitReport

go
  
create proc prBillWiseProfitReport
@CompanyID int,
@From int,
@To int, 
@DetailPart bit,
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@ValueDataWhereClause varchar(max),
@MasterDataWhereClause varchar(max),  
@ProcessedValueWhereClause varchar(max),
@DetailsMasterDataWhereClause varchar(max)=null,
@Order varchar(max),
@GrandTotal varchar(max),
@AlterHeaderTable varchar(max),
@AlterGroupTable varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@CostCentreId int=0

as  
   
set nocount on  
set transaction isolation level read uncommitted

declare @WhereClause varchar(max),@Query varchar(max)    


create table #T1
(
  CompanyId int,
  InOut int,	
  PeriodID int,
  Date int,
  Vtype int,
  No int,
  Id int,
  WHID int,
  ProductId int, 
  BarcodeId int,
  SerialNoId int,
  Rate float,
  CRate float,
  SRate float,
  Qty float,
  FOC float,
  Discount float,
  Tax float
)


create table #T2
(
CompanyId int,
PeriodID int,
Vtype int,
No int,
Date int,
Rate float,
Cost float,
Sales float,
Tax float
)


create table #Filter
(
CompanyId int,
VtypeId int,
PeriodId int,
No int
)


create table #BillWiseProfit 
(
CompanyId int,
PeriodID int,
VtypeId int,
Company varchar(100),
Date datetime,
VType varchar(15),
[No] int,
CCode varchar(100),
Customer nvarchar(200),
SalesMan nvarchar(100),
SalesWithTax float,
Sales float,
Discount float,
NetSales as(Sales-isnull(Discount,0)),
Rate float,
Cost float,
Profit float,
[Profit %] float,
Commission float,
Tax float
)


if len(@ValueDataWhereClause) > 0 and LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = @ValueDataWhereClause + ' and ' + @MasterDataWhereClause 
else if len(@ValueDataWhereClause) > 0 
  set @WhereClause = @ValueDataWhereClause 
else if LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = @MasterDataWhereClause 


--For Getting Cost
create table #tmpTable (ID int,BarcodeId int)

if len(@WhereClause) > 0
  begin
	
	exec('insert #Filter select t1.CompanyId,t1.VtypeId,t1.PeriodId,t1.No from invSalesHeader t1 
	      where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		  and (t1.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
		  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @WhereClause)
	
	exec('insert #Filter 
	      select t1.CompanyId,t1.VtypeId,t1.PeriodId,t1.No from invSalesReturnHeader t1 
		  where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		  and (t1.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
		  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @WhereClause)
	
	if object_id('pSalesHeader') is not null
		exec('insert #Filter select t1.CompanyId,t1.VtypeId,t1.PeriodId,t1.No from pSalesHeader t1 
		      where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
			  and (t1.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
			  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @WhereClause)
	
	if object_id('RMSOrderHeader') is not null
		exec('insert #Filter select t1.CompanyId,0,t1.Period,t1.No from RMSOrderHeader t1 where (t1.Branch = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and convert(varchar,t1.date,112) between ' + @From +
		 ' and ' + @To	+ ' and ' + @WhereClause)
	
	declare @CTWhereClause varchar(max)
	select @CTWhereClause=replace(@WhereClause,'t1.CustomerId','c.AccountId')
	select @CTWhereClause=replace(@CTWhereClause,'t1.VtypeId','v.Id')
	select @CTWhereClause=replace(@CTWhereClause,'t1.CompanyId','t1.CompanyFrom')
	
	exec('insert #Filter select t1.CompanyFrom,v.Id,t1.PeriodId,t1.No from invCompanyTransferHeader t1 
	      join aCompany c on t1.CompanyFrom=c.Id
		  join invVoucherTypeDetails v on v.VTypeId=16
	      where (t1.CompanyFrom = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and t1.date between ' + @From +
		 ' and ' + @To	+ ' and ' + @CTWhereClause)
	
	select @CTWhereClause=replace(@WhereClause,'t1.VtypeId','v.Id')

	exec('insert #Filter select sh.CompanyId,v.Id,si.PeriodId,si.No from invServiceHeader sh 
		  join invServiceInvoice si on sh.ServiceID=si.ServiceID
		  join invServiceOrder t1 on si.ServiceId=t1.Id
	      join invVoucherTypeDetails v on v.VTypeId=18
	      where (sh.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and si.date between ' + @From +
		 ' and ' + @To	+ ' and ' + @CTWhereClause)
	
	
	exec('insert #Filter select t1.CompanyId,v.Id,t1.PeriodId,t1.No from invReturnHeader t1 
		  join invVoucherTypeDetails v on v.VTypeId=8
	      where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @CTWhereClause)
	

	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesDetails t1
	join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.VtypeId = t2.VtypeId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')

	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesReturnDetails t1
	join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.VtypeId = t2.VtypeId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')

	if object_id('pSalesDetails') is not null
		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct t1.ProductId,t1.BarcodeId from pSalesDetails t1
		join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.VtypeId = t2.VtypeId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')

	
	if object_id('RMSOrderDetails') is not null
		exec('insert #tmpTable (Id) 
		select distinct t1.ProductId from RMSOrderDetails t1
		join #Filter t2 on t1.Branch = t2.CompanyId and t1.Period=t2.PeriodId and t1.No = t2.No')
	

		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct t1.ProductId,t1.BarcodeId from invCompanyTransferDetails t1
		join invCompanyTransferHeader h on t1.PeriodId=h.PeriodId and t1.No=h.No
		join #Filter t2 on h.CompanyFrom = t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')
	
	if object_id('invServiceDetails') is not null 
		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct d.ProductId,d.BarcodeId from invServiceDetails d
		join invServiceHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
		join invServiceInvoice si on h.ServiceID=si.ServiceID
		join #Filter f on f.CompanyId = si.CompanyId and f.PeriodId=si.PeriodId and f.No = si.No')
	
	exec('insert #tmpTable (Id) 
	select distinct t1.ProductId from invReturnDetails t1
	join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.No = t2.No
	join invVoucherTypeDetails v on t2.VtypeId=v.id and v.vtypeid=8')

	end
else
  begin
	
	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesDetails t1
	join invSalesHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
	where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
	and (t2.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
	and t2.date between '+@From+' and '+@To)

	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesReturnDetails t1
	join invSalesReturnHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
	where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
	and (t2.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
	and t2.date between '+@From+' and '+@To)
	
	
	if object_id('pSalesDetails') is not null and object_id('pSalesHeader') is not null
		exec('insert #tmpTable (Id,BarcodeId)
		select distinct t1.ProductId,t1.BarcodeId from pSalesDetails t1
		join pSalesHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
		where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		and (t2.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
		and t2.date between '+@From+' and '+@To)

	

	if object_id('RMSOrderDetails') is not null
		exec('insert #tmpTable (Id)
		select distinct ri.InventoryID from RMSOrderDetails t1
		join RMSItem ri on t1.ItemID=ri.ItemID
		join RMSOrderHeader t2 on t1.Branch = t2.Branch and t1.Period = t2.Period and t1.OrderNo = t2.OrderNo
		where (t2.Branch = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and convert(varchar,t2.date,112) between '+@From+' and '+@To)
	
	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invCompanyTransferDetails t1
	join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
	where (t2.CompanyFrom = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and t2.date between '+@From+' and '+@To)


	if object_id('invServiceDetails') is not null 
		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct t1.ProductId,t1.BarcodeId from invServiceDetails t1
		join invServiceHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
		join invServiceInvoice si on t2.ServiceID=si.ServiceID
		where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and si.date between '+@From+' and '+@To)
	

	exec('insert #tmpTable (Id) 
	select distinct t1.ProductId from invReturnDetails t1
	join invReturnHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.No = t2.No
	where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and t2.date between '+@From+' and '+@To)

end


delete tmpTable where SPID=@@SPID


if exists(select 1 from invProjectSettings where AutoBarcode=1 and CompanyId=@CompanyID)
	insert tmpTable(SPID,ID,BarcodeId) 
	select distinct @@SPID,Id,isnull(BarcodeId,0) from #tmpTable
else
	insert tmpTable(SPID,ID) 
	select distinct @@SPID,Id from #tmpTable

insert #T1(CompanyId,InOut,Date,Vtype,No,Id,WHID,ProductId,BarcodeId,SerialNoId,Rate,CRate,SRate,Qty,FOC,Discount,Tax) 
exec spStock @CompanyID=@CompanyID,@ToDate=@To,@Type=10,@CostCentreId=@CostCentreId

update t1 set t1.Rate = t2.Cost,t1.CRate = Cost from #T1 t1  join invProduct t2 on t1.ProductId = t2.Id  where isnull(t2.NonStockItem,0) = 1


--removing all transactions except sales
delete #T1 where id not in(4,5,13,15,16,19,23)
delete #T1 where date not between @From and @To

update #T1 set qty = -qty,Discount=isnull(Discount,0) where id not in(13)
update #T1 set vtype=0 where vtype is null
update t1 set t1.PeriodID=p.ID from #T1 t1 join aPeriod p on t1.Date between p.[From] and p.[To]
update #T1 set Tax=0 where Tax is null
update #T1 set FOC=0 where FOC is null


declare @OptCompanyId int
set @OptCompanyId=@CompanyId
if (@OptCompanyId=0) select @OptCompanyId=min(Id) from aCompany

--SerialNo Cost
if exists(select 1 from invOption where CompanyId=@OptCompanyId and StockCalculation=2)
Begin
	update sr set sr.CRate=pd.Rate from #T1 sr
	join invProductSerialNumber psn on sr.SerialNoId=psn.Id
	join invOpeningStock pd on psn.CompanyId=pd.CompanyId and psn.PeriodId=pd.PeriodId and psn.VtypeId=0 and psn.No=pd.No and psn.PSno=pd.Sno

	update sr set sr.CRate=pd.CostPrice from #T1 sr
	join invProductSerialNumber psn on sr.SerialNoId=psn.Id
	join invPurchaseDetails pd on psn.CompanyId=pd.CompanyId and psn.PeriodId=pd.PeriodId and psn.VtypeId=1 and psn.No=pd.No and psn.PSno=pd.Sno
End
-----------------

--Ignore 0 Cost
if exists(select 1 from invOption where CompanyId=@OptCompanyId and IgnoreNoCostInProfit =1)
	delete #T1 where isnull(CRate,0)=0

if exists(select 1  from invOption where ProfitCalculation=1 and CompanyID=@OptCompanyId)--with out tax
	insert #T2 
	select CompanyId,PeriodID,vtype,No,Date,sum(qty*rate) Rate,sum(qty*crate) Cost, sum((qty-foc) * isnull(srate,crate)) - isnull(sum(discount),0) Sales,isnull(sum(Tax),0) from #T1 group by CompanyId,PeriodID,vtype,No,Date
else
	insert #T2 
	select CompanyId,PeriodID,vtype,No,Date,sum(qty * Rate) Rate,sum(qty * crate) Cost, sum((qty-foc) * isnull(srate,crate)) - isnull(sum(discount),0)+ isnull(sum(Tax),0) Sales,isnull(sum(Tax),0) from #T1 group by CompanyId,PeriodID,vtype,No,Date


declare @ServiceVTypeId int
select @ServiceVTypeId=Id from invVoucherTypeDetails where VTypeId=18
if (@ServiceVTypeId>0)
	insert #T2
	select si.CompanyId,si.PeriodID,@ServiceVTypeId,si.No,si.Date,null Rate,null Cost,sh.NetTotal,null from invServiceInvoice si
	join invServiceHeader sh on si.ServiceID=sh.ServiceID
	left join invServiceDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
	where si.Date between @From and @To and sd.No is null


--Addition1
if exists(select top 1 1 from invSalesDetails where Addition1<>0)
Begin
	create table #Addition(CompanyId int,PeriodId int,VtypeId int,No int,Addition1 float)
	insert #Addition
	select CompanyId,PeriodId,VtypeId,No,sum(Addition1)Addition1 from invSalesDetails 
	where (CompanyId=@CompanyId or @CompanyId=0)and Addition1<>0
	group by CompanyId,PeriodId,VtypeId,No

	update b set b.Sales=b.Sales+isnull(s.Addition1,0) from #T2 b 
	join #Addition s on b.CompanyId=s.CompanyId and b.PeriodId=s.PeriodId and b.Vtype=s.VtypeId and b.No=s.No 
	
End

if len(@WhereClause) > 0
Begin
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,t1.Tax
	from #T2 t1
	join invSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.vtype = t6.vtypeid and t1.PeriodId=t6.PeriodId and t1.no = t6.no
	where t2.date between @From and @To

	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,-t2.discount, t1.sales - (isnull(t1.cost,0) - isnull(t2.discount,0)),t5.Commission,t1.Tax
	from #T2 t1
	join invSalesReturnHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.vtype = t6.vtypeid and t1.PeriodId=t6.PeriodId and t1.no = t6.no
	where t2.date between @From and @To

	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,0, t1.sales - (isnull(t1.cost,0)),t5.Commission,t1.Tax
	from #T2 t1
	join invCompanyTransferHeader t2 on t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyFrom = t1.CompanyId
	join invVoucherTypeDetails t3 on t3.VtypeId=16 and t1.vtype=0
	join aCompany c on t2.CompanyTo=c.Id
	join aAccount t4 on c.AccountId = t4.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	join #Filter t6 on t1.CompanyId=t6.CompanyId and t3.Id=t6.VtypeId and t1.PeriodId=t6.PeriodId and t1.no = t6.no
	where t2.date between @From and @To

	
	if object_id('pSalesHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,t1.Tax 
		from #T2 t1
		join pSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyID = t1.CompanyId
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		left join aAccount t4 on t2.CustomerId = t4.Id
		left outer join invSalesMan t5 on t2.SalesManId = t5.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.vtype = t6.vtypeid and t1.PeriodId=t6.PeriodId and t1.no = t6.no
		where t2.date between @From and @To

	if object_id('RMSOrderHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,SalesMan,Sales,Rate,Cost,Discount,Profit)
		select t1.CompanyId,t1.PeriodID,0,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t5.name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)) 
		from #T2 t1
		join RMSOrderHeader t2 on t1.no = t2.no and t2.Period = t1.PeriodID and t2.Branch = t1.CompanyId and t1.vtype is null
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		left outer join Waiter t5 on t2.Waiter = t5.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.PeriodId=t6.PeriodId and t1.no = t6.no and t1.vtype is null
		where convert(varchar,t2.date,112) between @From and @To

	
	if object_id('invServiceHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,Sales,Rate,Cost,Discount,Profit,Customer)
		select t1.CompanyId,t1.PeriodID,@ServiceVTypeId,c.Name,cast(cast(si.date as varchar) as datetime),t3.code,si.No,t2.NetTotal+t2.Discount,t1.Rate,t1.cost,si.discount, t2.NetTotal - (isnull(t1.cost,0)),a.Name
		from #T2 t1
		join invServiceHeader t2 on t1.Date>=t2.Date and t2.CompanyID = t1.CompanyId and t1.vtype=@ServiceVTypeId
		join invServiceInvoice si on t2.ServiceID=si.ServiceID and t1.no = si.no
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.PeriodId=t6.PeriodId and t1.no = t6.no and t1.vtype=t6.VtypeId
		join invServiceOrder o on si.ServiceId=o.Id
		join aAccount a on o.CustomerId=a.ID
		where convert(varchar,si.date,112) between @From and @To


		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.Discount,t1.sales -isnull(t2.Discount,0)- (isnull(t1.cost,0)),t5.Commission,Tax 
		from #T2 t1
		join invReturnHeader t2 on t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyId = t1.CompanyId
		join invVoucherTypeDetails t3 on t3.VtypeId=8 and t1.Vtype=t3.Id
		join aCompany c on t2.CompanyId=c.Id
		join aAccount t4 on t2.CustomerId = t4.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.PeriodId=t6.PeriodId and t1.no = t6.no and t1.vtype=t6.VtypeId
		left outer join invSalesMan t5 on t2.SalesManId = t5.Id
		where t2.date between @From and @To

End
else
Begin
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,t1.Tax 
	from #T2 t1
	join invSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  
	
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,-t2.discount, (t1.sales - (isnull(t1.cost,0) - isnull(t2.discount,0))),t5.Commission,t1.Tax 
	from #T2 t1
	join invSalesReturnHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  
	
	if object_id('pSalesHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,Tax 
		from #T2 t1
		join pSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.PeriodID = t1.PeriodID and t2.CompanyID = t1.CompanyId
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		left join aAccount t4 on t2.CustomerId = t4.Id
		left outer join invSalesMan t5 on t2.SalesManId = t5.Id
		where t2.date between @From and @To  


	if object_id('RMSOrderHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,SalesMan,Sales,Rate,Cost,Discount,Profit)
		select t1.CompanyId,t1.PeriodId,0,c.Name,t2.date,'RMS',t1.No,t5.Name,t1.sales,t1.Rate,t1.cost,t2.discountamount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discountamount,0)) 
		from #T2 t1
		join RMSOrderHeader t2 on t1.no = t2.Orderno and t2.Period = t1.PeriodID and t1.vtype=0 and t2.Branch = t1.CompanyId
		join aCompany c on t2.CompanyId=c.Id
		left outer join Waiter t5 on t2.Waiter = t5.Id
		where convert(varchar,t2.date,112) between @From and @To  
    

	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,0, t1.sales - (isnull(t1.cost,0)),t5.Commission,Tax 
	from #T2 t1
	join invCompanyTransferHeader t2 on t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyFrom = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype=0 and t3.VtypeId=16
	join aCompany c on t2.CompanyTo=c.Id
	join aAccount t4 on c.AccountId = t4.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  

	if object_id('invServiceHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,Sales,Rate,Cost,Discount,Profit)
		--select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(si.date as varchar) as datetime),t3.code,si.No,t4.Code,t4.name,case when si.PaymentMode=1 or isnull(si.Amount,0)=0 then t2.NetTotal else si.Amount+si.Discount end,t1.Rate,t1.cost,si.Discount,case when si.PaymentMode=1 or isnull(si.Amount,0)=0 then t2.NetTotal else si.Amount end-isnull(t1.cost,0)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(si.date as varchar) as datetime),t3.code,si.No,t4.Code,t4.name,t2.NetTotal+t2.Discount,t1.Rate,t1.cost,si.Discount,t2.NetTotal-isnull(t1.cost,0)
		from #T2 t1
		--join invServiceHeader t2 on t1.PeriodID = t2.PeriodID and t2.CompanyID = t1.CompanyId and t1.vtype=@ServiceVTypeId
		join invServiceHeader t2 on t1.Date>=t2.Date and t2.CompanyID = t1.CompanyId and t1.vtype=@ServiceVTypeId
		join invServiceInvoice si on t2.ServiceID=si.ServiceID and t1.no = si.no
		join invVoucherTypeDetails t3 on t1.vtype=t3.Id
		join invServiceOrder so on t2.ServiceID=so.ID
		join aAccount t4 on so.CustomerId = t4.Id
		join aCompany c on t2.CompanyId=c.Id
		where si.date between @From and @To  
	
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.Discount, t1.sales -isnull(t2.Discount,0)- (isnull(t1.cost,0)),t5.Commission,Tax 
	from #T2 t1
	join invReturnHeader t2 on t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyId = t1.CompanyId
	join invVoucherTypeDetails t3 on t3.VtypeId=8 and t1.Vtype=t3.Id
	join aCompany c on t2.CompanyId=c.Id
	join aAccount t4 on t2.CustomerId = t4.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  

End

update #BillWiseProfit set [Profit %] = ([Profit] * 100) / [Cost] where isnull([Cost],0) <> 0 

update #BillWiseProfit set Commission = Profit * Commission/100.0 where Commission<>0

update #BillWiseProfit set SalesWithTax=Sales+Tax --where Tax<>0

if len(@ProcessedValueWhereClause) > 0
  exec('delete t1 from #BillWiseProfit t1 where not ' +  @ProcessedValueWhereClause )

 

if @DetailPart = 1
begin

create table #BillWiseProfitDetails
(
CompanyId int,
PeriodID1 int,
VtypeId1 int,
No1 int,
Warehouse nvarchar(100),
Product nvarchar(200), 
Qty float,
ICost float,
SRate float,
ITotalCost float,
ISalesValue float,
IProfit float
)

if len(@DetailsMasterDataWhereClause)>0
	set @DetailsMasterDataWhereClause=' and ' + @DetailsMasterDataWhereClause

if exists(select 1  from invOption where ProfitCalculation=1 and CompanyID=@OptCompanyId)--with out tax
	exec('insert #BillWiseProfitDetails 
	select t1.CompanyId,t1.PeriodID,t1.vtype,t1.No,wh.Name,t3.name,t1.qty,t1.CRate,t1.srate ,t1.qty * t1.CRate,
	(t1.qty-t1.FOC) * t1.srate-t1.Discount ,(t1.qty-t1.FOC) * t1.srate-t1.Discount - (t1.qty * t1.rate)  from #T1 t1
	join #BillWiseProfit t2 on t1.CompanyId=t2.CompanyId and t1.PeriodID=t2.PeriodID and t1.vtype = t2.vtypeid and t1.No = t2.No
	join invProduct t3 on t1.ProductId = t3.Id
	left join invWarehouse wh on t1.WHID=wh.Id
	where t1.qty<>0 '+@DetailsMasterDataWhereClause )

else

	exec('insert #BillWiseProfitDetails 
	select t1.CompanyId,t1.PeriodID,t1.vtype,t1.No,wh.Name,t3.name,t1.qty,t1.crate,t1.srate + t1.Tax/t1.qty ,t1.qty * t1.crate,
	(t1.qty-t1.FOC) * t1.srate-t1.Discount + t1.Tax,(t1.qty-t1.FOC) * t1.srate-t1.Discount + t1.Tax - (t1.qty * t1.crate)  from #T1 t1
	join #BillWiseProfit t2 on t1.CompanyId=t2.CompanyId and t1.PeriodID=t2.PeriodID and t1.vtype = t2.vtypeid and t1.No = t2.No
	join invProduct t3 on t1.ProductId = t3.Id
	left join invWarehouse wh on t1.WHID=wh.Id
	where t1.qty<>0'+@DetailsMasterDataWhereClause)

end 


if @DetailPart = 1
Begin
	--Addition1
	if exists(select top 1 1 from invSalesDetails where Addition1<>0)
	update b set b.ISalesValue=b.ISalesValue+isnull(s.Addition1,0) from #BillWiseProfitDetails b join #Addition s on b.PeriodId1=s.PeriodId and b.VtypeId1=s.VtypeId and b.No1=s.No 
	where s.CompanyId=@CompanyId and Addition1<>0
	
	update #BillWiseProfitDetails set IProfit=ISalesValue-ITotalCost
End


if @Group = 0
    begin  
        if @DetailPart = 0
            begin    
                if @GroupTotal = 0        
                    exec('select ' + @columns + ' from #BillWiseProfit ' + @order)
                else
                    begin
                        if len(@order) > 0
                            begin 
								set @Query = 'select ' + @columns +  ' from (select 0 row_id,' + @columns + ' from #BillWiseProfit union all select 1 row_id, ' + 				@GrandTotal + ' from #BillWiseProfit  ) p ' + replace(@order,'order by','order by row_id,')
                                exec(@Query)
                            end 
                        else
                            exec('select ' + @columns + ' from #BillWiseProfit union all select ' + @GrandTotal + ' from #BillWiseProfit ' )
                    end          
            end
        else
			begin
				if @GroupTotal = 0        
					exec('select ' + @columns +  ' from #BillWiseProfit T1 JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId ' + @order)
                else
                    begin
                        if len(@order) > 0
                            begin
                                set @Query = 'select ' + @columns + ' from(select 0 row_id,' + @columns +  ' from #BillWiseProfit T1 JOIN #BillWiseProfitDetails T2 ON 
                                T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId
								union all select 1 row_id,' + @GrandTotal +  ' from #BillWiseProfit T1 
								JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId ) p '  + replace(@order,'order by','order by row_id,')
                                exec(@Query)
                            end	
                        else		
                            exec('select ' + @columns +  ' from #BillWiseProfit T1 
							JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1  and T1.CompanyId = T2.CompanyId
							union all  
							select ' + @GrandTotal +  ' from #BillWiseProfit T1 
                            JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId ' )  
                    end
            end


   end	
			
else  
	begin 
		create table #ProfitGroup(Rid numeric identity(1,1))  
		exec(@AlterGroupTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #ProfitGroup
	end   


drop table #BillWiseProfit

if @DetailPart = 1
	drop table #BillWiseProfitDetails

go

if OBJECT_ID('prLPODetailsPrint') is not null
	drop proc prLPODetailsPrint
go

create proc prLPODetailsPrint
@CompanyId int , 
@PeriodId int, 
@VtypeId int,
@No int as

set nocount on
set transaction isolation level read uncommitted

declare @LPO table(Sno int,ProductID int,Code varchar(50),Particulars nvarchar(200),OtherLanguage nvarchar(200),UOMID int,Barcode varchar(50),Warehouse varchar(50),Uom varchar(50),Qty float,Foc float,FRate float,Rate float,Gross float,DiscountP float,Discount float,Total float,Remark nvarchar(100),Property1 varchar(50),Property2 varchar(50),Property3 varchar(50),TaxGroupId int,TaxP float,Tax float,LUOM varchar(50),LMultiplier float)

insert @LPO(Sno,ProductID,Code,Particulars,OtherLanguage,UOMID,Warehouse,Uom,Qty,Foc,FRate,Rate,Gross,DiscountP,Discount,Total,Remark,TaxGroupId,Tax)
select t1.[Sno],t1.ProductID,t2.[Code],t2.Name Particulars,t2.OtherLanguage,t1.UOMID,t1.WarehouseID,t4.Name Uom,
t1.[Qty],t1.[Foc],t1.[FRate],t1.[Rate],t1.[Gross],t1.[DiscountP],
t1.[Discount],t1.[Total],t1.[Remark],t1.TaxGroupId,t1.Tax  from invLPODetails  t1
join invProduct t2 on t1.ProductId = t2.Id 
join invUom t4 on t1.UomId = t4.Id 
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No

--Warehose
update l set l.WareHouse=w.Name from @LPO l join invWarehouse w on l.WareHouse=w.Id 

--UBC
update sd set sd.Barcode=u.Barcode from @LPO sd join invUomLevels u on sd.ProductId = u.ProductId and sd.UOMID = u.UomId

--TaxP
update sd set sd.TaxP=t.OutputTax from @LPO sd join invTaxGroup t on sd.TaxGroupId=t.Id


--LUOM,LMultiplier
update l set l.LUOM=u.Name,l.LMultiplier=ul.Multiplayer from @LPO l join invUOMLevels ul on l.ProductId=ul.ProductId and l.UOMId=ul.UOMId join invUOM u on ul.UnitId=u.Id


--Properties  
declare @Property table(Ord tinyint,SNo int,Property varchar(100))  
  
insert @Property  
select Ord,sd.SNo,sp.Name  
from   
(select row_number() over (partition by (select 1) order by ID)Ord,* from invPurchaseProperty) p  
cross join @LPO sd  
join invPurchaseSubProperty sp on p.ID=sp.PropertyID  
join invLPOPropertyDetails spd on sd.sno=spd.sno and sp.ID=spd.SubPropertyID  
where spd.CompanyID=@CompanyID and spd.PeriodID=@PeriodID and spd.VTypeID=@VTypeID and spd.No=@No  
  
update sd set sd.Property1=p.Property from @LPO sd join @Property p on sd.sno=p.sno where p.Ord=1  
update sd set sd.Property2=p.Property from @LPO sd join @Property p on sd.sno=p.sno where p.Ord=2  
update sd set sd.Property3=p.Property from @LPO sd join @Property p on sd.sno=p.sno where p.Ord=3  

--Final
select Sno,Code,Particulars,OtherLanguage,Barcode,Warehouse,Uom,Qty,Foc,FRate,Rate,Gross,DiscountP,Discount,Total,Remark,Property1,Property2,Property3,TaxP,Tax,LUOM,LMultiplier from @LPO

go

alter proc prGetFilteredProducts
@TaxGroupID int=0,
@Filter varchar(max)=null,
@Product varchar(50)='' ,
@ZeroStockDate int=0,
@CompanyId int=1

as

set transaction isolation level read uncommitted
set nocount on

create table #Product(Id int,Code nvarchar(50),Name nvarchar(200),BaseUOM int,TaxGroupId int,Cost float,Rate float,WRate float,MRP float)

declare @Columns varchar(max),@Alter varchar(max)
select @Columns = isnull(@Columns + ',','') + quotename(name),
@Alter = isnull(@Alter + ',','') + quotename(name) + ' varchar(100) '  from invRateLevel where isnull(Rate,0)=0 and name<>'WRate' order by Id

if @Columns is not null
Begin
	exec('alter table #Product add ' + @Alter )

	exec('insert #Product
	      select Id,Code,Name,BaseUOM,TaxGroupId,Cost,Rate,WRate,MRP,'+@Columns+' from
          (select t1.Id,t1.Code,t1.Name,t1.BaseUOM,t1.TaxGroupId,t1.Cost,t1.Rate,t1.WRate,t1.MRP,rl.Name rlName,t2.Rate rlRate from invProduct t1
           left join invBarcode t2 on t1.Id=t2.ProductId and t1.BaseUOM=t2.UOMId
           left join (select * from invRateLevel where isnull(Rate,0)=0) rl on t2.LevelId=rl.Id)d
		   pivot
           (max(rlRate) for rlName in ('+@Columns+')) 
		   piv;
		 ')
End
Else
	insert #Product
	select Id,Code,Name,BaseUOM,TaxGroupId,Cost,Rate,WRate,MRP from invProduct	

if @ZeroStockDate>0
Begin
	declare @T1 table(CompanyId int,ProductID int,Qty float,Pieces float)
	insert tmpTable(SPID,ID) 
	select @@spid,id from #Product
	insert @T1(CompanyId,ProductID,Qty,Pieces) 
	exec spStock @CompanyID=0,@ToDate=@ZeroStockDate,@Type=12
	delete @T1 where Round(Qty,2)=0
	delete p from #Product p join @T1 t on p.Id=t.ProductId --where t.ProductId is null
End


if exists(select 1 from invOption where SalesRate=1 and CompanyID=@CompanyId)--Last
Begin
	--SRate 
	create table #SRate(Date int,ProductID int,SRate float,WRate float,MRP float)

	insert #SRate(Date,ProductID,SRate,WRate,MRP)
	select Date,ProductID,SRate,WRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate,WRate,MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1

	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate,MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1


	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by pd.Date desc)sno,pd.Date,ProductID,SRate,MRP from invProductionHeader pd
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1


	if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
		insert #SRate(Date,ProductID,SRate)
		select Date,ProductID,SRate from
		(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where pd.CompanyID=@CompanyID and (SRate>0)
		)a where sno=1


	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SalesRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SalesRate,MRP from invOpeningStock pd
	join invOpeningStockHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SalesRate>0 or MRP>0)
	)a where sno=1

	if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
		insert #SRate(Date,ProductID,SRate)
		select Date,ProductID,SRate from
		(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where ph.CompanyTo=1 and (SRate>0)
		)a where sno=1
	
	

	insert #SRate(Date,ProductID,SRate)
	select Date,ProductID,SRate from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invGoodsReceiptDetails pd
	join invGoodsReceiptHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0)
	)a where sno=1

	

	insert #SRate(Date,ProductID,SRate,WRate,MRP)
	select Date,ProductID,Rate,WRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.FromDate desc)sno,ph.FromDate Date,ProductID,Rate,WRate,MRP from invQtyRateSettingsDetails pd
	join invQtyRateSettingsHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (Rate>0 or MRP>0) and ToDate is null and Type=3
	)a where sno=1
	
	

	--Updation
	;with r as
	(select * from 
	(select ROW_NUMBER() over (partition by ProductID order by Date desc)Sno,ProductID,SRate,WRate,MRP from #SRate)a where sno=1
	)

	update p set p.Rate=r.SRate,p.WRate=r.WRate,p.MRP=r.MRP from #Product p join r on p.Id = r.ProductID
End

set @Columns=isnull(','+@Columns,'')

if len(@Filter)>0
	exec('select ROW_NUMBER()over(order by t1.Name)SNo,t1.Id ProductId,t1.Code,t1.Name Particulars,u.Id UOMId,u.Name UOM,t1.Cost,t1.Rate,t1.WRate,t1.MRP'+@Columns+' from #Product t1
	join invUOM u on t1.BaseUOM=u.Id
	left join vw_ProductProerty t3 on t1.Id = t3.Id 
	where ' + @Filter + ' 
	and (t1.TaxGroupID='+@TaxGroupID+'or '+@TaxGroupID+'=0) 
	and t1.Code + t1.Name like ''%'+@Product+'%''
	order by t1.Name')
else
	exec('select ROW_NUMBER()over(order by t1.Name)SNo,t1.Id ProductId,t1.Code,t1.Name Particulars,u.Id UOMId,u.Name UOM,t1.Cost,t1.Rate,t1.WRate,t1.MRP'+@Columns+' from #Product t1 
	join invUOM u on t1.BaseUOM=u.Id
	where (t1.TaxGroupID='+@TaxGroupID+' or '+@TaxGroupID+'=0) 
	and t1.Code + t1.Name like ''%'+@Product+'%''')


go

if OBJECT_ID('prGetProductStockAndRates') is not null
	drop proc prGetProductStockAndRates
go

	 
create proc prGetProductStockAndRates
@CompanyID int,
@ProductId int,
@UomId int=null,
@BarcodeID int=null,
@WareHouseID int=null,
@QtyRate tinyint=0, --  0-Qty , 1-Rate , 2-Qty & Rate
@Date int=99999999,
@SerialNoId int=null

as

set nocount on
set transaction isolation level read uncommitted

declare @T1 table 
(
Date int,
WHID int,
CompanyID int,
ProductId int,
BarcodeID int,
Rate float,
CP float,
SRate float,
WRate float,
MRP float,
Qty float,
Pieces float
)


if exists(select 1 from invOption where CompanyID=@CompanyID and StockCalculation=1)
Begin
	set @BarcodeID=null
	set @SerialNoId=null
End

if @BarcodeId>0
Begin
	insert tmpTable(SPID,ID,BarcodeID) values(@@spid,@ProductId,@BarcodeID)
	if @QtyRate=1 
		insert @T1(ProductID,BarcodeID,Rate,CP,SRate) 
		exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=5
	else
		insert @T1 (CompanyId,ProductID,BarcodeID,Rate,CP,SRate,Qty) 
		exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=4
End
Else
Begin
	if @WareHouseID>0
	Begin
		insert tmpTable(SPID,ID) values(@@spid,@ProductId)
		insert @T1(CompanyID,WHID,ProductID,Rate,CP,SRate,Qty,Pieces) 
		exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=6,@WHID=@WareHouseID
		delete @T1 where WHID<>@WareHouseID
	End
	Else
	Begin
		if @QtyRate=0 --Qty
		Begin
			Begin
				declare @T3 table(CompanyId int,ProductID int,BarcodeId int,Qty float,Pieces float)
				insert tmpTable(SPID,ID) values(@@spid,@ProductId)
				insert @T3(CompanyId,ProductID,BarcodeId,Qty,Pieces)
				exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=12

				insert @T1(CompanyId,ProductID,Qty,Pieces)
				select CompanyId,ProductID,sum(Qty),sum(Pieces) from @T3 group by CompanyId,ProductID

			End
		End
		else if @QtyRate=1 --Rate
		Begin
			
			if exists(select 1 from invOption where CompanyID=@CompanyID and GlobalCost=1) 
				set @CompanyID=0

			insert tmpTable(SPID,ID) values(@@spid,@ProductId)
			insert @T1(Date,ProductID,BarcodeID,Rate,CP,SRate) 
			exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=15
		End
		else if @QtyRate=2 -- Qty & Rate
		Begin
			
			insert tmpTable(SPID,ID) values(@@spid,@ProductId)

			insert @T1(CompanyID,ProductID,Rate,CP,SRate,WRate,MRP,Qty,Pieces) 
			exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=1

			if (@BarcodeID>0)
			Begin
				declare @T2 table(Date int,ProductId int,BarcodeID int,Rate float,CP float,SRate float)

				insert tmpTable(SPID,ID) values(@@spid,@ProductId)
				insert @T2(Date,ProductID,BarcodeID,Rate,CP,SRate) 
				exec spStock @CompanyID=@CompanyID,@ToDate=@Date,@Type=2
			
				;with t2 as(select top 1 Rate,CP,SRate from @T2 order by date desc,BarcodeID desc)
					update t1  set t1.Rate=t2.Rate,t1.CP=t2.CP,t1.SRate=t2.SRate from @T1 t1 cross join t2
			End

			if exists(select 1 from @t1 where Rate is null or CP is null)
				update t1  set t1.Rate=t2.Cost,t1.CP=t2.Cost,t1.SRate=t2.Rate from @T1 t1 join invProduct t2 on t2.ID=@ProductId
			
		End
	End
End

declare @Secondary float
select top 1 @Secondary = Secondary from invUomLevels where ProductId = @ProductId and UomId = @UomId order by Sno 


if @Secondary is not null
	update @T1 set Qty=Qty/@Secondary,Rate=Rate*@Secondary,CP=CP*@Secondary,SRate=SRate*@Secondary

if not exists(select 1 from @T1)
	insert @T1(Rate,CP,SRate)
	select Cost,Cost,Rate from invUOMLevels where ProductId=@ProductID and UOMId=@UOMId



if exists(select 1 from invOption where Companyid=@CompanyId and StockCalculation=2)
Begin
	Begin
		declare @MasterDataWhereClause varchar(100)
		set @MasterDataWhereClause=' t1.Id='+cast(@ProductId as varchar)
		declare @CP float
		set @CP=1
		exec prIMIStockReport @CompanyId=@CompanyId,@Date=@Date,@MasterDataWhereClause=@MasterDataWhereClause,@Type=@CP output

		update t set t.Rate=@CP,t.CP=@CP from @T1 t where @CP>0
	End
End

if (@SerialNoId>0)
Begin
	declare @SerialRate table(Rate float,CP float,SRate float)

	insert @SerialRate(Rate,CP,SRate)
	select p.Rate,p.CostPrice,p.SRate from invProductSerialNumber s 
	join invPurchaseDetails p on s.CompanyId=p.CompanyId and s.PeriodId=p.PeriodId and s.VtypeId=p.Vtypeid and s.No=p.No and s.PSNo=p.SNo
	where s.Id=@SerialNoId

	update t set t.Rate=s.Rate,t.CP=s.CP,t.SRate=s.SRate from @T1 t cross join @SerialRate s

	update t set t.Rate=s.Rate,t.CP=s.Rate,t.SRate=s.SRate from @T1 t 
	join invCompanyTransferDetails s on s.SerialNoId=@SerialNoId
	join invCompanyTransferHeader h on s.PeriodId=h.PeriodId and s.No=h.No
	where h.CompanyTo=@CompanyId
End

update f set f.Rate=p.Cost,f.CP=p.Cost from @T1 f join invUOMLevels p on f.ProductID=p.ProductID and p.UOMId=@UOMId where f.Rate=0 or f.Rate is null

select top 1 Rate,CP,SRate,Qty,Pieces from @T1 order by date desc,BarcodeID desc


go


if object_id('prGetinvCarrier') is not null
	drop proc prGetinvCarrier
go	
	
create proc prGetinvCarrier
as
set nocount on

select t1.[Id],t1.[Code],t1.[Name],t1.[Address1],t1.[Address2],t1.[Address3],
t1.[Phone],t1.[MobileNo],t2.Name AccountName from invCarrier t1
left join aAccount t2 on t1.AccountId = t2.Id 
order by t1.Name 

go


if object_id('prGetinvCarrierById') is not null
	drop proc prGetinvCarrierById
go	
	
create proc prGetinvCarrierById
@Id int 
as
set nocount on

select t1.*,t2.name AccountName from invCarrier t1
left join aAccount t2 on t1.AccountID = t2.Id 
where t1.Id = @Id 

go

if object_id('prSaveinvCarrier') is not null
	drop proc prSaveinvCarrier
go	
	
create proc prSaveinvCarrier
@Id int,
@Code varchar(25),
@Name varchar(100),
@Address1 varchar(100),
@Address2 varchar(100),
@Address3 varchar(100),
@Phone varchar(50),
@MobileNo varchar(50),
@Email varchar(100),
@Web varchar(100),
@Fax varchar(50),
@Remark varchar(250),
@Air bit,
@Ground bit,
@Water bit,
@AccountId int,
@AccountName varchar(100),
@CompanyId int
as

set nocount on


declare @t table(ID int,Status tinyint,Message varchar(100)) 


--Insertion to account
declare @UnderID int
declare @AccountSubGroupId int

select @UnderId = Vendors from aAccountSettings
select @AccountSubGroupId = @UnderId



if exists (select 1 from invCarrier where Id <> @Id and Code = @code )
begin
  select 0 Id,2 Status,'Duplicate Code' Message 
  return
end

if exists (select 1 from invCarrier where Id <> @Id and Name = @Name)
begin
  select 0 Id,3 Status,'Duplicate Name' Message
  return
end

if len(@AccountName)>0
Begin
	insert @t 
	exec spSaveAccount @ID=@AccountId,@Code=@Code,@Name=@AccountName,
		 @AccountSubGroupID=@AccountSubGroupID,@UnderAccountID=@UnderID,
		 @OB=0,@DrCr=0,@CompanyID=@CompanyID,@ModuleID=1,@IsAllowDuplicateName = 0

	if isnull(@AccountId,0) = 0 
	begin
	select @AccountId = ID from @t where Status=0
	if @AccountId is null or @AccountId = 0
	Begin
		select * from @t
		return
	End
	end
End

if isnull(@Id,0) = 0
  begin

      select @Id = isnull(max(id),0) + 1 from invCarrier 

      insert invCarrier([Id],[Code],[Name],[Address1],[Address2],[Address3],[Phone],[MobileNo],[Email],
      [Web],[Fax],[Remark],Air,Ground,Water,AccountId)
      values(@Id,@Code,@Name,nullif(@Address1,''),nullif(@Address2,''),nullif(@Address3,''),
      nullif(@Phone,''),nullif(@MobileNo,''),nullif(@Email,''),nullif(@Web,''),nullif(@Fax,''),
      nullif(@Remark,''),@Air,@Ground,@Water,nullif(@AccountId,0))	  

  end
else
	begin
		update invCarrier set [Name]= @Name,Code = @Code,
				      [Address1]= nullif(@Address1,''),
				      [Address2]= nullif(@Address2,''),
				      [Address3]= nullif(@Address3,''),
				      [Phone]= nullif(@Phone,''),
				      [MobileNo]= nullif(@MobileNo,''),
				      [Email]= nullif(@Email,''),
				      [Web]= nullif(@Web,''),
				      [Fax]= nullif(@Fax,''),
				      [Remark]= nullif(@Remark,''),
				      Air = @Air,Ground = @Ground, Water = @Water

		where [Id] = @Id


	end     
     
  
   select @Id ID,0 status ,'Saved Successfully' Message


go 

if object_id('spImportProductsFromExcel') is not null
    drop proc spImportProductsFromExcel

go

create proc spImportProductsFromExcel
@GeneralData xml,
@UomData1 xml,
@UomData2 xml,
@UomData3 xml,
@PropertyData xml,
@AutoEntry bit,
@UomLink int,
@RolRoq xml,
@MinMaxStock xml,
@CostCentre xml,
@RateLevel1 xml,
@RateLevel2 xml,
@RateLevel3 xml,
@IgnoreDuplicates bit=null,
@CompanyId int

as

set nocount on
set xact_abort on

declare @Message nvarchar(500)

begin tran 

declare @CostCentreID int,
        @MsrId int,
        @RateLevel int,
        @BranchId int ,
        @AccId int 

declare @Products table
(
Code varchar(50),
Name nvarchar(200),
NameInOL nvarchar(200),
BaseUom varchar(100),
PRate float,
SRate float,
WRate float,
MRP float,
Tax varchar(50),
Vendor varchar(100),
Id int,
ItemId int,
UomId int,
VendorId int,
Barcode varchar(50)
)


declare @Uom1 table
(
Uom varchar(100),
Barcode varchar(100),
EqualTo float,
Cost float,
Price float,
Id int,
UomId int
)

declare @Uom2 table
(
Uom varchar(100),
Barcode varchar(100),
EqualTo float,
Cost float,
Price float,
Id int,
UomId int
)

declare @Uom3 table
(
Uom varchar(100),
Barcode varchar(100),
EqualTo float,
Cost float,
Price float,
Id int,
UomId int
)




declare @Level1 table
(
Uom varchar(100),
Barcode varchar(100),
LevelId int,
Rate float,
Id int,
UomId int
)


declare @Level2 table
(
Uom varchar(100),
Barcode varchar(100),
LevelId int,
Rate float,
Id int,
UomId int
)


declare @Level3 table
(
Uom varchar(100),
Barcode varchar(100),
LevelId int,
Rate float,
Id int,
UomId int
)

declare @Rol table
(
Id int,
Rol float,
Roq float
)

declare @MinStock table
(
Id int,
Minimum float,
Maximum float
)

declare @Barcode table
(
Barcode varchar(100)
)

declare @Property table
(
Id int,
PropertyId int,
SubProperty nvarchar(100),
Code varchar(25),
SubPropertyId int 
)


declare @Cost_Centre table
(
Id int,
[Name] varchar(100),
CostCentreId int
)

set @Message = ''


declare @idoc int      
exec sp_xml_preparedocument @idoc output, @GeneralData

insert @Products (Code,Name,NameInOL,BaseUom,PRate,SRate,WRate,MRP,Vendor,Tax,Id,ItemId,UomId,VendorId,Barcode)
select Code,[Description],DescriptionInOL,BaseUom,replace(PRate,',',''),replace(SRate,',',''),replace(WRate,',',''),replace(MRP,',',''),Vendor,replace(Tax,',',''),Id,0 ItemId,0 UomId,0 VendorId,Barcode 
from openxml (@idoc, '/Details/Table1',2)      
with
(
Code varchar(50) '@Code',
Description nvarchar(100) '@Name',
DescriptionInOL nvarchar(100) '@NameInOL',
BaseUom varchar(100) '@BaseUom',
PRate nvarchar(50) '@PRate',
SRate nvarchar(50) '@SRate',
WRate nvarchar(50) '@WRate',
MRP nvarchar(50) '@MRP',
Vendor varchar(100) '@Vendor',
Tax nvarchar(50) '@Tax',
Barcode varchar(50) '@Barcode',
Id int '@Id'
)
exec sp_xml_removedocument @idoc 


if exists(select 1 from invOption where isnull(AllowDuplicateProduct,0)=0 and CompanyId=@CompanyId)
Begin
	select @Message='Duplicate Item Name ' + rtrim(Name) +' in the excel' from @Products where len(Name)>0 group by rtrim(Name) having count(rtrim(Name)) > 1
	if len(@Message)>0
	begin
	  commit tran
	  select @Message	
	  return
	end


	if (@IgnoreDuplicates=1)
		delete t1 from @Products t1 join invProduct t2 on rtrim(t1.Name) = rtrim(t1.Name)
	Else
	Begin
		select @Message='Already have the Item with Name ' + rtrim(t1.Name) +' in the Database. Please remove it from Excel' from @Products t1 join invProduct t2 on rtrim(t1.Name) = rtrim(t2.Name)
		if len(@Message)>0
		begin
		  commit tran
		  select @Message	
		  return
		end
	End


	if (isnull(@IgnoreDuplicates,0)=0)
	Begin
		select @Message='Duplicate Item code ' + Code +' in the excel' from @Products where len(code)>0 group by code having count(code) > 1
		if len(@Message)>0
		begin
		  commit tran
		  select @Message	
		  return
		end
	End

	if (@IgnoreDuplicates=1)
		delete t1 from @Products t1 join invProduct t2 on t1.code = t2.Code
	Else
	Begin
		select @Message='Already have the Item with Code ' + t1.Code +' in the Database. Please remove it from Excel' from @Products t1 join invProduct t2 on t1.code = t2.Code
		if len(@Message)>0
		begin
		  commit tran
		  select @Message	
		  return
		end
	End
End


if not exists (select top 1 1 from invUom)
begin
  set @Message = 'Please create at least one UOM'
  commit tran
  select @Message	
  return
end

declare @UOM varchar(50)
select @UOM=min(Name) from invUom


--<Uom Details>
exec sp_xml_preparedocument @idoc output, @UomData1
insert @Uom1 
select case when len(Uom)=0 then @UOM else Uom end,Barcode,case when EqualTo=0 then 1 else EqualTo end,isnull(Cost,0),isnull(Price,0),Id,0 UomId from openxml (@idoc, '/Details/Table1',2)      
with
(
Uom varchar(100) '@Uom1',
Barcode varchar(100) '@Barcode1',
EqualTo float '@EqualTo1',
Cost float '@Cost1',
Price float '@Price1',
Id int '@Id'
)
exec sp_xml_removedocument @idoc       


exec sp_xml_preparedocument @idoc output, @UomData2
insert @Uom2 select Uom,Barcode,EqualTo,isnull(Cost,0),isnull(Price,0),Id,0 UomId from openxml (@idoc, '/Details/Table1',2)      
with
(
Uom varchar(100) '@Uom2',
Barcode varchar(100) '@Barcode2',
EqualTo float '@EqualTo2',
Cost float '@Cost2',
Price float '@Price2',
Id int '@Id'
)
exec sp_xml_removedocument @idoc


exec sp_xml_preparedocument @idoc output, @UomData3
insert @Uom3 select Uom,Barcode,EqualTo,isnull(Cost,0),isnull(Price,0),Id,0 UomId from openxml (@idoc, '/Details/Table1',2)      
with
(
Uom varchar(100) '@Uom3',
Barcode varchar(100) '@Barcode3',
EqualTo float '@EqualTo3',
Cost float '@Cost3',
Price float '@Price3',
Id int '@Id'
)
exec sp_xml_removedocument @idoc


insert @Barcode select Barcode from @Uom1 where len(Barcode) > 0 and Barcode is not null
insert @Barcode select Barcode from @Uom2 where len(Barcode) > 0 and Barcode is not null
insert @Barcode select Barcode from @Uom3 where len(Barcode) > 0 and Barcode is not null

if (isnull(@IgnoreDuplicates,0)=0)
Begin
	select @Message='Duplicate barcode '+ Barcode +' in the Excel' from @Barcode group by Barcode having count(Barcode) > 1
	if len(@Message)>0
	begin
	  commit tran
	  select @Message	
	  return
	end
End

if (@IgnoreDuplicates=1)
	delete t1 from @Barcode t1 join invUOMLevels t2 on t1.Barcode = t2.Barcode	
Else
Begin
	select @Message='Already have the Item with Barcode ' + t1.Barcode +' in the Database. Please remove it from Excel' from @Barcode t1 join invUOMLevels t2 on t1.Barcode = t2.Barcode
	if len(@Message)>0
	begin
	  commit tran
	  select @Message	
	  return
	end
End


--<Sales Rate Level>
exec sp_xml_preparedocument @idoc output, @RateLevel1
insert @Level1 select Uom,Barcode,LevelId,isnull(Rate,0)Rate,Id,0 UomId from openxml (@idoc, '/Details/Table1',2)      
with
(
Uom varchar(100) '@Uom1',
Barcode varchar(100) '@Barcode1',
LevelId int  '@LevelId',
Rate float '@Rate',
Id int '@Id'
)
exec sp_xml_removedocument @idoc 


exec sp_xml_preparedocument @idoc output, @RateLevel2
insert @Level2 select Uom,Barcode,LevelId,isnull(Rate,0)Rate,Id,0 UomId from openxml (@idoc, '/Details/Table1',2)      
with
(
Uom varchar(100) '@Uom2',
Barcode varchar(100) '@Barcode2',
LevelId int  '@LevelId',
Rate float '@Rate',
Id int '@Id'
)
exec sp_xml_removedocument @idoc


exec sp_xml_preparedocument @idoc output, @RateLevel3
insert @Level3 select Uom,Barcode,LevelId,isnull(Rate,0)Rate,Id,0 UomId from openxml (@idoc, '/Details/Table1',2)      
with
(
Uom varchar(100) '@Uom3',
Barcode varchar(100) '@Barcode3',
LevelId int  '@LevelId',
Rate float '@Rate',
Id int '@Id'
)
exec sp_xml_removedocument @idoc


--</Sales Rate Level>


--Property
exec sp_xml_preparedocument @idoc output, @PropertyData
insert @Property select *,0 SubPropertyId from openxml (@idoc, '/Details/Table1',2)      
with
(
Id int '@Id',
PropertyId int '@PropertyId',
SubProperty nvarchar(100) '@SubProperty',
Code varchar(25) '@Code'
)
exec sp_xml_removedocument @idoc


--RolRoq
exec sp_xml_preparedocument @idoc output, @RolRoq
insert @Rol select Id,isnull(Rol,0),isnull(Roq,0) from openxml (@idoc, '/Details/Table1',2)      
with
(
Id int    '@Id',
Rol float '@Rol',
Roq float '@Roq'
)
exec sp_xml_removedocument @idoc

--Minimum & Maximum Stock
exec sp_xml_preparedocument @idoc output, @MinMaxStock
insert @MinStock select Id,isnull(Minimum,0),isnull(Maximum,0) from openxml (@idoc, '/Details/Table1',2)      
with
(
Id      int   '@Id',
Minimum float '@Minimum',
Maximum float '@Maximum'
)
exec sp_xml_removedocument @idoc


--Cost Centre
exec sp_xml_preparedocument @idoc output, @CostCentre
insert @Cost_Centre select Id,[Name],0 CostCentreId from openxml (@idoc, '/Details/Table1',2)      
with
(
Id  int '@Id',
[Name]  varchar(100) '@Name'
)
exec sp_xml_removedocument @idoc

--Update UOM Id [Base Uom]
update t2 set t2.UomId = t1.Id from invUOM t1
join @Products t2 on t1.Name = t2.BaseUom


select @MsrId = isnull(max(Id),0) from invUOM
;with t1 as (select distinct BaseUom from @Products where UomId = 0 and Len(BaseUom)>0)

insert invUOM (ID,Code,Name)
select row_number() over(order by (select 1)) + @MsrId, substring(BaseUom,1,25),BaseUom from t1

update t2 set t2.UomId = t1.ID from invUOM t1 join @Products t2 on t1.Name = t2.BaseUom where t2.UomId = 0 and len(t2.BaseUom)>0


--Uom Details 1
update t2 set t2.UomId = t1.ID from invUOM t1 join @Uom1 t2 on t1.Name = t2.Uom


select @MsrId = isnull(max(ID),0) from invUOM
;with t1 as (select distinct Uom from @Uom1 where UomId = 0)

insert invUOM (Id,Code,Name)
select row_number() over(order by (select 1)) + @MsrId, substring(Uom,1,25),Uom from t1

update t2 set t2.UomId = t1.Id from invUOM t1
join @Uom1 t2 on t1.Name = t2.Uom where t2.UomId = 0


--Uom Details 2
update t2 set t2.UomId = t1.ID from invUOM t1
join @Uom2 t2 on t1.Name = t2.Uom

select @MsrId = isnull(max(ID),0) from invUOM
;with t1 as (select distinct Uom from @Uom2 where UomId = 0)

insert invUOM (ID,Code,Name)
select row_number() over(order by (select 1)) + @MsrId, substring(Uom,1,25),Uom from t1

update t2 set t2.UomId = t1.ID from invUOM t1
join @Uom2 t2 on t1.Name = t2.Uom where t2.UomId = 0


--Uom Details 3
update t2 set t2.UomId = t1.Id from invUOM t1
join @Uom3 t2 on t1.Name = t2.Uom

select @MsrId = isnull(max(Id),0) from invUOM
;with t1 as (select distinct Uom from @Uom3 where UomId = 0)

insert invUOM (Id,Code,Name)
select row_number() over(order by (select 1)) + @MsrId, substring(Uom,1,25),Uom from t1

update t2 set t2.UomId = t1.ID from invUOM t1 join @Uom3 t2 on t1.Name = t2.Uom where t2.UomId = 0


-- Uom id updation in sales rate level
update t2 set t2.UomId = t1.ID from invUOM t1 join @Level1 t2 on t1.Name = t2.Uom

update t2 set t2.UomId = t1.ID from invUOM t1
join @Level2 t2 on t1.Name = t2.Uom

update t2 set t2.UomId = t1.ID from invUOM t1
join @Level3  t2 on t1.Name = t2.Uom
-----------------------------------------------

--select top 1 @CostCentreID=ID from invCostCentre


--Tax
declare @TaxGroupId int
select @TaxGroupId=isnull(max(ID),0)+1 from invTaxGroup

declare @TaxGroup table(Tax varchar(50))
insert @TaxGroup select distinct Tax from @Products where isnumeric(Tax)=1

insert invTaxGroup(Id,Code,Name,InputTax,OutputTax,PurchaseValueTitle,PurchaseTaxTitle,SalesValueTitle,SalesTaxTitle,CGST,SGST)
select @TaxGroupId+row_number() over(order by (select 1)),'T'+Tax,'Tax'+Tax,Tax,Tax,'VALUE'+Tax,'TAX'+Tax,'VALUE'+Tax,'TAX'+Tax,cast(Tax as float)/2.0,cast(Tax as float)/2.0 from @TaxGroup p left join invTaxGroup t on p.Tax=t.InputTax where t.Id is null

update p set p.Tax=t.Id from @Products p left join invTaxGroup t on p.Tax=cast(t.InputTax as varchar)

update p set p.Tax=t.Id from @Products p join invTaxGroup t on p.Tax=t.Name where p.Tax is null

-------

--Item Master
declare @ID int
select @ID=isnull(max(ID),0) from invProduct
insert invProduct(ID,Name,Code,OtherLanguage,BaseUOM,[Cost],Rate,WRate,MRP,SalesUOM,PurchaseUOM,StockUOM,MinUOM,MaxUOM,ROLUOM,ROQUOM,Autoentry,CostCentreID,TaxGroupId)
select ID+@ID,Name,code,NameInOL,nullif(UomId,0),PRate,SRate,WRate,MRP,UomId,UomId,UomId,UomId,UomId,UomId,UomId,@AutoEntry,@CostCentreID,nullif(Tax,0) from 
(select min(Id)Id,Name,Code,NameInOL,UomId,PRate,SRate,WRate,MRP,Tax from @Products group by Name,Code,NameInOL,UomId,PRate,SRate,WRate,MRP,Tax)P


--update uoms
update invProduct set BaseUOM=1,SalesUOM=1,PurchaseUOM=1,StockUOM=1,MinUOM=1,MaxUOM=1,ROLUOM=1,ROQUOM=1 where BaseUom is null

--Update ItemId
update t2 set t2.ItemId = t1.ID from invProduct t1
join @Products t2 on t1.code = t2.code and t1.Name=t2.Name

set @RateLevel = (select top 1 ID from invRateLevel order by ID)


--Uom1
insert invUOMLevels(SNo,ProductID,UOMID,Multiplayer,Secondary,UnitId,Cost,Rate,Barcode)
select 1,t2.ItemId,t1.UomId,t1.EqualTo,t1.EqualTo,t1.UomId,t1.Cost,t1.Price,t1.Barcode from @Uom1 t1
join @Products t2 on t1.Id = t2.Id


--Uom2
insert invUOMLevels(SNo,ProductID,UOMID,Multiplayer,Secondary,UnitId,Cost,Rate,Barcode)
select 2,t2.ItemId,t1.UomId,t1.EqualTo,t1.EqualTo,t3.UomId,t1.Cost,t1.Price,t1.Barcode from @Uom2 t1
join @Products t2 on t1.Id = t2.Id
join @Uom1 t3 on t1.Id = t3.Id




--Uom3
if @UomLink = 0
	begin
		insert invUOMLevels(SNo,ProductID,UOMID,Multiplayer,Secondary,UnitId,Cost,Rate,Barcode)
		select 3,t2.ItemId,t1.UomId,t1.EqualTo,t3.EqualTo * t1.EqualTo ,t3.UomId,t1.Cost,t1.Price,t1.Barcode from @Uom3 t1
		join @Products t2 on t1.Id = t2.Id
		join @Uom1 t3 on t1.Id = t3.Id
	end
else
	begin
		insert invUOMLevels(SNo,ProductID,UOMID,Multiplayer,Secondary,UnitId,Cost,Rate,Barcode)
		select 3,t2.ItemId,t1.UomId,t1.EqualTo,t3.EqualTo * t1.EqualTo ,t3.UomId,t1.Cost,t1.Price,t1.Barcode from @Uom3 t1
		join @Products t2 on t1.Id = t2.Id
		join @Uom2 t3 on t1.Id = t3.Id
	end


insert invUomLevels
select 1,Id,BaseUOM,1,BaseUom,1,Cost,Rate,null,null,Mrp,NRate from invProduct where id not in(select ProductId from invUomLevels)
------------------------

insert invBarcode(ProductID,Rate,LevelID,UOMID)
select distinct t2.ItemId,t1.Rate,t1.LevelId,t1.UomId from @Level1 t1
join @Products t2 on t1.Id = t2.Id

insert invBarcode(ProductID,Rate,LevelID,UOMID)
select distinct t2.ItemId,t1.Rate,t1.LevelId,t1.UomId from @Level2 t1
join @Products t2 on t1.Id = t2.Id

insert invBarcode(ProductID,Rate,LevelID,UOMID)
select distinct t2.ItemId,t1.Rate,t1.LevelId,t1.UomId from @Level3 t1
join @Products t2 on t1.Id = t2.Id

--Rol & Roq
update t3 set t3.ROL = t1.Rol,t3.ROQ = t1.Roq from @Rol t1
join @Products t2 on t1.Id = t2.Id
join invProduct t3 on t2.ItemId = t3.ID

--Minimum & Maximum Stock
update t3 set t3.MinStock = t1.Minimum,t3.MaxStock = t1.Maximum from @MinStock t1
join @Products t2 on t1.Id = t2.Id
join invProduct t3 on t2.ItemId = t3.Id

--<Property>
update t2 set t2.SubPropertyId = t1.ID from invProductSubProperty t1
join @Property t2 on  t1.PropertyID = t2.PropertyId and t1.Name = t2.SubProperty

select @MsrId = isnull(max(id),0) from invProductSubProperty

;with t1 as(select distinct PropertyId,SubProperty,Code from @Property where SubPropertyId = 0)
insert invProductSubProperty (ID,Code,Name,PropertyID,sImage)
select row_number() over(order by (select 1)) + @MsrId,case when len(code) > 0 then Code else substring(SubProperty,1,25) end,SubProperty,PropertyId,null from t1

update t2 set t2.SubPropertyId = t1.ID from invProductSubProperty t1
join @Property t2 on  t1.PropertyID = t2.PropertyId and t1.Name = t2.SubProperty

insert invProductPropertyDetails (ProductID,PropertyID,SubPropertyID)
select distinct t1.ItemId,t2.PropertyId,t2.SubPropertyId from @Products t1
join @Property t2 on t1.Id = t2.Id

--</Property>


--<Vendor>
--Acccr
update t2 set t2.VendorId = t1.ID from aAccount t1
join @Products t2 on  t1.Name = t2.Vendor
where len(t2.Vendor) > 0 and t1.AccountSubGroupID = 7

select @Accid = max(ID) from aAccount

;with t1 as (select distinct Vendor from @Products where VendorId = 0 and len(Vendor) > 0)
insert aAccount (ID,Name,AccountSubGroupID,UnderAccountID,ModuleID) 
select ROW_NUMBER()over(order by (select 1))+@Accid,vendor,7,7,1 from t1

update aAccount set Code = ID where ID > @AccId

--Addrs
insert invVendor(AccountID,Name,CompanyID)
select ID,Name,@CompanyId from aAccount where ID > @AccId

update t2 set t2.VendorId = t1.ID from aAccount t1
join @Products t2 on  t1.Name = t2.Vendor
where len(t2.Vendor) > 0 and t1.AccountSubGroupID = 7 and t2.VendorId = 0


insert invPreferredVendors(Sno,ProductId,VendorId)
select distinct 1,ItemId,VendorId from @Products where VendorId > 0
--</Vendor>


--<Cost Centre>
update t2 set t2.CostCentreId = t1.ID from invCostCentre t1
join @Cost_Centre t2 on  t1.Name = t2.[Name]

;with t1 as(select distinct [Name] from @Cost_Centre where CostCentreId = 0)
insert invCostCentre(ID,Code,Name)
select row_number() over(order by (select 1)),row_number() over(order by (select 1)),Name from t1

update t2 set t2.CostCentreId = t1.ID from invCostCentre t1
join @Cost_Centre t2 on  t1.Name = t2.[Name]
where t2.CostCentreId = 0

update t3 set t3.CostCentreId = t1.CostCentreId from @Cost_Centre t1
join @Products t2 on t1.Id = t2.Id
join invProduct t3 on t2.ItemId = t3.Id
--</Cost Centre>

commit tran

select @Message

go

if OBJECT_ID('prGetBarcodeDetailsForPurchase') is not null
	drop proc prGetBarcodeDetailsForPurchase 
go

create proc prGetBarcodeDetailsForPurchase 
@Barcode varchar(50),
@CompanyId int=1
as

set nocount on
set transaction isolation level read uncommitted

declare @BarcodeDetails table(CompanyId int,PeriodId int,VtypeId int,No int,SNo int,ProductId int,Name nvarchar(100),BarcodeID int,UOMID int,Rate float,Cost float,SRate float,MRP float,InvoiceNo varchar(50),CCode varchar(50),TaxGroupID int,TaxGroup varchar(50),Tax float,UBC varchar(50),Code varchar(50),AutoEntry bit,NativeCaption nvarchar(100),SerialNo bit,Multiplier float,Date int)

insert @BarcodeDetails(ProductId,UOMID,Rate,Cost,SRate,MRP,UBC,Multiplier)  --UBC
select ProductId,UomId,Cost,Cost,Rate,MRP,Barcode,Secondary from invUOMLevels where Barcode=@Barcode

if @@ROWCOUNT=0
	insert @BarcodeDetails(ProductId,UOMID,Rate,Cost,SRate,MRP,TaxGroupID,Code,AutoEntry,NativeCaption,Name,SerialNo) --Code
	select ID,BaseUOM,Cost,Cost,Rate,MRP,TaxGroupId,Code,AutoEntry,OtherLanguage,Name,isnull(SerialNo,0) from invProduct where Code=@Barcode

if not exists(select top 1 1 from @BarcodeDetails)
BEGIN
  insert @BarcodeDetails(CompanyId,PeriodId,VtypeId,No,SNo,ProductId,BarcodeId,UOMID,Rate,Cost,SRate,InvoiceNo)
  select t1.CompanyId,t1.PeriodId,t1.VtypeId,t1.No,t1.Sno,t1.ProductId,t1.BarcodeId,t1.UomId,t1.Rate,t1.Cost,t1.SRate,
  isnull(t2.InvoiceNo,'') + ' - ' + convert(varchar,cast(cast(t2.DeliveryDate as varchar) as datetime),103) from invAutoBarcodeAndSalesRate t1
  left outer join invPurchaseHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
  where Barcode = @Barcode
END 	

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code from @BarcodeDetails p join invProductPropertyDetails pp on p.ProductId=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID
-------------------


--Tax Group
update b set b.TaxGroupID=p.TaxGroupID,b.Code=p.Code,b.AutoEntry=p.AutoEntry,b.NativeCaption=p.OtherLanguage,b.Name=p.Name,b.SerialNo = isnull(p.SerialNo,0) from @BarcodeDetails b join invProduct p on b.ProductId=p.Id where b.TaxGroupID is null
update b set b.TaxGroup=t.Name,b.Tax=t.InputTax from @BarcodeDetails b join invTaxGroup t on b.TaxGroupID=t.Id
-------------------

--UBC
update b set b.UBC=u.Barcode from @BarcodeDetails b join invUomLevels u on b.ProductId=u.ProductId and b.UOMID=u.UomId where b.UBC is null
update b set b.TaxGroup=t.Name,b.Tax=t.InputTax from @BarcodeDetails b join invTaxGroup t on b.TaxGroupID=t.Id
-------------------

declare @PurchaseRate int
select @PurchaseRate=PurchaseRate from invOption where CompanyId=@CompanyId


if @PurchaseRate=1
Begin
	 --Last Purchase Rate Settings
	;with l as
	(select top 1 d.Rate,d.CostPrice Cost,h.Date from invPurchaseDetails d 
	 join @BarcodeDetails b on d.ProductId=b.ProductID and d.UOMId=b.UOMId and  (b.BarcodeId=0 or b.BarcodeId is null)
	 join invPurchaseHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
	 where d.CompanyId=@CompanyId
	 order by h.Date desc)
     
	 update b set b.Rate=l.Rate,b.Cost=l.Cost,b.Date=l.Date from @BarcodeDetails b cross join l


	 --Last SRate Settings
	 ;with l as
	(select top 1 d.SRate,h.Date from invPurchaseDetails d 
	 join @BarcodeDetails b on d.ProductId=b.ProductID and (b.BarcodeId=0 or b.BarcodeId is null)
	 join invPurchaseHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
	 where d.CompanyId=@CompanyId
	 order by h.Date desc)
     
	 update b set b.SRate=l.SRate,b.Date=l.Date from @BarcodeDetails b cross join l

	 ;with l as
	(select top 1 d.Rate SRate,h.FromDate Date from invQtyRateSettingsDetails d 
	 join invProduct p on d.ProductId=p.Id and d.UOMID=p.SalesUom
	 join @BarcodeDetails b on b.ProductId=d.ProductID and (b.BarcodeId=0 or b.BarcodeId is null)
	 join invQtyRateSettingsHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No and b.Date<h.FromDate
	 where d.CompanyId=@CompanyId and h.Type=3
	 order by h.FromDate desc)
     
	 update b set b.SRate=l.SRate from @BarcodeDetails b cross join l


End
Else if @PurchaseRate=2 -- Weighted Average
Begin
	insert tmpTable(SPID,ID) select @@spid,ProductId from @BarcodeDetails
	declare @T table(Date int,ProductID int,BarcodeID int,Rate float,CP float,SRate float)
	insert @T(Date,ProductID,BarcodeID,Rate,CP,SRate) 
	exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=2
	update b set b.Rate=s.Rate,b.Cost=s.CP from @BarcodeDetails b join @T s on b.ProductId=s.ProductId
End


select @Barcode Barcode,isnull(t1.BarcodeId,0) BarcodeId,t1.Code,t3.Name Uom,
t1.UomId,t1.Rate,t1.Cost,t1.AutoEntry,t1.SRate,isnull(t1.InvoiceNo,'') InvoiceNo,t1.NativeCaption,t1.Name,t1.ProductId ID,
t1.CCode,t1.TaxGroupID,t1.TaxGroup,t1.Tax,t1.UBC,t1.MRP,t1.SerialNo,t1.Multiplier from @BarcodeDetails t1
join invUom t3 on t1.UomId = t3.Id




--Property
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and t1.VtypeID=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ProductID and t1.BarcodeID = bd.BarcodeID

union all

select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPackingPropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -1=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ProductID and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ProductID --and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId1,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId1 = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ProductID --and t1.BarcodeID = bd.BarcodeID

go

if object_id('spReportPurchaseTaxReturn') is not null drop proc spReportPurchaseTaxReturn

go

create proc spReportPurchaseTaxReturn
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

declare @TR table(GST varchar(50),TRN varchar(50),VtypeId int,No int,InvoiceNo varchar(50),Date smalldatetime,Vendor nvarchar(100),InvDate datetime,
InterState bit,ProductID int,Item varchar(50),HSN varchar(50),UOM varchar(50),Qty float,Rate float,TaxP float,Taxable float,Tax float,CESS float,Total float,VendorId int,
Description nvarchar(200),AdditionalDescription nvarchar(200))


--Purchase
insert @TR(VtypeId,No,InvoiceNo,Date,InvDate,InterState,ProductID,Uom,Qty,Rate,TaxP,Taxable,Tax,CESS,Total,VendorId)
select v.Id,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sh.InterState,sd.ProductID,u.Name UOM, Qty,sd.Rate,t.InputTax,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Total,sh.VendorId
from invPurchaseHeader sh 
join invPurchaseDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate


--Purchase Return
insert @TR(GST,VtypeId,No,InvoiceNo,Date,Vendor,InvDate,ProductID,Uom, Qty,Rate,TaxP,Taxable,Tax,CESS,Total,VendorId)
select c.GST,v.Id,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,c.Name Vendor,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sd.ProductID,u.Name UOM, -Qty,sd.Rate,t.InputTax,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition,-sd.Total,sh.VendorId from invVendor c
join invPurchaseReturnHeader sh on c.AccountID=sh.VendorID
join invPurchaseReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate

declare @CTVtype int
select @CTVtype=AccountVtypeID from invVoucherTypeDetails where VtypeId=16

--Company Transfer
insert @TR(VtypeId,No,Date,ProductID,UOM,Qty,Rate,TaxP,Taxable,Tax,Total,VendorId)
select v.Id,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
sd.ProductID,u.Name UOM, Qty,sd.Rate,t.InputTax,sd.Gross,sd.Tax,sd.Total,c.AccountId from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join @VType v on @CTVtype=v.ID
join aCompany c on c.Id=sh.CompanyFrom
where sh.CompanyTo=@CompanyID and sh.Date between @FromDate and @ToDate


--Journal
insert @TR(VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description)
select avs.Journal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,case when sh.DrCr=1 then sh.AccountID else sd.AccountID end,sd.Description from aJournalHdr sh
join aJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on case when sh.DrCr=1 then sd.AccountID else sh.AccountID end=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.Journal=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate
and sd.Tax<>0



--Multi Journal
insert @TR(VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description,AdditionalDescription)
select avs.MultiJournal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,sd.CreditorID,sd.Description,sd.AdditionalDescription from aMultiJournalHdr sh
join aMultiJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on sd.DebtorID=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.MultiJournal=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate
and sd.Tax<>0


--HSN
update t set t.Item=psp.Name,t.HSN=psp.Code from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--Vendor Details
update tr set tr.GST=c.GST,tr.TRN=c.TIN,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invVendor c on tr.VendorId=c.AccountID
update tr set tr.GST=c.GST,tr.TRN=c.TIN,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invCustomer c on tr.VendorId=c.AccountID
update tr set tr.Vendor=a.Name from @TR tr join aAccount a on tr.VendorId=a.Id where tr.Vendor is null


--Final Date
select GST,TRN,v.Code VType,No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,UOM, sum(Qty)Qty,Rate,TaxP,sum(Taxable)Taxable,sum(Tax)Tax,sum(CESS)CESS,sum(Total)Total from @TR t
--join invVoucherTypeDetails v on t.VtypeId=v.AccountVtypeId
join aVoucherType v on t.VtypeId=v.Id
group by GST,TRN,v.Code, No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,UOM, Rate,TaxP

go

if object_id('spReportPurchaseTaxReturn2') is not null drop proc spReportPurchaseTaxReturn2

go

create proc spReportPurchaseTaxReturn2
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

declare @TR table(GST varchar(50),No int,InvoiceNo varchar(50),Date smalldatetime,DDate smalldatetime,Vendor nvarchar(100),InvDate datetime,
InterState bit,ProductID int,Item varchar(100),HSN varchar(50),UOMId int,UOM varchar(50),Qty float,Rate float,Discount float,TaxP float,Taxable float,Tax float,CESS float,Total float,VendorId int,
Description nvarchar(200),AdditionalDescription nvarchar(200))


--Purchase
insert @TR(No,InvoiceNo,Date,DDate,InvDate,InterState,ProductID,UOMId,Qty,Rate,Discount,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sh.InterState,sd.ProductID,sd.UOMId,Qty,sd.Rate,sd.Discount,t.InputTax,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Total,sh.VendorId from invPurchaseHeader sh
join invPurchaseDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate


--Purchase Return
insert @TR(GST,No,InvoiceNo,Date,DDate,Vendor,InvDate,ProductID,UOMId,Qty,Rate,Discount,TaxP,Taxable,Tax,CESS,Total,VendorId)
select c.GST,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,c.Name Vendor,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sd.ProductID,sd.UOMId,-Qty,sd.Rate,sd.Discount,t.InputTax,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition,-sd.Total,sh.VendorId from invVendor c
join invPurchaseReturnHeader sh on c.AccountID=sh.VendorID
join invPurchaseReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate

declare @CTVtype int
select @CTVtype=AccountVtypeID from invVoucherTypeDetails where VtypeId=16

--Company Transfer
insert @TR(No,Date,ProductID,UOMId,Qty,Rate,TaxP,Taxable,Tax,Total,VendorId)
select sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
sd.ProductID,sd.UOMId,Qty,sd.Rate,t.InputTax,sd.Gross,sd.Tax,sd.Total,c.AccountId from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on @CTVtype=v.ID
join aCompany c on c.Id=sh.CompanyFrom
where sh.CompanyTo=@CompanyID and sh.Date between @FromDate and @ToDate


--Journal
insert @TR(No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description)
select sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,case when sh.DrCr=1 then sh.AccountID else sd.AccountID end,sd.Description from aJournalHdr sh
join aJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on case when sh.DrCr=1 then sd.AccountID else sh.AccountID end=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.Journal=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate
and sd.Tax<>0



--Multi Journal
insert @TR(No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description,AdditionalDescription)
select sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,sd.CreditorID,sd.Description,sd.AdditionalDescription from aMultiJournalHdr sh
join aMultiJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on sd.DebtorID=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.MultiJournal=v.ID
where sh.CompanyID=@CompanyID and sh.Date between @FromDate and @ToDate
and sd.Tax<>0


--Item
update t set t.Item=p.Name from @TR t join invProduct p on t.ProductId=p.Id


--HSN
update t set t.HSN=psp.Code from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--UOM
update t set t.UOM=u.Name from @TR t join invUOM u on t.UOMId=u.Id


--Vendor Details
update tr set tr.GST=c.GST,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invVendor c on tr.VendorId=c.AccountID
update tr set tr.GST=c.GST,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invCustomer c on tr.VendorId=c.AccountID
update tr set tr.Vendor=a.Name from @TR tr join aAccount a on tr.VendorId=a.Id where tr.Vendor is null

--PR IGST
update tr set tr.InterState=1 from @TR tr where SUBSTRING(GST,1,2)<>'32' and Qty<0


--Final Date
select GST,No,InvoiceNo,Date,DDate,Vendor,InvDate,InterState,Item,HSN,UOM,sum(Qty)Qty,Rate,Sum(Discount)Discount,TaxP,sum(Taxable)Taxable,sum(Tax)Tax,sum(CESS)CESS,sum(Total)Total from @TR 
group by GST,No,InvoiceNo,Date,DDate,Vendor,InvDate,InterState,Item,HSN,UOM,Rate,TaxP

go

if object_id('spProductCompanyStock') is not null drop proc spProductCompanyStock

go

create proc spProductCompanyStock
@ProductId int
as
set transaction isolation level read uncommitted
set xact_abort on

declare @Stock table(CompanyId int,WHID int,ProductId int,BarcodeId int,Rate float,CP float,SRate float,Stock float,Pieces float,Property1 varchar(50))

insert tmpTable(SPID,ID,BarcodeID) select @@spid,Id,null from invProduct where id=@ProductId

if exists(select 1 from invWarehouse)
Begin
	insert @Stock(CompanyId,WHID,ProductId,Rate,CP,SRate,Stock,Pieces)
	exec spStock @CompanyId=0,@Type=6,@ToDate=99999999

	declare @FStock table(CNo int,Name varchar(50),Warehouse varchar(50),Stock float)

	insert @FStock
	select row_number()over(partition by c.Name order by c.Id)CNo,c.Name,w.Name,s.Stock from @Stock s
	join aCompany c on s.CompanyId=c.Id
	left join invWarehouse w on s.WHID=w.Id

	if exists(select 1 from @FStock where Warehouse is not null)
		insert @FStock
		select max(CNo)+1,f1.Name,'(Total)',sum(f1.Stock) from @FStock f1 
		join (select Name from @FStock group by Name having count(1)>1)f2
		on f1.Name=f2.Name
		group by f1.Name

	select case when CNO=1 then Name end Company,Warehouse,Stock from @FStock Order by Name,CNo
End
Else
Begin
	insert @Stock(CompanyId,ProductId,BarcodeId,Stock,Pieces)
	exec spStock @CompanyId=0,@Type=12,@ToDate=99999999

	update s set s.Property1=psp.Name from @Stock s 
	join invPurchasePropertyDetails ppd on s.ProductId=ppd.ProductId and s.BarcodeId=ppd.BarcodeId
	join invPurchaseSubProperty psp on ppd.SubPropertyId=psp.Id
	
	select c.Name Company,Property1,sum(Stock)Stock from @Stock s
	join aCompany c on s.CompanyId=c.ID
	group by c.Name,Property1
End



go

if OBJECT_ID('prGetBarcodeDetailsForSales') is not null
	drop proc prGetBarcodeDetailsForSales 

go

create proc prGetBarcodeDetailsForSales 
@Barcode varchar(50),
@RateLevelID int,
@CustomerID int=0,
@CompanyID int=1,
@CostCentreId int=0

as

set nocount on
set transaction isolation level read uncommitted

if exists(select 1 from invOption where CostCentreIndependentProducts=1 and CompanyId=@CompanyID)
	set @CostCentreId=0

declare @BarcodeDetails table(CompanyID int,PeriodID int,VTypeID int,No int,SNo int,ID int,BarcodeID int,UOMID int,Cost float,Rate float,SRate float,WRate float,MRP float,Qty float,UnitID int,Multiplier float,Code varchar(25),Name nvarchar(100),NativeCaption nvarchar(100),UOM varchar(25),SalesUOM varchar(25),AutoEntry bit,TaxGroupID int,TaxGroup varchar(50),Tax float,TaxInclusive bit,NonStock bit,CCode varchar(50),CategoryID int,Barcode varchar(50),HaveSerialNo bit,DiscountPercent float,TAddition float)

insert @BarcodeDetails(ID,UOMID,Rate,SRate,WRate,MRP,UnitID,Multiplier,SalesUOM)  --Code
select ID,SALESUOM,Cost,Rate,WRate,MRP,1,1,isnull(SalesUom,BaseUOM) from invProduct 
where Code=@Barcode 
and (Inactive is null or Inactive = 0) 
and (@CostCentreId=0 or CostCentreId=@CostCentreId)


update b set b.SRate=u.Rate  from @BarcodeDetails b 
	join invUOMLevels u on b.ID=u.ProductId and b.UomId=u.UomId


if (@RateLevelId>0)
Begin
	update b set b.SRate=case when r.Rate=2 then b.MRP else b.WRate end from @BarcodeDetails b 	join invRateLevel r on r.Id=@RateLevelId where r.Rate>1 
	update p set p.SRate=r.Rate from @BarcodeDetails p join invBarcode r on r.ProductID=p.ID and p.SalesUOM=r.UOMID and LevelId=@RateLevelID
End

if not exists(select top 1 1 from @BarcodeDetails)
Begin
	if @RateLevelId>0
		insert @BarcodeDetails(ID,UOMID,Rate,SRate,MRP,UnitID,Multiplier,Barcode)  --UBC
		select u.ProductID,u.UOMID,u.Cost,isnull(r.Rate,u.Rate),u.MRP,u.UnitID,u.Multiplayer,u.Barcode from invUOMLevels u
		left join invBarcode r on u.ProductId=r.ProductId and u.UomId=r.UomId and r.LevelId=@RateLevelId
		where Barcode=@Barcode	 

	else
		insert @BarcodeDetails(ID,UOMID,Rate,SRate,MRP,UnitID,Multiplier,Barcode,Cost)  --UBC
		select ProductID,UOMID,Cost,Rate,MRP,UnitID,Multiplayer,Barcode,Cost from invUOMLevels where Barcode=@Barcode	 

End

declare @Date int
select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @InterCompanyRateSettings bit
select @InterCompanyRateSettings=InterCompanyRateSettings from invOption where CompanyId=@CompanyId

if exists(select top 1 1 from @BarcodeDetails)
Begin
	if exists(select top 1 1 from invOption where SalesRate=1 and (SalesRateSelection=0 or SalesRateSelection is null)  and CompanyId=@CompanyID)--To update LAST RATE for Code
	Begin
			
		declare @LRate table(Date int,Rate float,SRate float,WRate float,MRP float)

		insert @LRate
		select top 1 null,p.Rate,p.SalesRate,null,p.Mrp from invOpeningStock p 
		join @BarcodeDetails b on p.ProductID=b.ID and p.UomId=b.UOMID 
		where p.CompanyId=@CompanyID
		order by p.PeriodId desc,p.No desc

		insert @LRate
		select top 1 h.Date,d.Rate,d.SRate,d.WRate,d.Mrp from invPurchaseDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID 
		join invPurchaseHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
		where h.CompanyId=@CompanyID
		order by h.Date desc

		insert @LRate
		select top 1 h.Date,d.Rate,d.SRate,null,d.Mrp from invPackingDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID
		join invPackingHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No 
		order by h.Date desc

		insert @LRate
		select top 1 h.FromDate,d.Rate,d.Rate,null,d.Mrp from invQtyRateSettingsDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID 
		join invQtyRateSettingsHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
		where @Date >= h.FromDate and h.ToDate is null and  d.LQty is null and d.UQty is null and h.FromTime=0 and h.Type=3
		and (d.CompanyId=@CompanyID or @InterCompanyRateSettings=1)
		order by h.FromDate desc,h.No desc

		if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
			insert @LRate
			select top 1 ph.Date,pd.Rate,pd.SRate,null,null from invStockAdjustmentDetails pd
			join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
			join @BarcodeDetails b on pd.ProductID=b.ID and pd.UomId=b.UOMID
			where pd.CompanyID=@CompanyID and pd.SRate > 0 
			order by ph.Date desc,ph.[No] desc
		
		if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
			insert @LRate
			select top 1 ph.Date,pd.Rate,pd.SRate,null,null from invCompanyTransferDetails pd
			join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
			join @BarcodeDetails b on pd.ProductID=b.ID and pd.UomId=b.UOMID
			where ph.CompanyTo=@CompanyID and pd.SRate > 0 
			order by ph.Date desc,ph.[No] desc
		
		
		declare @RateId int
		select @RateId=Rate from invRateLevel where Id=@RateLevelId

		;with r as
		(select top 1 Rate,case @RateId when 2 then MRP when 3 then WRate else SRate end SRate,WRate,Mrp from @LRate order by Date desc)
		
		update b set b.Rate=r.Rate,b.SRate=r.SRate,b.Mrp=r.MRP from @BarcodeDetails b cross join r

		

	End	
End



if not exists(select top 1 1 from @BarcodeDetails)
Begin
	if @RateLevelID>0
	Begin
		insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
		select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,
		case r.Rate 
			when 2 then isnull(t1.MRP,t1.SRate) 
			when 3 then isnull(t2.WRate,t1.SRate) end,
		t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
		join invPurchaseDetails t2 on t1.CompanyID=t2.CompanyID and t1.PeriodID=t2.PeriodID and t1.VtypeID=t2.VtypeID and t1.No=t2.No and t1.Sno=t2.Sno
		join invRateLevel r on r.ID=@RateLevelID and isnull(r.PercentageOf,0)<>1
		where t1.Barcode = @Barcode


		--if @@rowcount=0
		if not exists(select top 1 1 from @BarcodeDetails)
			insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
			select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.SRate*(100.0+Percentage)/100.0,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
			join invRateLevel r on r.ID=@RateLevelID and r.PercentageOf=1
			where t1.Barcode = @Barcode
		
        --if @@rowcount=0
		if not exists(select top 1 1 from @BarcodeDetails)
			insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
			select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.Mrp,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
			join invRateLevel r on r.ID=@RateLevelID and r.Rate=2
			where t1.Barcode = @Barcode
		
	End
	else
	Begin
		insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,Rate,SRate,Mrp,UomId,Barcode)--Auto Barcode
		select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.Rate,t1.SRate,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
		where t1.Barcode = @Barcode

		;with ct as
		(select row_number()over(partition by bd.Id,bd.BarcodeId order by ch.Date desc)sno,bd.Id,bd.BarcodeId,cd.Rate,cd.SRate from @BarcodeDetails bd 
		 join invCompanyTransferDetails cd on bd.Id=cd.ProductId and bd.BarcodeId=cd.BarcodeId
		 join invCompanyTransferHeader ch on cd.PeriodId=ch.PeriodId and cd.No=ch.No
		 where ch.CompanyTo=@CompanyId)

		 update bd set bd.Rate=ct.Rate,bd.SRate=ct.SRate from @BarcodeDetails bd join ct on bd.Id=ct.Id and bd.BarcodeId=ct.BarcodeId and ct.sno=1
		
	End
End


if exists(select 1 from invOption where SalesUBCRateSelection=1 and CompanyId=@CompanyID)
Begin
	if not exists(select 1 from @BarcodeDetails where BarcodeID>0)
	Begin
		insert @BarcodeDetails(PeriodId,No,ID,UOMID,SRate,WRate,Mrp,Barcode,Cost)--UBC
		select p.PeriodId,p.No,p.ProductID,p.UOMID,p.SalesRate*b.Multiplier,p.SalesRate*b.Multiplier,p.Mrp*b.Multiplier,b.Barcode,p.Rate from invOpeningStock p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UnitID 
		where p.SalesRate>0 and p.InactiveStock is null
		union all
		select p.PeriodId,p.No,p.ProductID,p.UOMID,p.SRate*b.Multiplier,p.WRate*b.Multiplier,p.Mrp*b.Multiplier,b.Barcode,p.CostPrice from invPurchaseDetails p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UnitID 
		where p.SRate>0 and p.InactiveStock is null

		;with d as(select row_number() over(partition by ID,UOMID,SRate,MRP order by (select 1))sno from @BarcodeDetails b)

		delete d where sno>1

		if exists(select top 1 1 from @BarcodeDetails where SRate>0) 
			delete @BarcodeDetails where isnull(SRate,0)=0
	End

End

if not exists(select 1 from @BarcodeDetails)--Weighing Machine Code
Begin
	declare @IdPos int
	declare @Qty float
	declare @UOMId int

	
	if LEN(@Barcode) in(13 ,18)
	Begin
		if substring(@Barcode,1,2)in('66','99','00') -- For IBIS Qatar
		begin
			if substring(@Barcode,7,1)='5' or substring(@Barcode,7,1)='1'--Weight	
			Begin
				set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
				set @Barcode=substring(@Barcode,3,4)
		 
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
				select ID,BaseUOM,t1.Rate,t1.MRP,case when AutoEntry=1 and t1.Rate=0 then 1 else @Qty end 
					from invProduct t1 join invUomLevels t2 
					on t1.ID=t2.ProductID and t1.BaseUom=t2.uomID
					where (Code=@Barcode or t2.Barcode=@Barcode)
			End
			else if substring(@Barcode,7,1)='0'--Value
			Begin
				declare @Value float
				set @Value=cast(substring(@Barcode,8,5) as float)/100.0
				select @Value
				set @Barcode=substring(@Barcode,3,4)	
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
				select ID,BaseUOM,case when AutoEntry=1 then @Value else Rate end,MRP,case when AutoEntry=1 then 1 else @Value/nullif(Rate,0) end from invProduct where Code=@Barcode
			End
		End
		else if len(@Barcode)=13 
			and exists(select 1 from invProduct p join invUomLevels u on p.Id=u.ProductId and p.BaseUom=u.UomId
			where p.Code=SUBSTRING(@Barcode,1,4) and len(isnull(u.Barcode,''))=0) 
		Begin
			set @Qty=cast(substring(@Barcode,5,5) as float)/1000.0
			set @Value=cast(substring(@Barcode,10,4) as float)/100.0
			select @Qty,@Value
			insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
			select ID,BaseUOM,@Value/@Qty,MRP,@Qty from invProduct 
			where Code=SUBSTRING(@Barcode,1,4)
		End
		else
		Begin
			if substring(@Barcode,7,1)='0' -- For Touch Soft Abudhabi
			begin		
				set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
				set @Barcode=Left(@Barcode,6)
		
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
					select ID,BaseUOM,Rate,MRP,@Qty from invProduct where Code=@Barcode
			End
		End

	End

	if charindex('%',@Barcode)>0 or charindex('#',@Barcode)>0
	Begin
		declare @Rate float
		set @IdPos=charindex('%',@Barcode)

		if @IdPos>0
		Begin
			set @Qty=cast(substring(@Barcode,@IdPos+1,5) as float)/1000.0
			set @Rate=cast(substring(@Barcode,@IdPos+6,len(@Barcode)-@IdPos) as float)/100.0
		End
		Else
		Begin
			set @IdPos=charindex('#',@Barcode)
			set @Qty=cast(substring(@Barcode,@IdPos+1,len(@Barcode)-@IdPos) as float)
		End
		
		set @Barcode=Left(@Barcode,@IdPos-1)

		insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Code
	        select ID,BaseUOM,@Rate,MRP,@Qty,0 from invProduct where Code=@Barcode
		
		if @@rowcount=0
			insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Barcode
				select p.ID,p.BaseUOM,@Rate,p.MRP,@Qty,0 from invProduct p join invUOMLevels u on p.ID=u.ProductId where u.Barcode=@Barcode
		
		
		--Last PRate
		declare @SRate float
		select top 1 @SRate=p.SRate from invPurchaseDetails p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UOMID 
		where p.SRate>0 and p.InactiveStock is null order by p.PeriodID desc,p.No desc

		if @SRate is not null
			update @BarcodeDetails set SRate=@SRate
		
		set @Barcode=null
	
	End
	else if substring(@Barcode,1,1)=substring(@Barcode,2,1) --KSA
	Begin
		set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
		set @Barcode=substring(@Barcode,3,5)
		
		insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Code
	        select ID,BaseUOM,Rate,MRP,@Qty,0 from invProduct where Code=@Barcode
	End
End


--if @@rowcount=0
if not exists(select 1 from @BarcodeDetails)
	insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Sales Order 
	select  ProductId,uomid,Rate,0,Qty,1 from invSalesOrderDetails   where RefCode=@Barcode
		

--Updating Data from purchase (Auto Barcode Option)
update t1 set t1.TaxGroupId = t3.TaxGroupId,t1.WRate = t3.WRate from @BarcodeDetails t1
join invAutoBarcodeAndSalesRate t2 on t1.Id = t2.ProductId and t1.BarcodeId = t2.BarcodeId
join invPurchaseDetails t3 on t2.CompanyId = t3.CompanyId and t2.PeriodId = t3.PeriodId and t2.VtypeId = t3.VTypeId
and t2.No = t3.No and t2.sno = t3.sno


--Product
update b set b.Code=p.Code,b.Name=p.Name,b.NativeCaption=p.OtherLanguage,b.SalesUOM=p.SalesUOM,b.AutoEntry=p.AutoEntry,
b.TaxGroupID =  p.TaxGroupID ,b.HaveSerialNo = p.SerialNo,
b.TaxInclusive=p.TaxInclusive,b.NonStock=p.NonStockItem from @BarcodeDetails b 
join invProduct p on b.Id = p.Id 

--UOM
update b set b.UOM=u.Name from @BarcodeDetails b join invUom u on b.UomId = u.Id 

--TaxGroup
update b set b.TaxGroup=t.Name,b.Tax=t.OutputTax,b.TAddition=t.Addition from @BarcodeDetails b join invTaxGroup t on b.TaxGroupId = t.Id

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code,p.CategoryID=pp.SubPropertyId from @BarcodeDetails p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

--Barcode
update b set b.Barcode=u.Barcode from invUomLevels u join @BarcodeDetails b on u.ProductId=b.ID and u.UOMID=b.UOMID where b.Barcode is null


--Qtywise Rate Settings
declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)


update p set p.SRate=s.Rate,p.WRate=s.WRate,p.MRP=s.MRP,p.DiscountPercent=s.DiscountPercent from invQtyRateSettingsDetails s 
join @BarcodeDetails p on s.ProductId=p.Id and s.UOMID=p.UOMID
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
--and isnull(s.BarcodeId,0)=isnull(p.BarcodeId,0) and s.CompanyId=@CompanyID
and isnull(s.BarcodeId,0)=0 and s.CompanyId=@CompanyID
and @Time between h.FromTime and h.ToTime

update p set p.DiscountPercent=s.DiscountPercent from invQtyRateSettingsDetails s 
join @BarcodeDetails p on s.ProductId=p.Id and s.BarcodeId=p.BarcodeId
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
and @Time between h.FromTime and h.ToTime


declare @ProductId int
declare @SalesUOM int

select @ProductId=Id,@SalesUOM = SalesUOM from @BarcodeDetails

declare @DefaultCustomerId int
declare @SalesRate int
select @DefaultCustomerId=DefaultCustomer,@SalesRate=SalesRate from invOption where CompanyID=@CompanyID


if @CustomerID>0 and @CustomerID<>isnull(@DefaultCustomerId,0) and (@SalesRate = 2 or @SalesRate = 4) and ISNULL(@RateLevelId,0) = 0 
and not exists(select 1 from @BarcodeDetails where BarcodeId is not null)
Begin
	
	declare @TaxOption int
	select @TaxOption=TaxOption from invOption

	if @TaxOption=2
		select @TaxOption=TaxInclusive from @BarcodeDetails
		
	declare @DRate table(Date int,Rate float,DiscountP float)

	--Getting Customer Last Rate
	declare @DiscountP float

	insert @DRate(Date,Rate,DiscountP)
	select top 1 sh.Date,case when @TaxOption=1 then sd.Rate+sd.Tax/sd.Qty else sd.Rate end,sd.DiscountP from invSalesDetails sd 
	join invSalesHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
	join @BarcodeDetails b on sd.ProductId=b.ID and sd.UomId=b.UOMID
	--where sd.ProductID=@ProductId and sh.CustomerID=@CustomerID 
	where sh.CustomerID=@CustomerID
	order by sh.Date desc,sh.No desc

	if exists(select 1 from invOption where SalesRate = 4)
		insert @DRate(Date,Rate)
		select top 1 sh.Date,sd.SRate from invPurchaseDetails sd
		join invPurchaseHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
		where sd.ProductId = @ProductId and sd.UomId = @SalesUOM and sd.SRate > 0 order by sh.Date desc,sh.No desc

	select top 1 @Rate=Rate from @DRate order by Date desc
	select @DiscountP=max(DiscountP) from @DRate
	
End

if exists(select 1 from invOption where SalesRate = 0 and CompanyID=@CompanyID) and exists(select 1 from invProjectSettings where isnull(AutoBarcode,0) = 0)
	update @BarcodeDetails set SRate=0
	
--Getting Customer Set Rate
--Drilling for Over Accounts,
if not exists(select 1 from @BarcodeDetails where BarcodeId is not null)
Begin
	declare @UnderAccountID int
	select @Rate=Rate,@UnderAccountID=CustomerID from invCustomerRate where CustomerID=@CustomerID and ProductID=@ProductId

	if @Rate is null
	Begin
		set @UnderAccountID=@CustomerID
		while @Rate is null and @UnderAccountID is not null
		begin
			select @UnderAccountID=max(UnderAccountID) from aAccount where ID=@UnderAccountID and ID<>UnderAccountID
			select @Rate=Rate from invCustomerRate where CustomerID=@UnderAccountID and ProductID=@ProductId
		end
	End
End

update @BarcodeDetails set SRate=@Rate where @Rate is not null and BarcodeId is null


if isnull(@RateLevelId,0) > 0
	update b set b.SRate=b.SRate*(100.0+Percentage)/100.0 from @BarcodeDetails b,invRateLevel r where r.ID=@RateLevelId and r.PercentageOf=1


--Final
select Barcode,BarcodeId,Code,Name,NativeCaption,CCode,CategoryID,ID,UOMID,Uom,SalesUom,Rate,Cost,SRate,WRate,AutoEntry,TaxGroupId,TaxGroup,Tax,
TaxInclusive,NonStock,HaveSerialNo,isnull(Mrp,0) MRP,isnull(Qty,case when AutoEntry=1 then 1 end)Qty,DiscountPercent,TAddition from @BarcodeDetails
order by PeriodId desc,No desc

--Property
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and t1.VtypeID=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ID and t1.BarcodeID = bd.BarcodeID

union all

select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPackingPropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -1=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ID and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ID --and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId1,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId1 = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ID --and t1.BarcodeID = bd.BarcodeID

go

if OBJECT_ID('prGetBarcodeDetailsForSales') is not null
	drop proc prGetBarcodeDetailsForSales 

go

create proc prGetBarcodeDetailsForSales 
@Barcode varchar(50),
@RateLevelID int,
@CustomerID int=0,
@CompanyID int=1,
@CostCentreId int=0

as

set nocount on
set transaction isolation level read uncommitted

if exists(select 1 from invOption where CostCentreIndependentProducts=1 and CompanyId=@CompanyID)
	set @CostCentreId=0

declare @BarcodeDetails table(CompanyID int,PeriodID int,VTypeID int,No int,SNo int,ID int,BarcodeID int,UOMID int,Cost float,Rate float,SRate float,WRate float,MRP float,Qty float,UnitID int,Multiplier float,Code varchar(25),Name nvarchar(100),NativeCaption nvarchar(100),UOM varchar(25),SalesUOM varchar(25),AutoEntry bit,TaxGroupID int,TaxGroup varchar(50),Tax float,TaxInclusive bit,NonStock bit,CCode varchar(50),CategoryID int,Barcode varchar(50),HaveSerialNo bit,DiscountPercent float,TAddition float)

insert @BarcodeDetails(ID,UOMID,Rate,SRate,WRate,MRP,UnitID,Multiplier,SalesUOM)  --Code
select ID,SALESUOM,Cost,Rate,WRate,MRP,1,1,isnull(SalesUom,BaseUOM) from invProduct 
where Code=@Barcode 
and (Inactive is null or Inactive = 0) 
and (@CostCentreId=0 or CostCentreId=@CostCentreId)


update b set b.SRate=u.Rate  from @BarcodeDetails b 
	join invUOMLevels u on b.ID=u.ProductId and b.UomId=u.UomId


if (@RateLevelId>0)
Begin
	update b set b.SRate=case when r.Rate=2 then b.MRP else b.WRate end from @BarcodeDetails b 	join invRateLevel r on r.Id=@RateLevelId where r.Rate>1 
	update p set p.SRate=r.Rate from @BarcodeDetails p join invBarcode r on r.ProductID=p.ID and p.SalesUOM=r.UOMID and LevelId=@RateLevelID
End

if not exists(select top 1 1 from @BarcodeDetails)
Begin
	if @RateLevelId>0
		insert @BarcodeDetails(ID,UOMID,Rate,SRate,MRP,UnitID,Multiplier,Barcode)  --UBC
		select u.ProductID,u.UOMID,u.Cost,isnull(r.Rate,u.Rate),u.MRP,u.UnitID,u.Multiplayer,u.Barcode from invUOMLevels u
		left join invBarcode r on u.ProductId=r.ProductId and u.UomId=r.UomId and r.LevelId=@RateLevelId
		where Barcode=@Barcode	 

	else
		insert @BarcodeDetails(ID,UOMID,Rate,SRate,MRP,UnitID,Multiplier,Barcode,Cost)  --UBC
		select ProductID,UOMID,Cost,Rate,MRP,UnitID,Multiplayer,Barcode,Cost from invUOMLevels where Barcode=@Barcode	 

End

declare @Date int
select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @InterCompanyRateSettings bit
select @InterCompanyRateSettings=InterCompanyRateSettings from invOption where CompanyId=@CompanyId

if exists(select top 1 1 from @BarcodeDetails)
Begin
	if exists(select top 1 1 from invOption where SalesRate=1 and (SalesRateSelection=0 or SalesRateSelection is null)  and CompanyId=@CompanyID)--To update LAST RATE for Code
	Begin
			
		declare @LRate table(Date int,Rate float,SRate float,WRate float,MRP float)

		insert @LRate
		select top 1 null,p.Rate,p.SalesRate,null,p.Mrp from invOpeningStock p 
		join @BarcodeDetails b on p.ProductID=b.ID and p.UomId=b.UOMID 
		where p.CompanyId=@CompanyID
		order by p.PeriodId desc,p.No desc

		insert @LRate
		select top 1 h.Date,d.Rate,d.SRate,d.WRate,d.Mrp from invPurchaseDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID 
		join invPurchaseHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
		where h.CompanyId=@CompanyID
		order by h.Date desc

		insert @LRate
		select top 1 h.Date,d.Rate,d.SRate,null,d.Mrp from invPackingDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID
		join invPackingHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No 
		order by h.Date desc

		insert @LRate
		select top 1 h.FromDate,d.Rate,d.Rate,d.WRate,d.Mrp from invQtyRateSettingsDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID 
		join invQtyRateSettingsHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
		where @Date >= h.FromDate and h.ToDate is null and  d.LQty is null and d.UQty is null and h.FromTime=0 and h.Type=3
		and (d.CompanyId=@CompanyID or @InterCompanyRateSettings=1)
		order by h.FromDate desc,h.No desc

		if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
			insert @LRate
			select top 1 ph.Date,pd.Rate,pd.SRate,null,null from invStockAdjustmentDetails pd
			join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
			join @BarcodeDetails b on pd.ProductID=b.ID and pd.UomId=b.UOMID
			where pd.CompanyID=@CompanyID and pd.SRate > 0 
			order by ph.Date desc,ph.[No] desc
		
		if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
			insert @LRate
			select top 1 ph.Date,pd.Rate,pd.SRate,null,null from invCompanyTransferDetails pd
			join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
			join @BarcodeDetails b on pd.ProductID=b.ID and pd.UomId=b.UOMID
			where ph.CompanyTo=@CompanyID and pd.SRate > 0 
			order by ph.Date desc,ph.[No] desc
		
		
		declare @RateId int
		select @RateId=Rate from invRateLevel where Id=@RateLevelId

		;with r as
		(select top 1 Rate,case @RateId when 2 then MRP when 3 then WRate else SRate end SRate,WRate,Mrp from @LRate order by Date desc)
		
		update b set b.Rate=r.Rate,b.SRate=r.SRate,b.Mrp=r.MRP from @BarcodeDetails b cross join r

		

	End	
End



if not exists(select top 1 1 from @BarcodeDetails)
Begin
	if @RateLevelID>0
	Begin
		insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
		select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,
		case r.Rate 
			when 2 then isnull(t1.MRP,t1.SRate) 
			when 3 then isnull(t2.WRate,t1.SRate) end,
		t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
		join invPurchaseDetails t2 on t1.CompanyID=t2.CompanyID and t1.PeriodID=t2.PeriodID and t1.VtypeID=t2.VtypeID and t1.No=t2.No and t1.Sno=t2.Sno
		join invRateLevel r on r.ID=@RateLevelID and isnull(r.PercentageOf,0)<>1
		where t1.Barcode = @Barcode


		--if @@rowcount=0
		if not exists(select top 1 1 from @BarcodeDetails)
			insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
			select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.SRate*(100.0+Percentage)/100.0,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
			join invRateLevel r on r.ID=@RateLevelID and r.PercentageOf=1
			where t1.Barcode = @Barcode
		
        --if @@rowcount=0
		if not exists(select top 1 1 from @BarcodeDetails)
			insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
			select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.Mrp,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
			join invRateLevel r on r.ID=@RateLevelID and r.Rate=2
			where t1.Barcode = @Barcode
		
	End
	else
	Begin
		insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,Rate,SRate,Mrp,UomId,Barcode)--Auto Barcode
		select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.Rate,t1.SRate,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
		where t1.Barcode = @Barcode

		;with ct as
		(select row_number()over(partition by bd.Id,bd.BarcodeId order by ch.Date desc)sno,bd.Id,bd.BarcodeId,cd.Rate,cd.SRate from @BarcodeDetails bd 
		 join invCompanyTransferDetails cd on bd.Id=cd.ProductId and bd.BarcodeId=cd.BarcodeId
		 join invCompanyTransferHeader ch on cd.PeriodId=ch.PeriodId and cd.No=ch.No
		 where ch.CompanyTo=@CompanyId)

		 update bd set bd.Rate=ct.Rate,bd.SRate=ct.SRate from @BarcodeDetails bd join ct on bd.Id=ct.Id and bd.BarcodeId=ct.BarcodeId and ct.sno=1
		
	End
End


if exists(select 1 from invOption where SalesUBCRateSelection=1 and CompanyId=@CompanyID)
Begin
	if not exists(select 1 from @BarcodeDetails where BarcodeID>0)
	Begin
		insert @BarcodeDetails(PeriodId,No,ID,UOMID,SRate,WRate,Mrp,Barcode,Cost)--UBC
		select p.PeriodId,p.No,p.ProductID,p.UOMID,p.SalesRate*b.Multiplier,p.SalesRate*b.Multiplier,p.Mrp*b.Multiplier,b.Barcode,p.Rate from invOpeningStock p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UnitID 
		where p.SalesRate>0 and p.InactiveStock is null
		union all
		select p.PeriodId,p.No,p.ProductID,p.UOMID,p.SRate*b.Multiplier,p.WRate*b.Multiplier,p.Mrp*b.Multiplier,b.Barcode,p.CostPrice from invPurchaseDetails p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UnitID 
		where p.SRate>0 and p.InactiveStock is null

		;with d as(select row_number() over(partition by ID,UOMID,SRate,MRP order by (select 1))sno from @BarcodeDetails b)

		delete d where sno>1

		if exists(select top 1 1 from @BarcodeDetails where SRate>0) 
			delete @BarcodeDetails where isnull(SRate,0)=0
	End

End

if not exists(select 1 from @BarcodeDetails)--Weighing Machine Code
Begin
	declare @IdPos int
	declare @Qty float
	declare @UOMId int

	
	if LEN(@Barcode) in(13 ,18)
	Begin
		if substring(@Barcode,1,2)in('66','99','00') -- For IBIS Qatar
		begin
			if substring(@Barcode,7,1)='5' or substring(@Barcode,7,1)='1'--Weight	
			Begin
				set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
				set @Barcode=substring(@Barcode,3,4)
		 
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
				select ID,BaseUOM,t1.Rate,t1.MRP,case when AutoEntry=1 and t1.Rate=0 then 1 else @Qty end 
					from invProduct t1 join invUomLevels t2 
					on t1.ID=t2.ProductID and t1.BaseUom=t2.uomID
					where (Code=@Barcode or t2.Barcode=@Barcode)
			End
			else if substring(@Barcode,7,1)='0'--Value
			Begin
				declare @Value float
				set @Value=cast(substring(@Barcode,8,5) as float)/100.0
				select @Value
				set @Barcode=substring(@Barcode,3,4)	
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
				select ID,BaseUOM,case when AutoEntry=1 then @Value else Rate end,MRP,case when AutoEntry=1 then 1 else @Value/nullif(Rate,0) end from invProduct where Code=@Barcode
			End
		End
		else if len(@Barcode)=13 
			and exists(select 1 from invProduct p join invUomLevels u on p.Id=u.ProductId and p.BaseUom=u.UomId
			where p.Code=SUBSTRING(@Barcode,1,4) and len(isnull(u.Barcode,''))=0) 
		Begin
			set @Qty=cast(substring(@Barcode,5,5) as float)/1000.0
			set @Value=cast(substring(@Barcode,10,4) as float)/100.0
			select @Qty,@Value
			insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
			select ID,BaseUOM,@Value/@Qty,MRP,@Qty from invProduct 
			where Code=SUBSTRING(@Barcode,1,4)
		End
		else
		Begin
			if substring(@Barcode,7,1)='0' -- For Touch Soft Abudhabi
			begin		
				set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
				set @Barcode=Left(@Barcode,6)
		
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
					select ID,BaseUOM,Rate,MRP,@Qty from invProduct where Code=@Barcode
			End
		End

	End

	if charindex('%',@Barcode)>0 or charindex('#',@Barcode)>0
	Begin
		declare @Rate float
		set @IdPos=charindex('%',@Barcode)

		if @IdPos>0
		Begin
			set @Qty=cast(substring(@Barcode,@IdPos+1,5) as float)/1000.0
			set @Rate=cast(substring(@Barcode,@IdPos+6,len(@Barcode)-@IdPos) as float)/100.0
		End
		Else
		Begin
			set @IdPos=charindex('#',@Barcode)
			set @Qty=cast(substring(@Barcode,@IdPos+1,len(@Barcode)-@IdPos) as float)
		End
		
		set @Barcode=Left(@Barcode,@IdPos-1)

		insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Code
	        select ID,BaseUOM,@Rate,MRP,@Qty,0 from invProduct where Code=@Barcode
		
		if @@rowcount=0
			insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Barcode
				select p.ID,p.BaseUOM,@Rate,p.MRP,@Qty,0 from invProduct p join invUOMLevels u on p.ID=u.ProductId where u.Barcode=@Barcode
		
		
		--Last PRate
		declare @SRate float
		select top 1 @SRate=p.SRate from invPurchaseDetails p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UOMID 
		where p.SRate>0 and p.InactiveStock is null order by p.PeriodID desc,p.No desc

		if @SRate is not null
			update @BarcodeDetails set SRate=@SRate
		
		set @Barcode=null
	
	End
	else if substring(@Barcode,1,1)=substring(@Barcode,2,1) --KSA
	Begin
		set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
		set @Barcode=substring(@Barcode,3,5)
		
		insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Code
	        select ID,BaseUOM,Rate,MRP,@Qty,0 from invProduct where Code=@Barcode
	End
End


--if @@rowcount=0
if not exists(select 1 from @BarcodeDetails)
	insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Sales Order 
	select  ProductId,uomid,Rate,0,Qty,1 from invSalesOrderDetails   where RefCode=@Barcode
		

--Updating Data from purchase (Auto Barcode Option)
update t1 set t1.TaxGroupId = t3.TaxGroupId,t1.WRate = t3.WRate from @BarcodeDetails t1
join invAutoBarcodeAndSalesRate t2 on t1.Id = t2.ProductId and t1.BarcodeId = t2.BarcodeId
join invPurchaseDetails t3 on t2.CompanyId = t3.CompanyId and t2.PeriodId = t3.PeriodId and t2.VtypeId = t3.VTypeId
and t2.No = t3.No and t2.sno = t3.sno


--Product
update b set b.Code=p.Code,b.Name=p.Name,b.NativeCaption=p.OtherLanguage,b.SalesUOM=p.SalesUOM,b.AutoEntry=p.AutoEntry,
b.TaxGroupID =  p.TaxGroupID ,b.HaveSerialNo = p.SerialNo,
b.TaxInclusive=p.TaxInclusive,b.NonStock=p.NonStockItem from @BarcodeDetails b 
join invProduct p on b.Id = p.Id 

--UOM
update b set b.UOM=u.Name from @BarcodeDetails b join invUom u on b.UomId = u.Id 

--TaxGroup
update b set b.TaxGroup=t.Name,b.Tax=t.OutputTax,b.TAddition=t.Addition from @BarcodeDetails b join invTaxGroup t on b.TaxGroupId = t.Id

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code,p.CategoryID=pp.SubPropertyId from @BarcodeDetails p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

--Barcode
update b set b.Barcode=u.Barcode from invUomLevels u join @BarcodeDetails b on u.ProductId=b.ID and u.UOMID=b.UOMID where b.Barcode is null


--Qtywise Rate Settings
declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)


update p set p.SRate=s.Rate,p.WRate=s.WRate,p.MRP=s.MRP,p.DiscountPercent=s.DiscountPercent from invQtyRateSettingsDetails s 
join @BarcodeDetails p on s.ProductId=p.Id and s.UOMID=p.UOMID
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
--and isnull(s.BarcodeId,0)=isnull(p.BarcodeId,0) and s.CompanyId=@CompanyID
and isnull(s.BarcodeId,0)=0 and s.CompanyId=@CompanyID
and @Time between h.FromTime and h.ToTime

update p set p.DiscountPercent=s.DiscountPercent from invQtyRateSettingsDetails s 
join @BarcodeDetails p on s.ProductId=p.Id and s.BarcodeId=p.BarcodeId
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
and @Time between h.FromTime and h.ToTime


declare @ProductId int
declare @SalesUOM int

select @ProductId=Id,@SalesUOM = SalesUOM from @BarcodeDetails

declare @DefaultCustomerId int
declare @SalesRate int
select @DefaultCustomerId=DefaultCustomer,@SalesRate=SalesRate from invOption where CompanyID=@CompanyID


if @CustomerID>0 and @CustomerID<>isnull(@DefaultCustomerId,0) and (@SalesRate = 2 or @SalesRate = 4) and ISNULL(@RateLevelId,0) = 0 
and not exists(select 1 from @BarcodeDetails where BarcodeId is not null)
Begin
	
	declare @TaxOption int
	select @TaxOption=TaxOption from invOption

	if @TaxOption=2
		select @TaxOption=TaxInclusive from @BarcodeDetails
		
	declare @DRate table(Date int,Rate float,DiscountP float)

	--Getting Customer Last Rate
	declare @DiscountP float

	insert @DRate(Date,Rate,DiscountP)
	select top 1 sh.Date,case when @TaxOption=1 then sd.Rate+sd.Tax/sd.Qty else sd.Rate end,sd.DiscountP from invSalesDetails sd 
	join invSalesHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
	join @BarcodeDetails b on sd.ProductId=b.ID and sd.UomId=b.UOMID
	--where sd.ProductID=@ProductId and sh.CustomerID=@CustomerID 
	where sh.CustomerID=@CustomerID
	order by sh.Date desc,sh.No desc

	if exists(select 1 from invOption where SalesRate = 4)
		insert @DRate(Date,Rate)
		select top 1 sh.Date,sd.SRate from invPurchaseDetails sd
		join invPurchaseHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
		where sd.ProductId = @ProductId and sd.UomId = @SalesUOM and sd.SRate > 0 order by sh.Date desc,sh.No desc

	select top 1 @Rate=Rate from @DRate order by Date desc
	select @DiscountP=max(DiscountP) from @DRate
	
End

if exists(select 1 from invOption where SalesRate = 0 and CompanyID=@CompanyID) and exists(select 1 from invProjectSettings where isnull(AutoBarcode,0) = 0)
	update @BarcodeDetails set SRate=0
	
--Getting Customer Set Rate
--Drilling for Over Accounts,
if not exists(select 1 from @BarcodeDetails where BarcodeId is not null)
Begin
	declare @UnderAccountID int
	select @Rate=Rate,@UnderAccountID=CustomerID from invCustomerRate where CustomerID=@CustomerID and ProductID=@ProductId

	if @Rate is null
	Begin
		set @UnderAccountID=@CustomerID
		while @Rate is null and @UnderAccountID is not null
		begin
			select @UnderAccountID=max(UnderAccountID) from aAccount where ID=@UnderAccountID and ID<>UnderAccountID
			select @Rate=Rate from invCustomerRate where CustomerID=@UnderAccountID and ProductID=@ProductId
		end
	End
End

update @BarcodeDetails set SRate=@Rate where @Rate is not null and BarcodeId is null


if isnull(@RateLevelId,0) > 0
	update b set b.SRate=b.SRate*(100.0+Percentage)/100.0 from @BarcodeDetails b,invRateLevel r where r.ID=@RateLevelId and r.PercentageOf=1


--Final
select Barcode,BarcodeId,Code,Name,NativeCaption,CCode,CategoryID,ID,UOMID,Uom,SalesUom,Rate,Cost,SRate,WRate,AutoEntry,TaxGroupId,TaxGroup,Tax,
TaxInclusive,NonStock,HaveSerialNo,isnull(Mrp,0) MRP,isnull(Qty,case when AutoEntry=1 then 1 end)Qty,DiscountPercent,TAddition from @BarcodeDetails
order by PeriodId desc,No desc

--Property
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and t1.VtypeID=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ID and t1.BarcodeID = bd.BarcodeID

union all

select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPackingPropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -1=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ID and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ID --and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId1,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId1 = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ID --and t1.BarcodeID = bd.BarcodeID

go

if OBJECT_ID('prGetOtherUomSalesRate') is not null 
	drop proc prGetOtherUomSalesRate 
go

create proc prGetOtherUomSalesRate 
@ProductId int,
@UomId int,
@CustomerID int,
@RateLevelId int,
@CompanyId int=1

as


set nocount on
set transaction isolation level read uncommitted

declare @T1 table(Rate float,MRP float,WRate float,UOMId int)

--Getting Set Rate
declare @Date int
select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)

insert @T1
select s.Rate,s.MRP,s.WRate,null from invQtyRateSettingsDetails s 
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where s.ProductID=@ProductId and s.UOMID=@UomId and @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null and s.CompanyId=@CompanyId
and @Time between h.FromTime and h.ToTime


if exists(select 1 from @T1 where Rate is not null)
Begin
	select * from @T1
	return
End


declare @ProductDetails table(Rate float,MRP float,WRate float,Secondary float,BaseUOM int)

insert @ProductDetails 
select isnull(nullif(u.Rate,0),p.Rate),isnull(nullif(u.MRP,0),p.MRP),p.WRate,Secondary,p.BaseUOM from invProduct p
left join invUomLevels u on p.Id=u.ProductId
where isnull(u.ProductId,p.Id) = @ProductId and isnull(u.UomId,p.BaseUOM) = @UomId 


if (@RateLevelID>0)
Begin
	update p set p.Rate=r.Rate from @ProductDetails p join invBarcode r on r.ProductID=@ProductId and @UOMId=r.UOMID and LevelId=@RateLevelID
	update p set p.Rate=p.WRate from @ProductDetails p join invRateLevel r on r.Rate=3 where r.ID=@RateLevelID and p.WRate>0 and @UOMId=p.BaseUOM
	update p set p.Rate=p.MRP from @ProductDetails p join invRateLevel r on r.Rate=2 where r.ID=@RateLevelID and p.MRP>0
	update p set p.Rate=p.MRP*(100.0+r.Percentage)/100.0 from @ProductDetails p join invRateLevel r on r.Rate=0 and r.PercentageOf=2 where r.ID=@RateLevelID and p.MRP>0 and r.Percentage<>0
	update p set p.Rate=p.Rate*(100.0+r.Percentage)/100.0 from @ProductDetails p join invRateLevel r on r.Rate=0 and r.PercentageOf=1 where r.ID=@RateLevelID and p.Rate>0 and r.Percentage<>0
End

update p set p.WRate=r.Rate from @ProductDetails p 
join invBarcode r on r.ProductID=@ProductId and @UOMId=r.UOMID
join invRateLevel rl on r.LevelId=rl.Id and rl.Rate=3

update p set p.MRP=r.Rate from @ProductDetails p 
join invBarcode r on r.ProductID=@ProductId and @UOMId=r.UOMID
join invRateLevel rl on r.LevelId=rl.Id and rl.Rate=2

--Product Master Rate
if exists(select 1 from invOption where SalesRate = 3 and CompanyID=@CompanyID)
begin 
	select Rate,Mrp from @ProductDetails
	return
end

declare @DefaultCustomerId int
declare @SalesRate int
select @DefaultCustomerId=DefaultCustomer,@SalesRate=SalesRate from invOption where CompanyID=@CompanyID

--Getting Customer Rates
if isnull(@CustomerID,0)>0 and @CustomerID<>@DefaultCustomerId and @SalesRate = 2
Begin
	--Getting Customer Last Rate
	insert @T1(Rate,MRP)
	select top 1 sd.Rate,sd.MRP from invSalesDetails sd 
	join invSalesHeader sh on sd.VtypeID=sh.VtypeId and sd.No=sh.No 
	where sd.ProductID=@ProductId and sh.CustomerID=@CustomerID and sd.UomId = @UomId order by sh.Date desc
End
else if ISNULL(@RateLevelId,0) > 0 and not exists(select 1 from invOption where SalesRate in(1,2) and CompanyId=@CompanyId)
begin
	insert @T1(Rate)	
	select top 1 t1.Rate from invPurchaseUomDetails t1 		
	join invPurchaseHeader t2 on t1.VtypeId = t2.VtypeId and t1.[No] = t2.[No]
	where t1.ProductId = @ProductId and t1.UomId = @UomId and t1.LevelId = @RateLevelId and t1.Rate > 0 
	order by t2.Date desc
	
	if not exists(select 1 from @T1 where Rate is not null)
		insert @T1(Rate)	
		select t1.Rate from invBarcode t1 		
		where t1.ProductId = @ProductId and t1.UomId = @UomId and t1.LevelId = @RateLevelId 
	
	if not exists(select 1 from @T1 where Rate is not null)
		insert @T1(Rate,MRP)
		select t1.MRP,t1.MRP from invUOMLevels t1 		
		join invRateLevel r on r.Rate=2 and r.Id = @RateLevelId 
		where t1.ProductId = @ProductId and t1.UomId = @UomId 
end

else if exists(select 1 from invOption where SalesRate in(1,2) and CompanyId=@CompanyId)
begin 
	
	declare @DRate table(Date int,Rate float,MRP float,WRate float,UOMId int)

	insert @DRate(Date,Rate,UOMId)	
	select top 1 t2.Date,t1.Rate,t1.UOMId from invPurchaseUomDetails t1 		
	join invPurchaseHeader t2 on t1.CompanyId=t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.[No] = t2.[No]
	where t1.ProductId = @ProductId and t1.UomId = @UomId and t1.Rate > 0 
	order by t2.Date desc,t2.No desc


	insert @DRate(Date,Rate,MRP,WRate)
  	select top 1 t2.Date,t1.SRate,t1.MRP,t1.WRate from invPurchaseDetails t1 		
	join invPurchaseHeader t2 on t1.CompanyId=t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.[No] = t2.[No]
	left join invRateLevel r on r.Id = @RateLevelId
	where t1.ProductId = @ProductId and t1.SRate > 0 order by t2.Date desc,t2.No desc

	insert @DRate(Date,Rate,MRP)
  	select top 1 t2.Date,t1.SRate,t1.MRP from invPackingDetails t1 		
	join invPackingHeader t2 on t1.CompanyId=t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.[No] = t2.[No]
	where t1.ProductId = @ProductId and t1.SRate > 0 order by t2.Date desc

	declare @InterCompanyRateSettings bit
	select @InterCompanyRateSettings=InterCompanyRateSettings from invOption where CompanyId=@CompanyId

	insert @DRate(Date,Rate,MRP,WRate)	
	select top 1 h.FromDate,s.Rate/pd.Secondary,s.MRP/pd.Secondary,s.WRate/pd.Secondary from invQtyRateSettingsDetails s 
	join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
	join @ProductDetails pd on s.ProductID=@ProductId and s.UOMID=@UomId
	where @Date>=h.FromDate and h.ToDate is null and s.LQty is null and s.UQty is null and (s.CompanyId=@CompanyID or @InterCompanyRateSettings=1)
	order by h.FromDate desc,h.No desc

	declare @RateId int
	select @RateId=Rate from invRateLevel where Id=@RateLevelId

	insert @T1(Rate,MRP,WRate,UOMId)
  	select top 1 case @RateId when 2 then MRP when 3 then WRate else Rate end,MRP,WRate,UOMId from @DRate order by Date desc,UOMId desc

	if not exists(select 1 from @T1 where UOMId=@UOMId)
		update t set t.Rate=t.Rate*ul.Secondary,t.MRP=t.MRP*ul.Secondary from @T1 t,@ProductDetails ul
		update t set t.Rate=t.Rate/ul.Secondary,t.MRP=t.MRP/ul.Secondary from @T1 t,invUOMlevels ul join invProduct p on ul.ProductId=p.Id and ul.UomId=p.SalesUom where ul.ProductId=@ProductId

end	


--Final Data
if not exists(select 1 from @T1 where Rate is not null)
	select Rate,MRP,WRate from @ProductDetails
else
	select Rate,MRP,WRate from @T1

go

if object_id('spSyncDownloading') is not null drop proc spSyncDownloading

go

create proc spSyncDownloading
@CompanyID int

as

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 


declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Source DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like'1%' and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End


if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End

Begin try
	--Downloading

	--Masters


	--aPeriod
	exec ('insert Into aPeriod([ID],[Code],[Name],[From],[To])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[From],a1.[To] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aPeriod a1
		   left join aPeriod a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountGroup
	exec ('insert Into aAccountGroup([ID],[Code],[Name],[AccountTypeID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountTypeID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup a1
		   left join aAccountGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountSubGroup
	exec ('insert Into aAccountSubGroup([ID],[Code],[Name],[AccountGroupID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountGroupID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup a1
		   left join aAccountSubGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )


	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
		   left join aAccount a2 on a1.ID=a2.ID
		   where a2.ID is null'
			)

	exec (' update a1 set a1.Name=a2.Name,a1.UnderAccountID=a2.UnderAccountID,a1.NameInOL=a2.NameInOL from aAccount a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID')



	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
			select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
			left join aAccount a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--aCompany
	exec ('insert Into aCompany(ID,Code,Name,Address,Phone,Email,AccountID)
		   select a1.ID,a1.Code,a1.Name,a1.Address,a1.Phone,a1.Email,a1.AccountID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCompany a1
		   left join aCompany a2 on a1.ID=a2.ID
		   where a2.ID is null 
		   and a1.ID in(select CompanyFrom from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCompanyTransferHeader union select CompanyTo from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCompanyTransferHeader)'
		 )
	

	--invUOM
	exec ('insert Into invUOM(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOM a1
			left join invUOM a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--invProduct
	exec ('insert Into invProduct(Id,Code,Name,Packing,OtherLanguage,CostCentreId,Cost,Rate,BaseUom,PurchaseUom,SalesUom,StockUom,MinStock,MinUom,MaxStock,MaxUom,ROL,ROLUom,ROQ,ROQUom,Inactive,NonStockItem,Expiry,CounterItem,AutoEntry,Barcode,TaxGroupId,Mrp,PackingUnit,Profit,HideFromDevice,TaxInclusive,NRate,RateEdit)
		   select a1.Id,a1.Code,a1.Name,a1.Packing,a1.OtherLanguage,a1.CostCentreId,a1.Cost,a1.Rate,a1.BaseUom,a1.PurchaseUom,a1.SalesUom,a1.StockUom,a1.MinStock,a1.MinUom,a1.MaxStock,a1.MaxUom,a1.ROL,a1.ROLUom,a1.ROQ,a1.ROQUom,a1.Inactive,a1.NonStockItem,a1.Expiry,a1.CounterItem,a1.AutoEntry,a1.Barcode,a1.TaxGroupId,a1.Mrp,a1.PackingUnit,a1.Profit,a1.HideFromDevice,a1.TaxInclusive,a1.NRate,a1.RateEdit from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a1
		   left join invProduct a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.AutoEntry=a2.AutoEntry,a1.TaxGroupID=a2.TaxGroupID,a1.OtherLanguage=a2.OtherLanguage,a1.InActive=a2.InActive,a1.MRP=a2.MRP,a1.NRate=a1.NRate,a1.WRate=a2.WRate from invProduct a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a2 on a1.ID=a2.ID')


	ALTER TABLE invUOMLevels Disable TRIGGER triggerinvUOMLevels
	--invUOMLevels
	exec ('insert Into invUOMLevels(Sno,ProductID,UOMID,Multiplayer,UnitID,Secondary,Cost,Rate,Barcode,BarcodeID,MRP,NRate)
		   select a1.Sno,a1.ProductID,a1.UOMID,a1.Multiplayer,a1.UnitID,a1.Secondary,a1.Cost,a1.Rate,a1.Barcode,a1.BarcodeID,a1.MRP,a1.NRate from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a1
		   left join invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno
		   where a2.ProductID is null'
		)

	exec ('update a1 set a1.UomId=a2.UomId,a1.MultiPlayer=a2.MultiPlayer,a1.UnitId=a2.UnitId,a1.Secondary=a2.Secondary,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.Barcode=a2.Barcode,a1.BarcodeId=a2.BarcodeId,a1.MRP=a2.MRP,a1.NRate=a2.NRate from invUOMLevels a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno')

	ALTER TABLE invUOMLevels Enable TRIGGER triggerinvUOMLevels

	--Salesman
	exec ('insert Into invSalesman(Id,Code,Name,AccountID,WareHouseID,CompanyId)
			select a1.Id,a1.Code,a1.Name,a1.AccountID,a1.WareHouseID,a1.CompanyId from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesman a1
			left join invSalesman a2 on a1.ID=a2.ID
			where a2.ID is null'
			)
	
	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.AccountID=a2.AccountID,a1.WareHouseID=a2.WareHouseID,a1.CompanyId=a2.CompanyId from invSalesman a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesman a2 on a1.Id=a2.Id')


	--invPurchaseProperty
	exec ('insert Into invPurchaseProperty(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty a1
			left join invPurchaseProperty a2 on a1.ID=a2.ID
			where a2.ID is null'
			)


	--invPurchaseSubProperty
	exec ('insert Into invPurchaseSubProperty(Id,Code,Name,PropertyID)
			select a1.Id,a1.Code,a1.Name,a1.PropertyID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseSubProperty a1
			left join invPurchaseSubProperty a2 on a1.ID=a2.ID
			where a2.ID is null'
			)
	
	--invWarehouse
	exec ('insert Into invWarehouse(Id,Code,Name,CostCentreId)
			select a1.Id,a1.Code,a1.Name,a1.CostCentreId from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invWarehouse a1
			left join invWarehouse a2 on a1.ID=a2.ID
			where a2.ID is null'
			)


	--Transactions

	create table #SalesToSync (CompanyID int,PeriodID int,VTypeID int,No int,Date int)


	--Delete onlined edited purchase entries from offline
	exec('insert #SalesToSync(CompanyID,PeriodID,VtypeID,No) 
	select s.CompanyID,s.PeriodID,s.VtypeID,s.No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount>0')

	if exists(select top 1 1 from #SalesToSync)
	Begin
		
		exec('update s set s.SyncCount=SyncCount-1 from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount>0')

		delete p1 from invPurchaseDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invPurchaseHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchasePropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from invPurchaseReturnDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invPurchaseReturnHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchasePropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from invProductSerialNumber p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchaseAdditions p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invAutoBarcodeAndSalesRate p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from aTransaction p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No 
		join invVoucherTypeDetails v on p1.VoucherTypeID=v.AccountVtypeID and p2.VtypeID=v.ID
		where p1.ModuleID=1

		delete #SalesToSync

	End
	exec('delete s from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount=0')
	

	--invProductSerialNumber
	exec ('insert Into invProductSerialNumber(VtypeId,No,PSNo,Sno,SerialNo,CompanyID,PeriodID,ID)
			select a1.VtypeId,a1.No,a1.PSNo,a1.Sno,a1.SerialNo,a1.CompanyID,a1.PeriodID,a1.ID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProductSerialNumber a1
			left join invProductSerialNumber a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	--invCustomer
	exec ('insert Into invCustomer (Name,Address1,Address2,Address3,Phone,MobileNo,Email,Web,ContactPerson,CreditLimit,DueDays,CurrencyId,RateLevelId,SalesManId,PaymentTerms,Remark,AccountID,FileNo,Place,TIN,CST,DLNo1,DLNo2,Inactive,CompanyID,GST)
		   select v1.Name,v1.Address1,v1.Address2,v1.Address3,v1.Phone,v1.MobileNo,v1.Email,v1.Web,v1.ContactPerson,v1.CreditLimit,v1.DueDays,v1.CurrencyId,v1.RateLevelId,v1.SalesManId,v1.PaymentTerms,v1.Remark,v1.AccountID,v1.FileNo,v1.Place,v1.TIN,v1.CST,v1.DLNo1,v1.DLNo2,v1.Inactive,v1.CompanyID,v1.GST from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCustomer v1
		   left join invCustomer v2 on v1.AccountID=v2.AccountID
		   where v2.AccountID is null'
		 )	

	exec ('update a1 set a1.Name=a2.Name,a1.Address1=a2.Address1,a1.Address2=a2.Address2,a1.Address3=a2.Address3,a1.Phone=a2.Phone,a1.MobileNo=a2.MobileNo,a1.Email=a2.Email,a1.ContactPerson=a2.ContactPerson,a1.CreditLimit=a2.CreditLimit,a1.DueDays=a2.DueDays,a1.RateLevelId=a2.RateLevelId,a1.SalesManId=a2.SalesManId,a1.Place=a2.Place,a1.TIN=a2.TIN,a1.Inactive=a2.Inactive,a1.CompanyID=a2.CompanyID,a1.GST=a2.GST from invCustomer a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCustomer a2 on a1.AccountID=a2.AccountID')

	--invAutoBarcodeAndSalesRate
	exec ('insert Into invAutoBarcodeAndSalesRate(VtypeId,No,Sno,ProductId,UomId,BarcodeId,Barcode,SRate,Printed,Rate,Cost,CompanyId,PeriodId,Mrp,Sticker)
		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.UomId,p1.BarcodeId,p1.Barcode,p1.SRate,p1.Printed,p1.Rate,p1.Cost,p1.CompanyId,p1.PeriodId,p1.Mrp,p1.Sticker from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invAutoBarcodeAndSalesRate p1
		   left join invAutoBarcodeAndSalesRate p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		 )

	
	--Delete onlined edited company transfer entries from offline
	exec('insert #SalesToSync(PeriodID,No) 
	select s.PeriodID,s.No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID=16 and s.SyncCount>0')

