SelectionInJobForm,ReportColumnWidth,InterChangeRateQty,SRCustomerItemsOnly,EditableAutoCode,AllowDuplicateProduct,ShowSnoFromPurchase,ShowSnoFromSales,UsePropertyCodeAsPrefix,Property1Id,Property2Id,Property1Length,Property2Length,RetrieveProdcutDetails,SalesCalculateFooterAddition,PurchaseInvoiceNoMandatory,QoutationMultipleImporting,SRAccount,SalesDisplayStock,SalesPostPaidSeparately,SalesInvoiceNoMandatory,SalesSalesmanMandatory,ProductAutoEntry,SalesFontBold,JobTaxOption,SalesKeepLastDate,SalesPrintFile,ShowSalesAnalysis,ProductDisplayCP,ProductDisplayStock,SalesDisplayCP,SalesQuantityRate,SalesDisplayProfit,SalesBlockBelowCost,ReportPrintAlignment,PurchaseToCustomers,ProductClearProperty,SalesAllowCreditDefaultCustomer,ExcessShortageAccountID,SalesAllowDuplicateInvoiceNo,SalesPromptOldDayEdit,SalesBlockBelowWRate,SalesGenerateCodeInRemarks,SalesFooterPage,LPOPrintFile,MessageForUniqueBarcode,SalesPrintFile1,SalesEditableGross,SalesDisplayProductDetails,SalesStyle,AutoSynchronizingInterval,SalesDetailedDescription,CompanyTransferApproval,SalesMessage1,ProfitCalculation,CompanyTransferRate)
		   select a1.ItemCodeLength,a1.DockContent,a1.TaxOption,a1.TransferDb,a1.AccountLinking,a1.InPutTaxAccount,a1.OutPutTaxAccount,a1.DefaultCustomer,a1.AdditionCaption,a1.AdditionAccount,a1.SalesPrintType,a1.SalesEntryFocus,a1.PurchaseEntryFocus,a1.PurchaseReturnEntryFocus,a1.SalesReturnEntryFocus,a1.DefaultSearchInPurchase,a1.DefaultSearchInPurchaseReturn,a1.DefaultSearchInSales,a1.DefaultSearchInSalesReturn,a1.DefaultSearchOfVendor,a1.DefaultSearchOfCustomer,a1.DefaultFocusOfPurchase,a1.DefaultFocusOfPurchaseReturn,a1.DefaultFocusOfSales,a1.DefaultFocusOfSalesReturn,a1.DefaultFocusControlOfPurchase,a1.DefaultFocusControlOfPurchaseReturn,a1.DefaultFocusControlOfSales,a1.DefaultFocusControlOfSalesReturn,a1.SkipToNextRowPurchase,a1.SkipToNextRowPurchaseReturn,a1.SkipToNextRowSales,a1.SkipToNextRowSalesReturn,a1.CheckOutOfStock,a1.BlockNonStockEntry,a1.SalesFooterFocus,a1.CustomerSalesDetails,a1.PurchaseRate,a1.RoundOffInSales,a1.DuplicateCustomer,a1.SalesRoundOffAccount,a1.SalesRate,a1.Password,a1.DefaultBaseUomId,a1.CompelsorySalesRateEntry,a1.AutoProductCode,a1.ProductPrefix,a1.BatchAndExpiry,a1.NonTaxableId,a1.RoundOffInPurchase,a1.PurchaseRoundOffAccount,a1.DefaultReportDate,a1.DecimalFormat,a1.PaymentModeInPurchase,a1.PaymentModeInSales,a1.CompanyID,a1.DefaultWareHouseID,a1.GrossEditableInPurchase,a1.ExpensesInPurchase,a1.SalesFooterAddition,a1.DefaultVendor,a1.ProductionAccount,a1.SalesAdditionAccount,a1.PRateCalculation,a1.DefaultPurchaseSearchType,a1.DefaultSalesSearchType,a1.SalesPrePrintingCaption,a1.SalesFromAndToTimes,a1.RentalAccount,a1.CreditNote,a1.SalesPrePrintingMessage,a1.StockCalculation,a1.JobWorksToNotesInSales,a1.Approval,a1.PurchaseDisplayStock,a1.SalesBlockByCreditLimit,a1.AddMaterialsInJobInvoicePrint,a1.AddLabourCostToJobInvoice,a1.SalesRateSelection,a1.RemoteServerName,a1.RemoteUserName,a1.RemoteUserPassword,a1.RemoteDBO,a1.AutoExportingInterval,a1.SalesIndividualExporting,a1.PurchaseIndividualExporting,a1.CompanyTransferAccountID,a1.VendorUnder,a1.CustomerUnder,a1.BarcodePrefix,a1.ProductCompulsoryInQt,a1.MaterialSpecificationInQT,a1.ProductionAutoCostCalculation,a1.CategoryPropertyID,a1.SalesDP,a1.ExportingProfitPercent,a1.SalesNRateEdit,a1.SalesRoundOffCaption,a1.ForeignCurrencyInPurchase,a1.SalestoVendors,a1.CustomerSelectionInJobForm,a1.ReportColumnWidth,a1.InterChangeRateQty,a1.SRCustomerItemsOnly,a1.EditableAutoCode,a1.AllowDuplicateProduct,a1.ShowSnoFromPurchase,a1.ShowSnoFromSales,a1.UsePropertyCodeAsPrefix,a1.Property1Id,a1.Property2Id,a1.Property1Length,a1.Property2Length,a1.RetrieveProdcutDetails,a1.SalesCalculateFooterAddition,a1.PurchaseInvoiceNoMandatory,a1.QoutationMultipleImporting,a1.SRAccount,a1.SalesDisplayStock,a1.SalesPostPaidSeparately,a1.SalesInvoiceNoMandatory,a1.SalesSalesmanMandatory,a1.ProductAutoEntry,a1.SalesFontBold,a1.JobTaxOption,a1.SalesKeepLastDate,a1.SalesPrintFile,a1.ShowSalesAnalysis,a1.ProductDisplayCP,a1.ProductDisplayStock,a1.SalesDisplayCP,a1.SalesQuantityRate,a1.SalesDisplayProfit,a1.SalesBlockBelowCost,a1.ReportPrintAlignment,a1.PurchaseToCustomers,a1.ProductClearProperty,a1.SalesAllowCreditDefaultCustomer,a1.ExcessShortageAccountID,a1.SalesAllowDuplicateInvoiceNo,a1.SalesPromptOldDayEdit,a1.SalesBlockBelowWRate,a1.SalesGenerateCodeInRemarks,a1.SalesFooterPage,a1.LPOPrintFile,a1.MessageForUniqueBarcode,a1.SalesPrintFile1,a1.SalesEditableGross,a1.SalesDisplayProductDetails,a1.SalesStyle,a1.AutoSynchronizingInterval,a1.SalesDetailedDescription,a1.CompanyTransferApproval,a1.SalesMessage1,a1.ProfitCalculation,a1.CompanyTransferRate from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invOption a1
