		   select p1.No,p1.Sno,p1.ProductID,p1.WareHouseID,p1.UOMID,p1.Qty,p1.Rate,p1.SalesRate,p1.MfrDate,p1.ExpDate,p1.Remark,p1.CompanyID,p1.PeriodID,p1.Profit,p1.MRP from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invOpeningStock p1
		   left join invOpeningStock p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
