	--invPurchaseHeader
	exec ('insert Into invPurchaseHeader (VtypeId,No,Date,DeliveryDate,VendorId,PaymentMode,InvoiceNo,DueDate,Total,DiscountP,Discount,NetTotal,Notes,TaxCalculation,Tax,TaxType,LRNo,CompanyId,PeriodId,RoundOff,Paid)
		   select p1.VtypeId,p1.No,p1.Date,p1.DeliveryDate,p1.VendorId,p1.PaymentMode,p1.InvoiceNo,p1.DueDate,p1.Total,p1.DiscountP,p1.Discount,p1.NetTotal,p1.Notes,p1.TaxCalculation,p1.Tax,p1.TaxType,p1.LRNo,p1.CompanyId,p1.PeriodId,p1.RoundOff,p1.Paid from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseHeader p1
		   left join invPurchaseHeader p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		 )
	

	--invPurchaseDetails
	exec ('insert Into invPurchaseDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,FRate,Rate,CostPrice,Gross,DiscountP,Discount,Total,MfrDate,ExpDate,Remark,TaxGroupId,Tax,IType,INo,ISno,IQty,IFOC,Profit,SRate,CompanyId,PeriodId,Mrp,InactiveStock,Addition,WRate)
