		exec('update s set s.SyncCount=SyncCount-1 from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID=16 and s.SyncCount>0')

		delete p1 from invCompanyTransferDetails p1 join #SalesToSync p2 on p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invCompanyTransferHeader p1 join #SalesToSync p2 on p1.PeriodID=p2.PeriodID and p1.No=p2.No
