	--Delete onlined edited sales entries from offline and Download
	
	create table #AVType(CompanyID int,PeriodID int,ID int,No int)

	exec('insert #SalesToSync(CompanyID,PeriodID,VTypeID,No) select CompanyID,PeriodID,VTypeID,No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where Sync=1 and CompanyID='+ @CompanyID)

	insert #AVType select s.CompanyID,s.PeriodID,v.AccountVtypeID,s.No from #SalesToSync s join invVoucherTypeDetails v on s.VTypeID=v.Id


	if exists(select top 1 1 from #SalesToSync)
	Begin
		
		delete p1 from invSalesHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		delete p1 from invSalesDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
	    delete p1 from invSalesProductSerialNumber p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		delete p1 from invSalesPropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No

		--invSalesHeader
		exec ('insert Into invSalesHeader(VtypeId,No,Date,DeliveryDate,CustomerId,PaymentMode,SalesManId,RateLevelId,DueDate,QuotationNo,Total,DiscountP,Discount,NetTotal,Notes,TaxCalculation,Tax,SalesReturn,Paid,Rep1,Rep2,RoundOff,AirwayBillNo,CompanyId,PeriodId,Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnId,CostCentreId,ShippingId,ShippingNo,CreditCardID,ExportCompanyID)
		       select p1.VtypeId,p1.No,p1.Date,p1.DeliveryDate,p1.CustomerId,p1.PaymentMode,p1.SalesManId,p1.RateLevelId,p1.DueDate,p1.QuotationNo,p1.Total,p1.DiscountP,p1.Discount,p1.NetTotal,p1.Notes,p1.TaxCalculation,p1.Tax,p1.SalesReturn,p1.Paid,p1.Rep1,p1.Rep2,p1.RoundOff,p1.AirwayBillNo,p1.CompanyId,p1.PeriodId,p1.Advance,p1.Time,p1.Addition,p1.PrePrintingString,p1.FromTime,p1.ToTime,p1.JobId,p1.ReturnId,p1.CostCentreId,p1.ShippingId,p1.ShippingNo,p1.CreditCardID,p1.ExportCompanyID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader p1
		       join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
		  )
		

		--invSalesDetails
		exec ('insert Into invSalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,FType,ARate,Length,Width)
		       select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.WarehouseId,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Gross,p1.DiscountP,p1.Discount,p1.Total,p1.MfrDate,p1.ExpDate,p1.Remark,p1.BarcodeId,p1.TaxGroupId,p1.Tax,p1.Addition,p1.IType,p1.INo,p1.ISno,p1.IQty,p1.IFOC,p1.Pieces,p1.SerialNoId,p1.CompanyId,p1.PeriodId,p1.MRP,p1.SalesmanID,p1.FType,p1.ARate,p1.Length,p1.Width from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails p1
		       join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
		     )
	
	
	
		--invSalesProductSerialNumber
		exec ('insert Into invSalesProductSerialNumber(CompanyID,PeriodID,VTypeID,No,USno,Sno,ProductID,SerialNoID)
			   select p1.CompanyID,p1.PeriodID,p1.VTypeID,p1.No,p1.USno,p1.Sno,p1.ProductID,p1.SerialNoID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesProductSerialNumber p1
			   join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
		     )		
	


	    --invSalesPropertyDetails
	    exec ('insert Into invSalesPropertyDetails(CompanyID,PeriodID,VTypeID,No,Sno,ProductID,SubPropertyID)
		       select p1.CompanyID,p1.PeriodID,p1.VTypeID,p1.No,p1.Sno,p1.ProductID,p1.SubPropertyID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails p1
		       join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
		     )
		

		exec('update '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader set Sync=null where Sync=1 and CompanyID='+ @CompanyID)
		
		delete #SalesToSync
			
	End
