		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.BarcodeID,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Total,p1.CompanyId,p1.PeriodId,p1.MRP,p1.TaxGroupID,p1.Tax,p1.DiscountPercentage,p1.DiscountAmount,p1.SerialNoID,p1.ReturnVTypeID,p1.ReturnNo from pSalesDetails p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesDetails p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	 

	if object_id('pPayment') is not null	
	--pPayment
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pPayment(VtypeId,No,CardID,CurrencyID,AccountID,Amount,CompanyID,PeriodID,UserID,CAmount,CNo,GiftCardID)
		   select p1.VtypeId,p1.No,p1.CardID,p1.CurrencyID,p1.AccountID,p1.Amount,p1.CompanyID,p1.PeriodID,p1.UserID,p1.CAmount,p1.CNo,p1.GiftCardID from pPayment p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pPayment p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)
	

	if object_id('pSalesReturnHeader') is not null
	--pSalesReturnHeader
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnHeader(VtypeId,No,Date,Time,SalesManId,Total,Discount,RoundOff,NetTotal,Shift,CompanyId,PeriodId,UserID,BalanceReturn,RateLevelID,Notes,CustomerID,TaxAmount,TaxGroup,TaxMethode,CostCentreID,CustomerContact,CustomerContactName,CVtypeId,QRCodeImage,EInvoice,Remark1,Remark2,Remark3)
		   select p1.VtypeId,p1.No,p1.Date,p1.Time,p1.SalesManId,p1.Total,p1.Discount,p1.RoundOff,p1.NetTotal,p1.Shift,p1.CompanyId,p1.PeriodId,p1.UserID,p1.BalanceReturn,p1.RateLevelID,p1.Notes,p1.CustomerID,p1.TaxAmount,p1.TaxGroup,p1.TaxMethode,p1.CostCentreID,p1.CustomerContact,p1.CustomerContactName,p1.CVtypeId,p1.QRCodeImage,p1.EInvoice,p1.Remark1,p1.Remark2,p1.Remark3 from pSalesReturnHeader p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnHeader p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		  )


		  
	
	
	if object_id('pSalesReturnDetails') is not null	
	--pSalesReturnDetails
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnDetails(VtypeId,No,Sno,ProductId,BarcodeID,UomId,Qty,Foc,Rate,Total,CompanyId,PeriodId,MRP,TaxGroupID,Tax,DiscountPercentage,DiscountAmount)
		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.BarcodeID,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Total,p1.CompanyId,p1.PeriodId,p1.MRP,p1.TaxGroupID,p1.Tax,p1.DiscountPercentage,p1.DiscountAmount from pSalesReturnDetails p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnDetails p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	
	if object_id('pReturnPayment') is not null	
	--pReturnPayment
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pReturnPayment(VtypeId,No,CardID,CurrencyID,AccountID,Amount,CompanyID,PeriodID,UserID,CAmount,CNo)
		   select p1.VtypeId,p1.No,p1.CardID,p1.CurrencyID,p1.AccountID,p1.Amount,p1.CompanyID,p1.PeriodID,p1.UserID,p1.CAmount,p1.CNo from pReturnPayment p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pReturnPayment p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	
	if object_id('pLogin') is not null	
	Begin
		--pLogin
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLogin(UserID,LogIn,LogOut,Status,VTypeID,Shift,CompanyID,ExcessShortage,CardAmount)
			   select p1.UserID,p1.LogIn,p1.LogOut,p1.Status,p1.VTypeID,p1.Shift,p1.CompanyID,p1.ExcessShortage,p1.CardAmount from pLogin p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLogin p2 on p1.UserID=p2.UserID and p1.VTypeID=p2.VTypeID and p1.Shift=p2.Shift and p1.CompanyID=p2.CompanyID
			   where p2.Shift is null and p1.CompanyID='+ @CompanyID
			)

			--pLogin
		exec ('update p2 set p2.Login=p1.Login,p2.LogOut=p1.LogOut,p2.Status=p1.Status,p2.ExcessShortage=p1.ExcessShortage,p2.CardAmount=p1.CardAmount from pLogin p1
			   join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLogin p2 on p1.UserID=p2.UserID and p1.VTypeID=p2.VTypeID and p1.Shift=p2.Shift and p1.CompanyID=p2.CompanyID
			   where p1.CompanyID='+ @CompanyID
			)

	End

		
	if object_id('pLoginDenomination') is not null	
	--pLoginDenomination
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLoginDenomination(UserID,VTypeID,Shift,Denomination,Qty)
		   select p1.UserID,p1.VTypeID,p1.Shift,p1.Denomination,p1.Qty from pLoginDenomination p1 
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLoginDenomination p2 on p1.Shift=p2.Shift and p1.VTypeID=p2.VTypeID and p1.UserID=p2.UserID
		   where p2.UserID is null '
		)

		if object_id('pClosingDenomination') is not null	
	--pLoginDenomination
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pClosingDenomination(UserID,VTypeID,Shift,Denomination,Qty,CompanyID)
		   select p1.UserID,p1.VTypeID,p1.Shift,p1.Denomination,p1.Qty,p1.CompanyID from pClosingDenomination p1 
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pClosingDenomination p2 on p1.Shift=p2.Shift and p1.VTypeID=p2.VTypeID and p1.UserID=p2.UserID and p1.CompanyID=p2.CompanyID
		   where p2.UserID is null and p1.CompanyID='+ @CompanyID
		)

	create table #VType(ID int)
	insert #VType(ID)
	select AccountVTypeID from invVoucherTypeDetails where VtypeID in(3,4,12,23)
	

	if (@UploadReceiptPayment=1)
	Begin
		--aCashPaymentHdr
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentHdr(No,RefNo,Date,CreditorID,Total,CompanyID,PeriodID,UserID)
			   select p1.No,p1.RefNo,p1.Date,p1.CreditorID,p1.Total,p1.CompanyID,p1.PeriodID,p1.UserID from aCashPaymentHdr p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentHdr p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )

		
		--aCashPaymentDtl
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentDtl(No,SNo,DebtorID,Description,Amount,CompanyID,PeriodID,CostCentreID,Discount)
			   select p1.No,p1.SNo,p1.DebtorID,p1.Description,p1.Amount,p1.CompanyID,p1.PeriodID,p1.CostCentreID,p1.Discount from aCashPaymentDtl p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentDtl p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )
		
		--aCashReceiptHdr
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptHdr(No,RefNo,Date,DebtorID,Total,CompanyID,PeriodID,UserID)
			   select p1.No,p1.RefNo,p1.Date,p1.DebtorID,p1.Total,p1.CompanyID,p1.PeriodID,p1.UserID from aCashReceiptHdr p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptHdr p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )
		
		--aCashReceiptDtl
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptDtl(No,SNo,CreditorID,Description,Amount,CompanyID,PeriodID,CostCentreID,Discount)
			   select p1.No,p1.SNo,p1.CreditorID,p1.Description,p1.Amount,p1.CompanyID,p1.PeriodID,p1.CostCentreID,p1.Discount from aCashReceiptDtl p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptDtl p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )

		insert #VType(ID)
		select CashReceipt from aVoucherTypeSettings 

		insert #VType(ID)
		select CashPayment from aVoucherTypeSettings 

	End


	--delete 0 Amount POS Transaction
	exec ('delete t from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t
	       join invVoucherTypeDetails v on t.VoucherTypeId=v.AccountVtypeId and v.VtypeId in(12,23)
		   where round(t.Amount,2)=0 and t.ModuleId=7 and t.CompanyID='+ @CompanyID
		 )

    --aTransaction
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo,CreditCardID,CostCentreID)
		   select t1.CompanyID,t1.PeriodID,t1.Date,t1.VoucherTypeID,t1.No,t1.DebtorID,t1.CreditorID,t1.Amount,t1.Description,t1.RefNo,t1.ModuleID,t1.AccountID,t1.CDate,t1.CNo,t1.SNo,t1.CreditCardID,t1.CostCentreID from aTransaction t1
		   join #VType v on t1.VoucherTypeID=v.ID
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and isnull(t1.Date,0)=isnull(t2.Date,0) and isnull(t1.No,0)=isnull(t2.No,0)
		   where t2.No is null and t1.CompanyID='+ @CompanyID
		 )
	

	--Downloading Customer Transactions
	exec ('insert Into aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo,CreditCardID,CostCentreID)
		   select t1.CompanyID,t1.PeriodID,t1.Date,t1.VoucherTypeID,t1.No,t1.DebtorID,t1.CreditorID,t1.Amount,t1.Description,t1.RefNo,t1.ModuleID,t1.AccountID,t1.CDate,t1.CNo,t1.SNo,t1.CreditCardID,t1.CostCentreID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t1
		   join invCustomer c on t1.DebtorId=c.AccountId or t1.CreditorId=c.AccountId
		   left join #VType v on t1.VoucherTypeID=v.ID
		   left join aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and isnull(t1.Date,0)=isnull(t2.Date,0) and isnull(t1.No,0)=isnull(t2.No,0)
		   where t2.No is null and v.ID is null and t1.CompanyID='+ @CompanyID
		 )
	
	

	--Deleting Customer Cash Receipt
	if (@UploadReceiptPayment=0)
	exec ('delete t1 from aTransaction t1
		   join invCustomer c on t1.DebtorId=c.AccountId or t1.CreditorId=c.AccountId
		   join aVoucherTypeSettings v on t1.VoucherTypeID in(v.CashReceipt,v.ChequePayment)
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and isnull(t1.Date,0)=isnull(t2.Date,0) and isnull(t1.No,0)=isnull(t2.No,0)
		   where t2.CompanyID is null and t1.CompanyID='+ @CompanyID
		 )
    
	
	--Delete duplicate from Remote Server
	declare @Query varchar(max)
	set @Query = @RmtSrvName + '.'+@RmtDBName +'.'+ @RmtDBO+ '.spDeleteDoubleEntries '+cast(@CompanyId as varchar) 
	exec(@Query)  
	------------------------------------

	exec spDeleteDoubleEntries @CompanyId

	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if object_id('spStock') is not null 
	drop proc spStock

go

create proc spStock
@CompanyID int=0,
@CostCentreId int=0,
@WHID int=0,
@FromDate int=0,
@ToDate int,
@Type float output

as

set nocount on
set transaction isolation level read uncommitted

declare @FirstCompanyId int
select @FirstCompanyId=min(Id) from aCompany

declare @DefaultWareHouseID int,@PRateCalculation tinyint,@StockCalculation tinyint,@CompanyTransferApproval bit,@SalesApproval bit,@WareHouseTransferCrossChecking bit,@SalesCostwiseStock bit,@PurchaseCPCalculation int,@StockwithBarcodeOnly bit,@CostCentreIndependentReports bit,@InActiveStock bit
select @DefaultWareHouseID=DefaultWareHouseID,@PRateCalculation=PRateCalculation,@StockCalculation=StockCalculation,@CompanyTransferApproval=isnull(CompanyTransferApproval,0),@SalesApproval=isnull(SalesApproval,0),@WareHouseTransferCrossChecking=isnull(WareHouseTransferCrossChecking,0),@SalesCostwiseStock=isnull(SalesCostwiseStock,0),@PurchaseCPCalculation=isnull(PurchaseCPCalculation,0),@StockwithBarcodeOnly=isnull(StockwithBarcodeOnly,0),@CostCentreIndependentReports=CostCentreIndependentReports,@InActiveStock=InActiveStock from invOption where CompanyID=case when @CompanyID=0 then @FirstCompanyId else @CompanyID end --0-WA,1-Last,2-Master

if @CostCentreIndependentReports=1
	set @CostCentreId=0

declare @WHCostCentreId int
select @WHCostCentreId=CostCentreId from invWarehouse where Id=@WHID

declare @CostCentreWHID int
select @CostCentreWHID=Id from invWarehouse where CostCentreId=@CostCentreId

create table #Stock
(
CompanyID int,
InOut bit,
TransactionID tinyint,
WHID int,
CostCentreId int,
ProductID int,
UOMID int,
BarcodeID int,
SerialNoId int,
Rate float,
Qty float,
FOC float,
Discount float,
Tax float,
CP float,
SRate float,
WRate float,
MRP float,
Date int,
VTypeId int,
No int,
ROQty float,
Pieces float,
SNo int
)

create table #tmpProduct(ID int,BarcodeID int,TaxGroupId int)

declare @DefaultCostCentreID int
select @DefaultCostCentreID=CostCentreId from invWarehouse where Id=@DefaultWareHouseID

if @Type is null
	insert #tmpProduct(ID,TaxGroupId) 
	select ID,TaxGroupId from invProduct where (inactive is null or inactive=0 or @InActiveStock=1) and (NonStockItem=0 or NonStockItem is null) and (SerialNo=0 or SerialNo is null or @StockCalculation<2)
else if @Type in(0,3)
	insert #tmpProduct(ID,TaxGroupId) 
	select ID,TaxGroupId from invProduct where (inactive is null or inactive=0 or @InActiveStock=1) and (NonStockItem=0 or NonStockItem is null) 
else if @Type = 10
    insert #tmpProduct(ID,BarcodeID,TaxGroupId)select t.ID,t.BarcodeID,p.TaxGroupId from tmpTable t join invProduct p on t.ID=p.Id where SPID=@@spid
else if @Type = 13
	insert #tmpProduct(ID,BarcodeID,TaxGroupId)
	select t.ID,t.BarcodeID,TaxGroupId from tmpTable t join invProduct p on t.ID=p.Id where SPID=@@spid
else if @Type = 1
	insert #tmpProduct(ID,BarcodeID)
	select t.ID,t.BarcodeID from tmpTable t 
	--join invProduct p on t.ID=p.Id 
	where SPID=@@spid
else
	insert #tmpProduct(ID,BarcodeID)
	select t.ID,t.BarcodeID from tmpTable t join invProduct p on t.ID=p.Id 
	where (p.NonStockItem=0 or p.NonStockItem is null) and SPID=@@spid
	
update #tmpProduct set BarcodeID=null where BarcodeId=0

declare @AutoBarCode bit
select @AutoBarCode=AutoBarCode from invProjectSettings where CompanyId=case when @CompanyID=0 then @FirstCompanyId else @CompanyID end

declare @UBC bit
select top 1 @UBC=1 from invUOMLevels where Barcode is not null


--Stock In

--Opening Stock

insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,SRate,Date,MRP)
select @CompanyID,1, null,p.ID,BaseUom,Cost,OpeningStock,Rate,0,MRP from invProduct p
join #tmpProduct t on p.ID=t.ID
where OpeningStock <>0 and  (inactive is null or inactive=0 or @InActiveStock=1) and (NonStockItem=0 or NonStockItem is null) 
and (@WHID=0 or @DefaultWareHouseID=@WHID) 
and (@CostCentreId=0 or p.CostCentreId=@CostCentreId)

if (@AutoBarCode=1)
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,SRate,Date,MRP)
	select o.CompanyID,1,o.WareHouseID,o.ProductId,o.UOMID,b.BarcodeID,o.Rate,Qty,SalesRate,0,o.MRP from invOpeningStock o
	left join invAutoBarcodeAndSalesRate b on o.CompanyID=b.CompanyID and o.PeriodID=b.PeriodID and b.VTypeID = 0 and o.No=b.No and o.SNo=b.SNo
	join #tmpProduct p on o.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
	where (@CompanyID=0 or o.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
Else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,CP,Qty,SRate,Date,MRP,WRate)
	select o.CompanyID,1,o.WareHouseID,o.ProductId,o.UOMID,o.Rate,o.Rate,Qty,SalesRate,0,o.MRP,o.WRate from invOpeningStock o
	join #tmpProduct p on o.ProductId=p.ID
	where (@CompanyID=0 or CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or WareHouseID=@CostCentreWHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

	

--Purchase
if (@AutoBarCode=1)
Begin
	if (@UBC=1)
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,VTypeId,No,MRP)
		select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,b.BarcodeID,pd.Rate,Qty+FOC,pd.CostPrice,pd.SRate,ph.Date,pd.VTypeID,pd.No,pd.MRP from invPurchaseDetails pd
		join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		left join invAutoBarcodeAndSalesRate b on pd.CompanyID=b.CompanyID and pd.PeriodID=b.PeriodID and pd.VTypeID=b.VTypeID and pd.No=b.No and pd.SNo=b.SNo
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	Else
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,WRate,Date,VTypeId,No,MRP)
		select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,b.BarcodeID,pd.Rate,Qty+FOC,pd.CostPrice,pd.SRate,pd.WRate,ph.Date,pd.VTypeID,pd.No,pd.MRP from invPurchaseDetails pd
		join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		left join invAutoBarcodeAndSalesRate b on pd.CompanyID=b.CompanyID and pd.PeriodID=b.PeriodID and pd.VTypeID=b.VTypeID and pd.No=b.No and pd.SNo=b.SNo
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
        and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
End
Else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,WRate,Date,VTypeId,No,MRP)
	select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate-isnull(pd.Discount/nullif(pd.Qty,0),0),Qty+FOC,pd.CostPrice,pd.SRate,pd.WRate,ph.Date,pd.VTypeID,pd.No,pd.MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	and (@CostCentreId=0 or isnull(ph.CostCentreId,@DefaultCostCentreId)=@CostCentreId)	

	

if isnull(@Type,0) not in(3,4,7,9,11)--Not for Barcode Stock
Begin
	--Goods Receipt
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,VTypeId,No)
	select pd.CompanyID,11,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,Qty+FOC,pd.Rate,pd.Rate,ph.Date,pd.VTypeID,pd.No from invGoodsReceiptDetails pd
	join invGoodsReceiptHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)

	--Purchase-Goods Receipt
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,VTypeId,No,MRP)
	select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,-(Qty+FOC),pd.CostPrice,pd.SRate,ph.Date,pd.VTypeID,pd.No,MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and pd.IType=2 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
End


--Packing
if (@AutoBarCode=1)
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No,MRP)
	select pd.CompanyID,8,pd.WareHouseID,pd.ProductId,pd.UOMID,b.BarcodeID,pd.Rate,pd.Qty,pd.CostPrice,pd.SRate,ph.Date,pd.No,pd.MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
	join invAutoBarcodeAndSalesRate b on pd.CompanyID=b.CompanyID and pd.PeriodID=b.PeriodID and b.VTypeID=-1 and pd.No=b.No and pd.SNo=b.SNo
	join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
Else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,No,MRP)
	select pd.CompanyID,8,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,pd.Qty,pd.CostPrice,pd.SRate,ph.Date,pd.No,MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)



--Production
if (@AutoBarCode=1)
	insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeID,Rate,Qty,UOMId,CP,SRate,Date,No)
	select ph.CompanyID,case when ph.Type=1 then 1 end,9,ph.ProductId,b.BarcodeID,isnull(sum(pd.Total/ph.Qty),ph.PRate),case when ph.Type=1 then -1 else 1 end * ph.Qty,ph.UOMId,ph.PCost,ph.SRate,ph.Date,ph.No from invProductionHeader ph
	left join invAutoBarcodeAndSalesRate b on ph.CompanyID=b.CompanyID and ph.PeriodID=b.PeriodID and b.VTypeID=-2 and ph.No=b.No and 0=b.SNo
	join #tmpProduct p on ph.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
	left join invProductionDetails pd on ph.CompanyID=pd.CompanyID and ph.PeriodID=pd.PeriodID and ph.No=pd.No
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
	and ph.Qty<>0 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	group by ph.CompanyID,ph.ProductId,b.BarcodeID,ph.PRate,ph.PCost,ph.Qty,ph.UomId,ph.SRate,ph.Date,ph.No,ph.Type
else
	insert #Stock(CompanyID,InOut,TransactionID,ProductID,Rate,Qty,UOMId,CP,SRate,Date,No)
	select ph.CompanyID,case when ph.Type=1 then 1 end,9,ph.ProductId,isnull(sum(pd.Total/ph.Qty),ph.PRate),case when ph.Type=1 then -1 else 1 end * ph.Qty,ph.UOMId,ph.PCost,ph.SRate,ph.Date,ph.No from invProductionHeader ph
	join #tmpProduct p on ph.ProductId=p.ID
	left join invProductionDetails pd on ph.CompanyID=pd.CompanyID and ph.PeriodID=pd.PeriodID and ph.No=pd.No
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
	and ph.Qty<>0 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	group by ph.CompanyID,ph.ProductId,ph.PRate,ph.PCost,ph.Qty,ph.UomId,ph.SRate,ph.Date,ph.No,ph.Type


--Purchase Return
if (@AutoBarCode=1)
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,Date,VTypeId,No)
	select pd.CompanyID,3,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,-Qty,ph.Date,pd.VTypeID,pd.No from invPurchaseReturnDetails pd
	join invPurchaseReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,Date,VTypeId,No)
	select pd.CompanyID,3,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,-Qty,ph.Date,pd.VTypeID,pd.No from invPurchaseReturnDetails pd
	join invPurchaseReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)

--Company Transfer
if @AutoBarcode=1
	insert #Stock(CompanyID,WHID,TransactionID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No)
	select ph.CompanyTo,ph.WarehouseTo,16,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,pd.Qty,case when @PurchaseCPCalculation=3 then (pd.Total-pd.Tax)/pd.Qty else pd.Total/pd.Qty end,pd.SRate,ph.Date,pd.No from invCompanyTransferDetails pd
	join invCompanyTransferHeader ph on ph.PeriodID=pd.PeriodID and  pd.No=ph.No
	--join #tmpProduct p on pd.ProductId=p.ID and isnull(pd.BarcodeId,0)=isnull(p.BarcodeId,0)
	join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
	left join invTaxGroup tg on p.TaxGroupId=tg.Id
	where ph.Date<=@ToDate 
	and (ph.CompanyTo=@CompanyID or @CompanyID=0)
	and (@CompanyTransferApproval=0 or ph.Approve=1)
	and (@WHID=0 or isnull(WarehouseTo,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseTo,@DefaultWareHouseID)=@CostCentreWHID)
else
	insert #Stock(CompanyID,WHID,TransactionID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,No,WRate)
	select ph.CompanyTo,ph.WarehouseTo,16,pd.ProductId,pd.UOMID,pd.Rate,pd.Qty,case when @PurchaseCPCalculation=3 then (pd.Total-pd.Tax)/pd.Qty else pd.Total/pd.Qty end,pd.SRate,ph.Date,pd.No,pd.WRate from invCompanyTransferDetails pd
	join invCompanyTransferHeader ph on ph.PeriodID=pd.PeriodID and  pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	left join invTaxGroup tg on p.TaxGroupId=tg.Id
	where ph.Date<=@ToDate 
	and (ph.CompanyTo=@CompanyID or @CompanyID=0)
	and (@CompanyTransferApproval=0 or ph.Approve=1)
	and (@WHID=0 or isnull(WarehouseTo,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseTo,@DefaultWareHouseID)=@CostCentreWHID)

if isnull(@Type,0) in(3,4,7,9,11)--For Barcode Stock Only
	--Barcode Changing
	insert #Stock(CompanyID,TransactionID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No,MRP)
	select pd.CompanyID,18,pd.ProductId,pd.UOMID,pd.NewBarcodeID,pd.Rate,Stock,pd.Rate,pd.Rate,pd.Date,pd.No,MRP from invBarcodeChanging pd
	join #tmpProduct p on pd.ProductId=p.ID and (p.barcodeId = pd.NewBarcodeID or p.barcodeId is null)
	where pd.Date<=@ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID) 


--Stock Receipt
insert #Stock(CompanyID,TransactionID,ProductID,UOMID,Rate,Qty,CP,Date,No)
select pd.CompanyID,22,pd.ProductId,pd.UOMID,pd.Rate,Qty,pd.Rate,ph.Date,pd.No from invStockReceiptDetails pd
join invStockReceiptHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
join #tmpProduct p on pd.ProductId=p.ID
where ph.Date<=@ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
and (@WHID=0 or @WHID=@DefaultWareHouseID)


if isnull(@Type,0) not in (12)--Not for Qty Only
	update s set s.CP=s.Rate from #Stock s where s.CP=0



if isnull(@Type,0) not in (5,13) or (@Type=13 and @PRateCalculation=0)  --Not for CP Calculation
Begin
	--Stock Out
	--Sales
	if (@AutoBarCode=1)
		insert #Stock(Sno,CompanyID,InOut,TransactionID,CostCentreId,WHID,ProductID,UOMID,BarcodeID,SerialNoId,Qty,FOC,Discount,Tax,Date,VTypeId,No,SRate,Pieces,Rate,CP)
		select distinct pd.sno,pd.CompanyID,1,4,ph.CostCentreId,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.SerialNoId,-(Qty+Foc),FOC,pd.Discount,pd.Tax+isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate,-pd.Pieces,case when @SalesCostwiseStock=1 then pd.Cost end,case when @SalesCostwiseStock=1 then pd.Cost end from invSalesDetails pd
		join invSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or ph.CostCentreId=@WHCostCentreId) 
		and (@SalesApproval=0 or ph.Approve=1)
		and isnull(ph.EInvoice,0) not in(2,4)
	Else
		insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,WHID,ProductID,UOMID,SerialNoId,Qty,FOC,Discount,Tax,Date,VTypeId,No,SRate,Pieces,Rate,CP)
		select pd.CompanyID,1,4,ph.CostCentreId,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.SerialNoId,-(Qty+Foc),FOC,pd.Discount,pd.Tax+isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate,-pd.Pieces,case when @SalesCostwiseStock=1 then pd.Cost end,case when @SalesCostwiseStock=1 then pd.Cost end from invSalesDetails pd
		join invSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		join invVoucherTypeDetails v on ph.VtypeId=v.Id
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,v.CostCentreID)=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID) 
		and (@SalesApproval=0 or ph.Approve=1)
		and (ph.BlockStockCalculation is null)
		and isnull(ph.EInvoice,0) not in(2,4)
	
	--Mixing
	if isnull(@Type,0) not in (10) or @PRateCalculation=0--Profit
	Begin
		delete s from #Stock s join invProductMixingHeader m on s.ProductID=m.ProductID where s.TransactionID=4

		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate,VtypeId)
		select rd.CompanyId,1,4,pd.ProductID,-rd.Qty*pd.qty/isnull(ph.Qty,1),convert(varchar,rh.Date,112),rd.No,rd.Rate,rd.VtypeId from invSalesDetails rd
		join invSalesHeader rh on rd.CompanyId=rh.CompanyId and rd.PeriodId=rh.PeriodId and rd.VtypeId=rh.VtypeId and rd.No=rh.No
		join invProduct ri on rd.ProductId =ri.Id		
		join (select CompanyId,No,h.ProductID,h.Qty from invProductMixingHeader h where (h.CompanyId=@CompanyId or @CompanyId=0)) ph on ri.Id=ph.Productid
		join (select CompanyId,No,d.ProductID,d.Qty from invProductMixingDetails d  join #tmpProduct b on b.ID=d.ProductId where (d.CompanyId=@CompanyId or @CompanyId=0)) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No
		join invVoucherTypeDetails v on rh.VtypeId=v.Id
		where rh.Date between @FromDate and @ToDate
		and (rd.CompanyId=@CompanyId or @CompanyId=0)
		and (@CostCentreId=0 or rh.CostCentreId=@CostCentreId or v.CostCentreID=@CostCentreId or @CostCentreId=@DefaultCostCentreID)
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID) 
		and (@SalesApproval=0 or rh.Approve=1)
		and (rh.BlockStockCalculation is null)
		and isnull(rh.EInvoice,0) not in(2,4)
	End

	
	--Multi Sales
	if (@AutoBarCode=1)
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,BarcodeID,Qty,Discount,Tax,Date,VTypeId,No,SRate)
		select pd.CompanyID,1,4,pd.WareHouseID,ph.ProductId,pd.UOMID,null,-Qty,null,pd.Tax,ph.Date,pd.VTypeID,pd.No,pd.Rate from invMultiSalesDetails pd
		join invMultiSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on ph.ProductID=p.ID --and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	Else
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Tax,Date,VTypeId,No,SRate)
		select pd.CompanyID,1,4,pd.WareHouseID,ph.ProductId,pd.UOMID,-Qty,null,pd.Tax,ph.Date,pd.VTypeID,pd.No,pd.Rate from invMultiSalesDetails pd
		join invMultiSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on ph.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	
	--POS Sales
	if object_id('pSalesDetails') is not null and object_id('pSalesHeader') is not null
	Begin
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,BarcodeID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,pd.BarcodeID,-(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesDetails pd
			join pSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,-(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesDetails pd
			join pSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
		
		--Mixing
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate)
		select rd.CompanyId,1,15,pd.ProductID,-rd.Qty*pd.qty,convert(varchar,rh.Date,112),rd.No,rd.Rate from pSalesDetails rd
		join pSalesHeader rh on rd.CompanyId=rh.CompanyId and rd.PeriodId=rh.PeriodId and rd.No=rh.No
		join invProduct ri on rd.ProductId =ri.Id		
		join (select CompanyId,No,h.ProductID from invProductMixingHeader h ) ph on ri.Id=ph.Productid
		join (select CompanyId,No,d.ProductID,d.Qty from invProductMixingDetails d  join #tmpProduct b on b.ID=d.ProductId) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No
		where (rd.CompanyId=@CompanyId or @CompanyId=0) and rh.Date between @FromDate and @ToDate
	End

	if object_id('pSalesReturnDetails') is not null and object_id('pSalesReturnHeader') is not null
	Begin
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,BarcodeID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,pd.BarcodeID,(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesReturnDetails pd
			join pSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesReturnDetails pd
			join pSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
	End

	

	--Restaurant 
	if object_id('RMSOrderDetails') is not null and object_id('RMSOrderHeader') is not null
	Begin

		--Sales
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate)
		select pd.Branch,1,19,ri.InventoryID,-Qty,convert(varchar,ph.Date,112),pd.OrderNo,pd.Rate from RMSOrderDetails pd
		join RMSOrderHeader ph on pd.Branch=ph.Branch and pd.Period=ph.Period and pd.OrderNo=ph.OrderNo
		join RMSItem ri on pd.ItemID =ri.ItemID
		join #tmpProduct p on ri.InventoryID=p.ID
		left join (select distinct productid from invProductMixingHeader)pm on ri.InventoryID=pm.ProductID
		where convert(varchar,ph.Date,112) between @FromDate and @ToDate and (@CompanyID=0 or pd.Branch=@CompanyID) and pd.IsModifier=0 and pm.ProductID is null


		--Mixing
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,UOMID,Qty,Date,No,SRate)
		select rd.Branch,1,19,pd.ProductID,pd.UOMID,-rd.Qty*pd.qty,convert(varchar,rh.Date,112),rd.OrderNo,rd.Rate from RMSOrderDetails rd
		join RMSOrderHeader rh on rd.Branch=rh.Branch and rd.Period=rh.Period and rd.OrderNo=rh.OrderNo
		join RMSItem ri on rd.ItemID =ri.ItemID
		--join #tmpProduct p on ri.InventoryID=p.ID
		join (select CompanyId,No,h.ProductID from invProductMixingHeader h ) ph on ri.InventoryID=ph.Productid
		join (select CompanyId,No,d.ProductID,d.UOMID,d.Qty from invProductMixingDetails d join #tmpProduct b on b.ID=d.ProductID) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No

	End
	--Restaurant Consumption
	if object_id('Consumptiondtls') is not null and object_id('Consumptiondtls') is not null
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,No)
		select pd.BranchID,1,20,pd.WarehouseId,pd.ItemID,pd.UomID,-Qty,convert(varchar, ph.Date,112),pd.Vno from Consumptiondtls pd
		join ConsumptionHdr ph on pd.BranchID=ph.BranchID  and pd.Vno=ph.Vno
		join #tmpProduct p on pd.ItemID=p.ID
		where convert(varchar,ph.Date,112) between @FromDate and @ToDate and (@CompanyID=0 or pd.BranchID=@CompanyID) and (@WHID=0 or pd.WarehouseId=@WHID)

	
	--Sales Return
	if (@AutoBarCode=1)
		insert #Stock(Sno,CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,BarcodeID,Qty,Discount,Tax,Date,VTypeId,No,SRate)
		select distinct pd.Sno,pd.CompanyID,1,5,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,Qty+Foc,-pd.Discount,-pd.Tax-isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate from invSalesReturnDetails pd
		join invSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		--join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	    and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
		and isnull(ph.EInvoice,0) not in(2,4)
	else
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Tax,Date,VTypeId,No,SRate,SerialNoId)
		select pd.CompanyID,1,5,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty+Foc,-pd.Discount,-pd.Tax-isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate,pd.SerialNoId from invSalesReturnDetails pd
		join invSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	    and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
		and isnull(ph.EInvoice,0) not in(2,4)
		
		
	--Mixing
	if isnull(@Type,0) not in (10) or @PRateCalculation=0--Profit
	Begin
		delete s from #Stock s join invProductMixingHeader m on s.ProductID=m.ProductID where s.TransactionID=5

		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate,VtypeId)
		select rd.CompanyId,1,4,pd.ProductID,rd.Qty*pd.qty/isnull(ph.Qty,1),convert(varchar,rh.Date,112),rd.No,rd.Rate,rd.VtypeId from invSalesReturnDetails rd
		join invSalesReturnHeader rh on rd.CompanyId=rh.CompanyId and rd.PeriodId=rh.PeriodId and rd.VtypeId=rh.VtypeId and rd.No=rh.No
		join invProduct ri on rd.ProductId =ri.Id		
		join (select CompanyId,No,h.ProductID,h.Qty from invProductMixingHeader h where h.CompanyId=@CompanyId) ph on ri.Id=ph.Productid
		join (select CompanyId,No,d.ProductID,d.Qty from invProductMixingDetails d  join #tmpProduct b on b.ID=d.ProductId where d.CompanyId=@CompanyId) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No
		where rd.CompanyId=@CompanyId and rh.Date between @FromDate and @ToDate
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or rh.CostCentreId=@CostCentreId  or @CostCentreId=@DefaultCostCentreID)
	End


	if isnull(@Type,0) not in(10,11) or @PRateCalculation=0--Not for Profit Reports
	Begin
		--Packing
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeID,Qty,Date,No,Rate,CP)
			select CompanyID,1,8,ph.RawMaterialId,ph.BarcodeID,-Qty,ph.Date,ph.No,ph.CP,ph.CP from invPackingHeader ph
			join #tmpProduct p on ph.RawMaterialID=p.ID and (p.BarcodeID is null or ph.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,Rate,CP)
			select CompanyID,1,8,ph.RawMaterialId,-Qty,ph.Date,ph.No,ph.CP,ph.CP from invPackingHeader ph
			join #tmpProduct p on ph.RawMaterialID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

		

		--Production
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeID,Qty,UomId,Date,No,Rate,CP)
			select pd.CompanyID,case when isnull(ph.Type,0)=0 then 1 end,9,pd.ProductId,pd.BarcodeID,case when ph.Type=1 then 1 else -1 end * pd.Qty,pd.UOMId,ph.Date,ph.No,pd.Rate,pd.Rate from invProductionDetails pd
			join invProductionHeader ph on pd.CompanyID=ph.CompanyId and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,UomId,Date,No,Rate,CP)
			select pd.CompanyID,case when isnull(ph.Type,0)=0 then 1 end,9,pd.ProductId,case when ph.Type=1 then 1 else -1 end * pd.Qty,pd.UomId,ph.Date,ph.No,pd.Rate,pd.Rate from invProductionDetails pd
			join invProductionHeader ph on pd.CompanyID=ph.CompanyId and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

			
			
		--Issue
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Date,No,SRate)
		select pd.CompanyID,1,12,pd.WareHouseID,pd.ProductId,pd.UOMID,-Qty,pd.Discount,ph.Date,pd.No,pd.Rate from invIssueDetails pd
		join invIssueHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

		--Damage
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,BarcodeID,Qty,Date,No,SRate,SerialNoId)
			select pd.CompanyID,1,14,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,-Qty,ph.Date,pd.No,pd.Rate,pd.SerialNoId from invDamageDetails pd
			join invDamageHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

		Else
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,No,SRate,SerialNoId)
			select pd.CompanyID,1,14,pd.WareHouseID,pd.ProductId,pd.UOMID,-Qty,ph.Date,pd.No,pd.Rate,SerialNoId from invDamageDetails pd
			join invDamageHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	End

	declare @VTypeId int
	select @VtypeId=Id from invVoucherTypeDetails where VTypeId=8

	if @Type=10
		--Return
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Date,No,SRate,VtypeId)
		select pd.CompanyID,1,13,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty*NOD,pd.Discount,ph.Date,pd.No,pd.Rate,@VtypeId from invReturnDetails pd
		join invReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		and isnull(pd.Pending,0)=0
	Else
		--Return
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Date,No,SRate,VtypeId)
		select pd.CompanyID,1,13,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty,pd.Discount,ph.Date,pd.No,pd.Rate,@VtypeId from invReturnDetails pd
		join invReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		and isnull(pd.Pending,0)=0
	
	

	--if isnull(@Type,0) not in(3,4,7,9,11)--Not for Barcode Stock
	if isnull(@Type,0) not in(3,4,7,9,10,11)--Not for Barcode Stock,Profit
	Begin
		--DeliveryNote
		if not exists(select 1 from invOption where ExcludeDNFromStock=1 and CompanyID=@CompanyID)
		Begin
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,VTypeId,No,SRate)
			select pd.CompanyID,1,10,pd.WareHouseID,pd.ProductId,pd.UOMID,-(Qty+Foc),ph.Date,pd.VTypeID,pd.No,pd.Rate from invDeliveryNoteDetails pd
			join invDeliveryNoteHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			join invVoucherTypeDetails v on ph.VtypeId=v.Id
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or v.CostCentreID=@CostCentreId or @DefaultCostCentreID=@CostCentreId)
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID) 
			 

			--(Sales-DeliveryNote)
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,VTypeId,No,SRate)
			select pd.CompanyID,1,4,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty,ph.Date,pd.VTypeID,pd.No,pd.Rate from invSalesDetails pd
			join invSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			join invVoucherTypeDetails v on ph.VtypeId=v.Id
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) and pd.IType=2 
			and (@CostCentreId=0 or v.CostCentreID=@CostCentreId or @DefaultCostCentreID=@CostCentreId)
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID) 
		End
		
	End
	
	--Stock Adjustment
	if (@AutoBarCode=1)
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,CP,SRate,Qty,Date,No,Pieces)
		select pd.CompanyID,7,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,pd.Cost,pd.SRate,AdjustedQty,ph.Date,pd.No,pd.AdjustedPieces from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	Else
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,CP,SRate,Qty,Date,No,Pieces)
		select pd.CompanyID,7,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,pd.Cost,pd.SRate,AdjustedQty,ph.Date,pd.No,pd.AdjustedPieces from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductId=p.ID
		join invProduct pm on pd.ProductId=pm.Id
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(isnull(WareHouseID,@DefaultWareHouseID),0)=isnull(@CostCentreWHID,0))
		and (@CostCentreId=0 or pm.CostCentreId=@CostCentreID)
	
	--WareHouse Transfer
	if @Type in(6,7,17) or @WHID>0 or @CostCentreWHID>0 
	Begin
		if (@AutoBarCode=1)
		Begin
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,BarcodeId,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,1,17,ph.WareHouseFrom,pd.ProductId,pd.BarcodeId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseFrom=@WHID)
			and (@CostCentreId=0 or ph.WareHouseFrom=@CostCentreWHID)
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)

			insert #Stock(CompanyID,TransactionID,WHID,ProductID,BarcodeId,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,17,ph.WareHouseTo,pd.ProductId,pd.BarcodeId,pd.UOMID,isnull(pd.RQty,pd.Qty),ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseTo=@WHID)
			and (@CostCentreId=0 or ph.WareHouseTo=@CostCentreWHID)
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)
		End
		Else
		Begin
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,1,17,ph.WareHouseFrom,pd.ProductId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			join invWarehouse w on ph.WareHouseFrom=w.Id
			left join invSalesMan s on ph.SalesManId=s.Id
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseFrom=@WHID)
			and (@CostCentreId=0 or w.CostCentreID=@CostCentreId or s.CostCentreID=@CostCentreId)	
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)

			insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,17,ph.WareHouseTo,pd.ProductId,pd.UOMID,isnull(pd.RQty,pd.Qty),ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			join invWarehouse w on ph.WareHouseTo=w.Id
			left join invSalesMan s on ph.SalesManId=s.Id
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseTo=@WHID)
			and (@CostCentreId=0 or w.CostCentreID=@CostCentreId or s.CostCentreID=@CostCentreId)	
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)
		End
	End

	

	--CompanyTransfer
	if (@AutoBarcode=1)
		insert #Stock(CompanyID,WHID,InOut,TransactionID,ProductID,BarcodeId,UOMID,Qty,Date,No,SRate,Tax)
		select ph.CompanyFrom,ph.WarehouseFrom,1,16,pd.ProductId,pd.BarcodeId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Tax from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodID=ph.PeriodID and pd.No=ph.No
		--join #tmpProduct p on pd.ProductId=p.ID and isnull(pd.BarcodeId,0)=isnull(p.BarcodeId,0)
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (ph.CompanyFrom=@CompanyID or @CompanyID=0)
		and (@CompanyTransferApproval=0 or ph.Approve=1)
		and (@WHID=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@CostCentreWHID)
	else
		insert #Stock(CompanyID,WHID,InOut,TransactionID,ProductID,UOMID,Qty,Date,No,SRate,Tax,SerialNoId,WRate)
		select ph.CompanyFrom,ph.WarehouseFrom,1,16,pd.ProductId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Tax,pd.SerialNoId,pd.WRate from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductId=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (ph.CompanyFrom=@CompanyID or @CompanyID=0)
		and (@CompanyTransferApproval=0 or ph.Approve=1)
		and (@WHID=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@CostCentreWHID)
	

	if isnull(@Type,0) in(3,4,7,9,11)--For Barcode Stock Only
		--Barcode Changing
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No)
		select pd.CompanyID,1,18,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,-Stock,pd.Rate,pd.Rate,pd.Date,pd.No from invBarcodeChanging pd
		join #tmpProduct p on pd.ProductId=p.ID and (p.barcodeId = pd.BarcodeID or p.barcodeId is null)
		where pd.Date<=@ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	
	if (@AutoBarCode=1)
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeId,UOMID,Qty,Date,No,SRate)
		select @CompanyID,1,21,pd.ProductId,pd.BarcodeId,pd.UOMID,-Qty,ph.Date,pd.No,pd.Rate from invStockPaymentDetails pd
		join invStockPaymentHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
		join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.StockDeductFrom=1 and ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID)
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or @WHID=@DefaultWareHouseID)
	else
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,UOMID,Qty,Date,No,SRate)
		select @CompanyID,1,21,pd.ProductId,pd.UOMID,-Qty,ph.Date,pd.No,pd.Rate from invStockPaymentDetails pd
		join invStockPaymentHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.StockDeductFrom=1 and ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID)
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or @WHID=@DefaultWareHouseID)

	select @VtypeId=Id from invVoucherTypeDetails where VTypeId=18
	if object_id('invServiceDetails') is not null  
	Begin
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeId,UOMID,Qty,Date,VtypeId,No,SRate)
		select pd.CompanyID,1,23,pd.ProductId,pd.BarcodeId,pd.UomID,-Qty,isnull(si.Date,ph.Date),@VTypeId,isnull(si.No,ph.No),pd.Rate from invServiceDetails pd
		join invServiceHeader ph on pd.CompanyID=ph.CompanyID  and pd.No=ph.No and pd.PeriodId=ph.PeriodId
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
		left join invServiceInvoice si on ph.ServiceID=si.ServiceID
		where convert(varchar,isnull(si.Date,ph.Date),112) between @FromDate and @ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID)
	End
End



--Converting to Primary UOM
update s set s.Rate=s.Rate/u.Secondary,s.Qty=s.Qty*u.Secondary,s.CP=s.CP/u.Secondary,s.SRate=s.SRate/u.Secondary,s.MRP=s.MRP/u.Secondary from #Stock s join invUOMLevels u on s.ProductId=u.ProductId and s.UOMID=u.UomId where u.Secondary<>1 and u.Secondary<>0 
------------------------------------------

create table #FIFO (Ord int,CompanyID int,WHID int,ProductID int,Date int,Rate float,CP float,SRate float,WRate float,Qty float,RQty float,OQty float,IQty float Unique Clustered(CompanyID,WHID,ProductID,Ord))

--Rate Calculation
if (isnull(@Type,0) not in(12,16))--(Not for Qty Only,Ratewise Stock)
Begin
	update #Stock set CP=Rate where CP=0 or CP is null
	
	if (@AutoBarCode=1 and @StockCalculation=0)--Barcode Rate Calculation
	Begin
		
		update t1 set t1.Rate = t2.Rate ,t1.Cp = t2.Cost from #Stock t1
		join invBarcodeChanging t2 on t1.ProductId = t2.ProductId and t1.BarcodeId = t2.NewBarcodeId 

		declare @BRate table(ProductID int,BarcodeID int,Rate float,CP float,SRate float,SNo int Unique Clustered(ProductID,BarcodeID))
		
		insert @BRate(ProductID,BarcodeID,Rate,CP,SRate)
		select ProductID,BarcodeID,Rate,CP,SRate from
		(select row_number()over(partition by ProductID,BarcodeID order by date desc)SNo,ProductID,BarcodeID,Rate,CP,SRate,Date from #Stock where InOut is null and Qty>0 and BarcodeID>0)b
		where sno=1
		--select ProductID,BarcodeID,max(Rate),max(CP),max(SRate) from #Stock where InOut is null and Qty>0 and BarcodeID>0 group by ProductID,BarcodeID

		update @BRate set CP=Rate where CP=0

	End

	declare @NonAutoBC bit
	select top 1 @NonAutoBC=1 from invProductionHeader
	
	if (isnull(@Type,0) in (0,1,2,6,8,13,10,15) and @PRateCalculation=0 and @StockCalculation>0 or @Type in(14,17))--FIFO
	Begin
		--Summarising
		create table #SStock (CompanyId int,ProductId int,Date int,WHID int,Rate float,CP float,SRate float,WRate float,Qty float,TransactionId int,InOut bit)

		--if @CompanyId=0 and isnull(@Type,0)<>1
		if @CompanyId=0 and isnull(@Type,0)not in(1,6)
			insert #SStock
			select 0,ProductId,Date,WHID,Rate,CP,SRate,WRate,sum(Qty),TransactionId,InOut from #Stock group by ProductId,Date,WHID,Rate,CP,SRate,WRate,TransactionId,InOut having sum(Qty)<>0
		Else
			insert #SStock
			select CompanyId,ProductId,Date,WHID,Rate,CP,SRate,WRate,sum(Qty),TransactionId,InOut from #Stock group by CompanyId,ProductId,Date,WHID,Rate,CP,SRate,WRate,TransactionId,InOut having sum(Qty)<>0

		
		if @Type in(6,17) 
			insert #FIFO(Ord,CompanyID,WHID,ProductID,Date,Rate,CP,SRate,WRate,Qty)
			select row_number()over(partition by CompanyID,ProductID order by Date),CompanyID,isnull(nullif(WHID,0),@DefaultwarehouseId),ProductID,Date,Rate,CP,SRate,WRate,Qty from #SStock where InOut is null and Qty>0
		else
			insert #FIFO(Ord,CompanyID,WHID,ProductID,Date,Rate,CP,SRate,WRate,Qty)
			select row_number()over(partition by CompanyID,ProductID order by Date,TransactionId desc),CompanyID,0,ProductID,Date,Rate,CP,SRate,WRate,Qty from #SStock where InOut is null and Qty>=0

		
		
		--Updating Running Qty
		declare @RQty table(CompanyID int,WHID int,ProductID int,Ord int,Qty float Unique Clustered(CompanyID,WHID,ProductID,Ord))

		insert @RQty
		select f2.CompanyID,f2.WHID,f2.ProductID,f2.Ord,sum(f1.Qty)Qty from #FIFO f1 join #FIFO f2 on f1.CompanyID=f2.CompanyID and f1.WHID=f2.WHID and f1.ProductID=f2.ProductID and f1.Ord<=f2.Ord group by f2.CompanyID,f2.WHID,f2.ProductID,f2.Ord

		update f set f.RQty=r.Qty from #FIFO f join @RQty r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID and f.Ord=r.Ord

		--Updating In Total Qty
		;with r as(select CompanyID,ProductID,WHID,sum(Qty)Qty from #FIFO group by CompanyID,WHID,ProductID)
		update f set f.IQty=r.Qty from #FIFO f join r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID

		--Updating Out Total Qty
		declare @MS table(CompanyID int,WHID int,ProductID int,Qty float,[In] bit Unique Clustered (CompanyID,WHID,ProductID))

		if @Type in(6,17) 
			insert @MS(CompanyID,WHID,ProductID,Qty)
			select CompanyID,isnull(nullif(WHID,0),@DefaultwarehouseId),ProductID,sum(Qty)Qty from #SStock where InOut is not null or Qty<0 
			group by CompanyID,isnull(nullif(WHID,0),@DefaultwarehouseId),ProductID
		Else
			insert @MS(CompanyID,WHID,ProductID,Qty)
			select CompanyID,0,ProductID,sum(Qty)Qty from #SStock where InOut is not null or Qty<0 
			group by CompanyID,ProductID
		
		
		update f set f.OQty=-r.Qty from #FIFO f join @MS r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID
		update r set r.[In]=1 from #FIFO f join @MS r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID
		--end Updating Out Total Qty
		

		if isnull(@Type,0) not in(8,10)--Stock Register,Profit
		--if isnull(@Type,0) not in(8)--Stock Register
		Begin
			--deleting +stock item
			delete #FIFO where IQty>=OQty and RQty<=OQty
				
			--deleting -stock item
			;with r as(select row_number()over(partition by CompanyID,WHID,ProductID order by RQty desc)sno,* from #FIFO where RQty<OQty)
			update r set Qty=case when sno=1 then RQty-OQty end
			delete #FIFO where Qty is null
			--end deleting -stock item


			--updating first batch stock
			;with r as(select row_number()over(partition by CompanyID,WHID,ProductID order by RQty)sno,* from #FIFO where Qty>RQty-OQty)
			update r set Qty=case when sno=1 then RQty-OQty end
			delete #FIFO where Qty is null
			--end updating first batch stock
		End

		
		--inserting non IN item
		update @MS set WHID=@DefaultwarehouseId where WHID=0

		insert #FIFO(CompanyID,WHID,ProductID,Qty)
		select CompanyID,WHID,ProductID,sum(Qty) from @MS where [In] is null group by CompanyID,WHID,ProductID

		--inserting non Sales but SR item
		insert #FIFO(CompanyID,WHID,ProductID,Qty,Rate,CP,SRate,WRate)
		select CompanyID,WHID,ProductID,-OQty,Rate,CP,SRate,WRate from #FIFO where RQty=IQty and OQty<0

		
		if isnull(@Type,0) not in(12) -- DN distribution
		Begin
			
			declare @DN table(SNo int,CompanyId int,ProductId int,Date int,Rate float,Qty float)
			insert @DN
			select row_number()over(partition by d.CompanyID,d.ProductID order by d.PeriodID desc,d.No desc)Sno,d.CompanyID,d.ProductID,h.Date,d.Rate/u.Secondary Rate,d.Qty*u.Secondary Qty from invDebitNoteDetails d 
			join invDebitNoteHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No 
			join #tmpProduct t on d.ProductId=t.ID
			join (select distinct ProductId,UomId,Secondary from invUOMLevels) u on d.ProductId=u.ProductId and d.UomId=u.UomId

			declare @SNo int,@MaxSNo int
			select @SNo=1,@MaxSNo=max(SNo) from @DN

			while @SNo<=@MaxSNO
			Begin
				;with d as
				(select * from @DN where sno=@SNo)

				,lp as  -- Last Purchases
				(select row_number()over(partition by f.CompanyID,f.ProductID order by Ord desc)Sno,f.CompanyID,f.ProductID,f.Date,f.Rate,f.CP,f.Qty from #FIFO f join d on f.CompanyID=d.CompanyID and f.ProductID=d.ProductID and f.Date<=d.Date and ((f.RQty-isnull(f.OQty,0)<=d.Qty) or f.Qty>d.Qty))
				
				update l set l.CP=l.CP-d.Rate,l.Rate=l.Rate-d.Rate from lp l join d on l.CompanyID=d.CompanyID and l.ProductID=d.ProductID

				set @SNo=@SNo+1

			End
		End
				
	End
	Else if (@AutoBarCode=0 or @UBC=1 or @NonAutoBC=1 or @StockCalculation=1 or @Type=13)   --Non Barcode Stock
	Begin
		if @PRateCalculation=2-- Master
		Begin
			if @Type=10
				update s set s.Rate=p.Cost,s.CP=p.Cost from #Stock s join invProduct p on s.ProductID=p.ID
			Else
				update s set s.Rate=p.Cost,s.CP=p.Cost,s.SRate=p.Rate,s.WRate=p.WRate from #Stock s join invProduct p on s.ProductID=p.ID
		End
		Else
		Begin	
			declare @Rate table(CompanyID int,Date int,ProductID int,Rate float,CP float,SRate float,WRate float,MRP float Unique Clustered(CompanyID,Date,ProductID))
			
			declare @Date table (CompanyID int,Date int,ProductID int,RQty float Unique Clustered(CompanyID,Date,ProductID))

			if isnull(@Type,0) in(0,1,2,6,8,15) and @PRateCalculation=1
			Begin
				insert @Date(CompanyID,Date,ProductID)
				select CompanyID,max(Date),ProductID from #Stock group by CompanyID,ProductID
			End
			Else
			Begin
				insert @Date(CompanyID,Date,ProductID)
				select distinct CompanyID,Date,ProductID from #Stock where InOut=1 and (BarcodeID is null or BarcodeID=0 or @StockCalculation=1)
				if not exists(select 1 from @Date)--if not sales at all
					insert @Date(CompanyID,Date,ProductID)select distinct CompanyID,@ToDate,ProductID from #Stock  
				
			End
			
			if (@PRateCalculation=1) --Last CP
			Begin
				
				create table #IStock (CompanyID int,ProductID int,Date int,Rate float,CP float,SRate float,WRate float,MRP float)

				insert #IStock 
				select CompanyID,ProductID,Date,Rate,CP,SRate,WRate,MRP from #Stock where InOut is null and Qty>0 --and (BarcodeID is null or BarcodeID=0) 
				
				insert @Rate(CompanyID,Date,ProductID,Rate,CP,SRate,WRate,MRP)
				select l.CompanyID,l.Date,s.ProductID,max(s.Rate),max(s.CP),max(s.SRate),max(s.WRate),max(s.MRP) from #IStock s
				join
				(select d.CompanyID,d.Date,s.ProductID,max(s.Date)PDate from #IStock s join @Date d on d.CompanyID=s.CompanyID and d.Date>=s.Date and d.ProductID=s.ProductID group by d.CompanyID,d.Date,s.ProductID) l --For Finding Sales Day's Max Purchase Date
				on l.CompanyID=s.CompanyID and l.ProductID=s.ProductID and l.PDate=s.Date
				group by l.CompanyID,l.Date,s.ProductID
				
				update r set r.WRate=p.WRate from @Rate r join invProduct p on r.ProductId=p.Id where r.Wrate is null
				update r set r.MRP=p.MRP from @Rate r join invProduct p on r.ProductId=p.Id where r.MRP is null

			End
			Else -- Weighted Average
			Begin

				--create table #DValue (CompanyID int,Date int,ProductID int,PValue float,CPValue float,SValue float,Qty float,RQty float)

				create table #DValue (CompanyID int,Date int,ProductID int,PValue float,CPValue float,SValue float,Qty float)
				
				insert #DValue(CompanyID,Date,ProductID,PValue,CPValue,SValue,Qty)
				select CompanyID,Date,ProductID,sum(Rate*Qty) PValue,sum(CP*Qty) CPValue,sum(SRate*Qty) SValue,sum(Qty)Qty from #Stock where InOut is null and Qty>0 group by CompanyID,ProductID,Date
				--------------------------------
				insert @Rate(CompanyID,Date,ProductID,Rate,CP,SRate)
				select t.CompanyID,t.Date,s.ProductID,sum(s.PValue)/sum(s.Qty),sum(s.CPValue)/sum(s.Qty),sum(s.SValue)/sum(s.Qty) from 
				@Date t join    
				#DValue s   
				--on t.Date>=s.Date and t.CompanyID=s.CompanyID and t.ProductID=s.ProductID group by t.CompanyID,t.Date,s.ProductID having sum(s.Qty)<>0
				on t.CompanyID=s.CompanyID and t.ProductID=s.ProductID 
				group by t.CompanyID,t.Date,s.ProductID having sum(s.Qty)<>0
				
				-------------------------------------
			End
			
			update @Rate set CP=Rate where CP=0
		End
	End
	---------------
	
	--Rate Updation
	if not(@PRateCalculation=0 and isnull(@Type,0) in(0,1) and @StockCalculation>0)
	Begin
		if @Type in (8,9,10,11)--For Profit SRate must be taken from sales table.So no need to update from purchase/master
		Begin
			if @PRateCalculation=0   --FIFO
			Begin
							
				--Updating Running  OQty

				declare @SOQty table(CompanyId int,WHID int,ProductId int,Date int,Qty float Unique Clustered(CompanyID,WHID,ProductID,Date))
				insert @SOQty
				select CompanyId,case when @whid=0 then 0 else WHID end WHId,ProductId,Date,sum(Qty)Qty from #Stock where not (InOut is null and Qty>0) and TransactionId not in(2) group by CompanyId,case when @whid=0 then 0 else WHID end,ProductId,Date

				declare @ROQty table(CompanyID int,WHID int,ProductID int,Date int,Qty float Unique Clustered(CompanyID,WHID,ProductID,Date))
				insert @ROQty
				select f2.CompanyID,case when @whid=0 then 0 else f2.WHID end,f2.ProductID,f2.Date,sum(f1.Qty)Qty from @SOQty f1 join @SOQty f2 on f1.CompanyID=f2.CompanyID and f1.WHID=f2.WHID and f1.ProductID=f2.ProductID and f1.Date<=f2.Date
				group by f2.CompanyID,f2.WHID,f2.ProductID,f2.Date

				update f set f.ROQty=-r.Qty from #Stock f join @ROQty r on f.CompanyID=r.CompanyID and (@WHId=0 or f.WHID=r.WHID) and f.ProductID=r.ProductID and f.Date=r.Date
				
				create table #CP(Date int,ProductId int,Rate float,CP float)
				insert #CP
				select s.Date,s.ProductId,sum(f.Rate*f.Qty)/sum(f.Qty)Rate,sum(f.CP*f.Qty)/sum(f.Qty)CP from #FIFO f join #Stock s on f.ProductId=s.ProductId and f.RQty>=s.ROQty and f.Date<=s.Date where s.Rate is null group by s.Date,s.ProductId
				
				update s set s.Rate=f.Rate,s.CP=f.CP from #CP f join #Stock s on f.ProductId=s.ProductId  and f.Date=s.Date 
				where s.Rate is null or (@SalesCostwiseStock=0 and s.InOut=1)

			End
		
			
			if (@AutoBarCode=0 or @UBC=1 or @StockCalculation=1)   --Non Barcode Stock
				update s set s.Rate=r.Rate,s.CP=r.CP from #Stock s join @Rate r on s.CompanyID=r.CompanyID and s.Date=r.Date and s.ProductID=r.ProductID where (s.InOut=1 or s.Qty<0) and s.TransactionID not in(2,15,9,17)
			
			if (@AutoBarCode=1)--Barcode Stock
				update s set s.Rate=r.Rate,s.CP=r.CP from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where (s.InOut=1 or s.Qty<0)
			
			

			--Serial No CP
			if (@StockCalculation=2 or @Type=10)
				update s set s.Rate=pd.Rate,s.CP=pd.CostPrice from #Stock s join invProductSerialNumber sn on s.SerialNoId=sn.id and s.CompanyId=sn.CompanyId join invPurchaseDetails pd on sn.CompanyId=pd.CompanyId and sn.PeriodId=pd.PeriodId and sn.VtypeId=pd.Vtypeid and sn.No=pd.No and sn.PSNo=pd.SNo and s.ProductId=pd.ProductId 
			
			

			if @Type in(8,10) -- SR,profit
			Begin
				
				--To get last rate for minus stock items
				declare @LRate table(ProductId int,Rate float,CP float)

				;with r1 as (select row_number()over(partition by productid order by date desc)Sno,ProductID,Rate,CP from @Rate)
				insert @LRate
				select ProductID,Rate,CP from r1 where sno=1

				;with r1 as (select row_number()over(partition by productid order by date desc)Sno,ProductID,Rate,CP from #FIFO)
				insert @LRate
				select ProductID,Rate,CP from r1 where sno=1
				
				;with r1 as (select row_number()over(partition by s.productid order by date desc)Sno,s.ProductID,s.Rate,s.CP from #Stock s left join @LRate l on s.ProductId=l.ProductId where InOut is null or InOut=0 and l.ProductId is null)
				insert @LRate
				select ProductID,Rate,CP from r1 where sno=1
				
				update s set s.Rate=p.Rate,s.CP=p.CP from #Stock s join @LRate p on s.ProductID=p.ProductID where s.Rate is null
				
				;with p as (select ProductID,sum(Rate*Qty)/sum(Qty) Rate,sum(CP*Qty)/sum(Qty)CP from #FIFO group by ProductID)
				update s set s.Rate=p.Rate,s.CP=p.CP from #Stock s join p on s.ProductID=p.ProductID where s.Rate is null

				update s set s.Rate=p.Cost,s.CP=p.Cost from #Stock s join invProduct p on s.ProductID=p.ID where s.Rate is null
			End
			else
				update s set s.Rate=p.Cost,s.CP=p.Cost,s.SRate=p.Rate from #Stock s join invProduct p on s.ProductID=p.ID where s.Rate is null
			
		End
		Else 
		Begin
			if (@AutoBarCode=1 and @StockCalculation=0)--Barcode Stock
			Begin
				update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where (s.InOut=1 or s.Qty<0)
				update s set s.CP=r.CP from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where s.CP=0
				update s set s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where s.SRate=0 or s.SRate is null
				update #Stock set CP=Rate where CP=0
				
				if isnull(@Type,0) not in(0,4,7)
				Begin
					;with r as
					(select row_number()over(partition by CompanyId,ProductId order by date desc)Sno,CompanyId,ProductId,Rate,CP,SRate,WRate,MRP from @Rate)
					update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate,s.WRate=r.WRate,s.MRP=r.MRP from #Stock s join r on s.CompanyID=r.CompanyID and s.ProductID=r.ProductID and r.Sno=1 where (s.Rate is null or s.BarcodeId=0 or s.BarcodeId is null)
				End
				
				
			End
			Else
			Begin
				if isnull(@Type,0) in(0,1,6) and @PRateCalculation=1
				Begin
					update @Rate set Date=0 --To speed up joining by indexed fields in below line
					update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate,s.WRate=r.WRate,s.MRP=r.MRP from #Stock s join @Rate r on s.CompanyID=r.CompanyID and s.ProductID=r.ProductID and r.Date=0
				End
				Else
					update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate,s.MRP=r.MRP from #Stock s join @Rate r on s.CompanyID=r.CompanyID and s.Date=r.Date and s.ProductID=r.ProductID where (s.InOut=1 or s.Qty<0)
			End	
			update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID  where s.Rate is null
			update s set s.Rate=p.Cost,s.CP=p.Cost,s.SRate=p.Rate,s.MRP=p.MRP from #Stock s join invProduct p on s.ProductID=p.ID where s.Rate is null or s.Rate=0
			update s set s.SRate=p.Rate from #Stock s join invProduct p on s.ProductID=p.ID where s.SRate is null or s.SRate=0
			update s set s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID where s.TransactionID=7 and Qty<0
		End
	End
	
	if exists(select top 1 1 from #FIFO)
	Begin
		update f set f.Rate=p.Cost,f.CP=p.Cost from #FIFO f join invProduct p on f.ProductID=p.ID where f.Rate=0 or f.Rate is null
		update #FIFO set CP=Rate where CP=0
		update s set s.SRate=p.Rate from #FIFO s join invProduct p on s.ProductID=p.ID where s.SRate is null or s.SRate=0
	End
	
	update #Stock set BarcodeId=null where BarcodeId=0
	update #Stock set Wrate=null where WRate=0

End


---------------------------------------------------------------
if @Type in(6,7,17) or @WHID>0 or @DefaultWareHouseID>0--WareHouse
Begin
	update s set s.WHID=w.Id from #Stock s join invWareHouse w on s.CostCentreId=w.CostCentreId where s.WHID=0 or s.WHID is null
	update s set s.WHID=@DefaultWareHouseID from #Stock s where s.WHID=0 or s.WHID is null
	update s set s.WHID=@DefaultWareHouseID from #FIFO s where s.WHID=0 or s.WHID is null
End
-------------------------------------------------------------------------------------------

if (@AutoBarcode=1 and @StockCalculation=0)
	update s set s.CP=b.Cost from #Stock s join invAutoBarcodeandSalesRate b on s.ProductId=b.ProductId and s.BarcodeId=b.BarcodeId where s.CP=0 or s.CP is null

if (@AutoBarcode=1 and @StockwithBarcodeOnly=1 and @StockCalculation=0)
	delete s from #Stock s left join invAutoBarcodeandSalesRate b on s.ProductId=b.ProductId and s.BarcodeId=b.BarcodeId where s.BarcodeId>0 and b.BarcodeId is null

if @Type=10
	update s set s.Rate=b.Rate,s.CP=b.Cost from #Stock s join invAutoBarcodeandSalesRate b on s.ProductId=b.ProductId where s.CP=0 or s.CP is null and b.CompanyId=@CompanyId


--Final Selection
if @Type is null --Total Stock Value
Begin
	declare @StockValue int
	select @StockValue=StockValue from aOption

	if (@AutoBarcode=1 and @StockCalculation=0)
	Begin
		select @Type=case when @StockValue=1 then sum(CP*Qty) else sum(Rate*Qty) end from 
		(select CompanyID,ProductID,BarcodeId,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,WValue/Qty WRate,null MRP,Qty from
		(select CompanyID,ProductID,BarcodeId,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyID,ProductID,BarcodeId having sum(Qty)<>0)s)a
	End
	Else
	Begin
		if @PRateCalculation=0
			select @Type=case when @StockValue=1 then sum(CP*Qty) else sum(Rate*Qty) end from #FIFO
		Else
			select @Type=case when @StockValue=1 then sum(CP*Qty) else sum(Rate*Qty) end from 
			(select CompanyID,ProductID,Rate,CP,SRate,WRate,max(MRP)MRP,sum(Qty)Qty from #Stock group by CompanyID,ProductID,Rate,CP,SRate,WRate)a
	End
End
else if @Type=0  --All Item Rate,Qty
Begin
	if @PRateCalculation=0
		select ProductID,Rate,CP,SRate,sum(Qty)Qty from #FIFO group by ProductID,Rate,SRate,CP
	Else
		select ProductID,Rate,CP,SRate,sum(Qty)Qty from #Stock group by ProductID,Rate,SRate,CP
End
else if @Type=1  --Supplied Item Rate,Qty
Begin
	if (@AutoBarcode=1 and @StockCalculation=0)
		select CompanyID,ProductID,sum(RValue)/sum(Qty) Rate,sum(CPvalue)/sum(Qty) CP,sum(SValue)/sum(Qty) SRate,sum(WValue)/sum(Qty) WRate,null MRP,sum(Qty)Qty,sum(Pieces)Pieces from
		(select CompanyID,ProductID,BarcodeId,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(round(sum(Qty),12),0)Qty,sum(Pieces)Pieces from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyID,ProductID,BarcodeID having sum(Qty)<>0)s
		group by CompanyID,ProductID having sum(Qty)<>0
	Else if @PRateCalculation=0 --FIFO
		select CompanyID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,WValue/Qty WRate,null MRP,Qty,null from
		(select CompanyID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #FIFO group by CompanyID,ProductID)s
	Else if @PRateCalculation=3 --WA
		select CompanyID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,WValue/Qty WRate,null MRP,Qty,null from
		(select CompanyID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #Stock group by CompanyID,ProductID)s
	Else
		select CompanyID,ProductID,Rate,CP,SRate,WRate,max(MRP)MRP,sum(Qty)Qty,sum(Pieces)Pieces from #Stock group by CompanyID,ProductID,Rate,CP,SRate,WRate
End
else if @Type=2 --Rate,CP,SRate only
Begin
	if exists(select top 1 1 from @BRate)
		select null,ProductID,BarcodeID,Rate,CP,SRate from @BRate order by BarcodeID desc
	else if exists(select top 1 1 from #FIFO)
	Begin
		select null,ProductID,null,Rate,CP,null from
		(select ProductID,sum(Rate*Qty)/sum(Qty)Rate,sum(CP*Qty)/sum(Qty)CP,sum(Qty)Qty from #FIFO group by ProductID having sum(Qty)<>0)r
		union all --Rate of 0 stock item
		select null,s.ProductID,null,max(s.Rate),max(s.CP),null from #Stock s left join #FIFO f on s.ProductID=f.ProductID where f.ProductID is null group by s.ProductID 
	End
	else if exists(select top 1 1 from @Rate)
		select Date,ProductID,null,Rate,CP,SRate from @Rate order by Date desc
	else 
		select top 1 null,ProductId,null,CP,CP,Rate from #Stock where InOut is null order by date desc
		
End

else if @Type in(3,4)  --Item,Barcode,Rate,Qty
Begin
	select CompanyId,ProductID,BarcodeID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,Qty from
	(select CompanyID,ProductID,BarcodeID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyID,ProductID,BarcodeID having sum(Qty)<>0)s
End
else if @Type=5  --Supplied Barcode,Rate
	select ProductID,BarcodeID,Rate,CP,SRate from @BRate
else if @Type=6  --Supplied WH,Item,Rate,Qty
Begin
	if @PRateCalculation=0
		select CompanyId,WHID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,Qty,null Pieces from
		(select CompanyId,WHID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,nullif(sum(Qty),0)Qty from #FIFO group by CompanyID,WHID,ProductID)s
	else
		select CompanyId,WHID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,Qty,Pieces from
		(select CompanyId,WHID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,nullif(sum(Qty),0)Qty,sum(Pieces)Pieces from #Stock group by CompanyID,WHID,ProductID)s
End
else if @Type=7  --Supplied WH,Item,Barcode,Rate,Qty
	select WHID,ProductID,BarcodeID,Rate,CP,SRate,sum(Qty)Qty from #Stock group by WHID,ProductID,BarcodeID,Rate,CP,SRate
else if @Type=8  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Rate,Qty
	select CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,Rate,CP,SRate,sum(Qty)Qty from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,Rate,CP,SRate
else if @Type=9  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Barcode,Rate,Qty
	select CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate,sum(Qty)Qty from #Stock group by CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate
else if @Type=10  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Rate,Qty,Discount(Sales/SR Only,for Profit)
Begin
	select CompanyId,InOut,Date,VtypeId,No,TransactionID,WHID,ProductID,BarcodeId,SerialNoId,Rate,CP,SRate,sum(Qty)Qty,sum(FOC)FOC,sum(Discount)Discount,sum(Tax)Tax from #Stock 	where InOut=1 
	group by CompanyId,InOut,Date,VtypeId,No,TransactionID,WHID,ProductID,BarcodeId,SerialNoId,Rate,CP,SRate
	--select InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeId,Rate,CP,SRate,sum(Qty)Qty,sum(FOC)FOC,sum(Discount)Discount,sum(Tax)Tax from #Stock where InOut=1 group by InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeId,Rate,CP,SRate
End
else if @Type=11  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Barcode,Rate,Qty,Discount(Sales/SR Only,for Profit)
	select InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate,sum(Qty)Qty,sum(Discount)Discount from #Stock where InOut=1 group by InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate
else if @Type=12  --Supplied ProductID,Qty
Begin
	if (@AutoBarcode=1 and @StockCalculation=0 and @StockWithBarcodeOnly=1)
		select CompanyId,ProductID,BarcodeId,sum(Qty)Qty,sum(Pieces)Pieces from #Stock where BarcodeId>0 group by CompanyId,ProductID,BarcodeId
	Else
		select CompanyId,ProductID,null BarcodeId,sum(Qty)Qty,sum(Pieces)Pieces from #Stock group by CompanyId,ProductID
End
else if @Type=13  --Supplied ProductID,CP
Begin
	declare @CP table(ProductId int,CP float)

	if exists(select top 1 1 from #FIFO)
		insert @CP
		select ProductID,sum(CP*Qty)/nullif(sum(Qty),0)CP from #FIFO group by ProductID
	Else
		insert @CP
		select ProductID,CP from @Rate
	

	select * from @CP	
	union all
	select p.Id,Cost from invProduct p join #tmpProduct t on p.Id=t.Id left join @CP c on p.Id=c.ProductId where c.ProductId is null

End
else if @Type=14  --For Stock Ageing
Begin
	if (@AutoBarcode=1 and @StockCalculation=0)
		select ProductID,BarcodeId,min(Date)Date,sum(Qty)Qty,sum(Rate*Qty)Value from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by ProductID,BarcodeId having sum(Qty)<>0
	Else
		select ProductID,0 BarcodeId,Date,sum(Qty)Qty,sum(Rate*Qty)Value from #FIFO group by ProductID,Date having sum(Qty)<>0
End
else if @Type=15  --For Product Stock having barcodes
Begin
	if exists(select top 1 1 from #FIFO)
	Begin
		select null,ProductID,null,Rate,CP,null from
		(select ProductID,sum(Rate*Qty)/sum(Qty)Rate,sum(CP*Qty)/sum(Qty)CP,sum(Qty)Qty from #FIFO group by ProductID having sum(Qty)<>0)r
		union all --Rate of 0 stock item
		--select null,s.ProductID,null,max(s.Rate),max(s.CP),null from #Stock s left join #FIFO f on s.ProductID=f.ProductID where f.ProductID is null group by s.ProductID 
		select null,ProductId,null,Rate,CP,SRate from
		(select row_number()over (partition by s.ProductId order by s.Date desc)sno,s.ProductID,s.Rate,s.CP,s.SRate from #Stock s left join #FIFO f on s.ProductID=f.ProductID where f.ProductID is null)s
		where sno=1
	End
	else if exists(select top 1 1 from @Rate)
		--select Date,ProductID,null,Rate,CP,SRate from @Rate order by Date desc
		select null,ProductId,null,Rate,CP,SRate from
		(select row_number()over (partition by ProductId order by Date desc)sno,ProductId,Rate,CP,SRate from @Rate)s
		where sno=1
	else 
		select null,ProductId,null,Rate,CP,SRate from
		(select row_number()over (partition by ProductId order by Date desc)sno,ProductId,Rate,CP,SRate from #Stock where InOut is null and Qty>0)s
		where sno=1
End
else if @Type=16  --Ratewise Stock
	select ProductID,Date,round(CP,2),sum(Qty)Qty  from #Stock where CP<>0 group by ProductID,Date,round(CP,2) having sum(Qty)<>0
else if @Type=17  --For WH wise Stock Ageing
	select ProductID,WHID,Date,sum(Qty)Qty,sum(Rate*Qty)Value from #FIFO group by ProductID,WHID,Date


drop table #Stock
delete tmpTable where SPID=@@SPID



go

if object_id('prGetCustomerForSales') is not null
	drop proc prGetCustomerForSales
go	
	
create proc prGetCustomerForSales
@UserID int,
@CompanyId int=1
as

set nocount on
set transaction isolation level read uncommitted

create table #Customer(ID int,Code varchar(50),Name nvarchar(100),NickName nvarchar(100),NameInOL nvarchar(100),Address1 nvarchar(100),
Address2 nvarchar(100),Address3 nvarchar(100),Address4 nvarchar(100),Address5 nvarchar(100),Phone varchar(100),ContactPerson nvarchar(100),
SalesManID int,CreditLimit float,DueDays int,TIN varchar(100),UnderID int,Under nvarchar(100),RateLevelID int,GST varchar(100),PaymentMode int,Property nvarchar(150),Address nvarchar(500),Place nvarchar(100),Address8 nvarchar(100),DLNO1 nvarchar(100))

insert #Customer(ID,Code,Name,NickName,NameInOL,Address1,Address2,Address3,Address4,Address5,Phone,ContactPerson,SalesManID,CreditLimit,DueDays,TIN,UnderID,RateLevelID,GST,PaymentMode,Place,Address8,DLNO1)
select t2.[Id],t2.[Code],t2.[Name],t1.[Name] [NickName],t2.NameinOL,t1.[Address1],t1.[Address2],t1.[Address3],t1.[Address4],t1.[Address5],
isnull(t1.[Phone],'')+'   '+isnull(t1.[MobileNo],''),t1.[ContactPerson],isnull(t1.SalesManId,0)SalesManId,t1.CreditLimit,t1.DueDays,t1.TIN,t2.UnderAccountID,t1.RateLevelID,t1.GST,t1.PaymentMode,t1.Place,t1.Address8,DLNO1 from invCustomer t1
join aAccount t2 on t1.AccountId = t2.Id 
join invUserCompany uc on t1.CompanyID=uc.CompanyID and uc.UserID=@UserID
where uc.Customer=1 and (t1.InActive is null or t1.InActive=0)


if exists(select top 1 1 from invOption where SalesToVendors=1 and CompanyId=@CompanyId)
	insert #Customer(ID,Code,Name,NickName,NameInOL,Address1,Address2,Address3,Phone,ContactPerson,SalesManID,CreditLimit,DueDays,TIN,UnderID,RateLevelID,GST)
	select t2.[Id],t2.[Code],t2.[Name],t1.[Name] [NickName],t2.NameinOL,t1.[Address1],t1.[Address2],t1.[Address3],
	isnull(t1.[Phone],'')+isnull(t1.[MobileNo],''),t1.[ContactPerson],0 SalesManId,t1.CreditLimit,t1.DueDays,t1.TIN,t2.UnderAccountID,null,t1.GST from invVendor t1
	join aAccount t2 on t1.AccountId = t2.Id 
	join invUserCompany uc on t1.CompanyID=uc.CompanyID and uc.UserID=@UserID
	where uc.Vendor=1 and (t1.InActive is null or t1.InActive=0)



insert #Customer(ID,Code,Name,NickName,NameInOL,Address1,Address2,Address3,Phone,ContactPerson,SalesManID,CreditLimit,DueDays,TIN,UnderID,RateLevelID,GST,Address8,DLNO1,Place)
select t2.[Id],t2.[Code],t2.[Name],t1.[Name] [NickName],t2.NameinOL,t1.[Address1],t1.[Address2],t1.[Address3],isnull(t1.[Phone],'')+isnull(t1.[MobileNo],''),t1.[ContactPerson],0 SalesManId,t1.CreditLimit,t1.DueDays,t1.TIN,t2.UnderAccountID,null,t1.GST,t1.Address8,t1.DLNO1,t1.Place from invCustomer t1
join aCompany c on t1.AccountId=c.AccountId
join aAccount t2 on t1.AccountId = t2.Id
left join #Customer cu on t1.AccountId=cu.Id where cu.Id is null


--Under
update c set c.Under=u.Name from #Customer c join aAccount u on c.UnderID=u.ID

if exists(select 1 from invOption where DefaultSearchOfCustomer=2)
Begin
	
	update c set c.Property=s.Code+' '+c.Name from #Customer c join invAccountPropertyDetails pd on c.ID=pd.AccountID join invAccountSubProperty s on pd.SubPropertyID=s.ID 
	update #Customer set Property=Name where Property is null
End

--Address
update #Customer set Address=rtrim(ltrim(isnull(Address1,'')+' '+isnull(Address2,'')+' '+isnull(Address3,'')+' '+isnull(Place,''))),phone=ltrim(rtrim(phone))

--Vendor to Customer Details
update c1 set c1.Address1=c2.Address1,c1.Address2=c2.Address2,c1.Address3=c2.Address3,c1.Address4=c2.address4,c1.Address5=c2.Address5,c1.GST=c2.GST,c1.Place=c2.Place,c1.Address8=c2.Address8,c1.DLNO1=c2.Address8 from #Customer c1 
join invVendor v on c1.ID=v.AccountID
join invCustomer c2 on v.TIN=c2.TIN
where c1.Address4 is null and c1.Address5 is null and c1.TIN>''

select * from #Customer order by Name

go

if object_id('spGetInvSalesHeader') is not null
	drop proc spGetInvSalesHeader
go

create proc spGetInvSalesHeader      
@CompanyID int,      
@PeriodID int,      
@VtypeID int,      
@No int      
as      
set nocount on   
set transaction isolation level read uncommitted

declare @Table table(CustomerID int,Code nvarchar(50),Customer nvarchar(100),Under nvarchar(100),VType varchar(50),No int,Date smalldatetime,
Amount float,Notes nvarchar(500),SalesReturn float,AirWayBillNo varchar(50),PaymentMode tinyint,VtypeDetails varchar(50),QuotationNo int,
Rep1 varchar(100),Rep2 varchar(100),DeliveryDate smalldatetime,Discount float,Total float,SalesMan nvarchar(50),Address1 nvarchar(100),
Address2 nvarchar(100),Address3 nvarchar(100),Place nvarchar(100),Phone nVarchar(50),MobileNo nVarchar(50),Email nVarchar(100),Location varchar(500),
ContactPerson nvarchar(100),PaymentTerms nvarchar(100),RoundOff float,Advance float,Tax float,Paid float,TIN nVarchar(100),CST nVarchar(100),
DLNo1 nVarchar(100),DLNo2 nVarchar(100),PrePrintingString  nVarchar(100),Time int,DiscountP float,Company varchar(50),Property1 varchar(100),
Addition float,GST nVarchar(100),Address nvarchar(300),TaxP float,BillTax float,CustomerInOL nvarchar(100),ReturnID int,RateLevel varchar(50),
UserName varchar(100),CardNo varchar(25),CardID int,Points float,Redempted float,DueDate datetime,TokenNo int,CostCentre nvarchar(50),
QRCodeImage Image,PeriodCode varchar(50),PeriodName varchar(50),ShippingNo varchar(50),Remark1 nVarchar(2000),Remark2 nVarchar(2000),Remark3 nVarchar(2000),Remark4 nVarchar(2000),
Address4 nvarchar(100),Address5 nvarchar(100),Address6 nvarchar(100),Address7 nvarchar(100),Address8 nvarchar(100),Address9 nvarchar(100),AName nvarchar(100)
,InvoiceFormat nvarchar(100),SalesManCode nvarchar(50),SRVtypeId int,SRNo int,PiadBy int,CreditCardID int,CreditCard nVarchar(50),Discount1 float,Discount2 float,Discount3 float,LocalMobileNo varchar(100))  

insert @Table(CustomerID,Code,Under,VType,No,Date,Amount,Notes,SalesReturn,AirWayBillNo,PaymentMode,VtypeDetails,QuotationNo,DeliveryDate,
Discount,Total,SalesMan,RoundOff,Advance,Tax,Paid,PrePrintingString,Time,DiscountP,Company,Addition,Address,TaxP,BillTax,CustomerInOL,ReturnID,
RateLevel,UserName,CardID,DueDate,TokenNo,CostCentre,QRCodeImage,PeriodCode,PeriodName,ShippingNo,Remark1,Remark2,Remark3,Remark4,AName,SRVtypeId,
SRNo,PiadBy,CreditCardID,Discount1,Discount2,Discount3,LocalMobileNo)  

select s.CustomerID,a.Code,u.Name,v.Code,s.No,cast(cast(s.Date as varchar)as smalldatetime),s.NetTotal,s.Notes,s.SalesReturn,s.AirWayBillNo,
s.PaymentMode,v.Description,QuotationNo,cast(cast(s.DeliveryDate as varchar)as smalldatetime)DeliveryDate,s.Discount,s.Total,s.SalesManID,
s.RoundOff,s.Advance,s.Tax,s.Paid,s.PrePrintingString,s.Time,s.DiscountP,co.Name Company,s.Addition,s.Address,s.TaxGroupID,s.BillTax,a.NameInOL,
s.ReturnID,s.RateLevelID,usr.name,pc.CardId,cast(cast(nullif(s.duedate,0) as varchar) as datetime),s.TokenNo,s.CostCentreId,s.QRCodeImage,
p.Code,p.Name,s.ShippingNo,Remark1,Remark2,Remark3,Remark4,a.Name,sr.VtypeId,sr.No,s.PaidBy,s.CreditCardID,s.Discount1,s.Discount2,s.Discount3,s.LocalMobileNo from invSalesHeader s      
join invVoucherTypeDetails v on s.VtypeID=v.ID      
join aAccount a on s.CustomerID=a.ID  
join aAccount u on a.UnderAccountID=u.ID  
join aCompany co on s.CompanyID=co.ID  
join aPeriod p on s.PeriodId=p.Id
left outer join invUser usr on s.userid = usr.id
left outer join invPrivilegeCardSales pc on pc.CompanyId=s.CompanyId and pc.PeriodId=s.PeriodId and pc.VtypeId=s.VtypeID and pc.No=s.No
left outer join invSalesReturnHeader sr on s.ReturnId=sr.Id
where s.CompanyID=@CompanyID and s.PeriodID=@PeriodID and s.VtypeId=@VtypeID and s.No=@No      


--Customer
update t set t.Customer=c.Name,t.Address1=c.Address1,t.Address2=c.Address2,t.Address3=c.Address3,t.Address4=c.Address4,t.Address5=c.Address5,t.Address6=c.Address6,t.Address7=c.Address7,t.Place=c.Place,t.Phone=c.Phone,t.Address8=c.Address8,t.Address9=c.Address9,
t.MobileNo=c.MobileNo,t.EMail=c.EMail,t.Location=c.Location,t.ContactPerson=c.ContactPerson,t.PaymentTerms=c.PaymentTerms,t.DLNo1=c.DLNo1,
t.DLNo2=c.DLNo2,t.TIN=c.TIN,t.GST=c.GST,t.CST=c.CST from invCustomer c join @Table t on c.AccountID=t.CustomerID

--Vendor
update t set t.Customer=c.Name,t.Address1=c.Address1,t.Address2=c.Address2,t.Address3=c.Address3,t.Phone=c.Phone,t.MobileNo=c.MobileNo,
t.EMail=c.EMail,t.Location=c.Fax,t.ContactPerson=c.ContactPerson,t.PaymentTerms=c.PaymentTerms,t.DLNo1=c.DLNo1,t.DLNo2=c.DLNo2,t.GST=c.GST,
t.TIN=c.TIN from invVendor c join @Table t on c.AccountID=t.CustomerID where t.Customer is null
 

--Rep1  
update t set t.Rep1=r.Name from invRep1 r join @Table t on r.ID=t.Rep1   
--Rep2  
update t set t.Rep2=r.Name from invRep2 r join @Table t on r.ID=t.Rep2  
--Salesman  
update t set t.Salesman=s.Name,t.SalesmanCode=s.Code from invSalesMan s join @Table t on s.ID=t.SalesMan  
--Property1  
update t set t.Property1=s.Name from @Table t join invAccountPropertyDetails pd on t.CustomerID=pd.AccountID join invAccountSubProperty s on pd.SubPropertyID=s.ID  
where pd.PropertyID=1  
--TaxP
update t set t.TaxP=tg.OutPutTax from invTaxGroup tg join @Table t on tg.ID=t.TaxP
--Rate Level
update t set t.RateLevel=r.Name from invRateLevel r join @Table t on r.ID=t.RateLevel
--Rate Level
update t set t.CostCentre=c.Name from invCostCentre c join @Table t on c.ID=t.CostCentre
--CreditCard
update t set t.CreditCard=c.Name from  aCreditCard c join @Table t on c.ID=t.CreditCardID

  
--Privilege Card
declare @PC Table (CardID int ,CardNo Varchar(50),Points float,Redempted float)
insert @PC
select i.id,i.CardNo, Sum(pc.Points),SUM(pc.Redempted) from invPrivilegeCardSales pc join invPrivilegeCardIssue i on pc.CardID=i.ID
join @Table t on pc.CardId =t.CardID  
group by i.id,i.CardNo
update t set t.CardNo=pc.CardNo,t.Points=pc.Points,t.Redempted=pc.Redempted from @PC pc join @Table t on pc.CardId =t.CardID  
-------------

--Invoice Format
update t set t.InvoiceFormat=v.InvoiceFormat from @Table t join invVoucherTypeStartNo v on v.CompanyId=@CompanyID and v.PeriodId=@PeriodID and v.VtypeId=@VtypeID 

select * from @Table  

go

if object_id('prGetCustomerForSales') is not null
	drop proc prGetCustomerForSales
go	
	
create proc prGetCustomerForSales
@UserID int,
@CompanyId int=1
as

set nocount on
set transaction isolation level read uncommitted

create table #Customer(ID int,Code varchar(50),Name nvarchar(100),NickName nvarchar(100),NameInOL nvarchar(100),Address1 nvarchar(100),
Address2 nvarchar(100),Address3 nvarchar(100),Address4 nvarchar(100),Address5 nvarchar(100),Phone varchar(100),ContactPerson nvarchar(100),
SalesManID int,CreditLimit float,DueDays int,TIN varchar(100),UnderID int,Under nvarchar(100),RateLevelID int,GST varchar(100),PaymentMode int,Property nvarchar(150),Address nvarchar(500),Place nvarchar(100),Address8 nvarchar(100),DLNO1 nvarchar(100))

insert #Customer(ID,Code,Name,NickName,NameInOL,Address1,Address2,Address3,Address4,Address5,Phone,ContactPerson,SalesManID,CreditLimit,DueDays,TIN,UnderID,RateLevelID,GST,PaymentMode,Place,Address8,DLNO1)
select t2.[Id],t2.[Code],t2.[Name],t1.[Name] [NickName],t2.NameinOL,t1.[Address1],t1.[Address2],t1.[Address3],t1.[Address4],t1.[Address5],
isnull(t1.[Phone],'')+'   '+isnull(t1.[MobileNo],''),t1.[ContactPerson],isnull(t1.SalesManId,0)SalesManId,t1.CreditLimit,t1.DueDays,t1.TIN,t2.UnderAccountID,t1.RateLevelID,t1.GST,t1.PaymentMode,t1.Place,t1.Address8,DLNO1 from invCustomer t1
join aAccount t2 on t1.AccountId = t2.Id 
join invUserCompany uc on t1.CompanyID=uc.CompanyID and uc.UserID=@UserID
where uc.Customer=1 and (t1.InActive is null or t1.InActive=0)


if exists(select top 1 1 from invOption where SalesToVendors=1 and CompanyId=@CompanyId)
	insert #Customer(ID,Code,Name,NickName,NameInOL,Address1,Address2,Address3,Phone,ContactPerson,SalesManID,CreditLimit,DueDays,TIN,UnderID,RateLevelID,GST)
	select t2.[Id],t2.[Code],t2.[Name],t1.[Name] [NickName],t2.NameinOL,t1.[Address1],t1.[Address2],t1.[Address3],
	isnull(t1.[Phone],'')+isnull(t1.[MobileNo],''),t1.[ContactPerson],0 SalesManId,t1.CreditLimit,t1.DueDays,t1.TIN,t2.UnderAccountID,null,t1.GST from invVendor t1
	join aAccount t2 on t1.AccountId = t2.Id 
	join invUserCompany uc on t1.CompanyID=uc.CompanyID and uc.UserID=@UserID
	where uc.Vendor=1 and (t1.InActive is null or t1.InActive=0)



insert #Customer(ID,Code,Name,NickName,NameInOL,Address1,Address2,Address3,Phone,ContactPerson,SalesManID,CreditLimit,DueDays,TIN,UnderID,RateLevelID,GST,Address8,DLNO1,Place)
select t2.[Id],t2.[Code],t2.[Name],t1.[Name] [NickName],t2.NameinOL,t1.[Address1],t1.[Address2],t1.[Address3],isnull(t1.[Phone],'')+isnull(t1.[MobileNo],''),t1.[ContactPerson],0 SalesManId,t1.CreditLimit,t1.DueDays,t1.TIN,t2.UnderAccountID,null,t1.GST,t1.Address8,t1.DLNO1,t1.Place from invCustomer t1
join aCompany c on t1.AccountId=c.AccountId
join aAccount t2 on t1.AccountId = t2.Id
left join #Customer cu on t1.AccountId=cu.Id where cu.Id is null


--Under
update c set c.Under=u.Name from #Customer c join aAccount u on c.UnderID=u.ID

if exists(select 1 from invOption where DefaultSearchOfCustomer=2)
Begin
	
	update c set c.Property=s.Code+' '+c.Name from #Customer c join invAccountPropertyDetails pd on c.ID=pd.AccountID join invAccountSubProperty s on pd.SubPropertyID=s.ID 
	update #Customer set Property=Name where Property is null
End

--Address
update #Customer set Address=rtrim(ltrim(isnull(Address1,'')+' '+isnull(Address2,'')+' '+isnull(Address3,'')+' '+isnull(Place,''))),phone=ltrim(rtrim(phone))

--Vendor to Customer Details
update c1 set c1.Address1=c2.Address1,c1.Address2=c2.Address2,c1.Address3=c2.Address3,c1.Address4=c2.address4,c1.Address5=c2.Address5,c1.GST=c2.GST,c1.Place=c2.Place,c1.Address8=c2.Address8,c1.DLNO1=c2.DLNO1 from #Customer c1 
join invVendor v on c1.ID=v.AccountID
join invCustomer c2 on v.TIN=c2.TIN
where c1.Address4 is null and c1.Address5 is null and c1.TIN>''

select * from #Customer order by Name

go

if object_id('prStockReport') is not null
  drop proc prStockReport

go
  
create proc prStockReport 
@To int, 
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@ValueDataWhereClause varchar(max),
@MasterDataWhereClause varchar(max),  
@Order varchar(max),
@GrandTotal varchar(max),
@AlterHeaderTable varchar(max),
@AlterGroupTable varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@ProcessedValueFilter varchar(max),
@ProcessedMasterFilter varchar(max),
@CompanyID int,
@PRateCalculation int=null,
@CostCentreId int=0
as  
   
set nocount on  
set transaction isolation level read uncommitted

declare @cols varchar(max),
        @colVal varchar(max),
        @WhereClause varchar(max)         

create table #T1 
(
CompanyId int,
ProductId int,
Rate float,
CP float,
SRate float,
WRate float,
MRP float,
Qty float,
StockQty float,
Stock varchar(50),
StockCP float,
StockMultiplier float,
Barcode varchar(50),
Pieces float
)

create table #Vendors
(
ProductId int,
VendorId int,
Name nvarchar(200)
)

create table #TaxGroup
(
ProductId int,
TaxGroupId int
)

declare @Purchase table
(
ProductId int,
VendorId int,
TaxGroupId int
)

insert #Vendors (ProductId,VendorId) select ProductId,max(VendorId) from invPrefeRredVendors group by ProductId

insert #TaxGroup(ProductId,TaxGroupId) select Id,TaxGroupId from invProduct

Sales
;with t1 as (select t2.ProductId,t2.TaxGroupId,row_number() over(partition by t2.ProductId order by t1.Date desc) Sno from invSalesHeader t1
join invSalesDetails t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No 
where t1.CompanyID = @CompanyID
and t1.Date<=@To
)

update tg set tg.TaxGroupId=t1.TaxGroupId from #TaxGroup tg join t1 on tg.ProductId=t1.ProductId
--------

;with t1 as (select t1.VendorId,t2.ProductId,t2.TaxGroupId,row_number() over(partition by t2.ProductId order by t1.Date desc) Sno from invPurchaseHeader t1
join invPurchaseDetails t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No 
where t1.CompanyID = @CompanyID
and t1.Date<=@To
)

insert @Purchase (ProductId,VendorId,TaxGroupId) select ProductId,VendorId,TaxGroupId from t1 where sno = 1

update t1 set t1.VendorId = t2.VendorId from #Vendors t1
join @Purchase t2 on t1.ProductId = t2.ProductId

update t1 set t1.TaxGroupId = t2.TaxGroupId from #TaxGroup t1
join @Purchase t2 on t1.ProductId = t2.ProductId


insert #Vendors (ProductId,VendorId) 
select t1.ProductId,t1.VendorId from @Purchase t1
left outer join #Vendors t2 on t1.ProductId = t2.ProductId 
where t2.ProductId is null

update t1 set t1.Name = t2.Name from #Vendors t1
join aAccount t2 on t1.VendorId = t2.Id

declare @OptCompanyId int
select @OptCompanyId=min(Id) from aCompany
set @OptCompanyId=case when @CompanyID=0 then @OptCompanyId else @CompanyID end

declare @InActiveStock bit
select @InActiveStock=isnull(InActiveStock,0) from invOption where CompanyId=@OptCompanyId

if len(@ValueDataWhereClause) > 0 and LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0 and ' + @ValueDataWhereClause + ' and ' + @MasterDataWhereClause 
else if len(@ValueDataWhereClause) > 0 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0 and ' + @ValueDataWhereClause 
else if LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0 and ' + @MasterDataWhereClause 
else 
  set @WhereClause = ' where (isnull(t3.inactive,0) = 0 or '+cast(@InActiveStock as varchar)+'=1) and isnull(NonStockItem,0) = 0'  


if len(@WhereClause) > 0 
begin
	exec('insert tmpTable(SPID,ID,BarcodeID) select @@spid,t3.Id,null from invProduct t3 
				join invUom t4 on t3.BaseUom = t4.id 
				join vw_ProductProerty t6 on t3.Id = t6.Id
				join #TaxGroup tg on t3.Id=tg.ProductId
                left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
				left join #Vendors t10 on t3.Id = t10.ProductId
				left join invCostCentre t11 on t3.CostCentreId = t11.Id
				' + @WhereClause) 
	end
else
begin
	
	insert tmpTable(SPID,ID,BarcodeID) select @@spid,Id,null from invProduct 
	where (isnull(inactive,0) = 0 or @InActiveStock=1) and isnull(NonStockItem,0) = 0
end


declare @CurrentPRateCalculation int
if @CompanyId <> 0 and @PRateCalculation is not null
begin
  select @CurrentPRateCalculation = PRateCalculation from invOption where CompanyId = @CompanyId
  update invOption set PRateCalculation = @PRateCalculation where CompanyId = @CompanyId
end



insert #T1(CompanyId,ProductId,Rate,CP,SRate,WRate,MRP,Qty,Pieces) 
exec spstock @ToDate=@To,@Type=1,@CompanyID=@CompanyID,@CostCentreId=@CostCentreId

--MRP
update t1 set t1.MRP=p.MRP from #T1 t1 join invProduct p on t1.ProductId=p.Id where isnull(t1.MRP,0)=0

exec('insert #T1(CompanyId,ProductId,Rate,CP,SRate,WRate,MRP,Qty) 
	select '+@CompanyId+',t3.Id,t3.Cost,t3.Cost,t3.Rate,t3.WRate,t3.MRP,0 from invProduct t3 
	join invUom t4 on t3.BaseUom = t4.id 
	join vw_ProductProerty t6 on t3.Id = t6.Id
	join #TaxGroup tg on t3.Id=tg.ProductId
	left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
	left join #Vendors t10 on t3.Id = t10.ProductId
	left join invCostCentre t11 on t3.CostCentreId = t11.Id
	left join #T1 t on t3.Id=t.ProductId and '+@CompanyId+'=t.CompanyId 
	'+@WhereClause + ' and t.ProductId is null ')

if @CompanyId <> 0 and @CurrentPRateCalculation is not null
begin
  update invOption set PRateCalculation = @CurrentPRateCalculation where CompanyId = @CompanyId
end

if len(@ProcessedValueFilter) > 0 
begin
	update #T1 set Rate=isnull(Rate,0),CP=isnull(CP,0),SRate=isnull(SRate,0),Qty=isnull(Qty,0)--to filter null value also
	exec ('delete t1 from #T1 t1 where not (' + @ProcessedValueFilter +')')
end		

if len(@ProcessedMasterFilter) > 0 
begin
  exec ('delete t1 from #T1 t1 where not (' + @ProcessedMasterFilter +')')
end		


create index ind#T1 on #T1(ProductId)

--Stock CP,Qty
update t set t.Barcode=u.Barcode,t.StockQty=round(t.Qty/u.Secondary,10),t.StockMultiplier=u.Secondary,t.StockCP=t.CP*u.Secondary from #T1 t join invProduct p on p.Id=t.ProductId join invUOMLevels u on t.ProductId=u.ProductId and p.StockUom=u.UomId where u.Secondary<>0
update t set t.Stock=cast(floor(t.StockQty) as varchar)+'.'+cast((t.StockQty-floor(t.StockQty))*t.StockMultiplier as varchar) from #T1 t
--WRate
update t set t.Wrate=r.Rate from invBarcode r join #T1 t on r.ProductId=t.ProductId join invRateLevel l on r.LevelId=l.Id and l.Rate=3 where t.Wrate is null
update t set t.Wrate=r.WRate from invProduct r join #T1 t on r.Id=t.ProductId where t.Wrate is null or t.Wrate=0


if @Group = 0  
	if @GroupTotal = 0     
		begin
			
			exec('select row_number() over (order by (select 1)) SNo,' + @Columns + ' from #T1 t1 
			join invProduct t3 on t1.ProductId = t3.Id 
			join invUom t4 on t3.BaseUom = t4.id 
			left join invUom t5 on t3.StockUom = t5.Id 
			join vw_ProductProerty t6 on t1.ProductId = t6.Id
            join aCompany t7 on t1.CompanyId = t7.Id
			join #TaxGroup tg on t3.Id=tg.ProductId
			left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
			left join #Vendors t10 on t1.ProductId = t10.ProductId
			left join invCostCentre t11 on t3.CostCentreId = t11.Id
			' + @Order)


		end
    else
		begin
			if LEN(@Order) = 0 
				begin
					exec('select row_number() over (order by (select 1)) SNo,' + @Columns + ' from #T1 t1 
					join invProduct t3 on t1.ProductId = t3.Id 
					join invUom t4 on t3.BaseUom = t4.id
                 	left join invUom t5 on t3.StockUom = t5.Id  
					join vw_ProductProerty t6 on t1.ProductId = t6.Id
					join aCompany t7 on t1.CompanyId = t7.Id
                    join #TaxGroup tg on t3.Id=tg.ProductId
					left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
					left join #Vendors t10 on t1.ProductId = t10.ProductId
					left join invCostCentre t11 on t3.CostCentreId = t11.Id
					union all select null,' + @GrandTotal + ' from #T1 t1 
					join invProduct t3 on t1.ProductId = t3.Id 
					join invUom t4 on t3.BaseUom = t4.id 
                    left join invUom t5 on t3.StockUom = t5.Id 
			   		join vw_ProductProerty t6 on t1.ProductId = t6.Id
                    join aCompany t7 on t1.CompanyId = t7.Id
                    join #TaxGroup tg on t3.Id=tg.ProductId
					left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
					left join #Vendors t10 on t1.ProductId = t10.ProductId
					left join invCostCentre t11 on t3.CostCentreId = t11.Id
					' )

				end
		  else
			begin
			     declare @Query varchar(max)
					 
				 
				set @Query = 'select case when row_id=0 then row_number() over ('+@Order+') end-1 SNo,* from 
                                (select 0 row_id,' + @Columns + ' from #T1 t1 
								 join invProduct t3 on t1.ProductId = t3.Id 
				                 join invUom t4 on t3.BaseUom = t4.id 
			                     left join invUom t5 on t3.StockUom = t5.Id 
				                 left outer join vw_ProductProerty t6 on t1.ProductId = t6.Id
                                 join aCompany t7 on t1.CompanyId = t7.Id
                                 join #TaxGroup tg on t3.Id=tg.ProductId
								 left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
								 left join #Vendors t10 on t1.ProductId = t10.ProductId
								 left join invCostCentre t11 on t3.CostCentreId = t11.Id
				                 union all 
								 select 1 row_id,' + @GrandTotal + ' from #T1 t1 
				                 join invProduct t3 on t1.ProductId = t3.Id 
				                 join invUom t4 on t3.BaseUom = t4.id 
			                     left join invUom t5 on t3.StockUom = t5.Id 
				                 join vw_ProductProerty t6 on t1.ProductId = t6.Id
                                 join aCompany t7 on t1.CompanyId = t7.Id
                                 join #TaxGroup tg on t3.Id=tg.ProductId
								 left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
								 left join #Vendors t10 on t1.ProductId = t10.ProductId
								 left join invCostCentre t11 on t3.CostCentreId = t11.Id
				) p ' + replace(@order,'order by','order by row_id,')
				
				 
          		exec(@Query)
			end	   		
		end			

else  
	begin  
		
		create table #Stock ([ ] int)
		exec(@AlterHeaderTable)
		alter table #Stock drop column [ ]

		exec('insert #Stock select ' + @Columns + ' from #T1 t1 
		join invProduct t3 on t1.ProductId = t3.Id 
		join invUom t4 on t3.BaseUom = t4.id 
		left join invUom t5 on t3.StockUom = t5.Id 		
        join vw_ProductProerty t6 on t1.ProductId = t6.Id
        join aCompany t7 on t1.CompanyId = t7.Id
        join #TaxGroup tg on t3.Id=tg.ProductId
	    left join invTaxGroup t9 on tg.TaxGroupId = t9.Id
		left join #Vendors t10 on t1.ProductId = t10.ProductId
		left join invCostCentre t11 on t3.CostCentreId = t11.Id
		' + @Order)

		create table #StockGroup(Rid numeric identity(1,1))  
		exec(@AlterGroupTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #Stock,#StockGroup
	end   


go

if object_id('spImportSalesFromExcel') is not null
    drop proc spImportSalesFromExcel

go

create proc spImportSalesFromExcel
@CompanyId int,
@PeriodId int,
@VtypeId int,
@UserId int,
@Xml xml

as

set nocount on
set xact_abort on

declare @idoc int      
exec sp_xml_preparedocument @idoc output, @Xml

declare @Sales table(SNo int identity(1,1),InvoiceNo varchar(100),InvoiceDate int,PaymentMode int,CustomerCode nvarchar(100),Customer nvarchar(100),Address1 nvarchar(150),Address2 nvarchar(150),TaxRegNo varchar(25),EMail varchar(50),Product nvarchar(100),Qty float,Rate float,TaxP float,Tax float,Total float)

insert @Sales (InvoiceNo,InvoiceDate,PaymentMode,CustomerCode,Customer,Address1,Address2,TaxRegNo,EMail,Product,Qty,Rate,TaxP)
select InvoiceNo,InvoiceDate,case PaymentMode when 'Card' then 3 when 'Credit' then 1 else 0 end,CustomerCode,Customer,Address1,Address2,TaxRegNo,EMail,Product,Qty,Rate,TaxP
from openxml (@idoc, '/Details/Table1',2)      
with
(
InvoiceNo   varchar(100)  '@InvoiceNo',
InvoiceDate int   '@InvoiceDate',
PaymentMode varchar(50)   '@PaymentMode',
Customer    nvarchar(100) '@Customer',
CustomerCode    nvarchar(100) '@CustomerCode',
Address1    nvarchar(300) '@Address1',
Address2    nvarchar(300) '@Address2',
TaxRegNo    varchar(25)   '@TaxRegNo',
EMail       varchar(50)   '@EMail',
Product     nvarchar(100) '@Product',
Qty         float         '@Qty',
Rate        float         '@Rate',
TaxP        float         '@TaxP'
)
exec sp_xml_removedocument @idoc 


delete s from @Sales s join invSalesHeader h on s.InvoiceNo=h.AirWayBillNo and h.PeriodId=@PeriodId and h.CompanyId=@CompanyId and h.VtypeId=@VtypeId

update @Sales set Tax=Qty*Rate*TaxP/100.0
update @Sales set Total=Qty*Rate+Tax

----------
declare @No table([No] int)
insert @No exec prGetSalesMaxVno @CompanyID,@PeriodID,@VtypeId

declare @InvoiceNo table(InvoiceNo varchar(50),No int)
insert @InvoiceNo
select InvoiceNo,row_number()over(order by SNo)No from
(select InvoiceNo,max(SNo)SNo from @Sales group by InvoiceNo)i

update i set i.No=i.No+n.No-1 from @InvoiceNo i cross join @No n

----------


declare @MaxId int

-------Customer
select @MaxId=isnull(max(Id),0) from aAccount

declare @Customer table(Id int,Code nvarchar(100),Name nvarchar(100),TaxRegNo varchar(50),Address1 nvarchar(150),Address2 nvarchar(150),EMail varchar(50))
insert @Customer
select row_number()over(order by (select 1))+@MaxId,CustomerCode,Customer,TaxRegNo,Address1,Address2,EMail from
(select s.CustomerCode,s.Customer,s.TaxRegNo,max(s.Address1)Address1,max(s.Address2)Address2,max(s.EMail)EMail from @Sales s 
left join (select a.Code,c.Name,c.TIN from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
where c.Name is null group by s.CustomerCode,s.Customer,s.TaxRegNo)c

insert aAccount(Id,Code,Name,AccountSubGroupId,UnderAccountID,ModuleId)
select Id,case when len(c.Code)=0 then cast(Id as varchar) else c.Code end,Name,sg.SundryDebtors,s.Customers,1 from @Customer c
cross join aSubGroupSettings sg 
join aAccountSettings s on s.CompanyId=@CompanyId

insert invCustomer(AccountId,Name,Address1,Address2,Email,TIN,CompanyId)
select Id,Name,c.Address1,c.Address2,c.EMail,TaxRegNo,@CompanyId from @Customer c 
--------------


-------Product
select @MaxId=isnull(max(Id),0) from invProduct

declare @Product table(Id int,Name nvarchar(100),Rate float,TaxP float)
insert @Product(Id,Name)
select row_number()over(order by (select 1))+@MaxId,Product from
(select distinct Product from @Sales s left join invProduct p on s.Product=p.Name where p.Name is null)p

update p set p.Rate=s.Rate,p.TaxP=s.TaxP from @Product p join @Sales s on p.Name=s.Product


select @MaxId=isnull(max(Id),0) from invTaxGroup
insert invTaxGroup(Id,Code,Name,InputTax,OutPutTax,PurchaseValueTitle,PurchaseTaxTitle,SalesValueTitle,SalesTaxTitle,CGST,SGST)
select row_number()over(order by (select 1))+@MaxId,'T'+TaxP,'Tax'+TaxP,TaxP,TaxP,'Value'+TaxP,'Tax'+TaxP,'Value'+TaxP,'Tax'+TaxP,TaxP/2,TaxP/2 from
(select distinct cast(TaxP as varchar)TaxP from @Sales s left join invTaxGroup t on s.TaxP=t.OutputTax where t.Name is null)p


-------Product
declare @UOMId int
select @UOMId=min(Id) from invUOM

insert invProduct(Id,Code,Name,Rate,BaseUOM,PurchaseUOM,SalesUOM,StockUOM,MinUOM,MaxUOM,ROLUOM,ROQUOM,TaxGroupId)
select p.Id,p.Id,p.Name,p.Rate,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,t.Id from @Product p 
join invTaxGroup t on p.TaxP=t.OutputTax

insert invUOMLevels(Sno,ProductId,UomId,Multiplayer,UnitId,Secondary,Rate)
select 1,Id,@UOMId,1,@UOMId,1,Rate from @Product p 
--------------


insert invSalesHeader(VtypeId,No,Date,DeliveryDate,CustomerId,PaymentMode,Total,NetTotal,TaxCalculation,Tax,AirwayBillNo,CompanyId,PeriodId,Time,UserId,SalesmanId)
select @VtypeId,i.No,s.InvoiceDate,s.InvoiceDate,min(c.AccountId),s.PaymentMode,sum(Total),sum(Total),1,sum(Tax),s.InvoiceNo,@CompanyId,@PeriodId,
substring(convert(varchar,current_timestamp,8),1,2)+substring(convert(varchar,current_timestamp,8),4,2),@UserId,nullif(min(c.SalesManId),0) from @Sales s
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join (select a.Code,c.Name,c.TIN,c.AccountId,c.SalesManId from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
group by i.No,s.InvoiceDate,s.PaymentMode,s.InvoiceNo


insert invSalesDetails(VtypeId,No,SNo,ProductId,UOMId,Qty,Rate,Gross,Total,TaxGroupId,Tax,CompanyId,PeriodId)
select @VtypeId,i.No,row_number()over(partition by i.No order by i.No),p.Id,@UOMId,s.Qty,s.Rate,s.Qty*s.Rate,s.Total,p.TaxGroupId,s.Tax,@CompanyId,@PeriodId from @Sales s 
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join invProduct p on s.Product=p.Name


declare @AccountVtypeId int
select @AccountVtypeId=AccountVtypeId from invVoucherTypeDetails where Id=@VtypeId

insert aTransaction(CompanyId,PeriodId,Date,VoucherTypeId,No,DebtorId,CreditorId,Amount,Description,RefNo,ModuleID)
select @CompanyId,@PeriodId,s.InvoiceDate,@AccountVtypeId,i.No,case when s.PaymentMode=1 then c.AccountId else isnull(o.SalesCashAccountId,st.CashInHand) end,st.Sales,sum(s.Total),'Sales',s.InvoiceNo,1 from @Sales s
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join (select a.Code,c.Name,c.TIN,c.AccountId from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
join aAccountSettings st on st.CompanyId=@CompanyId
join invOption o on o.CompanyId=@CompanyId
group by s.InvoiceDate,i.No,c.AccountID,st.Sales,s.InvoiceNo,s.PaymentMode,o.SalesCashAccountId,st.CashInHand

insert aTransaction(CompanyId,PeriodId,Date,VoucherTypeId,No,DebtorId,CreditorId,Amount,Description,RefNo,ModuleID)
select @CompanyId,@PeriodId,s.InvoiceDate,@AccountVtypeId,i.No,st.Sales,o.OutPutTaxAccount,sum(s.Tax),'Sales Tax',s.InvoiceNo,1 from @Sales s
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join (select a.Code,c.Name,c.TIN,c.AccountId from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
join aAccountSettings st on st.CompanyId=@CompanyId
join invOption o on o.CompanyId=@CompanyId
group by s.InvoiceDate,i.No,c.AccountID,st.Sales,s.InvoiceNo,o.OutPutTaxAccount


go


if OBJECT_ID('prImportQuotationToSales') is not null
	drop proc prImportQuotationToSales
	
go

create proc prImportQuotationToSales
@CompanyID int,
@PeriodID int,
@No int,
@WarehouseId int,
@CustomerId int=0

as

set transaction isolation level read uncommitted
set nocount on
	
declare @Warehouse varchar(100)
select @Warehouse = Name from invWarehouse where Id =  @WarehouseId 

if not exists(select 1 from invOption where QoutationMultipleImporting=1 and CompanyID=@CompanyID)
Begin
	select @No = 0 from invSalesOrderHeader where CompanyId = @CompanyId and PeriodId = @PeriodId and QuotationNo = @No 
	if @No > 0
		select @No = 0 from invDeliveryNoteHeader where CompanyId = @CompanyId and PeriodId = @PeriodId and QuotationNo = @No
	if @No > 0
		select @No = 0 from invSalesHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and QuotationNo = @No
End


if @No > 0
begin
 if exists(select [No] from invQuotationHeader where CompanyId = @CompanyId and PeriodId = @PeriodId and No = @No and Approve = 0)
     set @No = 0
end 

create table #Header(CustomerId int,Customer nvarchar(100),PeriodId int)

insert #Header
select q.CustomerID,a.Name,q.PeriodId from invQuotationHeader q
join invCustomer c on q.CustomerId=c.AccountID
join aAccount a on c.AccountID=a.ID
where q.CompanyId = @CompanyId and q.[No] = @No and (q.CustomerId=@CustomerId or @CustomerId=0)

select top 1 @PeriodID=PeriodId from #Header order by PeriodId desc

select * from #Header order by PeriodId desc

declare @PurchasePropertyColumns varchar(max)
select @PurchasePropertyColumns = isnull(@PurchasePropertyColumns + ',t6.',',t6.') + quotename(name) + ',t6.' + quotename(name + '_Id')  from invPurchaseProperty 
order by Id

if @PurchasePropertyColumns is null
  set @PurchasePropertyColumns = ''

exec('select cast(0 as bit) [ ],t1.[Sno],t2.[Code],t2.Name Particulars,t1.[ProductId],
' + '''' + @Warehouse + '''' +  ' Warehouse,' + @WarehouseId + ' [WarehouseId],t4.Name Uom,
t1.[UomId],isnull(t1.[Qty],0)[Qty],isnull(t1.[Foc],0) [Foc],t1.[Rate],
t1.[Gross],t1.[DiscountP],t1.[Discount],
t2.TaxGroupId,isnull(t5.Name,'''') TaxGroup,isnull(t5.OutputTax,0) TaxP, Tax,
t1.[Total],GETDATE() [MfrDate],
GETDATE() [ExpDate],t2.SerialNo HaveSerialNo,t1.[Remark] ' + @PurchasePropertyColumns + 'from invQuotationDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
join invUom t4 on t1.UomId = t4.Id 
left join invTaxGroup t5 on t2.TaxGroupId = t5.Id
left join invJobWork w on t1.ProductId=w.ProductId
join vw_QuotationProperty t6 on t1.CompanyId = t6.CompanyId and t1.PeriodId = t6.PeriodId and t1.[No] = t6.No and t1.Sno = t6.Sno
where t1.CompanyId = ' + @CompanyId + ' and t1.PeriodId = ' + @PeriodId + ' and t1.[No] = ' + @No + '
and w.Id is null
order by t1.Sno ')

	
go

if object_id('prGetSalesForSearching') is not null
	drop proc prGetSalesForSearching
go

create proc prGetSalesForSearching
@CompanyID int,
@PeriodID int,
@VtypeId int,
@CustomerId int=0 
as
set nocount on
set transaction isolation level read uncommitted

create table #aAccount (Id int,Name nvarchar(100),Phone varchar(100),TIN varchar(100))

insert #aAccount(Id,Name) 
select Id,Name from aAccount

update a set a.Phone=isnull(c.MobileNo,'')+isnull(c.Phone,''),a.TIN=isnull(c.GST,'')+isnull(c.TIN,'') from #aAccount a join invCustomer c on a.Id=c.AccountID
update a set a.Phone=isnull(c.MobileNo,'')+isnull(c.Phone,''),a.TIN=isnull(c.GST,'')+isnull(c.TIN,'') from #aAccount a join invVendor c on a.Id=c.AccountID

select t1.[No],t1.AirwayBillNo InvoiceNo,CONVERT(varchar, cast(cast(nullif(t1.[Date],0) as varchar) as datetime),103) [Date],isnull(isnull(t1.address,t3.Name),'CANCELLED') [Customer],t3.TIN,
t3.Phone,t1.NetTotal,t1.Address,t1.Notes,cast(t1.TokenNo as varchar) + ' ' + convert(varchar,cast(cast(nullif(t1.Date,0) as varchar) as datetime) ,103) TokenNo from invSalesHeader t1
join #aAccount t3 on t1.CustomerId = t3.Id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and (t1.CustomerId = @CustomerId or @CustomerId = 0)
order by t1.[No] desc

go

if OBJECT_ID('prQuotationHeaderPrint') is not null
	drop proc prQuotationHeaderPrint
go

create proc prQuotationHeaderPrint
@CompanyId int,
@PeriodId int, 
@No int as
set nocount on

 
select t1.[No],cast(cast(t1.[Date] as varchar) as datetime) [Date],
cast(cast(t1.[ValidUpto] as varchar) as datetime) [ValidUpto],t2.Name [Customer],t4.Name NickName,
t3.Name [RateLevel],isnull(t1.[ReviseNo],0) / 100 [ReviseNo],t1.[RefferenceNo], 
t1.[Total],isnull(t1.[DiscountP],0) [DiscountP],isnull(t1.[Discount],0) [Discount],t1.[NetTotal],t1.[Notes],
t4.Address1,t4.Address2,t4.Address3,T4.Place,t4.Phone,t4.MobileNo,t4.Email,t4.ContactPerson,t4.[FileNo],
t4.PaymentTerms,t4.[DLNo1],t4.[DLNo2],t4.[CST],t4.[Address4],t4.[Address5],t4.[Address6],t4.[Address7],t4.[Address8],t4.[Address9],
t1.Subject ,isnull(t1.[Attention],'') [Attention],
isnull(t1.[InqRef],0) [InqRef],cast(cast(t1.[InqDate] as varchar) as datetime) [InqDate],
isnull(t4.GST,'') GST,isnull(t4.TIN,'') TIN,
S.NAME SALESMAN,t1.Address,t2.NameinOL,t1.BillTax 
from invQuotationHeader t1
join aAccount t2 on t1.CustomerId = t2.Id 
left outer join invRateLevel t3 on t1.[RateLevelId] = t3.Id
join invCustomer t4 on t1.CustomerId = t4.AccountID 
LEFT OUTER JOIN INVSALESMAN S ON T1.SALESMANID=S.ID  
where  t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[No] = @No

go

if object_id('prCheckPassword') is not null
	drop proc prCheckPassword
go	
	
create proc prCheckPassword
@Name varchar(25),
@Password varchar(20)

as
set nocount on

select * from invUser where Name = @Name and [Password] = @Password

select c.ID,c.Name from invUserCompany uc 
join invUser u on uc.UserID=u.ID 
join (select ID,Name from aCompany union all select null ID,'(Common)'Name) c on isnull(uc.CompanyID,0)=isnull(c.ID,0)
where u.Name = @Name and u.[Password] = @Password and uc.Login=1
order by (case when c.id is null then 0 end)


select c.ID,c.Name,c.CostCentreId,isnull(ac.Name,'(Common)') CostCentre from invUserCostCentre uc 
join invUser u on uc.UserID=u.ID 
join (select ID,Name,CostCentreID from invCostCentre union all select null ID,'(Common)'Name,null CostCentreID) c on isnull(uc.CostCentreID,0)=isnull(c.ID,0)
left join aCostCentre ac on c.CostCentreID=ac.Id
where u.Name = @Name and u.[Password] = @Password and uc.Login=1 
--order by (case when c.id is null then 0 end)
order by c.Id

go

if object_id('prSalesReturnDetailsPrint') is not  null
     drop proc prSalesReturnDetailsPrint

go

create proc prSalesReturnDetailsPrint  
@CompanyID int,  
@PeriodID int,  
@VtypeID int,  
@No int as  

set transaction isolation level read uncommitted  
set nocount on  
  
declare @CategoryPropertyId int  
select @CategoryPropertyId = isnull(CategoryPropertyId,0) from invOption where CompanyId = @CompanyId  
  

declare @T1 table (ProductId int,Code varchar(100))

insert @T1 select distinct t1.ProductId,t3.Code from  invSalesReturnDetails t1  
join invProductPropertyDetails t2 on t1.ProductId = t2.ProductId and t2.PropertyId = @CategoryPropertyId  
join invProductSubProperty t3 on t2.SubPropertyId = t3.Id  
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No

declare @Details table(Sno int,ProductId int,Barcode varchar(50),Code varchar(50),Particulars nvarchar(400),Packing nvarchar(800),OtherLanguage nvarchar(400)
,Warehouse varchar(50),UOMId int,Uom nvarchar(50),Qty float,Foc float,Rate float,Mrp float,Gross float,DiscountP float,Discount float,[Net Amount] float,Total float,
MfrDate smalldatetime,ExpDate smalldatetime,Remark nvarchar(100),Tax float,OutPutTax float,SerialNo varchar(100),CategoryCode varchar(50),Addition2 float,NOP float,
Addition float)

insert @Details(Sno,ProductId,Barcode,Code,Particulars,Packing,OtherLanguage,Warehouse,UOMId,Uom,Qty,Foc,Rate,Mrp,Gross,DiscountP,Discount,[Net Amount],Total,MfrDate,ExpDate,Remark,Tax,OutPutTax,SerialNo,CategoryCode,Addition2,NOP,Addition)
select t1.[Sno],t1.ProductId,isnull(t5.Barcode,'') Barcode,  
t2.Code,t2.Name Particulars,t2.Packing,t2.OtherLanguage,t3.Name Warehouse,t1.UOMId,t4.Name Uom,  
t1.[Qty],t1.[Foc],t1.[Rate],t2.Mrp,t1.[Gross],t1.[DiscountP],  
t1.[Discount],t1.Gross - t1.discount  [Net Amount],t1.[Total],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],  
cast(cast(t1.[ExpDate] as varchar) as datetime) [ExpDate] ,t1.[Remark],t1.Tax,t.OutPutTax,
isnull(sn.SerialNo,t1.SerialNo)SerialNo,t6.code CategoryCode,t1.Addition2,1,t1.Addition from invSalesReturnDetails t1  
join invProduct t2 on t1.ProductId = t2.Id   
left outer join invWarehouse t3 on t1.WarehouseId = t3.Id   
join invUom t4 on t1.UomId = t4.Id   
left outer join invAutoBarcodeAndSalesRate t5 on t1.ProductId = t5.ProductId and t1.BarcodeId = t5.BarcodeId    
left join invTaxGroup t on t1.TaxGroupID=t.ID  
left outer join invProductSerialNumber sn on t1.SerialNoId = sn.Id  
left outer join @T1 t6 on t1.ProductId = t6.ProductId
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No order by t1.Sno   

--NOP
update s set s.NOP=ul.Multiplayer from invUOM u join invUOMLevels ul on u.id=ul.UOMID join @Details s on s.ProductID=ul.ProductID and s.UOMID=ul.UnitID and ul.Secondary<>1 and ul.SNo<3

select * from @Details
  
go

alter table invJobWork alter column Name nvarchar(200)

go

if object_id('prSaveinvJobWork') is not null
	drop proc prSaveinvJobWork
go	
	
create proc prSaveinvJobWork

@Id int ,
@Code varchar(25),
@Name nvarchar(200),
@Rate float ,
@ProductId int,
@Status int output
 
as
set nocount on

if exists (select 1 from invJobWork where Id <> @Id and Code = @code )
begin
  set @Status = 2
  return
end

if exists (select 1 from invJobWork where Id <> @Id and Name = @Name)
begin
  set @Status = 3
  return
end

if @Id = 0
  begin
	  select @Id = isnull(MAX(Id),0) + 1 from invJobWork
	  insert invJobWork (Id,Code,Name,Rate,ProductId) values(@Id,@Code,@Name,nullif(@Rate,0),nullif(@ProductId,0))
  end
else
     update invJobWork set Code = @Code, Name = @Name,Rate = nullif(@Rate,0),ProductId=nullif(@ProductId,0) where Id = @Id 
  
set @Status = 1 

go 

if object_id('prExportSales') is not null drop proc prExportSales

go

create proc prExportSales
@CompanyID int,
@PeriodID int,
@VtypeID int,
@ExportNo int

as

SET NOCOUNT ON
SET XACT_ABORT ON
SET DEADLOCK_PRIORITY LOW
SET LOCK_TIMEOUT 10000

--declare @CompanyID int
declare @No int

--SET @CompanyID=1

declare @TableColumnList varchar(max),
        @ColumnList varchar(max),
        @UpdateColumnList varchar(max)
        

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)
declare @LocalDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB,@LocalDBName=LocalDatabase  from invOption where CompanyID=@CompanyID
set @RmtDBName=case when len(@LocalDBName)>0 then @LocalDBName else @RmtDBName end

if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB' Message
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Exporting to same DB is not allowable' Message
	return
End 

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0 and len(rtrim(isnull(@LocalDBName,'')))=0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+'].'

End

       
if len(rtrim(isnull(@LocalDBName,'')))>0
Begin
	set @RmtSrvName=''
	set @RmtDBO=''
End

    
--------------------   
create table #T1(No int,Message nvarchar(100))

exec('insert #T1(Message) select ''Permission Granted for User ''+u.Name+'' for Menu ''+upper(f.Name)+'' in Destination DB'' from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like''1%''')

declare @Message nvarchar(100)
select @Message=max(Message) from #T1


if @Message is not null
Begin
	select @Message Message
	return
End


exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
ExportCompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and ExportNo='+@ExportNo)
select @No=max(No) from #T1
------------------

--Begin Transaction


if(@No is null)
begin
	exec('insert #T1(No) exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.prGetSalesMaxVno '+@CompanyID+','+@PeriodID+','+@VtypeId)
	select @No=max(No) from #T1 
end
else
begin

	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete t from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction t WITH (ROWLOCK) join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@No+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID)

end	


--insertion

--aPeriod
--select @UpdateColumnList = dbo.fnGetUpdateColumnList('aPeriod','Id')
--exec('update t2 set ' + @UpdateColumnList + ' from aPeriod t1 
--      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aPeriod t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aPeriod'),
       @ColumnList = dbo.fnGetColumnList('aPeriod')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aPeriod (' + @TableColumnList + ') select ' + @ColumnList + ' from aPeriod t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aPeriod t2 on t1.Id = t2.Id where t2.Id is null')



--aAccountGroup
select @UpdateColumnList = dbo.fnGetUpdateColumnList('aAccountGroup','Id')
exec('update t2 set ' + @UpdateColumnList + ' from aAccountGroup t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aAccountGroup'),
       @ColumnList = dbo.fnGetColumnList('aAccountGroup')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup (' + @TableColumnList + ') select ' + @ColumnList + ' from aAccountGroup t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup t2 on t1.Id = t2.Id where t2.Id is null')


--aAccountType
select @UpdateColumnList = dbo.fnGetUpdateColumnList('aAccountType','Id')
exec('update t2 set ' + @UpdateColumnList + ' from aAccountType t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountType t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aAccountType'),
       @ColumnList = dbo.fnGetColumnList('aAccountType')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountType (' + @TableColumnList + ') select ' + @ColumnList + ' from aAccountType t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountType t2 on t1.Id = t2.Id where t2.Id is null')


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup(ID,Code,Name,AccountGroupID) 
      select a1.ID,a1.Code,a1.Name,a1.AccountGroupID from aAccountSubGroup a1
	  left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup a2 on a1.ID=a2.ID where a2.ID is null')


--aAccount
exec ('insert Into '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
        select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from aAccount a1
		left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID
		where a2.ID is null'
	    )

exec (' update a2 set a2.UnderAccountID=a1.UnderAccountID,a2.Name=a1.Name from aAccount a1 join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID')

--aAccount
exec ('insert Into '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
        select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from aAccount a1
		left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID
		where a2.ID is null'
	    )

--Warehouse
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invWarehouse','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invWarehouse t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invWarehouse t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invWarehouse'),
       @ColumnList = dbo.fnGetColumnList('invWarehouse')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invWarehouse (' + @TableColumnList + ') select ' + @ColumnList + ' from invWarehouse t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invWarehouse t2 on t1.Id = t2.Id where t2.Id is null')


--SalesMan 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invSalesMan','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invSalesMan t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesMan t2 on t1.Id = t2.Id')

