left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductProperty t2 on t1.Id = t2.Id where t2.Id is null')

--Purchase Property 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invPurchaseProperty','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invPurchaseProperty t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invPurchaseProperty'),
       @ColumnList = dbo.fnGetColumnList('invPurchaseProperty')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty (' + @TableColumnList + ') select ' + @ColumnList + ' from invPurchaseProperty t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty t2 on t1.Id = t2.Id where t2.Id is null')


--Product Sub Property 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invProductSubProperty','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invProductSubProperty t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductSubProperty t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invProductSubProperty'),
       @ColumnList = dbo.fnGetColumnList('invProductSubProperty')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductSubProperty (' + @TableColumnList + ') select ' + @ColumnList + ' from invProductSubProperty t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductSubProperty t2 on t1.Id = t2.Id where t2.Id is null')

--Purchase Sub Property 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invPurchaseSubProperty','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invPurchaseSubProperty t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseSubProperty t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invPurchaseSubProperty'),
       @ColumnList = dbo.fnGetColumnList('invPurchaseSubProperty')

