exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,
	   MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2) 
      select VtypeId,No,row_number()over(order by sno),ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,
      ExpDate,Remark,BarcodeId,TaxGroupId,isnull(Tax,0),Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2 from #SalesDetails')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails(VtypeId,No,Sno,ProductId,SubPropertyId,CompanyId,PeriodId) 
      select VtypeId,'+@No+',Sno,ProductId,SubPropertyId,'+@CompanyID+',PeriodId from invSalesPropertyDetails WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions(CompanyID,PeriodID,VtypeID,No,DebtorId,CreditorId,Description,Amount) 
      select '+@CompanyID+',PeriodID,VtypeID,'+@No+',DebtorId,CreditorId,Description,Amount from invSalesAdditions WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


--Transactions
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,
AccountID,CDate,CNo,SNo) 
      select '+@CompanyID+',PeriodID,Date,VoucherTypeID,'+@No+',DebtorID,CreditorID,Amount,t.Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo from aTransaction t WITH (NOLOCK) 
	  join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	  where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@ExportNo+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID
	  )


go

if object_Id('prJobInvoiceReport') is not null
	drop proc prJobInvoiceReport

go

create proc prJobInvoiceReport
@CompanyId int,
@From int,
@To int, 
@DetailPart bit,
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@GrandTotal varchar(max),
@Order varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@HeaderValueDataWhereClause varchar(max),
@HeaderMasterDataWhereClause varchar(max),
@DetailsValueDataWhereClause varchar(max),
@DetailsMasterDataWhereClause varchar(max),
@AlterTable varchar(max) as      
set nocount on        

declare @Query varchar(max),
		@WhereClause varchar(max)

create table #JobInvoiceHeader
(
[CompanyId] int,
[PeriodId] int,
[VtypeId] int,
[Voucher Type] varchar(50),
[No] int,
[Date] datetime,
[JobNo] varchar(50),
[RefNo] varchar(50),
[CostCentre] nvarchar(100),
[Customer] nvarchar(100),
[Colour] nvarchar(100),
[ModelNo] nvarchar(100),
[Staff] varchar(100),
[Total] float,
[Discount] float,
Taxable float,
Tax float,
[NetTotal] float,
[JobTotal] float,
[Advance] float,
Cash float,
Card float,
[Balance] float,
[Notes] nvarchar(500) ,
CreditCard nvarchar(100),
Material float,
EIStatus varchar(15)
)

declare @Col nvarchar(100)
select @Col = '['+VehicleNo1+'] nvarchar(100),'+'['+VehicleNo2+'] nvarchar(100)' from invJobCustomization
exec ('alter table #JobInvoiceHeader add '+ @Col)



if len(@HeaderValueDataWhereClause) > 0 and LEN(@HeaderMasterDataWhereClause) > 0 
  set @WhereClause = @HeaderValueDataWhereClause + ' and ' + @HeaderMasterDataWhereClause + ' and '
else if len(@HeaderValueDataWhereClause) > 0 
  set @WhereClause = @HeaderValueDataWhereClause + ' and '
else if LEN(@HeaderMasterDataWhereClause) > 0 
  set @WhereClause = @HeaderMasterDataWhereClause + ' and '
else 
  set @WhereClause = ''  


exec('insert #JobInvoiceHeader select t1.CompanyId,t1.PeriodId,t1.VtypeId,t3.Name,t1.[No],cast(cast(t1.[Date] as  varchar) as datetime) ,
t2.JobNo,t1.RefNo,
t4.Name,t2.Customer,t2.Colour,t2.ModelNo,t6.name,
t1.[Amount] + t1.[Discount] - isnull(t1.Tax,0),t1.[Discount],t1.[Amount] - isnull(t1.Tax,0),t1.Tax,t1.[Amount],t1.JobTotal,
t2.Advance,t1.Cash,t1.Card,t1.JobTotal - isnull(t1.Cash,0)- isnull(t1.Card,0) - isnull(t2.Advance,0) ,t1.[Notes] ,t5.name,t7.NetTotal,
case t1.EInvoice when 1 then ''CLEARED'' when 2 then ''NOT_CLEARED'' when 3 then ''REPORTED'' when 4 then ''NOT_REPORTED'' end,
t2.VehicleNo,t2.VehicleNo2
from invJobInvoice t1
join invJobForm t2 on t1.JobId = t2.Id 
join invVoucherTypeDetails t3 on t1.VtypeId = t3.Id 
left outer join invCostCentre t4 on t2.CostCentreId = t4.id
left outer join aCreditCard t5 on t1.CreditCardId = t5.Id
left outer join invSalesMan t6 on t1.SalesManId = t6.Id
left join invSalesHeader t7 on t1.JobId=t7.JobId
where ' + @WhereClause + ' t1.CompanyId = ' + @CompanyId + ' and t1.Date between ' + @From + ' and ' + @To)


if @DetailPart = 1
begin
	create table #JobInvoiceDetails
	(
        [CompanyId1] int,
        [PeriodId1] int,
        [VtypeId1] int ,
		[No1] int ,
		[Sno] int ,
		[Code] varchar(50),
		[Particulars] nvarchar(100) ,
        [Employee] nvarchar(100) ,
		[Qty] float ,
		[Rate] float ,
		[Amount] float 
	)
	
		
		
		if len(@DetailsValueDataWhereClause) > 0 and LEN(@DetailsMasterDataWhereClause) > 0 
		  set @WhereClause = @DetailsValueDataWhereClause + ' and ' + @DetailsMasterDataWhereClause + ' and '
		else if len(@DetailsValueDataWhereClause) > 0 
		  set @WhereClause = @DetailsValueDataWhereClause + ' and '
		else if LEN(@DetailsMasterDataWhereClause) > 0 
		  set @WhereClause = @DetailsMasterDataWhereClause + ' and '
		else 
		  set @WhereClause = ''  

		exec('insert #JobInvoiceDetails select t1.CompanyId,t1.PeriodId,t1.[VtypeId],t1.[No],t1.[Sno],t2.[Code],t2.Name Particulars,t4.name,
		t1.[Qty],t1.[Rate],t1.[Amount] from invJobInvoiceDetails t1
		join invJobWork t2 on t1.WorkId = t2.Id 
        left outer join aAccount t4 on t1.EmployeeId = t4.Id
		join invJobInvoice t3 on t1.CompanyId = t3.CompanyId and t1.PeriodId = t3.PeriodId and t1.VtypeId = t3.VtypeId and t1.No = t3.No 
		where ' + @WhereClause + ' t1.CompanyId = ' + @CompanyId + ' and t3.Date between ' + @From + ' and ' + @To)
			
	end


if @Group = 0
	begin  
		if @DetailPart = 0
			begin    
				if @GroupTotal = 0        
					exec('select ' + @columns + ' from #JobInvoiceHeader ' + @order)
				else
					begin
						if len(@order) > 0
							begin 
								set @Query = 'select ' + @columns +  ' from (select 0 row_id,' + @columns + ' from #JobInvoiceHeader union all select 1 row_id, ' + @GrandTotal + ' from #JobInvoiceHeader ) p ' + replace(@order,'order by','order by row_id,')
								exec(@Query)
							end 
						else
							exec('select ' + @columns + ' from #JobInvoiceHeader union all select ' + @GrandTotal + ' from #JobInvoiceHeader ' )
					end          
			end
		else
			begin
				if @GroupTotal = 0        
					exec('select ' + @columns +  ' from #JobInvoiceHeader T1 JOIN #JobInvoiceDetails T2 ON t1.CompanyId = t2.CompanyId1 and t1.PeriodId = t2.PeriodId1 and T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 ' +  @order)
				else
					begin
						if len(@order) > 0
							begin
								set @Query = 'select ' + @columns + ' from(select 0 row_id,' + @columns +  ' from #JobInvoiceHeader T1 JOIN #JobInvoiceDetails T2 ON t1.CompanyId = t2.CompanyId1 and t1.PeriodId = t2.PeriodId1 and T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 union all select 1 row_id,' + @GrandTotal +  ' from #JobInvoiceHeader T1 JOIN #JobInvoiceDetails T2 ON t1.CompanyId = t2.CompanyId1 and t1.PeriodId = t2.PeriodId1 and T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 ) p '  + replace(@order,'order by','order by row_id,')
								exec(@Query)
							end	
						else		
							exec('select ' + @columns +  ' from #JobInvoiceHeader T1 JOIN #JobInvoiceDetails T2 ON t1.CompanyId = t2.CompanyId1 and t1.PeriodId = t2.PeriodId1 and T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 union all select ' + @GrandTotal +  ' from #JobInvoiceHeader T1 JOIN #JobInvoiceDetails T2 ON t1.CompanyId = t2.CompanyId1 and t1.PeriodId = t2.PeriodId1 and T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 ' )  
					end
			end
	end
else
	begin
		create table #JobInvoiceGroup(rid numeric identity(1,1))
		exec(@AlterTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #JobInvoiceGroup
end

