create proc prSaveJob
@CompanyId int,
@PeriodId int,
@No int,
@Date int,
@JobNo varchar(50),
@Customer nvarchar(100),
@VehicleNo nvarchar(50),
@Amount float,
@Work nvarchar(max),
@AdditionalWork nvarchar(max),
@DDate int,
@Time int,
@CostCentreId int,
@ContactNo varchar(50),
@VehicleNo2 nvarchar(50),
@Status int,
@FinishedDate int,
@ModelNo nvarchar(50),
@Colour nvarchar(50),
@SalesManID int,
@XmlCL xml,
@Advance float,
@Cash float,
@Card float,
@CreditCardID int,
@Year varchar(50),
@JobCustomerId int,
@Remark nvarchar(100)

as

set nocount on

declare @Id int

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetJobMaxVno
    @CompanyId = @CompanyId,
    @PeriodId = @PeriodId

    select @No = [No] from @T1 
    
    select @Id = isnull(max(id),0) + 1 from invJobForm

    insert invJobForm(ID,CompanyID,PeriodID,No,Date,JobNo,Customer,VehicleNo,Amount,Work,AdditionalWork,DDate,Time,
    CostCentreId,ContactNo,VehicleNo2,Status,FinishedDate,ModelNo,Colour,SalesManID,Advance,Cash,Card,CreditCardID,
    [Year],[CustomerId],Remark)
    values(@Id,@CompanyID,@PeriodID,@No,@Date,@JobNo,@Customer,@VehicleNo,@Amount,@Work,@AdditionalWork,@DDate,@Time,
    nullif(@CostCentreId,0),@ContactNo,@VehicleNo2,@Status,@FinishedDate,nullif(@ModelNo,''),nullif(@Colour,''),nullif(@SalesManID,0),
    nullif(@Advance,0),nullif(@Cash,0),nullif(@Card,0),nullif(@CreditCardID,0),nullif(@Year,''),nullif(@JobCustomerId,0),nullif(@Remark,''))
	
  end
else
   begin

	update invJobForm
               set Date = @Date,
				JobNo = @JobNo,
				Customer = @Customer,
				VehicleNo = @VehicleNo,
				Amount = @Amount,
				Work = @Work,
				AdditionalWork = @AdditionalWork,
				DDate = @DDate,
				Time = @Time	,
				CostCentreId = nullif(@CostCentreId,0),
				ContactNo = @ContactNo,
				VehicleNo2 = @VehicleNo2,
				Status = @Status,
				FinishedDate = @FinishedDate,
				ModelNo = nullif(@ModelNo,''),
				Colour = nullif(@Colour,''),
				SalesManID=nullif(@SalesManID,0),
				Advance = nullif(@Advance,0),
				CreditCardID = nullif(@CreditCardID,0),
				CustomerId = nullif(@JobCustomerId,0),
				Year = nullif(@Year,''),
				Remark=nullif(@Remark,'')
				where CompanyId = @CompanyId and PeriodId = @PeriodId and No = @No

        select @Id = Id from invJobForm where CompanyId = @CompanyId and PeriodId = @PeriodId and No = @No
        update invSalesHeader set AirWayBillNo = @JobNo where JobId = @Id

    end	

--Account Posting
declare @VoucherTypeID int
select @VoucherTypeID = AccountVtypeId from invVoucherTypeDetails where VTypeId = 14

delete aTransaction where ModuleID = 1 and CompanyId = @CompanyId and PeriodId = @PeriodId and VoucherTypeID = @VoucherTypeID and No = @No

if @VoucherTypeID is not null and @Advance > 0 
begin 

	declare @Code nvarchar(50),@Name nvarchar(100),@CustomerId int
	select @Code = 'Job '+ @JobNo,@Name=@Customer 
    
    if @JobCustomerId > 0 
       set @CustomerId = @JobCustomerId
    else
	   select @CustomerId=ID from aAccount where Code=@Code

	if isnull(@CustomerId,0) = 0
	Begin
		--Insertion to account
		declare @t table(ID int,Status tinyint,Message varchar(100))

		declare @UnderID int
		select @UnderID=Customers from aAccountSettings

		declare @AccountSubGroupID int
		select @AccountSubGroupID=AccountSubGroupID from aAccount where ID=@UnderID

		insert @t 
		exec spSaveAccount @ID= 0,@Code=@Code,@Name=@Name,@AccountSubGroupID=@AccountSubGroupID,
		@UnderAccountID=@UnderID,@OB=null,@DrCr=null,@CompanyID=1,
		@ModuleID=1,@IsAllowDuplicateName=1

		select @CustomerId = ID from @t where Status=0

		delete invCustomer where AccountId = @CustomerId
		insert invCustomer (CompanyId,AccountId,Name) select @CompanyId,@CustomerId,@Name where isnull(@CustomerId,0) > 0

	End

	
	update invJobForm set CustomerId = nullif(@CustomerId,0) where Id = @Id

	if @Cash>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardId)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CashInHand,@CustomerId,@Cash,'Job Advance(Cash)-' + @JobNo,nullif(@CreditCardID,0) from aAccountSettings where CompanyID=@CompanyID
	
	if @Card>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardId)
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,CreditCard,@CustomerId,@Card,'Job Advance(Card)-' + @JobNo,nullif(@CreditCardID,0) from aAccountSettings where CompanyID=@CompanyID

	
end 

  	
--Check List

delete invJobCheckList where JobID=@ID

declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlCL
	
insert invJobCheckList
(JobID,CheckListID)
select @ID,ID
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID    int '@ID',
CHK   bit '@CHK'
)

where CHK=1

exec sp_xml_removedocument @Idoc


select @No

go

if OBJECT_ID('prGetJob') is not null
