go

create proc prGetJob
@CompanyId int,
@PeriodId int,
@No int as
set nocount on

declare @ID int

select @ID=ID from invJobForm where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No 

select t1.[ID],t1.[No],t1.[Date],t1.[JobNo],isnull(t2.Name,t1.[Customer]) Customer,t1.[VehicleNo],t1.[Amount],
t1.[Work],t1.[AdditionalWork],t1.[DDate],t1.[Time],t1.[CostCentreId],t1.[ContactNo],t1.[VehicleNo2],t1.[Status],
t1.[FinishedDate],t1.[ModelNo],t1.[Colour],t1.[SalesManID],t1.[FinishTime],t1.[Advance],t1.Cash,t1.Card,
t1.[CreditCardID],t1.[CustomerId],t1.[Year],t1.[ModelName],t1.Remark from invJobForm t1 
left outer join aAccount t2 on t1.CustomerId = t2.Id
where t1.ID = @ID
 
select cast(case when j.JobID is not null then 1 end as bit)CHK,c.ID,c.Name from invCheckList c 
left join invJobCheckList j on c.ID=j.CheckListID and j.JobID=@ID

go

if OBJECT_ID('spGetInvJobHeader') is not null
  drop proc spGetInvJobHeader
  
  go
    
create proc spGetInvJobHeader    
@CompanyID int,    
@PeriodID int,    
@No int    
as    

set nocount on 

select s.ID,s.Customer,s.No,s.JobNo,cast(cast(s.Date as varchar)as smalldatetime)Date,s.Amount,s.Work,    
cast(cast(DDate as varchar)as smalldatetime)DeliveryDate,s.ContactNo,co.Name Company,s.Colour,s.ModelNo,s.VehicleNo,s.VehicleNo2,
s.Advance,s.Cash,s.Card,s.Time,s.Year,sm.Name Salesman,s.AdditionalWork,c.Address1,c.Address2,c.Address3,c.Address4,c.Address5,c.Address5,c.Address6,c.Address7,c.Address8,c.Address9,s.Remark from invJobForm s    
join aCompany co on s.CompanyID=co.ID
left join invSalesman sm on s.SalesmanId=sm.Id
left join invCustomer c on s.CustomerId=c.AccountID
where s.CompanyID=@CompanyID and s.PeriodID=@PeriodID and s.No=@No    
    
go

if object_id('prExportSales') is not null drop proc prExportSales

go

create proc prExportSales
@CompanyID int,
@PeriodID int,
@VtypeID int,
@ExportNo int

as

SET NOCOUNT ON
SET XACT_ABORT ON
SET DEADLOCK_PRIORITY LOW
SET LOCK_TIMEOUT 10000

--declare @CompanyID int
declare @No int

--SET @CompanyID=1

declare @TableColumnList varchar(max),
        @ColumnList varchar(max),
        @UpdateColumnList varchar(max)
        

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)
declare @LocalDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB,@LocalDBName=LocalDatabase  from invOption where CompanyID=@CompanyID
set @RmtDBName=case when len(@LocalDBName)>0 then @LocalDBName else @RmtDBName end

if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB' Message
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Exporting to same DB is not allowable' Message
	return
End 

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0 and len(rtrim(isnull(@LocalDBName,'')))=0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+'].'

End

       
if len(rtrim(isnull(@LocalDBName,'')))>0
Begin
	set @RmtSrvName=''
	set @RmtDBO=''
End

    
--------------------   
create table #T1(No int,Message nvarchar(100))

exec('insert #T1(Message) select ''Permission Granted for User ''+u.Name+'' for Menu ''+upper(f.Name)+'' in Destination DB'' from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like''1%''')

declare @Message nvarchar(100)
select @Message=max(Message) from #T1


if @Message is not null
Begin
	select @Message Message
	return
End


exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
ExportCompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and ExportNo='+@ExportNo)
select @No=max(No) from #T1
------------------

--Begin Transaction


if(@No is null)
begin
	exec('insert #T1(No) exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.prGetSalesMaxVno '+@CompanyID+','+@PeriodID+','+@VtypeId)
	select @No=max(No) from #T1 
end
else
begin

	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete t from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction t WITH (ROWLOCK) join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@No+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID)

end	


--insertion

--aPeriod
--select @UpdateColumnList = dbo.fnGetUpdateColumnList('aPeriod','Id')
--exec('update t2 set ' + @UpdateColumnList + ' from aPeriod t1 
--      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aPeriod t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aPeriod'),
       @ColumnList = dbo.fnGetColumnList('aPeriod')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aPeriod (' + @TableColumnList + ') select ' + @ColumnList + ' from aPeriod t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aPeriod t2 on t1.Id = t2.Id where t2.Id is null')



--aAccountGroup
select @UpdateColumnList = dbo.fnGetUpdateColumnList('aAccountGroup','Id')
exec('update t2 set ' + @UpdateColumnList + ' from aAccountGroup t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aAccountGroup'),
       @ColumnList = dbo.fnGetColumnList('aAccountGroup')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup (' + @TableColumnList + ') select ' + @ColumnList + ' from aAccountGroup t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup t2 on t1.Id = t2.Id where t2.Id is null')


--aAccountType
select @UpdateColumnList = dbo.fnGetUpdateColumnList('aAccountType','Id')
exec('update t2 set ' + @UpdateColumnList + ' from aAccountType t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountType t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('aAccountType'),
       @ColumnList = dbo.fnGetColumnList('aAccountType')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountType (' + @TableColumnList + ') select ' + @ColumnList + ' from aAccountType t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountType t2 on t1.Id = t2.Id where t2.Id is null')


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup(ID,Code,Name,AccountGroupID) 
      select a1.ID,a1.Code,a1.Name,a1.AccountGroupID from aAccountSubGroup a1
	  left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup a2 on a1.ID=a2.ID where a2.ID is null')


--aAccount
exec ('insert Into '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
        select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from aAccount a1
		left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID
		where a2.ID is null'
	    )

exec (' update a2 set a2.UnderAccountID=a1.UnderAccountID,a2.Name=a1.Name from aAccount a1 join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID')

--aAccount
exec ('insert Into '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
        select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from aAccount a1
		left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID
		where a2.ID is null'
	    )

--Warehouse
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invWarehouse','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invWarehouse t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invWarehouse t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invWarehouse'),
       @ColumnList = dbo.fnGetColumnList('invWarehouse')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invWarehouse (' + @TableColumnList + ') select ' + @ColumnList + ' from invWarehouse t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invWarehouse t2 on t1.Id = t2.Id where t2.Id is null')


--SalesMan 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invSalesMan','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invSalesMan t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesMan t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invSalesMan'),
       @ColumnList = dbo.fnGetColumnList('invSalesMan')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesMan (' + @TableColumnList + ') select ' + @ColumnList + ' from invSalesMan t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesMan t2 on t1.Id = t2.Id where t2.Id is null')


--Vendor & Customer 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('aAccount','Id')
exec('update t2 set ' + @UpdateColumnList + ' from aAccount t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount t2 on t1.Id = t2.Id')

--Customer
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invCustomer','AccountId')
exec('update t2 set  ' + @UpdateColumnList + '	from invCustomer t1 WITH (NOLOCK) 
join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invCustomer t2 WITH (NOLOCK) on t1.AccountId = t2.AccountId')


select @TableColumnList = dbo.fnGetTableColumnList('aAccount'),
       @ColumnList = dbo.fnGetColumnList('aAccount')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount (' + @TableColumnList + ') select ' + @ColumnList + ' from aAccount t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aAccount t2 on t1.Id = t2.Id where t2.Id is null')


--Vendor
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invVendor','AccountId')
exec('update t2 set  ' + @UpdateColumnList + '	from invVendor t1 WITH (NOLOCK) 
join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVendor t2 on t1.AccountId = t2.AccountId')

select @TableColumnList = dbo.fnGetTableColumnList('invVendor'),
       @ColumnList = dbo.fnGetColumnList('invVendor')
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVendor (' + @TableColumnList + ') select ' + @ColumnList + ' from invVendor t1 WITH (NOLOCK) 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVendor t2 WITH (NOLOCK) on t1.AccountId = t2.AccountId where t2.AccountId is null')


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invCustomer(Name,Address1,Address2,Address3,Phone,MobileNo,Email,Web,Fax,ContactPerson,
	CreditLimit,DueDays,CurrencyId,RateLevelId,SalesManId,PaymentTerms,Remark,AccountID,FileNo,Place,TIN,CST,DLNo1,DLNo2,GST,Inactive,CompanyID) 
      select p1.Name,p1.Address1,p1.Address2,p1.Address3,p1.Phone,p1.MobileNo,p1.Email,p1.Web,p1.Fax,p1.ContactPerson,
      p1.CreditLimit,p1.DueDays,p1.CurrencyId,p1.RateLevelId,p1.SalesManId,p1.PaymentTerms,p1.Remark,p1.AccountID,p1.FileNo,
      p1.Place,p1.TIN,p1.CST,p1.DLNo1,p1.DLNo2,p1.GST,p1.Inactive,'+@CompanyID+' from invCustomer p1 WITH (NOLOCK)
	  left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invCustomer p2 WITH (NOLOCK) on p1.AccountID=p2.AccountID where p2.AccountID is null')

exec ('update a2 set a2.Name=a1.Name from invCustomer a1 WITH (NOLOCK) join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invCustomer a2 on a1.AccountID=a2.AccountID')

--Tax Group
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invTaxGroup(Id,Code,Name,InputTax,OutputTax,PurchaseValueTitle,PurchaseTaxTitle,SalesValueTitle,SalesTaxTitle,Addition) 
      select p1.Id,p1.Code,p1.Name,p1.InputTax,p1.OutputTax,p1.PurchaseValueTitle,p1.PurchaseTaxTitle,p1.SalesValueTitle,p1.SalesTaxTitle,p1.Addition from invTaxGroup p1
	  left join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invTaxGroup p2 on p1.ID=p2.ID where p2.ID is null')

exec('update t2 set t2.Addition=t1.Addition from invTaxGroup t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invTaxGroup t2 on t1.Id = t2.Id')


--Product Property 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invProductProperty','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invProductProperty t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductProperty t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invProductProperty'),
       @ColumnList = dbo.fnGetColumnList('invProductProperty')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductProperty (' + @TableColumnList + ') select ' + @ColumnList + ' from invProductProperty t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProductProperty t2 on t1.Id = t2.Id where t2.Id is null')

--Purchase Property 
select @UpdateColumnList = dbo.fnGetUpdateColumnList('invPurchaseProperty','Id')
exec('update t2 set ' + @UpdateColumnList + ' from invPurchaseProperty t1 
      join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty t2 on t1.Id = t2.Id')

select @TableColumnList = dbo.fnGetTableColumnList('invPurchaseProperty'),
       @ColumnList = dbo.fnGetColumnList('invPurchaseProperty')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty (' + @TableColumnList + ') select ' + @ColumnList + ' from invPurchaseProperty t1 
left outer join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty t2 on t1.Id = t2.Id where t2.Id is null')


--Product Sub Property 
