exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,
	   MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2) 
      select VtypeId,No,row_number()over(order by sno),ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,
      ExpDate,Remark,BarcodeId,TaxGroupId,isnull(Tax,0),Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2 from #SalesDetails')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails(VtypeId,No,Sno,ProductId,SubPropertyId,CompanyId,PeriodId) 
      select VtypeId,'+@No+',Sno,ProductId,SubPropertyId,'+@CompanyID+',PeriodId from invSalesPropertyDetails WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions(CompanyID,PeriodID,VtypeID,No,DebtorId,CreditorId,Description,Amount) 
      select '+@CompanyID+',PeriodID,VtypeID,'+@No+',DebtorId,CreditorId,Description,Amount from invSalesAdditions WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


--Transactions
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,
AccountID,CDate,CNo,SNo) 
      select '+@CompanyID+',PeriodID,Date,VoucherTypeID,'+@No+',DebtorID,CreditorID,Amount,t.Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo from aTransaction t WITH (NOLOCK) 
	  join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	  where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@ExportNo+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID
	  )


go

if object_id('prGetActiveProductForSales') is not null
	drop proc prGetActiveProductForSales
go	
   
create proc prGetActiveProductForSales 
@UserId int,
@CompanyID int=1,
@CostCentreId int=null,
@CustomerId int=null

as  

set nocount on  
set transaction isolation level read uncommitted

declare @StockCostCentreId int
set @StockCostCentreId=@CostCentreId

if exists(select 1 from invOption where CompanyId=@CompanyID and CostCentreIndependentProducts=1)
	set @CostCentreId=0


create table #Product
(
[ ] bit not null default 0,
Id int,
Code varchar(50),
Name nvarchar(200),
Barcode varchar(50),
NativeCaption nvarchar(200),
CCode varchar(50),
CategoryID int,
AutoEntry bit,
TaxGroupId int,
SRate float,
NRate float,
WRate float,
MRP float,
PRate float,
Cost float,
TaxGroup varchar(50),
Tax float,
HStock varchar(50),
Stock float,
NonStock bit,
TaxInclusive bit,
AdditionP float,
HaveSerialNo bit,
CostCentreId int,
TAddition float,
Name1 nvarchar(200),
FOC float
)

insert #Product(Id,Code,Name,NativeCaption,AutoEntry,TaxGroupId,SRate,WRate,MRP,NonStock,TaxInclusive,AdditionP,HaveSerialNo,CostCentreId,Name1)
select Id,Code,Name,OtherLanguage,AutoEntry,TaxGroupId,Rate,WRate,MRP,NonStockItem,TaxInclusive,AdditionP,SerialNo,CostCentreId,replace(Name,'*','') from invProduct where (Inactive is null or Inactive = 0)



--Cost Centre Filtering
declare @CC table(Id int)

if isnull(@CostCentreId,0)=0
	insert @CC
	select isnull(CostCentreId,0) from invUserCostCentre where Product=1 and UserId=@UserID

if exists(select top 1 1 from invProduct where CostCentreId=@CostCentreId)
	insert @CC values(@CostCentreId)

if exists(select 1 from @CC)
	delete p from #Product p left join @CC c on isnull(p.CostCentreId,0)=c.Id where c.Id is null
-------

--Barcode
update p set p.Barcode=u.Barcode from #Product p join invUOMLevels u on p.ID=u.ProductID and u.SNo=1

create table #CostStock(ProductID int,Cost float,Stock float)

declare @StockItemsOnly bit
select @StockItemsOnly=SalesStockItemsOnly from invOption where CompanyID=@CompanyID

if exists(select 1 from invOption where (SalesStockItemsOnly=1 or SalesDisplayStock=1) and isnull(SalesCostwiseStock,0)=0 and CompanyID=@CompanyID)--Stock
Begin
	declare @PurchaseProperty bit
	--select top 1 @PurchaseProperty = 1 from invPurchaseSubProperty
	select @PurchaseProperty=SalesProperty from invProjectSettings where CompanyId=@CompanyID

	create table #PStock (CompanyID int,ProductID int,PurchaseSubPropertyID int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float) 
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct
		
	if @PurchaseProperty=1
	Begin
		insert #PStock(ProductID,PurchaseSubPropertyID,Qty) 
		exec spPurchasePropertyStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=0
		update #Product set Cost=0
	End
		
	Else
	Begin
		insert #PStock(CompanyID,ProductID,Rate,CP,SRate,WRate,MRP,Qty,Pieces) 
		exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=1,@CostCentreId=@StockCostCentreId

		if exists(select 1 from invOption where TaxOption=2 and CompanyID=@CompanyID)
			update p set p.PRate=s.Rate,p.Cost=s.CP,p.Stock=s.Qty from #Product p join #PStock s on p.ID=s.ProductID and round(s.Qty,2)<>0
		else
			update p set p.Cost=s.CP,p.Stock=s.Qty from #Product p join #PStock s on p.ID=s.ProductID and round(s.Qty,2)<>0

		if @StockItemsOnly=1
			delete #Product where (Stock<=0 or Stock is null) and (NonStock=0 or NonStock is null)
	
	End
	
End
Else if exists(select 1 from invOption where CompanyId=@CompanyId and SalesCostwiseStock=1)
Begin
	create table #DateCostStock(ProductID int,Date int,Cost float,Stock float)
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct 
	insert #DateCostStock(ProductID,Date,Cost,Stock)
	exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=16

	--Stock Adjustment
	create table #SA(ProductID int,Date int,Cost float,Stock float)
	insert #SA
	select ProductId,Date,Cost,Stock from
	(select row_number()over(partition by ProductId order by date desc)Sno,d.ProductId,h.Date,d.Cost,d.PhysicalStock Stock from invStockAdjustmentDetails d join invStockAdjustmentHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
	 where d.Cost>0
	 )sa where sa.Sno=1

	 delete c from #DateCostStock c join #SA s on c.ProductID=s.ProductId and c.Date<=s.Date

	 --update c set c.Stock=s.Stock from #DateCostStock c join #SA s on c.ProductID=s.ProductId and c.Date=s.Date
	 insert #DateCostStock
	 select s.ProductId,s.Date,s.Cost,s.Stock from #SA s --left join #DateCostStock d on s.ProductID=d.ProductID and d.Stock>0 where d.Date is null

	 --create table #CostStock(ProductID int,Cost float,Stock float)
	 insert #CostStock
	 select ProductId,round(Cost,2),sum(Stock) from #DateCostStock group by ProductId,round(Cost,2)
	 ---------------
	 
	 if @StockItemsOnly=1
		delete #CostStock where isnull(Stock,0)<=0
	
End

if exists(select 1 from invUser where ID=@UserID and CostDisplay=1) 
	 or exists(select 1 from invOption where CompanyID=@CompanyID and SalesDisplayCP=1)
Begin
	declare @CP table(ProductID int,CP float)

	insert tmpTable(ID,SPID) select ID,@@SPID from #Product where Cost is null or Cost=0
	insert @CP(ProductID,CP)
	exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=13
	
	update p set p.Cost=s.CP from #Product p join @CP s on p.ID=s.ProductID and round(s.CP,2)<>0 where p.Cost is null or p.Cost=0
End


--Aliases
insert #Product(Id,Code,Name,NativeCaption,AutoEntry,TaxGroupId,SRate,WRate,MRP,Cost,Name1)
select Id,Code,a.Alias,NativeCaption,AutoEntry,TaxGroupId,SRate,WRate,MRP,Cost,replace(a.Alias,'*','') from #Product p join invProductAlias a on p.ID=a.ProductID

declare @SalesRate int
select @SalesRate=SalesRate from invOption where CompanyID=@CompanyID

if (@SalesRate=1 or @SalesRate=2 or @SalesRate=4)--Last/Customer Last/Last Over Customer Last
Begin
	
	--SRate 
	create table #SRate(Date int,ProductID int,SRate float,WRate float,MRP float)

	insert #SRate(Date,ProductID,SRate,WRate,MRP)
	select Date,ProductID,SRate,WRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate,WRate,MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1

	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate,MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1


	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by pd.Date desc)sno,pd.Date,ProductID,SRate,MRP from invProductionHeader pd
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1


	if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
		insert #SRate(Date,ProductID,SRate)
		select Date,ProductID,SRate from
		(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where pd.CompanyID=@CompanyID and (SRate>0)
		)a where sno=1


	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SalesRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SalesRate,MRP from invOpeningStock pd
	join invOpeningStockHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SalesRate>0 or MRP>0)
	)a where sno=1

	if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
		insert #SRate(Date,ProductID,SRate)
		select Date,ProductID,SRate from
		(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where ph.CompanyTo=1 and (SRate>0)
		)a where sno=1
	
	

	insert #SRate(Date,ProductID,SRate)
	select Date,ProductID,SRate from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invGoodsReceiptDetails pd
	join invGoodsReceiptHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0)
	)a where sno=1

	

	insert #SRate(Date,ProductID,SRate,WRate,MRP)
	select Date,ProductID,Rate,WRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.FromDate desc)sno,ph.FromDate Date,ProductID,Rate,WRate,MRP from invQtyRateSettingsDetails pd
	join invQtyRateSettingsHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (Rate>0 or MRP>0) and ToDate is null and Type=3
	)a where sno=1
	
	

	--Updation
	;with r as
	(select * from 
	(select ROW_NUMBER() over (partition by ProductID order by Date desc)Sno,ProductID,SRate,WRate,MRP from #SRate)a where sno=1
	)

	update p set p.SRate=r.SRate,p.WRate=r.WRate,p.MRP=r.MRP from #Product p join r on p.Id = r.ProductID
	
	if (@SalesRate=2 and @CustomerId>0)--Customer Last Rate
	Begin
		create table #CLR(ProductId int,Rate float,MRP float unique clustered (ProductId))
		insert #CLR
		select ProductId,Rate,MRP from 
		(select ROW_NUMBER() over (partition by ProductID order by Date desc)Sno,ProductID,Rate,MRP from invSalesDetails sd
		 join invSalesHeader sh on sd.CompanyId=sh.CompanyId and sd.PeriodId=sh.PeriodId and sd.VtypeId=sh.VtypeId and sd.No=sh.No
		 where sh.CustomerId=@CustomerId
		)a where sno=1
		
		update p set p.SRate=r.Rate,p.MRP=r.MRP from #Product p join #CLR r on p.Id = r.ProductID
	End
End


--Updation
if exists(select 1 from invOption where SalesRate=0 and CompanyID=@CompanyID)--Zero Sales Rate
	update p set p.SRate=0,p.MRP=0,p.WRate=0 from #Product p 
	

----------------------
--TaxGroup
update p set p.TaxGroup=t.Name,p.Tax=t.OutputTax,p.TAddition=t.Addition from #Product p join invTaxGroup t on p.TaxGroupID = t.ID
----

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption where CompanyID=@CompanyID

if @@CatPropID is not null
	update p set p.CCode=sp.Code,p.CategoryID=pp.SubpropertyID from #Product p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

-------------------

--Stock CP,Qty
if exists(select top 1 1 from invSalesColumnCustomization where HQty=1 and HRate=1)
	update t set t.HStock=cast(floor(t.Stock/u.MultiPlayer) as varchar)+'.'+cast((t.Stock/u.MultiPlayer-floor(t.Stock/u.MultiPlayer))*u.MultiPlayer as varchar) from #Product t join invProduct p on p.Id=t.Id join invUOMLevels u on t.Id=u.ProductId and p.StockUom=u.UomId


--Qtywise Rate Settings
declare @Date int
select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)

update p set p.SRate=s.Rate from invQtyRateSettingsDetails s 
join #Product p on s.ProductId=p.Id 
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null
and @Time between h.FromTime and h.ToTime
and s.Rate<>0


--Qtywise FOC Settings
update p set p.FOC=s.FOC from invQtyRateSettingsDetails s 
join #Product p on s.ProductId=p.Id 
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null and s.Pieces is null
and @Time between h.FromTime and h.ToTime
and h.Type=5


--NRate
if exists(select 1 from invSalesColumnCustomization where NRate=1)
and not exists(select 1 from invOption where TaxOption=1 and CompanyId=@CompanyId)--Tax Inclusive
	update #Product set NRate=SRate*(100.0+Tax)/100.0

if exists(select top 1 1 from invOption where DefaultSearchInSales=2 and CompanyID=@CompanyId)
begin
	select p.*,s.Name collate database_default+' '+p.Name collate database_default Property from #Product p 
	join invProductPropertyDetails pd on p.ID=pd.ProductID
	join invProductSubProperty s on pd.SubPropertyID  =s.ID 
	order by p.Name
	return
end
Else if exists(select top 1 1 from invOption where DefaultSearchInSales=3 and CompanyId=@CompanyId)
Begin
	if @PurchaseProperty=1
	Begin
		declare @PStock table(ProductId int,SubPropertyId1 int,SubPropertyId2 int,Qty float)

		insert @PStock(ProductId,SubPropertyId1,Qty)
		select ProductId,PurchaseSubPropertyID,Qty from #PStock s left join invPurchaseSubProperty p on s.PurchaseSubPropertyID=p.Id where p.PropertyId=1 or p.PropertyId is null

		update ps set ps.SubPropertyId2=s.PurchaseSubPropertyID from @PStock ps join #PStock s on ps.ProductId=s.ProductId and s.Qty=ps.Qty left join invPurchaseSubProperty p on s.PurchaseSubPropertyID=p.Id where p.PropertyId=2

		if @StockItemsOnly=1
			select p.[ ],p.Code +'       '+ p.Name [Code + Name],p.Id, s.SubPropertyID1 PurchaseSubPropertyID1,sp1.Name PurchaseProperty1,s.SubPropertyID2 PurchaseSubPropertyID2,sp2.Name PurchaseProperty2,p.Code,p.Name,p.NativeCaption,p.CCode,p.CategoryID,p.AutoEntry,p.TaxGroupId,p.SRate,p.MRP,p.Cost,p.TaxGroup,p.Tax,s.Qty Stock,p.NonStock,p.TaxInclusive,p.HaveSerialNo,p.AdditionP,p.TAddition,p.FOC from @PStock s
			left join invPurchaseSubProperty sp1 on s.SubPropertyID1=sp1.ID
			left join invPurchaseSubProperty sp2 on s.SubPropertyID2=sp2.ID
			join #Product p on s.ProductID=p.ID
			where (s.Qty<>0 or p.NonStock=1)
		Else
			select p.[ ],p.Code +'       '+ p.Name [Code + Name],p.Id, s.SubPropertyID1 PurchaseSubPropertyID1,sp1.Name PurchaseProperty1,s.SubPropertyID2 PurchaseSubPropertyID2,sp2.Name PurchaseProperty2,p.Code,p.Name,p.NativeCaption,p.CCode,p.CategoryID,p.AutoEntry,p.TaxGroupId,p.SRate,p.MRP,p.Cost,p.TaxGroup,p.Tax,s.Qty Stock,p.NonStock,p.TaxInclusive,p.HaveSerialNo,p.AdditionP,p.TAddition,p.FOC from #Product p
			left join @PStock s on p.ID=s.ProductID
			left join invPurchaseSubProperty sp1 on s.SubPropertyID1=sp1.ID
			left join invPurchaseSubProperty sp2 on s.SubPropertyID2=sp2.ID
					
	End
	Else if exists(select top 1 1 from #CostStock)
	Begin
		alter table #Product drop column Stock,Cost
		update c set c.Stock=c.Stock/u.Secondary,c.Cost=c.Cost*u.Secondary from #CostStock c join invProduct p on c.ProductId=p.Id join invUOMLevels u on c.ProductId=u.ProductId and p.SalesUom=u.UOMId 
		select p.Code +'       '+ p.Name [Code + Name],p.*,c.Cost,c.Stock from #Product p left join #CostStock c on p.Id=c.ProductId order by p.Name
	End
	Else
		select p.Code +'       '+ p.Name [Code + Name], p.*,replace(p.Code +'       '+ p.Name,'*','')Name1 from #Product p order by p.Code + p.Name
End
Else if exists(select top 1 1 from #CostStock)
Begin
	alter table #Product drop column Stock,Cost
	update c set c.Stock=c.Stock/u.Secondary,c.Cost=c.Cost*u.Secondary from #CostStock c join invProduct p on c.ProductId=p.Id join invUOMLevels u on c.ProductId=u.ProductId and p.SalesUom=u.UOMId 
	select p.*,c.Cost,c.Stock from #Product p left join #CostStock c on p.Id=c.ProductId order by p.Name
End
Else
Begin
	if @PurchaseProperty=1
	Begin
		select p.[ ],p.Id,s.PurchaseSubPropertyID PurchaseSubPropertyID1,sp.Name PurchaseProperty1,p.Code,p.Name,p.NativeCaption,p.CCode,p.CategoryID,p.AutoEntry,p.TaxGroupId,p.SRate,p.MRP,p.Cost,p.TaxGroup,p.Tax,s.Qty Stock,p.NonStock,p.TaxInclusive,p.HaveSerialNo,p.AdditionP,p.TAddition from #Product p
		left join #PStock s on s.ProductID=p.ID
		left join invPurchaseSubProperty sp on s.PurchaseSubPropertyID=sp.ID
		where (s.Qty<>0 or p.NonStock=1 or @StockItemsOnly=0)
		order by productid,s.PurchaseSubPropertyID
	End
	Else
		select * from #Product order by Name
End

go

if object_id('spSyncDownloadProduct') is not null drop proc spSyncDownloadProduct

go

create proc spSyncDownloadProduct
@CompanyID int

as

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 


declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Source DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like'1%' and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End


if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End

Begin try
	--Downloading

	--Masters


	--invUOM
	exec ('insert Into invUOM(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOM a1
			left join invUOM a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--invProduct
	exec ('insert Into invProduct(Id,Code,Name,Packing,OtherLanguage,CostCentreId,Cost,Rate,BaseUom,PurchaseUom,SalesUom,StockUom,MinStock,MinUom,MaxStock,MaxUom,ROL,ROLUom,ROQ,ROQUom,Inactive,NonStockItem,Expiry,CounterItem,AutoEntry,Barcode,TaxGroupId,Mrp,PackingUnit,Profit,HideFromDevice,TaxInclusive,NRate,RateEdit)
		   select a1.Id,a1.Code,a1.Name,a1.Packing,a1.OtherLanguage,a1.CostCentreId,a1.Cost,a1.Rate,a1.BaseUom,a1.PurchaseUom,a1.SalesUom,a1.StockUom,a1.MinStock,a1.MinUom,a1.MaxStock,a1.MaxUom,a1.ROL,a1.ROLUom,a1.ROQ,a1.ROQUom,a1.Inactive,a1.NonStockItem,a1.Expiry,a1.CounterItem,a1.AutoEntry,a1.Barcode,a1.TaxGroupId,a1.Mrp,a1.PackingUnit,a1.Profit,a1.HideFromDevice,a1.TaxInclusive,a1.NRate,a1.RateEdit from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a1
		   left join invProduct a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.AutoEntry=a2.AutoEntry,a1.TaxGroupID=a2.TaxGroupID,a1.OtherLanguage=a2.OtherLanguage,a1.InActive=a2.InActive,a1.MRP=a2.MRP,a1.NRate=a1.NRate,a1.WRate=a2.WRate from invProduct a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a2 on a1.ID=a2.ID')


	ALTER TABLE invUOMLevels Disable TRIGGER triggerinvUOMLevels
	--invUOMLevels
	exec ('insert Into invUOMLevels(Sno,ProductID,UOMID,Multiplayer,UnitID,Secondary,Cost,Rate,Barcode,BarcodeID,MRP,NRate)
		   select a1.Sno,a1.ProductID,a1.UOMID,a1.Multiplayer,a1.UnitID,a1.Secondary,a1.Cost,a1.Rate,a1.Barcode,a1.BarcodeID,a1.MRP,a1.NRate from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a1
		   left join invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno
		   where a2.ProductID is null'
		)

	exec ('update a1 set a1.UomId=a2.UomId,a1.MultiPlayer=a2.MultiPlayer,a1.UnitId=a2.UnitId,a1.Secondary=a2.Secondary,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.Barcode=a2.Barcode,a1.BarcodeId=a2.BarcodeId,a1.MRP=a2.MRP,a1.NRate=a2.NRate from invUOMLevels a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno')

	ALTER TABLE invUOMLevels Enable TRIGGER triggerinvUOMLevels

	
	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if object_id('prExportSales') is not null drop proc prExportSales

go

create proc prExportSales
@CompanyID int,
@PeriodID int,
@VtypeID int,
@ExportNo int

as

SET NOCOUNT ON
SET XACT_ABORT ON
SET DEADLOCK_PRIORITY LOW
SET LOCK_TIMEOUT 10000

--declare @CompanyID int
declare @No int

--SET @CompanyID=1

declare @TableColumnList varchar(max),
        @ColumnList varchar(max),
        @UpdateColumnList varchar(max)
        

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)
declare @LocalDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB,@LocalDBName=LocalDatabase  from invOption where CompanyID=@CompanyID
set @RmtDBName=case when len(@LocalDBName)>0 then @LocalDBName else @RmtDBName end

if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB' Message
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Exporting to same DB is not allowable' Message
	return
End 

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0 and len(rtrim(isnull(@LocalDBName,'')))=0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+'].'

End


if len(rtrim(isnull(@LocalDBName,'')))>0
Begin
	set @RmtSrvName=''
	set @RmtDBO=''
End

    
--------------------   
create table #T1(No int,Message nvarchar(100))

exec('insert #T1(Message) select ''Permission Granted for User ''+u.Name+'' for Menu ''+upper(f.Name)+'' in Destination DB'' from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like''1%''')

declare @Message nvarchar(100)
select @Message=max(Message) from #T1


if @Message is not null
Begin
	select @Message Message
	return
End


exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
ExportCompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and ExportNo='+@ExportNo)
select @No=max(No) from #T1
------------------

--Begin Transaction


if(@No is null)
begin
	exec('insert #T1(No) exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.prGetSalesMaxVno '+@CompanyID+','+@PeriodID+','+@VtypeId)
	select @No=max(No) from #T1 
end
else
begin

	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete t from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction t WITH (ROWLOCK) join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@No+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID)

end	


