	exec('insert #SalesToSync(PeriodID,No) 
	select s.PeriodID,s.No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID=16 and s.SyncCount>0')

