				select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.WarehouseId,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Gross,p1.DiscountP,p1.Discount,p1.Total,p1.MfrDate,p1.ExpDate,p1.Remark,p1.BarcodeId,p1.CompanyId,p1.PeriodId,p1.Tax,p1.TaxGroupId,p1.SerialNoID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesReturnDetails p1
				join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
