			   select p1.CompanyID,p1.PeriodID,p1.VTypeID,p1.No,p1.Sno,p1.ProductID,p1.SubPropertyID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesReturnPropertyDetails p1
			   join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
			)

		exec('update '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesReturnHeader set Sync=null where Sync=1 and CompanyID='+ @CompanyID)
		
