		       join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No'
		  )
		

		--invSalesDetails
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,FType,ARate,Length,Width)
