	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pPayment(VtypeId,No,CardID,CurrencyID,AccountID,Amount,CompanyID,PeriodID,UserID,CAmount,CNo,GiftCardID)
		   select p1.VtypeId,p1.No,p1.CardID,p1.CurrencyID,p1.AccountID,p1.Amount,p1.CompanyID,p1.PeriodID,p1.UserID,p1.CAmount,p1.CNo,p1.GiftCardID from pPayment p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pPayment p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)
	

	if object_id('pSalesReturnHeader') is not null
	--pSalesReturnHeader
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnHeader(VtypeId,No,Date,Time,SalesManId,Total,Discount,RoundOff,NetTotal,Shift,CompanyId,PeriodId,UserID,BalanceReturn,RateLevelID,Notes,CustomerID,TaxAmount,TaxGroup,TaxMethode,CostCentreID,CustomerContact,CustomerContactName,CVtypeId,QRCodeImage,EInvoice,Remark1,Remark2,Remark3)
		   select p1.VtypeId,p1.No,p1.Date,p1.Time,p1.SalesManId,p1.Total,p1.Discount,p1.RoundOff,p1.NetTotal,p1.Shift,p1.CompanyId,p1.PeriodId,p1.UserID,p1.BalanceReturn,p1.RateLevelID,p1.Notes,p1.CustomerID,p1.TaxAmount,p1.TaxGroup,p1.TaxMethode,p1.CostCentreID,p1.CustomerContact,p1.CustomerContactName,p1.CVtypeId,p1.QRCodeImage,p1.EInvoice,p1.Remark1,p1.Remark2,p1.Remark3 from pSalesReturnHeader p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnHeader p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		  )


		  
	
	
	if object_id('pSalesReturnDetails') is not null	
	--pSalesReturnDetails
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnDetails(VtypeId,No,Sno,ProductId,BarcodeID,UomId,Qty,Foc,Rate,Total,CompanyId,PeriodId,MRP,TaxGroupID,Tax,DiscountPercentage,DiscountAmount)
		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.BarcodeID,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Total,p1.CompanyId,p1.PeriodId,p1.MRP,p1.TaxGroupID,p1.Tax,p1.DiscountPercentage,p1.DiscountAmount from pSalesReturnDetails p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnDetails p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	
	if object_id('pReturnPayment') is not null	
	--pReturnPayment
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pReturnPayment(VtypeId,No,CardID,CurrencyID,AccountID,Amount,CompanyID,PeriodID,UserID,CAmount,CNo)
		   select p1.VtypeId,p1.No,p1.CardID,p1.CurrencyID,p1.AccountID,p1.Amount,p1.CompanyID,p1.PeriodID,p1.UserID,p1.CAmount,p1.CNo from pReturnPayment p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pReturnPayment p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	
	if object_id('pLogin') is not null	
	Begin
		--pLogin
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLogin(UserID,LogIn,LogOut,Status,VTypeID,Shift,CompanyID,ExcessShortage,CardAmount)
			   select p1.UserID,p1.LogIn,p1.LogOut,p1.Status,p1.VTypeID,p1.Shift,p1.CompanyID,p1.ExcessShortage,p1.CardAmount from pLogin p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLogin p2 on p1.UserID=p2.UserID and p1.VTypeID=p2.VTypeID and p1.Shift=p2.Shift and p1.CompanyID=p2.CompanyID
			   where p2.Shift is null and p1.CompanyID='+ @CompanyID
			)

			--pLogin
		exec ('update p2 set p2.Login=p1.Login,p2.LogOut=p1.LogOut,p2.Status=p1.Status,p2.ExcessShortage=p1.ExcessShortage,p2.CardAmount=p1.CardAmount from pLogin p1
			   join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLogin p2 on p1.UserID=p2.UserID and p1.VTypeID=p2.VTypeID and p1.Shift=p2.Shift and p1.CompanyID=p2.CompanyID
			   where p1.CompanyID='+ @CompanyID
			)

	End

		
	if object_id('pLoginDenomination') is not null	
	--pLoginDenomination
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLoginDenomination(UserID,VTypeID,Shift,Denomination,Qty)
		   select p1.UserID,p1.VTypeID,p1.Shift,p1.Denomination,p1.Qty from pLoginDenomination p1 
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pLoginDenomination p2 on p1.Shift=p2.Shift and p1.VTypeID=p2.VTypeID and p1.UserID=p2.UserID
		   where p2.UserID is null '
		)

		if object_id('pClosingDenomination') is not null	
	--pLoginDenomination
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pClosingDenomination(UserID,VTypeID,Shift,Denomination,Qty,CompanyID)
		   select p1.UserID,p1.VTypeID,p1.Shift,p1.Denomination,p1.Qty,p1.CompanyID from pClosingDenomination p1 
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pClosingDenomination p2 on p1.Shift=p2.Shift and p1.VTypeID=p2.VTypeID and p1.UserID=p2.UserID and p1.CompanyID=p2.CompanyID
		   where p2.UserID is null and p1.CompanyID='+ @CompanyID
		)

	create table #VType(ID int)
	insert #VType(ID)
	select AccountVTypeID from invVoucherTypeDetails where VtypeID in(3,4,12,23)
	

	if (@UploadReceiptPayment=1)
	Begin
		--aCashPaymentHdr
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentHdr(No,RefNo,Date,CreditorID,Total,CompanyID,PeriodID,UserID)
			   select p1.No,p1.RefNo,p1.Date,p1.CreditorID,p1.Total,p1.CompanyID,p1.PeriodID,p1.UserID from aCashPaymentHdr p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentHdr p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )

		
		--aCashPaymentDtl
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentDtl(No,SNo,DebtorID,Description,Amount,CompanyID,PeriodID,CostCentreID,Discount)
			   select p1.No,p1.SNo,p1.DebtorID,p1.Description,p1.Amount,p1.CompanyID,p1.PeriodID,p1.CostCentreID,p1.Discount from aCashPaymentDtl p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashPaymentDtl p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )
		
		--aCashReceiptHdr
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptHdr(No,RefNo,Date,DebtorID,Total,CompanyID,PeriodID,UserID)
			   select p1.No,p1.RefNo,p1.Date,p1.DebtorID,p1.Total,p1.CompanyID,p1.PeriodID,p1.UserID from aCashReceiptHdr p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptHdr p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )
		
		--aCashReceiptDtl
		exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptDtl(No,SNo,CreditorID,Description,Amount,CompanyID,PeriodID,CostCentreID,Discount)
			   select p1.No,p1.SNo,p1.CreditorID,p1.Description,p1.Amount,p1.CompanyID,p1.PeriodID,p1.CostCentreID,p1.Discount from aCashReceiptDtl p1
			   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCashReceiptDtl p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
			   where p2.No is null and p1.CompanyID='+ @CompanyID
			  )

		insert #VType(ID)
		select CashReceipt from aVoucherTypeSettings 

		insert #VType(ID)
		select CashPayment from aVoucherTypeSettings 

	End


	--delete 0 Amount POS Transaction
	exec ('delete t from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t
	       join invVoucherTypeDetails v on t.VoucherTypeId=v.AccountVtypeId and v.VtypeId in(12,23)
		   where round(t.Amount,2)=0 and t.ModuleId=7 and t.CompanyID='+ @CompanyID
		 )

    --aTransaction
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo,CreditCardID,CostCentreID)
		   select t1.CompanyID,t1.PeriodID,t1.Date,t1.VoucherTypeID,t1.No,t1.DebtorID,t1.CreditorID,t1.Amount,t1.Description,t1.RefNo,t1.ModuleID,t1.AccountID,t1.CDate,t1.CNo,t1.SNo,t1.CreditCardID,t1.CostCentreID from aTransaction t1
		   join #VType v on t1.VoucherTypeID=v.ID
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and isnull(t1.Date,0)=isnull(t2.Date,0) and isnull(t1.No,0)=isnull(t2.No,0)
		   where t2.No is null and t1.CompanyID='+ @CompanyID
		 )
	

	--Downloading Customer Transactions
	exec ('insert Into aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo,CreditCardID,CostCentreID)
		   select t1.CompanyID,t1.PeriodID,t1.Date,t1.VoucherTypeID,t1.No,t1.DebtorID,t1.CreditorID,t1.Amount,t1.Description,t1.RefNo,t1.ModuleID,t1.AccountID,t1.CDate,t1.CNo,t1.SNo,t1.CreditCardID,t1.CostCentreID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t1
		   join invCustomer c on t1.DebtorId=c.AccountId or t1.CreditorId=c.AccountId
		   left join #VType v on t1.VoucherTypeID=v.ID
		   left join aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and isnull(t1.Date,0)=isnull(t2.Date,0) and isnull(t1.No,0)=isnull(t2.No,0)
		   where t2.No is null and v.ID is null and t1.CompanyID='+ @CompanyID
		 )
	
	

	--Deleting Customer Cash Receipt
	if (@UploadReceiptPayment=0)
	exec ('delete t1 from aTransaction t1
		   join invCustomer c on t1.DebtorId=c.AccountId or t1.CreditorId=c.AccountId
		   join aVoucherTypeSettings v on t1.VoucherTypeID in(v.CashReceipt,v.ChequePayment)
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and isnull(t1.Date,0)=isnull(t2.Date,0) and isnull(t1.No,0)=isnull(t2.No,0)
		   where t2.CompanyID is null and t1.CompanyID='+ @CompanyID
		 )
    
	
	--Delete duplicate from Remote Server
	declare @Query varchar(max)
	set @Query = @RmtSrvName + '.'+@RmtDBName +'.'+ @RmtDBO+ '.spDeleteDoubleEntries '+cast(@CompanyId as varchar) 
	exec(@Query)  
	------------------------------------

	exec spDeleteDoubleEntries @CompanyId

	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if object_id('spSyncDownloadProduct') is not null drop proc spSyncDownloadProduct

go

create proc spSyncDownloadProduct
@CompanyID int

as

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 


-----------------------
declare @Forms table(FormId varchar(10),Name varchar(100))
insert @Forms
select FormId,Name from invForms where FormId like'1%' 

if exists(select 1 from invProjectSettings where CompanyId=@CompanyId and BlockMasterCreation=1)
	delete @Forms where FormId in('12','1C')

declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Destination DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join @Forms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End
---------------------------


if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End

Begin try
	--Downloading

	--Masters


	--invUOM
	exec ('insert Into invUOM(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOM a1
			left join invUOM a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--invProduct
	exec ('insert Into invProduct(Id,Code,Name,Packing,OtherLanguage,CostCentreId,Cost,Rate,BaseUom,PurchaseUom,SalesUom,StockUom,MinStock,MinUom,MaxStock,MaxUom,ROL,ROLUom,ROQ,ROQUom,Inactive,NonStockItem,Expiry,CounterItem,AutoEntry,Barcode,TaxGroupId,Mrp,PackingUnit,Profit,HideFromDevice,TaxInclusive,NRate,RateEdit)
		   select a1.Id,a1.Code,a1.Name,a1.Packing,a1.OtherLanguage,a1.CostCentreId,a1.Cost,a1.Rate,a1.BaseUom,a1.PurchaseUom,a1.SalesUom,a1.StockUom,a1.MinStock,a1.MinUom,a1.MaxStock,a1.MaxUom,a1.ROL,a1.ROLUom,a1.ROQ,a1.ROQUom,a1.Inactive,a1.NonStockItem,a1.Expiry,a1.CounterItem,a1.AutoEntry,a1.Barcode,a1.TaxGroupId,a1.Mrp,a1.PackingUnit,a1.Profit,a1.HideFromDevice,a1.TaxInclusive,a1.NRate,a1.RateEdit from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a1
		   left join invProduct a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.AutoEntry=a2.AutoEntry,a1.TaxGroupID=a2.TaxGroupID,a1.OtherLanguage=a2.OtherLanguage,a1.InActive=a2.InActive,a1.MRP=a2.MRP,a1.NRate=a1.NRate,a1.WRate=a2.WRate from invProduct a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a2 on a1.ID=a2.ID')


	ALTER TABLE invUOMLevels Disable TRIGGER triggerinvUOMLevels
	--invUOMLevels
	exec ('insert Into invUOMLevels(Sno,ProductID,UOMID,Multiplayer,UnitID,Secondary,Cost,Rate,Barcode,BarcodeID,MRP,NRate)
		   select a1.Sno,a1.ProductID,a1.UOMID,a1.Multiplayer,a1.UnitID,a1.Secondary,a1.Cost,a1.Rate,a1.Barcode,a1.BarcodeID,a1.MRP,a1.NRate from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a1
		   left join invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno
		   where a2.ProductID is null'
		)

	exec ('update a1 set a1.UomId=a2.UomId,a1.MultiPlayer=a2.MultiPlayer,a1.UnitId=a2.UnitId,a1.Secondary=a2.Secondary,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.Barcode=a2.Barcode,a1.BarcodeId=a2.BarcodeId,a1.MRP=a2.MRP,a1.NRate=a2.NRate from invUOMLevels a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno')

	ALTER TABLE invUOMLevels Enable TRIGGER triggerinvUOMLevels

	
	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if object_id('spSyncDownloadingCustomer') is not null drop proc spSyncDownloadingCustomer

go

create proc spSyncDownloadingCustomer
@CompanyID int

as

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 

-----------------------
declare @Forms table(FormId varchar(10),Name varchar(100))
insert @Forms
select FormId,Name from invForms where FormId like'1%' 

if exists(select 1 from invProjectSettings where CompanyId=@CompanyId and BlockMasterCreation=1)
	delete @Forms where FormId in('12','1C')

declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Destination DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join @Forms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End
---------------------------

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End


Begin try
	--Downloading

	--Masters

	 

	--aAccountGroup
	exec ('insert Into aAccountGroup([ID],[Code],[Name],[AccountTypeID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountTypeID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup a1
		   left join aAccountGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountSubGroup
	exec ('insert Into aAccountSubGroup([ID],[Code],[Name],[AccountGroupID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountGroupID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup a1
		   left join aAccountSubGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )


	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
		   left join aAccount a2 on a1.ID=a2.ID
		   where a2.ID is null'
			)

	exec (' update a1 set a1.UnderAccountID=a2.UnderAccountID,a1.NameInOL=a2.NameInOL from aAccount a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID')



	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
			select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
			left join aAccount a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	

	   
	--Salesman
	exec ('insert Into invSalesman(Id,Code,Name,AccountID,WareHouseID,CompanyId)
			select a1.Id,a1.Code,a1.Name,a1.AccountID,a1.WareHouseID,a1.CompanyId from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesman a1
			left join invSalesman a2 on a1.ID=a2.ID
			where a2.ID is null'
			)
	
	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.AccountID=a2.AccountID,a1.WareHouseID=a2.WareHouseID,a1.CompanyId=a2.CompanyId from invSalesman a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesman a2 on a1.Id=a2.Id')

	   

  
	--invCustomer
	exec ('insert Into invCustomer (Name,Address1,Address2,Address3,Phone,MobileNo,Email,Web,Location,ContactPerson,CreditLimit,DueDays,CurrencyId,RateLevelId,SalesManId,PaymentTerms,Remark,AccountID,FileNo,Place,TIN,CST,DLNo1,DLNo2,Inactive,CompanyID,GST)
		   select v1.Name,v1.Address1,v1.Address2,v1.Address3,v1.Phone,v1.MobileNo,v1.Email,v1.Web,v1.Location,v1.ContactPerson,v1.CreditLimit,v1.DueDays,v1.CurrencyId,v1.RateLevelId,v1.SalesManId,v1.PaymentTerms,v1.Remark,v1.AccountID,v1.FileNo,v1.Place,v1.TIN,v1.CST,v1.DLNo1,v1.DLNo2,v1.Inactive,v1.CompanyID,v1.GST from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCustomer v1
		   left join invCustomer v2 on v1.AccountID=v2.AccountID
		   where v2.AccountID is null'
		 )	

	exec ('update a1 set a1.Name=a2.Name,a1.Address1=a2.Address1,a1.Address2=a2.Address2,a1.Address3=a2.Address3,a1.Phone=a2.Phone,a1.MobileNo=a2.MobileNo,a1.Email=a2.Email,a1.ContactPerson=a2.ContactPerson,a1.CreditLimit=a2.CreditLimit,a1.DueDays=a2.DueDays,a1.RateLevelId=a2.RateLevelId,a1.SalesManId=a2.SalesManId,a1.Place=a2.Place,a1.TIN=a2.TIN,a1.Inactive=a2.Inactive,a1.CompanyID=a2.CompanyID,a1.GST=a2.GST from invCustomer a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCustomer a2 on a1.AccountID=a2.AccountID')
	          

	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if OBJECT_ID('prPurchaseReturnHeaderPrint') is not null
	drop proc prPurchaseReturnHeaderPrint
go

create proc prPurchaseReturnHeaderPrint
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int as
set nocount on

select t1.[No],t3.Code VType,cast(cast(t1.[Date] as varchar) as datetime) Date,cast(cast(t1.[DeliveryDate] as varchar) as datetime) [DeliveryDate],
t4.Name [Vendor],case when t1.[PaymentMode] = 0 then 'Cash' else 'Credit' end [PaymentMode] ,t1.[InvoiceNo],
t1.[Total],t1.[DiscountP],t1.[Discount],t1.[NetTotal],t1.[Notes],
t4.Address1,t4.Address2,t4.Address3,t4.Phone,t4.MobileNo,t4.Email,t4.GST,t4.TIN,t1.Tax,t1.LRService,t1.LRNo,
t5.name UserName,isnull(t1.Addition,0) Addition,isnull(t1.Roff,0) Roff,v.InvoiceFormat,t1.QRCodeImage from invPurchaseReturnHeader t1
join invVoucherTypeDetails t3 on t1.VtypeID = t3.ID    
join (select AccountId,Name,Address1,Address2,Address3,Phone,MobileNo,EMail,GST,TIN from invVendor union all select AccountId,Name,Address1,Address2,Address3,Phone,MobileNo,EMail,GST,TIN from invCustomer) t4 on t1.VendorID = t4.AccountID   
left join invVoucherTypeStartNo v on v.CompanyId=@CompanyID and v.PeriodId=@PeriodID and v.VtypeId=@VtypeID 
left outer join invUser t5 on t1.UserId = t5.Id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No


go


if not exists(select name from sys.columns where object_id = object_id('invTaxGroup') and name = 'OnMRP') 
    alter table invTaxGroup add OnMRP bit


go

if object_id('prSaveinvTaxGroup') is not null
	drop proc prSaveinvTaxGroup
go	
	
create proc prSaveinvTaxGroup
@Id int,
@Code varchar(25),
@Name varchar(100),
@InputTax float,
@OutputTax float,
@PurchaseValueTitle varchar(50),
@PurchaseTaxTitle varchar(50),
@SalesValueTitle varchar(50),
@SalesTaxTitle varchar(50),
@CGST float,
@SGST float,
@Addition float,
@OnMRP bit,
@Status int output

 
as
set nocount on

if exists (select 1 from invTaxGroup where Id <> @Id and Code = @code )
begin
  set @Status = 2
  return
end

if exists (select 1 from invTaxGroup where Id <> @Id and Name = @Name)
begin
  set @Status = 3
  return
end

if @Id = 0
  begin
	  select @Id = isnull(MAX(Id),0) + 1 from invTaxGroup
	  insert invTaxGroup ([Id],[Code],[Name],[InputTax],[OutputTax],[PurchaseValueTitle],
	  [PurchaseTaxTitle],[SalesValueTitle],[SalesTaxTitle],CGST,SGST,Addition,OnMRP) 
	  values(@Id,@Code,@Name,@InputTax,@OutputTax,@PurchaseValueTitle,@PurchaseTaxTitle,@SalesValueTitle,@SalesTaxTitle,@CGST,@SGST,@Addition,@OnMRP)
  end
else
     update invTaxGroup set  Code= @Code,
							 Name= @Name,
							 InputTax= @InputTax,
							 OutputTax= @OutputTax,
							 PurchaseValueTitle= @PurchaseValueTitle,
							 PurchaseTaxTitle= @PurchaseTaxTitle,
							 SalesValueTitle= @SalesValueTitle,
							 SalesTaxTitle= @SalesTaxTitle,
							 CGST=@CGST,
							 SGST=@SGST,
							 Addition=@Addition,
							 OnMRP=@OnMRP
							where Id = @Id 
  
set @Status = 1 

go 

if object_id('prGetActiveProductForSales') is not null
	drop proc prGetActiveProductForSales
go	
   
create proc prGetActiveProductForSales 
@UserId int,
@CompanyID int=1,
@CostCentreId int=null,
@CustomerId int=null

as  

set nocount on  
set transaction isolation level read uncommitted

declare @StockCostCentreId int
set @StockCostCentreId=@CostCentreId

if exists(select 1 from invOption where CompanyId=@CompanyID and CostCentreIndependentProducts=1)
	set @CostCentreId=0


create table #Product
(
[ ] bit not null default 0,
Id int,
Code varchar(50),
Name nvarchar(200),
Barcode varchar(50),
NativeCaption nvarchar(200),
CCode varchar(50),
CategoryID int,
AutoEntry bit,
TaxGroupId int,
SRate float,
NRate float,
WRate float,
MRP float,
PRate float,
Cost float,
TaxGroup varchar(50),
Tax float,
HStock varchar(50),
Stock float,
NonStock bit,
TaxInclusive bit,
AdditionP float,
HaveSerialNo bit,
CostCentreId int,
TAddition float,
Name1 nvarchar(200),
FOC float,
TaxOnMRP bit
)

insert #Product(Id,Code,Name,NativeCaption,AutoEntry,TaxGroupId,SRate,WRate,MRP,NonStock,TaxInclusive,AdditionP,HaveSerialNo,CostCentreId,Name1)
select Id,Code,Name,OtherLanguage,AutoEntry,TaxGroupId,Rate,WRate,MRP,NonStockItem,TaxInclusive,AdditionP,SerialNo,CostCentreId,replace(Name,'*','') from invProduct where (Inactive is null or Inactive = 0)



--Cost Centre Filtering
declare @CC table(Id int)

if isnull(@CostCentreId,0)=0
	insert @CC
	select isnull(CostCentreId,0) from invUserCostCentre where Product=1 and UserId=@UserID

if exists(select top 1 1 from invProduct where CostCentreId=@CostCentreId)
	insert @CC values(@CostCentreId)

if exists(select 1 from @CC)
	delete p from #Product p left join @CC c on isnull(p.CostCentreId,0)=c.Id where c.Id is null
-------

--Barcode
update p set p.Barcode=u.Barcode from #Product p join invUOMLevels u on p.ID=u.ProductID and u.SNo=1

create table #CostStock(ProductID int,Cost float,Stock float)

declare @StockItemsOnly bit
select @StockItemsOnly=SalesStockItemsOnly from invOption where CompanyID=@CompanyID

if exists(select 1 from invOption where (SalesStockItemsOnly=1 or SalesDisplayStock=1) and isnull(SalesCostwiseStock,0)=0 and CompanyID=@CompanyID)--Stock
Begin
	declare @PurchaseProperty bit
	--select top 1 @PurchaseProperty = 1 from invPurchaseSubProperty
	select @PurchaseProperty=SalesProperty from invProjectSettings where CompanyId=@CompanyID

	create table #PStock (CompanyID int,ProductID int,PurchaseSubPropertyID int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float) 
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct
		
	if @PurchaseProperty=1
	Begin
		insert #PStock(ProductID,PurchaseSubPropertyID,Qty) 
		exec spPurchasePropertyStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=0
		update #Product set Cost=0
	End
		
	Else
	Begin
		insert #PStock(CompanyID,ProductID,Rate,CP,SRate,WRate,MRP,Qty,Pieces) 
		exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=1,@CostCentreId=@StockCostCentreId

		if exists(select 1 from invOption where TaxOption=2 and CompanyID=@CompanyID)
			update p set p.PRate=s.Rate,p.Cost=s.CP,p.Stock=s.Qty from #Product p join #PStock s on p.ID=s.ProductID and round(s.Qty,2)<>0
		else
			update p set p.Cost=s.CP,p.Stock=s.Qty from #Product p join #PStock s on p.ID=s.ProductID and round(s.Qty,2)<>0

		if @StockItemsOnly=1
			delete #Product where (Stock<=0 or Stock is null) and (NonStock=0 or NonStock is null)
	
	End
	
End
Else if exists(select 1 from invOption where CompanyId=@CompanyId and SalesCostwiseStock=1)
Begin
	create table #DateCostStock(ProductID int,Date int,Cost float,Stock float)
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct 
	insert #DateCostStock(ProductID,Date,Cost,Stock)
	exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=16

	--Stock Adjustment
	create table #SA(ProductID int,Date int,Cost float,Stock float)
	insert #SA
	select ProductId,Date,Cost,Stock from
	(select row_number()over(partition by ProductId order by date desc)Sno,d.ProductId,h.Date,d.Cost,d.PhysicalStock Stock from invStockAdjustmentDetails d join invStockAdjustmentHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
	 where d.Cost>0
	 )sa where sa.Sno=1

	 delete c from #DateCostStock c join #SA s on c.ProductID=s.ProductId and c.Date<=s.Date

	 --update c set c.Stock=s.Stock from #DateCostStock c join #SA s on c.ProductID=s.ProductId and c.Date=s.Date
	 insert #DateCostStock
	 select s.ProductId,s.Date,s.Cost,s.Stock from #SA s --left join #DateCostStock d on s.ProductID=d.ProductID and d.Stock>0 where d.Date is null

	 --create table #CostStock(ProductID int,Cost float,Stock float)
	 insert #CostStock
	 select ProductId,round(Cost,2),sum(Stock) from #DateCostStock group by ProductId,round(Cost,2)
	 ---------------
	 
	 if @StockItemsOnly=1
		delete #CostStock where isnull(Stock,0)<=0
	
End

if exists(select 1 from invUser where ID=@UserID and CostDisplay=1) 
	 or exists(select 1 from invOption where CompanyID=@CompanyID and SalesDisplayCP=1)
Begin
	declare @CP table(ProductID int,CP float)

	insert tmpTable(ID,SPID) select ID,@@SPID from #Product where Cost is null or Cost=0
	insert @CP(ProductID,CP)
	exec spStock @CompanyID=@CompanyID,@ToDate=99999999,@Type=13
	
	update p set p.Cost=s.CP from #Product p join @CP s on p.ID=s.ProductID and round(s.CP,2)<>0 where p.Cost is null or p.Cost=0
End


--Aliases
insert #Product(Id,Code,Name,NativeCaption,AutoEntry,TaxGroupId,SRate,WRate,MRP,Cost,Name1)
select Id,Code,a.Alias,NativeCaption,AutoEntry,TaxGroupId,SRate,WRate,MRP,Cost,replace(a.Alias,'*','') from #Product p join invProductAlias a on p.ID=a.ProductID

declare @SalesRate int
select @SalesRate=SalesRate from invOption where CompanyID=@CompanyID

if (@SalesRate=1 or @SalesRate=2 or @SalesRate=4)--Last/Customer Last/Last Over Customer Last
Begin
	
	--SRate 
	create table #SRate(Date int,ProductID int,SRate float,WRate float,MRP float)

	insert #SRate(Date,ProductID,SRate,WRate,MRP)
	select Date,ProductID,SRate,WRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate,WRate,MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1

	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate,MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1


	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by pd.Date desc)sno,pd.Date,ProductID,SRate,MRP from invProductionHeader pd
	where pd.CompanyID=@CompanyID and (SRate>0 or MRP>0)
	)a where sno=1


	if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
		insert #SRate(Date,ProductID,SRate)
		select Date,ProductID,SRate from
		(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where pd.CompanyID=@CompanyID and (SRate>0)
		)a where sno=1


	insert #SRate(Date,ProductID,SRate,MRP)
	select Date,ProductID,SalesRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SalesRate,MRP from invOpeningStock pd
	join invOpeningStockHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SalesRate>0 or MRP>0)
	)a where sno=1

	if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
		insert #SRate(Date,ProductID,SRate)
		select Date,ProductID,SRate from
		(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where ph.CompanyTo=1 and (SRate>0)
		)a where sno=1
	
	

	insert #SRate(Date,ProductID,SRate)
	select Date,ProductID,SRate from
	(select ROW_NUMBER() over (partition by ProductID order by ph.Date desc)sno,ph.Date,ProductID,SRate from invGoodsReceiptDetails pd
	join invGoodsReceiptHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (SRate>0)
	)a where sno=1

	

	insert #SRate(Date,ProductID,SRate,WRate,MRP)
	select Date,ProductID,Rate,WRate,MRP from
	(select ROW_NUMBER() over (partition by ProductID order by ph.FromDate desc)sno,ph.FromDate Date,ProductID,Rate,WRate,MRP from invQtyRateSettingsDetails pd
	join invQtyRateSettingsHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and (Rate>0 or MRP>0) and ToDate is null and Type=3
	)a where sno=1
	
	

	--Updation
	;with r as
	(select * from 
	(select ROW_NUMBER() over (partition by ProductID order by Date desc)Sno,ProductID,SRate,WRate,MRP from #SRate)a where sno=1
	)

	update p set p.SRate=r.SRate,p.WRate=r.WRate,p.MRP=r.MRP from #Product p join r on p.Id = r.ProductID
	
	if (@SalesRate=2 and @CustomerId>0)--Customer Last Rate
	Begin
		create table #CLR(ProductId int,Rate float,MRP float unique clustered (ProductId))
		insert #CLR
		select ProductId,Rate,MRP from 
		(select ROW_NUMBER() over (partition by ProductID order by Date desc)Sno,ProductID,Rate,MRP from invSalesDetails sd
		 join invSalesHeader sh on sd.CompanyId=sh.CompanyId and sd.PeriodId=sh.PeriodId and sd.VtypeId=sh.VtypeId and sd.No=sh.No
		 where sh.CustomerId=@CustomerId
		)a where sno=1
		
		update p set p.SRate=r.Rate,p.MRP=r.MRP from #Product p join #CLR r on p.Id = r.ProductID
	End
End


--Updation
if exists(select 1 from invOption where SalesRate=0 and CompanyID=@CompanyID)--Zero Sales Rate
	update p set p.SRate=0,p.MRP=0,p.WRate=0 from #Product p 
	

----------------------
--TaxGroup
update p set p.TaxGroup=t.Name,p.Tax=t.OutputTax,p.TAddition=t.Addition,p.TaxOnMRP=t.OnMRP from #Product p join invTaxGroup t on p.TaxGroupID = t.ID
----

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption where CompanyID=@CompanyID

if @@CatPropID is not null
	update p set p.CCode=sp.Code,p.CategoryID=pp.SubpropertyID from #Product p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

-------------------

--Stock CP,Qty
if exists(select top 1 1 from invSalesColumnCustomization where HQty=1 and HRate=1)
	update t set t.HStock=cast(floor(t.Stock/u.MultiPlayer) as varchar)+'.'+cast((t.Stock/u.MultiPlayer-floor(t.Stock/u.MultiPlayer))*u.MultiPlayer as varchar) from #Product t join invProduct p on p.Id=t.Id join invUOMLevels u on t.Id=u.ProductId and p.StockUom=u.UomId


--Qtywise Rate Settings
declare @Date int
select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)

update p set p.SRate=s.Rate from invQtyRateSettingsDetails s 
join #Product p on s.ProductId=p.Id 
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null
and @Time between h.FromTime and h.ToTime
and s.Rate<>0


--Qtywise FOC Settings
update p set p.FOC=s.FOC from invQtyRateSettingsDetails s 
join #Product p on s.ProductId=p.Id 
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null and s.Pieces is null
and @Time between h.FromTime and h.ToTime
and h.Type=5


--NRate
if exists(select 1 from invSalesColumnCustomization where NRate=1)
and not exists(select 1 from invOption where TaxOption=1 and CompanyId=@CompanyId)--Tax Inclusive
	update #Product set NRate=SRate*(100.0+Tax)/100.0

if exists(select top 1 1 from invOption where DefaultSearchInSales=2 and CompanyID=@CompanyId)
begin
	select p.*,s.Name collate database_default+' '+p.Name collate database_default Property from #Product p 
	join invProductPropertyDetails pd on p.ID=pd.ProductID
	join invProductSubProperty s on pd.SubPropertyID  =s.ID 
	order by p.Name
	return
end
Else if exists(select top 1 1 from invOption where DefaultSearchInSales=3 and CompanyId=@CompanyId)
Begin
	if @PurchaseProperty=1
	Begin
		declare @PStock table(ProductId int,SubPropertyId1 int,SubPropertyId2 int,Qty float)

		insert @PStock(ProductId,SubPropertyId1,Qty)
		select ProductId,PurchaseSubPropertyID,Qty from #PStock s left join invPurchaseSubProperty p on s.PurchaseSubPropertyID=p.Id where p.PropertyId=1 or p.PropertyId is null

		update ps set ps.SubPropertyId2=s.PurchaseSubPropertyID from @PStock ps join #PStock s on ps.ProductId=s.ProductId and s.Qty=ps.Qty left join invPurchaseSubProperty p on s.PurchaseSubPropertyID=p.Id where p.PropertyId=2

		if @StockItemsOnly=1
			select p.[ ],p.Code +'       '+ p.Name [Code + Name],p.Id, s.SubPropertyID1 PurchaseSubPropertyID1,sp1.Name PurchaseProperty1,s.SubPropertyID2 PurchaseSubPropertyID2,sp2.Name PurchaseProperty2,p.Code,p.Name,p.NativeCaption,p.CCode,p.CategoryID,p.AutoEntry,p.TaxGroupId,p.SRate,p.MRP,p.Cost,p.TaxGroup,p.Tax,s.Qty Stock,p.NonStock,p.TaxInclusive,p.HaveSerialNo,p.AdditionP,p.TAddition,p.FOC from @PStock s
			left join invPurchaseSubProperty sp1 on s.SubPropertyID1=sp1.ID
			left join invPurchaseSubProperty sp2 on s.SubPropertyID2=sp2.ID
			join #Product p on s.ProductID=p.ID
			where (s.Qty<>0 or p.NonStock=1)
		Else
			select p.[ ],p.Code +'       '+ p.Name [Code + Name],p.Id, s.SubPropertyID1 PurchaseSubPropertyID1,sp1.Name PurchaseProperty1,s.SubPropertyID2 PurchaseSubPropertyID2,sp2.Name PurchaseProperty2,p.Code,p.Name,p.NativeCaption,p.CCode,p.CategoryID,p.AutoEntry,p.TaxGroupId,p.SRate,p.MRP,p.Cost,p.TaxGroup,p.Tax,s.Qty Stock,p.NonStock,p.TaxInclusive,p.HaveSerialNo,p.AdditionP,p.TAddition,p.FOC from #Product p
			left join @PStock s on p.ID=s.ProductID
			left join invPurchaseSubProperty sp1 on s.SubPropertyID1=sp1.ID
			left join invPurchaseSubProperty sp2 on s.SubPropertyID2=sp2.ID
					
	End
	Else if exists(select top 1 1 from #CostStock)
	Begin
		alter table #Product drop column Stock,Cost
		update c set c.Stock=c.Stock/u.Secondary,c.Cost=c.Cost*u.Secondary from #CostStock c join invProduct p on c.ProductId=p.Id join invUOMLevels u on c.ProductId=u.ProductId and p.SalesUom=u.UOMId 
		select p.Code +'       '+ p.Name [Code + Name],p.*,c.Cost,c.Stock from #Product p left join #CostStock c on p.Id=c.ProductId order by p.Name
	End
	Else
		select p.Code +'       '+ p.Name [Code + Name], p.*,replace(p.Code +'       '+ p.Name,'*','')Name1 from #Product p order by p.Code + p.Name
End
Else if exists(select top 1 1 from #CostStock)
Begin
	alter table #Product drop column Stock,Cost
	update c set c.Stock=c.Stock/u.Secondary,c.Cost=c.Cost*u.Secondary from #CostStock c join invProduct p on c.ProductId=p.Id join invUOMLevels u on c.ProductId=u.ProductId and p.SalesUom=u.UOMId 
	select p.*,c.Cost,c.Stock from #Product p left join #CostStock c on p.Id=c.ProductId order by p.Name
End
Else
Begin
	if @PurchaseProperty=1
	Begin
		select p.[ ],p.Id,s.PurchaseSubPropertyID PurchaseSubPropertyID1,sp.Name PurchaseProperty1,p.Code,p.Name,p.NativeCaption,p.CCode,p.CategoryID,p.AutoEntry,p.TaxGroupId,p.SRate,p.MRP,p.Cost,p.TaxGroup,p.Tax,s.Qty Stock,p.NonStock,p.TaxInclusive,p.HaveSerialNo,p.AdditionP,p.TAddition from #Product p
		left join #PStock s on s.ProductID=p.ID
		left join invPurchaseSubProperty sp on s.PurchaseSubPropertyID=sp.ID
		where (s.Qty<>0 or p.NonStock=1 or @StockItemsOnly=0)
		order by productid,s.PurchaseSubPropertyID
	End
	Else
		select * from #Product order by Name
End

go

if object_id('prGetActiveProductForPurchase') is not null
	drop proc prGetActiveProductForPurchase
go	
   
create proc prGetActiveProductForPurchase
@VendorID int=0,
@UserID int=1,
@CompanyId int=1
as  

set nocount on  
set transaction isolation level read uncommitted

create table #Products([ ]bit,ID int,Code varchar(50),Name nvarchar(200),NativeCaption nvarchar(200),UBC varchar(50),TaxGroupID int,UOMID int,UOM varchar(50),Cost float,SRate float,MRP float,Tax float,TaxGroup varchar(50),Stock float,CCode varchar(50),SerialNo bit,CostCentreId int,AdditionP float,NonStock bit,TaxOnMRP bit)

if (@VendorID>0)
	insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,UOM,Cost,SRate,MRP,SerialNo,CostCentreId,AdditionP,NonStock)
	select p.ID,p.Code,p.Name,p.OtherLanguage,p.TaxGroupId,p.BaseUom,u.Name,p.Cost,p.Rate,p.Mrp,isnull(p.SerialNo,0) SerialNo,p.CostCentreId,p.AdditionP,p.NonStockItem from invProduct p 
	join invUom u on p.BaseUom=u.Id
	join invPreferredVendors v on p.Id=V.ProductId and v.VendorId=@VendorID
	where Inactive is null or Inactive = 0
Else
	insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,UOM,Cost,SRate,MRP,SerialNo,CostCentreId,AdditionP,NonStock)
	select p.ID,p.Code,p.Name,p.OtherLanguage,p.TaxGroupId,p.BaseUom,u.Name,p.Cost,p.Rate,p.Mrp,isnull(p.SerialNo,0) SerialNo,p.CostCentreId,p.AdditionP,p.NonStockItem from invProduct p 
	join invUom u on p.BaseUom=u.Id
	where Inactive is null or Inactive = 0


--Cost Centre Filtering
declare @CC table(Id int)
insert @CC
select isnull(CostCentreId,0) from invUserCostCentre where Product=1 and UserId=@UserID

if exists(select 1 from @CC)
	delete p from #Products p left join @CC c on isnull(p.CostCentreId,0)=c.Id where c.Id is null
-------

create index ind#Products on #Products(ID,UOMID)

--UOM Rates and Barcode
update p set p.UBC=u.Barcode from #Products p join invUomLevels u on p.ID=u.ProductID and p.UOMID = u.UOMID and u.Sno=1


--Aliases
insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,Cost,SRate,MRP,SerialNo,AdditionP)
select p.ID,p.Code,a.Alias,p.NativeCaption,p.TaxGroupId,p.UomId,p.Cost,p.SRate,p.MRP,isnull(p.SerialNo,0) SerialNo,p.AdditionP from #Products p join invProductAlias a on p.ID=a.ProductID


--Tax Details
update p set p.Tax=t.InputTax,p.TaxGroup=t.Name,p.TaxOnMRP=t.OnMRP from #Products p join invTaxGroup t on p.TaxGroupId = t.Id 

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code from #Products p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

-------------------

--Stock
if exists(select 1 from invOption where PurchaseDisplayStock=1 and CompanyId=@CompanyId)--Stock
Begin
	declare @PStock table(CompanyId int,ProductID int,BarcodeId int,Qty float,Pieces float)
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct where not (isnull(InActive,0)=1 or isnull(NonStockItem,0)=1)
	insert @PStock 
	exec spStock @ToDate=99999999,@Type=12,@CompanyId=@CompanyId
	create table #PStock(CompanyId int,ProductID int,Qty float,Pieces float Unique Clustered(ProductId)) 
	insert #PStock 
	select CompanyId,ProductID,sum(Qty),sum(Pieces) from @PStock group by CompanyId,ProductID
	delete #PStock where Qty=0
	update p set p.Stock=s.Qty from #Products p join #PStock s on p.ID=s.ProductID --and s.Qty<>0
End

if exists(select 1 from invOption where PurchaseRate=1 and CompanyID=@CompanyId)
Begin
	;with pd as
	(select row_number()over(partition by ProductId order by PeriodId desc,no desc)sno,pd.ProductId,pd.CostPrice,p.Cost from invPurchaseDetails pd 
	join #Products p on pd.ProductId=p.ID
	where pd.CompanyId=@CompanyId
	)

	update pd set pd.Cost=pd.CostPrice where pd.sno=1

End

if exists(select top 1 1 from invOption where DefaultSearchInPurchase=2 and CompanyId=@CompanyId)
	select Code +'       '+ Name [Code + Name],*,Cost Rate,replace(Code,'*','')Code1 from #Products
else
	select *,Cost Rate,replace(Code,'*','')Code1 from #Products order by name

drop table #Products

go


IF OBJECT_ID('prGetPurchase') IS NOT NULL
	DROP PROC prGetPurchase

GO

create proc prGetPurchase  
@CompanyID int,  
@PeriodID int,  
@VtypeId int,  
@No int as  
  
set nocount on  
set transaction isolation level read uncommitted  
  
--Temporaraly Storing Purchase Uom Details   
delete tmpPurchaseUomDetails where ProcId = @@spid  
insert tmpPurchaseUomDetails(ProcId,Sno,ProductId,UomId,LevelId,Rate)  
select @@spid,Sno,ProductId,UomId,LevelId,Rate from invPurchaseUomDetails   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No  
-----------------------------------------  
  
select t1.[No],t1.[Date],t1.[DeliveryDate],t1.[VendorId],t2.Name [Vendor],t1.[PaymentMode],t1.[InvoiceNo],  
t1.[LRNo],t1.[DueDate],t1.[Total],t1.[DiscountP],t1.[Discount],t1.[NetTotal],t1.[Notes],  
t1.[TaxCalculation],t1.[Tax],t1.[TaxType],RoundOff,Paid,t1.InterState,t1.CurrencyId,t1.FromAccountId,t1.ChequeNo,t1.ChequeDate,  
t1.Status,t1.SalesOrderRefNo,t1.Image,t1.Advance,t1.CostCentreId,t1.Discount1,t1.Discount2,t1.Discount3,t1.BillTaxGroupID,t1.BillTax,t1.Image1,t1.SalesManId,t1.Address from invPurchaseHeader t1  
join aAccount t2 on t1.VendorId = t2.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No  
  
declare @Details table(PSNo int,Code nvarchar(50),Particulars nvarchar(200),ProductId int,Warehouse varchar(50),WarehouseId int,Uom varchar(50),  
UomId int,Qty float,Foc float,FRate float,Rate float,CostPrice float,Profit float,SRate float,WRate float,Gross float,DiscountP float,Discount float,Total float,MfrDate smalldatetime,  
ExpDate smalldatetime,Remark varchar(100),TaxGroupId int,TaxGroup varchar(50),TaxP float,Tax float,IType int,IPeriodID int,INo int,ISno int,IQty float,IFOC float,Mrp float,UBC varchar(50),  
NativeCaption nvarchar(200),InactiveStock bit,NOP float,Addition float,CCode varchar(50),SerialNo bit,Point float,CostDistribution float,  
Discount1 float,NonStock bit,Pieces float,TaxOnMRP bit)  
  
insert @Details(PSNo,Code,Particulars,ProductId,WarehouseId,Uom,UomId,Qty,Foc,FRate,Rate,CostPrice,Profit,SRate,WRate,Gross,DiscountP,  
Discount,Total,MfrDate,ExpDate,Remark,TaxGroupId,Tax,IType,IPeriodID,INo,ISno,IQty,IFOC,Mrp,NativeCaption,InactiveStock,Addition,NOP,  
SerialNo,Point,CostDistribution,Discount1,NonStock,Pieces)  
select t1.[Sno] PSNo,t2.[Code],t2.Name Particulars,t1.[ProductId],t1.[WarehouseId],t4.Name Uom,  
t1.[UomId],t1.[Qty],t1.[Foc],t1.[FRate],t1.[Rate],t1.[CostPrice],t1.[Profit],t1.[SRate],t1.WRate,t1.[Gross],t1.[DiscountP],  
t1.[Discount],t1.[Total],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],  
cast(cast(case when t1.[ExpDate]<21000101 then t1.[ExpDate] end as varchar) as datetime) [ExpDate] ,t1.[Remark],  
t1.TaxGroupId,t1.Tax,  
t1.[IType],t1.IPeriodID,t1.[INo],t1.[ISno],t1.[IQty],t1.[IFOC],ISNULL(t1.Mrp,0) Mrp,  
t2.OtherLanguage NativeCaption,ISNULL(t1.InactiveStock,0) InactiveStock,t1.Addition,1 NOP,isnull(t2.SerialNo,0),Point,CostDistribution,  
Discount1,t2.NonStockItem,isnull(t1.Pieces,0) from invPurchaseDetails t1  
join invProduct t2 on t1.ProductId = t2.Id   
join invUom t4 on t1.UomId = t4.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No    
  
  
--Category Codes  
declare @@CatPropID int  
select @@CatPropID=CategoryPropertyID from invOption where CompanyID=@CompanyID  
  
declare @Category table(ProductID int,Code varchar(50))  
  
if @@CatPropID is not null  
Begin  
 insert @Category  
 select pp.ProductID,sp.Code from invProductPropertyDetails pp join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID  
End  
  
update d set d.CCode=c.Code from @Details d join @Category c on d.ProductID=c.ProductID  
  
--Barcode  
update d set d.UBC=ul.Barcode from @Details d join invUOMLevels ul on d.ProductID=ul.ProductID and d.UOMId=ul.UOMID  
  
--WareHouse  
update d set d.WareHouse=w.Name from @Details d join invWareHouse w on d.WarehouseID=w.ID  
  
--Tax Group  
update d set d.TaxGroup=t.Name,d.TaxP=t.InputTax,d.TaxOnMRP=t.OnMRP from @Details d join invTaxGroup t on d.TaxGroupID=t.ID   
  
--NOP  
update d set d.NOP=ul.Multiplayer from @Details d join invUOMLevels ul on d.ProductID=ul.ProductID and ul.Secondary<>1 and ul.SNo<3  
  
--Final Selection  
select * from @Details order by PSno  
---------------------------  
  
select SNo,BarcodeId,Barcode,SRate,Printed,Sticker from invAutoBarcodeAndSalesRate   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No order by Sno  
  
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1  
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id   
join invPurchaseProperty t3 on t2.PropertyId = t3.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No order by t1.Sno   
  
select [PSno],[Sno],[SerialNo],[Id] from invProductSerialNumber   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No   
order by [PSno],[Sno]  
  
select a.CreditorID,c.Name Creditor,a.DebtorID,d.Name Debtor,a.Description,a.Amount,a.DNo from invPurchaseAdditions a  
join aAccount c on a.CreditorID=c.ID  
join aAccount d on a.DebtorID=d.ID  
where a.CompanyID = @CompanyID and a.PeriodID  = @PeriodID and a.[VtypeId] = @VtypeId and a.[No] = @No   
  
  
select t.ProductID,p.Name Product,t.OB,t.[In],t.[Out],t.Balance from invPurchaseTrayDetails t  
join invProduct p on t.ProductID=p.ID  
where t.CompanyID = @CompanyID and t.PeriodID  = @PeriodID and t.[VtypeId] = @VtypeId and t.[No] = @No   
  
GO

if object_id('prGetSales') is not null
	drop proc prGetSales
go

create proc prGetSales
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int as
set nocount on
declare @Header table(
No int,Date int,DeliveryDate int,
CustomerId int,Customer nvarchar(100),
PaymentMode tinyint,SalesManId int,
RateLevelId int,DueDate int,
QuotationNo int,Total float,DiscountP float,
Discount float,NetTotal float,
Notes nvarchar(4000),Tax float,SalesReturn float,
TaxCalculation int,Collected bit,
Rep1 varchar(100),Rep2 varchar(100),Paid float,RoundOff float,
Advance float,AirwayBillNo varchar(50),Time int,Addition float,
PrePrintingString varchar(100),FromTime int,ToTime int,JobId int,
JobCustomer nvarchar(200),Work nvarchar(max),AdditionalWork nvarchar(max),
ReturnId int,SRNo int,CostCentreId int,ShippingId int,ShippingNo varchar(50),
ShippingCode varchar(50),CreditCardID int,Address nvarchar(300),InterState bit,
CardId int,PaidBy tinyint,TaxGroupID int,BillTax float,LocalMobileNo varchar(100),Approve bit,TokenNo int,
Remark1 nVarchar(2000),Remark2 nVarchar(2000),Remark3 nVarchar(500),Remark4 nVarchar(500),EInvoice int,NotEdit bit,
Remark5 nVarchar(2000),Remark6 nVarchar(2000),Remark7 nVarchar(2000),Remark8 nVarchar(2000),Remark9 nVarchar(2000),Remark10 nVarchar(2000),
Remark11 nVarchar(2000),Remark12 nVarchar(2000),Discount1 float,Discount2 float,Discount3 float,EWay bit)

declare @Redempted int 

insert @Header(No,Date,DeliveryDate,CustomerId,PaymentMode,SalesManId,RateLevelId,DueDate,
QuotationNo,Total,DiscountP,Discount,NetTotal,Notes,Tax,SalesReturn,TaxCalculation,Rep1,Rep2,Paid,
RoundOff,Advance,AirwayBillNo,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnID,
CostCentreId,ShippingId,ShippingNo,CreditCardID,Address,InterState,CardId,PaidBy,TaxGroupID,BillTax,
LocalMobileNo,Approve,TokenNo,Remark1,Remark2,Remark3,Remark4,EInvoice,NotEdit,
Remark5,Remark6,Remark7,Remark8,Remark9,Remark10,Remark11,Remark12,Discount1,Discount2,Discount3,eway)
select No,Date,DeliveryDate,CustomerId,PaymentMode,SalesManId,RateLevelId,DueDate,QuotationNo,Total,
DiscountP,Discount,NetTotal,Notes,Tax,SalesReturn,TaxCalculation,Rep1,Rep2,Paid,RoundOff,Advance,AirwayBillNo,
Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnID,CostCentreId,ShippingId,ShippingNo,CreditCardID,
Address,InterState,cardid,h.PaidBy,h.TaxGroupID,h.BillTax,h.LocalMobileNo,h.Approve,h.TokenNo,Remark1,Remark2,Remark3,Remark4,
h.EInvoice,h.NotEdit,h.Remark5,h.Remark6,h.Remark7,h.Remark8,h.Remark9,h.Remark10,h.Remark11,h.Remark12,h.Discount1,h.Discount2,
h.Discount3,h.Eway from invSalesHeader h
where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and No = @No

--Customer
update h set h.Customer=a.Name from @Header h join aAccount a on h.CustomerID=a.ID

select @Redempted = Redempted from invPrivilegeCardSales 
where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and No = @No

update h set h.Collected=1 from @Header h join invCashCollection cc on cc.No=h.No where cc.VtypeId=@VtypeId and cc.CompanyId=@CompanyId and cc.PeriodId=@PeriodId
update h set h.JobCustomer=j.Customer,h.Work=j.Work,h.AdditionalWork=j.AdditionalWork from @Header h join invJobForm j on h.JobId = j.Id
update h set h.SRNo=sr.No from @Header h join invSalesReturnHeader sr on h.ReturnId = sr.Id
update h set h.ShippingCode=s.Code from @Header h join invShippingMethode s on h.ShippingId = s.Id

select *,@Redempted Redempted from @Header

declare @Details table(Sno int,Code varchar(50),Particulars nvarchar(200),SalesmanID int,Salesman varchar(50),NativeCaption nvarchar(200),
ProductId int,Warehouse varchar(50),WarehouseId int,Uom nvarchar(50),UomId int,Qty float,Foc float,Pieces float,Rate float,MRP float,
Gross float,Addition float,DiscountP float,Discount float,Total float,MfrDate smalldatetime,ExpDate smalldatetime,Remark nvarchar(1000),
BarcodeId int,Barcode varchar(50),TaxGroupId int,TaxGroup varchar(50),TaxP float,Tax float,IType int,IPeriodId int,INo int,ISno int,
IQty float,IFOC float,SerialNoId int,SerialNo varchar(100),FType tinyint,NOP float,ARate float,NonStock bit,Length float,Width float,
TaxInclusive bit,CCode varchar(50),CategoryID int,ATaxGroupID int,Addition1 float,WRate float,PAddition float,HaveSerialNo bit,
TAddition float,Addition2 float,AdditionP float,Cost float,Remark1 nvarchar(100),TaxOnMRP bit)

insert @Details(Sno,Code,Particulars,SalesmanID,NativeCaption,ProductId,WarehouseId,Uom,UomId,Qty,Foc,Pieces,Rate,MRP,Gross,Addition,DiscountP,
Discount,Total,MfrDate,ExpDate,Remark,BarcodeID,TaxGroupId,Tax,IType,IPeriodId,INo,ISno,IQty,IFOC,SerialNoId,SerialNo,FType,ARate,NonStock,
Length,Width,TaxInclusive,ATaxGroupID,Addition1,WRate,PAddition,HaveSerialNo,Addition2,AdditionP,Cost,Remark1)

select t1.Sno,t2.Code,t2.Name,t1.SalesmanID,t2.OtherLanguage,t1.ProductID,t1.WareHouseID,t4.Name,t1.UomId,t1.Qty,t1.Foc,t1.Pieces,t1.Rate,t1.MRP,t1.Gross,t1.Addition,t1.DiscountP,t1.Discount,t1.Total,
cast(cast(case when t1.MfrDate between 19000101 and 21000000 then  t1.MfrDate end as varchar) as smalldatetime),
cast(cast(case when t1.ExpDate between 19000101 and 21000000 then  t1.ExpDate end as varchar) as smalldatetime),t1.Remark,t1.BarcodeID,t1.TaxGroupId,t1.Tax,t1.IType,t1.IPeriodId,t1.INo,t1.ISno,t1.IQty,t1.IFOC,
isnull(t1.SerialNoId,0),isnull(t5.SerialNo,''),t1.FType,t1.ARate,t2.NonStockItem,t1.Length,t1.Width,t2.TaxInclusive,t2.TaxGroupId,t1.Addition1,t2.WRate,t2.Addition,t2.SerialNo,t1.Addition2,t2.AdditionP,t1.Cost,t1.Remark1
from invSalesDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
join invUom t4 on t1.UomId = t4.Id
left outer join invProductSerialNumber t5 on t1.SerialNoId = t5.Id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No

update t1 set t1.SalesMan=t2.Name from @Details t1 join invSalesMan t2 on t1.SalesmanID=t2.Id
update t1 set t1.WareHouse=t2.Name from @Details t1 join invWareHouse t2 on t1.WareHouseID=t2.Id
update t1 set t1.Barcode=t5.Barcode from @Details t1 join invAutoBarcodeAndSalesRate t5 on t1.ProductId = t5.ProductId and t1.BarcodeId = t5.BarcodeId
update t1 set t1.Barcode=t5.Barcode from @Details t1 join invUOMLevels t5 on t1.ProductId = t5.ProductId and t1.UOMID = t5.UOMID where t1.Barcode is null
update t1 set t1.TaxGroup=t2.Name,t1.TaxP=t2.OutPutTax,t1.TAddition=t2.Addition,t1.TaxOnMRP=t2.OnMRP from @Details t1 join invTaxGroup t2 on t1.TaxGroupID=t2.Id
update t1 set t1.NOP=t2.Multiplayer from @Details t1 join invUOMLevels t2 on t1.ProductID=t2.ProductID and t2.Secondary<>1 and t2.SNo<3
update @Details set NOP=1 where NOP is null
update @Details set FType=1 where FType is null



--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption where CompanyID=@CompanyID

if @@CatPropID is not null
	update p set p.CCode=sp.Code,p.CategoryID=pp.SubPropertyId from @Details p join invProductPropertyDetails pp on p.ProductID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

select *,Sno USNo from @Details order by SNo

select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invSalesPropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No order by t1.Sno 

--Product Serial Number
select t1.USno,t1.Sno,t1.SerialNoId Id,isnull(t2.SerialNo,t1.SerialNo)SerialNo from invSalesProductSerialNumber t1
left join invProductSerialNumber t2 on t1.SerialNoId = t2.Id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No 
order by t1.USNo,t1.Sno 

select a.DebtorID,d.Name Debtor,a.CreditorID,c.Name Creditor,a.Description,a.Amount from invSalesAdditions a
join aAccount c on a.CreditorID=c.ID
join aAccount d on a.DebtorID=d.ID
where a.CompanyID = @CompanyID and a.PeriodID  = @PeriodID and a.[VtypeId] = @VtypeId and a.[No] = @No 


select t.ProductID,p.Name Product,t.OB,t.[In],t.[Out],t.Balance from invSalesTrayDetails t
join invProduct p on t.ProductID=p.ID
where t.CompanyID = @CompanyID and t.PeriodID  = @PeriodID and t.[VtypeId] = @VtypeId and t.[No] = @No 

go

if object_id('spReportPurchaseTaxReturn1') is not null drop proc spReportPurchaseTaxReturn1

go

create proc spReportPurchaseTaxReturn1
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

declare @TR table(CompanyId int,VtypeId int,GST varchar(50),No int,InvoiceNo varchar(50),Date smalldatetime,Vendor nvarchar(100),InvDate datetime,InterState bit,ProductID int,Item varchar(50),HSN varchar(50),Qty float,TaxP float,Taxable float,Tax float,CESS float,Total float,VendorId int,
Description nvarchar(200),AdditionalDescription nvarchar(200))


--Purchase
insert @TR(CompanyId,VtypeId,No,InvoiceNo,Date,InvDate,InterState,ProductID,Qty,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,sh.VtypeId,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sh.InterState,sd.ProductID,Qty,case when sh.TaxType=0 then t.InputTax end,sd.Gross-case when sh.TaxCalculation=1 then sd.Discount else 0 end,sd.Tax,sd.Addition,sd.Total,sh.VendorId from invPurchaseHeader sh
join invPurchaseDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
left join invTaxGroup t on sd.TaxGroupID=t.ID
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Purchase Return
insert @TR(CompanyId,VtypeId,No,InvoiceNo,Date,InvDate,ProductID,Qty,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,sh.VtypeId,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sd.ProductID,-Qty,case when sh.TaxType=1 then t.InputTax end,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition,-sd.Total,sh.VendorId from invPurchaseReturnHeader sh
join invPurchaseReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate

declare @CTVtype int
select @CTVtype=AccountVtypeID from invVoucherTypeDetails where VtypeId=16

--Company Transfer
insert @TR(CompanyId,VtypeId,No,Date,ProductID,Qty,TaxP,Taxable,Tax,Total,VendorId)
select sh.CompanyTo,@CTVtype,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
sd.ProductID,Qty,t.InputTax,sd.Gross,sd.Tax,sd.Total,c.AccountId from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on @CTVtype=v.ID
join aCompany c on c.Id=sh.CompanyFrom
where (sh.CompanyTo=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Journal
insert @TR(CompanyId,VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description)
select sh.CompanyId,avs.Journal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,case when sh.DrCr=1 then sh.AccountID else sd.AccountID end,Description from aJournalHdr sh
join aJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on case when sh.DrCr=1 then sd.AccountID else sh.AccountID end=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.Journal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0



--Multi Journal
insert @TR(CompanyId,VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description,AdditionalDescription)
select sh.CompanyId,avs.MultiJournal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,sd.CreditorID,sd.Description,sd.AdditionalDescription from aMultiJournalHdr sh
join aMultiJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on sd.DebtorID=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.MultiJournal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0


--HSN
update t set t.Item=psp.Name,t.HSN=psp.Code from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--Vendor Details
update tr set tr.GST=isnull(c.GST,c.TIN),tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invVendor c on tr.VendorId=c.AccountID
update tr set tr.GST=isnull(c.GST,c.TIN),tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invCustomer c on tr.VendorId=c.AccountID
update tr set tr.Vendor=a.Name from @TR tr join aAccount a on tr.VendorId=a.Id where tr.Vendor is null


--Final Date
select c.Name Company,c.Code CCode,vd.Code Vtype,GST,No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,sum(Qty)Qty,TaxP,sum(Taxable)Taxable,sum(Tax)Tax,sum(CESS)CESS,sum(Total)Total from @TR t
join aVoucherType vd on t.VtypeId=vd.Id
join aCompany c on c.Id=t.CompanyId
group by c.Name,c.Code,vd.Code,GST,No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,TaxP

go

if object_id('spReportPurchaseTaxReturn') is not null drop proc spReportPurchaseTaxReturn

go

create proc spReportPurchaseTaxReturn
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

declare @TR table(CompanyId int,GST varchar(50),TRN varchar(50),VtypeId int,No int,InvoiceNo varchar(50),Date smalldatetime,Vendor nvarchar(100),InvDate datetime,
InterState bit,ProductID int,Item varchar(50),HSN varchar(50),UOM varchar(50),Qty float,Rate float,TaxP float,Taxable float,Tax float,CESS float,Total float,VendorId int,
Description nvarchar(200),AdditionalDescription nvarchar(200))


--Purchase
insert @TR(CompanyId,VtypeId,No,InvoiceNo,Date,InvDate,InterState,ProductID,Uom,Qty,Rate,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,v.Id,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sh.InterState,sd.ProductID,u.Name UOM, Qty,sd.Rate,t.InputTax,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Total,sh.VendorId
from invPurchaseHeader sh 
join invPurchaseDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Purchase Return
insert @TR(CompanyId,GST,VtypeId,No,InvoiceNo,Date,Vendor,InvDate,ProductID,Uom, Qty,Rate,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,c.GST,v.Id,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,c.Name Vendor,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sd.ProductID,u.Name UOM, -Qty,sd.Rate,t.InputTax,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition,-sd.Total,sh.VendorId from invVendor c
join invPurchaseReturnHeader sh on c.AccountID=sh.VendorID
join invPurchaseReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate

declare @CTVtype int
select @CTVtype=AccountVtypeID from invVoucherTypeDetails where VtypeId=16

--Company Transfer
insert @TR(CompanyId,VtypeId,No,Date,ProductID,UOM,Qty,Rate,TaxP,Taxable,Tax,Total,VendorId)
select CompanyTo,v.Id,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
sd.ProductID,u.Name UOM, Qty,sd.Rate,t.InputTax,sd.Gross,sd.Tax,sd.Total,c.AccountId from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join @VType v on @CTVtype=v.ID
join aCompany c on c.Id=sh.CompanyFrom
where (sh.CompanyTo=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Journal
insert @TR(CompanyId,VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description)
select sh.CompanyId,avs.Journal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,case when sh.DrCr=1 then sh.AccountID else sd.AccountID end,sd.Description from aJournalHdr sh
join aJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on case when sh.DrCr=1 then sd.AccountID else sh.AccountID end=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.Journal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0



--Multi Journal
insert @TR(CompanyId,VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description,AdditionalDescription)
select sh.CompanyId,avs.MultiJournal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,sd.CreditorID,sd.Description,sd.AdditionalDescription from aMultiJournalHdr sh
join aMultiJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on sd.DebtorID=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.MultiJournal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0


--HSN
update t set t.Item=psp.Name,t.HSN=psp.Code from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--Vendor Details
update tr set tr.GST=c.GST,tr.TRN=c.TIN,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invVendor c on tr.VendorId=c.AccountID
update tr set tr.GST=c.GST,tr.TRN=c.TIN,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invCustomer c on tr.VendorId=c.AccountID
update tr set tr.Vendor=a.Name from @TR tr join aAccount a on tr.VendorId=a.Id where tr.Vendor is null


--Final Date
select c.Name Company,GST,TRN,v.Code VType,No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,UOM, sum(Qty)Qty,Rate,TaxP,sum(Taxable)Taxable,sum(Tax)Tax,sum(CESS)CESS,sum(Total)Total from @TR t
join aVoucherType v on t.VtypeId=v.Id
join aCompany c on t.CompanyId=c.Id
group by c.Name,GST,TRN,v.Code, No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,UOM, Rate,TaxP

go

if object_id('spReportPurchaseTaxReturn2') is not null drop proc spReportPurchaseTaxReturn2

go

create proc spReportPurchaseTaxReturn2
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

declare @TR table(CompanyId int,GST varchar(50),No int,InvoiceNo varchar(50),Date smalldatetime,DDate smalldatetime,Vendor nvarchar(100),InvDate datetime,
InterState bit,ProductID int,Item varchar(100),HSN varchar(50),UOMId int,UOM varchar(50),Qty float,Rate float,Discount float,TaxP float,Taxable float,Tax float,CESS float,Total float,VendorId int,
Description nvarchar(200),AdditionalDescription nvarchar(200))


--Purchase
insert @TR(CompanyId,No,InvoiceNo,Date,DDate,InvDate,InterState,ProductID,UOMId,Qty,Rate,Discount,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sh.InterState,sd.ProductID,sd.UOMId,Qty,sd.Rate,sd.Discount,t.InputTax,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Total,sh.VendorId from invPurchaseHeader sh
join invPurchaseDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Purchase Return
insert @TR(CompanyId,GST,No,InvoiceNo,Date,DDate,Vendor,InvDate,ProductID,UOMId,Qty,Rate,Discount,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,c.GST,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,c.Name Vendor,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sd.ProductID,sd.UOMId,-Qty,sd.Rate,sd.Discount,t.InputTax,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition,-sd.Total,sh.VendorId from invVendor c
join invPurchaseReturnHeader sh on c.AccountID=sh.VendorID
join invPurchaseReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0)  and sh.Date between @FromDate and @ToDate

declare @CTVtype int
select @CTVtype=AccountVtypeID from invVoucherTypeDetails where VtypeId=16

--Company Transfer
insert @TR(CompanyId,No,Date,ProductID,UOMId,Qty,Rate,TaxP,Taxable,Tax,Total,VendorId)
select sh.CompanyTo,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
sd.ProductID,sd.UOMId,Qty,sd.Rate,t.InputTax,sd.Gross,sd.Tax,sd.Total,c.AccountId from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on @CTVtype=v.ID
join aCompany c on c.Id=sh.CompanyFrom
where (sh.CompanyTo=@CompanyID or @CompanyID=0)  and sh.Date between @FromDate and @ToDate


--Journal
insert @TR(CompanyId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description)
select sh.CompanyId,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,case when sh.DrCr=1 then sh.AccountID else sd.AccountID end,sd.Description from aJournalHdr sh
join aJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on case when sh.DrCr=1 then sd.AccountID else sh.AccountID end=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.Journal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0



--Multi Journal
insert @TR(CompanyId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description,AdditionalDescription)
select sh.CompanyId,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,sd.CreditorID,sd.Description,sd.AdditionalDescription from aMultiJournalHdr sh
join aMultiJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on sd.DebtorID=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.MultiJournal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0


--Item
update t set t.Item=p.Name from @TR t join invProduct p on t.ProductId=p.Id


--HSN
update t set t.HSN=psp.Code from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--UOM
update t set t.UOM=u.Name from @TR t join invUOM u on t.UOMId=u.Id


--Vendor Details
update tr set tr.GST=c.GST,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invVendor c on tr.VendorId=c.AccountID
update tr set tr.GST=c.GST,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invCustomer c on tr.VendorId=c.AccountID
update tr set tr.Vendor=a.Name from @TR tr join aAccount a on tr.VendorId=a.Id where tr.Vendor is null

--PR IGST
update tr set tr.InterState=1 from @TR tr where SUBSTRING(GST,1,2)<>'32' and Qty<0


--Final Date
select c.Name Company,GST,No,InvoiceNo,Date,DDate,Vendor,InvDate,InterState,Item,HSN,UOM,sum(Qty)Qty,Rate,Sum(Discount)Discount,TaxP,sum(Taxable)Taxable,sum(Tax)Tax,sum(CESS)CESS,sum(Total)Total from @TR t
join aCompany c on t.CompanyId=c.Id
group by c.Name,GST,No,InvoiceNo,Date,DDate,Vendor,InvDate,InterState,Item,HSN,UOM,Rate,TaxP

go

if OBJECT_ID('prPurchaseReturnDetailsPrint') is not null
	drop proc prPurchaseReturnDetailsPrint
go
create proc prPurchaseReturnDetailsPrint
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int as

set nocount on
set transaction isolation level read uncommitted

declare @PR table(SNo int,ProductID int,UOMID int,BarcodeID int,Barcode varchar(50),Code varchar(50),Particulars varchar(200),OtherLanguage nvarchar(200),CategoryCode varchar(50),WareHouse varchar(50),UOM varchar(50),Qty float,FOC float,Rate float,Gross float,DiscountP float,Discount float,Total float,MfrDate smalldatetime,ExpDate smalldatetime,Remark varchar(100),TaxP float,Tax float,SerialNoId int,SerialNo varchar(50),AdditionP float,Addition float)

insert @PR(SNo,ProductID,UOMID,BarcodeID,Code,Particulars,OtherLanguage,CategoryCode,WareHouse,UOM,Qty,FOC,Rate,Gross,DiscountP,Discount,Total,MfrDate,ExpDate,Remark,TaxP,Tax,SerialNoId,AdditionP,Addition)
select t1.[Sno],t1.ProductID,t1.UOMID,t1.BarcodeID,t2.[Code], t2.Name Particulars,
t2.OtherLanguage,null,t3.Name Warehouse,t4.Name Uom,
t1.[Qty],t1.[Foc],t1.[Rate],t1.[Gross],t1.[DiscountP],
t1.[Discount],t1.[Total],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],
cast(cast(t1.[ExpDate] as varchar) as datetime) [ExpDate] ,t1.[Remark],t.InputTax TaxP,t1.Tax,t1.SerialNoId,t2.AdditionP,t1.Addition from invPurchaseReturnDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
left outer join invWarehouse t3 on t1.WarehouseId = t3.Id 
join invUom t4 on t1.UomId = t4.Id 
left join invTaxGroup t on t1.taxgroupid=t.id
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No 
order by t1.Sno 

--Barcode
update p set p.Barcode=u.Barcode from @PR p join invUOMLevels u on p.ProductID = u.ProductID and p.UomId = u.UomId

--Auto Barcode
update p set p.Barcode=b.Barcode from @PR p join invAutoBarcodeAndSalesRate b on p.ProductId = b.ProductId and p.BarcodeId = b.BarcodeId 

--Category Code
declare @CategoryPropertyId int
select @CategoryPropertyId = isnull(CategoryPropertyId,0) from invOption where CompanyId = @CompanyId

update t1 set t1.CategoryCode = t3.Code from  @PR t1
join invProductPropertyDetails t2 on t1.ProductId = t2.ProductId and t2.PropertyId = @CategoryPropertyId
join invProductSubProperty t3 on t2.SubPropertyId = t3.Id

--SerialNo
update p set p.SerialNo=s.SerialNo from @PR p join invProductSerialNumber s on p.SerialNoId=s.Id

select * from @PR

go


if object_id('prGetLabelPrintCollection') is not null 
	drop proc prGetLabelPrintCollection

go

create proc prGetLabelPrintCollection  
@xmlBarcode nvarchar(4000),  --xml (changed due to arabic problem)
@BlankLabels tinyint  
  
as  
  
declare @Idoc int  
exec sp_xml_preparedocument @Idoc out,@xmlBarcode  
  
select null Sno,null Code,null Name,cast(null as nvarchar(100)) OtherLanguage,null VendorCode,null Vendor,null Barcode,
null Cost,null Rate,null NRate,null EncryptedCost,null EncryptedRate,null Size,null Remark,null MRP,
null Property1,null Property2,null Property3 ,null MfrDate ,null  ExpDate,null PProperty1,null PProperty2,null UOM,null SCount,null Sticker,null WRate , null EncryptedWRate from master..spt_values where type
='P' and number<@BlankLabels  
union all  
select SNo,Code,x.Name,OtherLanguage,VendorCode,Vendor,Barcode,Cost,Rate,NRate,EncryptedCost,EncryptedRate,Size,Remark,
MRP,Property1,Property2,Property3,MfrDate,ExpDate,PProperty1,PProperty2,UOM,n.number+1,x.Sticker,WRate ,EncryptedWRate from openxml (@Idoc,'/TableHeader/Table1',2)  
with  
(  
SNo int '@Sno',
Code varchar(100) '@Code',  
Name nvarchar(100) '@Name',  
OtherLanguage nvarchar(100) N'@OtherLanguage',  
VendorCode nvarchar(100) '@VendorCode',  
Vendor varchar(100) '@Vendor',  
Barcode varchar(100) '@Barcode',  
Sticker int '@Sticker',  
Cost float '@Cost',  
Rate float '@SRate',
NRate float '@NRate',
MRP float '@MRP',  
EncryptedCost varchar(25) '@EncryptedCost',  
EncryptedRate nvarchar(25) '@EncryptedRate', 
Size varchar(50) '@Size',  
Remark varchar(100) '@Remark',  
Property1 varchar(50) '@Property1',  
Property2 varchar(50) '@Property2',  
Property3 varchar(50) '@Property3',  
Printed bit '@Printed'  ,
MfrDate DateTime '@MDate' ,
ExpDate DateTime '@EDate',
PProperty1 varchar(50) '@PProperty1',  
PProperty2 varchar(50) '@PProperty2',
UOM varchar(50) '@UOM',
EncryptedWRate nvarchar(25) '@EncryptedWRate',  
WRate nvarchar(25) '@WRate'
) x  
join master..spt_values n on n.number<x.Sticker  
where x.Printed=0 and n.type='P'  
order by SNo
  
exec sp_xml_removedocument @Idoc  
  
GO

if OBJECT_ID('prGetSalesReturnAmount') is not null
	drop proc prGetSalesReturnAmount
go

create proc prGetSalesReturnAmount
@CompanyID int,
@Date int,
@SRNo int,
@No int 

as

set transaction isolation level read uncommitted
set nocount on

declare @Flag int

declare @T1 table (Id int,NetTotal float)

insert @T1 
select top 1 Id,NetTotal from invSalesReturnHeader
where CreditNote=1 and CompanyID = @CompanyID and Date<=@Date and [No] = @SRNo 
order by PeriodId desc


select @Flag = No from invSalesHeader where ReturnId in (select Id from @T1) 
and CompanyID = @CompanyID and Date<= @Date and No <> @No


select Id,NetTotal,isnull(@Flag,0) Flag,@SRNo SRNo from @T1

go




if object_id('spGetLastSalesDetails') is not null drop proc spGetLastSalesDetails

go

create proc spGetLastSalesDetails
@ProductID int,
@CustomerId int=0,
@CompanyId int=1

as

declare @SD table(Date int,Vtype varchar(50),No int,Customer nvarchar(100),UOM varchar(50),Rate float,NRate float,Qty float,FOC float)

--Sales
insert @SD(Date,VType,No,Customer,UOM,Rate,NRate,Qty,FOC)
select h.Date,h.VtypeId,h.No,h.CustomerId,d.UomId,d.Rate,SUM(d.Total) /nullif(SUM(d.Qty),0) NRate,SUM(d.Qty),SUM(d.foc) from invSalesDetails d 
join invSalesHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
where d.ProductId=@ProductID and (h.CustomerId=@CustomerID or @CustomerID=0) and d.CompanyId=@CompanyId
GROUP BY h.Date,h.No,h.CustomerId,d.UomId,d.Rate,h.VtypeId


--Sales Return
insert @SD(Date,VType,No,Customer,UOM,Rate,NRate,Qty,FOC)
select h.Date,h.VTypeId,h.No,h.CustomerId,d.UomId,d.Rate,d.Total/nullif(d.Qty,0) NRate,-d.Qty,-d.Foc from invSalesReturnDetails d 
join invSalesReturnHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
where d.ProductId=@ProductID and (h.CustomerId=@CustomerID or @CustomerID=0) and d.CompanyId=@CompanyId


--POS Sales
if OBJECT_ID('pSalesDetails') is not null and OBJECT_ID('pSalesHeader') is not null 
	insert @SD(Date,VType,No,Customer,UOM,Rate,NRate,Qty,FOC)
	select h.Date,h.VtypeId,h.No,h.CustomerId,d.UomId,d.Rate,d.Total/d.Qty NRate,d.Qty,d.Foc from pSalesDetails d 
	join pSalesHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
	where d.ProductId=@ProductID and (h.CustomerId=@CustomerID or @CustomerID=0) and d.CompanyId=@CompanyId

--Customer
update s set s.Customer=c.Name from @SD s join aAccount c on s.Customer=c.ID

--UOM
update s set s.UOM=u.Name from @SD s join invUom u on s.UOM=u.Id

--VType
update s set s.Vtype=v.Name from @SD s join invVoucherTypeDetails v on s.Vtype=v.Id

--Final
select cast(cast(Date as varchar) as smalldatetime)Date,VType,No,Customer,UOM,Rate,NRate,Qty,FOC from @SD order by Date desc


go

if OBJECT_ID('prQuotationHeaderPrint') is not null
	drop proc prQuotationHeaderPrint
go

create proc prQuotationHeaderPrint
@CompanyId int,
@PeriodId int, 
@No int as
set nocount on

 
select t1.[No],cast(cast(t1.[Date] as varchar) as datetime) [Date],
cast(cast(t1.[ValidUpto] as varchar) as datetime) [ValidUpto],t2.Name [Customer],t4.Name NickName,
t3.Name [RateLevel],isnull(t1.[ReviseNo],0) / 100 [ReviseNo],t1.[RefferenceNo], 
t1.[Total],isnull(t1.[DiscountP],0) [DiscountP],isnull(t1.[Discount],0) [Discount],t1.[NetTotal],t1.[Notes],
t4.Address1,t4.Address2,t4.Address3,T4.Place,t4.Phone,t4.MobileNo,t4.Email,t4.ContactPerson,t4.[FileNo],
t4.PaymentTerms,t4.[DLNo1],t4.[DLNo2],t4.[CST],t4.[Address4],t4.[Address5],t4.[Address6],t4.[Address7],t4.[Address8],t4.[Address9],
t1.Subject ,isnull(t1.[Attention],'') [Attention],
isnull(t1.[InqRef],0) [InqRef],cast(cast(t1.[InqDate] as varchar) as datetime) [InqDate],
isnull(t4.GST,'') GST,isnull(t4.TIN,'') TIN,
S.NAME SALESMAN,t1.Address,t2.NameinOL,t1.BillTax,j.Colour,j.ModelName,j.ModelNo,j.VehicleNo,j.VehicleNo2
from invQuotationHeader t1
join aAccount t2 on t1.CustomerId = t2.Id 
left outer join invRateLevel t3 on t1.[RateLevelId] = t3.Id
join invCustomer t4 on t1.CustomerId = t4.AccountID 
LEFT OUTER JOIN INVSALESMAN S ON T1.SALESMANID=S.ID
left join invJobForm j on t1.RefferenceNo=j.JobNo and t1.Date>=j.Date
where  t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[No] = @No

go

if object_id('spStock') is not null 
	drop proc spStock

go

create proc spStock
@CompanyID int=0,
@CostCentreId int=0,
@WHID int=0,
@FromDate int=0,
@ToDate int,
@Type float output

as

set nocount on
set transaction isolation level read uncommitted

declare @FirstCompanyId int
select @FirstCompanyId=min(Id) from aCompany

declare @DefaultWareHouseID int,@PRateCalculation tinyint,@StockCalculation tinyint,@CompanyTransferApproval bit,@SalesApproval bit,@WareHouseTransferCrossChecking bit,@SalesCostwiseStock bit,@PurchaseCPCalculation int,@StockwithBarcodeOnly bit,@CostCentreIndependentReports bit,@InActiveStock bit
select @DefaultWareHouseID=DefaultWareHouseID,@PRateCalculation=PRateCalculation,@StockCalculation=StockCalculation,@CompanyTransferApproval=isnull(CompanyTransferApproval,0),@SalesApproval=isnull(SalesApproval,0),@WareHouseTransferCrossChecking=isnull(WareHouseTransferCrossChecking,0),@SalesCostwiseStock=isnull(SalesCostwiseStock,0),@PurchaseCPCalculation=isnull(PurchaseCPCalculation,0),@StockwithBarcodeOnly=isnull(StockwithBarcodeOnly,0),@CostCentreIndependentReports=CostCentreIndependentReports,@InActiveStock=InActiveStock from invOption where CompanyID=case when @CompanyID=0 then @FirstCompanyId else @CompanyID end --0-WA,1-Last,2-Master

if @CostCentreIndependentReports=1
	set @CostCentreId=0

declare @WHCostCentreId int
select @WHCostCentreId=CostCentreId from invWarehouse where Id=@WHID

declare @CostCentreWHID int
select @CostCentreWHID=Id from invWarehouse where CostCentreId=@CostCentreId

create table #Stock
(
CompanyID int,
InOut bit,
TransactionID tinyint,
WHID int,
CostCentreId int,
ProductID int,
UOMID int,
BarcodeID int,
SerialNoId int,
Rate float,
Qty float,
FOC float,
Discount float,
Tax float,
CP float,
SRate float,
WRate float,
MRP float,
Date int,
VTypeId int,
No int,
ROQty float,
Pieces float,
SNo int
)

create table #tmpProduct(ID int,BarcodeID int,TaxGroupId int)

declare @DefaultCostCentreID int
select @DefaultCostCentreID=CostCentreId from invWarehouse where Id=@DefaultWareHouseID

if @Type is null
	insert #tmpProduct(ID,TaxGroupId) 
	select ID,TaxGroupId from invProduct where (inactive is null or inactive=0 or @InActiveStock=1) and (NonStockItem=0 or NonStockItem is null) and (SerialNo=0 or SerialNo is null or @StockCalculation<2)
else if @Type in(0,3)
	insert #tmpProduct(ID,TaxGroupId) 
	select ID,TaxGroupId from invProduct where (inactive is null or inactive=0 or @InActiveStock=1) and (NonStockItem=0 or NonStockItem is null) 
else if @Type = 10
    insert #tmpProduct(ID,BarcodeID,TaxGroupId)select t.ID,t.BarcodeID,p.TaxGroupId from tmpTable t join invProduct p on t.ID=p.Id where SPID=@@spid
else if @Type = 13
	insert #tmpProduct(ID,BarcodeID,TaxGroupId)
	select t.ID,t.BarcodeID,TaxGroupId from tmpTable t join invProduct p on t.ID=p.Id where SPID=@@spid
else if @Type = 1
	insert #tmpProduct(ID,BarcodeID)
	select t.ID,t.BarcodeID from tmpTable t 
	--join invProduct p on t.ID=p.Id 
	where SPID=@@spid
else
	insert #tmpProduct(ID,BarcodeID)
	select t.ID,t.BarcodeID from tmpTable t join invProduct p on t.ID=p.Id 
	where (p.NonStockItem=0 or p.NonStockItem is null) and SPID=@@spid
	
update #tmpProduct set BarcodeID=null where BarcodeId=0

declare @AutoBarCode bit
select @AutoBarCode=AutoBarCode from invProjectSettings where CompanyId=case when @CompanyID=0 then @FirstCompanyId else @CompanyID end

declare @UBC bit
select top 1 @UBC=1 from invUOMLevels where Barcode is not null


--Stock In

--Opening Stock

insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,SRate,Date,MRP)
select @CompanyID,1, null,p.ID,BaseUom,Cost,OpeningStock,Rate,0,MRP from invProduct p
join #tmpProduct t on p.ID=t.ID
where OpeningStock <>0 and  (inactive is null or inactive=0 or @InActiveStock=1) and (NonStockItem=0 or NonStockItem is null) 
and (@WHID=0 or @DefaultWareHouseID=@WHID) 
and (@CostCentreId=0 or p.CostCentreId=@CostCentreId)

if (@AutoBarCode=1)
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,SRate,Date,MRP)
	select o.CompanyID,1,o.WareHouseID,o.ProductId,o.UOMID,b.BarcodeID,o.Rate,Qty,SalesRate,0,o.MRP from invOpeningStock o
	left join invAutoBarcodeAndSalesRate b on o.CompanyID=b.CompanyID and o.PeriodID=b.PeriodID and b.VTypeID = 0 and o.No=b.No and o.SNo=b.SNo
	join #tmpProduct p on o.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
	where (@CompanyID=0 or o.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
Else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,CP,Qty,SRate,Date,MRP,WRate)
	select o.CompanyID,1,o.WareHouseID,o.ProductId,o.UOMID,o.Rate,o.Rate,Qty,SalesRate,0,o.MRP,o.WRate from invOpeningStock o
	join #tmpProduct p on o.ProductId=p.ID
	where (@CompanyID=0 or CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or WareHouseID=@CostCentreWHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

	

--Purchase
if (@AutoBarCode=1)
Begin
	if (@UBC=1)
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,VTypeId,No,MRP)
		select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,b.BarcodeID,pd.Rate,Qty+FOC,pd.CostPrice,pd.SRate,ph.Date,pd.VTypeID,pd.No,pd.MRP from invPurchaseDetails pd
		join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		left join invAutoBarcodeAndSalesRate b on pd.CompanyID=b.CompanyID and pd.PeriodID=b.PeriodID and pd.VTypeID=b.VTypeID and pd.No=b.No and pd.SNo=b.SNo
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	Else
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,WRate,Date,VTypeId,No,MRP)
		select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,b.BarcodeID,pd.Rate,Qty+FOC,pd.CostPrice,pd.SRate,pd.WRate,ph.Date,pd.VTypeID,pd.No,pd.MRP from invPurchaseDetails pd
		join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		left join invAutoBarcodeAndSalesRate b on pd.CompanyID=b.CompanyID and pd.PeriodID=b.PeriodID and pd.VTypeID=b.VTypeID and pd.No=b.No and pd.SNo=b.SNo
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
        and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
End
Else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,WRate,Date,VTypeId,No,MRP)
	select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate-isnull(pd.Discount/nullif(pd.Qty,0),0),Qty+FOC,pd.CostPrice,pd.SRate,pd.WRate,ph.Date,pd.VTypeID,pd.No,pd.MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	and (@CostCentreId=0 or isnull(ph.CostCentreId,@DefaultCostCentreId)=@CostCentreId)	

	

if isnull(@Type,0) not in(3,4,7,9,11)--Not for Barcode Stock
Begin
	--Goods Receipt
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,VTypeId,No)
	select pd.CompanyID,11,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,Qty+FOC,pd.Rate,pd.Rate,ph.Date,pd.VTypeID,pd.No from invGoodsReceiptDetails pd
	join invGoodsReceiptHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)

	--Purchase-Goods Receipt
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,VTypeId,No,MRP)
	select pd.CompanyID,2,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,-(Qty+FOC),pd.CostPrice,pd.SRate,ph.Date,pd.VTypeID,pd.No,MRP from invPurchaseDetails pd
	join invPurchaseHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and pd.IType=2 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
End


--Packing
if (@AutoBarCode=1)
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No,MRP)
	select pd.CompanyID,8,pd.WareHouseID,pd.ProductId,pd.UOMID,b.BarcodeID,pd.Rate,pd.Qty,pd.CostPrice,pd.SRate,ph.Date,pd.No,pd.MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
	join invAutoBarcodeAndSalesRate b on pd.CompanyID=b.CompanyID and pd.PeriodID=b.PeriodID and b.VTypeID=-1 and pd.No=b.No and pd.SNo=b.SNo
	join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
Else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,No,MRP)
	select pd.CompanyID,8,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,pd.Qty,pd.CostPrice,pd.SRate,ph.Date,pd.No,MRP from invPackingDetails pd
	join invPackingHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(pd.WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)



--Production
if (@AutoBarCode=1)
	insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeID,Rate,Qty,UOMId,CP,SRate,Date,No)
	select ph.CompanyID,case when ph.Type=1 then 1 end,9,ph.ProductId,b.BarcodeID,isnull(sum(pd.Total/ph.Qty),ph.PRate),case when ph.Type=1 then -1 else 1 end * ph.Qty,ph.UOMId,ph.PCost,ph.SRate,ph.Date,ph.No from invProductionHeader ph
	left join invAutoBarcodeAndSalesRate b on ph.CompanyID=b.CompanyID and ph.PeriodID=b.PeriodID and b.VTypeID=-2 and ph.No=b.No and 0=b.SNo
	join #tmpProduct p on ph.ProductId=p.ID and (p.BarcodeID is null or b.BarcodeID=p.BarcodeID)
	left join invProductionDetails pd on ph.CompanyID=pd.CompanyID and ph.PeriodID=pd.PeriodID and ph.No=pd.No
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
	and ph.Qty<>0 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	group by ph.CompanyID,ph.ProductId,b.BarcodeID,ph.PRate,ph.PCost,ph.Qty,ph.UomId,ph.SRate,ph.Date,ph.No,ph.Type
else
	insert #Stock(CompanyID,InOut,TransactionID,ProductID,Rate,Qty,UOMId,CP,SRate,Date,No)
	select ph.CompanyID,case when ph.Type=1 then 1 end,9,ph.ProductId,isnull(sum(pd.Total/ph.Qty),ph.PRate),case when ph.Type=1 then -1 else 1 end * ph.Qty,ph.UOMId,ph.PCost,ph.SRate,ph.Date,ph.No from invProductionHeader ph
	join #tmpProduct p on ph.ProductId=p.ID
	left join invProductionDetails pd on ph.CompanyID=pd.CompanyID and ph.PeriodID=pd.PeriodID and ph.No=pd.No
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
	and ph.Qty<>0 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	group by ph.CompanyID,ph.ProductId,ph.PRate,ph.PCost,ph.Qty,ph.UomId,ph.SRate,ph.Date,ph.No,ph.Type


--Purchase Return
if (@AutoBarCode=1)
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,Qty,Date,VTypeId,No)
	select pd.CompanyID,3,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,-Qty,ph.Date,pd.VTypeID,pd.No from invPurchaseReturnDetails pd
	join invPurchaseReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
else
	insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,Qty,Date,VTypeId,No)
	select pd.CompanyID,3,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,-Qty,ph.Date,pd.VTypeID,pd.No from invPurchaseReturnDetails pd
	join invPurchaseReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	where ph.Date<=@ToDate 
	and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)

--Company Transfer
if @AutoBarcode=1
	insert #Stock(CompanyID,WHID,TransactionID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No)
	select ph.CompanyTo,ph.WarehouseTo,16,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,pd.Qty,case when @PurchaseCPCalculation=3 then (pd.Total-pd.Tax)/pd.Qty else pd.Total/pd.Qty end,pd.SRate,ph.Date,pd.No from invCompanyTransferDetails pd
	join invCompanyTransferHeader ph on ph.PeriodID=pd.PeriodID and  pd.No=ph.No
	--join #tmpProduct p on pd.ProductId=p.ID and isnull(pd.BarcodeId,0)=isnull(p.BarcodeId,0)
	join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
	left join invTaxGroup tg on p.TaxGroupId=tg.Id
	where ph.Date<=@ToDate 
	and (ph.CompanyTo=@CompanyID or @CompanyID=0)
	and (@CompanyTransferApproval=0 or ph.Approve=1)
	and (@WHID=0 or isnull(WarehouseTo,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseTo,@DefaultWareHouseID)=@CostCentreWHID)
else
	insert #Stock(CompanyID,WHID,TransactionID,ProductID,UOMID,Rate,Qty,CP,SRate,Date,No,WRate)
	select ph.CompanyTo,ph.WarehouseTo,16,pd.ProductId,pd.UOMID,pd.Rate,pd.Qty,case when @PurchaseCPCalculation=3 then (pd.Total-pd.Tax)/pd.Qty else pd.Total/pd.Qty end,pd.SRate,ph.Date,pd.No,pd.WRate from invCompanyTransferDetails pd
	join invCompanyTransferHeader ph on ph.PeriodID=pd.PeriodID and  pd.No=ph.No
	join #tmpProduct p on pd.ProductId=p.ID
	left join invTaxGroup tg on p.TaxGroupId=tg.Id
	where ph.Date<=@ToDate 
	and (ph.CompanyTo=@CompanyID or @CompanyID=0)
	and (@CompanyTransferApproval=0 or ph.Approve=1)
	and (@WHID=0 or isnull(WarehouseTo,@DefaultWareHouseID)=@WHID)
	and (@CostCentreId=0 or isnull(WareHouseTo,@DefaultWareHouseID)=@CostCentreWHID)

if isnull(@Type,0) in(3,4,7,9,11)--For Barcode Stock Only
	--Barcode Changing
	insert #Stock(CompanyID,TransactionID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No,MRP)
	select pd.CompanyID,18,pd.ProductId,pd.UOMID,pd.NewBarcodeID,pd.Rate,Stock,pd.Rate,pd.Rate,pd.Date,pd.No,MRP from invBarcodeChanging pd
	join #tmpProduct p on pd.ProductId=p.ID and (p.barcodeId = pd.NewBarcodeID or p.barcodeId is null)
	where pd.Date<=@ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID) 


--Stock Receipt
insert #Stock(CompanyID,TransactionID,ProductID,UOMID,Rate,Qty,CP,Date,No)
select pd.CompanyID,22,pd.ProductId,pd.UOMID,pd.Rate,Qty,pd.Rate,ph.Date,pd.No from invStockReceiptDetails pd
join invStockReceiptHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
join #tmpProduct p on pd.ProductId=p.ID
where ph.Date<=@ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
and (@WHID=0 or @WHID=@DefaultWareHouseID)


if isnull(@Type,0) not in (12)--Not for Qty Only
	update s set s.CP=s.Rate from #Stock s where s.CP=0



if isnull(@Type,0) not in (5,13) or (@Type=13 and @PRateCalculation=0)  --Not for CP Calculation
Begin
	--Stock Out
	--Sales
	if (@AutoBarCode=1)
		insert #Stock(Sno,CompanyID,InOut,TransactionID,CostCentreId,WHID,ProductID,UOMID,BarcodeID,SerialNoId,Qty,FOC,Discount,Tax,Date,VTypeId,No,SRate,Pieces,Rate,CP)
		select distinct pd.sno,pd.CompanyID,1,4,ph.CostCentreId,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.SerialNoId,-(Qty+Foc),FOC,pd.Discount,pd.Tax+isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate,-pd.Pieces,case when @SalesCostwiseStock=1 then pd.Cost end,case when @SalesCostwiseStock=1 then pd.Cost end from invSalesDetails pd
		join invSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or ph.CostCentreId=@WHCostCentreId) 
		and (@SalesApproval=0 or ph.Approve=1)
		and isnull(ph.EInvoice,0) not in(2,4)
	Else
		insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,WHID,ProductID,UOMID,SerialNoId,Qty,FOC,Discount,Tax,Date,VTypeId,No,SRate,Pieces,Rate,CP)
		select pd.CompanyID,1,4,ph.CostCentreId,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.SerialNoId,-(Qty+Foc),FOC,pd.Discount,pd.Tax+isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate,-pd.Pieces,case when @SalesCostwiseStock=1 then pd.Cost end,case when @SalesCostwiseStock=1 then pd.Cost end from invSalesDetails pd
		join invSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		join invVoucherTypeDetails v on ph.VtypeId=v.Id
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,v.CostCentreID)=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID) 
		and (@SalesApproval=0 or ph.Approve=1)
		and (ph.BlockStockCalculation is null)
		and isnull(ph.EInvoice,0) not in(2,4)
	
	--Mixing
	if isnull(@Type,0) not in (10) or @PRateCalculation=0--Profit
	Begin
		delete s from #Stock s join invProductMixingHeader m on s.ProductID=m.ProductID where s.TransactionID=4

		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate,VtypeId)
		select rd.CompanyId,1,4,pd.ProductID,-rd.Qty*pd.qty/isnull(ph.Qty,1),convert(varchar,rh.Date,112),rd.No,rd.Rate,rd.VtypeId from invSalesDetails rd
		join invSalesHeader rh on rd.CompanyId=rh.CompanyId and rd.PeriodId=rh.PeriodId and rd.VtypeId=rh.VtypeId and rd.No=rh.No
		join invProduct ri on rd.ProductId =ri.Id		
		join (select CompanyId,No,h.ProductID,h.Qty from invProductMixingHeader h where (h.CompanyId=@CompanyId or @CompanyId=0)) ph on ri.Id=ph.Productid
		join (select CompanyId,No,d.ProductID,d.Qty from invProductMixingDetails d  join #tmpProduct b on b.ID=d.ProductId where (d.CompanyId=@CompanyId or @CompanyId=0)) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No
		join invVoucherTypeDetails v on rh.VtypeId=v.Id
		where rh.Date between @FromDate and @ToDate
		and (rd.CompanyId=@CompanyId or @CompanyId=0)
		and (@CostCentreId=0 or rh.CostCentreId=@CostCentreId or v.CostCentreID=@CostCentreId or @CostCentreId=@DefaultCostCentreID)
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID) 
		and (@SalesApproval=0 or rh.Approve=1)
		and (rh.BlockStockCalculation is null)
		and isnull(rh.EInvoice,0) not in(2,4)
	End

	
	--Multi Sales
	if (@AutoBarCode=1)
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,BarcodeID,Qty,Discount,Tax,Date,VTypeId,No,SRate)
		select pd.CompanyID,1,4,pd.WareHouseID,ph.ProductId,pd.UOMID,null,-Qty,null,pd.Tax,ph.Date,pd.VTypeID,pd.No,pd.Rate from invMultiSalesDetails pd
		join invMultiSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on ph.ProductID=p.ID --and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	Else
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Tax,Date,VTypeId,No,SRate)
		select pd.CompanyID,1,4,pd.WareHouseID,ph.ProductId,pd.UOMID,-Qty,null,pd.Tax,ph.Date,pd.VTypeID,pd.No,pd.Rate from invMultiSalesDetails pd
		join invMultiSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on ph.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	
	--POS Sales
	if object_id('pSalesDetails') is not null and object_id('pSalesHeader') is not null
	Begin
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,BarcodeID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,pd.BarcodeID,-(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesDetails pd
			join pSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,-(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesDetails pd
			join pSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
		
		--Mixing
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate)
		select rd.CompanyId,1,15,pd.ProductID,-rd.Qty*pd.qty,convert(varchar,rh.Date,112),rd.No,rd.Rate from pSalesDetails rd
		join pSalesHeader rh on rd.CompanyId=rh.CompanyId and rd.PeriodId=rh.PeriodId and rd.No=rh.No
		join invProduct ri on rd.ProductId =ri.Id		
		join (select CompanyId,No,h.ProductID from invProductMixingHeader h ) ph on ri.Id=ph.Productid
		join (select CompanyId,No,d.ProductID,d.Qty from invProductMixingDetails d  join #tmpProduct b on b.ID=d.ProductId) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No
		where (rd.CompanyId=@CompanyId or @CompanyId=0) and rh.Date between @FromDate and @ToDate
	End

	if object_id('pSalesReturnDetails') is not null and object_id('pSalesReturnHeader') is not null
	Begin
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,BarcodeID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,pd.BarcodeID,(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesReturnDetails pd
			join pSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,CostCentreId,ProductID,UOMID,Qty,Date,VTypeId,No,SRate,Tax,SerialNoId)
			select pd.CompanyID,1,15,ph.CostCentreId,pd.ProductId,pd.UOMID,(Qty+isnull(Foc,0)),ph.Date,pd.VTypeID,pd.No,pd.Rate,isnull(pd.Tax,0)+isnull(ph.TaxAmount*pd.Total/nullif(ph.NetTotal,0),0),pd.SerialNoId from pSalesReturnDetails pd
			join pSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId)
			and (@WHID=0 or ph.CostCentreId=@WHCostCentreId or @WHID=@DefaultWareHouseID)
	End

	

	--Restaurant 
	if object_id('RMSOrderDetails') is not null and object_id('RMSOrderHeader') is not null
	Begin

		--Sales
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate)
		select pd.Branch,1,19,ri.InventoryID,-Qty,convert(varchar,ph.Date,112),pd.OrderNo,pd.Rate from RMSOrderDetails pd
		join RMSOrderHeader ph on pd.Branch=ph.Branch and pd.Period=ph.Period and pd.OrderNo=ph.OrderNo
		join RMSItem ri on pd.ItemID =ri.ItemID
		join #tmpProduct p on ri.InventoryID=p.ID
		left join (select distinct productid from invProductMixingHeader)pm on ri.InventoryID=pm.ProductID
		where convert(varchar,ph.Date,112) between @FromDate and @ToDate and (@CompanyID=0 or pd.Branch=@CompanyID) and pd.IsModifier=0 and pm.ProductID is null


		--Mixing
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,UOMID,Qty,Date,No,SRate)
		select rd.Branch,1,19,pd.ProductID,pd.UOMID,-rd.Qty*pd.qty,convert(varchar,rh.Date,112),rd.OrderNo,rd.Rate from RMSOrderDetails rd
		join RMSOrderHeader rh on rd.Branch=rh.Branch and rd.Period=rh.Period and rd.OrderNo=rh.OrderNo
		join RMSItem ri on rd.ItemID =ri.ItemID
		--join #tmpProduct p on ri.InventoryID=p.ID
		join (select CompanyId,No,h.ProductID from invProductMixingHeader h ) ph on ri.InventoryID=ph.Productid
		join (select CompanyId,No,d.ProductID,d.UOMID,d.Qty from invProductMixingDetails d join #tmpProduct b on b.ID=d.ProductID) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No

	End
	--Restaurant Consumption
	if object_id('Consumptiondtls') is not null and object_id('Consumptiondtls') is not null
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,No)
		select pd.BranchID,1,20,pd.WarehouseId,pd.ItemID,pd.UomID,-Qty,convert(varchar, ph.Date,112),pd.Vno from Consumptiondtls pd
		join ConsumptionHdr ph on pd.BranchID=ph.BranchID  and pd.Vno=ph.Vno
		join #tmpProduct p on pd.ItemID=p.ID
		where convert(varchar,ph.Date,112) between @FromDate and @ToDate and (@CompanyID=0 or pd.BranchID=@CompanyID) and (@WHID=0 or pd.WarehouseId=@WHID)

	
	--Sales Return
	if (@AutoBarCode=1)
		insert #Stock(Sno,CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,BarcodeID,Qty,Discount,Tax,Date,VTypeId,No,SRate)
		select distinct pd.Sno,pd.CompanyID,1,5,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,Qty+Foc,-pd.Discount,-pd.Tax-isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate from invSalesReturnDetails pd
		join invSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		--join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	    and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
		and isnull(ph.EInvoice,0) not in(2,4)
	else
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Tax,Date,VTypeId,No,SRate,SerialNoId)
		select pd.CompanyID,1,5,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty+Foc,-pd.Discount,-pd.Tax-isnull(pd.Addition2,0),ph.Date,pd.VTypeID,pd.No,pd.Rate,pd.SerialNoId from invSalesReturnDetails pd
		join invSalesReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
	    and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or ph.CostCentreId=@CostCentreId)
		and isnull(ph.EInvoice,0) not in(2,4)
		
		
	--Mixing
	if isnull(@Type,0) not in (10) or @PRateCalculation=0--Profit
	Begin
		delete s from #Stock s join invProductMixingHeader m on s.ProductID=m.ProductID where s.TransactionID=5

		insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,SRate,VtypeId)
		select rd.CompanyId,1,4,pd.ProductID,rd.Qty*pd.qty/isnull(ph.Qty,1),convert(varchar,rh.Date,112),rd.No,rd.Rate,rd.VtypeId from invSalesReturnDetails rd
		join invSalesReturnHeader rh on rd.CompanyId=rh.CompanyId and rd.PeriodId=rh.PeriodId and rd.VtypeId=rh.VtypeId and rd.No=rh.No
		join invProduct ri on rd.ProductId =ri.Id		
		join (select CompanyId,No,h.ProductID,h.Qty from invProductMixingHeader h where h.CompanyId=@CompanyId) ph on ri.Id=ph.Productid
		join (select CompanyId,No,d.ProductID,d.Qty from invProductMixingDetails d  join #tmpProduct b on b.ID=d.ProductId where d.CompanyId=@CompanyId) pd on ph.CompanyID=pd.CompanyID and ph.No=pd.No
		where rd.CompanyId=@CompanyId and rh.Date between @FromDate and @ToDate
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID or rh.CostCentreId=@CostCentreId  or @CostCentreId=@DefaultCostCentreID)
	End


	if isnull(@Type,0) not in(10,11) or @PRateCalculation=0--Not for Profit Reports
	Begin
		--Packing
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeID,Qty,Date,No,Rate,CP)
			select CompanyID,1,8,ph.RawMaterialId,ph.BarcodeID,-Qty,ph.Date,ph.No,ph.CP,ph.CP from invPackingHeader ph
			join #tmpProduct p on ph.RawMaterialID=p.ID and (p.BarcodeID is null or ph.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,Date,No,Rate,CP)
			select CompanyID,1,8,ph.RawMaterialId,-Qty,ph.Date,ph.No,ph.CP,ph.CP from invPackingHeader ph
			join #tmpProduct p on ph.RawMaterialID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

		

		--Production
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeID,Qty,UomId,Date,No,Rate,CP)
			select pd.CompanyID,case when isnull(ph.Type,0)=0 then 1 end,9,pd.ProductId,pd.BarcodeID,case when ph.Type=1 then 1 else -1 end * pd.Qty,pd.UOMId,ph.Date,ph.No,pd.Rate,pd.Rate from invProductionDetails pd
			join invProductionHeader ph on pd.CompanyID=ph.CompanyId and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		Else
			insert #Stock(CompanyID,InOut,TransactionID,ProductID,Qty,UomId,Date,No,Rate,CP)
			select pd.CompanyID,case when isnull(ph.Type,0)=0 then 1 end,9,pd.ProductId,case when ph.Type=1 then 1 else -1 end * pd.Qty,pd.UomId,ph.Date,ph.No,pd.Rate,pd.Rate from invProductionDetails pd
			join invProductionHeader ph on pd.CompanyID=ph.CompanyId and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or ph.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

			
			
		--Issue
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Date,No,SRate)
		select pd.CompanyID,1,12,pd.WareHouseID,pd.ProductId,pd.UOMID,-Qty,pd.Discount,ph.Date,pd.No,pd.Rate from invIssueDetails pd
		join invIssueHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

		--Damage
		if (@AutoBarCode=1)
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,BarcodeID,Qty,Date,No,SRate,SerialNoId)
			select pd.CompanyID,1,14,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,-Qty,ph.Date,pd.No,pd.Rate,pd.SerialNoId from invDamageDetails pd
			join invDamageHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
			join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)

		Else
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,No,SRate,SerialNoId)
			select pd.CompanyID,1,14,pd.WareHouseID,pd.ProductId,pd.UOMID,-Qty,ph.Date,pd.No,pd.Rate,SerialNoId from invDamageDetails pd
			join invDamageHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
			join #tmpProduct p on pd.ProductID=p.ID
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
			and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	End

	declare @VTypeId int
	select @VtypeId=Id from invVoucherTypeDetails where VTypeId=8

	if @Type=10
		--Return
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Date,No,SRate,VtypeId)
		select pd.CompanyID,1,13,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty*NOD,pd.Discount,ph.Date,pd.No,pd.Rate,@VtypeId from invReturnDetails pd
		join invReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		and isnull(pd.Pending,0)=0
	Else
		--Return
		insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Discount,Date,No,SRate,VtypeId)
		select pd.CompanyID,1,13,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty,pd.Discount,ph.Date,pd.No,pd.Rate,@VtypeId from invReturnDetails pd
		join invReturnHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
		and isnull(pd.Pending,0)=0
	
	

	--if isnull(@Type,0) not in(3,4,7,9,11)--Not for Barcode Stock
	if isnull(@Type,0) not in(3,4,7,9,10,11)--Not for Barcode Stock,Profit
	Begin
		--DeliveryNote
		if not exists(select 1 from invOption where ExcludeDNFromStock=1 and CompanyID=@CompanyID)
		Begin
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,VTypeId,No,SRate)
			select pd.CompanyID,1,10,pd.WareHouseID,pd.ProductId,pd.UOMID,-(Qty+Foc),ph.Date,pd.VTypeID,pd.No,pd.Rate from invDeliveryNoteDetails pd
			join invDeliveryNoteHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			join invVoucherTypeDetails v on ph.VtypeId=v.Id
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@CostCentreId=0 or v.CostCentreID=@CostCentreId or @DefaultCostCentreID=@CostCentreId)
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID) 
			 

			--(Sales-DeliveryNote)
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,VTypeId,No,SRate)
			select pd.CompanyID,1,4,pd.WareHouseID,pd.ProductId,pd.UOMID,Qty,ph.Date,pd.VTypeID,pd.No,pd.Rate from invSalesDetails pd
			join invSalesHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.VTypeID=ph.VTypeID and pd.No=ph.No
			join #tmpProduct p on pd.ProductID=p.ID
			join invVoucherTypeDetails v on ph.VtypeId=v.Id
			where ph.Date between @FromDate and @ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) and pd.IType=2 
			and (@CostCentreId=0 or v.CostCentreID=@CostCentreId or @DefaultCostCentreID=@CostCentreId)
			and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID) 
		End
		
	End
	
	--Stock Adjustment
	if (@AutoBarCode=1)
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,BarcodeID,Rate,CP,SRate,Qty,Date,No,Pieces)
		select pd.CompanyID,7,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,pd.Cost,pd.SRate,AdjustedQty,ph.Date,pd.No,pd.AdjustedPieces from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseID,@DefaultWareHouseID)=@CostCentreWHID)
	Else
		insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Rate,CP,SRate,Qty,Date,No,Pieces)
		select pd.CompanyID,7,pd.WareHouseID,pd.ProductId,pd.UOMID,pd.Rate,pd.Cost,pd.SRate,AdjustedQty,ph.Date,pd.No,pd.AdjustedPieces from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductId=p.ID
		join invProduct pm on pd.ProductId=pm.Id
		where ph.Date<=@ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
		and (@WHID=0 or isnull(WareHouseID,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(isnull(WareHouseID,@DefaultWareHouseID),0)=isnull(@CostCentreWHID,0))
		and (@CostCentreId=0 or pm.CostCentreId=@CostCentreID)
	
	--WareHouse Transfer
	if @Type in(6,7,17) or @WHID>0 or @CostCentreWHID>0 
	Begin
		if (@AutoBarCode=1)
		Begin
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,BarcodeId,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,1,17,ph.WareHouseFrom,pd.ProductId,pd.BarcodeId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseFrom=@WHID)
			and (@CostCentreId=0 or ph.WareHouseFrom=@CostCentreWHID)
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)

			insert #Stock(CompanyID,TransactionID,WHID,ProductID,BarcodeId,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,17,ph.WareHouseTo,pd.ProductId,pd.BarcodeId,pd.UOMID,isnull(pd.RQty,pd.Qty),ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseTo=@WHID)
			and (@CostCentreId=0 or ph.WareHouseTo=@CostCentreWHID)
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)
		End
		Else
		Begin
			insert #Stock(CompanyID,InOut,TransactionID,WHID,ProductID,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,1,17,ph.WareHouseFrom,pd.ProductId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			join invWarehouse w on ph.WareHouseFrom=w.Id
			left join invSalesMan s on ph.SalesManId=s.Id
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseFrom=@WHID)
			and (@CostCentreId=0 or w.CostCentreID=@CostCentreId or s.CostCentreID=@CostCentreId)	
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)

			insert #Stock(CompanyID,TransactionID,WHID,ProductID,UOMID,Qty,Date,No,Rate,CP,SRate)
			select pd.CompanyID,17,ph.WareHouseTo,pd.ProductId,pd.UOMID,isnull(pd.RQty,pd.Qty),ph.Date,pd.No,pd.Rate,pd.Rate,pd.SRate from invWareHouseTransferDetails pd
			join invWareHouseTransferHeader ph on pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID and pd.No=ph.No
			join #tmpProduct p on pd.ProductId=p.ID
			join invWarehouse w on ph.WareHouseTo=w.Id
			left join invSalesMan s on ph.SalesManId=s.Id
			where ph.Date<=@ToDate 
			and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
			and (@WHID=0 or ph.WareHouseTo=@WHID)
			and (@CostCentreId=0 or w.CostCentreID=@CostCentreId or s.CostCentreID=@CostCentreId)	
			and (@WarehouseTransferCrossChecking=0 or pd.Checked=1)
		End
	End

	

	--CompanyTransfer
	if (@AutoBarcode=1)
		insert #Stock(CompanyID,WHID,InOut,TransactionID,ProductID,BarcodeId,UOMID,Qty,Date,No,SRate,Tax)
		select ph.CompanyFrom,ph.WarehouseFrom,1,16,pd.ProductId,pd.BarcodeId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Tax from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodID=ph.PeriodID and pd.No=ph.No
		--join #tmpProduct p on pd.ProductId=p.ID and isnull(pd.BarcodeId,0)=isnull(p.BarcodeId,0)
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.Date between @FromDate and @ToDate 
		and (ph.CompanyFrom=@CompanyID or @CompanyID=0)
		and (@CompanyTransferApproval=0 or ph.Approve=1)
		and (@WHID=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@CostCentreWHID)
	else
		insert #Stock(CompanyID,WHID,InOut,TransactionID,ProductID,UOMID,Qty,Date,No,SRate,Tax,SerialNoId,WRate)
		select ph.CompanyFrom,ph.WarehouseFrom,1,16,pd.ProductId,pd.UOMID,-pd.Qty,ph.Date,pd.No,pd.Rate,pd.Tax,pd.SerialNoId,pd.WRate from invCompanyTransferDetails pd
		join invCompanyTransferHeader ph on pd.PeriodID=ph.PeriodID and pd.No=ph.No
		join #tmpProduct p on pd.ProductId=p.ID
		where ph.Date between @FromDate and @ToDate 
		and (ph.CompanyFrom=@CompanyID or @CompanyID=0)
		and (@CompanyTransferApproval=0 or ph.Approve=1)
		and (@WHID=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@WHID)
		and (@CostCentreId=0 or isnull(WareHouseFrom,@DefaultWareHouseID)=@CostCentreWHID)
	

	if isnull(@Type,0) in(3,4,7,9,11)--For Barcode Stock Only
		--Barcode Changing
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,UOMID,BarcodeID,Rate,Qty,CP,SRate,Date,No)
		select pd.CompanyID,1,18,pd.ProductId,pd.UOMID,pd.BarcodeID,pd.Rate,-Stock,pd.Rate,pd.Rate,pd.Date,pd.No from invBarcodeChanging pd
		join #tmpProduct p on pd.ProductId=p.ID and (p.barcodeId = pd.BarcodeID or p.barcodeId is null)
		where pd.Date<=@ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID) 
	
	if (@AutoBarCode=1)
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeId,UOMID,Qty,Date,No,SRate)
		select @CompanyID,1,21,pd.ProductId,pd.BarcodeId,pd.UOMID,-Qty,ph.Date,pd.No,pd.Rate from invStockPaymentDetails pd
		join invStockPaymentHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
		join #tmpProduct p on pd.ProductID=p.ID and (p.BarcodeID is null or pd.BarcodeID=p.BarcodeID)
		where ph.StockDeductFrom=1 and ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID)
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or @WHID=@DefaultWareHouseID)
	else
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,UOMID,Qty,Date,No,SRate)
		select @CompanyID,1,21,pd.ProductId,pd.UOMID,-Qty,ph.Date,pd.No,pd.Rate from invStockPaymentDetails pd
		join invStockPaymentHeader ph on pd.No=ph.No and pd.CompanyID=ph.CompanyID and pd.PeriodID=ph.PeriodID
		join #tmpProduct p on pd.ProductID=p.ID
		where ph.StockDeductFrom=1 and ph.Date between @FromDate and @ToDate 
		and (@CompanyID=0 or pd.CompanyID=@CompanyID)
		and (@CostCentreId=0 or ph.CostCentreId=@CostCentreId or isnull(ph.CostCentreId,@DefaultCostCentreID)=@CostCentreId)
		and (@WHID=0 or @WHID=@DefaultWareHouseID)

	select @VtypeId=Id from invVoucherTypeDetails where VTypeId=18
	if object_id('invServiceDetails') is not null  
	Begin
		insert #Stock(CompanyID,InOut,TransactionID,ProductID,BarcodeId,UOMID,Qty,Date,VtypeId,No,SRate)
		select pd.CompanyID,1,23,pd.ProductId,pd.BarcodeId,pd.UomID,-Qty,isnull(si.Date,ph.Date),@VTypeId,isnull(si.No,ph.No),pd.Rate from invServiceDetails pd
		join invServiceHeader ph on pd.CompanyID=ph.CompanyID  and pd.No=ph.No and pd.PeriodId=ph.PeriodId
		join #tmpProduct p on pd.ProductId=p.ID and (p.BarcodeID is null or p.BarcodeID=0 or pd.BarcodeID=p.BarcodeID)
		left join invServiceInvoice si on ph.ServiceID=si.ServiceID
		where convert(varchar,isnull(si.Date,ph.Date),112) between @FromDate and @ToDate and (@CompanyID=0 or pd.CompanyID=@CompanyID)
	End
End


if isnull(@Type,0)<>18
	--Converting to Primary UOM
	update s set s.Rate=s.Rate/u.Secondary,s.Qty=s.Qty*u.Secondary,s.CP=s.CP/u.Secondary,s.SRate=s.SRate/u.Secondary,s.MRP=s.MRP/u.Secondary from #Stock s join invUOMLevels u on s.ProductId=u.ProductId and s.UOMID=u.UomId where u.Secondary<>1 and u.Secondary<>0 
------------------------------------------

create table #FIFO (Ord int,CompanyID int,WHID int,ProductID int,Date int,Rate float,CP float,SRate float,WRate float,Qty float,RQty float,OQty float,IQty float Unique Clustered(CompanyID,WHID,ProductID,Ord))

--Rate Calculation
if (isnull(@Type,0) not in(12,16,18))--(Not for Qty Only,Ratewise Stock)
Begin
	update #Stock set CP=Rate where CP=0 or CP is null
	
	if (@AutoBarCode=1 and @StockCalculation=0)--Barcode Rate Calculation
	Begin
		
		update t1 set t1.Rate = t2.Rate ,t1.Cp = t2.Cost from #Stock t1
		join invBarcodeChanging t2 on t1.ProductId = t2.ProductId and t1.BarcodeId = t2.NewBarcodeId 

		declare @BRate table(ProductID int,BarcodeID int,Rate float,CP float,SRate float,SNo int Unique Clustered(ProductID,BarcodeID))
		
		insert @BRate(ProductID,BarcodeID,Rate,CP,SRate)
		select ProductID,BarcodeID,Rate,CP,SRate from
		(select row_number()over(partition by ProductID,BarcodeID order by date desc)SNo,ProductID,BarcodeID,Rate,CP,SRate,Date from #Stock where InOut is null and Qty>0 and BarcodeID>0)b
		where sno=1
		--select ProductID,BarcodeID,max(Rate),max(CP),max(SRate) from #Stock where InOut is null and Qty>0 and BarcodeID>0 group by ProductID,BarcodeID

		update @BRate set CP=Rate where CP=0

	End

	declare @NonAutoBC bit
	select top 1 @NonAutoBC=1 from invProductionHeader
	
	if (isnull(@Type,0) in (0,1,2,6,8,13,10,15) and @PRateCalculation=0 and @StockCalculation>0 or @Type in(14,17))--FIFO
	Begin
		--Summarising
		create table #SStock (CompanyId int,ProductId int,Date int,WHID int,Rate float,CP float,SRate float,WRate float,Qty float,TransactionId int,InOut bit)

		--if @CompanyId=0 and isnull(@Type,0)<>1
		if @CompanyId=0 and isnull(@Type,0)not in(1,6)
			insert #SStock
			select 0,ProductId,Date,WHID,Rate,CP,SRate,WRate,sum(Qty),TransactionId,InOut from #Stock group by ProductId,Date,WHID,Rate,CP,SRate,WRate,TransactionId,InOut having sum(Qty)<>0
		Else
			insert #SStock
			select CompanyId,ProductId,Date,WHID,Rate,CP,SRate,WRate,sum(Qty),TransactionId,InOut from #Stock group by CompanyId,ProductId,Date,WHID,Rate,CP,SRate,WRate,TransactionId,InOut having sum(Qty)<>0

		
		if @Type in(6,17) 
			insert #FIFO(Ord,CompanyID,WHID,ProductID,Date,Rate,CP,SRate,WRate,Qty)
			select row_number()over(partition by CompanyID,ProductID order by Date),CompanyID,isnull(nullif(WHID,0),@DefaultwarehouseId),ProductID,Date,Rate,CP,SRate,WRate,Qty from #SStock where InOut is null and Qty>0
		else
			insert #FIFO(Ord,CompanyID,WHID,ProductID,Date,Rate,CP,SRate,WRate,Qty)
			select row_number()over(partition by CompanyID,ProductID order by Date,TransactionId desc),CompanyID,0,ProductID,Date,Rate,CP,SRate,WRate,Qty from #SStock where InOut is null and Qty>=0

		
		
		--Updating Running Qty
		declare @RQty table(CompanyID int,WHID int,ProductID int,Ord int,Qty float Unique Clustered(CompanyID,WHID,ProductID,Ord))

		insert @RQty
		select f2.CompanyID,f2.WHID,f2.ProductID,f2.Ord,sum(f1.Qty)Qty from #FIFO f1 join #FIFO f2 on f1.CompanyID=f2.CompanyID and f1.WHID=f2.WHID and f1.ProductID=f2.ProductID and f1.Ord<=f2.Ord group by f2.CompanyID,f2.WHID,f2.ProductID,f2.Ord

		update f set f.RQty=r.Qty from #FIFO f join @RQty r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID and f.Ord=r.Ord

		--Updating In Total Qty
		;with r as(select CompanyID,ProductID,WHID,sum(Qty)Qty from #FIFO group by CompanyID,WHID,ProductID)
		update f set f.IQty=r.Qty from #FIFO f join r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID

		--Updating Out Total Qty
		declare @MS table(CompanyID int,WHID int,ProductID int,Qty float,[In] bit Unique Clustered (CompanyID,WHID,ProductID))

		if @Type in(6,17) 
			insert @MS(CompanyID,WHID,ProductID,Qty)
			select CompanyID,isnull(nullif(WHID,0),@DefaultwarehouseId),ProductID,sum(Qty)Qty from #SStock where InOut is not null or Qty<0 
			group by CompanyID,isnull(nullif(WHID,0),@DefaultwarehouseId),ProductID
		Else
			insert @MS(CompanyID,WHID,ProductID,Qty)
			select CompanyID,0,ProductID,sum(Qty)Qty from #SStock where InOut is not null or Qty<0 
			group by CompanyID,ProductID
		
		
		update f set f.OQty=-r.Qty from #FIFO f join @MS r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID
		update r set r.[In]=1 from #FIFO f join @MS r on f.CompanyID=r.CompanyID and f.WHID=r.WHID and f.ProductID=r.ProductID
		--end Updating Out Total Qty
		

		if isnull(@Type,0) not in(8,10)--Stock Register,Profit
		--if isnull(@Type,0) not in(8)--Stock Register
		Begin
			--deleting +stock item
			delete #FIFO where IQty>=OQty and RQty<=OQty
				
			--deleting -stock item
			;with r as(select row_number()over(partition by CompanyID,WHID,ProductID order by RQty desc)sno,* from #FIFO where RQty<OQty)
			update r set Qty=case when sno=1 then RQty-OQty end
			delete #FIFO where Qty is null
			--end deleting -stock item


			--updating first batch stock
			;with r as(select row_number()over(partition by CompanyID,WHID,ProductID order by RQty)sno,* from #FIFO where Qty>RQty-OQty)
			update r set Qty=case when sno=1 then RQty-OQty end
			delete #FIFO where Qty is null
			--end updating first batch stock
		End

		
		--inserting non IN item
		update @MS set WHID=@DefaultwarehouseId where WHID=0

		insert #FIFO(CompanyID,WHID,ProductID,Qty)
		select CompanyID,WHID,ProductID,sum(Qty) from @MS where [In] is null group by CompanyID,WHID,ProductID

		--inserting non Sales but SR item
		insert #FIFO(CompanyID,WHID,ProductID,Qty,Rate,CP,SRate,WRate)
		select CompanyID,WHID,ProductID,-OQty,Rate,CP,SRate,WRate from #FIFO where RQty=IQty and OQty<0

		
		if isnull(@Type,0) not in(12) -- DN distribution
		Begin
			
			declare @DN table(SNo int,CompanyId int,ProductId int,Date int,Rate float,Qty float)
			insert @DN
			select row_number()over(partition by d.CompanyID,d.ProductID order by d.PeriodID desc,d.No desc)Sno,d.CompanyID,d.ProductID,h.Date,d.Rate/u.Secondary Rate,d.Qty*u.Secondary Qty from invDebitNoteDetails d 
			join invDebitNoteHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No 
			join #tmpProduct t on d.ProductId=t.ID
			join (select distinct ProductId,UomId,Secondary from invUOMLevels) u on d.ProductId=u.ProductId and d.UomId=u.UomId

			declare @SNo int,@MaxSNo int
			select @SNo=1,@MaxSNo=max(SNo) from @DN

			while @SNo<=@MaxSNO
			Begin
				;with d as
				(select * from @DN where sno=@SNo)

				,lp as  -- Last Purchases
				(select row_number()over(partition by f.CompanyID,f.ProductID order by Ord desc)Sno,f.CompanyID,f.ProductID,f.Date,f.Rate,f.CP,f.Qty from #FIFO f join d on f.CompanyID=d.CompanyID and f.ProductID=d.ProductID and f.Date<=d.Date and ((f.RQty-isnull(f.OQty,0)<=d.Qty) or f.Qty>d.Qty))
				
				update l set l.CP=l.CP-d.Rate,l.Rate=l.Rate-d.Rate from lp l join d on l.CompanyID=d.CompanyID and l.ProductID=d.ProductID

				set @SNo=@SNo+1

			End
		End
				
	End
	Else if (@AutoBarCode=0 or @UBC=1 or @NonAutoBC=1 or @StockCalculation=1 or @Type=13)   --Non Barcode Stock
	Begin
		if @PRateCalculation=2-- Master
		Begin
			if @Type=10
				update s set s.Rate=p.Cost,s.CP=p.Cost from #Stock s join invProduct p on s.ProductID=p.ID
			Else
				update s set s.Rate=p.Cost,s.CP=p.Cost,s.SRate=p.Rate,s.WRate=p.WRate from #Stock s join invProduct p on s.ProductID=p.ID
		End
		Else
		Begin	
			declare @Rate table(CompanyID int,Date int,ProductID int,Rate float,CP float,SRate float,WRate float,MRP float Unique Clustered(CompanyID,Date,ProductID))
			
			declare @Date table (CompanyID int,Date int,ProductID int,RQty float Unique Clustered(CompanyID,Date,ProductID))

			if isnull(@Type,0) in(0,1,2,6,8,15) and @PRateCalculation=1
			Begin
				insert @Date(CompanyID,Date,ProductID)
				select CompanyID,max(Date),ProductID from #Stock group by CompanyID,ProductID
			End
			Else
			Begin
				insert @Date(CompanyID,Date,ProductID)
				select distinct CompanyID,Date,ProductID from #Stock where InOut=1 and (BarcodeID is null or BarcodeID=0 or @StockCalculation=1)
				if not exists(select 1 from @Date)--if not sales at all
					insert @Date(CompanyID,Date,ProductID)select distinct CompanyID,@ToDate,ProductID from #Stock  
				
			End
			
			if (@PRateCalculation=1) --Last CP
			Begin
				
				create table #IStock (CompanyID int,ProductID int,Date int,Rate float,CP float,SRate float,WRate float,MRP float)

				insert #IStock 
				select CompanyID,ProductID,Date,Rate,CP,SRate,WRate,MRP from #Stock where InOut is null and Qty>0 --and (BarcodeID is null or BarcodeID=0) 
				
				insert @Rate(CompanyID,Date,ProductID,Rate,CP,SRate,WRate,MRP)
				select l.CompanyID,l.Date,s.ProductID,max(s.Rate),max(s.CP),max(s.SRate),max(s.WRate),max(s.MRP) from #IStock s
				join
				(select d.CompanyID,d.Date,s.ProductID,max(s.Date)PDate from #IStock s join @Date d on d.CompanyID=s.CompanyID and d.Date>=s.Date and d.ProductID=s.ProductID group by d.CompanyID,d.Date,s.ProductID) l --For Finding Sales Day's Max Purchase Date
				on l.CompanyID=s.CompanyID and l.ProductID=s.ProductID and l.PDate=s.Date
				group by l.CompanyID,l.Date,s.ProductID
				
				update r set r.WRate=p.WRate from @Rate r join invProduct p on r.ProductId=p.Id where r.Wrate is null
				update r set r.MRP=p.MRP from @Rate r join invProduct p on r.ProductId=p.Id where r.MRP is null

			End
			Else -- Weighted Average
			Begin

				--create table #DValue (CompanyID int,Date int,ProductID int,PValue float,CPValue float,SValue float,Qty float,RQty float)

				create table #DValue (CompanyID int,Date int,ProductID int,PValue float,CPValue float,SValue float,Qty float)
				
				insert #DValue(CompanyID,Date,ProductID,PValue,CPValue,SValue,Qty)
				select CompanyID,Date,ProductID,sum(Rate*Qty) PValue,sum(CP*Qty) CPValue,sum(SRate*Qty) SValue,sum(Qty)Qty from #Stock where InOut is null and Qty>0 group by CompanyID,ProductID,Date
				--------------------------------
				insert @Rate(CompanyID,Date,ProductID,Rate,CP,SRate)
				select t.CompanyID,t.Date,s.ProductID,sum(s.PValue)/sum(s.Qty),sum(s.CPValue)/sum(s.Qty),sum(s.SValue)/sum(s.Qty) from 
				@Date t join    
				#DValue s   
				--on t.Date>=s.Date and t.CompanyID=s.CompanyID and t.ProductID=s.ProductID group by t.CompanyID,t.Date,s.ProductID having sum(s.Qty)<>0
				on t.CompanyID=s.CompanyID and t.ProductID=s.ProductID 
				group by t.CompanyID,t.Date,s.ProductID having sum(s.Qty)<>0
				
				-------------------------------------
			End
			
			update @Rate set CP=Rate where CP=0
		End
	End
	---------------
	
	--Rate Updation
	if not(@PRateCalculation=0 and isnull(@Type,0) in(0,1) and @StockCalculation>0)
	Begin
		if @Type in (8,9,10,11)--For Profit SRate must be taken from sales table.So no need to update from purchase/master
		Begin
			if @PRateCalculation=0   --FIFO
			Begin
							
				--Updating Running  OQty

				declare @SOQty table(CompanyId int,WHID int,ProductId int,Date int,Qty float Unique Clustered(CompanyID,WHID,ProductID,Date))
				insert @SOQty
				select CompanyId,case when @whid=0 then 0 else WHID end WHId,ProductId,Date,sum(Qty)Qty from #Stock where not (InOut is null and Qty>0) and TransactionId not in(2) group by CompanyId,case when @whid=0 then 0 else WHID end,ProductId,Date

				declare @ROQty table(CompanyID int,WHID int,ProductID int,Date int,Qty float Unique Clustered(CompanyID,WHID,ProductID,Date))
				insert @ROQty
				select f2.CompanyID,case when @whid=0 then 0 else f2.WHID end,f2.ProductID,f2.Date,sum(f1.Qty)Qty from @SOQty f1 join @SOQty f2 on f1.CompanyID=f2.CompanyID and f1.WHID=f2.WHID and f1.ProductID=f2.ProductID and f1.Date<=f2.Date
				group by f2.CompanyID,f2.WHID,f2.ProductID,f2.Date

				update f set f.ROQty=-r.Qty from #Stock f join @ROQty r on f.CompanyID=r.CompanyID and (@WHId=0 or f.WHID=r.WHID) and f.ProductID=r.ProductID and f.Date=r.Date
				
				create table #CP(Date int,ProductId int,Rate float,CP float)
				insert #CP
				select s.Date,s.ProductId,sum(f.Rate*f.Qty)/sum(f.Qty)Rate,sum(f.CP*f.Qty)/sum(f.Qty)CP from #FIFO f join #Stock s on f.ProductId=s.ProductId and f.RQty>=s.ROQty and f.Date<=s.Date where s.Rate is null group by s.Date,s.ProductId
				
				update s set s.Rate=f.Rate,s.CP=f.CP from #CP f join #Stock s on f.ProductId=s.ProductId  and f.Date=s.Date 
				where s.Rate is null or (@SalesCostwiseStock=0 and s.InOut=1)

			End
		
			
			if (@AutoBarCode=0 or @UBC=1 or @StockCalculation=1)   --Non Barcode Stock
				update s set s.Rate=r.Rate,s.CP=r.CP from #Stock s join @Rate r on s.CompanyID=r.CompanyID and s.Date=r.Date and s.ProductID=r.ProductID where (s.InOut=1 or s.Qty<0) and s.TransactionID not in(2,15,9,17)
			
			if (@AutoBarCode=1)--Barcode Stock
				update s set s.Rate=r.Rate,s.CP=r.CP from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where (s.InOut=1 or s.Qty<0)
			
			

			--Serial No CP
			if (@StockCalculation=2 or @Type=10)
				update s set s.Rate=pd.Rate,s.CP=pd.CostPrice from #Stock s join invProductSerialNumber sn on s.SerialNoId=sn.id and s.CompanyId=sn.CompanyId join invPurchaseDetails pd on sn.CompanyId=pd.CompanyId and sn.PeriodId=pd.PeriodId and sn.VtypeId=pd.Vtypeid and sn.No=pd.No and sn.PSNo=pd.SNo and s.ProductId=pd.ProductId 
			
			

			if @Type in(8,10) -- SR,profit
			Begin
				
				--To get last rate for minus stock items
				declare @LRate table(ProductId int,Rate float,CP float)

				;with r1 as (select row_number()over(partition by productid order by date desc)Sno,ProductID,Rate,CP from @Rate)
				insert @LRate
				select ProductID,Rate,CP from r1 where sno=1

				;with r1 as (select row_number()over(partition by productid order by date desc)Sno,ProductID,Rate,CP from #FIFO)
				insert @LRate
				select ProductID,Rate,CP from r1 where sno=1
				
				;with r1 as (select row_number()over(partition by s.productid order by date desc)Sno,s.ProductID,s.Rate,s.CP from #Stock s left join @LRate l on s.ProductId=l.ProductId where InOut is null or InOut=0 and l.ProductId is null)
				insert @LRate
				select ProductID,Rate,CP from r1 where sno=1
				
				update s set s.Rate=p.Rate,s.CP=p.CP from #Stock s join @LRate p on s.ProductID=p.ProductID where s.Rate is null
				
				;with p as (select ProductID,sum(Rate*Qty)/sum(Qty) Rate,sum(CP*Qty)/sum(Qty)CP from #FIFO group by ProductID)
				update s set s.Rate=p.Rate,s.CP=p.CP from #Stock s join p on s.ProductID=p.ProductID where s.Rate is null

				update s set s.Rate=p.Cost,s.CP=p.Cost from #Stock s join invProduct p on s.ProductID=p.ID where s.Rate is null
			End
			else
				update s set s.Rate=p.Cost,s.CP=p.Cost,s.SRate=p.Rate from #Stock s join invProduct p on s.ProductID=p.ID where s.Rate is null
			
		End
		Else 
		Begin
			if (@AutoBarCode=1 and @StockCalculation=0)--Barcode Stock
			Begin
				update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where (s.InOut=1 or s.Qty<0)
				update s set s.CP=r.CP from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where s.CP=0
				update s set s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID and s.BarcodeID=r.BarcodeID where s.SRate=0 or s.SRate is null
				update #Stock set CP=Rate where CP=0
				
				if isnull(@Type,0) not in(0,4,7)
				Begin
					;with r as
					(select row_number()over(partition by CompanyId,ProductId order by date desc)Sno,CompanyId,ProductId,Rate,CP,SRate,WRate,MRP from @Rate)
					update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate,s.WRate=r.WRate,s.MRP=r.MRP from #Stock s join r on s.CompanyID=r.CompanyID and s.ProductID=r.ProductID and r.Sno=1 where (s.Rate is null or s.BarcodeId=0 or s.BarcodeId is null)
				End
				
				
			End
			Else
			Begin
				if isnull(@Type,0) in(0,1,6) and @PRateCalculation=1
				Begin
					update @Rate set Date=0 --To speed up joining by indexed fields in below line
					update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate,s.WRate=r.WRate,s.MRP=r.MRP from #Stock s join @Rate r on s.CompanyID=r.CompanyID and s.ProductID=r.ProductID and r.Date=0
				End
				Else
					update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate,s.MRP=r.MRP from #Stock s join @Rate r on s.CompanyID=r.CompanyID and s.Date=r.Date and s.ProductID=r.ProductID where (s.InOut=1 or s.Qty<0)
			End	
			update s set s.Rate=r.Rate,s.CP=r.CP,s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID  where s.Rate is null
			update s set s.Rate=p.Cost,s.CP=p.Cost,s.SRate=p.Rate,s.MRP=p.MRP from #Stock s join invProduct p on s.ProductID=p.ID where s.Rate is null or s.Rate=0
			update s set s.SRate=p.Rate from #Stock s join invProduct p on s.ProductID=p.ID where s.SRate is null or s.SRate=0
			update s set s.SRate=r.SRate from #Stock s join @BRate r on s.ProductID=r.ProductID where s.TransactionID=7 and Qty<0
		End
	End
	
	if exists(select top 1 1 from #FIFO)
	Begin
		update f set f.Rate=p.Cost,f.CP=p.Cost from #FIFO f join invProduct p on f.ProductID=p.ID where f.Rate=0 or f.Rate is null
		update #FIFO set CP=Rate where CP=0
		update s set s.SRate=p.Rate from #FIFO s join invProduct p on s.ProductID=p.ID where s.SRate is null or s.SRate=0
	End
	
	update #Stock set BarcodeId=null where BarcodeId=0
	update #Stock set Wrate=null where WRate=0

End


---------------------------------------------------------------
if @Type in(6,7,17) or @WHID>0 or @DefaultWareHouseID>0--WareHouse
Begin
	update s set s.WHID=w.Id from #Stock s join invWareHouse w on s.CostCentreId=w.CostCentreId where s.WHID=0 or s.WHID is null
	update s set s.WHID=@DefaultWareHouseID from #Stock s where s.WHID=0 or s.WHID is null
	update s set s.WHID=@DefaultWareHouseID from #FIFO s where s.WHID=0 or s.WHID is null
End
-------------------------------------------------------------------------------------------

if (@AutoBarcode=1 and @StockCalculation=0)
	update s set s.CP=b.Cost from #Stock s join invAutoBarcodeandSalesRate b on s.ProductId=b.ProductId and s.BarcodeId=b.BarcodeId where s.CP=0 or s.CP is null

if (@AutoBarcode=1 and @StockwithBarcodeOnly=1 and @StockCalculation=0)
	delete s from #Stock s left join invAutoBarcodeandSalesRate b on s.ProductId=b.ProductId and s.BarcodeId=b.BarcodeId where s.BarcodeId>0 and b.BarcodeId is null

if @Type=10
	update s set s.Rate=b.Rate,s.CP=b.Cost from #Stock s join invAutoBarcodeandSalesRate b on s.ProductId=b.ProductId where s.CP=0 or s.CP is null and b.CompanyId=@CompanyId


--Final Selection
if @Type is null --Total Stock Value
Begin
	declare @StockValue int
	select @StockValue=StockValue from aOption

	if (@AutoBarcode=1 and @StockCalculation=0)
	Begin
		select @Type=case when @StockValue=1 then sum(CP*Qty) else sum(Rate*Qty) end from 
		(select CompanyID,ProductID,BarcodeId,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,WValue/Qty WRate,null MRP,Qty from
		(select CompanyID,ProductID,BarcodeId,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyID,ProductID,BarcodeId having sum(Qty)<>0)s)a
	End
	Else
	Begin
		if @PRateCalculation=0
			select @Type=case when @StockValue=1 then sum(CP*Qty) else sum(Rate*Qty) end from #FIFO
		Else
			select @Type=case when @StockValue=1 then sum(CP*Qty) else sum(Rate*Qty) end from 
			(select CompanyID,ProductID,Rate,CP,SRate,WRate,max(MRP)MRP,sum(Qty)Qty from #Stock group by CompanyID,ProductID,Rate,CP,SRate,WRate)a
	End
End
else if @Type=0  --All Item Rate,Qty
Begin
	if @PRateCalculation=0
		select ProductID,Rate,CP,SRate,sum(Qty)Qty from #FIFO group by ProductID,Rate,SRate,CP
	Else
		select ProductID,Rate,CP,SRate,sum(Qty)Qty from #Stock group by ProductID,Rate,SRate,CP
End
else if @Type=1  --Supplied Item Rate,Qty
Begin
	if (@AutoBarcode=1 and @StockCalculation=0)
		select CompanyID,ProductID,sum(RValue)/sum(Qty) Rate,sum(CPvalue)/sum(Qty) CP,sum(SValue)/sum(Qty) SRate,sum(WValue)/sum(Qty) WRate,null MRP,sum(Qty)Qty,sum(Pieces)Pieces from
		(select CompanyID,ProductID,BarcodeId,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(round(sum(Qty),12),0)Qty,sum(Pieces)Pieces from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyID,ProductID,BarcodeID having sum(Qty)<>0)s
		group by CompanyID,ProductID having sum(Qty)<>0
	Else if @PRateCalculation=0 --FIFO
		select CompanyID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,WValue/Qty WRate,null MRP,Qty,null from
		(select CompanyID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #FIFO group by CompanyID,ProductID)s
	Else if @PRateCalculation=3 --WA
		select CompanyID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,WValue/Qty WRate,null MRP,Qty,null from
		(select CompanyID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #Stock group by CompanyID,ProductID)s
	Else
		select CompanyID,ProductID,Rate,CP,SRate,WRate,max(MRP)MRP,sum(Qty)Qty,sum(Pieces)Pieces from #Stock group by CompanyID,ProductID,Rate,CP,SRate,WRate
End
else if @Type=2 --Rate,CP,SRate only
Begin
	if exists(select top 1 1 from @BRate)
		select null,ProductID,BarcodeID,Rate,CP,SRate from @BRate order by BarcodeID desc
	else if exists(select top 1 1 from #FIFO)
	Begin
		select null,ProductID,null,Rate,CP,null from
		(select ProductID,sum(Rate*Qty)/sum(Qty)Rate,sum(CP*Qty)/sum(Qty)CP,sum(Qty)Qty from #FIFO group by ProductID having sum(Qty)<>0)r
		union all --Rate of 0 stock item
		select null,s.ProductID,null,max(s.Rate),max(s.CP),null from #Stock s left join #FIFO f on s.ProductID=f.ProductID where f.ProductID is null group by s.ProductID 
	End
	else if exists(select top 1 1 from @Rate)
		select Date,ProductID,null,Rate,CP,SRate from @Rate order by Date desc
	else 
		select top 1 null,ProductId,null,CP,CP,Rate from #Stock where InOut is null order by date desc
		
End

else if @Type in(3,4)  --Item,Barcode,Rate,Qty
Begin
	select CompanyId,ProductID,BarcodeID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,Qty from
	(select CompanyID,ProductID,BarcodeID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,sum(WRate*Qty)WValue,nullif(sum(Qty),0)Qty from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyID,ProductID,BarcodeID having sum(Qty)<>0)s
End
else if @Type=5  --Supplied Barcode,Rate
	select ProductID,BarcodeID,Rate,CP,SRate from @BRate
else if @Type=6  --Supplied WH,Item,Rate,Qty
Begin
	if @PRateCalculation=0
		select CompanyId,WHID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,Qty,null Pieces from
		(select CompanyId,WHID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,nullif(sum(Qty),0)Qty from #FIFO group by CompanyID,WHID,ProductID)s
	else
		select CompanyId,WHID,ProductID,RValue/Qty Rate,CPvalue/Qty CP,SValue/Qty SRate,Qty,Pieces from
		(select CompanyId,WHID,ProductID,sum(Rate*Qty)RValue,sum(CP*Qty)CPValue,sum(SRate*Qty)SValue,nullif(sum(Qty),0)Qty,sum(Pieces)Pieces from #Stock group by CompanyID,WHID,ProductID)s
End
else if @Type=7  --Supplied WH,Item,Barcode,Rate,Qty
	select WHID,ProductID,BarcodeID,Rate,CP,SRate,sum(Qty)Qty from #Stock group by WHID,ProductID,BarcodeID,Rate,CP,SRate
else if @Type=8  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Rate,Qty
	select CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,Rate,CP,SRate,sum(Qty)Qty from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,Rate,CP,SRate
else if @Type=9  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Barcode,Rate,Qty
	select CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate,sum(Qty)Qty from #Stock group by CompanyId,InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate
else if @Type=10  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Rate,Qty,Discount(Sales/SR Only,for Profit)
Begin
	select CompanyId,InOut,Date,VtypeId,No,TransactionID,WHID,ProductID,BarcodeId,SerialNoId,Rate,CP,SRate,sum(Qty)Qty,sum(FOC)FOC,sum(Discount)Discount,sum(Tax)Tax from #Stock 	where InOut=1 
	group by CompanyId,InOut,Date,VtypeId,No,TransactionID,WHID,ProductID,BarcodeId,SerialNoId,Rate,CP,SRate
	--select InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeId,Rate,CP,SRate,sum(Qty)Qty,sum(FOC)FOC,sum(Discount)Discount,sum(Tax)Tax from #Stock where InOut=1 group by InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeId,Rate,CP,SRate
End
else if @Type=11  --Supplied InOut,Date,VtypeId,No,Transaction,Item,Barcode,Rate,Qty,Discount(Sales/SR Only,for Profit)
	select InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate,sum(Qty)Qty,sum(Discount)Discount from #Stock where InOut=1 group by InOut,Date,VtypeId,No,TransactionID,ProductID,BarcodeID,Rate,CP,SRate
else if @Type=12  --Supplied ProductID,Qty
Begin
	if (@AutoBarcode=1 and @StockCalculation=0 and @StockWithBarcodeOnly=1)
		select CompanyId,ProductID,BarcodeId,sum(Qty)Qty,sum(Pieces)Pieces from #Stock where BarcodeId>0 group by CompanyId,ProductID,BarcodeId
	Else
		select CompanyId,ProductID,null BarcodeId,sum(Qty)Qty,sum(Pieces)Pieces from #Stock group by CompanyId,ProductID
End
else if @Type=13  --Supplied ProductID,CP
Begin
	declare @CP table(ProductId int,CP float)

	if exists(select top 1 1 from #FIFO)
		insert @CP
		select ProductID,sum(CP*Qty)/nullif(sum(Qty),0)CP from #FIFO group by ProductID
	Else
		insert @CP
		select ProductID,CP from @Rate
	

	select * from @CP	
	union all
	select p.Id,Cost from invProduct p join #tmpProduct t on p.Id=t.Id left join @CP c on p.Id=c.ProductId where c.ProductId is null

End
else if @Type=14  --For Stock Ageing
Begin
	if (@AutoBarcode=1 and @StockCalculation=0)
		select ProductID,BarcodeId,min(Date)Date,sum(Qty)Qty,sum(Rate*Qty)Value from #Stock where (@StockwithBarcodeOnly=0 or BarcodeId>0) group by ProductID,BarcodeId having sum(Qty)<>0
	Else
		select ProductID,0 BarcodeId,Date,sum(Qty)Qty,sum(Rate*Qty)Value from #FIFO group by ProductID,Date having sum(Qty)<>0
End
else if @Type=15  --For Product Stock having barcodes
Begin
	if exists(select top 1 1 from #FIFO)
	Begin
		select null,ProductID,null,Rate,CP,null from
		(select ProductID,sum(Rate*Qty)/sum(Qty)Rate,sum(CP*Qty)/sum(Qty)CP,sum(Qty)Qty from #FIFO group by ProductID having sum(Qty)<>0)r
		union all --Rate of 0 stock item
		--select null,s.ProductID,null,max(s.Rate),max(s.CP),null from #Stock s left join #FIFO f on s.ProductID=f.ProductID where f.ProductID is null group by s.ProductID 
		select null,ProductId,null,Rate,CP,SRate from
		(select row_number()over (partition by s.ProductId order by s.Date desc)sno,s.ProductID,s.Rate,s.CP,s.SRate from #Stock s left join #FIFO f on s.ProductID=f.ProductID where f.ProductID is null)s
		where sno=1
	End
	else if exists(select top 1 1 from @Rate)
		--select Date,ProductID,null,Rate,CP,SRate from @Rate order by Date desc
		select null,ProductId,null,Rate,CP,SRate from
		(select row_number()over (partition by ProductId order by Date desc)sno,ProductId,Rate,CP,SRate from @Rate)s
		where sno=1
	else 
		select null,ProductId,null,Rate,CP,SRate from
		(select row_number()over (partition by ProductId order by Date desc)sno,ProductId,Rate,CP,SRate from #Stock where InOut is null and Qty>0)s
		where sno=1
End
else if @Type=16  --Ratewise Stock
	select ProductID,Date,round(CP,2),sum(Qty)Qty  from #Stock where CP<>0 group by ProductID,Date,round(CP,2) having sum(Qty)<>0
else if @Type=17  --For WH wise Stock Ageing
	select ProductID,WHID,Date,sum(Qty)Qty,sum(Rate*Qty)Value from #FIFO group by ProductID,WHID,Date
else if @Type=18  --ProductID,UOM,Qty
	select ProductID,UOMId,sum(Qty)Qty from #Stock group by ProductID,UOMId


drop table #Stock
delete tmpTable where SPID=@@SPID



go

if OBJECT_ID('prGetJobInvoiceDetailsForPrint') is not null
	drop proc prGetJobInvoiceDetailsForPrint
go

create proc prGetJobInvoiceDetailsForPrint
@CompanyId int,
@PeriodId int,
@VtypeId int,
@No int as
set nocount on


if (select AddMaterialsInJobInvoicePrint from invOption where CompanyID = @CompanyID) = 0
 begin
   select 0 Type,t1.Sno,t2.name Particulars,isnull(t3.name,'') Employee,t1.Qty,t1.Rate,t1.Amount,t2.Code,p.OtherLanguage NameInOL from invJobInvoiceDetails t1
   join invJobWork t2 on t1.WorkId = t2.Id 
   left outer join aAccount t3 on t1.EmployeeId = t3.Id
   left join invProduct p on t2.ProductId=p.Id
   where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.VtypeId = @VtypeId and t1.[No] = @No 
   order by t1.sno
 end
else
 begin 
   declare @T1 table
   (
     Type tinyint,	
     Sno int identity(1,1),
	 ProductId int,
     Particulars nvarchar(200),
     Qty float,
     Rate float,
     Amount float,
     Code nvarchar(100),
     Employee nvarchar(100),
	 NameInOL nvarchar(100),
	 Property1 varchar(100)
   )
   
   declare @T2 table(PeriodId int, VtypeId int,No int)
   
   insert @T1(Type,Particulars,Employee,Qty,Rate,Amount,Code,NameInOL)
   select 0,t2.name Particulars,isnull(t3.name,'') Employee,t1.Qty,t1.Rate,t1.Amount,t2.Code,p.OtherLanguage from invJobInvoiceDetails t1
   join invJobWork t2 on t1.WorkId = t2.Id 
   left join aAccount t3 on t1.EmployeeId = t3.Id
   left join invProduct p on t2.ProductId=p.Id
   where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.VtypeId = @VtypeId and t1.[No] = @No 
   order by t1.sno

   
   insert @T2 (PeriodId,VtypeId,No)
   select t1.PeriodId,t1.VtypeId,t1.No from invSalesHeader t1
   join invJobInvoice t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.JobId = t2.JobId
   where t2.CompanyId = @CompanyId and t2.PeriodId = @PeriodId and t2.VtypeId = @VtypeId and t2.[No] = @No 

   insert @T1 (Type,ProductId,Particulars,Qty,Rate,Amount,Code,NameInOL)
   select 1,t1.ProductId,t2.name Particulars,t1.Qty,t1.Rate,t1.gross,t2.Code,t2.OtherLanguage from invSalesDetails t1
   join invProduct t2 on t1.ProductId = t2.Id 
   join @t2 t3 on t1.CompanyId = @CompanyId and t1.PeriodId = t3.PeriodId and t1.VtypeId = t3.VtypeId and t1.[No] = t3.[No]
   order by t1.no,t1.sno

   --Product Properties  
	update sd set sd.Property1=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID join @T1 sd on ppd.ProductID=sd.ProductId where psp.PropertyId=1

   select Type,Sno,Particulars,Employee,Qty,Rate,Amount,Code,NameInOL,Property1 from @T1 order by Sno

 end

go


 if object_id('prGetActiveProductForPurchase') is not null
	drop proc prGetActiveProductForPurchase
go	
   
create proc prGetActiveProductForPurchase
@VendorID int=0,
@UserID int=1,
@CompanyId int=1
as  

set nocount on  
set transaction isolation level read uncommitted

create table #Products([ ]bit,ID int,Code varchar(50),Name nvarchar(200),NativeCaption nvarchar(200),UBC varchar(50),TaxGroupID int,UOMID int,UOM varchar(50),Cost float,SRate float,MRP float,Tax float,TaxGroup varchar(50),Stock float,CCode varchar(50),SerialNo bit,CostCentreId int,AdditionP float,NonStock bit,TaxOnMRP bit)

if (@VendorID>0)
	insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,UOM,Cost,SRate,MRP,SerialNo,CostCentreId,AdditionP,NonStock)
	select p.ID,p.Code,p.Name,p.OtherLanguage,p.TaxGroupId,p.BaseUom,u.Name,p.Cost,p.Rate,p.Mrp,isnull(p.SerialNo,0) SerialNo,p.CostCentreId,p.AdditionP,p.NonStockItem from invProduct p 
	join invUom u on p.BaseUom=u.Id
	join invPreferredVendors v on p.Id=V.ProductId and v.VendorId=@VendorID
	where Inactive is null or Inactive = 0
Else
	insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,UOM,Cost,SRate,MRP,SerialNo,CostCentreId,AdditionP,NonStock)
	select p.ID,p.Code,p.Name,p.OtherLanguage,p.TaxGroupId,p.BaseUom,u.Name,p.Cost,p.Rate,p.Mrp,isnull(p.SerialNo,0) SerialNo,p.CostCentreId,p.AdditionP,p.NonStockItem from invProduct p 
	join invUom u on p.BaseUom=u.Id
	where Inactive is null or Inactive = 0


--Cost Centre Filtering
declare @CC table(Id int)
insert @CC
select isnull(CostCentreId,0) from invUserCostCentre where Product=1 and UserId=@UserID

if exists(select 1 from @CC)
	delete p from #Products p left join @CC c on isnull(p.CostCentreId,0)=c.Id where c.Id is null
-------

create index ind#Products on #Products(ID,UOMID)


--UOM Rates and Barcode
update p set p.UBC=u.Barcode from #Products p join invUomLevels u on p.ID=u.ProductID and p.UOMID = u.UOMID and u.Sno=1


--Aliases
insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,Cost,SRate,MRP,SerialNo,AdditionP)
select p.ID,p.Code,a.Alias,p.NativeCaption,p.TaxGroupId,p.UomId,p.Cost,p.SRate,p.MRP,isnull(p.SerialNo,0) SerialNo,p.AdditionP from #Products p join invProductAlias a on p.ID=a.ProductID

--Tax Details
update p set p.Tax=t.InputTax,p.TaxGroup=t.Name,p.TaxOnMRP=t.OnMRP from #Products p join invTaxGroup t on p.TaxGroupId = t.Id 

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code from #Products p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

-------------------
--Stock
if exists(select 1 from invOption where PurchaseDisplayStock=1 and CompanyId=@CompanyId)--Stock
Begin
	create table #PStock1(CompanyId int,ProductID int,BarcodeId int,Qty float,Pieces float)
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct where not (isnull(InActive,0)=1 or isnull(NonStockItem,0)=1)
	insert #PStock1 
	exec spStock @ToDate=99999999,@Type=12,@CompanyId=@CompanyId
	return
	create table #PStock(CompanyId int,ProductID int,Qty float,Pieces float Unique Clustered(ProductId)) 
	insert #PStock 
	select CompanyId,ProductID,sum(Qty),sum(Pieces) from #PStock1 group by CompanyId,ProductID
	delete #PStock where Qty=0
	update p set p.Stock=s.Qty from #Products p join #PStock s on p.ID=s.ProductID --and s.Qty<>0
End

if exists(select 1 from invOption where PurchaseRate=1 and CompanyID=@CompanyId)
Begin
	;with pd as
	(select row_number()over(partition by ProductId order by PeriodId desc,no desc)sno,pd.ProductId,pd.CostPrice,p.Cost from invPurchaseDetails pd 
	join #Products p on pd.ProductId=p.ID
	where pd.CompanyId=@CompanyId
	)

	update pd set pd.Cost=pd.CostPrice where pd.sno=1

End


if exists(select top 1 1 from invOption where DefaultSearchInPurchase=2 and CompanyId=@CompanyId)
	select Code +'       '+ Name [Code + Name],*,Cost Rate,replace(Code,'*','')Code1 from #Products
else
	select *,Cost Rate,replace(Code,'*','')Code1 from #Products order by name

drop table #Products

go


alter table invPurchaseDetails alter column Remark nvarchar(500)

go

IF OBJECT_ID('prGetPurchase') IS NOT NULL
	DROP PROC prGetPurchase

GO

create proc prGetPurchase  
@CompanyID int,  
@PeriodID int,  
@VtypeId int,  
@No int as  
  
set nocount on  
set transaction isolation level read uncommitted  
  
--Temporaraly Storing Purchase Uom Details   
delete tmpPurchaseUomDetails where ProcId = @@spid  
insert tmpPurchaseUomDetails(ProcId,Sno,ProductId,UomId,LevelId,Rate)  
select @@spid,Sno,ProductId,UomId,LevelId,Rate from invPurchaseUomDetails   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No  
-----------------------------------------  
  
select t1.[No],t1.[Date],t1.[DeliveryDate],t1.[VendorId],t2.Name [Vendor],t1.[PaymentMode],t1.[InvoiceNo],  
t1.[LRNo],t1.[DueDate],t1.[Total],t1.[DiscountP],t1.[Discount],t1.[NetTotal],t1.[Notes],  
t1.[TaxCalculation],t1.[Tax],t1.[TaxType],RoundOff,Paid,t1.InterState,t1.CurrencyId,t1.FromAccountId,t1.ChequeNo,t1.ChequeDate,  
t1.Status,t1.SalesOrderRefNo,t1.Image,t1.Advance,t1.CostCentreId,t1.Discount1,t1.Discount2,t1.Discount3,t1.BillTaxGroupID,t1.BillTax,t1.Image1,t1.SalesManId,t1.Address from invPurchaseHeader t1  
join aAccount t2 on t1.VendorId = t2.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No  
  
declare @Details table(PSNo int,Code nvarchar(50),Particulars nvarchar(200),ProductId int,Warehouse varchar(50),WarehouseId int,Uom varchar(50),  
UomId int,Qty float,Foc float,FRate float,Rate float,CostPrice float,Profit float,SRate float,WRate float,Gross float,DiscountP float,Discount float,Total float,MfrDate smalldatetime,  
ExpDate smalldatetime,Remark nvarchar(500),TaxGroupId int,TaxGroup varchar(50),TaxP float,Tax float,IType int,IPeriodID int,INo int,ISno int,IQty float,IFOC float,Mrp float,UBC varchar(50),  
NativeCaption nvarchar(200),InactiveStock bit,NOP float,Addition float,CCode varchar(50),SerialNo bit,Point float,CostDistribution float,  
Discount1 float,NonStock bit,Pieces float,TaxOnMRP bit)  
  
insert @Details(PSNo,Code,Particulars,ProductId,WarehouseId,Uom,UomId,Qty,Foc,FRate,Rate,CostPrice,Profit,SRate,WRate,Gross,DiscountP,  
Discount,Total,MfrDate,ExpDate,Remark,TaxGroupId,Tax,IType,IPeriodID,INo,ISno,IQty,IFOC,Mrp,NativeCaption,InactiveStock,Addition,NOP,  
SerialNo,Point,CostDistribution,Discount1,NonStock,Pieces)  
select t1.[Sno] PSNo,t2.[Code],t2.Name Particulars,t1.[ProductId],t1.[WarehouseId],t4.Name Uom,  
t1.[UomId],t1.[Qty],t1.[Foc],t1.[FRate],t1.[Rate],t1.[CostPrice],t1.[Profit],t1.[SRate],t1.WRate,t1.[Gross],t1.[DiscountP],  
t1.[Discount],t1.[Total],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],  
cast(cast(case when t1.[ExpDate]<21000101 then t1.[ExpDate] end as varchar) as datetime) [ExpDate] ,t1.[Remark],  
t1.TaxGroupId,t1.Tax,  
t1.[IType],t1.IPeriodID,t1.[INo],t1.[ISno],t1.[IQty],t1.[IFOC],ISNULL(t1.Mrp,0) Mrp,  
t2.OtherLanguage NativeCaption,ISNULL(t1.InactiveStock,0) InactiveStock,t1.Addition,1 NOP,isnull(t2.SerialNo,0),Point,CostDistribution,  
Discount1,t2.NonStockItem,isnull(t1.Pieces,0) from invPurchaseDetails t1  
join invProduct t2 on t1.ProductId = t2.Id   
join invUom t4 on t1.UomId = t4.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No    
  
  
--Category Codes  
declare @@CatPropID int  
select @@CatPropID=CategoryPropertyID from invOption where CompanyID=@CompanyID  
  
declare @Category table(ProductID int,Code varchar(50))  
  
if @@CatPropID is not null  
Begin  
 insert @Category  
 select pp.ProductID,sp.Code from invProductPropertyDetails pp join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID  
End  
  
update d set d.CCode=c.Code from @Details d join @Category c on d.ProductID=c.ProductID  
  
--Barcode  
update d set d.UBC=ul.Barcode from @Details d join invUOMLevels ul on d.ProductID=ul.ProductID and d.UOMId=ul.UOMID  
  
--WareHouse  
update d set d.WareHouse=w.Name from @Details d join invWareHouse w on d.WarehouseID=w.ID  
  
--Tax Group  
update d set d.TaxGroup=t.Name,d.TaxP=t.InputTax,d.TaxOnMRP=t.OnMRP from @Details d join invTaxGroup t on d.TaxGroupID=t.ID   
  
--NOP  
update d set d.NOP=ul.Multiplayer from @Details d join invUOMLevels ul on d.ProductID=ul.ProductID and ul.Secondary<>1 and ul.SNo<3  
  
--Final Selection  
select * from @Details order by PSno  
---------------------------  
  
select SNo,BarcodeId,Barcode,SRate,Printed,Sticker from invAutoBarcodeAndSalesRate   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No order by Sno  
  
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1  
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id   
join invPurchaseProperty t3 on t2.PropertyId = t3.Id   
where t1.CompanyID = @CompanyID and t1.PeriodID  = @PeriodID and t1.[VtypeId] = @VtypeId and t1.[No] = @No order by t1.Sno   
  
select [PSno],[Sno],[SerialNo],[Id] from invProductSerialNumber   
where CompanyID = @CompanyID and PeriodID  = @PeriodID and [VtypeId] = @VtypeId and [No] = @No   
order by [PSno],[Sno]  
  
select a.CreditorID,c.Name Creditor,a.DebtorID,d.Name Debtor,a.Description,a.Amount,a.DNo from invPurchaseAdditions a  
join aAccount c on a.CreditorID=c.ID  
join aAccount d on a.DebtorID=d.ID  
where a.CompanyID = @CompanyID and a.PeriodID  = @PeriodID and a.[VtypeId] = @VtypeId and a.[No] = @No   
  
  
select t.ProductID,p.Name Product,t.OB,t.[In],t.[Out],t.Balance from invPurchaseTrayDetails t  
join invProduct p on t.ProductID=p.ID  
where t.CompanyID = @CompanyID and t.PeriodID  = @PeriodID and t.[VtypeId] = @VtypeId and t.[No] = @No   
  
GO







IF OBJECT_ID('prSavePurchase') IS NOT NULL
	DROP PROC prSavePurchase

GO
  
create proc prSavePurchase    
@CompanyID int,    
@PeriodID int,    
@VtypeId int,    
@No int,    
@Date int,    
@DeliveryDate int,    
@VendorId int,    
@PaymentMode tinyint,    
@InvoiceNo varchar(20),    
@DueDate int,    
@Total float,    
@DiscountP float,    
@Discount float,    
@RoundOff float,    
@NetTotal float,    
@Paid float,    
@Notes varchar(500),    
@TaxCalculation int,    
@Tax float,    
@TaxType int,    
@LRNo varchar(20),    
@Addition float,  
@InterState bit=null,  
@Export bit,  
@CurrencyId int,  
@FromAccountID int=null,  
@ChequeNo varchar(50)=null,  
@ChequeDate int=null,  
@Status tinyint=null,  
@XmlProductDetails xml,    
@XmlBarcodeDetails xml,    
@XmlPropertyDetails xml,    
@XmlProductSno xml,    
@XmlAdditions xml,  
@UserId int  = null,  
@SalesOrderRefNo varchar(50) = null,  
@Image Image =null,  
@Advance float=null,  
@CostCentreId int=null,  
@Discount1 float=null,  
@Discount2 float=null,  
@Discount3 float=null,  
@BillTaxGroupID int=null,  
@BillTax float=null,  
@Image1 Image =null,  
@SalesManId int=null,  
@XmlTray xml=null,  
@Address nvarchar(300)=null  
  
as    
  
set nocount on    
    
set xact_abort on    
    
--Validation    
    
--Barcode & Sales Rate    
    
declare @Idoc int    
declare @SerialId int --IMI Id  
declare @VoucherTypeID int  
    
declare @invAutoBarcodeAndSalesRate table(Sno int,ProductId int,UomId int,BarcodeId int,Barcode varchar(25),SRate float,Printed bit,Rate float,Cost float,MRP float,Sticker int)    
    
exec sp_xml_preparedocument @Idoc out ,@XmlBarcodeDetails    
    
insert @invAutoBarcodeAndSalesRate ([Sno],[ProductId],[UomId],[BarcodeId],[Barcode],[SRate],[Printed],[Rate],[Cost],MRP,Sticker)    
select [Sno],[ProductId],[UomId],[BarcodeId],[Barcode],[SRate],[Printed],[Rate],[Cost],Mrp,Sticker from openxml (@Idoc,'/TableHeader/Table1',2)    
with    
(    
Sno int '@Sno',    
ProductId int '@ProductId',    
UomId int '@UomId',    
BarcodeId int '@BarcodeId',    
Barcode varchar(25) '@Barcode',    
SRate float '@SRate',    
Printed bit '@Printed',    
Rate float '@Rate',    
Cost float '@Cost',  
Mrp float '@Mrp',  
Sticker int '@Sticker'  
)    
    
exec sp_xml_removedocument @Idoc    
    
declare @Message varchar(100)    
  
select @Message='Barcode '+ b.Barcode +' is already given as Code for the item '+ u.Name from @invAutoBarcodeAndSalesRate b join invProduct u on b.Barcode=u.Code    
if @Message is not null    
Begin    
 select @No No,@Message Message    
 return    
End    
  
    
select @Message='Barcode '+ b.Barcode +' is already given as UBC for an item' from @invAutoBarcodeAndSalesRate b join invUOMLevels u on b.Barcode=u.Barcode where len(rtrim(b.Barcode))>0  
if @Message is not null    
Begin    
 select @No No,@Message Message    
 return    
End    
  
  
select @Message='Barcode '+ b.Barcode +' is already given as Barcode for an item' from @invAutoBarcodeAndSalesRate b 
join invAutoBarcodeAndSalesRate u on b.Barcode=u.Barcode  where not (u.CompanyID=@CompanyID and u.PeriodID=@PeriodID and 
u.VtypeID=@VtypeID and u.No=@No) and  len(rtrim(b.Barcode))>0  
if @Message is not null    
Begin    
 select @No No,@Message Message    
 return    
End    
  
  
declare @PurchaseAccountID int,@DiscountAccountID int,@CashInHandID int,@PurchaseRoundOffAccount int,@TaxAccountID int,@PDCPayableID int    
select @PurchaseAccountID=Purchase,@DiscountAccountID=DiscountReceived,@CashInHandID=CashInHand,@PDCPayableID=PDCPayable from aAccountSettings where CompanyID=@CompanyID  
    
select @TaxAccountID=InPutTaxAccount,@PurchaseRoundOffAccount = PurchaseRoundOffAccount from invOption  where CompanyID = @CompanyID  
  
if @RoundOff<>0  and isnull(@PurchaseRoundOffAccount,0) = 0  
Begin  
 select @No No,'Please set Account for Purchase Round Off' Message    
 return  
End    
-----end of Validation    
    
Begin Transaction    
  
--declare @Sync int  
  
if(@No = 0)    
begin    
 declare @T1 table([No] int)    
 insert @T1 exec prGetPurchaseMaxVno @CompanyId,@PeriodId,@VtypeId    
 select @No = [No] from @T1     
end    
else    
begin    
 delete invPurchaseHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
  
 ALTER TABLE invPurchaseDetails Disable TRIGGER triggerinvPurchaseDetails  
 delete invPurchaseDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
 ALTER TABLE invPurchaseDetails Enable TRIGGER triggerinvPurchaseDetails  
  
 delete invAutoBarcodeAndSalesRate where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
 delete invPurchasePropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
 delete invPurchaseUomDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
 delete invPurchaseAdditions where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
  
 delete invPurchaseTrayDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
  
  
 select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId  
 delete aTransaction where ModuleID = 1 and VoucherTypeID = @VoucherTypeID and [No] = @No and CompanyID=@CompanyID and PeriodID=@PeriodID  
  
 declare @Sync int  
 select @Sync=isnull(max(ID),1)*3 from invCostCentre  
 delete s from invSyncDetails s where s.CompanyID=@CompanyID and s.PeriodID=@PeriodId and s.VtypeID=@VtypeId and s.No=@No  
 if exists(select 1 from invOption where CompanyID=@CompanyID and SyncUpdatedEntries=1)  
  insert invSyncDetails(CompanyID,PeriodID,VtypeID,No,SyncCompanyID,SyncCount)  
  select @CompanyID,@PeriodID,@VtypeId,@No,c.ID,@Sync from aCompany c   
end     
   
 set transaction isolation level read uncommitted  
  
 insert invPurchaseHeader([CompanyId],[PeriodId],[VtypeId],[No],[Date],[DeliveryDate],[VendorId],[PaymentMode],[InvoiceNo],    
 [DueDate],[Total],[DiscountP],[Discount],[NetTotal],[Notes],[TaxCalculation],[Tax],[TaxType],[LRNo],[RoundOff],Paid,InterState,  
 CurrencyId,FromAccountID,ChequeNo,ChequeDate,Status,UserId,SalesOrderRefNo,Image,Advance,CostCentreId,Discount1,Discount2,Discount3,BillTaxGroupID,BillTax,Image1,SalesManId,Address)    
 values(@CompanyId,@PeriodId,@VtypeId,@No,@Date,@DeliveryDate,@VendorId,@PaymentMode,@InvoiceNo,@DueDate,    
 @Total,@DiscountP,@Discount,@NetTotal,@Notes,@TaxCalculation,@Tax,@TaxType,nullif(@LRNo,''),nullif(@RoundOff,0),nullif(@Paid,0),  
 nullif(@InterState,0),nullif(@CurrencyId,0),nullif(@FromAccountID,0),nullif(@ChequeNo,''),nullif(@ChequeDate,0),nullif(@Status,0),nullif(@UserId,0),  
 nullif(@SalesOrderRefNo,''),@Image,nullif(@Advance,0),nullif(@CostCentreId,0),@Discount1,@Discount2,@Discount3,nullif(@BillTaxGroupID,0),@BillTax,@Image1,NULLIF(@SalesManId,0),nullif(rtrim(@Address),''))    
   
 declare @Details table(Sno int,ProductId int,WarehouseId int,UomId int,Qty float,Foc float,FRate float,Rate float,CostPrice float,SRate float,WRate float,    
 Mrp float,Profit float,Gross float,Addition float,TaxGroupId int,Tax float,DiscountP float,Discount float,Total float,MfrDate int,ExpDate int,    
 Remark varchar(100),IType int,IPeriodID int,INo int,ISno int,IQty float,IFOC float,InactiveStock bit,Point float,CostDistribution float,Discount1 float,Pieces float)  
  
  
 exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails    
     
 insert @Details    
 ([Sno],[ProductId],[WarehouseId],[UomId],  
 [Qty],[Foc],[FRate],[Rate],[CostPrice],[SRate],WRate,[Profit] ,[Gross],[TaxGroupId],  
 [Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],    
 [IType],IPeriodID,[INo],[ISno],[IQty],[IFOC],[Mrp],[InactiveStock],Addition,Point,CostDistribution,Discount1,Pieces)    
   
 select [Sno],[ProductId],nullif([WarehouseId],0),UomId,[Qty],[Foc],[FRate],[Rate],[CostPrice],    
 nullif(SRate,0),nullif(WRate,0),[Profit],[Gross],nullif([TaxGroupId],0),[Tax],[DiscountP],[Discount],[Total],    
 --convert(varchar,[MfrDate],112),  
 --convert(varchar,[ExpDate],112),  
 case when MfrDate<>ExpDate then convert(varchar,[MfrDate],112) end,  
 case when MfrDate<>ExpDate then convert(varchar,[ExpDate],112) end,  
[Remark],    
 nullif([IType],0) [IType],nullif([IPeriodID],0) [IPeriodID],nullif([INo],0) [INo],[ISno],    
 nullif([IQty],0) [IQTy], nullif([IFOC],0) [IFOC],nullif([Mrp],0) Mrp,  
 nullif([InactiveStock],0) InactiveStock,nullif(Addition,0),nullif(Point,0),nullif(CostDistribution,0),nullif(Discount1,0),nullif(Pieces,0) from openxml (@Idoc,'/TableHeader/Table1',2)    
 with    
 (    
 Sno            int '@PSno',    
 ProductId      int '@ProductId',    
 WarehouseId    int '@WarehouseId',    
 UomId          int '@UomId',    
 Qty            float '@Qty',    
 Foc            float '@Foc',   
 Pieces         float '@Pieces',    
 FRate          float '@FRate',    
 Rate           float '@Rate',    
 CostPrice      float '@CostPrice',    
 SRate          float '@SRate',    
 WRate          float '@WRate',    
 Mrp            float '@MRP',    
 Profit         float '@Profit',    
 Gross          float '@Gross',    
 Addition       float '@Addition',   
 TaxGroupId     int '@TaxGroupId',    
 Tax            float '@Tax',    
 DiscountP      float '@DiscountP',    
 Discount       float '@Discount',    
 Discount1      float '@Discount1',  
 Total          float '@Total',    
 MfrDate        datetime '@MfrDate',    
 ExpDate        datetime '@ExpDate',    
 Remark         nvarchar(500) '@Remark',    
 IType          int '@IType',    
 IPeriodID      int '@IPeriodID',  
 INo            int '@INo',    
 ISno           int '@ISno',    
 IQty           float '@IQty',    
 IFOC           float '@IFOC',  
 InactiveStock  bit '@InactiveStock',  
 Point          float '@Point',  
 CostDistribution float '@CostDistribution'  
 )    
    
 exec sp_xml_removedocument @Idoc    
   
  
if not exists(select 1 from invPurchaseColumnCustomization where SRate=1)  
 update @Details set SRate=null  
  
 insert invPurchaseDetails    
 (CompanyId,[PeriodId],[VtypeId],[No],[Sno],[ProductId],[WarehouseId],[UomId],  
 [Qty],[Foc],[FRate],[Rate],[CostPrice],[SRate],WRate,[Profit] ,[Gross],[TaxGroupId],  
 [Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],    
 [IType],IPeriodID,[INo],[ISno],[IQty],[IFOC],[Mrp],[InactiveStock],Addition,Point,CostDistribution,Discount1,Pieces)    
 select @CompanyId,@PeriodId,@VtypeId,@No,[Sno],[ProductId],[WarehouseId],[UomId],  
 [Qty],[Foc],[FRate],[Rate],[CostPrice],[SRate],WRate,[Profit] ,[Gross],[TaxGroupId],  
 [Tax],[DiscountP],[Discount],[Total],nullif([MfrDate],19000101),nullif([ExpDate],19000101),[Remark],    
 [IType],IPeriodID,[INo],[ISno],[IQty],[IFOC],[Mrp],[InactiveStock],Addition,Point,CostDistribution,Discount1,Pieces  
 from @Details  
   
  
 --Barcode & Sales Rate    
 --exec sp_xml_preparedocument @Idoc out ,@XmlBarcodeDetails    
    
 insert invAutoBarcodeAndSalesRate ([CompanyId],[PeriodId],[VtypeId],[No],[Sno],[ProductId],[UomId],[BarcodeId],    
 [Barcode],[SRate],[Printed],[Rate],[Cost],[Mrp],Sticker)    
 select @CompanyId,@PeriodId,@VtypeId,@No,[Sno],[ProductId],[UomId],[BarcodeId],[Barcode],[SRate],    
 [Printed],[Rate],[Cost],nullif([Mrp],0),nullif(Sticker,0) from @invAutoBarcodeAndSalesRate  
   
 --openxml (@Idoc,'/TableHeader/Table1',2)    
 --with    
 --(    
 --Sno int '@Sno',    
 --ProductId int '@ProductId',    
 --UomId int '@UomId',    
 --BarcodeId int '@BarcodeId',    
 --Barcode varchar(25) '@Barcode',    
 --SRate float '@SRate',    
 --Printed bit '@Printed',    
 --Rate float '@Rate',    
 --Cost float '@Cost',  
 --Mrp float '@Mrp',  
 --Sticker int '@Sticker'  
 --)    
    
 --exec sp_xml_removedocument @Idoc    
   
  
 --Property    
 exec sp_xml_preparedocument @Idoc out ,@XmlPropertyDetails    
    
 insert invPurchasePropertyDetails([CompanyId],[PeriodId],[VtypeId],[No],[Sno],[ProductId],[BarcodeId],[SubPropertyId])    
 select @CompanyId,@PeriodId,@VtypeId,@No,[Sno],[ProductId],[BarcodeId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)    
 with    
 (    
 Sno int '@Sno',    
 ProductId int '@ProductId',    
 BarcodeId int '@BarcodeId',    
 SubPropertyId int '@SubPropertyId'    
 )    
    
 exec sp_xml_removedocument @Idoc    
    
    --<Purchase Uom Details>    
    insert invPurchaseUomDetails([CompanyId],[PeriodId],VtypeId,[No],Sno,ProductId,UomId,LevelId,Rate)    
    select @CompanyId,@PeriodId,@VtypeId,@No,Sno,ProductId,UomId,LevelId,Rate  from tmpPurchaseUomDetails      
    where ProcId = @@spid     
        
    delete tmpPurchaseUomDetails  where ProcId = @@spid     
    --<Purchase Uom Details/>    
    
    
    
 --Product Serial Number    
 declare @SerialNumber table  
 (  
   PSno int,    
   Sno int,    
   SerialNo varchar(100),  
   Id int  
 )  
   
 exec sp_xml_preparedocument @Idoc out ,@XmlProductSno    
    
 select @SerialId = isnull(max(Id),0) from invProductSerialNumber  
  
 --Generating the Primary key for IMI  
 insert @SerialNumber([PSno],[Sno],[SerialNo],[Id])    
 select [PSno],[Sno],[SerialNo],[Id] from openxml (@Idoc,'/TableHeader/Table1',2)    
 with    
 (    
 PSno int '@PSno',    
 Sno int '@Sno',    
 SerialNo varchar(100) '@SerialNo',  
 Id int '@Id'    
 )    
    
 exec sp_xml_removedocument @Idoc    
    
  
  -- Tray Details  
   
 exec sp_xml_preparedocument @Idoc out,@XmlTray    
 insert invPurchaseTrayDetails([CompanyId],[PeriodId],[VtypeId],[No],ProductID,OB,[In],[Out],Balance)    
 select @CompanyId,@PeriodId,@VtypeId,@No,ProductID,[OB],[In],[Out],Balance  from openxml (@Idoc,'/TableHeader/Table1',2)    
 with    
 (    
 ProductID int '@ProductID',  
 [OB] int '@OB',   
 [In] int '@In',    
 [Out] int '@Out',     
 Balance int '@Balance'  
    
 )    
 exec sp_xml_removedocument @Idoc    
  
  
;with t1 as(select *,row_number() over(order by PSno,Sno) TSNo from @SerialNumber where Id = 0)  
update t1 set Id = @SerialId + TSNo  where Id = 0  
  
  
 --Delete removed IMI  
 delete t1 from  invProductSerialNumber t1  
 left outer join @SerialNumber t2 on t1.Id = t2.Id  
 where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.VtypeId = @VtypeId and t1.No = @No and t2.Id is null   
  
 insert invProductSerialNumber([CompanyId],[PeriodId],[VtypeId],[No],[PSno],[Sno],[SerialNo],[Id])     
 select @CompanyId,@PeriodId,@VtypeId,@No,t1.[PSno],t1.[Sno],t1.[SerialNo],t1.[Id] from @SerialNumber t1  
 left outer join invProductSerialNumber t2 on t1.Id = t2.Id    
 where t2.Id is null  
   
 update t1 set t1.sno = t2.sno,t1.[SerialNo] = t2.[SerialNo] from  invProductSerialNumber t1  
 join @SerialNumber t2 on t1.Id = t2.Id  
   
  
 --Checking of duplicate entry  
 declare @IMI table  
 (  
 SerialNo varchar(100)  
 )  
  
 insert @IMI(SerialNo) select SerialNo from invProductSerialNumber   
 where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No  
   
  
 --Duplicate Serial Number  
 declare @DupSerNo table(SerialId int,SerialNo varchar(50),Qty float)  
 insert @DupSerNo  
 select t1.Id,t1.SerialNo,1 from invProductSerialNumber t1  
 join @IMI t2 on t1.SerialNo = t2.SerialNo   
 where not(t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[VtypeId] = @VtypeId and t1.[No] = @No)  
  
 insert @DupSerNo  
 select SerialNoId,s.SerialNo,-pd.Qty from invPurchaseReturnDetails pd  
 join @DupSerNo s on pd.SerialNoId=s.SerialId  
 where pd.CompanyId = @CompanyId  
  
 select @Message='Serial No.'+SerialNo+' Have already in Stock' from @DupSerNo group by SerialNo having sum(Qty)>0  
 if @Message is not null  
 begin  
    select @No No,@Message [Message]    
    rollback transaction  
 return  
 end  
 -------------  
  
  
 --Additions    
 declare @PurchaseAdditions table(CreditorID int,DebtorID int,Description varchar(100),Amount float,DNo int)    
 exec sp_xml_preparedocument @Idoc out ,@XmlAdditions    
 insert @PurchaseAdditions(CreditorID,DebtorID,Description,Amount,DNo)    
 select CreditorID,DebtorID,nullif(Description,''),Amount,DNo from openxml (@Idoc,'/TableHeader/Table1',2)    
 with    
 (    
 CreditorID  int '@CreditorID',    
 DebtorID    int '@DebtorID',    
 Description varchar(100) '@Description',    
 Amount      float '@Amount'  ,  
 DNo      int '@DNo'  
 )    
 where Amount<>0    
    
 exec sp_xml_removedocument @Idoc    
    
 insert invPurchaseAdditions(CompanyId,PeriodId,VtypeId,No,CreditorID,DebtorID,Description,Amount,DNo)    
 select @CompanyId,@PeriodId,@VtypeId,@No,CreditorID,DebtorID,Description,Amount,DNo from @PurchaseAdditions    
   
 if @FromAccountID=0  
 set @FromAccountID=@CashInHandID  
   
  
 --Posting to Accounts    
if exists(select 1 from invOption where AccountLinking=1)    
Begin    
   
 select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId    
 set @VoucherTypeID=isnull(@VoucherTypeID,0)  
  
 select @CostCentreId=CostCentreId from invCostCentre where id=@CostCentreId  
 select @CostCentreId=c.CostCentreId from invVoucherTypeDetails v join invCostCentre c on v.CostCentreId=c.id where v.ID=@VtypeId  
 select @CostCentreId=nullif(@CostCentreId,0)  
  
 if @PaymentMode=0 and @Paid>@NetTotal  
  insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
  values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@VendorID,@FromAccountID,@Paid-@NetTotal,'Excess Paid In Purchase',@CostCentreId)  
  
 declare @CreditorId int  
 declare @Vendor nvarchar(100)  
   
   
 if @PaymentMode=0  
 Begin  
  select @Vendor=Name from aAccount where Id=@VendorId  
  --set @CreditorId=case when @FromAccountID=0 then @CashInHandID else @FromAccountID end  
  set @CreditorId=@CashInHandID  
 End  
 else  
  set @CreditorId=@VendorId  
  
  
 --Addition  
 if @Addition<>0  
 Begin  
  declare @AdditionAccountID int  
  select @AdditionAccountID=PurchaseAdditionAccount from invOption where CompanyId=@CompanyId  
  
  if @AdditionAccountID>0   
   insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)  
   values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,4,@AdditionAccountID,@PurchaseAccountID,@Addition,'Addition In Purchase',@CostCentreId)    
  else  
   set @Total=@Total-@Addition  
    
 End  
  
  
  
 if @PaymentMode=1 and @Paid<>0  
 Begin  
  --Total    
  insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)    
  values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@PurchaseAccountID,@CreditorId,@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+isnull(@BillTax,0),'Purchase - '+@InvoiceNo+'   '+convert(varchar,cast(cast(@DeliveryDate as varchar) as smalldatetime),
106),@CostCentreId)     
  
  --Paid  
  if len(@ChequeNo)>0  
   insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,AccountID,CNo,CDate,CostCentreId,Sno)  
   values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditorId,@PDCPayableID,@Paid,'Paid In Purchase',@FromAccountID,@ChequeNo,@ChequeDate,@CostCentreId,1)  
  Else  
   insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId,Sno)  
   values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditorId,@FromAccountID,@Paid,'Paid In Purchase',@CostCentreId,1)  
  End  
 Else  
 Begin  
  --Total    
  if @Advance<>0 and @PaymentMode=0  
  Begin  
   insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)    
   values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@PurchaseAccountID,@CreditorId,@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+isnull(@BillTax,0)-@Advance-isnull(@Paid,0),
   'Purchase - '+@InvoiceNo+'   '+convert(varchar,cast(cast(@DeliveryDate as varchar) as smalldatetime),106) + isnull('  '+@Vendor,''),@CostCentreId)     
  
   insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)    
   values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@PurchaseAccountID,@VendorId,@Advance,
   'Purchase - '+@InvoiceNo+'   '+convert(varchar,cast(cast(@DeliveryDate as varchar) as smalldatetime),106) + isnull('  '+@Vendor,''),@CostCentreId)     
  End  
  else  
   insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)    
   values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@PurchaseAccountID,@CreditorId,@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+isnull(@BillTax,0)-isnull(@Paid,0),
   'Purchase - '+@InvoiceNo+'   '+convert(varchar,cast(cast(@DeliveryDate as varchar) as smalldatetime),106) + isnull('  '+@Vendor,''),@CostCentreId)     
 End  
    
 --Partial Payment  
 if @PaymentMode=0 and @Paid<>0  
 Begin  
  insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)    
  values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@PurchaseAccountID,@FromAccountId,@Paid,'Purchase - '+@InvoiceNo+'   '+convert(varchar,cast(cast(@DeliveryDate as varchar) as smalldatetime),106) + isnull('  '+@Vendor,''),@CostCentreId)     
 End  
  
  
 --Tax    
 if @Tax>0  and isnull(@TaxAccountID,0) > 0   
 Begin    
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,1,@TaxAccountID,@PurchaseAccountID,@Tax,'Purchase Tax - '+@InvoiceNo,@CostCentreId)     
 End    
    
   --Tax    
 if @BillTax>0  and isnull(@TaxAccountID,0) > 0   
 Begin    
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,1,@TaxAccountID,@PurchaseAccountID,@BillTax,'Purchase Tax - '+@InvoiceNo,@CostCentreId)     
 End    
    
    
 --Discount    
 if @Discount>0    
 Begin    
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,2,@PurchaseAccountID,@DiscountAccountID,@Discount,'Purchase Discount - '+@InvoiceNo,@CostCentreId)     
 End    
    
 --RoundOff    
 if @RoundOff>0  and isnull(@PurchaseRoundOffAccount,0) > 0  
 Begin    
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,3,@PurchaseRoundOffAccount,@PurchaseAccountID,@RoundOff,'Purchase RoundOff - '+@InvoiceNo,@CostCentreId)     
 End    
    
 if @RoundOff<0    
 Begin    
  insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
  values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,3,@PurchaseAccountID,@PurchaseRoundOffAccount,abs(@RoundOff),'Purchase RoundOff - '+@InvoiceNo,@CostCentreId)     
 End    
    
 --Additions    
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,row_number()over(order by Amount desc)+3,DebtorID,CreditorID,Amount,Description,@CostCentreId from @PurchaseAdditions where Amount>0  
  
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,row_number()over(order by Amount desc)+3,CreditorID,DebtorID,abs(Amount),Description,@CostCentreId from @PurchaseAdditions where Amount<0  
    
   
 --Product Account  
 insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)    
 select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,p.AccountId,@PurchaseAccountID,sum(d.Gross),p.Name,@CostCentreId from @Details d join invProduct p on d.ProductId=p.Id where p.AccountId is not null group by p.AccountId,p.Name  
    
End    
    
Commit    
  
if @Export=1  
 exec prExportPurchase @CompanyID=@CompanyID,@PeriodID=@PeriodID,@VtypeID=@VtypeID,@ExportNo=@No  
     
select @No No,@Message Message  

GO
if object_id('spSyncDownloadProduct') is not null drop proc spSyncDownloadProduct

go

create proc spSyncDownloadProduct
@CompanyID int

as

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 


-----------------------
declare @Forms table(FormId varchar(10),Name varchar(100))
insert @Forms
select FormId,Name from invForms where FormId like'1%' 

if exists(select 1 from invProjectSettings where CompanyId=@CompanyId and BlockMasterCreation=1)
	delete @Forms where FormId in('1','12','1C')

declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Destination DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join @Forms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End
---------------------------


if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End

Begin try
	--Downloading

	--Masters


	--invUOM
	exec ('insert Into invUOM(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOM a1
			left join invUOM a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--invProduct
	exec ('insert Into invProduct(Id,Code,Name,Packing,OtherLanguage,CostCentreId,Cost,Rate,BaseUom,PurchaseUom,SalesUom,StockUom,MinStock,MinUom,MaxStock,MaxUom,ROL,ROLUom,ROQ,ROQUom,Inactive,NonStockItem,Expiry,CounterItem,AutoEntry,Barcode,TaxGroupId,Mrp,PackingUnit,Profit,HideFromDevice,TaxInclusive,NRate,RateEdit)
		   select a1.Id,a1.Code,a1.Name,a1.Packing,a1.OtherLanguage,a1.CostCentreId,a1.Cost,a1.Rate,a1.BaseUom,a1.PurchaseUom,a1.SalesUom,a1.StockUom,a1.MinStock,a1.MinUom,a1.MaxStock,a1.MaxUom,a1.ROL,a1.ROLUom,a1.ROQ,a1.ROQUom,a1.Inactive,a1.NonStockItem,a1.Expiry,a1.CounterItem,a1.AutoEntry,a1.Barcode,a1.TaxGroupId,a1.Mrp,a1.PackingUnit,a1.Profit,a1.HideFromDevice,a1.TaxInclusive,a1.NRate,a1.RateEdit from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a1
		   left join invProduct a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.AutoEntry=a2.AutoEntry,a1.TaxGroupID=a2.TaxGroupID,a1.OtherLanguage=a2.OtherLanguage,a1.InActive=a2.InActive,a1.MRP=a2.MRP,a1.NRate=a1.NRate,a1.WRate=a2.WRate from invProduct a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a2 on a1.ID=a2.ID')


	ALTER TABLE invUOMLevels Disable TRIGGER triggerinvUOMLevels
	--invUOMLevels
	exec ('insert Into invUOMLevels(Sno,ProductID,UOMID,Multiplayer,UnitID,Secondary,Cost,Rate,Barcode,BarcodeID,MRP,NRate)
		   select a1.Sno,a1.ProductID,a1.UOMID,a1.Multiplayer,a1.UnitID,a1.Secondary,a1.Cost,a1.Rate,a1.Barcode,a1.BarcodeID,a1.MRP,a1.NRate from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a1
		   left join invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno
		   where a2.ProductID is null'
		)

	exec ('update a1 set a1.UomId=a2.UomId,a1.MultiPlayer=a2.MultiPlayer,a1.UnitId=a2.UnitId,a1.Secondary=a2.Secondary,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.Barcode=a2.Barcode,a1.BarcodeId=a2.BarcodeId,a1.MRP=a2.MRP,a1.NRate=a2.NRate from invUOMLevels a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno')

	ALTER TABLE invUOMLevels Enable TRIGGER triggerinvUOMLevels

	
	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if object_id('prGetLabelPrintCollection') is not null 
	drop proc prGetLabelPrintCollection

go

create proc prGetLabelPrintCollection  
@xmlBarcode nvarchar(max),  --xml (changed due to arabic problem)
@BlankLabels tinyint  
  
as  
  
declare @Idoc int  
exec sp_xml_preparedocument @Idoc out,@xmlBarcode  
  
select null Sno,null Code,null Name,cast(null as nvarchar(100)) OtherLanguage,null VendorCode,null Vendor,null Barcode,
null Cost,null Rate,null NRate,null EncryptedCost,null EncryptedRate,null Size,null Remark,null MRP,
null Property1,null Property2,null Property3 ,null MfrDate ,null  ExpDate,null PProperty1,null PProperty2,null UOM,null SCount,null Sticker,null WRate , null EncryptedWRate from master..spt_values where type
='P' and number<@BlankLabels  
union all  
select SNo,Code,x.Name,OtherLanguage,VendorCode,Vendor,Barcode,Cost,Rate,NRate,EncryptedCost,EncryptedRate,Size,Remark,
MRP,Property1,Property2,Property3,MfrDate,ExpDate,PProperty1,PProperty2,UOM,n.number+1,x.Sticker,WRate ,EncryptedWRate from openxml (@Idoc,'/TableHeader/Table1',2)  
with  
(  
SNo int '@Sno',
Code varchar(100) '@Code',  
Name nvarchar(100) '@Name',  
OtherLanguage nvarchar(100) N'@OtherLanguage',  
VendorCode nvarchar(100) '@VendorCode',  
Vendor varchar(100) '@Vendor',  
Barcode varchar(100) '@Barcode',  
Sticker int '@Sticker',  
Cost float '@Cost',  
Rate float '@SRate',
NRate float '@NRate',
MRP float '@MRP',  
EncryptedCost varchar(25) '@EncryptedCost',  
EncryptedRate nvarchar(25) '@EncryptedRate', 
Size varchar(50) '@Size',  
Remark varchar(100) '@Remark',  
Property1 varchar(50) '@Property1',  
Property2 varchar(50) '@Property2',  
Property3 varchar(50) '@Property3',  
Printed bit '@Printed'  ,
MfrDate DateTime '@MDate' ,
ExpDate DateTime '@EDate',
PProperty1 varchar(50) '@PProperty1',  
PProperty2 varchar(50) '@PProperty2',
UOM varchar(50) '@UOM',
EncryptedWRate nvarchar(25) '@EncryptedWRate',  
WRate nvarchar(25) '@WRate'
) x  
join master..spt_values n on n.number<x.Sticker  
where x.Printed=0 and n.type='P'  
order by SNo
  
exec sp_xml_removedocument @Idoc  
  
GO

if object_id('spSyncDownloading') is not null drop proc spSyncDownloading

go

create proc spSyncDownloading
@CompanyID int

as

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 


-----------------------
declare @Forms table(FormId varchar(10),Name varchar(100))
insert @Forms
select FormId,Name from invForms where FormId like'1%' 

if exists(select 1 from invProjectSettings where CompanyId=@CompanyId and BlockMasterCreation=1)
	delete @Forms where FormId in('1','12','1C')

declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Source DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join @Forms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End
---------------------------

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End

Begin try
	--Downloading

	--Masters


	--aPeriod
	exec ('insert Into aPeriod([ID],[Code],[Name],[From],[To])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[From],a1.[To] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aPeriod a1
		   left join aPeriod a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountGroup
	exec ('insert Into aAccountGroup([ID],[Code],[Name],[AccountTypeID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountTypeID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup a1
		   left join aAccountGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountSubGroup
	exec ('insert Into aAccountSubGroup([ID],[Code],[Name],[AccountGroupID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountGroupID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup a1
		   left join aAccountSubGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )


	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
		   left join aAccount a2 on a1.ID=a2.ID
		   where a2.ID is null'
			)

	exec (' update a1 set a1.Name=a2.Name,a1.UnderAccountID=a2.UnderAccountID,a1.NameInOL=a2.NameInOL from aAccount a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID')



	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
			select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
			left join aAccount a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--aCompany
	exec ('insert Into aCompany(ID,Code,Name,Address,Phone,Email,AccountID)
		   select a1.ID,a1.Code,a1.Name,a1.Address,a1.Phone,a1.Email,a1.AccountID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCompany a1
		   left join aCompany a2 on a1.ID=a2.ID
		   where a2.ID is null 
		   and a1.ID in(select CompanyFrom from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCompanyTransferHeader union select CompanyTo from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCompanyTransferHeader)'
		 )
	

	--invUOM
	exec ('insert Into invUOM(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOM a1
			left join invUOM a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--invProduct
	exec ('insert Into invProduct(Id,Code,Name,Packing,OtherLanguage,CostCentreId,Cost,Rate,BaseUom,PurchaseUom,SalesUom,StockUom,MinStock,MinUom,MaxStock,MaxUom,ROL,ROLUom,ROQ,ROQUom,Inactive,NonStockItem,Expiry,CounterItem,AutoEntry,Barcode,TaxGroupId,Mrp,PackingUnit,Profit,HideFromDevice,TaxInclusive,NRate,RateEdit)
		   select a1.Id,a1.Code,a1.Name,a1.Packing,a1.OtherLanguage,a1.CostCentreId,a1.Cost,a1.Rate,a1.BaseUom,a1.PurchaseUom,a1.SalesUom,a1.StockUom,a1.MinStock,a1.MinUom,a1.MaxStock,a1.MaxUom,a1.ROL,a1.ROLUom,a1.ROQ,a1.ROQUom,a1.Inactive,a1.NonStockItem,a1.Expiry,a1.CounterItem,a1.AutoEntry,a1.Barcode,a1.TaxGroupId,a1.Mrp,a1.PackingUnit,a1.Profit,a1.HideFromDevice,a1.TaxInclusive,a1.NRate,a1.RateEdit from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a1
		   left join invProduct a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.AutoEntry=a2.AutoEntry,a1.TaxGroupID=a2.TaxGroupID,a1.OtherLanguage=a2.OtherLanguage,a1.InActive=a2.InActive,a1.MRP=a2.MRP,a1.NRate=a1.NRate,a1.WRate=a2.WRate from invProduct a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProduct a2 on a1.ID=a2.ID')


	ALTER TABLE invUOMLevels Disable TRIGGER triggerinvUOMLevels
	--invUOMLevels
	exec ('insert Into invUOMLevels(Sno,ProductID,UOMID,Multiplayer,UnitID,Secondary,Cost,Rate,Barcode,BarcodeID,MRP,NRate)
		   select a1.Sno,a1.ProductID,a1.UOMID,a1.Multiplayer,a1.UnitID,a1.Secondary,a1.Cost,a1.Rate,a1.Barcode,a1.BarcodeID,a1.MRP,a1.NRate from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a1
		   left join invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno
		   where a2.ProductID is null'
		)

	exec ('update a1 set a1.UomId=a2.UomId,a1.MultiPlayer=a2.MultiPlayer,a1.UnitId=a2.UnitId,a1.Secondary=a2.Secondary,a1.Rate=a2.Rate,a1.Cost=a2.Cost,a1.Barcode=a2.Barcode,a1.BarcodeId=a2.BarcodeId,a1.MRP=a2.MRP,a1.NRate=a2.NRate from invUOMLevels a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invUOMLevels a2 on a1.ProductID=a2.ProductID and a1.Sno=a2.Sno')

	ALTER TABLE invUOMLevels Enable TRIGGER triggerinvUOMLevels

	--Salesman
	exec ('insert Into invSalesman(Id,Code,Name,AccountID,WareHouseID,CompanyId)
			select a1.Id,a1.Code,a1.Name,a1.AccountID,a1.WareHouseID,a1.CompanyId from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesman a1
			left join invSalesman a2 on a1.ID=a2.ID
			where a2.ID is null'
			)
	
	exec ('update a1 set a1.Code=a2.Code,a1.Name=a2.Name,a1.AccountID=a2.AccountID,a1.WareHouseID=a2.WareHouseID,a1.CompanyId=a2.CompanyId from invSalesman a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSalesman a2 on a1.Id=a2.Id')


	--invPurchaseProperty
	exec ('insert Into invPurchaseProperty(Id,Code,Name)
			select a1.Id,a1.Code,a1.Name from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseProperty a1
			left join invPurchaseProperty a2 on a1.ID=a2.ID
			where a2.ID is null'
			)


	--invPurchaseSubProperty
	exec ('insert Into invPurchaseSubProperty(Id,Code,Name,PropertyID)
			select a1.Id,a1.Code,a1.Name,a1.PropertyID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invPurchaseSubProperty a1
			left join invPurchaseSubProperty a2 on a1.ID=a2.ID
			where a2.ID is null'
			)
	
	--invWarehouse
	exec ('insert Into invWarehouse(Id,Code,Name,CostCentreId)
			select a1.Id,a1.Code,a1.Name,a1.CostCentreId from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invWarehouse a1
			left join invWarehouse a2 on a1.ID=a2.ID
			where a2.ID is null'
			)


	--Transactions

	create table #SalesToSync (CompanyID int,PeriodID int,VTypeID int,No int,Date int)


	--Delete onlined edited purchase entries from offline
	exec('insert #SalesToSync(CompanyID,PeriodID,VtypeID,No) 
	select s.CompanyID,s.PeriodID,s.VtypeID,s.No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount>0')

	if exists(select top 1 1 from #SalesToSync)
	Begin
		
		exec('update s set s.SyncCount=SyncCount-1 from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount>0')

		delete p1 from invPurchaseDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invPurchaseHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchasePropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from invPurchaseReturnDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invPurchaseReturnHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchasePropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from invProductSerialNumber p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchaseAdditions p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invAutoBarcodeAndSalesRate p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from aTransaction p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No 
		join invVoucherTypeDetails v on p1.VoucherTypeID=v.AccountVtypeID and p2.VtypeID=v.ID
		where p1.ModuleID=1

		delete #SalesToSync

	End
	exec('delete s from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount=0')
	

	--invProductSerialNumber
	exec ('insert Into invProductSerialNumber(VtypeId,No,PSNo,Sno,SerialNo,CompanyID,PeriodID,ID)
			select a1.VtypeId,a1.No,a1.PSNo,a1.Sno,a1.SerialNo,a1.CompanyID,a1.PeriodID,a1.ID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invProductSerialNumber a1
			left join invProductSerialNumber a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	--invCustomer
	exec ('insert Into invCustomer (Name,Address1,Address2,Address3,Phone,MobileNo,Email,Web,ContactPerson,CreditLimit,DueDays,CurrencyId,RateLevelId,SalesManId,PaymentTerms,Remark,AccountID,FileNo,Place,TIN,CST,DLNo1,DLNo2,Inactive,CompanyID,GST)
		   select v1.Name,v1.Address1,v1.Address2,v1.Address3,v1.Phone,v1.MobileNo,v1.Email,v1.Web,v1.ContactPerson,v1.CreditLimit,v1.DueDays,v1.CurrencyId,v1.RateLevelId,v1.SalesManId,v1.PaymentTerms,v1.Remark,v1.AccountID,v1.FileNo,v1.Place,v1.TIN,v1.CST,v1.DLNo1,v1.DLNo2,v1.Inactive,v1.CompanyID,v1.GST from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCustomer v1
		   left join invCustomer v2 on v1.AccountID=v2.AccountID
		   where v2.AccountID is null'
		 )	

	exec ('update a1 set a1.Name=a2.Name,a1.Address1=a2.Address1,a1.Address2=a2.Address2,a1.Address3=a2.Address3,a1.Phone=a2.Phone,a1.MobileNo=a2.MobileNo,a1.Email=a2.Email,a1.ContactPerson=a2.ContactPerson,a1.CreditLimit=a2.CreditLimit,a1.DueDays=a2.DueDays,a1.RateLevelId=a2.RateLevelId,a1.SalesManId=a2.SalesManId,a1.Place=a2.Place,a1.TIN=a2.TIN,a1.Inactive=a2.Inactive,a1.CompanyID=a2.CompanyID,a1.GST=a2.GST from invCustomer a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invCustomer a2 on a1.AccountID=a2.AccountID')

	--invAutoBarcodeAndSalesRate
	exec ('insert Into invAutoBarcodeAndSalesRate(VtypeId,No,Sno,ProductId,UomId,BarcodeId,Barcode,SRate,Printed,Rate,Cost,CompanyId,PeriodId,Mrp,Sticker)
		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.UomId,p1.BarcodeId,p1.Barcode,p1.SRate,p1.Printed,p1.Rate,p1.Cost,p1.CompanyId,p1.PeriodId,p1.Mrp,p1.Sticker from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invAutoBarcodeAndSalesRate p1
		   left join invAutoBarcodeAndSalesRate p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		 )

	
	--Delete onlined edited company transfer entries from offline
	exec('insert #SalesToSync(PeriodID,No) 
	select s.PeriodID,s.No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID=16 and s.SyncCount>0')

	if exists(select top 1 1 from #SalesToSync)
	Begin
		
		exec('update s set s.SyncCount=SyncCount-1 from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID=16 and s.SyncCount>0')

		delete p1 from invCompanyTransferDetails p1 join #SalesToSync p2 on p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invCompanyTransferHeader p1 join #SalesToSync p2 on p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invCompanyTransferPropertyDetails p1 join #SalesToSync p2 on p1.PeriodID=p2.PeriodID and p1.No=p2.No
