	exec ('update a1 set a1.FromDate=a2.FromDate,a1.Notes=a2.Notes,a1.ToDate=a2.ToDate,a1.Type=a2.Type,a1.FromTime=a2.FromTime,a1.ToTime=a2.ToTime from invQtyRateSettingsHeader a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invQtyRateSettingsHeader a2 on a1.CompanyID=a2.CompanyID and a1.PeriodID=a2.PeriodID and a1.No=a2.No where a2.CompanyId='+@CompanyID)
