	exec ('update a1 set a1.ProductId=a2.ProductId,a1.UOMId=a2.UOMId,a1.BarcodeId=a2.BarcodeId,a1.LQty=a2.LQty,a1.UQty=a2.UQty,a1.Rate=a2.Rate,a1.DiscountPercent=a2.DiscountPercent,a1.WRate=a2.WRate,a1.MRP=a2.MRP from invQtyRateSettingsDetails a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invQtyRateSettingsDetails a2 on a1.CompanyID=a2.CompanyID and a1.PeriodID=a2.PeriodID and a1.No=a2.No and a1.SNo=a2.SNo where a2.CompanyId='+@CompanyID)


