declare @UploadReceiptPayment bit

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB,@UploadReceiptPayment=UploadReceiptAndPayment from invOption where CompanyID=@CompanyID


if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB'
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Synchronizing to same DB is not allowable'
	return
End 


-----------------------
declare @Forms table(FormId varchar(10),Name varchar(100))
insert @Forms
select FormId,Name from invForms where FormId like'1%' 

if exists(select 1 from invProjectSettings where CompanyId=@CompanyId and BlockMasterCreation=1)
	delete @Forms where FormId in('1','12','1C')

declare @Message nvarchar(100)
select @Message='Permission Granted for User '+u.Name+' for Menu '+upper(f.Name)+' in Source DB' from invUserDetails ud
join invUser u on ud.UserId=u.Id
join @Forms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and (ud.Edit=1 or ud.[Delete]=1 or ud.[Add]=1)

if @Message is not null
Begin
	select @Message Message
	return
End
---------------------------


if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+']'

End



Begin try
	--Downloading

	--Masters


	--aPeriod
	exec ('insert Into aPeriod([ID],[Code],[Name],[From],[To])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[From],a1.[To] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aPeriod a1
		   left join aPeriod a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountGroup
	exec ('insert Into aAccountGroup([ID],[Code],[Name],[AccountTypeID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountTypeID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountGroup a1
		   left join aAccountGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )

	--aAccountSubGroup
	exec ('insert Into aAccountSubGroup([ID],[Code],[Name],[AccountGroupID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountGroupID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccountSubGroup a1
		   left join aAccountSubGroup a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )


	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
		   select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
		   left join aAccount a2 on a1.ID=a2.ID
		   where a2.ID is null'
			)

	exec ('update a1 set a1.Name=a2.Name,a1.UnderAccountID=a2.UnderAccountID,a1.NameInOL=a2.NameInOL from aAccount a1 join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a2 on a1.ID=a2.ID')

	
	--aAccount
	exec ('insert Into aAccount ([ID],[Code],[Name],[AccountSubGroupID],[ModuleID])
			select a1.[ID],a1.[Code],a1.[Name],a1.[AccountSubGroupID],a1.[ModuleID] from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aAccount a1
			left join aAccount a2 on a1.ID=a2.ID
			where a2.ID is null'
			)

	
	--aCompany
	exec ('insert Into aCompany(ID,Code,Name,Address,Phone,Email,AccountID)
		   select a1.ID,a1.Code,a1.Name,a1.Address,a1.Phone,a1.Email,a1.AccountID from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aCompany a1
		   left join aCompany a2 on a1.ID=a2.ID
		   where a2.ID is null'
		 )
	

