	--Transactions
	create table #SalesToSync (CompanyID int,PeriodID int,VTypeID int,No int,Date int)

	--Delete onlined edited purchase entries from offline
	exec('insert #SalesToSync(CompanyID,PeriodID,VtypeID,No) 
	select s.CompanyID,s.PeriodID,s.VtypeID,s.No from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount>0')

	if exists(select top 1 1 from #SalesToSync)
	Begin
		
		exec('update s set s.SyncCount=SyncCount-1 from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount>0')

		delete p1 from invPurchaseDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invPurchaseHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchasePropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from invPurchaseReturnDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No -- please dont change position
		delete p1 from invPurchaseReturnHeader p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchasePropertyDetails p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from invProductSerialNumber p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invPurchaseAdditions p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No
		delete p1 from invAutoBarcodeAndSalesRate p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.VtypeID=p2.VtypeID and p1.PeriodID=p2.PeriodID and p1.No=p2.No

		delete p1 from aTransaction p1 join #SalesToSync p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.No=p2.No 
		join invVoucherTypeDetails v on p1.VoucherTypeID=v.AccountVtypeID and p2.VtypeID=v.ID
		where p1.ModuleID=1

		delete #SalesToSync

	End
	exec('delete s from'+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.invSyncDetails s join invVoucherTypeDetails v on s.VtypeID=v.ID where s.SyncCompanyID='+ @CompanyID +' and v.VtypeID in(1,2) and s.SyncCount=0')


