			exec('delete p1 from '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesHeader p1 join #SalesToSync p2 on p1.CompanyID='+ @CompanyID+' and p1.PeriodID=p2.PeriodID and p1.VtypeId=p2.VtypeId and p1.No=p2.No')
