	if object_id('pSalesHeader') is not null
	--pSalesHeader
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesHeader(VtypeId,No,Date,Time,SalesManId,Total,Discount,RoundOff,NetTotal,Shift,CompanyId,PeriodId,UserID,BalanceReturn,CardID,RateLevelID,Notes,CustomerID,TaxAmount,TaxGroup,TaxMethode,CostCentreID)
		   select p1.VtypeId,p1.No,p1.Date,p1.Time,p1.SalesManId,p1.Total,p1.Discount,p1.RoundOff,p1.NetTotal,p1.Shift,p1.CompanyId,p1.PeriodId,p1.UserID,p1.BalanceReturn,p1.CardID,p1.RateLevelID,p1.Notes,p1.CustomerID,p1.TaxAmount,p1.TaxGroup,p1.TaxMethode,p1.CostCentreID from pSalesHeader p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesHeader p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		  )
	
	
	if object_id('pSalesDetails') is not null	
	--pSalesDetails
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesDetails(VtypeId,No,Sno,ProductId,BarcodeID,UomId,Qty,Foc,Rate,Total,CompanyId,PeriodId,MRP,TaxGroupID,Tax,DiscountPercentage,DiscountAmount)
		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.BarcodeID,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Total,p1.CompanyId,p1.PeriodId,p1.MRP,p1.TaxGroupID,p1.Tax,p1.DiscountPercentage,p1.DiscountAmount from pSalesDetails p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesDetails p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	
	if object_id('pPayment') is not null	
	--pPayment
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pPayment(VtypeId,No,CardID,CurrencyID,AccountID,Amount,CompanyID,PeriodID,UserID,CAmount,CNo)
		   select p1.VtypeId,p1.No,p1.CardID,p1.CurrencyID,p1.AccountID,p1.Amount,p1.CompanyID,p1.PeriodID,p1.UserID,p1.CAmount,p1.CNo from pPayment p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pPayment p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)
	

	if object_id('pSalesReturnHeader') is not null
	--pSalesReturnHeader
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnHeader(VtypeId,No,Date,Time,SalesManId,Total,Discount,RoundOff,NetTotal,Shift,CompanyId,PeriodId,UserID,BalanceReturn,RateLevelID,Notes,CustomerID,TaxAmount,TaxGroup,TaxMethode,CostCentreID,CustomerContact,CustomerContactName,CVtypeId)
		   select p1.VtypeId,p1.No,p1.Date,p1.Time,p1.SalesManId,p1.Total,p1.Discount,p1.RoundOff,p1.NetTotal,p1.Shift,p1.CompanyId,p1.PeriodId,p1.UserID,p1.BalanceReturn,p1.RateLevelID,p1.Notes,p1.CustomerID,p1.TaxAmount,p1.TaxGroup,p1.TaxMethode,p1.CostCentreID,p1.CustomerContact,p1.CustomerContactName,p1.CVtypeId from pSalesReturnHeader p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnHeader p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		  )
	
	
	if object_id('pSalesReturnDetails') is not null	
	--pSalesReturnDetails
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnDetails(VtypeId,No,Sno,ProductId,BarcodeID,UomId,Qty,Foc,Rate,Total,CompanyId,PeriodId,MRP,TaxGroupID,Tax,DiscountPercentage,DiscountAmount)
		   select p1.VtypeId,p1.No,p1.Sno,p1.ProductId,p1.BarcodeID,p1.UomId,p1.Qty,p1.Foc,p1.Rate,p1.Total,p1.CompanyId,p1.PeriodId,p1.MRP,p1.TaxGroupID,p1.Tax,p1.DiscountPercentage,p1.DiscountAmount from pSalesReturnDetails p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pSalesReturnDetails p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)

	
	if object_id('pReturnPayment') is not null	
	--pReturnPayment
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pReturnPayment(VtypeId,No,CardID,CurrencyID,AccountID,Amount,CompanyID,PeriodID,UserID,CAmount,CNo)
		   select p1.VtypeId,p1.No,p1.CardID,p1.CurrencyID,p1.AccountID,p1.Amount,p1.CompanyID,p1.PeriodID,p1.UserID,p1.CAmount,p1.CNo from pReturnPayment p1
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.pReturnPayment p2 on p1.CompanyID=p2.CompanyID and p1.PeriodID=p2.PeriodID and p1.VTypeID=p2.VTypeID and p1.No=p2.No
		   where p2.No is null and p1.CompanyID='+ @CompanyID
		)


	create table #VType(ID int)
	insert #VType(ID)
	select AccountVTypeID from invVoucherTypeDetails where VtypeID in(3,4,12,23)

	--aTransaction
	exec ('insert Into '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo,CreditCardID,CostCentreID)
		   select t1.CompanyID,t1.PeriodID,t1.Date,t1.VoucherTypeID,t1.No,t1.DebtorID,t1.CreditorID,t1.Amount,t1.Description,t1.RefNo,t1.ModuleID,t1.AccountID,t1.CDate,t1.CNo,t1.SNo,t1.CreditCardID,t1.CostCentreID from aTransaction t1
		   join #VType v on t1.VoucherTypeID=v.ID
		   left join '+ @RmtSrvName + '.'+ @RmtDBName + '.'+ @RmtDBO +'.aTransaction t2 on t1.CompanyID=t2.CompanyID and isnull(t1.PeriodID,0)=isnull(t2.PeriodID,0) and t1.VoucherTypeID=t2.VoucherTypeID and t1.No=t2.No
		   where t2.No is null and t1.CompanyID='+ @CompanyID
		 )
	
	SELECT null

End try

Begin Catch
	SELECT ERROR_MESSAGE();  
End Catch


go

if object_id('prBillWiseProfitReport') is not null
  drop proc prBillWiseProfitReport

go
  
create proc prBillWiseProfitReport
@CompanyID int,
@From int,
@To int, 
@DetailPart bit,
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@ValueDataWhereClause varchar(max),
@MasterDataWhereClause varchar(max),  
@ProcessedValueWhereClause varchar(max),
@DetailsMasterDataWhereClause varchar(max)=null,
@Order varchar(max),
@GrandTotal varchar(max),
@AlterHeaderTable varchar(max),
@AlterGroupTable varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@CostCentreId int=0

as  
   
set nocount on  
set transaction isolation level read uncommitted

declare @WhereClause varchar(max),@Query varchar(max)    


create table #T1
(
  CompanyId int,
  InOut int,	
  PeriodID int,
  Date int,
  Vtype int,
  No int,
  Id int,
  WHID int,
  ProductId int, 
  BarcodeId int,
  SerialNoId int,
  Rate float,
  CRate float,
  SRate float,
  Qty float,
  FOC float,
  Discount float,
  Tax float
)


create table #T2
(
CompanyId int,
PeriodID int,
Vtype int,
No int,
Date int,
Rate float,
Cost float,
Sales float,
Tax float
)


create table #Filter
(
CompanyId int,
VtypeId int,
PeriodId int,
No int
)


create table #BillWiseProfit 
(
CompanyId int,
PeriodID int,
VtypeId int,
Company varchar(100),
Date datetime,
VType varchar(15),
[No] int,
CCode varchar(100),
Customer nvarchar(200),
SalesMan nvarchar(100),
SalesWithTax float,
Sales float,
Discount float,
NetSales as(Sales-isnull(Discount,0)),
Rate float,
Cost float,
Profit float,
[Profit %] float,
Commission float,
Tax float,
CustomerId int
)


if len(@ValueDataWhereClause) > 0 and LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = @ValueDataWhereClause + ' and ' + @MasterDataWhereClause 
else if len(@ValueDataWhereClause) > 0 
  set @WhereClause = @ValueDataWhereClause 
else if LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = @MasterDataWhereClause 


--For Getting Cost
create table #tmpTable (ID int,BarcodeId int)

if len(@WhereClause) > 0
  begin
	
	exec('insert #Filter select t1.CompanyId,t1.VtypeId,t1.PeriodId,t1.No from invSalesHeader t1 
	      where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		  and (t1.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
		  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @WhereClause)
	
	exec('insert #Filter 
	      select t1.CompanyId,t1.VtypeId,t1.PeriodId,t1.No from invSalesReturnHeader t1 
		  where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		  and (t1.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
		  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @WhereClause)
	
	if object_id('pSalesHeader') is not null
		exec('insert #Filter select t1.CompanyId,t1.VtypeId,t1.PeriodId,t1.No from pSalesHeader t1 
		      where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
			  and (t1.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
			  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @WhereClause)
	
	if object_id('RMSOrderHeader') is not null
		exec('insert #Filter select t1.CompanyId,0,t1.Period,t1.No from RMSOrderHeader t1 where (t1.Branch = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and convert(varchar,t1.date,112) between ' + @From +
		 ' and ' + @To	+ ' and ' + @WhereClause)
	
	declare @CTWhereClause varchar(max)
	select @CTWhereClause=replace(@WhereClause,'t1.CustomerId','c.AccountId')
	select @CTWhereClause=replace(@CTWhereClause,'t1.VtypeId','v.Id')
	select @CTWhereClause=replace(@CTWhereClause,'t1.CompanyId','t1.CompanyFrom')
	
	exec('insert #Filter select t1.CompanyFrom,v.Id,t1.PeriodId,t1.No from invCompanyTransferHeader t1 
	      join aCompany c on t1.CompanyFrom=c.Id
		  join invVoucherTypeDetails v on v.VTypeId=16
	      where (t1.CompanyFrom = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and t1.date between ' + @From +
		 ' and ' + @To	+ ' and ' + @CTWhereClause)
	
	select @CTWhereClause=replace(@WhereClause,'t1.VtypeId','v.Id')

	exec('insert #Filter select sh.CompanyId,v.Id,si.PeriodId,si.No from invServiceHeader sh 
		  join invServiceInvoice si on sh.ServiceID=si.ServiceID
		  join invServiceOrder t1 on si.ServiceId=t1.Id
	      join invVoucherTypeDetails v on v.VTypeId=18
	      where (sh.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and si.date between ' + @From +
		 ' and ' + @To	+ ' and ' + @CTWhereClause)
	
	
	exec('insert #Filter select t1.CompanyId,v.Id,t1.PeriodId,t1.No from invReturnHeader t1 
		  join invVoucherTypeDetails v on v.VTypeId=8
	      where (t1.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		  and t1.date between ' + @From + ' and ' + @To	+ ' and ' + @CTWhereClause)
	

	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesDetails t1
	join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.VtypeId = t2.VtypeId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')

	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesReturnDetails t1
	join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.VtypeId = t2.VtypeId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')

	if object_id('pSalesDetails') is not null
		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct t1.ProductId,t1.BarcodeId from pSalesDetails t1
		join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.VtypeId = t2.VtypeId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')

	
	if object_id('RMSOrderDetails') is not null
		exec('insert #tmpTable (Id) 
		select distinct t1.ProductId from RMSOrderDetails t1
		join #Filter t2 on t1.Branch = t2.CompanyId and t1.Period=t2.PeriodId and t1.No = t2.No')
	

		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct t1.ProductId,t1.BarcodeId from invCompanyTransferDetails t1
		join invCompanyTransferHeader h on t1.PeriodId=h.PeriodId and t1.No=h.No
		join #Filter t2 on h.CompanyFrom = t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.No = t2.No')
	
	if object_id('invServiceDetails') is not null 
		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct d.ProductId,d.BarcodeId from invServiceDetails d
		join invServiceHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
		join invServiceInvoice si on h.ServiceID=si.ServiceID
		join #Filter f on f.CompanyId = si.CompanyId and f.PeriodId=si.PeriodId and f.No = si.No')
	
	exec('insert #tmpTable (Id) 
	select distinct t1.ProductId from invReturnDetails t1
	join #Filter t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.No = t2.No
	join invVoucherTypeDetails v on t2.VtypeId=v.id and v.vtypeid=8')

	end
else
  begin
	
	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesDetails t1
	join invSalesHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
	where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
	and (t2.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
	and t2.date between '+@From+' and '+@To)

	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invSalesReturnDetails t1
	join invSalesReturnHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
	where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
	and (t2.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
	and t2.date between '+@From+' and '+@To)
	
	
	if object_id('pSalesDetails') is not null and object_id('pSalesHeader') is not null
		exec('insert #tmpTable (Id,BarcodeId)
		select distinct t1.ProductId,t1.BarcodeId from pSalesDetails t1
		join pSalesHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.No = t2.No
		where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) 
		and (t2.CostCentreId = ' +  @CostCentreId + ' or ' +  @CostCentreId + '=0)
		and t2.date between '+@From+' and '+@To)

	

	if object_id('RMSOrderDetails') is not null
		exec('insert #tmpTable (Id)
		select distinct ri.InventoryID from RMSOrderDetails t1
		join RMSItem ri on t1.ItemID=ri.ItemID
		join RMSOrderHeader t2 on t1.Branch = t2.Branch and t1.Period = t2.Period and t1.OrderNo = t2.OrderNo
		where (t2.Branch = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and convert(varchar,t2.date,112) between '+@From+' and '+@To)
	
	
	exec('insert #tmpTable (Id,BarcodeId) 
	select distinct t1.ProductId,t1.BarcodeId from invCompanyTransferDetails t1
	join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
	where (t2.CompanyFrom = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and t2.date between '+@From+' and '+@To)


	if object_id('invServiceDetails') is not null 
		exec('insert #tmpTable (Id,BarcodeId) 
		select distinct t1.ProductId,t1.BarcodeId from invServiceDetails t1
		join invServiceHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
		join invServiceInvoice si on t2.ServiceID=si.ServiceID
		where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and si.date between '+@From+' and '+@To)
	

	exec('insert #tmpTable (Id) 
	select distinct t1.ProductId from invReturnDetails t1
	join invReturnHeader t2 on t1.CompanyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.No = t2.No
	where (t2.CompanyId = ' +  @CompanyId + ' or ' +  @CompanyId + '=0) and t2.date between '+@From+' and '+@To)

end


delete tmpTable where SPID=@@SPID


if exists(select 1 from invProjectSettings where AutoBarcode=1 and CompanyId=@CompanyID)
	insert tmpTable(SPID,ID,BarcodeId) 
	select distinct @@SPID,Id,isnull(BarcodeId,0) from #tmpTable
else
	insert tmpTable(SPID,ID) 
	select distinct @@SPID,Id from #tmpTable

insert #T1(CompanyId,InOut,Date,Vtype,No,Id,WHID,ProductId,BarcodeId,SerialNoId,Rate,CRate,SRate,Qty,FOC,Discount,Tax) 
exec spStock @CompanyID=@CompanyID,@ToDate=@To,@Type=10,@CostCentreId=@CostCentreId


update t1 set t1.Rate = t2.Cost,t1.CRate = Cost from #T1 t1  join invProduct t2 on t1.ProductId = t2.Id  where isnull(t2.NonStockItem,0) = 1


--removing all transactions except sales
delete #T1 where id not in(4,5,13,15,16,19,23)
delete #T1 where date not between @From and @To

update #T1 set qty = -qty,Discount=isnull(Discount,0) where id not in(13)
update #T1 set vtype=0 where vtype is null
update t1 set t1.PeriodID=p.ID from #T1 t1 join aPeriod p on t1.Date between p.[From] and p.[To]
update #T1 set Tax=0 where Tax is null
update #T1 set FOC=0 where FOC is null


declare @OptCompanyId int
set @OptCompanyId=@CompanyId
if (@OptCompanyId=0) select @OptCompanyId=min(Id) from aCompany

--SerialNo Cost
if exists(select 1 from invOption where CompanyId=@OptCompanyId and StockCalculation=2)
Begin
	update sr set sr.CRate=pd.Rate from #T1 sr
	join invProductSerialNumber psn on sr.SerialNoId=psn.Id
	join invOpeningStock pd on psn.CompanyId=pd.CompanyId and psn.PeriodId=pd.PeriodId and psn.VtypeId=0 and psn.No=pd.No and psn.PSno=pd.Sno

	update sr set sr.CRate=pd.CostPrice from #T1 sr
	join invProductSerialNumber psn on sr.SerialNoId=psn.Id
	join invPurchaseDetails pd on psn.CompanyId=pd.CompanyId and psn.PeriodId=pd.PeriodId and psn.VtypeId=1 and psn.No=pd.No and psn.PSno=pd.Sno
End
-----------------

--Ignore 0 Cost
if exists(select 1 from invOption where CompanyId=@OptCompanyId and IgnoreNoCostInProfit =1)
	delete #T1 where isnull(CRate,0)=0

if exists(select 1  from invOption where ProfitCalculation=1 and CompanyID=@OptCompanyId)--with out tax
	insert #T2 
	select CompanyId,PeriodID,vtype,No,Date,sum(qty*rate) Rate,sum(qty*crate) Cost, sum((qty-foc) * isnull(srate,crate)) - isnull(sum(discount),0) Sales,isnull(sum(Tax),0) from #T1 group by CompanyId,PeriodID,vtype,No,Date
else
	insert #T2 
	select CompanyId,PeriodID,vtype,No,Date,sum(qty * Rate) Rate,sum(qty * crate) Cost, sum((qty-foc) * isnull(srate,crate)) - isnull(sum(discount),0)+ isnull(sum(Tax),0) Sales,isnull(sum(Tax),0) from #T1 group by CompanyId,PeriodID,vtype,No,Date


declare @ServiceVTypeId int
select @ServiceVTypeId=Id from invVoucherTypeDetails where VTypeId=18
if (@ServiceVTypeId>0)
	insert #T2
	select si.CompanyId,si.PeriodID,@ServiceVTypeId,si.No,si.Date,null Rate,null Cost,sh.NetTotal,null from invServiceInvoice si
	join invServiceHeader sh on si.ServiceID=sh.ServiceID
	left join invServiceDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
	where si.Date between @From and @To and sd.No is null


--Addition1
if exists(select top 1 1 from invSalesDetails where Addition1<>0)
Begin
	create table #Addition(CompanyId int,PeriodId int,VtypeId int,No int,Addition1 float)
	insert #Addition
	select CompanyId,PeriodId,VtypeId,No,sum(Addition1)Addition1 from invSalesDetails 
	where (CompanyId=@CompanyId or @CompanyId=0)and Addition1<>0
	group by CompanyId,PeriodId,VtypeId,No

	update b set b.Sales=b.Sales+isnull(s.Addition1,0) from #T2 b 
	join #Addition s on b.CompanyId=s.CompanyId and b.PeriodId=s.PeriodId and b.Vtype=s.VtypeId and b.No=s.No 
	
End

if len(@WhereClause) > 0
Begin
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,t1.Tax
	from #T2 t1
	join invSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.vtype = t6.vtypeid and t1.PeriodId=t6.PeriodId and t1.no = t6.no
	where t2.date between @From and @To

	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,-t2.discount, t1.sales - (isnull(t1.cost,0) - isnull(t2.discount,0)),t5.Commission,t1.Tax
	from #T2 t1
	join invSalesReturnHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.vtype = t6.vtypeid and t1.PeriodId=t6.PeriodId and t1.no = t6.no
	where t2.date between @From and @To

	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,0, t1.sales - (isnull(t1.cost,0)),t5.Commission,t1.Tax
	from #T2 t1
	join invCompanyTransferHeader t2 on t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyFrom = t1.CompanyId
	join invVoucherTypeDetails t3 on t3.VtypeId=16 and t1.vtype=0
	join aCompany c on t2.CompanyTo=c.Id
	join aAccount t4 on c.AccountId = t4.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	join #Filter t6 on t1.CompanyId=t6.CompanyId and t3.Id=t6.VtypeId and t1.PeriodId=t6.PeriodId and t1.no = t6.no
	where t2.date between @From and @To

	
	if object_id('pSalesHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.name,t5.name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,t1.Tax 
		from #T2 t1
		join pSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.periodid = t1.PeriodID and t2.CompanyID = t1.CompanyId
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		left join aAccount t4 on t2.CustomerId = t4.Id
		left outer join invSalesMan t5 on t2.SalesManId = t5.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.vtype = t6.vtypeid and t1.PeriodId=t6.PeriodId and t1.no = t6.no
		where t2.date between @From and @To

	if object_id('RMSOrderHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,SalesMan,Sales,Rate,Cost,Discount,Profit)
		select t1.CompanyId,t1.PeriodID,0,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t5.name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)) 
		from #T2 t1
		join RMSOrderHeader t2 on t1.no = t2.no and t2.Period = t1.PeriodID and t2.Branch = t1.CompanyId and t1.vtype is null
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		left outer join Waiter t5 on t2.Waiter = t5.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.PeriodId=t6.PeriodId and t1.no = t6.no and t1.vtype is null
		where convert(varchar,t2.date,112) between @From and @To

	
	if object_id('invServiceHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,Sales,Rate,Cost,Discount,Profit,Customer)
		select t1.CompanyId,t1.PeriodID,@ServiceVTypeId,c.Name,cast(cast(si.date as varchar) as datetime),t3.code,si.No,t2.NetTotal+t2.Discount,t1.Rate,t1.cost,si.discount, t2.NetTotal - (isnull(t1.cost,0)),a.Name
		from #T2 t1
		join invServiceHeader t2 on t1.Date>=t2.Date and t2.CompanyID = t1.CompanyId and t1.vtype=@ServiceVTypeId
		join invServiceInvoice si on t2.ServiceID=si.ServiceID and t1.no = si.no
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.PeriodId=t6.PeriodId and t1.no = t6.no and t1.vtype=t6.VtypeId
		join invServiceOrder o on si.ServiceId=o.Id
		join aAccount a on o.CustomerId=a.ID
		where convert(varchar,si.date,112) between @From and @To


		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.Discount,t1.sales -isnull(t2.Discount,0)- (isnull(t1.cost,0)),t5.Commission,Tax 
		from #T2 t1
		join invReturnHeader t2 on t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyId = t1.CompanyId
		join invVoucherTypeDetails t3 on t3.VtypeId=8 and t1.Vtype=t3.Id
		join aCompany c on t2.CompanyId=c.Id
		join aAccount t4 on t2.CustomerId = t4.Id
		join #Filter t6 on t1.CompanyId=t6.CompanyId and t1.PeriodId=t6.PeriodId and t1.no = t6.no and t1.vtype=t6.VtypeId
		left outer join invSalesMan t5 on t2.SalesManId = t5.Id
		where t2.date between @From and @To

End
else
Begin
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax,CustomerId)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,t1.Tax,t2.CustomerId 
	from #T2 t1
	join invSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  
	
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,-t2.discount, (t1.sales - (isnull(t1.cost,0) - isnull(t2.discount,0))),t5.Commission,t1.Tax 
	from #T2 t1
	join invSalesReturnHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyID = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype = t3.id
	join aAccount t4 on t2.CustomerId = t4.Id
	join aCompany c on t2.CompanyId=c.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  
	
	if object_id('pSalesHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.discount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discount,0)),t5.Commission,Tax 
		from #T2 t1
		join pSalesHeader t2 on t1.vtype = t2.vtypeid and t1.no = t2.no and t2.PeriodID = t1.PeriodID and t2.CompanyID = t1.CompanyId
		join invVoucherTypeDetails t3 on t1.vtype = t3.id
		join aCompany c on t2.CompanyId=c.Id
		left join aAccount t4 on t2.CustomerId = t4.Id
		left outer join invSalesMan t5 on t2.SalesManId = t5.Id
		where t2.date between @From and @To  


	if object_id('RMSOrderHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,SalesMan,Sales,Rate,Cost,Discount,Profit)
		select t1.CompanyId,t1.PeriodId,0,c.Name,t2.date,'RMS',t1.No,t5.Name,t1.sales,t1.Rate,t1.cost,t2.discountamount, t1.sales - (isnull(t1.cost,0) + isnull(t2.discountamount,0)) 
		from #T2 t1
		join RMSOrderHeader t2 on t1.no = t2.Orderno and t2.Period = t1.PeriodID and t1.vtype=0 and t2.Branch = t1.CompanyId
		join aCompany c on t2.CompanyId=c.Id
		left outer join Waiter t5 on t2.Waiter = t5.Id
		where convert(varchar,t2.date,112) between @From and @To  
    

	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,0, t1.sales - (isnull(t1.cost,0)),t5.Commission,Tax 
	from #T2 t1
	join invCompanyTransferHeader t2 on t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyFrom = t1.CompanyId
	join invVoucherTypeDetails t3 on t1.vtype=0 and t3.VtypeId=16
	join aCompany c on t2.CompanyTo=c.Id
	join aAccount t4 on c.AccountId = t4.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  

	if object_id('invServiceHeader') is not null
		insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,Sales,Rate,Cost,Discount,Profit)
		--select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(si.date as varchar) as datetime),t3.code,si.No,t4.Code,t4.name,case when si.PaymentMode=1 or isnull(si.Amount,0)=0 then t2.NetTotal else si.Amount+si.Discount end,t1.Rate,t1.cost,si.Discount,case when si.PaymentMode=1 or isnull(si.Amount,0)=0 then t2.NetTotal else si.Amount end-isnull(t1.cost,0)
		select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(si.date as varchar) as datetime),t3.code,si.No,t4.Code,t4.name,t2.NetTotal+t2.Discount,t1.Rate,t1.cost,si.Discount,t2.NetTotal-isnull(t1.cost,0)
		from #T2 t1
		--join invServiceHeader t2 on t1.PeriodID = t2.PeriodID and t2.CompanyID = t1.CompanyId and t1.vtype=@ServiceVTypeId
		join invServiceHeader t2 on t1.Date>=t2.Date and t2.CompanyID = t1.CompanyId and t1.vtype=@ServiceVTypeId
		join invServiceInvoice si on t2.ServiceID=si.ServiceID and t1.no = si.no
		join invVoucherTypeDetails t3 on t1.vtype=t3.Id
		join invServiceOrder so on t2.ServiceID=so.ID
		join aAccount t4 on so.CustomerId = t4.Id
		join aCompany c on t2.CompanyId=c.Id
		where si.date between @From and @To  
	
	insert #BillWiseProfit (CompanyId,PeriodID,VtypeId,Company,Date,Vtype,No,CCode,Customer,SalesMan,Sales,Rate,Cost,Discount,Profit,Commission,Tax)
	select t1.CompanyId,t1.PeriodID,t1.vtype,c.Name,cast(cast(t2.date as varchar) as datetime),t3.code,t1.No,t4.Code,t4.name,t5.Name,t1.sales,t1.Rate,t1.cost,t2.Discount, t1.sales -isnull(t2.Discount,0)- (isnull(t1.cost,0)),t5.Commission,Tax 
	from #T2 t1
	join invReturnHeader t2 on t1.no = t2.no and t1.PeriodID = t2.PeriodID and t2.CompanyId = t1.CompanyId
	join invVoucherTypeDetails t3 on t3.VtypeId=8 and t1.Vtype=t3.Id
	join aCompany c on t2.CompanyId=c.Id
	join aAccount t4 on t2.CustomerId = t4.Id
	left outer join invSalesMan t5 on t2.SalesManId = t5.Id
	where t2.date between @From and @To  

End


--Production Cost for Non Stock Item
update b set b.Rate=ph.PRate,b.Cost=ph.PRate,b.Profit=b.NetSales-ph.PRate from #BillWiseProfit b
join invProductionHeader ph on b.CustomerId=ph.CustomerId and b.Date>=convert(varchar,b.Date,112)
where b.Cost=0
------------------

update #BillWiseProfit set [Profit %] = ([Profit] * 100) / [Cost] where isnull([Cost],0) <> 0 

update #BillWiseProfit set Commission = Profit * Commission/100.0 where Commission<>0

update #BillWiseProfit set SalesWithTax=Sales+Tax --where Tax<>0

if len(@ProcessedValueWhereClause) > 0
  exec('delete t1 from #BillWiseProfit t1 where not ' +  @ProcessedValueWhereClause )


