(
CompanyId int,
PeriodID1 int,
VtypeId1 int,
No1 int,
Warehouse nvarchar(100),
Product nvarchar(200), 
Qty float,
ICost float,
SRate float,
ITotalCost float,
ISalesValue float,
IProfit float
)

if len(@DetailsMasterDataWhereClause)>0
	set @DetailsMasterDataWhereClause=' and ' + @DetailsMasterDataWhereClause

if exists(select 1  from invOption where ProfitCalculation=1 and CompanyID=@OptCompanyId)--with out tax
	exec('insert #BillWiseProfitDetails 
	select t1.CompanyId,t1.PeriodID,t1.vtype,t1.No,wh.Name,t3.name,t1.qty,t1.CRate,t1.srate ,t1.qty * t1.CRate,
	(t1.qty-t1.FOC) * t1.srate-t1.Discount ,(t1.qty-t1.FOC) * t1.srate-t1.Discount - (t1.qty * t1.rate)  from #T1 t1
	join #BillWiseProfit t2 on t1.CompanyId=t2.CompanyId and t1.PeriodID=t2.PeriodID and t1.vtype = t2.vtypeid and t1.No = t2.No
	join invProduct t3 on t1.ProductId = t3.Id
	left join invWarehouse wh on t1.WHID=wh.Id
	where t1.qty<>0 '+@DetailsMasterDataWhereClause )

else

	exec('insert #BillWiseProfitDetails 
	select t1.CompanyId,t1.PeriodID,t1.vtype,t1.No,wh.Name,t3.name,t1.qty,t1.crate,t1.srate + t1.Tax/t1.qty ,t1.qty * t1.crate,
	(t1.qty-t1.FOC) * t1.srate-t1.Discount + t1.Tax,(t1.qty-t1.FOC) * t1.srate-t1.Discount + t1.Tax - (t1.qty * t1.crate)  from #T1 t1
	join #BillWiseProfit t2 on t1.CompanyId=t2.CompanyId and t1.PeriodID=t2.PeriodID and t1.vtype = t2.vtypeid and t1.No = t2.No
	join invProduct t3 on t1.ProductId = t3.Id
	left join invWarehouse wh on t1.WHID=wh.Id
	where t1.qty<>0'+@DetailsMasterDataWhereClause)

end 


if @DetailPart = 1
Begin
	--Addition1
	if exists(select top 1 1 from invSalesDetails where Addition1<>0)
	update b set b.ISalesValue=b.ISalesValue+isnull(s.Addition1,0) from #BillWiseProfitDetails b join #Addition s on b.PeriodId1=s.PeriodId and b.VtypeId1=s.VtypeId and b.No1=s.No 
	where s.CompanyId=@CompanyId and Addition1<>0
	
	update #BillWiseProfitDetails set IProfit=ISalesValue-ITotalCost
End


if @Group = 0
    begin  
        if @DetailPart = 0
            begin    
                if @GroupTotal = 0        
                    exec('select ' + @columns + ' from #BillWiseProfit ' + @order)
                else
                    begin
                        if len(@order) > 0
                            begin 
								set @Query = 'select ' + @columns +  ' from (select 0 row_id,' + @columns + ' from #BillWiseProfit union all select 1 row_id, ' + 				@GrandTotal + ' from #BillWiseProfit  ) p ' + replace(@order,'order by','order by row_id,')
                                exec(@Query)
                            end 
                        else
                            exec('select ' + @columns + ' from #BillWiseProfit union all select ' + @GrandTotal + ' from #BillWiseProfit ' )
                    end          
            end
        else
			begin
				if @GroupTotal = 0        
					exec('select ' + @columns +  ' from #BillWiseProfit T1 JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId ' + @order)
                else
                    begin
                        if len(@order) > 0
                            begin
                                set @Query = 'select ' + @columns + ' from(select 0 row_id,' + @columns +  ' from #BillWiseProfit T1 JOIN #BillWiseProfitDetails T2 ON 
                                T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId
								union all select 1 row_id,' + @GrandTotal +  ' from #BillWiseProfit T1 
								JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId ) p '  + replace(@order,'order by','order by row_id,')
                                exec(@Query)
                            end	
                        else		
                            exec('select ' + @columns +  ' from #BillWiseProfit T1 
							JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1  and T1.CompanyId = T2.CompanyId
							union all  
							select ' + @GrandTotal +  ' from #BillWiseProfit T1 
                            JOIN #BillWiseProfitDetails T2 ON T1.[No] = T2.[No1] and T1.VtypeId = T2.VtypeId1 and T1.PeriodId = T2.PeriodId1 and T1.CompanyId = T2.CompanyId ' )  
                    end
            end


   end	
			
else  
	begin 
		create table #ProfitGroup(Rid numeric identity(1,1))  
		exec(@AlterGroupTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #ProfitGroup
	end   


drop table #BillWiseProfit

if @DetailPart = 1
	drop table #BillWiseProfitDetails

go

if object_Id('prIMIStockRegister') is not null
	drop proc prIMIStockRegister
go

create proc prIMIStockRegister 
@SerialNoId int 

as

set transaction isolation level read uncommitted
set nocount on

declare @T1 table (CompanyId int,[Date] int,No int ,Id int,Qty int,Cost float,[Type] int,
AccountId int,[Description] varchar(200),Sno int identity(1,1))

declare @T2 table (CompanyId int,Sno int)
declare @T3 table (CompanyId int,Date int,Sno int identity(1,1))

declare @Type table(Id int, Name varchar(100))
insert @Type select 0,'Opening Stock'
insert @Type select 1,'Purchase'
insert @Type select 2,'Purchase Return'
insert @Type select 3,'Sales'
insert @Type select 4,'Sales Return'
insert @Type select 5,'Branch Transfer'
insert @Type select 6,'Damage'
insert @Type select 7,'Stock Adjustment'

declare @SerialNo table(Id int,SerialNo varchar(50))

insert @SerialNo
select s.Id,s.SerialNo from invProductSerialNumber s where s.Id=@SerialNoId

insert @SerialNo
select s1.Id,s1.SerialNo from invProductSerialNumber s1
join @SerialNo s2 on s1.SerialNo=s2.SerialNo
where s1.Id<>@SerialNoId


--Opening Stock
insert @T1 (CompanyId,Id,Qty,Cost,[Type],[No]) 
select t2.CompanyId,t1.Id,1,t2.[No],t2.Rate,0 from invProductSerialNumber t1
join invOpeningStock t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.vtypeid = 0 and t1.No = t2.No and t1.PSno = t2.Sno
join @SerialNo s on t1.Id=s.Id
--where t1.Id = @SerialNoId  
order by t2.CompanyId

--Purchase
insert @T1 (CompanyId,Id,Qty,Cost,Date,[No],[Type],AccountId) 
select t2.CompanyId,t1.Id,1,t2.CostPrice,t3.date,t3.[No],1,t3.VendorId  from invProductSerialNumber t1
left join invPurchaseDetails t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and 
t1.vtypeid = t2.vtypeid and t1.No = t2.No and t1.PSno = t2.Sno
join invPurchaseHeader t3 on t1.companyId = t3.CompanyId and t1.PeriodId = t3.PeriodId and 
t1.vtypeid = t3.vtypeid and t1.No = t3.No
--where t1.id = @SerialNoId 
join @SerialNo s on t1.Id=s.Id

--Company Transfer Inwards
insert @T1 (CompanyId,Id,Cost,Qty,Date,[No],[Type],AccountId) 
select t2.CompanyTo,t1.SerialNoId,t1.Rate,1,t2.Date,t2.[No],5,t2.CompanyFrom  from  invCompanyTransferDetails t1
join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
--where  t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.Companyto,t2.date,t2.no 


--Bulk Entry in Company Transfer
insert @T1 (CompanyId,Id,cost,Qty,date,[No],[Type],AccountId) 
select  t2.CompanyTo,t1.SerialNoId,t3.Rate,1,t2.Date,t2.[No],5,t2.CompanyFrom  from  invCompanyTransferProductSerialNumber t1
join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
join invCompanyTransferDetails t3 on t1.PeriodId = t3.PeriodId and t1.No = t3.No and t1.USno = t3.Sno 
--where t1.SerialNoId = @SerialNoId 
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.Companyto,t2.date,t2.no 


--Sales Return
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type],AccountId) 
select t1.CompanyId,t1.SerialNoId,1,t2.date,t2.[No],4,t2.CustomerId from  invSalesReturnDetails t1
join invSalesReturnHeader t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.vtypeid = t2.vtypeid and t1.No = t2.No
--where t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.CompanyId,t2.date,t2.no 

--Sales
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type],AccountId) 
select t1.CompanyId,t1.SerialNoId,-1,t2.Date,t2.[No],3,t2.CustomerId from  invSalesdetails t1
join invSalesHeader t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.vtypeid = t2.vtypeid and t1.No = t2.No
--where  t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.CompanyId,t2.date,t2.no 


--Purchase Return
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type],AccountId) 
select t1.CompanyId,t1.SerialNoId,-1,t2.Date,t2.[No],2,t2.VendorId  from  invPurchaseReturnDetails t1
join invPurchaseReturnHeader t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.vtypeid = t2.vtypeid and t1.No = t2.No
--where  t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.CompanyId,t2.date,t2.no 

--Damage
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type]) 
select t1.CompanyId,t1.SerialNoId,-1,t2.Date,t2.[No],6 from  invDamageDetails t1
join invDamageHeader t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and  t1.No = t2.No
--where  t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.CompanyId,t2.date,t2.no 


--Stock Adjustment
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type]) 
select t1.CompanyId,t1.SerialNoId,t1.AdjustedQty,t2.Date,t2.[No],7 from  invstockadjustmentdetails t1
join invStockAdjustmentHeader t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and  t1.No = t2.No
--where  t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.CompanyId,t2.date,t2.no 



--Company Transfer Outwards
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type],AccountId) select t2.CompanyFrom,t1.SerialNoId,-1,t2.Date,t2.[No],5,t2.CompanyTo from  invCompanyTransferDetails t1
join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
--where t1.SerialNoId = @SerialNoId
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.Companyfrom,t2.date,t2.no 

--Bulk Entry in sales
insert @T1 (CompanyId,Id,Qty,Date,[No],[Type],AccountId ) select t1.CompanyId,t1.SerialNoId ,-1,t2.date,t2.[No],3,t2.CustomerId from  invSalesProductSerialNumber t1
join invSalesHeader t2 on t1.companyId = t2.CompanyId and t1.PeriodId = t2.PeriodId and t1.vtypeid = t2.vtypeid and t1.No = t2.No
--where t1.SerialNoId = @SerialNoId 
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.CompanyId,t2.date,t2.no 

insert @T1 (CompanyId,Id,Qty,date,[No],[Type],AccountId) 
select t2.CompanyFrom,t1.SerialNoId,-1,t2.Date,t2.[No],5,t2.CompanyTo from  invCompanyTransferProductSerialNumber t1
join invCompanyTransferHeader t2 on t1.PeriodId = t2.PeriodId and t1.No = t2.No
--where t1.SerialNoId = @SerialNoId 
join @SerialNo s on t1.SerialNoId=s.Id
order by t2.Companyfrom,t2.date,t2.no 

update t1 set t1.Description = t2.name   from @T1 t1
join aAccount t2 on t1.AccountId = t2.id 
where t1.Type  <> 5 

update t1 set t1.Description = t2.name   from @T1 t1
join aCompany  t2 on t1.AccountId = t2.id 
where t1.Type  = 5 

--insert @T1 (CompanyId) select CompanyId from @T1 group by CompanyId  
insert @T3 (CompanyId,date)select CompanyId,min(Date) from @T1 group by CompanyId order by 2
 
insert @T2 (CompanyId,Sno) select CompanyId,MIN(SNO) from @T1 group by CompanyId  

select case when t1.sno = t4.sno then t2.Name else null end Branch,cast(cast(T1.Date as varchar) as datetime) Date,nullif(t1.No,0)No,t3.Name [Type],t1.Description ,t1.Qty  from @T1 t1
join aCompany t2 on t1.CompanyId = t2.Id 
left join @Type t3 on t1.[Type] = t3.Id
join @t2 t4 on t1.CompanyId = t4.CompanyId 
join @t3 t5 on t1.CompanyId = t5.CompanyId 
order by t5.sno,t1.CompanyId,t1.sno

go

if OBJECT_ID('prSaveReturn') is not null
	drop proc prSaveReturn
go

create proc prSaveReturn
@CompanyID int,
@PeriodID int,
@No int,
@Date int,
@Time int,
@CustomerId int,
@SalesManId int,
@RateLevelId int,
@SiteId int,
@Total float,
@Addition float,
@DiscountP float,
@Discount float,
@RoundOff float,
@NetTotal float,
@Advance float,
@Balance float,
@Paid float,
@Notes varchar(500),
@RefNo varchar(50)=null,
@PaidBy int=null,
@CreditCardID int=null,
@XmlProductDetails xml,
@XmlPropertyDetails xml,
@IPeriodID int,
@INo int,
@OutVno int output


as
set nocount on
set xact_abort on

Begin Transaction

declare @VoucherTypeID int

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetReturnMaxVno @CompanyID,@PeriodID
    select @No = [No] from @T1 
  end
	else
	begin

		delete invReturnHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No
		delete invReturnDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No
		delete invReturnPropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No
				
		select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where VTypeId=8

		delete aTransaction where ModuleID=1 and VoucherTypeID = @VoucherTypeID and [No] = @No and CompanyID=@CompanyID and PeriodID=@PeriodID

		--exec prDeleteReturn @VtypeId=@VtypeId,@No=@No,@CompanyID=@CompanyID,@PeriodID=@PeriodID

        end	
    	
insert invReturnHeader(CompanyId,PeriodId,No,Date,Time,CustomerId,SalesManId,RateLevelId,Total,DiscountP,Discount,RoundOff,NetTotal,Notes,Advance,Paid,Balance,IPeriodId,INo,Addition,SiteId,RefNo,PaidBy,CreditCardID)
values(@CompanyId,@PeriodId,@No,@Date,@Time,@CustomerId,nullif(@SalesManId,0),nullif(@RateLevelId,0),@Total,@DiscountP,@Discount,@RoundOff,@NetTotal,@Notes,@Advance,@Paid,@Balance,nullif(@IPeriodId,0),nullif(@INo,0),nullif(@Addition,0),nullif(@SiteId,0),@RefNo,nullif(@PaidBy,0),nullif(@CreditCardID,0))


declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert invReturnDetails(CompanyId,PeriodId,No,Sno,ProductId,WarehouseId,UomId,Qty,Rate,Gross,DiscountP,Discount,NOD,Total,Remark,Pending)
select @CompanyId,@PeriodId,@No,Sno,ProductId,nullif(WarehouseId,0),UomId,Qty,Rate,Gross,DiscountP,Discount,NOD,Total,Remark,Pending
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
ProductId      int '@ProductId',
ReturnmanId     int '@ReturnmanId',
WarehouseId    int '@WarehouseId',
UomId          int '@UomId',
Qty            float '@Qty',
Rate           float '@Rate',
Gross          float '@Gross',
DiscountP      float '@DiscountP',
Discount       float '@Discount',
NOD            float '@NOD',
Total          float '@Total',
Remark         varchar(100) '@Remark',
Pending        bit '@Pending'
)

exec sp_xml_removedocument @Idoc


--Property
exec sp_xml_preparedocument @Idoc out ,@XmlPropertyDetails

insert invReturnPropertyDetails(CompanyID,PeriodID,[No],[Sno],[ProductId],[SubPropertyId])
select @CompanyID,@PeriodID,@No,[Sno],[ProductId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno int '@Sno',
ProductId int '@ProductId',
SubPropertyId int '@SubPropertyId'
)

exec sp_xml_removedocument @Idoc

--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1)
Begin

	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where VTypeID=8

	declare @RentalAccountID int,
	        @DiscountAccountID int,
	        @CashInHandID int,
	        @RoundOffAccount int,
			@CreditCard int,
			@PostPaidSeparately bit
	        
	        
	select @DiscountAccountID=DiscountPaid,@CashInHandID=CashInHand,@CreditCard=CreditCard from aAccountSettings where CompanyID=@CompanyID
	select @RentalAccountID=RentalAccount,@RoundOffAccount = SalesRoundOffAccount,@PostPaidSeparately=SalesPostPaidSeparately from invOption where CompanyID=@CompanyID
	select @CreditCard=AccountId from aCreditCard where Id=@CreditCardId and AccountId>0

	declare @Description varchar(500)
	select @Description=isnull(@Description,'')+ s.Name from invSite s where s.Id=@SiteId
	select @Description=@Description +', '+convert(varchar,cast(cast(Date as varchar) as smalldatetime),3)+', '+cast(DateDiff(D,cast(cast(Date as varchar) as smalldatetime),cast(cast(@Date as varchar) as smalldatetime)+1) as varchar) from invIssueHeader where CompanyId=@CompanyId and PeriodId=@IPeriodId and No=@INo
		
	
	if @PostPaidSeparately=1
	Begin
		if @Total>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@RentalAccountID,@Total,'Return   '+@Description,@RefNo) 
	
		if @Paid>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,CreditCardId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else  @CashInHandID end,@CustomerID,@Paid,'Paid while Return',@RefNo,nullif(@CreditCardId,0)) 
		else if @Paid<0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,CreditCardId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,case when @PaidBy=1 then @CreditCard else  @CashInHandID end,abs(@Paid),'Paid Back while Return',@RefNo,nullif(@CreditCardId,0)) 
	End
	Else
	Begin
		if @Paid<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,CreditCardId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else  @CashInHandID end,@RentalAccountID,@Paid,'Return   '+@Description,@RefNo,nullif(@CreditCardId,0)) 

		if (@Total-isnull(@Paid,0))<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@RentalAccountID,@Total-isnull(@Paid,0),'Return   '+@Description,@RefNo) 

	End
	
		

	--Addition
	if @Addition>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@CashInHandID,@Addition,'Freight In Return',@RefNo) 
	
	--Discount
	if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DiscountAccountID,@CustomerID,@Discount,'Rental Discount',@RefNo) 
	

	--Round off
	if ISNULL(@RoundOffAccount,0) >  0 and @RoundOff <> 0
	begin
		if @RoundOff > 0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@RentalAccountID,@RoundOffAccount,@RoundOff,'Round Off In Return',@RefNo) 
		else 
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
		    values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@RoundOffAccount,@RentalAccountID,abs(@RoundOff),'Round Off In Return',@RefNo) 	
	end
	
	
End

set @OutVno = @No 

Commit

go

if object_id('prExportSales') is not null drop proc prExportSales

go

create proc prExportSales
@CompanyID int,
@PeriodID int,
@VtypeID int,
@ExportNo int

as

SET NOCOUNT ON
SET XACT_ABORT ON
SET DEADLOCK_PRIORITY LOW
SET LOCK_TIMEOUT 10000

--declare @CompanyID int
declare @No int

--SET @CompanyID=1

declare @TableColumnList varchar(max),
        @ColumnList varchar(max),
        @UpdateColumnList varchar(max)
        

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)
declare @LocalDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB,@LocalDBName=LocalDatabase  from invOption where CompanyID=@CompanyID
set @RmtDBName=case when len(@LocalDBName)>0 then @LocalDBName else @RmtDBName end

if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB' Message
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Exporting to same DB is not allowable' Message
	return
End 

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0 and len(rtrim(isnull(@LocalDBName,'')))=0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+'].'

End


if len(rtrim(isnull(@LocalDBName,'')))>0
Begin
	set @RmtSrvName=''
	set @RmtDBO=''
End

    
--------------------   
create table #T1(No int,Message nvarchar(100))

exec('insert #T1(Message) select ''Permission Granted for User ''+u.Name+'' for Menu ''+upper(f.Name)+'' in Destination DB'' from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like''1%''')

declare @Message nvarchar(100)
select @Message=max(Message) from #T1


if @Message is not null
Begin
	select @Message Message
	return
End


exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
ExportCompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and ExportNo='+@ExportNo)
select @No=max(No) from #T1
------------------

--Begin Transaction


if(@No is null)
begin
	exec('insert #T1(No) exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.prGetSalesMaxVno '+@CompanyID+','+@PeriodID+','+@VtypeId)
	select @No=max(No) from #T1 
end
else
begin

	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete t from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction t WITH (ROWLOCK) join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@No+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID)

end	


