--Details
create table #SalesDetails (VtypeId int,No int,Sno int,ProductId int,WarehouseId int,UomId int,Qty float,Foc float,Rate float,Gross float,DiscountP float,Discount float,Total float,MfrDate int,ExpDate int,Remark varchar(100),BarcodeId int,TaxGroupId int,Tax float,Addition float,IType int,INo int,ISno int,IQty float,IFOC float,Pieces float,SerialNoId int,CompanyId int,PeriodId int,MRP float,SalesmanID int,OutPutTax float,Addition2 float,TAddition float,GSTIN varchar(50),Date int)

insert #SalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2,GSTIN,Date)
select d.VtypeId,@No,d.Sno,d.ProductId,d.WarehouseId,d.UomId,d.Qty,d.Foc,d.Rate,d.Gross,d.DiscountP,d.Discount,d.Total,d.MfrDate,
d.ExpDate,d.Remark,d.BarcodeId,d.TaxGroupId,d.Tax,d.Addition,d.IType,d.INo,d.ISno,d.IQty,d.IFOC,d.Pieces,d.SerialNoId,@CompanyID,d.PeriodId,d.MRP,d.SalesmanID,d.Addition2,c.GST,h.Date from invSalesDetails d WITH (NOLOCK)
join invSalesHeader h  WITH (NOLOCK) on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
join (select AccountId,GST from invCustomer WITH (NOLOCK) union all select AccountId,GST from invVendor WITH (NOLOCK)) c on h.CustomerId=c.AccountId
where d.CompanyId = @CompanyId and d.PeriodId = @PeriodId and d.[VtypeId] = @VtypeId and d.[No] = @ExportNo

declare @cTaxGroup int
select @cTaxGroup=TaxOption from invOption where CompanyID=@CompanyID

if @cTaxGroup=0
begin
	exec('update s set s.TaxGroupID=p.TaxGroupID from #SalesDetails s join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProduct p WITH (NOLOCK) on s.ProductID=p.ID')
end

create table #Option(TaxOption int,Addition2Method int,SalesStockItemsOnly bit)

exec('insert #Option(TaxOption,Addition2Method,SalesStockItemsOnly) select TaxOption,Addition2Method,SalesStockItemsOnly from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invOption where CompanyID='+@CompanyID)

declare @TaxOption int,@Addition2Method int,@SalesStockItemsOnly bit
select @TaxOption=TaxOption,@Addition2Method=Addition2Method,@SalesStockItemsOnly=SalesStockItemsOnly from #Option


if @cTaxGroup=0
Begin
	if @TaxOption=1--Inclusive
	Begin
		update s set s.OutPutTax=t.OutPutTax,s.TAddition=case when len(isnull(s.GSTIN,''))=0 then t.Addition end,s.Rate=case when s.Qty<>0 then (s.Total*100/(100+t.OutputTax)+s.Discount)/s.Qty else s.Rate end from #SalesDetails s join invTaxGroup t on s.TaxGroupID=t.ID
			
		update s set s.Gross=s.Rate*s.Qty,s.Tax=(s.Rate*s.Qty-s.Discount)*s.OutPutTax/100 from #SalesDetails s

		update s set s.Total=s.Gross+isnull(s.Tax,0)-s.Discount from #SalesDetails s 

		update s set s.DiscountP=case when s.Gross=0 then 0 else s.Discount*100.0/s.Gross end from #SalesDetails s 

	End

	if @TaxOption=2--Exclusive
	Begin
		update s set s.Tax=s.Gross*t.OutPutTax/100 from #SalesDetails s join invTaxGroup t on s.TaxGroupID=t.ID
		update s set s.Total=s.Gross+s.Tax from #SalesDetails s 
	End

End

declare @Total float


if @SalesStockItemsOnly=1
Begin
	create table #PStock (CompanyID int,ProductID int,Qty float,Pieces float) 
	declare @Date int
	select top 1 @Date=Date from #SalesDetails 

	exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.tmpTable(ID,SPID) select ProductId,@@SPID from #SalesDetails')
	exec ('insert #PStock exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.spStock @CompanyID='+@CompanyID+',@ToDate='+@Date+',@Type=12')

	delete #PStock where isnull(Qty,0)=0

	delete sd from #SalesDetails sd left join #PStock s on sd.ProductId=s.ProductID and sd.Qty<=s.Qty where s.ProductID is null

	--if not exists(select 1 from #SalesDetails)
	--Begin
	--	select @ExportNo No,'There is no item having stock to export' Message,null HSNo,1 Exporting
	--	return
	--End 

	select @Total=sum(Total) from #SalesDetails

End

set @Total=isnull(@Total,0)

--To check duplicate in destination DB
declare @DNo int
delete #T1
exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
CompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and No='+@No)
select @DNo=max(No) from #T1
if @DNo is not null
Begin
	select @ExportNo No,'There is already entry with No '+ cast(@DNo as varchar) + ' in Destination DB. Please Export Again' Message,null HSNo,1 Exporting	
	return
End


--Header
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader(VtypeId,No,Date,DeliveryDate,CustomerId,Address,PaymentMode,SalesManId,RateLevelId,DueDate,
	  QuotationNo,Total,DiscountP,Discount,NetTotal,Notes,TaxCalculation,Tax,SalesReturn,Rep1,Rep2,Paid,RoundOff,AirwayBillNo,CompanyId,
	  PeriodId,Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnId,CostCentreId,ShippingId,ShippingNo,ExportNo,ExportCompanyID) 
      select VtypeId,'+@No+',Date,DeliveryDate,CustomerId,Address,PaymentMode,SalesManId,RateLevelId,DueDate,QuotationNo,
      case when '+@Total+'<>0 then '+@Total+' else Total end,DiscountP,Discount,case when '+@Total+'<>0 then '+@Total+' else NetTotal end,Notes,TaxCalculation,Tax,SalesReturn,Rep1,Rep2,case when Paid>'+@Total+' then '+@Total+' else Paid end,RoundOff,AirwayBillNo,'+@CompanyID+',
      PeriodId,Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,null ReturnId,CostCentreId,ShippingId,ShippingNo,'+@ExportNo+',CompanyId from invSalesHeader WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


--Shifted to here on 20260313
if not exists(select 1 from #SalesDetails)
Begin
	select @ExportNo No,'There is no item having stock to export' Message,null HSNo,1 Exporting

	exec('update '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader set Total=0,NetTotal=0
	      where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)

	return
End
------------

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,
	   MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2) 
      select VtypeId,No,row_number()over(order by sno),ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,
      ExpDate,Remark,BarcodeId,TaxGroupId,isnull(Tax,0),Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2 from #SalesDetails')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails(VtypeId,No,Sno,ProductId,SubPropertyId,CompanyId,PeriodId) 
      select VtypeId,'+@No+',Sno,ProductId,SubPropertyId,'+@CompanyID+',PeriodId from invSalesPropertyDetails WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions(CompanyID,PeriodID,VtypeID,No,DebtorId,CreditorId,Description,Amount) 
      select '+@CompanyID+',PeriodID,VtypeID,'+@No+',DebtorId,CreditorId,Description,Amount from invSalesAdditions WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


--Transactions
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,
AccountID,CDate,CNo,SNo) 
      select '+@CompanyID+',PeriodID,Date,VoucherTypeID,'+@No+',DebtorID,CreditorID,Amount,t.Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo from aTransaction t WITH (NOLOCK) 
	  join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	  where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@ExportNo+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID
	  )


go

if object_id('spImportSalesFromExcel') is not null
    drop proc spImportSalesFromExcel

go

create proc spImportSalesFromExcel
@CompanyId int,
@PeriodId int,
@VtypeId int,
@UserId int,
@Xml xml,
@ProductType int=0

as

set nocount on
set xact_abort on

declare @idoc int      
exec sp_xml_preparedocument @idoc output, @Xml

declare @Sales table(SNo int identity(1,1),InvoiceNo varchar(100),InvoiceDate int,PaymentMode int,CustomerCode nvarchar(100),Customer nvarchar(100),Address1 nvarchar(150),Address2 nvarchar(150),TaxRegNo varchar(25),EMail varchar(50),Address nvarchar(500),Product nvarchar(100),Qty float,Rate float,TaxP float,Tax float,Total float,Discount float)

insert @Sales (InvoiceNo,InvoiceDate,PaymentMode,CustomerCode,Customer,Address1,Address2,TaxRegNo,EMail,Address,Product,Qty,Rate,TaxP,Discount)
select InvoiceNo,InvoiceDate,case PaymentMode when 'Card' then 3 when 'Credit' then 1 else 0 end,CustomerCode,Customer,Address1,Address2,TaxRegNo,EMail,Address,Product,Qty,Rate,TaxP,Discount
from openxml (@idoc, '/Details/Table1',2)      
with
(
InvoiceNo   varchar(100)  '@InvoiceNo',
InvoiceDate int   '@InvoiceDate',
PaymentMode varchar(50)   '@PaymentMode',
Customer    nvarchar(100) '@Customer',
CustomerCode    nvarchar(100) '@CustomerCode',
Address1    nvarchar(300) '@Address1',
Address2    nvarchar(300) '@Address2',
Address    nvarchar(500) '@Address',
TaxRegNo    varchar(25)   '@TaxRegNo',
EMail       varchar(50)   '@EMail',
Product     nvarchar(100) '@Product',
Qty         float         '@Qty',
Rate        float         '@Rate',
TaxP        float         '@TaxP',
Discount    float         '@Discount'
)
exec sp_xml_removedocument @idoc 

delete s from @Sales s join invSalesHeader h on s.InvoiceNo=h.AirWayBillNo and h.PeriodId=@PeriodId and h.CompanyId=@CompanyId and h.VtypeId=@VtypeId

update @Sales set Tax=Qty*Rate*TaxP/100.0
update @Sales set Total=Qty*Rate+Tax-Discount

----------
declare @No table([No] int)
insert @No exec prGetSalesMaxVno @CompanyID,@PeriodID,@VtypeId

declare @InvoiceNo table(InvoiceNo varchar(50),No int)
insert @InvoiceNo
select InvoiceNo,row_number()over(order by SNo)No from
(select InvoiceNo,max(SNo)SNo from @Sales group by InvoiceNo)i

update i set i.No=i.No+n.No-1 from @InvoiceNo i cross join @No n

----------


declare @MaxId int

-------Customer
select @MaxId=isnull(max(Id),0) from aAccount

declare @Customer table(Id int,Code nvarchar(100),Name nvarchar(100),TaxRegNo varchar(50),Address1 nvarchar(150),Address2 nvarchar(150),EMail varchar(50))
insert @Customer
select row_number()over(order by (select 1))+@MaxId,CustomerCode,Customer,TaxRegNo,Address1,Address2,EMail from
(select s.CustomerCode,s.Customer,s.TaxRegNo,max(s.Address1)Address1,max(s.Address2)Address2,max(s.EMail)EMail from @Sales s 
left join (select a.Code,c.Name,c.TIN from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
where c.Name is null group by s.CustomerCode,s.Customer,s.TaxRegNo)c

insert aAccount(Id,Code,Name,AccountSubGroupId,UnderAccountID,ModuleId)
select Id,case when len(c.Code)=0 then cast(Id as varchar) else c.Code end,Name,sg.SundryDebtors,s.Customers,1 from @Customer c
cross join aSubGroupSettings sg 
join aAccountSettings s on s.CompanyId=@CompanyId

insert invCustomer(AccountId,Name,Address1,Address2,Email,TIN,CompanyId)
select Id,Name,c.Address1,c.Address2,c.EMail,TaxRegNo,@CompanyId from @Customer c 
--------------


-------Product
select @MaxId=isnull(max(Id),0) from invProduct

declare @Product table(Id int,Code nvarchar(100),Name nvarchar(100),Rate float,TaxP float)

if (@ProductType=1)--Code
Begin
	insert @Product(Id,Code,Name)
	select row_number()over(order by (select 1))+@MaxId,Product,Product from
	(select distinct Product from @Sales s left join invProduct p on s.Product=p.Code where p.Name is null)p

	update p set p.Rate=s.Rate,p.TaxP=s.TaxP from @Product p join @Sales s on p.Code=s.Product
End
Else
Begin
	insert @Product(Id,Name)
	select row_number()over(order by (select 1))+@MaxId,Product from
	(select distinct Product from @Sales s left join invProduct p on s.Product=p.Name where p.Name is null)p

	update p set p.Rate=s.Rate,p.TaxP=s.TaxP from @Product p join @Sales s on p.Name=s.Product
End

select @MaxId=isnull(max(Id),0) from invTaxGroup
insert invTaxGroup(Id,Code,Name,InputTax,OutPutTax,PurchaseValueTitle,PurchaseTaxTitle,SalesValueTitle,SalesTaxTitle,CGST,SGST)
select row_number()over(order by (select 1))+@MaxId,'T'+TaxP,'Tax'+TaxP,TaxP,TaxP,'Value'+TaxP,'Tax'+TaxP,'Value'+TaxP,'Tax'+TaxP,TaxP/2,TaxP/2 from
(select distinct cast(TaxP as varchar)TaxP from @Sales s left join invTaxGroup t on s.TaxP=t.OutputTax where t.Name is null)p


-------Product
declare @UOMId int
select @UOMId=min(Id) from invUOM

insert invProduct(Id,Code,Name,Rate,BaseUOM,PurchaseUOM,SalesUOM,StockUOM,MinUOM,MaxUOM,ROLUOM,ROQUOM,TaxGroupId)
select p.Id,isnull(p.Code,p.Id),p.Name,p.Rate,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,@UOMId,t.Id from @Product p 
join invTaxGroup t on p.TaxP=t.OutputTax


insert invUOMLevels(Sno,ProductId,UomId,Multiplayer,UnitId,Secondary,Rate)
select 1,Id,@UOMId,1,@UOMId,1,Rate from @Product p 
--------------

insert invSalesHeader(VtypeId,No,Date,DeliveryDate,CustomerId,Address,PaymentMode,Total,NetTotal,TaxCalculation,Tax,AirwayBillNo,CompanyId,PeriodId,Time,UserId,SalesmanId)
select @VtypeId,i.No,s.InvoiceDate,s.InvoiceDate,min(c.AccountId),s.Address,s.PaymentMode,sum(Total),sum(Total),1,sum(Tax),s.InvoiceNo,@CompanyId,@PeriodId,
substring(convert(varchar,current_timestamp,8),1,2)+substring(convert(varchar,current_timestamp,8),4,2),@UserId,nullif(min(c.SalesManId),0) from @Sales s
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join (select a.Code,c.Name,c.TIN,c.AccountId,c.SalesManId from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
group by i.No,s.InvoiceDate,s.PaymentMode,s.InvoiceNo,s.Address


insert invSalesDetails(VtypeId,No,SNo,ProductId,UOMId,Qty,Rate,Gross,Total,TaxGroupId,Tax,Discount,CompanyId,PeriodId)
select @VtypeId,i.No,row_number()over(partition by i.No order by i.No),p.Id,@UOMId,s.Qty,s.Rate,s.Qty*s.Rate,s.Total,p.TaxGroupId,s.Tax,s.Discount,@CompanyId,@PeriodId from @Sales s 
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join invProduct p on s.Product=case when @ProductType=1 then p.Code else p.Name end


declare @AccountVtypeId int
select @AccountVtypeId=AccountVtypeId from invVoucherTypeDetails where Id=@VtypeId

insert aTransaction(CompanyId,PeriodId,Date,VoucherTypeId,No,DebtorId,CreditorId,Amount,Description,RefNo,ModuleID)
select @CompanyId,@PeriodId,s.InvoiceDate,@AccountVtypeId,i.No,case when s.PaymentMode=1 then c.AccountId else isnull(o.SalesCashAccountId,st.CashInHand) end,st.Sales,sum(s.Total),'Sales',s.InvoiceNo,1 from @Sales s
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join (select a.Code,c.Name,c.TIN,c.AccountId from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
join aAccountSettings st on st.CompanyId=@CompanyId
join invOption o on o.CompanyId=@CompanyId
group by s.InvoiceDate,i.No,c.AccountID,st.Sales,s.InvoiceNo,s.PaymentMode,o.SalesCashAccountId,st.CashInHand

insert aTransaction(CompanyId,PeriodId,Date,VoucherTypeId,No,DebtorId,CreditorId,Amount,Description,RefNo,ModuleID)
select @CompanyId,@PeriodId,s.InvoiceDate,@AccountVtypeId,i.No,st.Sales,o.OutPutTaxAccount,sum(s.Tax),'Sales Tax',s.InvoiceNo,1 from @Sales s
join @InvoiceNo i on s.InvoiceNo=i.InvoiceNo
join (select a.Code,c.Name,c.TIN,c.AccountId from invCustomer c join aAccount a on c.AccountID=a.ID) c on (s.Customer=c.Name and s.TaxRegNo=c.TIN and len(s.CustomerCode)=0 or s.CustomerCode=c.Code)
join aAccountSettings st on st.CompanyId=@CompanyId
join invOption o on o.CompanyId=@CompanyId
group by s.InvoiceDate,i.No,c.AccountID,st.Sales,s.InvoiceNo,o.OutPutTaxAccount


go

if object_id('prSaveinvCustomer') is not null
	drop proc prSaveinvCustomer
go	
	
create proc prSaveinvCustomer
@Id int,
@Code varchar(15),
@Name nvarchar(100),
@UnderID int,
@NickName nvarchar(100),
@NameInOL nvarchar(100)=null,
@Address1 nvarchar(100),
@Address2 nvarchar(100),
@Address3 nvarchar(100),
@Address4 nvarchar(100)=null,
@Address5 nvarchar(100)=null,
@Address6 nvarchar(100)=null,
@Address7 nvarchar(100)=null,
@Address8 nvarchar(100)=null,
@Address9 nvarchar(100)=null,
@Place nvarchar(100),
@Phone nvarchar(50),
@MobileNo nvarchar(50),
@Email nvarchar(100),
@Web varchar(100),
@Location varchar(500)=null,
@ContactPerson nvarchar(100),
@CreditLimit float,
@DueDays float,
@CurrencyId int,
@RateLevelId int,
@SalesManId int,
@PaymentTerms nvarchar(100),
@FileNo nvarchar(50),
@Remark nvarchar(250),
@OB float,
@OBType bit,
@CompanyID int,
@xmlPropertyData xml,
@TIN nvarchar(100),
@CST nvarchar(100),
@DLNo1 nvarchar(100),
@DLNo2 nvarchar(100),
@GST nvarchar(100),
@OBCompanyID int=1,
@PaymentMode tinyint=null,
@Image Image =null,
@CostCentreId int=null,
@Approve bit=null
as

set nocount on

declare @DuplicateCustomer bit
declare @AllowDuplicatePhoneNo bit

select @DuplicateCustomer = DuplicateCustomer,@AllowDuplicatePhoneNo=AllowDuplicatePhoneNo from invOption 
where CompanyID=@CompanyID

declare @Message nvarchar(500)

--------
if isnull(@AllowDuplicatePhoneNo,0)=0
Begin
	if len(isnull(@Phone,'')+isnull(@MobileNo,''))>0
	Begin
		select @Message='There is already customer ' + Name + ' with the given phone number(s)' from invCustomer 
		where AccountID<>@Id and isnull(Phone,'')+isnull(MobileNo,'')=isnull(@Phone,'')+isnull(@MobileNo,'')
		if @Message is not null
		Begin
			select @Id ID,3 Status,@Message Message
			return
		End
	End
End
----------

--Insertion to account
if isnull(@UnderID,0)=0
	select @UnderID=Customers from aAccountSettings

declare @AccountSubGroupID int
select @AccountSubGroupID=AccountSubGroupID from aAccount where ID=@UnderID

select @CompanyID=nullif(@CompanyID,0)

declare @t table(ID int,Status tinyint,Message varchar(100)) 


if len(@Code) = 0-- To Generate New Code
Begin
	declare @Prefix varchar(50)    
	declare @Size int    
	
	select @Prefix=isnull(max(Left(Code, PatIndex('%[0-9]%', Code + '1') - 1)),''),@Size=isnull(max(len(Code)),0) from aAccount  where isnumeric(Code)=0
	select @Code=isnull(max(cast(replace(Code,@Prefix,'') as numeric)),0)+1 from aAccount where PATINDEX('%[^0-9]%',replace(Code,@Prefix,''))=0 and len(replace(Code,@Prefix,''))>0 and Code like @Prefix+'%'
	if len(@Prefix+@Code)>@Size set @Size=len(@Prefix+@Code)
	select @Code=@Prefix+replicate('0',@Size-len(@Prefix+@Code))+@Code  

End


declare @WarnMessage varchar(max)

if @Id>0
Begin
	select @WarnMessage='THE OB HAS REFERENCE IN BILLWISE RECEIPT : '+ cast(b.No as varchar)+' AND CAN''T UPDATE' from aBillwiseReceiptDtl b 
	join aBillwiseReceiptHdr h on b.CompanyId=h.CompanyId and b.PeriodId=h.PeriodId and b.No=h.No 
	where b.CompanyID=@OBCompanyID and b.EPeriodID is null and b.EVoucherTypeID is null  and b.ENo is null and h.CustomerId=@Id

	if (@WarnMessage is null)
		delete aTransaction where PeriodID is null and Date is null and No is null and (DebtorID=@Id and CreditorID=1 or DebtorID=1 and CreditorID=@Id) and CompanyID=@OBCompanyID
	Else
		set @OBCompanyID=null
End

insert @t 
exec spSaveAccount @ID=@Id,@Code=@Code,@Name=@Name,@NameInOL=@NameInOL,
	 @AccountSubGroupID=@AccountSubGroupID,@UnderAccountID=@UnderID,
     @OB=@OB,@DrCr=@OBType,@CompanyID=@OBCompanyID,@ModuleID=1,@IsAllowDuplicateName = @DuplicateCustomer


declare @NewId int

select @NewId=ID from @t where Status=0
if @NewId is null
Begin
	select * from @t
	return
End



if @NickName=''
	set @NickName=@Name

if isnull(@Id,0) = 0
  begin
      insert invCustomer([AccountId],[Name],[Address1],[Address2],[Address3],[Place],[Phone],[MobileNo],[Email],
      [Web],Location,[ContactPerson],[CreditLimit],[DueDays],[CurrencyId],[RateLevelId],[SalesManId],[PaymentTerms],FileNo,[Remark],
      [TIN],[CST],[DLNo1],[DLNo2],CompanyID,GST,PaymentMode,Image,Address4,Address5,Address6,Address7,Address8,Address9,CostCentreId,Approve)
      values(@NewId,@NickName,nullif(@Address1,''),nullif(@Address2,''),nullif(@Address3,''),nullif(@Place,''),
      nullif(@Phone,''),nullif(@MobileNo,''),nullif(@Email,''),nullif(@Web,''),nullif(@Location,''),
      nullif(@ContactPerson,''),nullif(@CreditLimit,0),nullif(@DueDays,0),nullif(@CurrencyId,0),
      nullif(@RateLevelId,0),nullif(@SalesManId,0),nullif(@PaymentTerms,''),nullif(@FileNo,''),
      nullif(@Remark,''),nullif(@TIN,''),nullif(@CST,''),nullif(@DLNo1,''),nullif(@DLNo2,''),@CompanyID,nullif(@GST,''),nullif(@PaymentMode,0),@Image,
	  nullif(@Address4,''),nullif(@Address5,''),nullif(@Address6,''),nullif(@Address7,''),nullif(@Address8,''),nullif(@Address9,''),nullif(@CostCentreId,0),nullif(@Approve,0))	  
  end
else
	begin
		update invCustomer set [Name]= @NickName,
		                    [Address1]= nullif(@Address1,''),
							[Address2]= nullif(@Address2,''),
							[Address3]= nullif(@Address3,''),
							[Place] = nullif(@Place,''),
							[Phone]= nullif(@Phone,''),
							[MobileNo]= nullif(@MobileNo,''),
							[Email]= nullif(@Email,''),
							[Web]= nullif(@Web,''),
							Location= nullif(@Location,''),
							[ContactPerson]= nullif(@ContactPerson,''),
							[CreditLimit]= nullif(@CreditLimit,0),
							[DueDays]= nullif(@DueDays,0),
							[CurrencyId]= nullif(@CurrencyId,0),
							[RateLevelId] = nullif(@RateLevelId,0),
							[SalesManId] = nullif(@SalesManId,0) , 
							[PaymentTerms]= nullif(@PaymentTerms,''),
							FileNo=nullif(@FileNo,''),
							[Remark]= nullif(@Remark,''),
							[TIN] = nullif(@TIN,''),
							[CST] = nullif(@CST,''),
							[DLNo1] = nullif(@DLNo1,''),
							[DLNo2] = nullif(@DLNo2,''),
							CompanyID=@CompanyID,
							[GST] = nullif(@GST,''),
							PaymentMode=nullif(@PaymentMode,0),
							Image=@Image,
							[Address4]= nullif(@Address4,''),
							[Address5]= nullif(@Address5,''),
							[Address6]= nullif(@Address6,''),
							[Address7]= nullif(@Address7,''),
							[Address8]= nullif(@Address8,''),
							[Address9]= nullif(@Address9,''),
							CostCentreId=nullif(@CostCentreId,0),
							Approve=nullif(@Approve,0)

		where [AccountID]= @NewId

        delete invAccountPropertyDetails where [AccountID]= @NewId	
	end     


   declare @Idoc int
   --<Property>
   exec sp_xml_preparedocument @Idoc out ,@xmlPropertyData
   
   insert invAccountPropertyDetails([AccountId],[PropertyId],[SubPropertyId])
   select @NewId,[PropertyId],[SubPropertyId] from openxml(@Idoc,'/TableHeader/Table1',2)
   with
   (
		PropertyId int '@PropertyId',
		SubPropertyId int '@SubPropertyId'
   )
   
   exec sp_xml_removedocument @Idoc 
   --<Property/>  
     
  
  select @NewId ID,0 status ,'Saved Successfully. '+ isnull(@WarnMessage,'') Message

go 



if object_id('prCustomerAddressList') is not null
  drop proc prCustomerAddressList

go
  
create proc prCustomerAddressList
@Columns varchar(max),
@ValueDataWhereClause varchar(max),
@MasterDataWhereClause varchar(max),
@Summary bit=0

as  

   
set nocount on  
set transaction isolation level read uncommitted

declare @WhereClause varchar(max)         


if len(@ValueDataWhereClause) > 0 and LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where ' + @ValueDataWhereClause + ' and ' + @MasterDataWhereClause
else if len(@ValueDataWhereClause) > 0 
  set @WhereClause = ' where ' + @ValueDataWhereClause 
else if LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where ' + @MasterDataWhereClause
else 
  set @WhereClause = ''   


if @Summary=1
	
	exec('select Value Address from 
	(
	select top 50000 
	cast(t2.Code as nvarchar(100))Code,
	t2.Name,
	cast(t1.address1 as nvarchar(100))address1,
	cast(t1.address2 as nvarchar(100))address2,
	cast(t1.address3 as nvarchar(100))address3,
	cast(t1.Place as nvarchar(100))Place,
	cast(t1.Phone as nvarchar(100)) Phone,
	cast(t1.MobileNo as nvarchar(100)) Mobile,
	t1.Email,
	cast(t1.Web as nvarchar(100))Web,
	cast(t1.Location as nvarchar(100)) Location,
	cast(t1.GST as nvarchar(100)) GSTIN,
	cast(replicate(''-'',100) as nvarchar(100)) [ ] from invCustomer t1
	join aAccount t2 on t1.AccountId = t2.Id
	join vw_customerProperty t3 on t1.AccountId = t3.AccountId ' + @WhereClause  + ' order by t2.name) t1
	unpivot
	(
	value for property in (' + @Columns + ',[ ])
	)
	t2 where len(value)>0')

Else
	
	exec('select ' + @Columns + ' from 
	(
	select top 50000 
	t2.Code,
	t2.Name,
	cast(t1.address1 as nvarchar(100))address1,
	cast(t1.address2 as nvarchar(100))address2,
	cast(t1.address3 as nvarchar(100))address3,
	cast(t1.Place as nvarchar(100))Place,
	cast(t1.Phone as nvarchar(100)) Phone,
	cast(t1.MobileNo as nvarchar(100)) Mobile,
	t1.Email,
	cast(t1.Web as nvarchar(100))Web,
	cast(t1.Location as nvarchar(100)) Location,
	cast(t1.GST as nvarchar(100)) GSTIN,
	s.Name Salesman
	from aAccount t2
	join vw_customerProperty t3 on t2.Id = t3.AccountId 
	left join invCustomer t1 on t2.Id = t1.AccountId
	left join invSalesman s on t1.SalesmanId=s.Id
	' + @WhereClause  + ' order by t2.name) t1')
	
	


go

if object_id('spGetSalesForCashReceipt') is not null drop proc spGetSalesForCashReceipt

go

create proc spGetSalesForCashReceipt
@Date int,
@DebtorId int,
@CompanyId int=1

as

declare @SalesmanId int
select @SalesmanId=id from invSalesman where accountid=@DebtorId

select 0 SNo,0 KSNo,fd.CustomerID CreditorID,a.Code,a.Name Creditor,fd.CostCentreID,c.Name CostCentre,fd.No Description,fd.NetTotal Amount,0 Discount,fd.NetTotal NetAmount from invSalesHeader fd 
join aAccount a on fd.CustomerID=a.ID 
left join invCostCentre ic on fd.CostCentreID=ic.ID
left join aCostCentre c on ic.CostCentreID=c.ID
where fd.Date=@Date and fd.PaymentMode=1 
and (@SalesmanId is null or fd.SalesmanId=@SalesmanId)
and CompanyId=@CompanyId
order by fd.No

go


if object_id('prGetActiveProductForPurchase') is not null
	drop proc prGetActiveProductForPurchase
go	
   
create proc prGetActiveProductForPurchase
@VendorID int=0,
@UserID int=1,
@CompanyId int=1
as  

set nocount on  
set transaction isolation level read uncommitted

create table #Products([ ]bit,ID int,Code varchar(50),Name nvarchar(200),NativeCaption nvarchar(200),UBC varchar(50),TaxGroupID int,UOMID int,UOM varchar(50),Cost float,SRate float,MRP float,Tax float,TaxGroup varchar(50),Stock float,CCode varchar(50),SerialNo bit,CostCentreId int,AdditionP float,NonStock bit,TaxOnMRP bit)

if (@VendorID>0)
	insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,UOM,Cost,SRate,MRP,SerialNo,CostCentreId,AdditionP,NonStock)
	select p.ID,p.Code,p.Name,p.OtherLanguage,p.TaxGroupId,p.BaseUom,u.Name,p.Cost,p.Rate,p.Mrp,isnull(p.SerialNo,0) SerialNo,p.CostCentreId,p.AdditionP,p.NonStockItem from invProduct p 
	join invUom u on p.BaseUom=u.Id
	join invPreferredVendors v on p.Id=V.ProductId and v.VendorId=@VendorID
	where Inactive is null or Inactive = 0
Else
	insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,UOM,Cost,SRate,MRP,SerialNo,CostCentreId,AdditionP,NonStock)
	select p.ID,p.Code,p.Name,p.OtherLanguage,p.TaxGroupId,p.BaseUom,u.Name,p.Cost,p.Rate,p.Mrp,isnull(p.SerialNo,0) SerialNo,p.CostCentreId,p.AdditionP,p.NonStockItem from invProduct p 
	join invUom u on p.BaseUom=u.Id
	where Inactive is null or Inactive = 0


--Cost Centre Filtering
declare @CC table(Id int)
insert @CC
select isnull(CostCentreId,0) from invUserCostCentre where Product=1 and UserId=@UserID

if exists(select 1 from @CC)
	delete p from #Products p left join @CC c on isnull(p.CostCentreId,0)=c.Id where c.Id is null
-------

create index ind#Products on #Products(ID,UOMID)


--UOM Rates and Barcode
update p set p.UBC=u.Barcode from #Products p join invUomLevels u on p.ID=u.ProductID and p.UOMID = u.UOMID and u.Sno=1


--Aliases
insert #Products(ID,Code,Name,NativeCaption,TaxGroupId,UomId,Cost,SRate,MRP,SerialNo,AdditionP)
select p.ID,p.Code,a.Alias,p.NativeCaption,p.TaxGroupId,p.UomId,p.Cost,p.SRate,p.MRP,isnull(p.SerialNo,0) SerialNo,p.AdditionP from #Products p join invProductAlias a on p.ID=a.ProductID

--Tax Details
update p set p.Tax=t.InputTax,p.TaxGroup=t.Name,p.TaxOnMRP=t.OnMRP from #Products p join invTaxGroup t on p.TaxGroupId = t.Id 

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code from #Products p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

-------------------
--Stock
if exists(select 1 from invOption where PurchaseDisplayStock=1 and CompanyId=@CompanyId)--Stock
Begin
	create table #PStock1(CompanyId int,ProductID int,BarcodeId int,Qty float,Pieces float)
	insert tmpTable(ID,SPID) select ID,@@SPID from invProduct where not (isnull(InActive,0)=1 or isnull(NonStockItem,0)=1)
	insert #PStock1 
	exec spStock @ToDate=99999999,@Type=12,@CompanyId=@CompanyId
	return
	create table #PStock(CompanyId int,ProductID int,Qty float,Pieces float Unique Clustered(ProductId)) 
	insert #PStock 
	select CompanyId,ProductID,sum(Qty),sum(Pieces) from #PStock1 group by CompanyId,ProductID
	delete #PStock where Qty=0
	update p set p.Stock=s.Qty from #Products p join #PStock s on p.ID=s.ProductID --and s.Qty<>0
End

if exists(select 1 from invOption where PurchaseRate=1 and CompanyID=@CompanyId)
Begin
	;with pd as
	(select row_number()over(partition by ProductId order by PeriodId desc,no desc)sno,pd.ProductId,pd.CostPrice,p.Cost from invPurchaseDetails pd 
	join #Products p on pd.ProductId=p.ID
	where pd.CompanyId=@CompanyId
	)

	update pd set pd.Cost=pd.CostPrice where pd.sno=1

End


if exists(select top 1 1 from invOption where DefaultSearchInPurchase=2 and CompanyId=@CompanyId)
	select Code +'       '+ Name [Code + Name],*,Cost Rate,replace(Code,'*','')Code1 from #Products
else
	select *,Cost Rate,replace(Code,'*','')Code1 from #Products order by name

drop table #Products

go


