--Tax Details
update p set p.Tax=t.InputTax,p.TaxGroup=t.Name,p.TaxOnMRP=t.OnMRP from #Products p join invTaxGroup t on p.TaxGroupId = t.Id 

--Category Code
declare @@CatPropID int
