	create table #PStock(CompanyId int,ProductID int,Qty float,Pieces float Unique Clustered(ProductId)) 
	insert #PStock 
	select CompanyId,ProductID,sum(Qty),sum(Pieces) from #PStock1 group by CompanyId,ProductID
	delete #PStock where Qty=0
	update p set p.Stock=s.Qty from #Products p join #PStock s on p.ID=s.ProductID --and s.Qty<>0
