if object_Id('prQuotationReport') is not null
	drop proc prQuotationReport  
go

create proc prQuotationReport 
@From int,
@To int, 
@DetailPart bit,
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@GrandTotal varchar(max),
@Order varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@HeaderValueDataWhereClause varchar(max),
@HeaderMasterDataWhereClause varchar(max),
@DetailsValueDataWhereClause varchar(max),
@DetailsMasterDataWhereClause varchar(max),
@AlterTable varchar(max),
@CompanyId int

as      

set transaction isolation level read uncommitted
set nocount on        

declare @Query varchar(max),
		@WhereClause varchar(max)

create table #QuotationHeader
(
[No] int,
[Date] datetime,
[Valid Upto] datetime,
[Customer] nvarchar(100),
[Sales Man] varchar(50) null ,
[Rate Level] varchar(50) null ,
[Refference No] varchar(50) null ,
[Revise No] int,
[Total] float,
[DiscountP] float,
[Discount] float,
[NetTotal] float,
[Notes] varchar(500) 
)


if len(@HeaderValueDataWhereClause) > 0 and LEN(@HeaderMasterDataWhereClause) > 0 
  set @WhereClause = @HeaderValueDataWhereClause + ' and ' + @HeaderMasterDataWhereClause + ' and '
else if len(@HeaderValueDataWhereClause) > 0 
  set @WhereClause = @HeaderValueDataWhereClause + ' and '
else if LEN(@HeaderMasterDataWhereClause) > 0 
  set @WhereClause = @HeaderMasterDataWhereClause + ' and '
else 
  set @WhereClause = ''  

exec('insert #QuotationHeader select t1.[No],cast(cast(t1.[Date] as  varchar) as datetime) ,
cast(cast(t1.[ValidUpto] as  varchar) as datetime),t2.Name [Vendor],t4.Name,t5.Name,
t1.RefferenceNo,t1.ReviseNo,t1.[Total],t1.[DiscountP],t1.[Discount],
t1.[NetTotal],t1.[Notes] from invQuotationHeader t1
join aAccount t2 on t1.CustomerId = t2.Id 
left outer join invSalesMan t4 on t1.SalesManId = t4.id
left outer join invRateLevel t5 on t1.RateLevelId = t5.id
where ' + @WhereClause + ' t1.Date between ' + @From + ' and ' + @To + ' and t1.CompanyId=' + @CompanyId)

if @DetailPart = 1
begin
	create table #QuotationDetalis
	(
		[No1] int ,
		[Sno] int ,
		[Code] varchar(50),
		[Particulars] varchar(200) ,
		[Uom] varchar(50) ,
		[Qty] float ,
		[Foc] float ,
		[Rate] float ,
		[Gross] float ,
		[IDiscountP] float ,
		[IDiscount] float ,
		[ITotal] float ,
		[Remark] varchar(100) 
	)
	
	    declare @AlterProperty varchar(max),@ProperyColumns varchar(max)
    	select @ProperyColumns = ISNULL(@ProperyColumns + ',','') + QUOTENAME(Name),
    	       @AlterProperty = ISNULL(@AlterProperty + ',','') + QUOTENAME(Name) + ' varchar(100) '
    	       from invProductProperty order by Name   
       
        exec('alter table #QuotationDetalis add ' + @AlterProperty)
		
		
		if len(@DetailsValueDataWhereClause) > 0 and LEN(@DetailsMasterDataWhereClause) > 0 
		  set @WhereClause = @DetailsValueDataWhereClause + ' and ' + @DetailsMasterDataWhereClause + ' and '
		else if len(@DetailsValueDataWhereClause) > 0 
		  set @WhereClause = @DetailsValueDataWhereClause + ' and '
		else if LEN(@DetailsMasterDataWhereClause) > 0 
		  set @WhereClause = @DetailsMasterDataWhereClause + ' and '
		else 
		  set @WhereClause = ''  

		    
		exec('insert #QuotationDetalis select t1.[No],t1.[Sno],t2.[Code],t2.Name Particulars,t4.Name Uom,
		t1.[Qty],t1.[Foc],t1.[Rate],t1.[Gross],t1.[DiscountP],
		t1.[Discount],t1.[Total],t1.[Remark],' + @ProperyColumns + ' from invQuotationDetails t1
		join invProduct t2 on t1.ProductId = t2.Id 
		join invUom t4 on t1.UomId = t4.Id 
		join invQuotationHeader t6 on t1.No = t6.No 
		left outer join vw_ProductProerty t7 on t1.ProductId = t7.Id
		where ' + @WhereClause + ' t6.Date between ' + @From + ' and ' + @To + ' and t1.CompanyId=' + @CompanyId)
			
	end


if @Group = 0
	begin  
		if @DetailPart = 0
			begin    
				if @GroupTotal = 0        
					exec('select ' + @columns + ' from #QuotationHeader ' + @order)
				else
					begin
						if len(@order) > 0
							begin 
								set @Query = 'select ' + @columns +  ' from (select 0 row_id,' + @columns + ' from #QuotationHeader union all select 1 row_id, ' + @GrandTotal + ' from #QuotationHeader ) p ' + replace(@order,'order by','order by row_id,')
								exec(@Query)
							end 
						else
							exec('select ' + @columns + ' from #QuotationHeader union all select ' + @GrandTotal + ' from #QuotationHeader ' )
					end          
			end
		else
			begin
				if @GroupTotal = 0        
					exec('select ' + @columns +  ' from #QuotationHeader T1 JOIN #QuotationDetalis T2 ON T1.[No] = T2.[No1]  ' +  @order)
				else
					begin
						if len(@order) > 0
							begin
								set @Query = 'select ' + @columns + ' from(select 0 row_id,' + @columns +  ' from #QuotationHeader T1 JOIN #QuotationDetalis T2 ON T1.[No] = T2.[No1]  union all select 1 row_id,' + @GrandTotal +  ' from #QuotationHeader T1 JOIN #QuotationDetalis T2 ON T1.[No] = T2.[No1]  ) p '  + replace(@order,'order by','order by row_id,')
								exec(@Query)
							end	
						else		
							exec('select ' + @columns +  ' from #QuotationHeader T1 JOIN #QuotationDetalis T2 ON T1.[No] = T2.[No1]  union all select ' + @GrandTotal +  ' from #QuotationHeader T1 JOIN #QuotationDetalis T2 ON T1.[No] = T2.[No1]  ' )  
					end
			end
	end
else
	begin
		create table #QuotationGroup(rid numeric identity(1,1))
		exec(@AlterTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #QuotationGroup
end

if @DetailPart = 1 drop table #QuotationDetalis
drop table #QuotationHeader

go

if object_id('prExportSales') is not null drop proc prExportSales

go

create proc prExportSales
@CompanyID int,
@PeriodID int,
@VtypeID int,
@ExportNo int

as

SET NOCOUNT ON
SET XACT_ABORT ON
SET DEADLOCK_PRIORITY LOW
SET LOCK_TIMEOUT 10000

--declare @CompanyID int
declare @No int

--SET @CompanyID=1

declare @TableColumnList varchar(max),
        @ColumnList varchar(max),
        @UpdateColumnList varchar(max)
        

declare @RmtSrvName varchar(50)
declare @RmtUsrName varchar(50)
declare @RmtUsrPwd varchar(50)
declare @RmtDBO varchar(50)
declare @RmtDBName varchar(50)
declare @LocalDBName varchar(50)

select @RmtSrvName=RemoteServerName,@RmtUsrName=RemoteUserName,@RmtUsrPwd=RemoteUserPassword,@RmtDBO=RemoteDBO,@RmtDBName=TransferDB,@LocalDBName=LocalDatabase  from invOption where CompanyID=@CompanyID
set @RmtDBName=case when len(@LocalDBName)>0 then @LocalDBName else @RmtDBName end

if isnull(@RmtDBName,'')=''
Begin
	select 'Please Set Transfer DB' Message
	return
End 



if isnull(@RmtSrvName,'')='' and isnull(@RmtUsrName,'')='' and isnull(@RmtUsrPwd,'')='' and isnull(@RmtDBO,'')='' and @RmtDBName=db_name()
Begin
	select 'Exporting to same DB is not allowable' Message
	return
End 

if len(rtrim(@RmtSrvName))>0 and len(rtrim(@RmtDBO))>0 and len(rtrim(isnull(@LocalDBName,'')))=0
Begin
	--remove existing linked servers
	declare @LocalLogin varchar(50)
	set @LocalLogin=suser_name()
	if exists(select 1 from master..sysservers where srvname=@rmtsrvname)
	Begin
		exec sp_droplinkedsrvlogin @RmtSrvName=@RmtSrvName,@LocalLogin=@LocalLogin
		exec sp_dropserver @server=@RmtSrvName,@droplogins='droplogins'
	End


	--add linked servers
	exec sp_addlinkedserver @RmtSrvName, N'SQL Server'
	exec sp_serveroption @RmtSrvName, 'data access', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc', 'true' 
	exec sp_serveroption @RmtSrvName, 'rpc out', 'true' 
	exec sp_serveroption @RmtSrvName, 'use remote collation', 'true' 
	exec sp_addlinkedsrvlogin  @RmtSrvName, 'false', @LocalLogin ,@RmtUsrName,@RmtUsrPwd

	select @RmtSrvName='['+ @RmtSrvName+'].'

End


if len(rtrim(isnull(@LocalDBName,'')))>0
Begin
	set @RmtSrvName=''
	set @RmtDBO=''
End

    
--------------------   
create table #T1(No int,Message nvarchar(100))

exec('insert #T1(Message) select ''Permission Granted for User ''+u.Name+'' for Menu ''+upper(f.Name)+'' in Destination DB'' from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invUserDetails ud
join invUser u on ud.UserId=u.Id
join invForms f on ud.FormId collate database_default =f.FormId collate database_default
where UserId>1 and ud.FormId like''1%''')

declare @Message nvarchar(100)
select @Message=max(Message) from #T1


if @Message is not null
Begin
	select @Message Message
	return
End


exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
ExportCompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and ExportNo='+@ExportNo)
select @No=max(No) from #T1
------------------

--Begin Transaction


if(@No is null)
begin
	exec('insert #T1(No) exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.prGetSalesMaxVno '+@CompanyID+','+@PeriodID+','+@VtypeId)
	select @No=max(No) from #T1 
end
else
begin

	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions WITH (ROWLOCK) where CompanyId = '+@CompanyID+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)
	exec('delete t from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction t WITH (ROWLOCK) join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@No+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID)

end	


