--Details
create table #SalesDetails (VtypeId int,No int,Sno int,ProductId int,WarehouseId int,UomId int,Qty float,Foc float,Rate float,Gross float,DiscountP float,Discount float,Total float,MfrDate int,ExpDate int,Remark varchar(100),BarcodeId int,TaxGroupId int,Tax float,Addition float,IType int,INo int,ISno int,IQty float,IFOC float,Pieces float,SerialNoId int,CompanyId int,PeriodId int,MRP float,SalesmanID int,OutPutTax float,Addition2 float,TAddition float,GSTIN varchar(50),Date int)

insert #SalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2,GSTIN,Date)
select d.VtypeId,@No,d.Sno,d.ProductId,d.WarehouseId,d.UomId,d.Qty,d.Foc,d.Rate,d.Gross,d.DiscountP,d.Discount,d.Total,d.MfrDate,
d.ExpDate,d.Remark,d.BarcodeId,d.TaxGroupId,d.Tax,d.Addition,d.IType,d.INo,d.ISno,d.IQty,d.IFOC,d.Pieces,d.SerialNoId,@CompanyID,d.PeriodId,d.MRP,d.SalesmanID,d.Addition2,c.GST,h.Date from invSalesDetails d WITH (NOLOCK)
join invSalesHeader h  WITH (NOLOCK) on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
join (select AccountId,GST from invCustomer WITH (NOLOCK) union all select AccountId,GST from invVendor WITH (NOLOCK)) c on h.CustomerId=c.AccountId
where d.CompanyId = @CompanyId and d.PeriodId = @PeriodId and d.[VtypeId] = @VtypeId and d.[No] = @ExportNo

declare @cTaxGroup int
select @cTaxGroup=TaxOption from invOption where CompanyID=@CompanyID

if @cTaxGroup=0
begin
	exec('update s set s.TaxGroupID=p.TaxGroupID from #SalesDetails s join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invProduct p WITH (NOLOCK) on s.ProductID=p.ID')
end

create table #Option(TaxOption int,Addition2Method int,SalesStockItemsOnly bit)

exec('insert #Option(TaxOption,Addition2Method,SalesStockItemsOnly) select TaxOption,Addition2Method,SalesStockItemsOnly from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invOption where CompanyID='+@CompanyID)

declare @TaxOption int,@Addition2Method int,@SalesStockItemsOnly bit
select @TaxOption=TaxOption,@Addition2Method=Addition2Method,@SalesStockItemsOnly=SalesStockItemsOnly from #Option


if @cTaxGroup=0
Begin
	if @TaxOption=1--Inclusive
	Begin
		update s set s.OutPutTax=t.OutPutTax,s.TAddition=case when len(isnull(s.GSTIN,''))=0 then t.Addition end,s.Rate=case when s.Qty<>0 then (s.Total*100/(100+t.OutputTax)+s.Discount)/s.Qty else s.Rate end from #SalesDetails s join invTaxGroup t on s.TaxGroupID=t.ID
			
		update s set s.Gross=s.Rate*s.Qty,s.Tax=(s.Rate*s.Qty-s.Discount)*s.OutPutTax/100 from #SalesDetails s

		update s set s.Total=s.Gross+isnull(s.Tax,0)-s.Discount from #SalesDetails s 

		update s set s.DiscountP=case when s.Gross=0 then 0 else s.Discount*100.0/s.Gross end from #SalesDetails s 

	End

	if @TaxOption=2--Exclusive
	Begin
		update s set s.Tax=s.Gross*t.OutPutTax/100 from #SalesDetails s join invTaxGroup t on s.TaxGroupID=t.ID
		update s set s.Total=s.Gross+s.Tax from #SalesDetails s 
	End

End

declare @Total float

if @SalesStockItemsOnly=1
Begin
	create table #PStock (CompanyID int,ProductID int,BarcodeId int,Qty float,Pieces float) 
	declare @Date int
	select top 1 @Date=Date from #SalesDetails 

	exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.tmpTable(ID,SPID) select ProductId,@@SPID from #SalesDetails')
	exec ('insert #PStock exec '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.spStock @CompanyID='+@CompanyID+',@ToDate='+@Date+',@Type=12')

	delete #PStock where isnull(Qty,0)=0

	delete sd from #SalesDetails sd left join #PStock s on sd.ProductId=s.ProductID and sd.Qty<=s.Qty where s.ProductID is null

	select @Total=sum(Total) from #SalesDetails

End

set @Total=isnull(@Total,0)

--To check duplicate in destination DB
declare @DNo int
delete #T1
exec('insert #T1(No) select No from '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader where 
CompanyID='+@CompanyID+' and PeriodID='+@PeriodID+' and VtypeId='+@VtypeId+' and No='+@No)
select @DNo=max(No) from #T1
if @DNo is not null
Begin
	select @ExportNo No,'There is already entry with No '+ cast(@DNo as varchar) + ' in Destination DB. Please Export Again' Message,null HSNo,1 Exporting	
	return
End


--Header
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader(VtypeId,No,Date,DeliveryDate,CustomerId,Address,PaymentMode,SalesManId,RateLevelId,DueDate,
	  QuotationNo,Total,DiscountP,Discount,NetTotal,Notes,TaxCalculation,Tax,SalesReturn,Rep1,Rep2,Paid,RoundOff,AirwayBillNo,CompanyId,
	  PeriodId,Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnId,CostCentreId,ShippingId,ShippingNo,ExportNo,ExportCompanyID) 
      select VtypeId,'+@No+',Date,DeliveryDate,CustomerId,Address,PaymentMode,SalesManId,RateLevelId,DueDate,QuotationNo,
      case when '+@Total+'<>0 then '+@Total+' else Total end,DiscountP,Discount,case when '+@Total+'<>0 then '+@Total+' else NetTotal end,Notes,TaxCalculation,Tax,SalesReturn,Rep1,Rep2,case when Paid>'+@Total+' then '+@Total+' else Paid end,RoundOff,AirwayBillNo,'+@CompanyID+',
      PeriodId,Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,null ReturnId,CostCentreId,ShippingId,ShippingNo,'+@ExportNo+',CompanyId from invSalesHeader WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


--Shifted to here on 20260313
if not exists(select 1 from #SalesDetails)
Begin
	select @ExportNo No,'There is no item having stock to export' Message,null HSNo,1 Exporting

	exec('update '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesHeader set Total=0,NetTotal=0
	      where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@No)

	return
End
------------

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesDetails(VtypeId,No,Sno,ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,
	   MfrDate,ExpDate,Remark,BarcodeId,TaxGroupId,Tax,Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2) 
      select VtypeId,No,row_number()over(order by sno),ProductId,WarehouseId,UomId,Qty,Foc,Rate,Gross,DiscountP,Discount,Total,MfrDate,
      ExpDate,Remark,BarcodeId,TaxGroupId,isnull(Tax,0),Addition,IType,INo,ISno,IQty,IFOC,Pieces,SerialNoId,CompanyId,PeriodId,MRP,SalesmanID,Addition2 from #SalesDetails')

exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesPropertyDetails(VtypeId,No,Sno,ProductId,SubPropertyId,CompanyId,PeriodId) 
      select VtypeId,'+@No+',Sno,ProductId,SubPropertyId,'+@CompanyID+',PeriodId from invSalesPropertyDetails WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invSalesAdditions(CompanyID,PeriodID,VtypeID,No,DebtorId,CreditorId,Description,Amount) 
      select '+@CompanyID+',PeriodID,VtypeID,'+@No+',DebtorId,CreditorId,Description,Amount from invSalesAdditions WITH (NOLOCK)
	  where CompanyId = '+@CompanyId+' and PeriodId = '+@PeriodId+' and [VtypeId] = '+@VtypeId+' and [No] = '+@ExportNo)


--Transactions
exec('insert '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.aTransaction(CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,ModuleID,
AccountID,CDate,CNo,SNo) 
      select '+@CompanyID+',PeriodID,Date,VoucherTypeID,'+@No+',DebtorID,CreditorID,Amount,t.Description,RefNo,ModuleID,AccountID,CDate,CNo,SNo from aTransaction t WITH (NOLOCK) 
	  join '+ @RmtSrvName + @RmtDBName + '.'+ @RmtDBO +'.invVoucherTypeDetails v on t.VoucherTypeID=v.AccountVTypeID 
	  where t.ModuleID=1 and v.ID='+@VtypeId+' and t.No = '+@ExportNo+' and t.CompanyID='+@CompanyID+' and t.PeriodID='+@PeriodID
	  )


go

if OBJECT_ID('prDeleteSales') is not null
	drop proc prDeleteSales
go

create proc prDeleteSales
@VtypeId int,
@No int,
@CompanyID int,
@PeriodID int,
@Date int,
@Cancel bit=null

as

set nocount on

declare @Message varchar(100)

select top 1 @Message='Have reference in Cash Collection' from invCashCollection where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No

if @Message is not null
begin
  select @Message Message
  return	
end

declare @InvoiceNo varchar(50)
if @Cancel=1 
	select @InvoiceNo=AirwayBillNo from invSalesHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No

set xact_abort on

Begin transaction
	
	if exists(select 1 from invOption where CompanyId=@CompanyId and SalesRecovery=1)
	Begin
		declare @HSNo int
		select @HSNo=isnull(max(HSNo),0)+1 from invSalesHeaderHistory where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
		exec spSaveSalesHistory @CompanyId=@CompanyId,@PeriodId=@PeriodId,@VtypeId=@VtypeId,@No=@No,@HSNo=@HSNo
	End

	--declare @VoucherTypeID int
	--select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	--delete aTransaction where ModuleID=1 and VoucherTypeID = @VoucherTypeID and [No] = @No and CompanyID=@CompanyID and PeriodID=@PeriodID

	delete t from aTransaction t 
	join invVoucherTypeDetails vd on t.VoucherTypeID=vd.AccountVtypeID
	join invSalesHeader h on t.CompanyID=h.CompanyId and t.PeriodID=h.PeriodId and vd.Id=h.VtypeId and t.No=h.No and t.Date=h.Date
	where t.ModuleID=1 and h.VtypeId = @VtypeId and h.No = @No and h.CompanyID=@CompanyID and h.PeriodID=@PeriodID

	delete invSalesHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesPropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesAdditions where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invPrivilegeCardSales where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
    delete invSalesProductSerialNumber where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesTrayDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No

	if @Cancel=1 
		insert invSalesHeader(CompanyId,PeriodId,VtypeId,No,AirwayBillNo,Sync,Date,CustomerId) values(@CompanyId,@PeriodId,@VtypeId,@No,@InvoiceNo,1,@Date,null)

Commit

select @Message Message,@HSNo HSNo

go

if object_id('prSaveSales') is not null
	drop proc prSaveSales
go

create proc prSaveSales
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int,
@Date int,
@DeliveryDate int,
@CustomerId int,
@PaymentMode tinyint,
@SalesManId int,
@RateLevelId int,
@DueDate int,
@QuotationNo int,
@Total float,
@DiscountP float,
@Discount float,
@NetTotal float,
@Notes nvarchar(4000),
@TaxCalculation int,
@Tax float,
@SalesReturn float,
@Addition float,
@XmlProductDetails xml,
@Rep1 int,
@Rep2 int,
@Paid float,
@RoundOff float,
@AirwayBillNo varchar(50),
@XmlPropertyDetails xml,
@Advance float,
@Time int,
@XmlAdditions xml,
@FooterAddition float,
@PrePrintingString varchar(50),
@FromTime int=null,
@ToTime int=null,
@JobId int,
@ReturnId int,
@CostCentreId int,
@ShippingId int,
@ShippingNo varchar(50),
@Address nvarchar(300)=null, 
@Export bit=null,
@CreditCardID int=null,
@InterState bit=null,
@CardId int = null,
@Redempted int = null,
@PaidBy tinyint=null,
@XmlProductSno xml,
@TaxGroupID int=null,
@BillTax float=null,
@Description nvarchar(100)=null,
@LocalMobileNo varchar(100) = null,
@Approve bit=null,
@UserId int = null,
@Addition2 float=null,
@TokenNo int = null,
@QRCodeImage Image=null,
@Remark1 nVarchar(500) =null,
@Remark2 nVarchar(500) =null,
@Remark3 nVarchar(500) =null,
@Remark4 nVarchar(500) =null,
@EInvoice int = null,
@XmlTray xml=null,
@NotEdit bit = null,
@Remark5 nvarchar(2000) = null ,
@Remark6 nvarchar(2000) = null ,
@Remark7 nvarchar(2000) = null ,
@Remark8 nvarchar(2000) = null ,
@Remark9 nvarchar(2000) = null ,
@Remark10 nvarchar(2000) = null ,
@Remark11 nvarchar(2000) = null ,
@Remark12 nvarchar(2000) = null ,
@Discount1 float=null,
@Discount2 float=null,
@Discount3 float=null,
@Eway bit = null


as
set nocount on
set xact_abort on

declare @Message varchar(100)
if not exists(select 1 from invOption where CompanyID=@CompanyID and SalesAllowDuplicateInvoiceNo=1) 
Begin
	if len(rtrim(@AirwayBillNo))>0
		select @Message='Invoice No Already given for Sales ' + cast(No as varchar) from invSalesHeader where CompanyID = @CompanyID and PeriodID = @PeriodID and VtypeId = @VtypeId and No <> @No and AirwayBillNo  = @AirwayBillNo 
End

if @Message is not null
Begin
	select @No No,@Message Message
	return
End

--Due Day Blocking
if (@PaymentMode>0)
Begin
	if exists(select 1 from invOption where SalesBlockByCreditLimit=1 and CompanyId=@CompanyId)
	Begin
		declare @DueDays int
		select @DueDays=DueDays from invCustomer where AccountID=@CustomerId and DueDays>0
		
		if isnull(@DueDays,0)=0
			select @DueDays=DueDays from invCostCentre where Id=@CostCentreId

		if (@DueDays>0)
		Begin
			
			if exists(select 1 from invOption where CompanyId=@CompanyId and DueCalculation=1)
			Begin
				declare @OS table(PeriodId int,Date smalldatetime,VoucherTypeID int,VType varchar(50),No int,SNo int,Account nvarchar(100),Description varchar(300),Age int,Amount varchar(50))

				if exists(select 1 from invVendor where AccountId=@CustomerID)
				Begin
					insert @OS
					exec spGetVendorOutstandingBills @CompanyId=@CompanyId,@ToDate=@Date,@VendorId=@CustomerID,@Type=2
					update @OS set Amount=cast(-1.0*cast(replace(Amount,',','') as float) as varchar) where isnumeric(Amount)=1
				End
				else
					insert @OS
					exec spGetCustomerOutstandingBills @CompanyId=@CompanyId,@ToDate=@Date,@CustomerID=@CustomerID,@Type=2

				delete @OS where isnumeric(Amount)=0
				select @Message='Due Days Over For No. ' + cast(No as varchar)+ char(10)+char(13)+'Amount - '+ Amount + char(10)+char(13) + 'Days - ' + cast(Age as varchar) from @OS where Age>@DueDays and cast(replace(Amount,',','') as float)>0
				if @Message is not null
				Begin
					select @No No,@Message Message
					return
				End
			End
			Else
			Begin
				declare @Due table(PeriodId int,Date smalldatetime,VoucherTypeID int,VType varchar(50),No int,Description varchar(300),Amount varchar(50),Age int,Balance varchar(50))
				insert @Due 
				exec spCustomersAgeing @ToDate=@Date,@AccountID=@CustomerID,@Type=3,@CompanyId=@CompanyId
				select @Message='Due Days Over For No. ' + cast(No as varchar)+ char(10)+char(13)+'Amount - '+ Amount + char(10)+char(13)+ 'Balance - '+Balance + char(10)+char(13) + 'Days - ' + cast(Age as varchar) from @Due where Age>@DueDays
				if @Message is not null
				Begin
					select @No No,@Message Message
					return
				End
			End
			
		End
	End
End

----------
declare @VoucherTypeID int
declare @Sync bit
Begin Transaction
if(@No = 0)
begin
	declare @T1 table([No] int)
	insert @T1 exec prGetSalesMaxVno @CompanyID,@PeriodID,@VtypeId
	select @No = [No] from @T1 
	--Token No
	if exists(select 1 from invOption where CompanyId=@CompanyId and TokenNo=1)
	begin
	    select  @TokenNo = isnull(max(TokenNo),0) + 1 from invSalesHeader 
        where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and [Date] = @Date 
	end
end
else
begin
	if exists(select 1 from invOption where CompanyId=@CompanyId and SalesRecovery=1)
	Begin
		declare @HSNo int
		select @HSNo=isnull(max(HSNo),0)+1 from invSalesHeaderHistory where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
		exec spSaveSalesHistory @CompanyId=@CompanyId,@PeriodId=@PeriodId,@VtypeId=@VtypeId,@No=@No,@HSNo=@HSNo
	End

	delete t from aTransaction t 
	join invVoucherTypeDetails vd on t.VoucherTypeID=vd.AccountVtypeID
	join invSalesHeader h on t.CompanyID=h.CompanyId and t.PeriodID=h.PeriodId and vd.Id=h.VtypeId and t.No=h.No and t.Date=h.Date
	where t.ModuleID=1 and h.VtypeId = @VtypeId and h.No = @No and h.CompanyID=@CompanyID and h.PeriodID=@PeriodID

	delete invSalesHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesPropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesAdditions where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invPrivilegeCardSales where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesProductSerialNumber where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesTrayDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No

	set @Sync=1
end	
  	
insert invSalesHeader([CompanyID],[PeriodID],[VtypeId],[No],[Date],[DeliveryDate],[CustomerId],[PaymentMode],
[SalesManId],[RateLevelId],[DueDate],[QuotationNo],[Total],[DiscountP],[Discount],[NetTotal],
[Notes],[TaxCalculation],[Tax],[SalesReturn],[Rep1],[Rep2],[Paid],[RoundOff],[AirwayBillNo],
Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnId,CostCentreId,ShippingId,ShippingNo,CreditCardID,
[Address],InterState,CardId,PaidBy,TaxGroupID,BillTax,LocalMobileNo,Sync,Approve,UserId,TokenNo,QRCodeImage,Remark1,Remark2,
Remark3,Remark4,EInvoice,NotEdit,[Remark5],[Remark6],[Remark7],[Remark8],[Remark9],[Remark10],[Remark11],[Remark12],Discount1,
Discount2,Discount3,EWay)
values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@DeliveryDate,@CustomerId,@PaymentMode,nullif(@SalesManId,0),@RateLevelId,@DueDate,@QuotationNo,
@Total,@DiscountP,@Discount,@NetTotal,@Notes,@TaxCalculation,@Tax,@SalesReturn,nullif(@Rep1,0),nullif(@Rep2,0),
nullif(@Paid,0),nullif(@RoundOff,0),nullif(@AirwayBillNo,''),nullif(@Advance,0),@Time,nullif(@FooterAddition,0),
nullif(@PrePrintingString,''),nullif(@FromTime,0),nullif(@ToTime,0),nullif(@JobId,0),nullif(@ReturnId,0),nullif(@CostCentreId,0),
nullif(@ShippingId,0),nullif(@ShippingNo,''),nullif(@CreditCardID,0),nullif(rtrim(@Address),''),nullif(@InterState,0),nullif(@CardId,0),nullif(@PaidBy,0),
nullif(@TaxGroupID,0),nullif(@BillTax,0),nullif(@LocalMobileNo,''),@Sync,nullif(@Approve,0),nullif(@UserId,0),nullif(@TokenNo,0),@QRCodeImage,
@Remark1,@Remark2,@Remark3,@Remark4,nullif(@EInvoice,0),nullif(@NotEdit,0),NULLIF(@Remark5,''),NULLIF(@Remark6,''),NULLIF(@Remark7,''),NULLIF(@Remark8,''),NULLIF(@Remark9,''),
NULLIF(@Remark10,''),NULLIF(@Remark11,''),NULLIF(@Remark12,''),nullif(@Discount1,0),nullif(@Discount2,0),nullif(@Discount3,0),@Eway)


--Details Part
declare @Details table(Sno int,ProductId int,SalesmanId int,WarehouseId int,UomId int,Qty float,Foc float,FType int,Pieces float,Rate float,MRP float,Gross float,
					   Addition float,TaxGroupId int,Tax float,DiscountP float,Discount float,Total float,MfrDate int,ExpDate int,Remark nvarchar(1000),BarcodeId int,
					   IType int,IPeriodId int,INo int,ISno int,IQty float,IFOC float,SerialNoId int,ARate float,Length float,Width float,Addition1 float,Addition2 float,Cost float,Remark1 nvarchar(100))

declare @Idoc int
exec sp_xml_preparedocument @Idoc out,@XmlProductDetails

insert @Details
([Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1)
select [Sno],[ProductId],nullif([WarehouseId],0),isnull(nullif([UomId],0),1),[Qty],[Foc],nullif([Pieces],0)[Pieces],
[Rate],MRP,[Gross],nullif(Addition,0) Addition,nullif([TaxGroupId],0),[Tax],[DiscountP],
[Discount],[Total],
case when @Date<>convert(varchar,[MfrDate],112) then convert(varchar,[MfrDate],112) end,
case when @Date<>convert(varchar,[ExpDate],112) then convert(varchar,[ExpDate],112) end,
nullif([Remark],'') [Remark],isnull([BarcodeId],0),nullif([IType],0) [IType],nullif(IPeriodId,0),nullif([INo],0) [INo],
case when IType>0 then isnull(ISno,0) end,nullif([IQty],0) [IQTy], nullif([IFOC],0) [IFOC],nullif([SerialNoId],0) SerialNoId,nullif(SalesmanId,0),
case when [Foc] = 0 then null else [FType] end,nullif(case when Rate<>ARate then ARate end,0),nullif(Length,0),nullif(Width,0),nullif(Addition1,0),nullif(Addition2,0),nullif(Cost,0),nullif(Remark1,'')
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
ProductId      int '@ProductId',
SalesmanId     int '@SalesmanId',
WarehouseId    int '@WarehouseId',
UomId          int '@UomId',
Qty            float '@Qty',
Foc            float '@Foc',
FType          int   '@FType',
Pieces         float '@Pieces',
Rate           float '@Rate',
MRP            float '@MRP',
Gross          float '@Gross',
Addition       float '@Addition', 
TaxGroupId     int '@TaxGroupId',
Tax            float '@Tax',
DiscountP      float '@DiscountP',
Discount       float '@Discount',
Total          float '@Total',
MfrDate        datetime '@MfrDate',
ExpDate        datetime '@ExpDate',
Remark         nvarchar(1000) '@Remark',
BarcodeId      int '@BarcodeId',
IType		   int '@IType',
IPeriodId	   int '@IPeriodId',
INo		       int '@INo',
ISno		   int '@ISno',
IQty		   float '@IQty',
IFOC           float '@IFOC',
SerialNoId     int '@SerialNoId',
ARate          float '@ARate' ,
Length         float '@Length' ,
Width          float '@Width' ,
Addition1      float '@Addition1',
Addition2      float '@Addition2',
Cost           float '@Cost',
Remark1         nvarchar(100) '@Remark1'
)
where ProductId>0

declare @CGSAccountId int
select @CGSAccountId=CostOfGoodsSoldAccountId from invOption where CompanyID = @CompanyID
if @CGSAccountId>0
Begin
	declare @Stock table(CompanyId int,ProductId int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float)
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	update invSalesHeader set BlockStockCalculation=1 where Date=@Date and Time>@Time
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	declare @BeforeCostofGoods float
	select @BeforeCostofGoods=sum(Qty*Rate) from @Stock
End

insert invSalesDetails([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1)
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],nullif([WarehouseId],0),[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1
from @Details

exec sp_xml_removedocument @Idoc


if @CGSAccountId>0
Begin
	delete @Stock
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	update invSalesHeader set BlockStockCalculation=null where Date=@Date and Time>@Time
	declare @AfterCostofGoods float
	select @AfterCostofGoods=sum(Qty*Rate) from @Stock
End

----------------

if isnull(@CardId,0) >0
begin
  declare @PointAccumulationAmount float
  select @PointAccumulationAmount = t2.PointAccumulationAmount from invPrivilegeCardIssue t1
  join invPrivilegeCard t2 on t1.CardId = t2.Id 
  where t1.Id = @CardId

  declare @LessProfitAmount float
  select @LessProfitAmount=sum(Total) from @Details d join invProduct p on d.ProductId=p.Id where p.LessProfit=1

  insert invPrivilegeCardSales([CompanyID],[PeriodID],[VtypeId],[No],CardId,BillAmount,Points,Redempted)
  select @CompanyID,@PeriodID,@VtypeId,@No,@CardId,@NetTotal,(@NetTotal-isnull(@LessProfitAmount,0))/@PointAccumulationAmount,@Redempted
  where isnull(@PointAccumulationAmount,0) > 0
end 


--Property

exec sp_xml_preparedocument @Idoc out,@XmlPropertyDetails
insert invSalesPropertyDetails(CompanyID,PeriodID,[VtypeId],[No],[Sno],[ProductId],[SubPropertyId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno int '@Sno',
ProductId int '@ProductId',
SubPropertyId int '@SubPropertyId'
)

exec sp_xml_removedocument @Idoc
--Additions
	declare @SalesAdditions table(CreditorID int,DebtorID int,Description varchar(100),Amount float)
	exec sp_xml_preparedocument @Idoc out,@XmlAdditions
	insert @SalesAdditions(CreditorID,DebtorID,Description,Amount)
	select CreditorID,DebtorID,nullif(Description,''),Amount from openxml (@Idoc,'/TableHeader/Table1',2)
	with
	(
	CreditorID  int '@CreditorID',
	DebtorID    int '@DebtorID',
	Description varchar(100) '@Description',
	Amount      float '@Amount'
	)
	where Amount>0
	exec sp_xml_removedocument @Idoc

	insert invSalesAdditions(CompanyId,PeriodId,VtypeId,No,CreditorID,DebtorID,Description,Amount)
	select @CompanyId,@PeriodId,@VtypeId,@No,CreditorID,DebtorID,Description,Amount from @SalesAdditions

 --Sales Product Serial Number (Bulk Saving)
 exec sp_xml_preparedocument @Idoc out,@XmlProductSno  
 insert invSalesProductSerialNumber([CompanyId],[PeriodId],[VtypeId],[No],[USno],[Sno],[ProductId],[SerialNoId],SerialNo)  
 select @CompanyId,@PeriodId,@VtypeId,@No,[USno],[Sno],[ProductId],nullif([Id],0),case when Id=0 then SerialNo end from openxml (@Idoc,'/TableHeader/Table1',2)  
 with  
 (  
 USno int '@USno',  
 Sno int '@Sno',  
 ProductId int '@ProductId',
 Id int '@Id',
 SerialNo varchar(100) '@SerialNo'
 )  
 exec sp_xml_removedocument @Idoc  

  
-- Tray Details
 
 exec sp_xml_preparedocument @Idoc out,@XmlTray  
 insert invSalesTrayDetails([CompanyId],[PeriodId],[VtypeId],[No],ProductID,OB,[In],[Out],Balance)  
 select @CompanyId,@PeriodId,@VtypeId,@No,ProductID,[OB],[In],[Out],Balance  from openxml (@Idoc,'/TableHeader/Table1',2)  
 with  
 (  
 ProductID int '@ProductID',
 [OB] int '@OB', 
 [In] int '@In',  
 [Out] int '@Out',   
 Balance int '@Balance'
  
 )  
 exec sp_xml_removedocument @Idoc  


--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and CompanyId=@CompanyId) 
   and exists(select 1 from invProjectSettings where isnull(DisablePostingInSales,0)=0 and CompanyId=@CompanyId)
   and isnull(@EInvoice,0) not in(2,4)
Begin
	if @PaymentMode=0  and isnull(@PaidBy,0)=0
		set @Paid=0
	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	declare @SalesAccountID int,
	        @DiscountAccountID int,
	        @CashInHandID int,
	        @SalesRoundOffAccount int,
			@CreditCard int,
			@AdditionAccountID int,
			@PurchaseAccountID int,
			@CommissionAccountID int
	
	
	select @SalesRoundOffAccount = SalesRoundOffAccount,@AdditionAccountID=AdditionAccount,@CashInHandID=nullif(SalesCashAccountId,0) from invOption where CompanyID = @CompanyID        
	select @SalesAccountID=Sales,@DiscountAccountID=DiscountPaid,@CashInHandID=isnull(@CashInHandID,CashInHand),@CreditCard=CreditCard,@PurchaseAccountID=Purchase,@CommissionAccountID=Commission from aAccountSettings where CompanyID=@CompanyID
	select @CreditCard=AccountId from aCreditCard where Id=@CreditCardId and AccountId>0
	select @CostCentreId=CostCentreId from invCostCentre where Id=@CostCentreId
	select @CostCentreId=nullif(@CostCentreId,0)

	select @CashInHandID=AccountID from invSalesman where Id=@SalesManId and AccountID>0

	--Footer Addition
	declare @FooterAdditionToPost float
	if not exists(select top 1 1 from @SalesAdditions) and @FooterAddition<>0
	Begin
		set @FooterAdditionToPost=@FooterAddition
	End

	declare @PNetTotal float
	select @PNetTotal=@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+ isnull(@FooterAdditionToPost,0) - isnull(@SalesReturn,0) + isnull(@BillTax,0)
	--select @PNetTotal=@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+ isnull(@FooterAdditionToPost,0) + isnull(@BillTax,0)
	if @PaymentMode=0 --Cash
	Begin
		--Paid
		if @Paid>0
		Begin
			if @PNetTotal<>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@SalesAccountID,@PNetTotal-isnull(@Advance,0)-isnull(@Paid,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Payment In Sales',@CostCentreId) 

		End
		Else
		Begin
			if @PNetTotal<>0
				--Net Total
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@SalesAccountID,@PNetTotal-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 
		End

		if @Advance>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,@SalesAccountID,@Advance,'Advance Adjustment',@CostCentreId) 
	End

	if @PaymentMode in(1,2) --Credit
	Begin
		--Paid
		if @Paid>0
		Begin
			if exists(select 1 from invOption where CompanyID=@CompanyID and SalesPostPaidSeparately=1)
			Begin
				if @PNetTotal<>0
					insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
					values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal,'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo,CostCentreId,CreditCardID)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@CustomerId,@Paid,'Payment In Sales',1,@CostCentreId,nullif(case when @PaidBy=1 then @CreditCardID end,0)) 	
			End
			Else
			Begin
				if (@PNetTotal-isnull(@Paid,0))<>0
					insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
					values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal-isnull(@Paid,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo,CostCentreId,CreditCardID)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Payment In Sales',1,@CostCentreId,nullif(case when @PaidBy=1 then @CreditCardID end,0)) 
			End
		End
		Else
		Begin
			--if @PNetTotal<>0
				--Net Total
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal,'Sales '+ substring(@Notes,1,90) + @AirwayBillNo+isnull(' '+@Description,''),@CostCentreId) 
		End
	End
	if @PaymentMode=3 --Credit Card
	Begin
		--Paid
		if @Paid>0
		Begin
			if (@PNetTotal-@Paid>0)
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditCard,@SalesAccountID,@PNetTotal-@Paid-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,nullif(@CreditCardID,0),@CostCentreId) 

			if (@Paid>@PNetTotal)
				set @Paid=@PNetTotal

			if @Paid>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Sales',@CostCentreId) 
		End
		Else
			--Net Total
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditCard,@SalesAccountID,@PNetTotal-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,nullif(@CreditCardID,0),@CostCentreId) 


		if @Advance>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,@SalesAccountID,@Advance,'Advance Adjustment',@CostCentreId) 
	End
	--Discount
	if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DiscountAccountID,@SalesAccountID,@Discount,'Sales Discount',@CostCentreId) 
	--Tax
	if @Tax>0
	Begin
		declare  @TaxAccountID int
		select @TaxAccountID=OutPutTaxAccount from invOption
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@TaxAccountID,@Tax,'Sales Tax',@CostCentreId) 
	End

	--Bill Tax
	if @BillTax>0
	Begin
		select @TaxAccountID=OutPutTaxAccount from invOption
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@TaxAccountID,@BillTax,'Sales Tax',@CostCentreId) 
	End

	--Addition
	if @Addition>0
	Begin
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,isnull(@AdditionAccountID,0),@Addition,'Addition In Sales',@CostCentreId) 
	End
	
	--Addition2
	if @Addition2>0
	Begin
		select @AdditionAccountID=isnull(SalesAddition2AccountId,@AdditionAccountID) from invOption where CompanyId=@CompanyId
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,isnull(@AdditionAccountID,0),@Addition2,@CostCentreId) 
	End

	--Footer Addition
	if @FooterAdditionToPost<>0
	Begin
        declare @SalesAdditionAccount int
		select @SalesAdditionAccount=SalesAdditionAccount from invOption where CompanyId=@CompanyId
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@SalesAdditionAccount,@FooterAdditionToPost,@CostCentreId) 
	End

	--Round off
	if ISNULL(@SalesRoundOffAccount,0) >  0 and @RoundOff <> 0
	begin
		if @RoundOff > 0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@SalesRoundOffAccount,@RoundOff,@CostCentreId) 
		else 
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		    values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesRoundOffAccount,@SalesAccountID,abs(@RoundOff),@CostCentreId) 	
	end

	--Additions
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,1,DebtorID,CreditorID,Amount,Description,@CostCentreId from @SalesAdditions


	--Product Account
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,p.AccountId,sum(d.Gross),p.Name,@CostCentreId from @Details d join invProduct p on d.ProductId=p.Id where p.AccountId is not null group by p.AccountId,p.Name

	--Salesman Commission
	if @SalesmanID>0 and @CommissionAccountID>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CommissionAccountID,s.AccountID1,@NetTotal*s.Commission/100.0,'Salesman Commission',@CostCentreId from invSalesMan s 
		where s.Id=@SalesmanId and s.AccountID1>0 and s.Commission<>0

	if @CGSAccountId>0
	Begin
		--Cost Of Goods Sold
		declare @Cost float
		set @Cost = isnull(@BeforeCostofGoods,0)-isnull(@AfterCostofGoods,0)

		if @Cost<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
			select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CGSAccountId,@PurchaseAccountId,@Cost,'Sales',@CostCentreId --from @CGS --having sum(CP)<>0
	End
End

if @JobId >0 and (select isnull(Status,0) from invJobCustomization) =  0	
	update InvJobForm Set Status=1 where ID=@JobId
Commit

if @Export=1
	exec prExportSales @CompanyID=@CompanyID,@PeriodID=@PeriodID,@VtypeID=@VtypeID,@ExportNo=@No

select @No No,@Message Message,@HSNo HSNo

go

if object_id('spGetInvSalesHeader') is not null
	drop proc spGetInvSalesHeader
go

create proc spGetInvSalesHeader      
@CompanyID int,      
@PeriodID int,      
@VtypeID int,      
@No int      
as      
set nocount on   
set transaction isolation level read uncommitted

declare @Table table(CustomerID int,Code nvarchar(50),Customer nvarchar(100),Under nvarchar(100),VType varchar(50),No int,Date smalldatetime,
Amount float,Notes nvarchar(500),SalesReturn float,AirWayBillNo varchar(50),PaymentMode tinyint,VtypeDetails varchar(50),QuotationNo int,
Rep1 varchar(100),Rep2 varchar(100),DeliveryDate smalldatetime,Discount float,Total float,SalesMan nvarchar(50),Address1 nvarchar(100),
Address2 nvarchar(100),Address3 nvarchar(100),Place nvarchar(100),Phone nVarchar(50),MobileNo nVarchar(50),Email nVarchar(100),Location varchar(500),
ContactPerson nvarchar(100),PaymentTerms nvarchar(100),RoundOff float,Advance float,Tax float,Paid float,TIN nVarchar(100),CST nVarchar(100),
DLNo1 nVarchar(100),DLNo2 nVarchar(100),PrePrintingString  nVarchar(100),Time int,DiscountP float,Company varchar(50),Property1 varchar(100),
Addition float,GST nVarchar(100),Address nvarchar(300),TaxP float,BillTax float,CustomerInOL nvarchar(100),ReturnID int,RateLevel varchar(50),
UserName varchar(100),CardNo varchar(25),CardID int,Points float,Redempted float,DueDate datetime,TokenNo int,CostCentre nvarchar(50),
QRCodeImage Image,PeriodCode varchar(50),PeriodName varchar(50),ShippingNo varchar(50),Remark1 nVarchar(2000),Remark2 nVarchar(2000),Remark3 nVarchar(2000),Remark4 nVarchar(2000),
Address4 nvarchar(100),Address5 nvarchar(100),Address6 nvarchar(100),Address7 nvarchar(100),Address8 nvarchar(100),Address9 nvarchar(100),AName nvarchar(100)
,InvoiceFormat nvarchar(100),SalesManCode nvarchar(50),SRVtypeId int,SRNo int,PiadBy int,CreditCardID int,CreditCard nVarchar(50),Discount1 float,Discount2 float,Discount3 float,LocalMobileNo varchar(100))  

insert @Table(CustomerID,Code,Under,VType,No,Date,Amount,Notes,SalesReturn,AirWayBillNo,PaymentMode,VtypeDetails,QuotationNo,DeliveryDate,
Discount,Total,SalesMan,RoundOff,Advance,Tax,Paid,PrePrintingString,Time,DiscountP,Company,Addition,Address,TaxP,BillTax,CustomerInOL,ReturnID,
RateLevel,UserName,CardID,DueDate,TokenNo,CostCentre,QRCodeImage,PeriodCode,PeriodName,ShippingNo,Remark1,Remark2,Remark3,Remark4,AName,SRVtypeId,
SRNo,PiadBy,CreditCardID,Discount1,Discount2,Discount3,LocalMobileNo)  

select s.CustomerID,a.Code,u.Name,v.Code,s.No,cast(cast(s.Date as varchar)as smalldatetime),s.NetTotal,s.Notes,s.SalesReturn,s.AirWayBillNo,
s.PaymentMode,v.Description,QuotationNo,cast(cast(nullif(s.DeliveryDate,0) as varchar)as smalldatetime)DeliveryDate,s.Discount,s.Total,s.SalesManID,
s.RoundOff,s.Advance,s.Tax,s.Paid,s.PrePrintingString,s.Time,s.DiscountP,co.Name Company,s.Addition,s.Address,s.TaxGroupID,s.BillTax,a.NameInOL,
s.ReturnID,s.RateLevelID,usr.name,pc.CardId,cast(cast(nullif(s.duedate,0) as varchar) as datetime),s.TokenNo,s.CostCentreId,s.QRCodeImage,
p.Code,p.Name,s.ShippingNo,Remark1,Remark2,Remark3,Remark4,a.Name,sr.VtypeId,sr.No,s.PaidBy,s.CreditCardID,s.Discount1,s.Discount2,s.Discount3,s.LocalMobileNo from invSalesHeader s      
join invVoucherTypeDetails v on s.VtypeID=v.ID      
join aAccount a on s.CustomerID=a.ID  
join aAccount u on a.UnderAccountID=u.ID  
join aCompany co on s.CompanyID=co.ID  
join aPeriod p on s.PeriodId=p.Id
left outer join invUser usr on s.userid = usr.id
left outer join invPrivilegeCardSales pc on pc.CompanyId=s.CompanyId and pc.PeriodId=s.PeriodId and pc.VtypeId=s.VtypeID and pc.No=s.No
left outer join invSalesReturnHeader sr on s.ReturnId=sr.Id
where s.CompanyID=@CompanyID and s.PeriodID=@PeriodID and s.VtypeId=@VtypeID and s.No=@No      


--Customer
update t set t.Customer=c.Name,t.Address1=c.Address1,t.Address2=c.Address2,t.Address3=c.Address3,t.Address4=c.Address4,t.Address5=c.Address5,t.Address6=c.Address6,t.Address7=c.Address7,t.Place=c.Place,t.Phone=c.Phone,t.Address8=c.Address8,t.Address9=c.Address9,
t.MobileNo=c.MobileNo,t.EMail=c.EMail,t.Location=c.Location,t.ContactPerson=c.ContactPerson,t.PaymentTerms=c.PaymentTerms,t.DLNo1=c.DLNo1,
t.DLNo2=c.DLNo2,t.TIN=c.TIN,t.GST=c.GST,t.CST=c.CST from invCustomer c join @Table t on c.AccountID=t.CustomerID

--Vendor
update t set t.Customer=c.Name,t.Address1=c.Address1,t.Address2=c.Address2,t.Address3=c.Address3,t.Phone=c.Phone,t.MobileNo=c.MobileNo,
t.EMail=c.EMail,t.Location=c.Fax,t.ContactPerson=c.ContactPerson,t.PaymentTerms=c.PaymentTerms,t.DLNo1=c.DLNo1,t.DLNo2=c.DLNo2,t.GST=c.GST,
t.TIN=c.TIN from invVendor c join @Table t on c.AccountID=t.CustomerID where t.Customer is null
 

--Rep1  
update t set t.Rep1=r.Name from invRep1 r join @Table t on r.ID=t.Rep1   
--Rep2  
update t set t.Rep2=r.Name from invRep2 r join @Table t on r.ID=t.Rep2  
--Salesman  
update t set t.Salesman=s.Name,t.SalesmanCode=s.Code from invSalesMan s join @Table t on s.ID=t.SalesMan  
--Property1  
update t set t.Property1=s.Name from @Table t join invAccountPropertyDetails pd on t.CustomerID=pd.AccountID join invAccountSubProperty s on pd.SubPropertyID=s.ID  
where pd.PropertyID=1  
--TaxP
update t set t.TaxP=tg.OutPutTax from invTaxGroup tg join @Table t on tg.ID=t.TaxP
--Rate Level
update t set t.RateLevel=r.Name from invRateLevel r join @Table t on r.ID=t.RateLevel
--Rate Level
update t set t.CostCentre=c.Name from invCostCentre c join @Table t on c.ID=t.CostCentre
--CreditCard
update t set t.CreditCard=c.Name from  aCreditCard c join @Table t on c.ID=t.CreditCardID

  
--Privilege Card
declare @PC Table (CardID int ,CardNo Varchar(50),Points float,Redempted float)
insert @PC
select i.id,i.CardNo, Sum(pc.Points),SUM(pc.Redempted) from invPrivilegeCardSales pc join invPrivilegeCardIssue i on pc.CardID=i.ID
join @Table t on pc.CardId =t.CardID  
group by i.id,i.CardNo
update t set t.CardNo=pc.CardNo,t.Points=pc.Points,t.Redempted=pc.Redempted from @PC pc join @Table t on pc.CardId =t.CardID  
-------------

--Invoice Format
update t set t.InvoiceFormat=v.InvoiceFormat from @Table t join invVoucherTypeStartNo v on v.CompanyId=@CompanyID and v.PeriodId=@PeriodID and v.VtypeId=@VtypeID 

select * from @Table  

go

if OBJECT_ID('prGetCostAndSalesUom') is not null 
	drop proc prGetCostAndSalesUom 
go

create proc prGetCostAndSalesUom 
@Id int,
@CustomerID int,
@RateLevelId int,
@BarcodeId int,
@CompanyID int=1,
@Date int=0

as

set nocount on
set transaction isolation level read uncommitted

declare @ProductDetails table(SalesUOM int,Rate float,WRate float,UOM nvarchar(100),Mrp float,NOP float,TaxInclusive bit,Cost float,Addition float,TAddition float,TaxGroupId int,BaseUOM int)
declare @SalesUOM int

insert @ProductDetails(SalesUOM,Rate,WRate,UOM,Mrp,NOP,TaxInclusive,Cost,Addition,TaxGroupId,BaseUOM)
select isnull(t1.SalesUom,t1.BaseUOM)SalesUom,isnull(nullif(t2.Rate,0),t1.Rate),t1.WRate,t3.Name Uom,isnull(t2.MRP,t1.MRP),isnull(n.Multiplayer,1),t1.TaxInclusive,isnull(t2.Cost,t1.Cost),t1.Addition,t1.TaxGroupId,t1.BaseUOM from invProduct t1
join invUom t3 on isnull(t1.SalesUom,t1.BaseUOM) = t3.Id 
left join invUomLevels t2 on t1.Id = t2.ProductId and t1.SalesUom = t2.UomId 
left join invUomLevels n on t1.Id = n.ProductId and n.Secondary<>1 and n.SNo<3
where t1.Id = @Id


--Getting Customer Last Rates
declare @Rate float
declare @Mrp float
declare @DiscountP float
declare @WRate float


--Getting Set Rate
if @Date=0
	select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)

declare @InterCompanyRateSettings bit
select @InterCompanyRateSettings=InterCompanyRateSettings from invOption where CompanyId=@CompanyId

select @Rate=s.Rate,@DiscountP=s.DiscountPercent from invQtyRateSettingsDetails s 
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
join @ProductDetails pd on s.ProductID=@ID and s.UOMID=pd.SalesUOM
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
and (s.CompanyId=@CompanyID or @InterCompanyRateSettings=1)
and @Time between h.FromTime and h.ToTime
order by h.FromDate


if @Rate is not null
Begin
	select SalesUOM,isnull(@Rate,Rate)Rate,WRate,UOM,isnull(@Mrp,Mrp) Mrp,NOP,@DiscountP DiscountP,Cost,Addition from @ProductDetails
	return
End

--Getting Customer Set Rate
--Drilling for Over Accounts,
declare @UnderAccountID int
select @UnderAccountID=@CustomerID
select @Rate=Rate from invCustomerRate where CustomerID=@UnderAccountID and ProductID=@Id
while @Rate is null and isnull(@UnderAccountID,0)>0
begin
	select @UnderAccountID=max(UnderAccountID) from aAccount where ID=@UnderAccountID and ID<>UnderAccountID
	select @Rate=Rate from invCustomerRate where CustomerID=@UnderAccountID and ProductID=@Id
end


if @Rate is not null
Begin
	select SalesUOM,isnull(@Rate,Rate)Rate,WRate,UOM,isnull(@Mrp,Mrp) Mrp,NOP,@DiscountP DiscountP,Cost,Addition from @ProductDetails
	return
End


--Zero Sales Rate
if exists(select 1 from invOption where SalesRate = 0 and CompanyID=@CompanyID)
begin 
	select SalesUOM,0 Rate,UOM,Mrp,NOP,Addition,Cost from @ProductDetails
	return
end


--Product Master Rate
if exists(select 1 from invOption where SalesRate = 3 and CompanyID=@CompanyID)
begin 
	if (@RateLevelID>0)
	Begin
		update p set p.Rate=r.Rate from @ProductDetails p join invBarcode r on r.ProductID=@ID and p.SalesUOM=r.UOMID and LevelId=@RateLevelID
		update p set p.Rate=p.WRate from @ProductDetails p join invRateLevel r on r.Rate=3 where r.ID=@RateLevelID and p.WRate>0 and p.SalesUOM=p.BaseUOM
		update p set p.Rate=p.MRP from @ProductDetails p join invRateLevel r on r.Rate=2 where r.ID=@RateLevelID and p.MRP>0
		update p set p.Rate=p.MRP*(100.0+r.Percentage)/100.0 from @ProductDetails p join invRateLevel r on r.Rate=0 and r.PercentageOf=2 where r.ID=@RateLevelID and p.MRP>0 and r.Percentage<>0
		update p set p.Rate=p.Rate*(100.0+r.Percentage)/100.0 from @ProductDetails p join invRateLevel r on r.Rate=0 and r.PercentageOf=1 where r.ID=@RateLevelID and p.Rate>0 and r.Percentage<>0
	End	
	
	select SalesUOM,Rate,WRate,UOM,Mrp,NOP,Addition,Cost from @ProductDetails

	return
end

select @SalesUOM = SalesUOM from @ProductDetails 

declare @DRate table(Date int,Rate float,DiscountP float,MRP float,WRate float)

declare @DefaultCustomerId int
declare @SalesRate int
select @DefaultCustomerId=isnull(DefaultCustomer,0),@SalesRate=SalesRate from invOption where CompanyID=@CompanyID

if @CustomerID>0 and @CustomerID<>@DefaultCustomerId and (@SalesRate = 2 or @SalesRate = 4) and ISNULL(@RateLevelId,0) = 0 
Begin
	
	declare @TaxOption int
	select @TaxOption=TaxOption from invOption where CompanyID=@CompanyID

	if @TaxOption=2
		select @TaxOption=TaxInclusive from @ProductDetails
	
	--Getting Customer Last Rate
	insert @DRate(Date,Rate,DiscountP)
	select top 1 sh.Date,case when @TaxOption=1 then sd.Total/sd.Qty*100/(100-sd.DiscountP) else sd.Rate end,sd.DiscountP from invSalesDetails sd 
	join invSalesHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
	where sd.ProductID=@ID and sh.CustomerID=@CustomerID and sd.CompanyID=@CompanyID and sd.UomId=@SalesUOM 
	order by sh.Date desc,sh.No desc

	if exists(select 1 from invOption where SalesRate = 4)
		insert @DRate(Date,Rate)
		select top 1 sh.Date,sd.SRate from invPurchaseDetails sd
		join invPurchaseHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
		where sd.ProductId = @Id and sd.UomId = @SalesUOM and sd.SRate > 0 and sd.CompanyID=@CompanyID 
		order by sh.Date desc,sh.No desc
	

	insert @DRate(Date,Rate,WRate,MRP)	
	select top 1 h.FromDate,s.Rate,s.WRate,s.MRP from invQtyRateSettingsDetails s 
	join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
	join @ProductDetails pd on s.ProductID=@ID and s.UOMID=pd.SalesUOM
	where @Date>=h.FromDate and h.ToDate is null and s.LQty is null and s.UQty is null and (s.CompanyId=@CompanyID or @InterCompanyRateSettings=1)
	order by h.FromDate desc,h.No desc

	select top 1 @Rate=Rate from @DRate order by Date desc
	select @DiscountP=max(DiscountP) from @DRate
	
End
else if isnull(@RateLevelId,0) > 0 
        and exists (select 1 from invRateLevel where ID=@RateLevelId and PercentageOf is null) --Based on PRate
		and @BarcodeId>0
Begin
	--if @BarcodeId = 0
	--Begin
	--	select top 1 @Rate = t1.Rate from invPurchaseUomDetails t1 		
	--	join @ProductDetails t3 on t1.ProductId = @Id and t1.UomId = t3.SalesUOM 
	--	where t1.LevelId = @RateLevelId and t1.Rate > 0 and t1.CompanyID=@CompanyID 
	--	order by t1.PeriodID desc,t1.No desc

	--	if @Rate is null
	--		select top 1 @Rate = case r.Rate when 2 then isnull(t1.MRP,t1.SRate) when 3 then isnull(isnull(t1.WRate,t3.WRate),t1.SRate) else t1.SRate end from invPurchaseDetails t1 		
	--		join @ProductDetails t3 on t1.ProductId = @Id --and t1.UomId = t3.SalesUOM 
	--		join invRateLevel r on r.ID=@RateLevelId
	--		where case when r.Rate=2 and t1.MRP is not null then t1.MRP else t1.SRate end > 0
	--		and t1.CompanyID=@CompanyID 
	--		order by t1.PeriodID desc,t1.No desc
		
	--	if @Rate is null
	--		select top 1 @Rate = case when r.Rate=2 and t1.MRP is not null then t1.MRP else (case when r.Rate=1 then t1.SalesRate end) end from invOpeningStock t1 		
	--		join @ProductDetails t3 on t1.ProductId = @Id and t1.UomId = t3.SalesUOM 
	--		join invRateLevel r on r.ID=@RateLevelId
	--		where case when r.Rate=2 and t1.MRP is not null then t1.MRP else t1.SalesRate end > 0
	--		and t1.CompanyID=@CompanyID 
	--		order by t1.PeriodID desc,t1.No desc
		
		
	--End			
	--else
	--Begin
		select top 1 @Rate = t1.Rate from invPurchaseUomDetails t1 		
		join invPurchaseHeader t2 on t1.companyid = t2.companyid and t1.PeriodId = t2.PeriodId and t1.VtypeId = t2.VtypeId and t1.[No] = t2.[No]
		join INVAUTOBARCODEANDSALESRATE t3 on t1.companyid = t3.companyid and t1.PeriodId = t3.PeriodId and t1.VtypeId = t3.VtypeId and t1.[No] = t3.[No] and t1.Sno = t3.Sno
        join @ProductDetails t4 on t1.ProductId = @Id and t1.UomId = t4.SalesUOM 
		where t1.LevelId = @RateLevelId and t3.BarcodeId = @BarcodeId and t1.Rate > 0 and t1.CompanyID=@CompanyID

		if @Rate is null
			select top 1 @Rate = case when r.Rate=2 and s.MRP is not null then s.MRP else s.SRate end from INVAUTOBARCODEANDSALESRATE s
			join invRateLevel r on r.ID=@RateLevelId
			where ProductId = @Id and BarcodeId = @BarcodeId and SRate > 0 and s.CompanyID=@CompanyID
			
	--End
		
	if @Rate is null
		select @Rate = t1.Rate from invBarcode t1 		
		join @ProductDetails t2 on t1.ProductId = @Id and t1.UomId = t2.SalesUOM 
		where t1.LevelId = @RateLevelId 
			
	if @Rate is null
			select top 1 @Rate = case r.Rate when 2 then s.MRP when 3 then s.WRate end from @ProductDetails s
			join invRateLevel r on r.ID=@RateLevelId
			where s.Rate > 0
			
end
else ---- Last Rate
begin 
	insert @DRate(Date,Rate,MRP)
	select top 1 t2.Date,t1.SRate,t1.Mrp from invPackingDetails t1 
	join invPackingHeader t2 on t1.CompanyId=t2.CompanyId and t1.PeriodId=t2.PeriodId and t1.No=t2.No		
	where t1.CompanyID=@CompanyID and t1.ProductId = @Id and t1.UomId = @SalesUOM and t1.SRate > 0 
	order by t2.Date desc,t1.No desc


	if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
		insert @DRate(Date,Rate,WRate)
		select top 1 ph.Date,pd.SRate,pd.WRate from invCompanyTransferDetails pd 		
		join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where ph.CompanyTo=@CompanyID and pd.ProductId = @Id and pd.UomId = @SalesUOM and pd.SRate > 0 
		order by ph.Date desc,pd.No desc
	

	insert @DRate(Date,Rate,MRP,WRate)
	select top 1 ph.Date,pd.SRate,pd.Mrp,pd.WRate from invPurchaseDetails pd 		
	join invPurchaseHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and pd.ProductId = @Id and pd.SRate > 0 
	order by ph.Date desc,pd.No desc
	
	insert @DRate(Date,Rate)
	select top 1 ph.Date,pd.Rate from invPurchaseUomDetails pd 		
	join invPurchaseHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.VtypeId=ph.VtypeId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and pd.ProductId = @Id and pd.UomId = @SalesUOM and pd.Rate > 0 
	order by ph.Date desc,pd.No desc
    
	    
	insert @DRate(Date,Rate,MRP)
    select Date,SRate,MRP from invProductionHeader 
	where CompanyID=@CompanyID and ProductId = @Id and SRate > 0 
	order by Date desc,[No] desc

	if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
		insert @DRate(Date,Rate)
		select top 1 ph.Date,SRate from invStockAdjustmentDetails pd
		join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
		where pd.CompanyID=@CompanyID and pd.ProductId = @Id and pd.UomId = @SalesUOM and pd.SRate > 0 
		order by ph.Date desc,ph.[No] desc

	insert @DRate(Rate,MRP,WRate)
	select top 1 SalesRate,MRP,WRate from invOpeningStock 
	where CompanyID=@CompanyID and ProductId = @Id and UomId = @SalesUOM and SalesRate > 0 order by [No] desc	

	insert @DRate(Date,Rate)
	select top 1 ph.Date,SRate from invGoodsReceiptDetails pd
	join invGoodsReceiptHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
	where pd.CompanyID=@CompanyID and pd.ProductId = @Id and pd.UomId = @SalesUOM and pd.SRate > 0 
	order by ph.Date desc,ph.[No] desc

	insert @DRate(Date,Rate,WRate,MRP)	
	select top 1 h.FromDate,s.Rate,s.WRate,s.MRP from invQtyRateSettingsDetails s 
	join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
	join @ProductDetails pd on s.ProductID=@ID and s.UOMID=pd.SalesUOM
	where @Date>=h.FromDate and h.ToDate is null and s.LQty is null and s.UQty is null and (s.CompanyId=@CompanyID or @InterCompanyRateSettings=1) and h.FromTime=0 and h.Type=3
	order by h.FromDate desc,h.No desc

	declare @RateId int
	select @RateId=Rate from invRateLevel where Id=@RateLevelId

	select top 1 @Rate=case @RateId when 2 then MRP when 3 then WRate else Rate end,@WRate=WRate,@MRP=MRP from @DRate order by Date desc

end	


if isnull(@RateLevelId,0) > 0
	select @Rate=@Rate*(100.0+Percentage)/100.0 from invRateLevel where ID=@RateLevelId and PercentageOf=1

--TAddition
update p set p.TAddition=t.Addition from @ProductDetails p join invTaxGroup t on p.TaxGroupId=t.Id

--Final Data
select SalesUOM,isnull(@Rate,Rate)Rate,isnull(@WRate,WRate)WRate,UOM,isnull(@Mrp,Mrp) Mrp,NOP,@DiscountP DiscountP,Cost,Addition,TAddition from @ProductDetails

go

if not exists(select name from sys.columns where object_id = object_id('invQtyRateSettingsDetails') and name = 'Cost') 
  alter table invQtyRateSettingsDetails add Cost float

go

if OBJECT_ID('prSaveQtyRateSettings') is not null
	drop proc prSaveQtyRateSettings
go

create proc prSaveQtyRateSettings
@CompanyId int,
@PeriodId int,
@No int,
@FromDate int,
@ToDate int,
@Type int,
@Notes varchar(500),
@FromTime int=null,
@ToTime int=null,
@XmlProductDetails xml
as

set nocount on
set xact_abort on

Begin Transaction

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetQtyRateSettingsMaxVno @CompanyId = @CompanyId ,@PeriodId = @PeriodId
    select @No = [No] from @T1 
  end
else
	begin
		exec prDeleteQtyRateSettings @No = @No , @CompanyId = @CompanyId ,@PeriodId = @PeriodId
    end	
    	
insert invQtyRateSettingsHeader([CompanyId],[PeriodId],[No],[FromDate],ToDate,[Type],[Notes],FromTime,ToTime)
values(@CompanyId,@PeriodId,@No,@FromDate,nullif(@ToDate,0),@Type,@Notes,@FromTime,@ToTime)


declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert invQtyRateSettingsDetails
([CompanyId],[PeriodId],[No],[Sno],[ProductId],UOMID,[LQty],[UQty],Cost,[Rate],BarcodeId,DiscountPercent,WRate,MRP,FOC,Pieces)
select @CompanyId,@PeriodId,@No,[Sno],[ProductId],UOMID,nullif([LQty],0),nullif([UQty],0),Cost,[Rate],BarcodeId,DiscountPercent,WRate,MRP,FOC,nullif(Pieces,0) from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno             int      '@Sno',
ProductId       int      '@ProductId',
UomId           int      '@UomId',
LQty            float    '@LQty',
UQty            float    '@UQty',
Cost            float    '@Cost',
Rate            float    '@Rate',
WRate           float    '@WRate',
MRP             float    '@MRP',
BarcodeId       int      '@BarcodeId',
DiscountPercent float    '@DiscountPercent',
FOC float    '@FOC',
Pieces float    '@Pieces'
)

exec sp_xml_removedocument @Idoc

Commit

go

if OBJECT_ID('prGetQtyRateSettings') is not null
	drop proc prGetQtyRateSettings
go

create proc prGetQtyRateSettings
@CompanyId int,
@PeriodId int,
@No int as

set nocount on
set transaction isolation level read uncommitted

select t1.[No],t1.[FromDate],t1.ToDate,t1.Type,t1.[Notes],t1.FromTime,t1.ToTime from invQtyRateSettingsHeader t1
where  t1.[CompanyId] = @CompanyId and t1.[PeriodId] = @PeriodId and t1.[No] = @No

declare @Details table(SNo int,Code varchar(50),Barcode varchar(50),Particulars nvarchar(100),ProductID int,UOMID int,UOM varchar(25),Cost float,LQty int,UQty int,
Rate float,BarcodeId int,DiscountPercent float,WRate float,MRP float,FOC FLOAT,TaxP float,TaxGroupId int,Pieces float)

insert @Details([Sno],Code,Particulars,[ProductId],UOMID,UOM,[LQty],[UQty],Cost,[Rate],BarcodeId,DiscountPercent,WRate,MRP,FOC,TaxGroupId,Pieces)
select t1.[Sno],t2.Code,t2.Name Particulars,t1.[ProductId],t1.UOMID,u.Name UOM,t1.[LQty],t1.[UQty],t1.Cost,t1.[Rate],BarcodeId,DiscountPercent,t1.WRate,t1.MRP,T1.FOC,t2.TaxGroupId,t1.Pieces from invQtyRateSettingsDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
join invUOM u on t1.UOMID = u.Id 
where t1.[CompanyId] = @CompanyId and t1.[PeriodId] = @PeriodId and t1.[No] = @No 

--UBC
update sd set sd.Barcode=u.Barcode from @Details sd join invUomLevels u on sd.ProductId = u.ProductId and sd.UOMID = u.UomId

--Barcode
update sd set sd.Barcode=b.Barcode from @Details sd join invAutoBarcodeAndSalesRate b on sd.ProductId=b.ProductId and sd.BarcodeId=b.BarcodeId

--Barcode
update sd set sd.TaxP=t.OutputTax from @Details sd join invTaxGroup t on sd.TaxGroupId=t.Id

--Final
select * from @Details order by ProductId

go

if object_id('prStockRegisterSummary') is not null
  drop proc prStockRegisterSummary

go
  
create proc prStockRegisterSummary
@From int,
@To int, 
@Group bit,
@GroupTotal bit,
@Columns varchar(max),
@ValueDataWhereClause varchar(max),
@MasterDataWhereClause varchar(max),  
@Order varchar(max),
@GrandTotal varchar(max),
@AlterHeaderTable varchar(max),
@AlterGroupTable varchar(max),
@TempTable varchar(max),
@GroupQuery varchar(max),
@ProcessedValueFilter varchar(max),
@ProcessedMasterFilter varchar(max),
@CompanyID int,
@CostCentreId int=0
as  
   
set nocount on  
set transaction isolation level read uncommitted

set @CostCentreId=isnull(@CostCentreId,0)

set @Columns=replace(@Columns,'t3.Name','t3.ID,t3.Name')
set @GrandTotal='null,'+@GrandTotal

declare @cols varchar(max),
        @colVal varchar(max),
        @WhereClause varchar(max)         

create table #T1 
(
  CompanyId int,
  InOut int,	
  Date int,
  Vtype int,
  Vno int,
  TransactionId int,
  ProductId int, 
  BarcodeId int,
  Rate float,
  CRate float,
  SRate float,
  Qty float
)

if len(@ValueDataWhereClause) > 0 and LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where isnull(t3.inactive,0) = 0 and ' + @ValueDataWhereClause + ' and ' + @MasterDataWhereClause 
else if len(@ValueDataWhereClause) > 0 
  set @WhereClause = ' where isnull(t3.inactive,0) = 0 and ' + @ValueDataWhereClause 
else if LEN(@MasterDataWhereClause) > 0 
  set @WhereClause = ' where isnull(t3.inactive,0) = 0 and ' + @MasterDataWhereClause 
else 
  set @WhereClause = ' where isnull(t3.inactive,0) = 0 '  

declare @AutoBarcode int
select @AutoBarcode=AutoBarcode from invprojectSettings where CompanyId=@CompanyID

declare @StockWithBarcodeOnly int
select @StockWithBarcodeOnly=StockWithBarcodeOnly from invOption where CompanyId=@CompanyID

if len(@WhereClause) > 0 
Begin
	if (@AutoBarcode=1 and @StockWithBarcodeOnly=1)
		exec('insert tmpTable(SPID,ID,BarcodeID) 
		      select distinct @@spid,t3.Id,b.BarcodeId from  invProduct t3 
			  join invAutoBarcodeandSalesRate b on t3.Id=b.ProductId
			  join vw_ProductProerty t6 on t3.Id = t6.Id
				' + @WhereClause) 
	Else
		exec('insert tmpTable(SPID,ID,BarcodeID) 
			  select @@spid,t3.Id,null from  invProduct t3 
			  join vw_ProductProerty t6 on t3.Id = t6.Id
				' + @WhereClause) 

End
else
Begin
	if (@AutoBarcode=1 and @StockWithBarcodeOnly=1)
		insert tmpTable(SPID,ID,BarcodeID) 
		select @@spid,Id,b.BarcodeId from invProduct p
		join invAutoBarcodeandSalesRate b on p.Id=b.ProductId
		where isnull(inactive,0) = 0	
	Else
		insert tmpTable(SPID,ID,BarcodeID) select @@spid,Id,null from invProduct where isnull(inactive,0) = 0	
End

if (@AutoBarcode=1)
	insert #T1 
	exec spstock @ToDate=@To,@Type=9,@CompanyID=@CompanyID,@CostCentreId=@CostCentreId
Else
	insert #T1(CompanyId,InOut,Date,Vtype,Vno,TransactionId,ProductId,Rate,CRate,SRate,Qty)
	exec spstock @ToDate=@To,@Type=8,@CompanyID=@CompanyID,@CostCentreId=@CostCentreId

create table #CurrentStock 
(
ProductId int,
BarcodeId int,
Opening float,
OValue float,
Purchase float,
PValue float,
PR float,
PRValue float,
CTIn float,
CTInValue float,
CTOut float,
CTOutValue float,
Sales float,
SValue float,
SR float,
SRValue float,
POS float,
POSValue float,
Closing float,
CValue float
)

insert #CurrentStock(ProductId,BarcodeId,Opening,OValue,Purchase,PValue,PR,PRValue,CTIn,CTInValue,CTOut,CTOutValue,Sales,SValue,SR,SRValue,POS,POSValue,Closing,CValue)
select ProductId,BarcodeId,
sum(case when TransactionId=1 then qty end)Opening,
sum(case when TransactionId=1 then qty*Rate end),
sum(case when TransactionId=2 then qty end)Purchase,
sum(case when TransactionId=2 then qty*Rate end),
sum(case when TransactionId=3 then qty end)PR,
sum(case when TransactionId=3 then qty*Rate end),
sum(case when TransactionId=16 and InOut is null then qty end)CTIn,
sum(case when TransactionId=16 and InOut is null then qty*Rate end),
sum(case when TransactionId=16 and InOut=1 then qty end)CTOut,
sum(case when TransactionId=16 and InOut=1 then qty*Rate end)CTOut,
sum(case when TransactionId=4 then qty end)Sales,
sum(case when TransactionId=4 then qty*Rate end),
sum(case when TransactionId=5 then qty end)SR,
sum(case when TransactionId=5 then qty*Rate end),
sum(case when TransactionId=15 then qty end)POS,
sum(case when TransactionId=15 then qty*Rate end),
sum(qty) closing,
sum(qty*Rate) CValue
from #T1 group by ProductId,BarcodeId


 
if len(@ProcessedValueFilter) > 0 and LEN(@ProcessedMasterFilter) > 0 
  set @WhereClause = ' where not (' + @ProcessedValueFilter + ' and ' + @ProcessedMasterFilter + ')'
else if len(@ProcessedValueFilter) > 0 
  set @WhereClause =  ' where not (' +  @ProcessedValueFilter + ')'
else if LEN(@ProcessedMasterFilter) > 0 
  set @WhereClause = ' where not (' +  @ProcessedMasterFilter + ')'
else 
  set @WhereClause = ''  


if len(@WhereClause) > 0
begin
	exec('delete t1 from #CurrentStock t1 ' +  @WhereClause )
end



create index ind#T1 on #T1(ProductId)

if @Group = 0  
	if @GroupTotal = 0     
		begin
			
			exec('select ' + @Columns + ' from #CurrentStock t1 
			join invProduct t3 on t1.ProductId = t3.Id 
			join vw_ProductProerty t6 on t1.ProductId = t6.Id 
			left join invAutoBarcodeandSalesRate b on t1.ProductId=b.Productid and t1.BarcodeId=b.BarcodeId '  + @Order)
		end
    else
		begin
		
		    if LEN(@Order) = 0 
				begin
					
				exec('select ' + @Columns + ' from #CurrentStock t1 
				join invProduct t3 on t1.ProductId = t3.Id 
				join vw_ProductProerty t6 on t1.ProductId = t6.Id
				left join invAutoBarcodeandSalesRate b on t1.ProductId=b.Productid and t1.BarcodeId=b.BarcodeId 
				union all select ' + @GrandTotal + ' from #CurrentStock t1 
				join invProduct t3 on t1.ProductId = t3.Id 
			   	join vw_ProductProerty t6 on t1.ProductId = t6.Id
				left join invAutoBarcodeandSalesRate b on t1.ProductId=b.Productid and t1.BarcodeId=b.BarcodeId ' )

				end
		  else
			begin
			    declare @Query varchar(max)
				set @Query = 'select * from(select 0 row_id,' + @Columns + ' from #CurrentStock t1 
				join invProduct t3 on t1.ProductId = t3.Id 
				left outer join vw_ProductProerty t6 on t1.ProductId = t6.Id
				left join invAutoBarcodeandSalesRate b on t1.ProductId=b.Productid and t1.BarcodeId=b.BarcodeId 
				union all 
				select 1 row_id,' + @GrandTotal + ' from #CurrentStock t1 
				join invProduct t3 on t1.ProductId = t3.Id 
				join vw_ProductProerty t6 on t1.ProductId = t6.Id
				left join invAutoBarcodeandSalesRate b on t1.ProductId=b.Productid and t1.BarcodeId=b.BarcodeId 
				) p ' + replace(@order,'order by','order by row_id,')
				
				exec(@Query)
			end	   		
		end			
else  
	begin  
			 
		create table #Stock ([ ] int)
		exec(@AlterHeaderTable)
				
		exec('insert #Stock select ' + @Columns + ' from #CurrentStock t1 
		join invProduct t3 on t1.ProductId = t3.Id 
        join vw_ProductProerty t6 on t1.ProductId = t6.Id 
		left join invAutoBarcodeandSalesRate b on t1.ProductId=b.Productid and t1.BarcodeId=b.BarcodeId' 
		+ @Order)
		
		create table #StockGroup(Rid numeric identity(1,1))  
		exec(@AlterGroupTable)
		exec(@TempTable)
		exec(@GroupQuery) 
		drop table #Stock,#StockGroup
	end   


select t1.ProductID,Secondary from #CurrentStock t1 
join invProduct p on t1.ProductID=p.ID 
join invUOMLevels u on t1.ProductID=u.ProductID and p.StockUOM=u.UOMID
 
go

if object_id('spGetSalesForCashReceipt') is not null drop proc spGetSalesForCashReceipt

go

create proc spGetSalesForCashReceipt
@Date int,
@DebtorId int,
@CompanyId int=1,
@SalesmanId int=0

as

if @SalesmanId=0
	select @SalesmanId=isnull(id,0) from invSalesman where accountid=@DebtorId

select 0 SNo,0 KSNo,fd.CustomerID CreditorID,a.Code,a.Name Creditor,fd.CostCentreID,c.Name CostCentre,fd.No Description,fd.NetTotal Amount,0 Discount,fd.NetTotal NetAmount from invSalesHeader fd 
join aAccount a on fd.CustomerID=a.ID 
left join invCostCentre ic on fd.CostCentreID=ic.ID
left join aCostCentre c on ic.CostCentreID=c.ID
where fd.Date=@Date and fd.PaymentMode=1 
and (@SalesmanId=0 or fd.SalesmanId=@SalesmanId)
and CompanyId=@CompanyId
order by fd.No

go


if object_id('spReportPurchaseTaxReturn') is not null drop proc spReportPurchaseTaxReturn

go

create proc spReportPurchaseTaxReturn
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

declare @TR table(CompanyId int,GST varchar(50),TRN varchar(50),VtypeId int,No int,InvoiceNo varchar(50),Date smalldatetime,Vendor nvarchar(100),InvDate datetime,
InterState bit,ProductID int,Item varchar(50),HSN varchar(50),UOM varchar(50),Qty float,Rate float,TaxP float,Taxable float,Tax float,CESS float,Total float,VendorId int,
Description nvarchar(200),AdditionalDescription nvarchar(200))


--Purchase
insert @TR(CompanyId,VtypeId,No,InvoiceNo,Date,InvDate,InterState,ProductID,Uom,Qty,Rate,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,v.Id,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sh.InterState,sd.ProductID,u.Name UOM, Qty,sd.Rate,t.InputTax,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Total,sh.VendorId
from invPurchaseHeader sh 
join invPurchaseDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Purchase Return
insert @TR(CompanyId,VtypeId,No,InvoiceNo,Date,InvDate,ProductID,Uom, Qty,Rate,TaxP,Taxable,Tax,CESS,Total,VendorId)
select sh.CompanyId,v.Id,sh.No,sh.InvoiceNo,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.DeliveryDate as varchar)as datetime) InvDate,sd.ProductID,u.Name UOM, -Qty,sd.Rate,t.InputTax,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition,-sd.Total,sh.VendorId from invPurchaseReturnHeader sh
join invPurchaseReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join invVoucherTypeDetails vt on sd.VtypeId=vt.Id
join @VType v on vt.AccountVtypeId=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate

declare @CTVtype int
select @CTVtype=AccountVtypeID from invVoucherTypeDetails where VtypeId=16

--Company Transfer
insert @TR(CompanyId,VtypeId,No,Date,ProductID,UOM,Qty,Rate,TaxP,Taxable,Tax,Total,VendorId)
select CompanyTo,v.Id,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
sd.ProductID,u.Name UOM, Qty,sd.Rate,t.InputTax,sd.Gross,sd.Tax,sd.Total,c.AccountId from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join invTaxGroup t on sd.TaxGroupID=t.ID
join invUom u on sd.UomId=u.Id
join @VType v on @CTVtype=v.ID
join aCompany c on c.Id=sh.CompanyFrom
where (sh.CompanyTo=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate


--Journal
insert @TR(CompanyId,VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description)
select sh.CompanyId,avs.Journal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,case when sh.DrCr=1 then sh.AccountID else sd.AccountID end,sd.Description from aJournalHdr sh
join aJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on case when sh.DrCr=1 then sd.AccountID else sh.AccountID end=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.Journal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0



--Multi Journal
insert @TR(CompanyId,VtypeId,No,Date,InvDate,TaxP,Taxable,Tax,Total,VendorId,Description,AdditionalDescription)
select sh.CompanyId,avs.MultiJournal,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,
cast(cast(sh.Date as varchar)as datetime) InvDate,t.Rate,sd.Amount,sd.Tax,sd.Amount+sd.Tax,sd.CreditorID,sd.Description,sd.AdditionalDescription from aMultiJournalHdr sh
join aMultiJournalDtl sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.No=sd.No
join aAccount a on sd.DebtorID=a.ID
join aTaxGroup t on a.TaxGroupID=t.ID
cross join aVoucherTypeSettings avs
join @VType v on avs.MultiJournal=v.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate
and sd.Tax<>0


--HSN
update t set t.Item=psp.Name,t.HSN=psp.Code from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID

--Vendor Details
update tr set tr.GST=c.GST,tr.TRN=c.TIN,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invVendor c on tr.VendorId=c.AccountID
update tr set tr.GST=c.GST,tr.TRN=c.TIN,tr.Vendor=isnull(tr.Vendor,c.Name) from @TR tr join invCustomer c on tr.VendorId=c.AccountID where tr.Vendor is null
update tr set tr.Vendor=a.Name from @TR tr join aAccount a on tr.VendorId=a.Id where tr.Vendor is null


--Final Date
select c.Name Company,GST,TRN,v.Code VType,No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,UOM, sum(Qty)Qty,Rate,TaxP,sum(Taxable)Taxable,sum(Tax)Tax,sum(CESS)CESS,sum(Total)Total from @TR t
join aVoucherType v on t.VtypeId=v.Id
join aCompany c on t.CompanyId=c.Id
group by c.Name,GST,TRN,v.Code, No,InvoiceNo,Date,Vendor,InvDate,InterState,Item,HSN,UOM, Rate,TaxP

go

if object_id('spReportSalesTaxReturn2') is not null drop proc spReportSalesTaxReturn2

go

create proc spReportSalesTaxReturn2
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml,
@GST tinyint=2,
@xmlTaxGroup xml

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

--TaxGroup
exec sp_xml_preparedocument @Idoc out ,@xmlTaxGroup

declare @TaxGroup table(ID int)	

insert @TaxGroup
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc


declare @TR table(CompanyId int,CustomerID int,GST varchar(50),TIN varchar(50),VType varchar(50),Prefix varchar(50),No int,Date smalldatetime,DDate smalldatetime,InterState bit,Customer nvarchar(200),Place varchar(100),Rate float,Taxable float,Tax float,Addition float,Addition1 float,Addition2 float,Total float)

--Sales
insert @TR(CompanyId,CustomerID,VType,Prefix,No,Date,DDate,Customer,InterState,Taxable,Rate,Tax,Addition,Addition1,Addition2,Total)
select sh.CompanyId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(nullif(sh.DeliveryDate,0) as varchar)as smalldatetime)DDate,sh.Address,sh.InterState,sd.Gross-sd.Discount,t.OutputTax,sd.Tax,sd.Addition,sd.Addition1,sd.Addition2,sd.Total from invSalesHeader sh
join invSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on sd.VtypeID=v.ID
join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
join invUOM u on sd.UOMID=u.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.BillTax is null


--Sales Billwise
insert @TR(CompanyId,CustomerID,VType,Prefix,No,Date,DDate,Customer,InterState,Rate,Taxable,Tax,Total)
select CompanyId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,sh.Address,sh.InterState,t.OutputTax Rate,sh.NetTotal-sh.BillTax-isnull(sh.RoundOff,0),sh.BillTax,sh.NetTotal from invSalesHeader sh
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join invTaxGroup t on sh.TaxGroupID=t.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.BillTax is not null


if object_id('pSalesHeader') is not null and object_id('pSalesDetails') is not null
Begin
	--POS Itemwise
	insert @TR(CompanyId,CustomerID,VType,No,Date,DDate,Taxable,Rate,Tax,Total)
	select sh.CompanyId,sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,sd.Rate*sd.Qty-isnull(sd.DiscountAmount,0),t.OutputTax,sd.Tax,sd.Total from pSalesHeader sh
	join pSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
	join @TaxGroup tg on sd.TaxGroupId=tg.ID
	join invTaxGroup t on sd.TaxGroupID=t.ID
	join @VType v on sd.VtypeID=v.ID
	join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
	join invUOM u on sd.UOMID=u.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax<>0 and sd.Tax<>0)


	--POS Billwise
	insert @TR(CompanyId,CustomerID,VType,No,Date,DDate,Rate,Taxable,Tax,Total)
	select CompanyId,sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,t.OutputTax Rate,case when TaxMethode=2 then sh.NetTotal-sh.TaxAmount else sh.Total end,sh.TaxAmount,sh.NetTotal from pSalesHeader sh
	join @TaxGroup tg on sh.TaxGroup=tg.ID
	join invTaxGroup t on sh.TaxGroup=t.ID
	join @VType v on sh.VtypeID=v.ID
	join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax<>0 and sh.TaxAmount<>0)

End

if object_id('pSalesReturnHeader') is not null and object_id('pSalesReturnDetails') is not null
Begin
	--POS Itemwise
	insert @TR(CompanyId,CustomerID,VType,No,Date,DDate,Taxable,Rate,Tax,Total)
	select sh.CompanyId,sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,-sd.Rate*sd.Qty,t.OutputTax,-sd.Tax,-sd.Total from pSalesReturnHeader sh
	join pSalesReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
	join @TaxGroup tg on sd.TaxGroupId=tg.ID
	join invTaxGroup t on sd.TaxGroupID=t.ID
	join @VType v on sd.VtypeID=v.ID
	join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
	join invUOM u on sd.UOMID=u.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax<>0 and sd.Tax<>0)


	--POS Billwise
	insert @TR(CompanyId,CustomerID,VType,No,Date,DDate,Rate,Taxable,Tax,Total)
	select CompanyId,sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,t.OutputTax Rate,-case when TaxMethode=2 then sh.NetTotal-sh.TaxAmount else sh.Total end,-sh.TaxAmount,-sh.NetTotal from pSalesReturnHeader sh
	join @TaxGroup tg on sh.TaxGroup=tg.ID
	join invTaxGroup t on sh.TaxGroup=t.ID
	join @VType v on sh.VtypeID=v.ID
	join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax<>0 and sh.TaxAmount<>0)

End


--Sales Return
insert @TR(CompanyId,CustomerID,VType,Prefix,No,Date,DDate,Taxable,Rate,Tax,Addition2,Total)
select sh.CompanyId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,-(sd.Gross-sd.Discount),t.OutputTax,-sd.Tax,-sd.Addition2,-sd.Total from invSalesReturnHeader sh
join invSalesReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on sd.VtypeID=v.ID
join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
join invUOM u on sd.UOMID=u.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and isnull(sh.BillTax,0)=0


--Sales Return Billwise
insert @TR(CompanyId,CustomerID,VType,Prefix,No,Date,DDate,Rate,Taxable,Tax,Total)
select CompanyId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,t.OutputTax Rate,-(sh.NetTotal-sh.BillTax-isnull(sh.RoundOff,0)),-sh.BillTax,-sh.NetTotal from invSalesReturnHeader sh
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join invTaxGroup t on sh.TaxGroupID=t.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.BillTax is not null


--Company Transfer

declare @CTVtype int
select @CTVtype=Id from invVoucherTypeDetails where VtypeId=16

insert @TR(CompanyId,CustomerID,VType,Prefix,No,Date,DDate,Rate,Taxable,Tax,Total)
select CompanyFrom,c.AccountID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime),t.OutputTax Rate,sd.Gross,sd.Tax,sd.Total from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on @CTVtype=v.ID
join invVoucherTypeDetails vt on @CTVtype=vt.ID
join invUOM u on sd.UOMID=u.ID
join aCompany c on sh.CompanyTo=c.Id
where (sh.CompanyFrom=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate 


--Job Invoice
insert @TR(CompanyId,CustomerID,Customer,VType,Prefix,No,Date,DDate,Rate,Taxable,Tax,Total)
select sh.CompanyID,sh.CustomerID,j.Customer,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,t.OutputTax Rate,sh.Amount-sh.Tax,sh.Tax,sh.Amount from invJobInvoice sh
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join invTaxGroup t on sh.TaxGroupID=t.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
join invJobForm j on sh.JobId=j.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.Tax is not null


--Customer Details
update tr set tr.GST=c.GST,tr.TIN=c.TIN,tr.Customer=isnull(tr.Customer,c.Name) from @TR tr join invVendor c on tr.CustomerID=c.AccountID
update tr set tr.GST=c.GST,tr.TIN=c.TIN,tr.Customer=isnull(tr.Customer,c.Name),tr.Place=c.Place from @TR tr join invCustomer c on tr.CustomerID=c.AccountID

if (@GST=0) delete @TR where isnull(GST,'')=''
if (@GST=1) delete @TR where LEN(GST)>0


--Final Date
select c.Code CCode,GST,TIN,VType,Prefix,No,Date,DDate,InterState,Customer,Place,Rate,sum(Taxable)Taxable,sum(Tax)Tax,sum(Addition)Addition,sum(Addition1)Addition1,sum(Addition2)Addition2,sum(Total)Total from @TR t
join aCompany c on c.ID=t.CompanyId
group by c.Code,GST,TIN,VType,Prefix,No,Date,DDate,InterState,Customer,Place,Rate 
order by no

go

if object_id('spReportSalesTaxReturn') is not null drop proc spReportSalesTaxReturn

go

create proc spReportSalesTaxReturn
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml,
@GST tinyint=2,
@xmlTaxGroup xml,
@CostCentreId int=0

as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

--TaxGroup
exec sp_xml_preparedocument @Idoc out ,@xmlTaxGroup

declare @TaxGroup table(ID int)	

insert @TaxGroup
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc


declare @TR table(CompanyId int,VtypeId int,PeriodId int,CompanyCode varchar(50),CompanyName nvarchar(100),CustomerID int,GST varchar(50),TIN varchar(50),VType varchar(50),Prefix varchar(50),No int,Date smalldatetime,DDate smalldatetime,InterState bit,Customer nvarchar(200),Place varchar(100),ProductID int,HSC varchar(50),HSN varchar(100),Rate float,Qty float,UOM varchar(50),Pieces float,Taxable float,Tax float,Addition float,Addition1 float,Addition2 float,Total float)


--Sales
insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,Customer,InterState,ProductID,Rate,Qty,UOM,Pieces,Taxable,Tax,Addition,Addition1,Addition2,Total)
select sh.CompanyId,sh.VtypeId,sh.PeriodId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(nullif(sh.DeliveryDate,0) as varchar)as smalldatetime)DDate,sh.Address,sh.InterState,sd.ProductID,t.OutputTax Rate,sd.Qty,u.Name,sd.Pieces,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Addition1,sd.Addition2,sd.Total from invSalesHeader sh
join invSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on sd.VtypeID=v.ID
join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
join invUOM u on sd.UOMID=u.ID
--left join invVoucherTypeStartNo sn on sd.VtypeId=sn.VtypeId and sd.CompanyId=sn.CompanyId and sd.PeriodId=sn.PeriodId 
where (sh.CompanyID=@CompanyID or @CompanyID=0) 
and sh.Date between @FromDate and @ToDate 
and sh.BillTax is null
and (@CostCentreId=0 or sh.CostCentreId=@CostCentreId)

--Sales Billwise
insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,Customer,InterState,Rate,Taxable,Tax,Total)
select sh.CompanyId,sh.VtypeId,PeriodId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,sh.Address,sh.InterState,t.OutputTax Rate,sh.NetTotal-sh.BillTax,sh.BillTax,sh.NetTotal from invSalesHeader sh
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join invTaxGroup t on sh.TaxGroupID=t.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) 
and sh.Date between @FromDate and @ToDate 
and sh.BillTax is not null
and (@CostCentreId=0 or sh.CostCentreId=@CostCentreId)


if object_id('pSalesHeader') is not null and object_id('pSalesDetails') is not null
Begin
	--POS Itemwise
	insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,ProductID,Rate,Qty,UOM,Taxable,Tax,Total)
	select sh.CompanyId,sh.VtypeId,sh.PeriodId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,sd.ProductID,t.OutputTax Rate,sd.Qty,u.Name,sd.Rate*sd.Qty,sd.Tax,sd.Total from pSalesHeader sh
	join pSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
	join @TaxGroup tg on sd.TaxGroupId=tg.ID
	join invTaxGroup t on sd.TaxGroupID=t.ID
	join @VType v on sd.VtypeID=v.ID
	join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
	join invUOM u on sd.UOMID=u.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax>0 and sd.Tax>0)


	--POS Billwise
	insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,Rate,Taxable,Tax,Total)
	select sh.CompanyId,sh.VtypeId,sh.PeriodId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,t.OutputTax Rate,case when TaxMethode=2 then sh.NetTotal-sh.TaxAmount else sh.Total end,sh.TaxAmount,sh.NetTotal from pSalesHeader sh
	join @TaxGroup tg on sh.TaxGroup=tg.ID
	join invTaxGroup t on sh.TaxGroup=t.ID
	join @VType v on sh.VtypeID=v.ID
	join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) 
	and sh.Date between @FromDate and @ToDate 
	and (t.OutputTax=0 or t.OutputTax>0 and sh.TaxAmount>0)


End

--Cencelled Bills
insert @TR(CompanyId,VtypeId,PeriodId,VType,Prefix,No,Date)
select sh.CompanyId,sh.VtypeId,PeriodId,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date from invSalesHeader sh
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) 
and sh.Date between @FromDate and @ToDate 
and isnull(sh.CustomerId,0)=0
and (@CostCentreId=0 or sh.CostCentreId=@CostCentreId)


--Sales Return
insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,ProductID,Rate,Qty,UOM,Taxable,Tax,Addition2,Total)
select sh.CompanyId,sh.VtypeId,sh.PeriodId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,sd.ProductID,t.OutputTax Rate,-sd.Qty,u.Name,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Addition2,-sd.Total from invSalesReturnHeader sh
join invSalesReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on sd.VtypeID=v.ID
join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
join invUOM u on sd.UOMID=u.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) 
and sh.Date between @FromDate and @ToDate 
and isnull(sh.BillTax,0)=0
and (@CostCentreId=0 or sh.CostCentreId=@CostCentreId)


--Sales Return Billwise
insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,Rate,Taxable,Tax,Total)
select sh.CompanyId,sh.VtypeId,PeriodId,sh.CustomerID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,t.OutputTax Rate,-(sh.NetTotal-sh.BillTax),-sh.BillTax,-sh.NetTotal from invSalesReturnHeader sh
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join invTaxGroup t on sh.TaxGroupID=t.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) 
and sh.Date between @FromDate and @ToDate 
and sh.BillTax is not null
and (@CostCentreId=0 or sh.CostCentreId=@CostCentreId)



--Company Transfer

declare @CTVtype int
select @CTVtype=Id from invVoucherTypeDetails where VtypeId=16

insert @TR(CompanyId,VtypeId,PeriodId,CustomerID,VType,Prefix,No,Date,DDate,ProductID,Rate,Qty,UOM,Taxable,Tax,Total)
select sh.CompanyFrom,VtypeId,sh.PeriodId,c.AccountID,vt.Code,vt.Description,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime),sd.ProductID,t.OutputTax Rate,sd.Qty,u.Name,sd.Gross,sd.Tax,sd.Total from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on @CTVtype=v.ID
join invVoucherTypeDetails vt on @CTVtype=vt.ID
join invUOM u on sd.UOMID=u.ID
join aCompany c on sh.CompanyTo=c.Id
where (sh.CompanyFrom=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate 


--Customer Details
update tr set tr.GST=c.GST,tr.TIN=c.TIN,tr.Customer=isnull(tr.Customer,c.Name) from @TR tr join invVendor c on tr.CustomerID=c.AccountID
update tr set tr.GST=c.GST,tr.TIN=c.TIN,tr.Customer=isnull(tr.Customer,c.Name),tr.Place=c.Place from @TR tr join invCustomer c on tr.CustomerID=c.AccountID
update tr set tr.Customer=c.Name from @TR tr join aAccount c on tr.CustomerID=c.Id where tr.Customer is null

if (@GST=0) delete @TR where isnull(GST,'')=''
if (@GST=1) delete @TR where LEN(GST)>0


--HSN
update t set t.HSC=psp.Code,t.HSN=psp.Name from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and (o.CompanyID=@CompanyID or @CompanyID=0)
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--HSN
update t set t.HSN=p.Name from @TR t join invProduct p on t.ProductID=p.ID where t.HSN is null or t.HSN=t.HSC

--Company
update t set t.CompanyCode=c.Code,t.CompanyName=c.Name from @TR t join aCompany c on t.CompanyId=c.ID


--InvoiceFormat
update t set t.Prefix=sn.InvoiceFormat from @TR t join invVoucherTypeStartNo sn on t.VtypeId=sn.VtypeId and t.CompanyId=sn.CompanyId and t.PeriodId=sn.PeriodId

--Final Date
select CompanyCode,CompanyName,GST,TIN,VType,Prefix,No,Date,DDate,InterState,Customer,Place,HSC,HSN,Rate,sum(Qty)Qty,UOM,sum(Pieces)Pieces,sum(Taxable)Taxable,sum(Tax)Tax,sum(Addition)Addition,sum(Addition1)Addition1,sum(Addition2)Addition2,sum(Total)Total from @TR 
group by CompanyCode,CompanyName,GST,TIN,VType,Prefix,No,Date,DDate,InterState,Customer,Place,HSC,HSN,Rate,UOM 
order by no

go

if object_id('spReportSalesTaxReturn1') is not null drop proc spReportSalesTaxReturn1

go

create proc spReportSalesTaxReturn1
@CompanyID int,
@FromDate int,
@ToDate int,
@xmlVType xml,
@GST tinyint=2,
@xmlTaxGroup xml


as

set nocount on
set transaction isolation level read uncommitted

--VType
declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@xmlVType

declare @VType table(ID int)	

insert @VType
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc

--TaxGroup
exec sp_xml_preparedocument @Idoc out ,@xmlTaxGroup

declare @TaxGroup table(ID int)	

insert @TaxGroup
select ID from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
ID int      '@ID'  
)

exec sp_xml_removedocument @Idoc


declare @TR table(CustomerID int,GST varchar(50),TIN varchar(50),VType varchar(50),No int,Date smalldatetime,DDate smalldatetime,InterState bit,Customer nvarchar(200),Place varchar(100),ProductID int,HSC varchar(50),HSN varchar(100),Rate float,Qty float,UOM varchar(50),Taxable float,Tax float,Addition float,Addition1 float,Total float)

--Sales
insert @TR(CustomerID,VType,No,Date,DDate,Customer,InterState,ProductID,Rate,Qty,UOM,Taxable,Tax,Addition,Addition1,Total)
select sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(nullif(sh.DeliveryDate,0) as varchar)as smalldatetime)DDate,sh.Address,sh.InterState,sd.ProductID,t.OutputTax Rate,sd.Qty,u.Name,sd.Gross-sd.Discount,sd.Tax,sd.Addition,sd.Addition1,sd.Total from invSalesHeader sh
join invSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on sd.VtypeID=v.ID
join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
join invUOM u on sd.UOMID=u.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.BillTax is null

--Sales Billwise
insert @TR(CustomerID,VType,No,Date,DDate,Customer,InterState,Rate,Taxable,Tax,Total)
select sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,sh.Address,sh.InterState,t.OutputTax Rate,sh.NetTotal-sh.BillTax,sh.BillTax,sh.NetTotal from invSalesHeader sh
--join invSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join invTaxGroup t on sh.TaxGroupID=t.ID
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
--join invUOM u on sd.UOMID=u.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.BillTax is not null

if object_id('pSalesHeader') is not null and object_id('pSalesDetails') is not null
Begin
	--POS Itemwise
	insert @TR(CustomerID,VType,No,Date,DDate,ProductID,Rate,Qty,UOM,Taxable,Tax,Total)
	select sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,sd.ProductID,t.OutputTax Rate,sd.Qty,u.Name,sd.Rate*sd.Qty,sd.Tax,sd.Total from pSalesHeader sh
	join pSalesDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
	join @TaxGroup tg on sd.TaxGroupId=tg.ID
	join invTaxGroup t on sd.TaxGroupID=t.ID
	join @VType v on sd.VtypeID=v.ID
	join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
	join invUOM u on sd.UOMID=u.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax>0 and sd.Tax>0)


	--POS Billwise
	insert @TR(CustomerID,VType,No,Date,DDate,Rate,Taxable,Tax,Total)
	select sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime)DDate,t.OutputTax Rate,case when TaxMethode=2 then sh.NetTotal-sh.TaxAmount else sh.Total end,sh.TaxAmount,sh.NetTotal from pSalesHeader sh
	join @TaxGroup tg on sh.TaxGroup=tg.ID
	join invTaxGroup t on sh.TaxGroup=t.ID
	join @VType v on sh.VtypeID=v.ID
	join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
	where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and (t.OutputTax=0 or t.OutputTax>0 and sh.TaxAmount>0)

End

--Sales Return
insert @TR(CustomerID,VType,No,Date,DDate,ProductID,Rate,Qty,UOM,Taxable,Tax,Total)
select sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,sd.ProductID,t.OutputTax Rate,-sd.Qty,u.Name,-(sd.Gross-sd.Discount),-sd.Tax,-sd.Total from invSalesReturnHeader sh
join invSalesReturnDetails sd on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sh.VTypeID=sd.VTypeID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on sd.VtypeID=v.ID
join invVoucherTypeDetails vt on sd.VTypeID=vt.ID
join invUOM u on sd.UOMID=u.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and isnull(sh.BillTax,0)=0



--Sales Return Billwise
insert @TR(CustomerID,VType,No,Date,DDate,Rate,Taxable,Tax,Total)
select sh.CustomerID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.DeliveryDate as varchar)as smalldatetime)DDate,t.OutputTax Rate,-(sh.NetTotal-sh.BillTax),-sh.BillTax,-sh.NetTotal from invSalesReturnHeader sh
join invTaxGroup t on sh.TaxGroupID=t.ID
join @TaxGroup tg on sh.TaxGroupId=tg.ID
join @VType v on sh.VtypeID=v.ID
join invVoucherTypeDetails vt on sh.VTypeID=vt.ID
where (sh.CompanyID=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate and sh.BillTax is not null




declare @CTVtype int
select @CTVtype=Id from invVoucherTypeDetails where VtypeId=16


insert @TR(CustomerID,VType,No,Date,DDate,ProductID,Rate,Qty,UOM,Taxable,Tax,Total)
select c.AccountID,vt.Code,sh.No,cast(cast(sh.Date as varchar)as smalldatetime)Date,cast(cast(sh.Date as varchar)as smalldatetime),sd.ProductID,t.OutputTax Rate,sd.Qty,u.Name,sd.Gross,sd.Tax,sd.Total from invCompanyTransferHeader sh
join invCompanyTransferDetails sd on sh.PeriodID=sd.PeriodID and sh.No=sd.No
join @TaxGroup tg on sd.TaxGroupId=tg.ID
join invTaxGroup t on sd.TaxGroupID=t.ID
join @VType v on @CTVtype=v.ID
join invVoucherTypeDetails vt on @CTVtype=vt.ID
join invUOM u on sd.UOMID=u.ID
join aCompany c on sh.CompanyTo=c.Id
where (sh.CompanyFrom=@CompanyID or @CompanyID=0) and sh.Date between @FromDate and @ToDate 

--Customer Details
update tr set tr.GST=c.GST,tr.TIN=c.TIN,tr.Customer=isnull(tr.Customer,c.Name) from @TR tr join invVendor c on tr.CustomerID=c.AccountID
update tr set tr.GST=c.GST,tr.TIN=c.TIN,tr.Customer=isnull(tr.Customer,c.Name),tr.Place=c.Place from @TR tr join invCustomer c on tr.CustomerID=c.AccountID
update tr set tr.Customer=c.Name from @TR tr join aAccount c on tr.CustomerID=c.Id where tr.Customer is null

if (@GST=0) delete @TR where isnull(GST,'')=''
if (@GST=1) delete @TR where LEN(GST)>0


--HSN
update t set t.HSC=psp.Code,t.HSN=psp.Name from @TR t
join invProductPropertyDetails ppd on t.ProductID=ppd.ProductID
join invOption o on ppd.PropertyID=o.CategoryPropertyID and o.CompanyID=@CompanyID
join invProductSubProperty psp on ppd.SubPropertyID=psp.ID


--Final Date
select GST,TIN,VType,No,Date,DDate,InterState,Customer,Place,HSC,HSN,Rate,sum(Qty)Qty,UOM,sum(Taxable)Taxable,sum(Tax)Tax,sum(Addition)Addition,sum(Addition1)Addition1,sum(Total)Total from @TR group by GST,TIN,VType,No,Date,DDate,InterState,Customer,Place,HSC,HSN,Rate,UOM order by no

go

if OBJECT_ID('prImportToStockFromExcelFile') is not null
	drop proc prImportToStockFromExcelFile
go

create proc prImportToStockFromExcelFile
@XmlProductDetails xml,
@Type int,
@ProductType int 
as
set nocount on


create table #T1
(
	Product varchar(100),
	Qty float ,
	Rate float,
	SerialNumber varchar(50),
	Id int,
	Property1 varchar(100),
	Property2 varchar(100),
	Remark varchar(100),
	Expiry varchar(100),
	Barcode varchar(100),
	SRate float,
	Sno int
)

declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert #T1   
select [Product],[Qty],[Rate],SerialNo,Id,Property1,Property2,Remark,Expiry,Barcode,SRate,Sno from openxml (@Idoc,'/TableHeader/Table1',2)
    with
    (
        Product varchar(100) '@Product',
        Qty float '@Qty',
        Rate float '@Rate',
		SRate float '@SRate',
		SerialNo varchar(100) '@SerialNo',
		Id int '@Id',
		Property1 varchar(100) '@Property1',
		Property2 varchar(100) '@Property2',
		Remark varchar(100) '@Remark',
		Expiry varchar(100) '@Expiry',
		Barcode varchar(100) '@Barcode',
        Sno int '@Sno'
	)
   exec sp_xml_removedocument @Idoc

delete #T1 where len(trim(Product))=0

if @ProductType<>1 and @Type<>2
	delete #T1 where isnull(Qty,0)=0


if @Type = 1 --Check New Products
begin
  if @ProductType = 1  
    select isnull(count(t1.Product),0) NewProducts from #T1 t1
    left outer join invUomLevels t2 on t1.Product = t2.Barcode
    where t2.barcode is null
  else if @ProductType = 3  
    select isnull(count(t1.Product),0) NewProducts from #T1 t1
    left outer join invAutoBarcodeAndSalesRate t2 on t1.Product = t2.Barcode
    where t2.barcode is null
  else
	  select isnull(count(t1.Product),0) NewProducts from #T1 t1
	  left outer join invProduct t2 on t1.Product = case when @ProductType = 2 then t2.Name else t2.code end
	  where t2.name is null 
	  and len(rtrim(t1.Product))>0
  return
end


if @Type = 2 --List New Products
begin
	if @ProductType = 1	
		select t1.Product from #T1 t1
		left outer join invUomLevels t2 on t1.Product = t2.Barcode
		where t2.barcode is null order by t1.Product
	else
		select t1.Product from #T1 t1
		left outer join invProduct t2 on t1.Product = case when @ProductType = 2 then t2.Name else t2.code end
		where t2.name is null and len(t1.Product)>0 
		and len(rtrim(t1.Product))>0
		order by t1.Product

	return
end


declare @Rate table
(
ProductId int,
Rate float
)

update #T1 set Rate = null where rate = 0
--Type = 3 Get the list
if @ProductType = 1
  begin       
	insert tmpTable (Id,Spid) select distinct t2.ProductId,@@spid from #T1 t1
    join invUomLevels t2 on t1.Product = t2.Barcode
	
    insert @Rate (ProductId,Rate)
	exec spstock @CompanyId=1,@CostCentreId=0,@WHID=0,@FromDate=0,@ToDate=99999999,@Type=13  

	select t3.Code,t3.Name Particulars,t3.Id [ProductId],
	t4.Name Uom,t4.Id [UomId],t1.[Qty],coalesce(t1.[Rate],t5.Rate * t2.Secondary,0) Rate,isnull(t3.SerialNo,0) SerialNo,t1.SerialNumber,t3.Rate SalesRate from #T1 t1
    join invUomLevels t2 on t1.Product = t2.Barcode
	join invProduct t3 on t2.ProductId = t3.Id
	join invUom t4 on t2.UomId = t4.Id
	left outer join @Rate t5 on t3.Id = t5.ProductId	
	order by t1.Sno

	return

  end
if @ProductType = 3 -- Auto Barcode
  begin       
	insert tmpTable (Id,Spid) select distinct t2.ProductId,@@spid from #T1 t1
    join invAutoBarcodeAndSalesRate t2 on t1.Product = t2.Barcode
	
    select t3.Code,t3.Name Particulars,t3.Id [ProductId],t5.BarcodeId,t5.Barcode,
	t4.Name Uom,t4.Id [UomId],t1.[Qty],t5.Rate,t5.SRate,isnull(t3.SerialNo,0) SerialNo,t1.SerialNumber,t3.Rate SalesRate from #T1 t1
    join invAutoBarcodeAndSalesRate t5 on t1.Product = t5.Barcode	
	join invProduct t3 on t5.ProductId = t3.Id
	join invUom t4 on t3.BaseUom = t4.Id
	order by t1.Sno
  end

else
	begin
		
		insert tmpTable (Id,Spid) 
		select distinct t2.Id,@@spid from #T1 t1
		join invProduct t2 on t1.Product = case when @ProductType = 2 then t2.Name else t2.code end
		where isnull(t1.Rate,0)=0
		
		insert @Rate (ProductId,Rate)
		exec spstock @CompanyId=1,@CostCentreId=0,@WHID=0,@FromDate=0,@ToDate=99999999,@Type=13 


		select t2.Code,t2.Name Particulars,t2.Id [ProductId],
		t4.Name Uom,t4.Id [UomId],t1.[Qty],coalesce(t1.[Rate],t5.Rate,0) Rate,isnull(t2.SerialNo,0) SerialNo,isnull(t1.SRate,t2.Rate) SalesRate,t1.SerialNumber,t1.Id,t1.Remark,case when ISDATE(t1.Expiry)=1 then cast(t1.Expiry as smalldatetime)end ExpDate,t1.Barcode from #T1 t1
		join invProduct t2 on t1.Product = case when @ProductType = 2 then t2.Name else t2.code end
		join invUom t4 on t2.BaseUom = t4.Id
		left outer join @Rate t5 on t2.Id = t5.ProductId	
		order by t1.Sno
		
		select Sno,pp.Name Property,psp.Name SubProperty,psp.Id SubPropertyId from #T1 t
		join invPurchaseSubProperty psp on psp.Name=case psp.PropertyId when 1 then t.Property1 when 2 then t.Property2 end
		join invPurchaseProperty pp on psp.PropertyId=pp.Id

	end

go

if object_id('spGetInvSalesDetailsSummary3') is not null
	drop proc spGetInvSalesDetailsSummary3  

go
  
create proc spGetInvSalesDetailsSummary3  
@CompanyID int,  
@PeriodID int,  
@VtypeID int,  
@No int  
as  

declare @SalesDetails Table(Property1Code varchar(100),Property1 varchar(100),Qty float,FOC float,Rate float,MRP float,DP float,Discount float,Gross float,[Net Amount] float,Tax float,Total float,OutPutTax float,ProductID int)  
  
insert @SalesDetails(Property1Code,Property1,Qty,FOC,Rate,MRP,DP,Discount,Gross,[Net Amount],Tax,Total,OutPutTax,ProductID)  
select p.Code,p.Name,s.Qty,s.FOC,s.Rate,s.MRP,s.DiscountP,S.Discount,s.Gross,s.Gross - s.discount [Net Amount],s.tax  [Vat Amt],s.Total,t.OutputTax,s.ProductId from invSalesDetails s  
join invProduct p on s.ProductId=p.Id  
--join invUom u on s.UomId=u.Id  
left outer join invTaxGroup t on p.TaxGroupId = t.Id   
--left outer join invAutoBarcodeAndSalesRate b on s.ProductId = b.ProductId and s.BarcodeId = b.BarcodeId   
--left outer join @HideQty hq on  s.ProductId= hq.Id  
where s.companyid = @CompanyID and s.periodId = @PeriodId and s.VtypeId=@VtypeID and s.No=@No  

 
--Product Properties  
declare @PropertyID int
select @PropertyID=min(ID) from invProductProperty
update sd set sd.Property1Code=psp.Code,sd.Property1=psp.Name from invProductPropertyDetails ppd join invProductSubProperty psp on ppd.SubPropertyID=psp.ID and ppd.PropertyID=@PropertyID
join @SalesDetails sd on ppd.ProductID=sd.ProductId
  
select row_number()over(order by (select 1))SNo,Property1Code,Property1,sum(Qty)Qty,sum(FOC)FOC,DP,OutputTax,sum(Discount)Discount,sum(Gross)Gross,sum([Net Amount])[Net Amount],sum(Tax)Tax,sum(Total)Total from @SalesDetails  
group by Property1Code,Property1,DP,OutputTax
  

go

if OBJECT_ID('prImportSalesToSalesReturn') is not null
	drop proc prImportSalesToSalesReturn
go

create proc prImportSalesToSalesReturn
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int,
@CustomerId int 

as

set transaction isolation level read uncommitted
set nocount on

declare @SD table(CompanyID int,PeriodID int,VTypeID int,No int,CustomerID int,ProductID int,Qty float)

insert @SD
select sd.CompanyID,sd.PeriodID,sd.VTypeID,sd.No,sh.CustomerID,sd.ProductID,sd.Qty from invSalesDetails sd
join invSalesHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeId = sh.VtypeId and sd.No = sh.No
where sd.VTypeID=@VtypeId
and (sd.[No] = @No or @No=0)
and (sh.CustomerID=@CustomerId or @CustomerId=0)


declare @UniversalNoSeries bit
select @UniversalNoSeries=UniversalNoSeries from invProjectSettings where CompanyId=@CompanyID

if @UniversalNoSeries=1 and @No>0
Begin
	if not exists(select top 1 1 from @SD)
		insert @SD
		select sd.CompanyID,sd.PeriodID,sd.VTypeID,sd.No,sh.CustomerID,sd.ProductID,sd.Qty from pSalesDetails sd
		join pSalesHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeId = sh.VtypeId and sd.No = sh.No
		where sd.[No] = @No
End


if (@No=0)
	insert @SD
	select sd.CompanyID,sd.PeriodID,sd.VTypeID,sd.No,sh.CustomerID,sd.ProductID,-sd.Qty from invSalesReturnDetails sd
	join invSalesReturnHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeId = sh.VtypeId and sd.No = sh.No
	and (sh.CustomerID=@CustomerId or @CustomerId=0)
		
select CompanyID,PeriodID,CustomerID,ProductID,sum(Qty)Qty into #Q from @SD group by CompanyID,PeriodID,CustomerID,ProductID having sum(Qty)>0


declare @PurchasePropertyColumns varchar(max)
select @PurchasePropertyColumns = isnull(@PurchasePropertyColumns + ',t8.',',t8.') + quotename(name) + ',t8.' + quotename(name + '_Id')  from invPurchaseProperty 
order by Id

if @PurchasePropertyColumns is null
	set @PurchasePropertyColumns = ''

create table #SalesHeader(CompanyId int,PeriodId int,VtypeId int,No int,CustomerId int,DiscountP float)
insert #SalesHeader
select CompanyId,PeriodId,VtypeId,No,CustomerId,DiscountP from invSalesHeader
where (CustomerID=@CustomerId or @CustomerId=0)
and (@No=0 or No=@No)

if @UniversalNoSeries=1 and @No>0
	insert #SalesHeader
	select CompanyId,PeriodId,VtypeId,No,CustomerId,0 from pSalesHeader
	where No=@No

create table #SalesDetails(CompanyId int,PeriodId int,VtypeId int,No int,Sno int,SerialNoId int,ProductId int,WarehouseId int,UOMId int,BarcodeId int,TaxGroupId int,FOC float,Rate float,Gross float,DiscountP float,Discount float,Tax float,Total float,MfrDate int,ExpDate int,Remark nvarchar(500))
insert #SalesDetails
select CompanyId,PeriodId,VtypeId,No,min(Sno),SerialNoId,ProductId,WarehouseId,UOMId,BarcodeId,TaxGroupId,FOC,Rate,sum(Gross),DiscountP,Discount,sum(Tax),sum(Total),max(MfrDate),min(ExpDate),Remark from invSalesDetails
where CompanyId =@CompanyId and PeriodId =@PeriodId and [VtypeId] =@VtypeId
and ([No] = @No or @No=0)
group by CompanyId,PeriodId,VtypeId,No,SerialNoId,ProductId,WarehouseId,UOMId,BarcodeId,TaxGroupId,FOC,Rate,DiscountP,Discount,Remark

--select * from #SalesDetails where ProductId=2658 return 

if @UniversalNoSeries=1 and @No>0
	insert #SalesDetails
	select CompanyId,PeriodId,VtypeId,No,Sno,SerialNoId,ProductId,null,UOMId,BarcodeId,TaxGroupId,FOC,Rate,Qty*Rate,DiscountPercentage,DiscountAmount,Tax,Total,19000101,19000101,null from pSalesDetails
	where CompanyId =@CompanyId and PeriodId =@PeriodId and [No] = @No

exec('select cast(0 as bit) [ ],t1.[Sno],t2.Code, t2.Name Particulars,t1.[ProductId],t3.Name Warehouse,t1.[WarehouseId],t4.Name Uom,
t1.[UomId],q.[Qty],isnull(t1.[Foc],0)FOC,t1.[Rate],t1.[Gross], t1.[DiscountP],
t1.[Discount],t1.[Total],cast(cast(t1.[MfrDate] as  varchar) as datetime) [MfrDate],
cast(cast(t1.[ExpDate] as varchar) as datetime) [ExpDate] ,isnull(t1.[Remark],'''') [Remark],
isnull(t1.BarcodeId,0) BarcodeId,isnull(t5.Barcode,'''') Barcode,
isnull(t1.TaxGroupId,0) TaxGroupId,t6.Name TaxGroup,isnull(t6.OutputTax,0) TaxP,isnull(t1.Tax,0) Tax,sh.CustomerId,a.Name Customer,sh.DiscountP BillDiscountP,t2.SerialNo HaveSerialNo,
isnull(t1.SerialNoId,0) SerialNoId, isnull(t7.SerialNo ,'''') SerialNo' + @PurchasePropertyColumns + '
from #SalesDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
left outer join invWarehouse t3 on t1.WarehouseId = t3.Id 
join invUom t4 on t1.UomId = t4.Id
left outer join invAutoBarcodeAndSalesRate t5 on t1.ProductId = t5.ProductId and t1.BarcodeId = t5.BarcodeId  
left outer join invTaxGroup t6 on t1.TaxGroupId = t6.Id
join #SalesHeader sh on sh.CompanyID=t1.CompanyID and sh.PeriodID=t1.PeriodID and t1.VtypeId = sh.VtypeId and t1.[No] = sh.[No]
join #q q on sh.CompanyID=q.CompanyID and sh.PeriodID=q.PeriodID and isnull(sh.CustomerID,0) = isnull(q.CustomerID,0) and t1.ProductID = q.ProductID
left join vw_SalesProperty t8 on t1.CompanyId = t8.CompanyId and t1.PeriodId = t8.PeriodId and t1.[No] = t8.No and t1.Sno = t8.Sno
left join aAccount a on sh.CustomerId=a.Id
left join invProductSerialNumber t7 on t1.SerialNoId = t7.id  
order by t1.Sno') 

go

if OBJECT_ID('prGetBarcodeDetailsForSales') is not null
	drop proc prGetBarcodeDetailsForSales 

go

create proc prGetBarcodeDetailsForSales 
@Barcode varchar(50),
@RateLevelID int,
@CustomerID int=0,
@CompanyID int=1,
@CostCentreId int=0

as

set nocount on
set transaction isolation level read uncommitted

if exists(select 1 from invOption where CostCentreIndependentProducts=1 and CompanyId=@CompanyID)
	set @CostCentreId=0

declare @BarcodeDetails table(CompanyID int,PeriodID int,VTypeID int,No int,SNo int,ID int,BarcodeID int,UOMID int,Cost float,Rate float,SRate float,WRate float,MRP float,Qty float,UnitID int,Multiplier float,Code varchar(25),Name nvarchar(100),NativeCaption nvarchar(100),UOM varchar(25),SalesUOM varchar(25),AutoEntry bit,TaxGroupID int,TaxGroup varchar(50),Tax float,TaxInclusive bit,NonStock bit,CCode varchar(50),CategoryID int,Barcode varchar(50),HaveSerialNo bit,DiscountPercent float,TAddition float)

insert @BarcodeDetails(ID,UOMID,Rate,Cost,SRate,WRate,MRP,UnitID,Multiplier,SalesUOM)  --Code
select ID,SALESUOM,Cost,Cost,Rate,WRate,MRP,1,1,isnull(SalesUom,BaseUOM) from invProduct 
where Code=@Barcode 
and (Inactive is null or Inactive = 0) 
and (@CostCentreId=0 or CostCentreId=@CostCentreId)


update b set b.SRate=u.Rate  from @BarcodeDetails b 
	join invUOMLevels u on b.ID=u.ProductId and b.UomId=u.UomId


if (@RateLevelId>0)
Begin
	update b set b.SRate=case when r.Rate=2 then b.MRP else b.WRate end from @BarcodeDetails b 	join invRateLevel r on r.Id=@RateLevelId where r.Rate>1 
	update p set p.SRate=r.Rate from @BarcodeDetails p join invBarcode r on r.ProductID=p.ID and p.SalesUOM=r.UOMID and LevelId=@RateLevelID
End

if not exists(select top 1 1 from @BarcodeDetails)
Begin
	if @RateLevelId>0
		insert @BarcodeDetails(ID,UOMID,Rate,SRate,MRP,UnitID,Multiplier,Barcode)  --UBC
		select u.ProductID,u.UOMID,u.Cost,isnull(r.Rate,u.Rate),u.MRP,u.UnitID,u.Multiplayer,u.Barcode from invUOMLevels u
		left join invBarcode r on u.ProductId=r.ProductId and u.UomId=r.UomId and r.LevelId=@RateLevelId
		where Barcode=@Barcode	 

	else
		insert @BarcodeDetails(ID,UOMID,Rate,SRate,MRP,UnitID,Multiplier,Barcode,Cost)  --UBC
		select ProductID,UOMID,Cost,Rate,MRP,UnitID,Multiplayer,Barcode,Cost from invUOMLevels where Barcode=@Barcode	 

End

declare @Date int
select @Date = convert(varchar,CURRENT_TIMESTAMP,112)

declare @InterCompanyRateSettings bit
select @InterCompanyRateSettings=InterCompanyRateSettings from invOption where CompanyId=@CompanyId

if exists(select top 1 1 from @BarcodeDetails)
Begin
	if exists(select top 1 1 from invOption where SalesRate=1 and (SalesRateSelection=0 or SalesRateSelection is null)  and CompanyId=@CompanyID)--To update LAST RATE for Code
	Begin
			
		declare @LRate table(Date int,Rate float,SRate float,WRate float,MRP float)

		insert @LRate
		select top 1 null,p.Rate,p.SalesRate,null,p.Mrp from invOpeningStock p 
		join @BarcodeDetails b on p.ProductID=b.ID and p.UomId=b.UOMID 
		where p.CompanyId=@CompanyID
		order by p.PeriodId desc,p.No desc

		insert @LRate
		select top 1 h.Date,d.Rate,d.SRate,d.WRate,d.Mrp from invPurchaseDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID 
		join invPurchaseHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.VtypeId=h.VtypeId and d.No=h.No
		where h.CompanyId=@CompanyID and d.SRate>0
		order by h.Date desc

		insert @LRate
		select top 1 h.Date,d.Rate,d.SRate,null,d.Mrp from invPackingDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID
		join invPackingHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No 
		order by h.Date desc

		insert @LRate
		select top 1 h.FromDate,d.Rate,d.Rate,d.WRate,d.Mrp from invQtyRateSettingsDetails d 
		join @BarcodeDetails b on d.ProductID=b.ID and d.UomId=b.UOMID 
		join invQtyRateSettingsHeader h on d.CompanyId=h.CompanyId and d.PeriodId=h.PeriodId and d.No=h.No
		where @Date >= h.FromDate and h.ToDate is null and  d.LQty is null and d.UQty is null and h.FromTime=0 and h.Type=3
		and (d.CompanyId=@CompanyID or @InterCompanyRateSettings=1)
		order by h.FromDate desc,h.No desc

		if not exists(select 1 from invOption where CompanyId=@CompanyId and IgnoreStockAdjustmentRate=1)
			insert @LRate
			select top 1 ph.Date,pd.Rate,pd.SRate,null,null from invStockAdjustmentDetails pd
			join invStockAdjustmentHeader ph on pd.CompanyId=ph.CompanyId and pd.PeriodId=ph.PeriodId and pd.No=ph.No
			join @BarcodeDetails b on pd.ProductID=b.ID and pd.UomId=b.UOMID
			where pd.CompanyID=@CompanyID and pd.SRate > 0 
			order by ph.Date desc,ph.[No] desc
		
		if exists(select 1 from invCompanyTransferColumnCustomization where SRate=1)
			insert @LRate
			select top 1 ph.Date,pd.Rate,pd.SRate,null,null from invCompanyTransferDetails pd
			join invCompanyTransferHeader ph on pd.PeriodId=ph.PeriodId and pd.No=ph.No
			join @BarcodeDetails b on pd.ProductID=b.ID and pd.UomId=b.UOMID
			where ph.CompanyTo=@CompanyID and pd.SRate > 0 
			order by ph.Date desc,ph.[No] desc
		
		
		declare @RateId int
		select @RateId=Rate from invRateLevel where Id=@RateLevelId

		;with r as
		(select top 1 Rate,case @RateId when 2 then MRP when 3 then WRate else SRate end SRate,WRate,Mrp from @LRate order by Date desc)
		
		update b set b.Rate=r.Rate,b.SRate=r.SRate,b.Mrp=r.MRP from @BarcodeDetails b cross join r

		

	End	
End



if not exists(select top 1 1 from @BarcodeDetails)
Begin
	if @RateLevelID>0
	Begin
		insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
		select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,
		case r.Rate 
			when 2 then isnull(t1.MRP,t1.SRate) 
			when 3 then isnull(t2.WRate,t1.SRate) end,
		t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
		join invPurchaseDetails t2 on t1.CompanyID=t2.CompanyID and t1.PeriodID=t2.PeriodID and t1.VtypeID=t2.VtypeID and t1.No=t2.No and t1.Sno=t2.Sno
		join invRateLevel r on r.ID=@RateLevelID and isnull(r.PercentageOf,0)<>1
		where t1.Barcode = @Barcode


		--if @@rowcount=0
		if not exists(select top 1 1 from @BarcodeDetails)
			insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
			select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.SRate*(100.0+Percentage)/100.0,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
			join invRateLevel r on r.ID=@RateLevelID and r.PercentageOf=1
			where t1.Barcode = @Barcode
		
        --if @@rowcount=0
		if not exists(select top 1 1 from @BarcodeDetails)
			insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,SRate,Mrp,UomId,Barcode)--Auto Barcode
			select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.Mrp,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
			join invRateLevel r on r.ID=@RateLevelID and r.Rate=2
			where t1.Barcode = @Barcode
		
	End
	else
	Begin
		insert @BarcodeDetails(CompanyID,PeriodID,VTypeID,No,SNo,ID,BarcodeID,Rate,SRate,Mrp,UomId,Barcode)--Auto Barcode
		select t1.CompanyID,t1.PeriodID,t1.VTypeID,t1.No,t1.SNo,t1.ProductID,t1.BarcodeID,t1.Rate,t1.SRate,t1.Mrp,t1.UomId,t1.Barcode from invAutoBarcodeAndSalesRate t1
		where t1.Barcode = @Barcode

		;with ct as
		(select row_number()over(partition by bd.Id,bd.BarcodeId order by ch.Date desc)sno,bd.Id,bd.BarcodeId,cd.Rate,cd.SRate from @BarcodeDetails bd 
		 join invCompanyTransferDetails cd on bd.Id=cd.ProductId and bd.BarcodeId=cd.BarcodeId
		 join invCompanyTransferHeader ch on cd.PeriodId=ch.PeriodId and cd.No=ch.No
		 where ch.CompanyTo=@CompanyId)

		 update bd set bd.Rate=ct.Rate,bd.SRate=ct.SRate from @BarcodeDetails bd join ct on bd.Id=ct.Id and bd.BarcodeId=ct.BarcodeId and ct.sno=1
		
	End
End


if exists(select 1 from invOption where SalesUBCRateSelection=1 and CompanyId=@CompanyID)
Begin
	if not exists(select 1 from @BarcodeDetails where BarcodeID>0)
	Begin
		insert @BarcodeDetails(PeriodId,No,ID,UOMID,SRate,WRate,Mrp,Barcode,Cost)--UBC
		select p.PeriodId,p.No,p.ProductID,p.UOMID,p.SalesRate*b.Multiplier,p.SalesRate*b.Multiplier,p.Mrp*b.Multiplier,b.Barcode,p.Rate from invOpeningStock p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UnitID 
		where p.SalesRate>0 and p.InactiveStock is null
		union all
		select p.PeriodId,p.No,p.ProductID,p.UOMID,p.SRate*b.Multiplier,p.WRate*b.Multiplier,p.Mrp*b.Multiplier,b.Barcode,p.CostPrice from invPurchaseDetails p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UnitID 
		where p.SRate>0 and p.InactiveStock is null

		;with d as(select row_number() over(partition by ID,UOMID,SRate,MRP order by (select 1))sno from @BarcodeDetails b)

		delete d where sno>1

		if exists(select top 1 1 from @BarcodeDetails where SRate>0) 
			delete @BarcodeDetails where isnull(SRate,0)=0
	End

End

if not exists(select 1 from @BarcodeDetails)--Weighing Machine Code
Begin
	declare @IdPos int
	declare @Qty float
	declare @UOMId int

	
	if LEN(@Barcode) in(13 ,18)
	Begin
		if substring(@Barcode,1,2)in('66','99','00') -- For IBIS Qatar
		begin
			if substring(@Barcode,7,1)='5' or substring(@Barcode,7,1)='1'--Weight	
			Begin
				set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
				set @Barcode=substring(@Barcode,3,4)
		 
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
				select ID,BaseUOM,t1.Rate,t1.MRP,case when AutoEntry=1 and t1.Rate=0 then 1 else @Qty end 
					from invProduct t1 join invUomLevels t2 
					on t1.ID=t2.ProductID and t1.BaseUom=t2.uomID
					where (Code=@Barcode or t2.Barcode=@Barcode)
			End
			else if substring(@Barcode,7,1)='0'--Value
			Begin
				declare @Value float
				set @Value=cast(substring(@Barcode,8,5) as float)/100.0
				select @Value
				set @Barcode=substring(@Barcode,3,4)	
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
				select ID,BaseUOM,case when AutoEntry=1 then @Value else Rate end,MRP,case when AutoEntry=1 then 1 else @Value/nullif(Rate,0) end from invProduct where Code=@Barcode
			End
		End
		else if len(@Barcode)=13 
			and exists(select 1 from invProduct p join invUomLevels u on p.Id=u.ProductId and p.BaseUom=u.UomId
			where p.Code=SUBSTRING(@Barcode,1,4) and len(isnull(u.Barcode,''))=0) 
		Begin
			set @Qty=cast(substring(@Barcode,5,5) as float)/1000.0
			set @Value=cast(substring(@Barcode,10,4) as float)/100.0
			select @Qty,@Value
			insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
			select ID,BaseUOM,@Value/@Qty,MRP,@Qty from invProduct 
			where Code=SUBSTRING(@Barcode,1,4)
		End
		else
		Begin
			if substring(@Barcode,7,1)='0' -- For Touch Soft Abudhabi
			begin		
				set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
				set @Barcode=Left(@Barcode,6)
		
				insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty)  --Code
					select ID,BaseUOM,Rate,MRP,@Qty from invProduct where Code=@Barcode
			End
		End

	End

	if charindex('%',@Barcode)>0 or charindex('#',@Barcode)>0
	Begin
		declare @Rate float
		set @IdPos=charindex('%',@Barcode)

		if @IdPos>0
		Begin
			set @Qty=cast(substring(@Barcode,@IdPos+1,5) as float)/1000.0
			set @Rate=cast(substring(@Barcode,@IdPos+6,len(@Barcode)-@IdPos) as float)/100.0
		End
		Else
		Begin
			set @IdPos=charindex('#',@Barcode)
			set @Qty=cast(substring(@Barcode,@IdPos+1,len(@Barcode)-@IdPos) as float)
		End
		
		set @Barcode=Left(@Barcode,@IdPos-1)

		insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Code
	        select ID,BaseUOM,@Rate,MRP,@Qty,0 from invProduct where Code=@Barcode
		
		if @@rowcount=0
			insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Barcode
				select p.ID,p.BaseUOM,@Rate,p.MRP,@Qty,0 from invProduct p join invUOMLevels u on p.ID=u.ProductId where u.Barcode=@Barcode
		
		
		--Last PRate
		declare @SRate float
		select top 1 @SRate=p.SRate from invPurchaseDetails p join @BarcodeDetails b on p.ProductID=b.ID and p.UOMID=b.UOMID 
		where p.SRate>0 and p.InactiveStock is null order by p.PeriodID desc,p.No desc

		if @SRate is not null
			update @BarcodeDetails set SRate=@SRate
		
		set @Barcode=null
	
	End
	else if substring(@Barcode,1,1)=substring(@Barcode,2,1) --KSA
	Begin
		set @Qty=cast(substring(@Barcode,8,5) as float)/1000.0
		set @Barcode=substring(@Barcode,3,5)
		
		insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Code
	        select ID,BaseUOM,Rate,MRP,@Qty,0 from invProduct where Code=@Barcode
	End
End


--if @@rowcount=0
if not exists(select 1 from @BarcodeDetails)
	insert @BarcodeDetails(ID,UOMID,SRate,MRP,Qty,AutoEntry)  --Sales Order 
	select  ProductId,uomid,Rate,0,Qty,1 from invSalesOrderDetails   where RefCode=@Barcode
		

--Updating Data from purchase (Auto Barcode Option)
update t1 set t1.TaxGroupId = t3.TaxGroupId,t1.WRate = t3.WRate from @BarcodeDetails t1
join invAutoBarcodeAndSalesRate t2 on t1.Id = t2.ProductId and t1.BarcodeId = t2.BarcodeId
join invPurchaseDetails t3 on t2.CompanyId = t3.CompanyId and t2.PeriodId = t3.PeriodId and t2.VtypeId = t3.VTypeId
and t2.No = t3.No and t2.sno = t3.sno


--Product
update b set b.Code=p.Code,b.Name=p.Name,b.NativeCaption=p.OtherLanguage,b.SalesUOM=p.SalesUOM,b.AutoEntry=p.AutoEntry,
b.TaxGroupID =  p.TaxGroupID ,b.HaveSerialNo = p.SerialNo,
b.TaxInclusive=p.TaxInclusive,b.NonStock=p.NonStockItem from @BarcodeDetails b 
join invProduct p on b.Id = p.Id 

--UOM
update b set b.UOM=u.Name from @BarcodeDetails b join invUom u on b.UomId = u.Id 

--TaxGroup
update b set b.TaxGroup=t.Name,b.Tax=t.OutputTax,b.TAddition=t.Addition from @BarcodeDetails b join invTaxGroup t on b.TaxGroupId = t.Id

--Category Code
declare @@CatPropID int
select @@CatPropID=CategoryPropertyID from invOption

if @@CatPropID is not null
	update p set p.CCode=sp.Code,p.CategoryID=pp.SubPropertyId from @BarcodeDetails p join invProductPropertyDetails pp on p.ID=pp.ProductID join invProductSubProperty sp on pp.SubPropertyID=sp.Id where sp.PropertyId=@@CatPropID

--Barcode
update b set b.Barcode=u.Barcode from invUomLevels u join @BarcodeDetails b on u.ProductId=b.ID and u.UOMID=b.UOMID where b.Barcode is null


--Qtywise Rate Settings
declare @Time int
set @Time=datepart(hour,current_timestamp)*100+datepart(minute,current_timestamp)


update p set p.SRate=s.Rate,p.WRate=s.WRate,p.MRP=s.MRP,p.DiscountPercent=s.DiscountPercent from invQtyRateSettingsDetails s 
join @BarcodeDetails p on s.ProductId=p.Id and s.UOMID=p.UOMID
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
--and isnull(s.BarcodeId,0)=isnull(p.BarcodeId,0) and s.CompanyId=@CompanyID
and isnull(s.BarcodeId,0)=0 and s.CompanyId=@CompanyID
and @Time between h.FromTime and h.ToTime

update p set p.DiscountPercent=s.DiscountPercent from invQtyRateSettingsDetails s 
join @BarcodeDetails p on s.ProductId=p.Id and s.BarcodeId=p.BarcodeId
join invQtyRateSettingsHeader h on s.CompanyId=h.CompanyId and s.PeriodId=h.PeriodId and s.No=h.No 
where @Date between h.FromDate and h.ToDate and s.LQty is null and s.UQty is null 
and @Time between h.FromTime and h.ToTime


declare @ProductId int
declare @SalesUOM int

select @ProductId=Id,@SalesUOM = SalesUOM from @BarcodeDetails

declare @DefaultCustomerId int
declare @SalesRate int
select @DefaultCustomerId=DefaultCustomer,@SalesRate=SalesRate from invOption where CompanyID=@CompanyID


if @CustomerID>0 and @CustomerID<>isnull(@DefaultCustomerId,0) and (@SalesRate = 2 or @SalesRate = 4) and ISNULL(@RateLevelId,0) = 0 
and not exists(select 1 from @BarcodeDetails where BarcodeId is not null)
Begin
	
	declare @TaxOption int
	select @TaxOption=TaxOption from invOption

	if @TaxOption=2
		select @TaxOption=TaxInclusive from @BarcodeDetails
		
	declare @DRate table(Date int,Rate float,DiscountP float)

	--Getting Customer Last Rate
	declare @DiscountP float

	insert @DRate(Date,Rate,DiscountP)
	select top 1 sh.Date,case when @TaxOption=1 then sd.Rate+sd.Tax/sd.Qty else sd.Rate end,sd.DiscountP from invSalesDetails sd 
	join invSalesHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
	join @BarcodeDetails b on sd.ProductId=b.ID and sd.UomId=b.UOMID
	--where sd.ProductID=@ProductId and sh.CustomerID=@CustomerID 
	where sh.CustomerID=@CustomerID
	order by sh.Date desc,sh.No desc

	if exists(select 1 from invOption where SalesRate = 4)
		insert @DRate(Date,Rate)
		select top 1 sh.Date,sd.SRate from invPurchaseDetails sd
		join invPurchaseHeader sh on sh.CompanyID=sd.CompanyID and sh.PeriodID=sd.PeriodID and sd.VtypeID=sh.VtypeId and sd.No=sh.No 
		where sd.ProductId = @ProductId and sd.UomId = @SalesUOM and sd.SRate > 0 order by sh.Date desc,sh.No desc

	select top 1 @Rate=Rate from @DRate order by Date desc
	select @DiscountP=max(DiscountP) from @DRate
	
End

if exists(select 1 from invOption where SalesRate = 0 and CompanyID=@CompanyID) and exists(select 1 from invProjectSettings where isnull(AutoBarcode,0) = 0)
	update @BarcodeDetails set SRate=0
	
--Getting Customer Set Rate
--Drilling for Over Accounts,
if not exists(select 1 from @BarcodeDetails where BarcodeId is not null)
Begin
	declare @UnderAccountID int
	select @Rate=Rate,@UnderAccountID=CustomerID from invCustomerRate where CustomerID=@CustomerID and ProductID=@ProductId

	if @Rate is null
	Begin
		set @UnderAccountID=@CustomerID
		while @Rate is null and @UnderAccountID is not null
		begin
			select @UnderAccountID=max(UnderAccountID) from aAccount where ID=@UnderAccountID and ID<>UnderAccountID
			select @Rate=Rate from invCustomerRate where CustomerID=@UnderAccountID and ProductID=@ProductId
		end
	End
End

update @BarcodeDetails set SRate=@Rate where @Rate is not null and BarcodeId is null


if isnull(@RateLevelId,0) > 0
	update b set b.SRate=b.SRate*(100.0+Percentage)/100.0 from @BarcodeDetails b,invRateLevel r where r.ID=@RateLevelId and r.PercentageOf=1


--Final
select Barcode,BarcodeId,Code,Name,NativeCaption,CCode,CategoryID,ID,UOMID,Uom,SalesUom,Rate,Cost,SRate,WRate,AutoEntry,TaxGroupId,TaxGroup,Tax,
TaxInclusive,NonStock,HaveSerialNo,isnull(Mrp,0) MRP,isnull(Qty,case when AutoEntry=1 then 1 end)Qty,DiscountPercent,TAddition from @BarcodeDetails
order by PeriodId desc,No desc

--Property
select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPurchasePropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and t1.VtypeID=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ID and t1.BarcodeID = bd.BarcodeID

union all

select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invPackingPropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -1=bd.VtypeID and t1.No=bd.No and t1.SNo=bd.Sno and 
t1.ProductID = bd.ID and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ID --and t1.BarcodeID = bd.BarcodeID

union all

select 1,t1.PurchaseSubPropertyId1,t3.Name [Property],t2.Name SubProperty from invProductionHeader t1
join invPurchaseSubProperty t2 on t1.PurchaseSubPropertyId1 = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
join @BarcodeDetails bd on t1.CompanyID = bd.CompanyID and t1.PeriodID=bd.PeriodID and -2=bd.VtypeID and t1.No=bd.No and --t1.SNo=bd.Sno and 
t1.ProductID = bd.ID --and t1.BarcodeID = bd.BarcodeID

go

if object_id('prSaveSales') is not null
	drop proc prSaveSales
go

create proc prSaveSales
@CompanyID int,
@PeriodID int,
@VtypeId int,
@No int,
@Date int,
@DeliveryDate int,
@CustomerId int,
@PaymentMode tinyint,
@SalesManId int,
@RateLevelId int,
@DueDate int,
@QuotationNo int,
@Total float,
@DiscountP float,
@Discount float,
@NetTotal float,
@Notes nvarchar(4000),
@TaxCalculation int,
@Tax float,
@SalesReturn float,
@Addition float,
@XmlProductDetails xml,
@Rep1 int,
@Rep2 int,
@Paid float,
@RoundOff float,
@AirwayBillNo varchar(50),
@XmlPropertyDetails xml,
@Advance float,
@Time int,
@XmlAdditions xml,
@FooterAddition float,
@PrePrintingString varchar(50),
@FromTime int=null,
@ToTime int=null,
@JobId int,
@ReturnId int,
@CostCentreId int,
@ShippingId int,
@ShippingNo varchar(50),
@Address nvarchar(300)=null, 
@Export bit=null,
@CreditCardID int=null,
@InterState bit=null,
@CardId int = null,
@Redempted int = null,
@PaidBy tinyint=null,
@XmlProductSno xml,
@TaxGroupID int=null,
@BillTax float=null,
@Description nvarchar(100)=null,
@LocalMobileNo varchar(100) = null,
@Approve bit=null,
@UserId int = null,
@Addition2 float=null,
@TokenNo int = null,
@QRCodeImage Image=null,
@Remark1 nVarchar(500) =null,
@Remark2 nVarchar(500) =null,
@Remark3 nVarchar(500) =null,
@Remark4 nVarchar(500) =null,
@EInvoice int = null,
@XmlTray xml=null,
@NotEdit bit = null,
@Remark5 nvarchar(2000) = null ,
@Remark6 nvarchar(2000) = null ,
@Remark7 nvarchar(2000) = null ,
@Remark8 nvarchar(2000) = null ,
@Remark9 nvarchar(2000) = null ,
@Remark10 nvarchar(2000) = null ,
@Remark11 nvarchar(2000) = null ,
@Remark12 nvarchar(2000) = null ,
@Discount1 float=null,
@Discount2 float=null,
@Discount3 float=null,
@Eway bit = null


as
set nocount on
set xact_abort on

declare @Message varchar(100)
if not exists(select 1 from invOption where CompanyID=@CompanyID and SalesAllowDuplicateInvoiceNo=1) 
Begin
	if len(rtrim(@AirwayBillNo))>0
		select @Message='Invoice No Already given for Sales ' + cast(No as varchar) from invSalesHeader where CompanyID = @CompanyID and PeriodID = @PeriodID and VtypeId = @VtypeId and No <> @No and AirwayBillNo  = @AirwayBillNo 
End

if @Message is not null
Begin
	select @No No,@Message Message
	return
End

--Due Day Blocking
if (@PaymentMode>0)
Begin
	if exists(select 1 from invOption where SalesBlockByCreditLimit=1 and CompanyId=@CompanyId)
	Begin
		declare @DueDays int
		select @DueDays=DueDays from invCustomer where AccountID=@CustomerId and DueDays>0
		
		if isnull(@DueDays,0)=0
			select @DueDays=DueDays from invCostCentre where Id=@CostCentreId

		if (@DueDays>0)
		Begin
			
			if exists(select 1 from invOption where CompanyId=@CompanyId and DueCalculation=1)
			Begin
				declare @OS table(PeriodId int,Date smalldatetime,VoucherTypeID int,VType varchar(50),No int,SNo int,Account nvarchar(100),Description varchar(300),Age int,Amount varchar(50))

				if exists(select 1 from invVendor where AccountId=@CustomerID)
				Begin
					insert @OS
					exec spGetVendorOutstandingBills @CompanyId=@CompanyId,@ToDate=@Date,@VendorId=@CustomerID,@Type=2
					update @OS set Amount=cast(-1.0*cast(replace(Amount,',','') as float) as varchar) where isnumeric(Amount)=1
				End
				else
					insert @OS
					exec spGetCustomerOutstandingBills @CompanyId=@CompanyId,@ToDate=@Date,@CustomerID=@CustomerID,@Type=2

				delete @OS where isnumeric(Amount)=0
				select @Message='Due Days Over For No. ' + cast(No as varchar)+ char(10)+char(13)+'Amount - '+ Amount + char(10)+char(13) + 'Days - ' + cast(Age as varchar) from @OS where Age>@DueDays and cast(replace(Amount,',','') as float)>0
				if @Message is not null
				Begin
					select @No No,@Message Message
					return
				End
			End
			Else
			Begin
				declare @Due table(PeriodId int,Date smalldatetime,VoucherTypeID int,VType varchar(50),No int,Description varchar(300),Amount varchar(50),Age int,Balance varchar(50))
				insert @Due 
				exec spCustomersAgeing @ToDate=@Date,@AccountID=@CustomerID,@Type=3,@CompanyId=@CompanyId
				select @Message='Due Days Over For No. ' + cast(No as varchar)+ char(10)+char(13)+'Amount - '+ Amount + char(10)+char(13)+ 'Balance - '+Balance + char(10)+char(13) + 'Days - ' + cast(Age as varchar) from @Due where Age>@DueDays
				if @Message is not null
				Begin
					select @No No,@Message Message
					return
				End
			End
			
		End
	End
End

----------
declare @VoucherTypeID int
declare @Sync bit
Begin Transaction
if(@No = 0)
begin
	declare @T1 table([No] int)
	insert @T1 exec prGetSalesMaxVno @CompanyID,@PeriodID,@VtypeId
	select @No = [No] from @T1 
	--Token No
	if exists(select 1 from invOption where CompanyId=@CompanyId and TokenNo=1)
	begin
	    select  @TokenNo = isnull(max(TokenNo),0) + 1 from invSalesHeader 
        where CompanyId = @CompanyId and PeriodId = @PeriodId and VtypeId = @VtypeId and [Date] = @Date 
	end
end
else
begin
	if exists(select 1 from invOption where CompanyId=@CompanyId and SalesRecovery=1)
	Begin
		declare @HSNo int
		select @HSNo=isnull(max(HSNo),0)+1 from invSalesHeaderHistory where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
		exec spSaveSalesHistory @CompanyId=@CompanyId,@PeriodId=@PeriodId,@VtypeId=@VtypeId,@No=@No,@HSNo=@HSNo
	End

	delete t from aTransaction t 
	join invVoucherTypeDetails vd on t.VoucherTypeID=vd.AccountVtypeID
	join invSalesHeader h on t.CompanyID=h.CompanyId and t.PeriodID=h.PeriodId and vd.Id=h.VtypeId and t.No=h.No and t.Date=h.Date
	where t.ModuleID=1 and h.VtypeId = @VtypeId and h.No = @No and h.CompanyID=@CompanyID and h.PeriodID=@PeriodID

	delete invSalesHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesPropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesAdditions where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invPrivilegeCardSales where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesProductSerialNumber where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No
	delete invSalesTrayDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [VtypeId] = @VtypeId and [No] = @No

	set @Sync=1
end	
  	
insert invSalesHeader([CompanyID],[PeriodID],[VtypeId],[No],[Date],[DeliveryDate],[CustomerId],[PaymentMode],
[SalesManId],[RateLevelId],[DueDate],[QuotationNo],[Total],[DiscountP],[Discount],[NetTotal],
[Notes],[TaxCalculation],[Tax],[SalesReturn],[Rep1],[Rep2],[Paid],[RoundOff],[AirwayBillNo],
Advance,Time,Addition,PrePrintingString,FromTime,ToTime,JobId,ReturnId,CostCentreId,ShippingId,ShippingNo,CreditCardID,
[Address],InterState,CardId,PaidBy,TaxGroupID,BillTax,LocalMobileNo,Sync,Approve,UserId,TokenNo,QRCodeImage,Remark1,Remark2,
Remark3,Remark4,EInvoice,NotEdit,[Remark5],[Remark6],[Remark7],[Remark8],[Remark9],[Remark10],[Remark11],[Remark12],Discount1,
Discount2,Discount3,EWay)
values(@CompanyID,@PeriodID,@VtypeId,@No,@Date,@DeliveryDate,@CustomerId,@PaymentMode,nullif(@SalesManId,0),@RateLevelId,@DueDate,@QuotationNo,
@Total,@DiscountP,@Discount,@NetTotal,@Notes,@TaxCalculation,@Tax,@SalesReturn,nullif(@Rep1,0),nullif(@Rep2,0),
nullif(@Paid,0),nullif(@RoundOff,0),nullif(@AirwayBillNo,''),nullif(@Advance,0),@Time,nullif(@FooterAddition,0),
nullif(@PrePrintingString,''),nullif(@FromTime,0),nullif(@ToTime,0),nullif(@JobId,0),nullif(@ReturnId,0),nullif(@CostCentreId,0),
nullif(@ShippingId,0),nullif(@ShippingNo,''),nullif(@CreditCardID,0),nullif(rtrim(@Address),''),nullif(@InterState,0),nullif(@CardId,0),nullif(@PaidBy,0),
nullif(@TaxGroupID,0),nullif(@BillTax,0),nullif(@LocalMobileNo,''),@Sync,nullif(@Approve,0),nullif(@UserId,0),nullif(@TokenNo,0),@QRCodeImage,
@Remark1,@Remark2,@Remark3,@Remark4,nullif(@EInvoice,0),nullif(@NotEdit,0),NULLIF(@Remark5,''),NULLIF(@Remark6,''),NULLIF(@Remark7,''),NULLIF(@Remark8,''),NULLIF(@Remark9,''),
NULLIF(@Remark10,''),NULLIF(@Remark11,''),NULLIF(@Remark12,''),nullif(@Discount1,0),nullif(@Discount2,0),nullif(@Discount3,0),@Eway)


--Details Part
declare @Details table(Sno int,ProductId int,SalesmanId int,WarehouseId int,UomId int,Qty float,Foc float,FType int,Pieces float,Rate float,MRP float,Gross float,
					   Addition float,TaxGroupId int,Tax float,DiscountP float,Discount float,Total float,MfrDate int,ExpDate int,Remark nvarchar(1000),BarcodeId int,
					   IType int,IPeriodId int,INo int,ISno int,IQty float,IFOC float,SerialNoId int,ARate float,Length float,Width float,Addition1 float,Addition2 float,Cost float,Remark1 nvarchar(100))

declare @Idoc int
exec sp_xml_preparedocument @Idoc out,@XmlProductDetails

insert @Details
([Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1)
select [Sno],[ProductId],nullif([WarehouseId],0),isnull(nullif([UomId],0),1),[Qty],[Foc],nullif([Pieces],0)[Pieces],
[Rate],MRP,[Gross],nullif(Addition,0) Addition,nullif([TaxGroupId],0),[Tax],[DiscountP],
[Discount],[Total],
case when @Date<>convert(varchar,[MfrDate],112) then convert(varchar,[MfrDate],112) end,
case when @Date<>convert(varchar,[ExpDate],112) then convert(varchar,[ExpDate],112) end,
nullif([Remark],'') [Remark],isnull([BarcodeId],0),nullif([IType],0) [IType],nullif(IPeriodId,0),nullif([INo],0) [INo],
case when IType>0 then isnull(ISno,0) end,nullif([IQty],0) [IQTy], nullif([IFOC],0) [IFOC],nullif([SerialNoId],0) SerialNoId,nullif(SalesmanId,0),
case when [Foc] = 0 then null else [FType] end,nullif(case when Rate<>ARate then ARate end,0),nullif(Length,0),nullif(Width,0),nullif(Addition1,0),nullif(Addition2,0),nullif(Cost,0),nullif(Remark1,'')
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
ProductId      int '@ProductId',
SalesmanId     int '@SalesmanId',
WarehouseId    int '@WarehouseId',
UomId          int '@UomId',
Qty            float '@Qty',
Foc            float '@Foc',
FType          int   '@FType',
Pieces         float '@Pieces',
Rate           float '@Rate',
MRP            float '@MRP',
Gross          float '@Gross',
Addition       float '@Addition', 
TaxGroupId     int '@TaxGroupId',
Tax            float '@Tax',
DiscountP      float '@DiscountP',
Discount       float '@Discount',
Total          float '@Total',
MfrDate        datetime '@MfrDate',
ExpDate        datetime '@ExpDate',
Remark         nvarchar(1000) '@Remark',
BarcodeId      int '@BarcodeId',
IType		   int '@IType',
IPeriodId	   int '@IPeriodId',
INo		       int '@INo',
ISno		   int '@ISno',
IQty		   float '@IQty',
IFOC           float '@IFOC',
SerialNoId     int '@SerialNoId',
ARate          float '@ARate' ,
Length         float '@Length' ,
Width          float '@Width' ,
Addition1      float '@Addition1',
Addition2      float '@Addition2',
Cost           float '@Cost',
Remark1         nvarchar(100) '@Remark1'
)
where ProductId>0

declare @CGSAccountId int
select @CGSAccountId=CostOfGoodsSoldAccountId from invOption where CompanyID = @CompanyID
if @CGSAccountId>0
Begin
	declare @Stock table(CompanyId int,ProductId int,Rate float,CP float,SRate float,WRate float,MRP float,Qty float,Pieces float)
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	update invSalesHeader set BlockStockCalculation=1 where Date=@Date and Time>@Time
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	declare @BeforeCostofGoods float
	select @BeforeCostofGoods=sum(Qty*Rate) from @Stock
End

insert invSalesDetails([CompanyID],[PeriodID],[VtypeId],[No],[Sno],[ProductId],[WarehouseId],[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1)
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],nullif([WarehouseId],0),[UomId],[Qty],[Foc],[Pieces],[Rate],MRP,[Gross],[Addition],
[TaxGroupId],[Tax],[DiscountP],[Discount],[Total],[MfrDate],[ExpDate],[Remark],[BarcodeId],
[IType],IPeriodId,[INo],[ISno],[IQty],[IFOC],[SerialNoId],SalesmanId,FType,ARate,Length,Width,Addition1,Addition2,Cost,Remark1
from @Details

exec sp_xml_removedocument @Idoc


if @CGSAccountId>0
Begin
	delete @Stock
	insert tmpTable(Id,SPID)
    select distinct ProductId,@@SPID from @Details
	insert @Stock
    exec spStock @CompanyId=@CompanyId,@ToDate=@Date,@Type=1
	update invSalesHeader set BlockStockCalculation=null where Date=@Date and Time>@Time
	declare @AfterCostofGoods float
	select @AfterCostofGoods=sum(Qty*Rate) from @Stock
End

----------------

if isnull(@CardId,0) >0
begin
  declare @PointAccumulationAmount float
  select @PointAccumulationAmount = t2.PointAccumulationAmount from invPrivilegeCardIssue t1
  join invPrivilegeCard t2 on t1.CardId = t2.Id 
  where t1.Id = @CardId

  declare @LessProfitAmount float
  select @LessProfitAmount=sum(Total) from @Details d join invProduct p on d.ProductId=p.Id where p.LessProfit=1

  insert invPrivilegeCardSales([CompanyID],[PeriodID],[VtypeId],[No],CardId,BillAmount,Points,Redempted)
  select @CompanyID,@PeriodID,@VtypeId,@No,@CardId,@NetTotal,(@NetTotal-isnull(@LessProfitAmount,0))/@PointAccumulationAmount,@Redempted
  where isnull(@PointAccumulationAmount,0) > 0
end 


--Property

exec sp_xml_preparedocument @Idoc out,@XmlPropertyDetails
insert invSalesPropertyDetails(CompanyID,PeriodID,[VtypeId],[No],[Sno],[ProductId],[SubPropertyId])
select @CompanyID,@PeriodID,@VtypeId,@No,[Sno],[ProductId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno int '@Sno',
ProductId int '@ProductId',
SubPropertyId int '@SubPropertyId'
)

exec sp_xml_removedocument @Idoc
--Additions
	declare @SalesAdditions table(CreditorID int,DebtorID int,Description varchar(100),Amount float)
	exec sp_xml_preparedocument @Idoc out,@XmlAdditions
	insert @SalesAdditions(CreditorID,DebtorID,Description,Amount)
	select CreditorID,DebtorID,nullif(Description,''),Amount from openxml (@Idoc,'/TableHeader/Table1',2)
	with
	(
	CreditorID  int '@CreditorID',
	DebtorID    int '@DebtorID',
	Description varchar(100) '@Description',
	Amount      float '@Amount'
	)
	where Amount>0
	exec sp_xml_removedocument @Idoc

	insert invSalesAdditions(CompanyId,PeriodId,VtypeId,No,CreditorID,DebtorID,Description,Amount)
	select @CompanyId,@PeriodId,@VtypeId,@No,CreditorID,DebtorID,Description,Amount from @SalesAdditions

 --Sales Product Serial Number (Bulk Saving)
 exec sp_xml_preparedocument @Idoc out,@XmlProductSno  
 insert invSalesProductSerialNumber([CompanyId],[PeriodId],[VtypeId],[No],[USno],[Sno],[ProductId],[SerialNoId],SerialNo)  
 select @CompanyId,@PeriodId,@VtypeId,@No,[USno],[Sno],[ProductId],nullif([Id],0),case when Id=0 then SerialNo end from openxml (@Idoc,'/TableHeader/Table1',2)  
 with  
 (  
 USno int '@USno',  
 Sno int '@Sno',  
 ProductId int '@ProductId',
 Id int '@Id',
 SerialNo varchar(100) '@SerialNo'
 )  
 exec sp_xml_removedocument @Idoc  

  
-- Tray Details
 
 exec sp_xml_preparedocument @Idoc out,@XmlTray  
 insert invSalesTrayDetails([CompanyId],[PeriodId],[VtypeId],[No],ProductID,OB,[In],[Out],Balance)  
 select @CompanyId,@PeriodId,@VtypeId,@No,ProductID,[OB],[In],[Out],Balance  from openxml (@Idoc,'/TableHeader/Table1',2)  
 with  
 (  
 ProductID int '@ProductID',
 [OB] int '@OB', 
 [In] int '@In',  
 [Out] int '@Out',   
 Balance int '@Balance'
  
 )  
 exec sp_xml_removedocument @Idoc  


--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1 and CompanyId=@CompanyId) 
   and exists(select 1 from invProjectSettings where isnull(DisablePostingInSales,0)=0 and CompanyId=@CompanyId)
   and isnull(@EInvoice,0) not in(2,4)
Begin
	if @PaymentMode=0  and isnull(@PaidBy,0)=0
		set @Paid=0
	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where ID=@VtypeId
	declare @SalesAccountID int,
	        @DiscountAccountID int,
	        @CashInHandID int,
	        @SalesRoundOffAccount int,
			@CreditCard int,
			@AdditionAccountID int,
			@PurchaseAccountID int,
			@CommissionAccountID int
	
	
	select @SalesRoundOffAccount = SalesRoundOffAccount,@AdditionAccountID=AdditionAccount,@CashInHandID=nullif(SalesCashAccountId,0) from invOption where CompanyID = @CompanyID        
	select @SalesAccountID=Sales,@DiscountAccountID=DiscountPaid,@CashInHandID=isnull(@CashInHandID,CashInHand),@CreditCard=CreditCard,@PurchaseAccountID=Purchase,@CommissionAccountID=Commission from aAccountSettings where CompanyID=@CompanyID
	select @CreditCard=AccountId from aCreditCard where Id=@CreditCardId and AccountId>0
	select @CostCentreId=CostCentreId from invCostCentre where Id=@CostCentreId
	select @CostCentreId=nullif(@CostCentreId,0)

	select @CashInHandID=AccountID from invSalesman where Id=@SalesManId and AccountID>0

	--Footer Addition
	declare @FooterAdditionToPost float
	if not exists(select top 1 1 from @SalesAdditions) and @FooterAddition<>0
	Begin
		set @FooterAdditionToPost=@FooterAddition
	End

	declare @PNetTotal float
	select @PNetTotal=@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+ isnull(@FooterAdditionToPost,0) - isnull(@SalesReturn,0) + isnull(@BillTax,0)
	--select @PNetTotal=@Total-isnull(@Discount,0)+isnull(@RoundOff,0)+ isnull(@FooterAdditionToPost,0) + isnull(@BillTax,0)
	if @PaymentMode=0 --Cash
	Begin
		--Paid
		if @Paid>0
		Begin
			if @PNetTotal<>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@SalesAccountID,@PNetTotal-isnull(@Advance,0)-isnull(@Paid,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Payment In Sales',@CostCentreId) 

		End
		Else
		Begin
			if @PNetTotal<>0
				--Net Total
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CashInHandID,@SalesAccountID,@PNetTotal-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 
		End

		if @Advance>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,@SalesAccountID,@Advance,'Advance Adjustment',@CostCentreId) 
	End

	if @PaymentMode in(1,2) --Credit
	Begin
		--Paid
		if @Paid>0
		Begin
			if exists(select 1 from invOption where CompanyID=@CompanyID and SalesPostPaidSeparately=1)
			Begin
				if @PNetTotal<>0
					insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
					values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal,'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo,CostCentreId,CreditCardID)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@CustomerId,@Paid,'Payment In Sales',1,@CostCentreId,nullif(case when @PaidBy=1 then @CreditCardID end,0)) 	
			End
			Else
			Begin
				if (@PNetTotal-isnull(@Paid,0))<>0
					insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
					values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal-isnull(@Paid,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,@CostCentreId) 

				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,SNo,CostCentreId,CreditCardID)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Payment In Sales',1,@CostCentreId,nullif(case when @PaidBy=1 then @CreditCardID end,0)) 
			End
		End
		Else
		Begin
			--if @PNetTotal<>0
				--Net Total
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@SalesAccountID,@PNetTotal,'Sales '+ substring(@Notes,1,90) + @AirwayBillNo+isnull(' '+@Description,''),@CostCentreId) 
		End
	End
	if @PaymentMode=3 --Credit Card
	Begin
		--Paid
		if @Paid>0
		Begin
			if (@PNetTotal-@Paid>0)
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditCard,@SalesAccountID,@PNetTotal-@Paid-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,nullif(@CreditCardID,0),@CostCentreId) 

			if (@Paid>@PNetTotal)
				set @Paid=@PNetTotal

			if @Paid>0
				insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
				values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else @CashInHandID end,@SalesAccountID,@Paid,'Sales',@CostCentreId) 
		End
		Else
			--Net Total
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CreditCardID,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CreditCard,@SalesAccountID,@PNetTotal-isnull(@Advance,0),'Sales '+ substring(@Notes,1,90) + @AirwayBillNo,nullif(@CreditCardID,0),@CostCentreId) 


		if @Advance>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,@SalesAccountID,@Advance,'Advance Adjustment',@CostCentreId) 
	End
	--Discount
	if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DiscountAccountID,@SalesAccountID,@Discount,'Sales Discount',@CostCentreId) 
	--Tax
	if @Tax>0
	Begin
		declare  @TaxAccountID int
		select @TaxAccountID=OutPutTaxAccount from invOption
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@TaxAccountID,@Tax,'Sales Tax',@CostCentreId) 
	End

	--Bill Tax
	if @BillTax>0
	Begin
		select @TaxAccountID=OutPutTaxAccount from invOption where CompanyId=@CompanyId
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@TaxAccountID,@BillTax,'Sales Tax',@CostCentreId) 
	End

	--Addition
	if @Addition>0
	Begin
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,isnull(@AdditionAccountID,0),@Addition,'Addition In Sales',@CostCentreId) 
	End
	
	--Addition2
	if @Addition2>0
	Begin
		select @AdditionAccountID=isnull(SalesAddition2AccountId,@AdditionAccountID) from invOption where CompanyId=@CompanyId
        insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,isnull(@AdditionAccountID,0),@Addition2,@CostCentreId) 
	End

	--Footer Addition
	if @FooterAdditionToPost<>0
	Begin
        declare @SalesAdditionAccount int
		select @SalesAdditionAccount=SalesAdditionAccount from invOption where CompanyId=@CompanyId
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@SalesAdditionAccount,@FooterAdditionToPost,@CostCentreId) 
	End

	--Round off
	if ISNULL(@SalesRoundOffAccount,0) >  0 and @RoundOff <> 0
	begin
		if @RoundOff > 0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,@SalesRoundOffAccount,@RoundOff,@CostCentreId) 
		else 
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,CostCentreId)
		    values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesRoundOffAccount,@SalesAccountID,abs(@RoundOff),@CostCentreId) 	
	end

	--Additions
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,SNo,DebtorID,CreditorID,Amount,Description,CostCentreId)
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,1,DebtorID,CreditorID,Amount,Description,@CostCentreId from @SalesAdditions


	--Product Account
	insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
	select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@SalesAccountID,p.AccountId,sum(d.Gross),p.Name,@CostCentreId from @Details d join invProduct p on d.ProductId=p.Id where p.AccountId is not null group by p.AccountId,p.Name

	--Salesman Commission
	if @SalesmanID>0 and @CommissionAccountID>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
		select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CommissionAccountID,s.AccountID1,@NetTotal*s.Commission/100.0,'Salesman Commission',@CostCentreId from invSalesMan s 
		where s.Id=@SalesmanId and s.AccountID1>0 and s.Commission<>0

	if @CGSAccountId>0
	Begin
		--Cost Of Goods Sold
		declare @Cost float
		set @Cost = isnull(@BeforeCostofGoods,0)-isnull(@AfterCostofGoods,0)

		if @Cost<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,CostCentreId)  
			select 1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CGSAccountId,@PurchaseAccountId,@Cost,'Sales',@CostCentreId --from @CGS --having sum(CP)<>0
	End
End

if @JobId >0 and (select isnull(Status,0) from invJobCustomization) =  0	
	update InvJobForm Set Status=1 where ID=@JobId
Commit

if @Export=1
	exec prExportSales @CompanyID=@CompanyID,@PeriodID=@PeriodID,@VtypeID=@VtypeID,@ExportNo=@No

select @No No,@Message Message,@HSNo HSNo

go

if not exists(select name from sys.columns where object_id = object_id('invReturnHeader') and name = 'TaxGroupID') 
	alter table invReturnHeader add TaxGroupID int foreign key references invTaxGroup(ID)
  
go

if not exists(select name from sys.columns where object_id = object_id('invReturnHeader') and name = 'Tax') 
	alter table invReturnHeader add Tax float
  
go

if OBJECT_ID('prSaveReturn') is not null
	drop proc prSaveReturn
go

create proc prSaveReturn
@CompanyID int,
@PeriodID int,
@No int,
@Date int,
@Time int,
@CustomerId int,
@SalesManId int,
@RateLevelId int,
@SiteId int,
@Total float,
@Addition float,
@DiscountP float,
@Discount float,
@TaxGroupId int,
@Tax float,
@RoundOff float,
@NetTotal float,
@Advance float,
@Balance float,
@Paid float,
@Notes varchar(500),
@RefNo varchar(50)=null,
@PaidBy int=null,
@CreditCardID int=null,
@XmlProductDetails xml,
@XmlPropertyDetails xml,
@IPeriodID int,
@INo int,
@OutVno int output


as
set nocount on
set xact_abort on

Begin Transaction

declare @VoucherTypeID int

if(@No = 0)
  begin
    declare @T1 table([No] int)
    insert @T1 exec prGetReturnMaxVno @CompanyID,@PeriodID
    select @No = [No] from @T1 
  end
	else
	begin

		delete invReturnHeader  where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No
		delete invReturnDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No
		delete invReturnPropertyDetails where CompanyId = @CompanyId and PeriodId = @PeriodId and [No] = @No
				
		select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where VTypeId=8

		delete aTransaction where ModuleID=1 and VoucherTypeID = @VoucherTypeID and [No] = @No and CompanyID=@CompanyID and PeriodID=@PeriodID

		--exec prDeleteReturn @VtypeId=@VtypeId,@No=@No,@CompanyID=@CompanyID,@PeriodID=@PeriodID

        end	
    	
insert invReturnHeader(CompanyId,PeriodId,No,Date,Time,CustomerId,SalesManId,RateLevelId,Total,DiscountP,Discount,RoundOff,NetTotal,Notes,Advance,Paid,Balance,IPeriodId,INo,Addition,SiteId,RefNo,PaidBy,CreditCardID,TaxGroupId,Tax)
values(@CompanyId,@PeriodId,@No,@Date,@Time,@CustomerId,nullif(@SalesManId,0),nullif(@RateLevelId,0),@Total,@DiscountP,@Discount,@RoundOff,@NetTotal,@Notes,@Advance,@Paid,@Balance,nullif(@IPeriodId,0),nullif(@INo,0),nullif(@Addition,0),nullif(@SiteId,0),@RefNo,nullif(@PaidBy,0),nullif(@CreditCardID,0),nullif(@TaxGroupId,0),nullif(@Tax,0))


declare @Idoc int
exec sp_xml_preparedocument @Idoc out ,@XmlProductDetails
	
insert invReturnDetails(CompanyId,PeriodId,No,Sno,ProductId,WarehouseId,UomId,Qty,Rate,Gross,DiscountP,Discount,NOD,Total,Remark,Pending)
select @CompanyId,@PeriodId,@No,Sno,ProductId,nullif(WarehouseId,0),UomId,Qty,Rate,Gross,DiscountP,Discount,NOD,Total,Remark,Pending
from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno            int '@Sno',
ProductId      int '@ProductId',
ReturnmanId     int '@ReturnmanId',
WarehouseId    int '@WarehouseId',
UomId          int '@UomId',
Qty            float '@Qty',
Rate           float '@Rate',
Gross          float '@Gross',
DiscountP      float '@DiscountP',
Discount       float '@Discount',
NOD            float '@NOD',
Total          float '@Total',
Remark         varchar(100) '@Remark',
Pending        bit '@Pending'
)

exec sp_xml_removedocument @Idoc


--Property
exec sp_xml_preparedocument @Idoc out ,@XmlPropertyDetails

insert invReturnPropertyDetails(CompanyID,PeriodID,[No],[Sno],[ProductId],[SubPropertyId])
select @CompanyID,@PeriodID,@No,[Sno],[ProductId],[SubPropertyId] from openxml (@Idoc,'/TableHeader/Table1',2)
with
(
Sno int '@Sno',
ProductId int '@ProductId',
SubPropertyId int '@SubPropertyId'
)

exec sp_xml_removedocument @Idoc

--Posting to Accounts
if exists(select 1 from invOption where AccountLinking=1)
Begin

	select @VoucherTypeID=AccountVTypeID from invVoucherTypeDetails where VTypeID=8

	declare @RentalAccountID int,
	        @DiscountAccountID int,
	        @CashInHandID int,
	        @RoundOffAccount int,
			@CreditCard int,
			@PostPaidSeparately bit
	        
	        
	select @DiscountAccountID=DiscountPaid,@CashInHandID=CashInHand,@CreditCard=CreditCard from aAccountSettings where CompanyID=@CompanyID
	select @RentalAccountID=RentalAccount,@RoundOffAccount = SalesRoundOffAccount,@PostPaidSeparately=SalesPostPaidSeparately from invOption where CompanyID=@CompanyID
	select @CreditCard=AccountId from aCreditCard where Id=@CreditCardId and AccountId>0

	declare @Description varchar(500)
	select @Description=isnull(@Description,'')+ s.Name from invSite s where s.Id=@SiteId
	select @Description=@Description +', '+convert(varchar,cast(cast(Date as varchar) as smalldatetime),3)+', '+cast(DateDiff(D,cast(cast(Date as varchar) as smalldatetime),cast(cast(@Date as varchar) as smalldatetime)+1) as varchar) from invIssueHeader where CompanyId=@CompanyId and PeriodId=@IPeriodId and No=@INo
		
	
	if @PostPaidSeparately=1
	Begin
		if @Total>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@RentalAccountID,@Total,'Return   '+@Description,@RefNo) 
	
		if @Paid>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,CreditCardId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else  @CashInHandID end,@CustomerID,@Paid,'Paid while Return',@RefNo,nullif(@CreditCardId,0)) 
		else if @Paid<0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,CreditCardId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerID,case when @PaidBy=1 then @CreditCard else  @CashInHandID end,abs(@Paid),'Paid Back while Return',@RefNo,nullif(@CreditCardId,0)) 
	End
	Else
	Begin
		if @Paid<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo,CreditCardId)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,case when @PaidBy=1 then @CreditCard else  @CashInHandID end,@RentalAccountID,@Paid,'Return   '+@Description,@RefNo,nullif(@CreditCardId,0)) 

		if (@Total-isnull(@Paid,0))<>0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@RentalAccountID,@Total-isnull(@Paid,0),'Return   '+@Description,@RefNo) 

	End
	
		

	--Addition
	if @Addition>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@CustomerId,@CashInHandID,@Addition,'Freight In Return',@RefNo) 
	
	--Discount
	if @Discount>0
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@DiscountAccountID,@CustomerID,@Discount,'Rental Discount',@RefNo) 
	
	--Tax
	if @Tax>0
	Begin
		declare @TaxAccountID int
		select @TaxAccountID=OutPutTaxAccount from invOption where CompanyId=@CompanyId
		insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description)
		values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@RentalAccountID,@TaxAccountID,@Tax,'Rental Tax') 
	End

	--Round off
	if ISNULL(@RoundOffAccount,0) >  0 and @RoundOff <> 0
	begin
		if @RoundOff > 0
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
			values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@RentalAccountID,@RoundOffAccount,@RoundOff,'Round Off In Return',@RefNo) 
		else 
			insert aTransaction(ModuleID,CompanyID,PeriodID,Date,VoucherTypeID,No,DebtorID,CreditorID,Amount,Description,RefNo)
		    values(1,@CompanyID,@PeriodID,@Date,@VoucherTypeID,@No,@RoundOffAccount,@RentalAccountID,abs(@RoundOff),'Round Off In Return',@RefNo) 	
	end
	
	
End

set @OutVno = @No 

Commit

go

if OBJECT_ID('prGetReturn') is not null
