create proc prGetReturn
@CompanyID int,
@PeriodID int,
@No int as
set nocount on

select t1.[No],t1.[Date],t1.[CustomerId],t2.Name [Customer],t1.[SalesManId],t1.[RateLevelId],t1.[Total],t1.Addition,t1.[DiscountP],t1.[Discount],t1.[NetTotal],t1.[Notes],
t1.RoundOff,t1.Advance,t1.SiteId,t1.RefNo,
t1.Time,isnull(ih.Date,t1.date) IDate,isnull(ih.Time,t1.time) ITime,isnull(t1.IPeriodID,0) IPeriodID,isnull(t1.INo,0) INo,t1.Paid,t1.Balance,t1.PaidBy,t1.CreditCardId,t1.TaxGroupId,t1.Tax from invReturnHeader t1
join aAccount t2 on t1.CustomerId = t2.Id 
left outer join invIssueHeader ih on t1.companyId=ih.CompanyId and t1.IPeriodID=ih.PeriodId and t1.INo=ih.No
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[No] = @No

select t1.[Sno],t2.Code, t2.Name Particulars,t2.OtherLanguage NativeCaption,t1.[ProductId],ISNULL(t3.Name,'') Warehouse,t1.[WarehouseId],t4.Name Uom,
t1.[UomId],t1.[Qty],t1.[Rate],t1.[Gross],t1.[DiscountP],
t1.[Discount],t1.NOD,t1.[Total],isnull(t1.[Remark],'') [Remark],t1.Pending
from invReturnDetails t1
join invProduct t2 on t1.ProductId = t2.Id 
left outer join invWarehouse t3 on t1.WarehouseId = t3.Id 
join invUom t4 on t1.UomId = t4.Id
left outer join invUOMLevels ul on t1.ProductID=ul.ProductID and t1.UomId=ul.UomId
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[No] = @No order by t1.Sno 

select t1.Sno,t1.SubPropertyId,t3.Name [Property],t2.Name SubProperty from invReturnPropertyDetails t1
join invPurchaseSubProperty t2 on t1.SubPropertyId = t2.Id 
join invPurchaseProperty t3 on t2.PropertyId = t3.Id 
where t1.CompanyId = @CompanyId and t1.PeriodId = @PeriodId and t1.[No] = @No order by t1.Sno 


go

if OBJECT_ID('prGetServiceInvoiceReport') is not null
	drop proc prGetServiceInvoiceReport
go

create proc prGetServiceInvoiceReport
@CompanyID int,
@FromDate int,
@ToDate int

as

set nocount on
set transaction isolation level read uncommitted

declare @SI table(ServiceID int,No int,SDNo int,Date smalldatetime,Time int,JobNo varchar(50),ProductName nvarchar(100),SerialNo varchar(50),Work varchar(200),Customer nvarchar(100),Mobileno varchar(50),ConsumedRate float,WorkTotal float,NetTotal float,Amount float,Discount float,Cash float,Bank float,TaxP float,Tax float,Credit float)

insert @SI
select si.ServiceID,si.[No],sh.No SDNo,cast(cast(isnull(si.[Date],sh.Date) as varchar)as smalldatetime)Date,si.Time,t1.[JobNo],t1.[ProductName],t1.[SerialNo],t1.[Work],
t2.Name Customer,t2.Mobileno,sh.ConsumedRate,sh.WorkTotal,sh.NetTotal,si.Amount,si.Discount,
case when si.PaymentMode=0 then si.Amount end Cash,
case when si.PaymentMode=1 then si.Amount end Bank,t.OutputTax TaxP,si.Tax,0
from invServiceOrder t1 
join (select Name,AccountId,MobileNo from invCustomer union select Name,AccountId,MobileNo from invVendor) t2 on t1.CustomerId = t2.AccountID
join invServiceHeader sh on t1.ID=sh.ServiceID and sh.Status=1 and isnull(sh.DeliveredSalesmanID,0) >0
join invserviceinvoice si on t1.Id=si.ServiceID and t1.Date<=si.Date
left outer join invSalesman S on  t1.[SalesManID]=S.ID
left join invTaxGroup t on si.TaxGroupId=t.Id 
where t1.CompanyId=@CompanyID  and isnull(si.[Date],sh.Date) between @FromDate and @ToDate 

update @SI set Credit=nullif(NetTotal-isnull(Amount,0)-isnull(Discount,0),0)

select * from @SI
 
go

